window.__copybookData__.texts=[{"id":1,"grade":"一年级上册","title":"我是中国人","paragraphs":["我是中国人。","我们都是中国人。","中华民族是一家。"]},{"id":2,"grade":"一年级上册","title":"我爱我们的祖国","paragraphs":["五星红旗","北京天安门","我爱五星红旗。","我爱北京天安门。","长江","黄河","我爱长江，我爱黄河。","我爱中华人民共和国。"]},{"id":3,"grade":"一年级上册","title":"我是小学生","paragraphs":["上学歌","太阳当空照，","花儿对我笑。","小鸟说：“早，早，早，","你为什么背上小书包？”","我去上学校，","天天不迟到。","爱学习，爱劳动，","长大要为人民立功劳。"]},{"id":4,"grade":"一年级上册","title":"我爱学语文","paragraphs":["读书 写字","讲故事 听故事"]},{"id":5,"grade":"一年级上册","title":"1 天地人","paragraphs":["天地人","你我他"]},{"id":6,"grade":"一年级上册","title":"2 金木水火土","paragraphs":["一二三四五，","金木水火土。","天地分上下，","日月照今古。"]},{"id":7,"grade":"一年级上册","title":"3 口耳目手足","paragraphs":["口耳目手足","站如松，坐如钟。","行如风，卧如弓。"]},{"id":8,"grade":"一年级上册","title":"4 日月山川","paragraphs":["日 月","山 川","水 火","田 禾"]},{"id":9,"grade":"一年级上册","title":"语文园地一","paragraphs":["一片两片三四片，","五片六片七八片。","九片十片无数片，","飞入芦花都不见。","人　天　口　田　日　目","作者：[唐代] 骆宾王","鹅，鹅，鹅，","曲项向天歌。","白毛浮绿水，","红掌拨清波。","“鹅，鹅，鹅！”面向蓝天，一群鹅儿伸着弯曲的脖子在歌唱。","白色的身体漂浮在碧绿水面，红红的脚掌拨动着清清水波。","骆宾王（约619—687年）字观光，汉族，婺州义乌人（今浙江义乌）。唐初诗人，与王勃、杨炯、卢照邻合称“初唐四杰”。又与富嘉谟并称“富骆”。高宗永徽中为道王李元庆府属，历武功、长安主簿，仪凤三年，入为侍御史，因事下狱，次年遇赦，调露二年除临海丞，不得志，辞官。有集。骆宾王于武则天光宅元年，为起兵扬州反武则天的徐敬业作《代李敬业传檄天下文》，敬业败，亡命不知所之，或云被杀，或云为僧。","小剪刀，手中拿，","我学奶奶剪窗花。","剪雪花，剪梅花，","剪对喜鹊叫喳喳。","剪只鸡，剪只鸭，","剪条鲤鱼摇尾巴。","大红鲤鱼谁来抱？","哦！再剪一个胖娃娃。"]},{"id":10,"grade":"一年级上册","title":"快乐读书吧","paragraphs":["我经常和爸爸妈妈一起读有趣的故事书。","我读了很多书，会讲很多故事，同学们叫我“故事大王”。","周末，我在书店看到了很多好看的图画书。","学了拼音，我就可以认更多的字，读更多的书了。"]},{"id":11,"grade":"一年级上册","title":"1 a o e","paragraphs":["ā  á  ǎ  à","ō  ó  ǒ  ò","ē  é  ě  è"]},{"id":12,"grade":"一年级上册","title":"2 i u ü","paragraphs":["ī  í  ǐ  ì","ū  ú  ǔ  ù","ǖ  ǘ  ǚ  ǜ"]},{"id":13,"grade":"一年级上册","title":"3 b p m f","paragraphs":["b p m f","b-ā-bā","b-á-bá","b-ǎ-bǎ","b-à-bà","bǎ bō bí bù","pá pò pī pǔ","mǎ mō mǐ mù","fā fó fǔ","爸爸","妈妈"]},{"id":14,"grade":"一年级上册","title":"4 d t n l","paragraphs":["d  t  n  l","dǎ  dé  dī  dú","tā  tè  tǐ  tú","ná  né  nǐ  nù  nǚ","lā  lè  lǐ  lù  lǘ","大地  马路  泥土","读一读","小白兔","小白兔，穿皮袄，","耳朵长，尾巴小。","三瓣嘴，胡子翘，","一动一动总在笑。"]},{"id":15,"grade":"一年级上册","title":"语文园地二","paragraphs":["他 八 马","七 地 你","目 土 足","作者：[唐代] 王维","远看山有色，","近听水无声。","春去花还在，","人来鸟不惊。","远看高山色彩明亮，走到近处却听不到水的声音。","春天过去了花仍在争奇斗艳，人走近了鸟却没有被惊动。","王维（701年－761年，一说699年—761年），字摩诘(jié)，号摩诘居士。汉族，河东蒲州（今山西运城）人，祖籍山西祁县，唐朝诗人，有“诗佛”之称。苏轼评价其：“味摩诘之诗，诗中有画；观摩诘之画，画中有诗。”开元九年（721年）中进士，任太乐丞。天宝年间，拜吏部郎中、给事中。唐肃宗乾元年间任尚书右丞，世称“王右丞”。王维是盛唐诗人的代表，今存诗400余首，重要诗作有《相思》《山居秋暝》等。王维精通佛学，受禅宗影响很大。佛教有一部《维摩诘经》，是王维名和字的由来。王维诗书画都很有名，多才多艺，音乐也很精通。与孟浩然合称“王孟”。","老山羊在地里收白菜，小白兔和小灰兔来帮忙。","收完白菜，老山羊把一车白菜送给小灰兔。小灰兔收下了，说：“谢谢您！”","老山羊又把一车白菜送给小白兔。小白兔说：“我不要白菜，请您给我一些菜籽吧。”老山羊送给小白兔一包菜籽。","小白兔回到家里，把地翻松，种上菜籽。","过了些日子，白菜长出来了。小白兔常常给白菜浇水，施肥，拔草，捉虫。白菜很快长大了。","小灰兔把一车白菜拉回家里。他不干活了，饿了就吃老山羊送的白菜。","过了些日子，小灰兔把白菜吃完了，又到老山羊家里去要白菜。","这时候，他看见小白兔挑着一担白菜，给老山羊送来了。小灰兔很奇怪，问道：“小白兔，你的菜是哪儿来的？”","小白兔说：“是我自己种的。只有自己种，才有吃不完的菜。”"]},{"id":16,"grade":"一年级上册","title":"5 g k h","paragraphs":["g k h","g-u-ā → guā","gā gè gù","kǎ kē kǔ","hā hē hǔ","g-u-à → guà","kuā huá","g-u-ō → guō","kuò huǒ","哥哥 弟弟 画画 荷花","读一读","说话","小溪流说话，哗哗，哗哗。","小雨点说话，沙沙，沙沙。","小鸽子说话，咕咕，咕咕。","小鸭子说话，嘎嘎，嘎嘎。","小花猫说话，喵喵，喵喵。","小青蛙说话，呱呱，呱呱。"]},{"id":17,"grade":"一年级上册","title":"6 j q x","paragraphs":["j q x","j-ī → jī","qì xī","j-i-ā → jiā","qiā xiá","j-ǖ → jū","q-ǖ → qū","x-ǖ → xū","打鼓","下棋","搭积木","在一起","小黄鸡，小黑鸡，","欢欢喜喜在一起。","刨刨土，捉捉虫，","青草地上做游戏。"]},{"id":18,"grade":"一年级上册","title":"7 z c s","paragraphs":["zi  ci  si","zá  zé  zǔ  zuó","cā  cè  cū  cuō","sǎ  sè  sù  suǒ","zǐ  cì  sī","字  词语  句子","过桥","数学题，一道道。","等号就像一座桥。","做对了，走过桥，","做错了，过不了。","想一想，算一算，","快快乐乐过了桥。"]},{"id":19,"grade":"一年级上册","title":"8 zh ch sh r","paragraphs":["zhi  chi  shi  ri","zhā  zhè  zhù","chá  chē  chū","shà  shé  shǔ","rè   rǔ","zhuǎ  zhuō  chuō","shuā  shuō  ruò","zhí   chī   shī  rì","擦桌子","折纸","读书","绕口令","四是四，","十是十。","十四是十四，","四十是四十。","四十不是十四，","十四不是四十。"]},{"id":20,"grade":"一年级上册","title":"9 y w","paragraphs":["y w","yi wu yu","yá wá wō","yī wǔ yǔ","鱼 鸭子 乌鸦 蚂蚁","读一读","哪座房子最漂亮","一座房，两座房，","青青的瓦，白白的墙。","三座房，四座房，","房前花果香，屋后树成行。","哪座房子最漂亮？","要数我们的小学堂。"]},{"id":21,"grade":"一年级上册","title":"语文园地三","paragraphs":["鸡 鱼 河","一座山 一棵树","四只鸽子 七朵花","一模一样 一心一意 独一无二","三头六臂 五颜六色 十全十美","谁会飞？","鸟会飞。","鸟儿怎样飞？","扇扇翅膀去又回。","谁会跑？","马会跑。","马儿怎样跑？","四脚腾空仰天叫。","谁会游？","鱼会游。","鱼儿怎样游？","摇摇尾巴摆摆头。"]},{"id":22,"grade":"一年级上册","title":"10 ai ei ui","paragraphs":["ai ei ui","āi ái ǎi ài","g-āi → gāi","g-u-āi → guāi","tái kāi cāi","huài kuài","ēi éi ěi èi","l-èi → lèi","bēi péi fēi","gěi wéi hēi","uī uí uǐ uì","t-uǐ → tuǐ","huì duī chuī","zuǐ suì ruì","pái duì","萝卜 白菜 蔬菜 鸭梨 西瓜 水果","洗手歌","排着队，向前走，","做什么？去洗手。","肥皂用来搓搓手，","清水帮我冲冲手，","毛巾给我擦擦手。","小手洗得真干净，","大家一起笑开口。"]},{"id":23,"grade":"一年级上册","title":"11 ao ou iu","paragraphs":["ao  ou  iu","āo  áo  ǎo  ào","tiào niǎo shǎo yào rào zǎo","ōu óu ǒu òu","kǒu ròu tóu lóu yóu zǒu shōu","iū iú iǔ iù","jiù qiú diū liù niú xiū","xiǎo niú","小桥 流水 垂柳 桃花","欢迎台湾小朋友","一只船，扬起帆，","漂啊漂啊到台湾。","接来台湾小朋友，","到我学校来参观。","伸出双手紧紧握，","热情的话儿说不完。"]},{"id":24,"grade":"一年级上册","title":"12 ie üe er","paragraphs":["ie  üe  er","ye  yue","piě  dié  bié  xié  qiē  jiě","lüè  nüè  jué  quē  xué","xiě  zuò  yè","梅花开 雪花飘 夜色美","月儿弯弯","月儿弯弯挂蓝天，","小溪弯弯出青山。","大河弯弯流入海，","山路弯弯到校园。"]},{"id":25,"grade":"一年级上册","title":"13 an en in un ün","paragraphs":["an  en  in  un  ün","yuan  yin  yun","g-u-ān → guān","k-u-ān → kuān","h-u-ān → huān","j-ü-ān → juān","q-ü-ān → quān","x-ü-ān → xuān","yuán yīn yùn","quán wān yǎn nán zhàn duǎn rǎn jiān","nèn chén kěn zhēn rén wèn","mín pīn nín jìn xīn qīn","chūn rùn tūn hūn zhǔn lún","jūn qún xún","lún chuán","蓝天 白云 草原 森林","家","蓝天是白云的家，","树林是小鸟的家，","小河是鱼儿的家，","泥土是种子的家。","我们是祖国的花朵，","祖国就是我们的家。"]},{"id":26,"grade":"一年级上册","title":"14 ang eng ing ong","paragraphs":["ang  eng  ing  ong","ying","qiáng bāng huáng chuāng","fēng rēng héng dēng","tīng jǐng bǐng qīng","sòng hǒng zhōng qióng","míng liàng","游泳 滑冰 骑自行车 打乒乓球","两只羊","桥东走来一只羊，","桥西走来一只羊，","一起走到小桥上。","你也不肯让，","我也不肯让，","扑通掉进河中央。"]},{"id":27,"grade":"一年级上册","title":"语文园地四","paragraphs":["上午 下午 晚上","昨天 今天 明天","上个月 这个月 下个月","去年 今年 明年","车  火车  马车  汽车","上车  坐车  车站  车厢","作者：[唐代] 李绅","锄禾日当午，","汗滴禾下土。","谁知盘中餐，","粒粒皆辛苦。","盛夏中午，烈日炎炎，农民还在劳作，汗珠滴入泥土。","有谁想到，我们碗中的米饭，一粒一粒都是农民辛苦劳动得来的呀？","李绅（772—846）汉族，亳州（今属安徽）人，生于乌程（今浙江湖州），长于润州无锡（今属江苏）。字公垂。唐元和元年（806年），进士及第，补国子助教。与元稹、白居易交游甚密，他一生最闪光的部分在于诗歌，他是在文学史上产生过巨大影响的新乐府运动的参与者。作有《乐府新题》20首，已佚。著有《悯农》诗两首：“锄禾日当午，汗滴禾下土，谁知盘中餐，粒粒皆辛苦。”脍炙人口，妇孺皆知，千古传诵。《全唐诗》存其诗四卷。","老师教大家念书。老师念一句，我们跟着念一句。窗外的风吹着，淅淅沙沙；窗外的鸟叫着，叽叽喳喳。","老师说：“风也在教小鸟念书吗？”我们仔细地听。窗外的风念着：“淅淅沙沙。”窗外的鸟念着：“叽叽喳喳。”","我们都笑了。哈哈！小鸟念错啦！"]},{"id":28,"grade":"一年级上册","title":"1 秋天","paragraphs":["天气凉了，树叶黄了，一片片叶子从树上落下来。","天那么蓝，那么高。一群大雁往南飞，一会儿排成个“人”字，一会儿排成个“一”字。","啊！秋天来了！"]},{"id":29,"grade":"一年级上册","title":"2 江南","paragraphs":["江南可采莲，","莲叶何田田。","鱼戏莲叶间。","鱼戏莲叶东，","鱼戏莲叶西，","鱼戏莲叶南，","鱼戏莲叶北。","江南水上可以采莲，莲叶层层叠叠繁茂葱翠，鱼儿在莲叶间嬉戏。","鱼一会在莲叶的东边嬉戏，一会在莲叶的西边嬉戏，一会在莲叶的的南边嬉戏，一会又在莲叶的北边嬉戏。"]},{"id":30,"grade":"一年级上册","title":"3 雪地里的小画家","paragraphs":["下雪啦，下雪啦！","雪地里来了一群小画家。","小鸡画竹叶，小狗画梅花，","小鸭画枫叶，小马画月牙。","不用颜料不用笔，","几步就成一幅画。","青蛙为什么没参加？","他在洞里睡着啦。"]},{"id":31,"grade":"一年级上册","title":"4 四季","paragraphs":["草芽尖尖，","他对小鸟说：","“我是春天。”","荷叶圆圆，","他对青蛙说：","“我是夏天。”","谷穗弯弯，","他鞠着躬说：","“我是秋天。”","雪人大肚子一挺，","他顽皮地说：","“我就是冬天。”"]},{"id":32,"grade":"一年级上册","title":"语文园地五","paragraphs":["南 北　男 女  开 关","正 反  先 后  内 外","男 女 开 关 正 反","春天   夏天   秋天   冬天","大地   树叶   青草   莲花","飞鸟   小鱼   青蛙   雪人","一年之计在于春，","一日之计在于晨。","一寸光阴一寸金，","寸金难买寸光阴。","老公公种了一个萝卜。萝卜长大了，老公公去地里拔萝卜。","老公公拉着萝卜叶子，“嗨哟！嗨哟！”拔呀拔，拔不动。","老公公喊老婆婆来帮忙。老婆婆拉着老公公，老公公拉着萝卜叶子，“嗨哟！嗨哟！”拔呀拔，拔不动。","老婆婆喊小姑娘来帮忙。小姑娘拉着老婆婆，老婆婆拉着老公公，老公公拉着萝卜叶子，“嗨哟！嗨哟！”拔呀拔，拔不动。","小姑娘喊小狗来帮忙。小狗拉着小姑娘，小姑娘拉着老婆婆，老婆婆拉着老公公，老公公拉着萝卜叶子，“嗨哟！嗨哟！”拔呀拔，拔不动。","小狗喊小猫来帮忙……"]},{"id":33,"grade":"一年级上册","title":"5 对韵歌","paragraphs":["云对雨，","雪对风。","花对树，","鸟对虫。","山清对水秀，","柳绿对桃红。"]},{"id":34,"grade":"一年级上册","title":"6 日月明","paragraphs":["日月明，田力男。","小大尖，小土尘。","二人从，三人众。","双木林，三木森。","一人不成众，","独木不成林。","众人一条心，","黄土变成金。"]},{"id":35,"grade":"一年级上册","title":"7 小书包","paragraphs":["橡皮  尺子  作业本","笔袋  铅笔  转笔刀","我的小书包，","宝贝真不少。","课本作业本，","铅笔转笔刀。","天天起得早，","陪我去学校。"]},{"id":36,"grade":"一年级上册","title":"8 升国旗","paragraphs":["中国  国旗  五星红旗","五星红旗，我们的国旗。","国歌声中，徐徐升起。","迎风飘扬，多么美丽。","向着国旗，我们立正。","望着国旗，我们敬礼。"]},{"id":37,"grade":"一年级上册","title":"语文园地六","paragraphs":["学校　老师　工厂　工人","医院　医生　传达室 门卫","你们  家里   男生  蓝色","上山  三年   写字  报纸","作者：[唐代] 李白","小时不识月，","呼作白玉盘。","又疑瑶台镜，","飞在青云端。","小时候不认识月亮， 把它称为白玉盘。","又怀疑是瑶台仙镜，飞在夜空青云之上。","李白（701年－762年） ，字太白，号青莲居士，又号“谪仙人”，唐代伟大的浪漫主义诗人，被后人誉为“诗仙”，与杜甫并称为“李杜”，为了与另两位诗人李商隐与杜牧即“小李杜”区别，杜甫与李白又合称“大李杜”。据《新唐书》记载，李白为兴圣皇帝（凉武昭王李暠）九世孙，与李唐诸王同宗。其人爽朗大方，爱饮酒作诗，喜交友。李白深受黄老列庄思想影响，有《李太白集》传世，诗作中多为醉时写就，代表作有《望庐山瀑布》《行路难》《蜀道难》《将进酒》《早发白帝城》等。","大树旁边的地里长着许多花生。花生已经开花了，一朵朵金黄色的小花，在阳光下格外鲜艳。","小松鼠问鼹鼠：“这是什么花啊？”鼹鼠说：“这是花生的花。到了秋天，会结花生。花生可好吃啦！”小松鼠很高兴，他想：等花生结了果，我就把它摘下来，留着冬天吃。","小松鼠每天都到地里去，看看结花生了没有。","他等啊，等啊，等到花都落光了，也没看见花生。","小松鼠感到很奇怪，自言自语地说：“是谁把花生摘走了呢？”"]},{"id":38,"grade":"一年级上册","title":"5 小小的船","paragraphs":["弯弯的月儿小小的船，","小小的船儿两头尖。","我在小小的船里坐，","只看见闪闪的星星蓝蓝的天。"]},{"id":39,"grade":"一年级上册","title":"6 影子","paragraphs":["影子在前，","影子在后，","影子常常跟着我，","就像一条小黑狗。","影子在左，","影子在右，","影子常常陪着我，","它是我的好朋友。"]},{"id":40,"grade":"一年级上册","title":"7 两件宝","paragraphs":["人有两件宝，","双手和大脑。","双手会做工，","大脑会思考。","用手不用脑，","事情做不好。","用脑不用手，","啥也办不到。","用手又用脑，","才能有创造。"]},{"id":41,"grade":"一年级上册","title":"语文园地七","paragraphs":["爷爷　奶奶 姥爷 姥姥","叔叔 姑姑 爸爸　妈妈　舅舅 姨妈","哥哥　姐姐　弟弟　妹妹","了　才　　云　山","儿　四　　我　心","明  晚 昨 春  妈 奶 姐 妹","早晨起来，面向太阳。","前面是东，后面是西。","左面是北，右面是南。","种瓜得瓜，种豆得豆。","前人栽树，后人乘凉。","千里之行，始于足下。","百尺竿头，更进一步。","有只小猴子在井边玩。他往井里一看，里面有个月亮。小猴子叫起来：“糟啦，糟啦！月亮掉在井里啦！”","大猴子听见了，跑过来一看，跟着叫起来：“糟啦，糟啦！月亮掉在井里啦！”","老猴子听见了，跑过来一看，也跟着叫起来：“糟啦，糟啦！月亮掉在井里啦！”","附近的猴子听见了，都跑过来看。大家跟着叫起来：“糟啦，糟啦！月亮掉在井里啦！咱们快把它捞上来！”","猴子们爬上了井旁边的大树。老猴子倒挂在树上，拉住大猴子的脚。大猴子也倒挂着，拉住另一只猴子的脚。猴子们就这样一只拉一只，一直挂到井里头，小猴子挂在最下边。","小猴子伸手去捞月亮，手刚碰到水，月亮就不见了。","老猴子一抬头，看见月亮还在天上。他喘着气，说：“不用捞了，不用捞了，月亮好好地挂在天上呢！”"]},{"id":42,"grade":"一年级上册","title":"8 比尾巴","paragraphs":["谁的尾巴长？","谁的尾巴短？","谁的尾巴好像一把伞？","猴子的尾巴长。","兔子的尾巴短。","松鼠的尾巴好像一把伞。","谁的尾巴弯？","谁的尾巴扁？","谁的尾巴最好看？","公鸡的尾巴弯。","鸭子的尾巴扁。","孔雀的尾巴最好看。"]},{"id":43,"grade":"一年级上册","title":"9 乌鸦喝水","paragraphs":["一只乌鸦口渴了，到处找水喝。乌鸦看见一个瓶子，瓶子里有水。但是，瓶子里水不多，瓶口又小，乌鸦喝不着水。怎么办呢？","乌鸦看见旁边有许多小石子，想出办法来了。","乌鸦把小石子一颗一颗地放进瓶子里。瓶子里的水渐渐升高，乌鸦就喝着水了。"]},{"id":44,"grade":"一年级上册","title":"10 雨点儿","paragraphs":["数不清的雨点儿，从云彩里落下来。","半空中，大雨点儿问小雨点儿：“你要到哪里去？”","小雨点儿回答：“我要去有花有草的地方。你呢？”","大雨点儿说：“我要去没有花没有草的地方。”","不久，有花有草的地方，花更红了，草更绿了。没有花没有草的地方，开出了红的花，长出了绿的草。"]},{"id":45,"grade":"一年级上册","title":"语文园地八","paragraphs":["花 口 作","牛 羊 只 爪 叶","旦 拼 音 果 白","果皮 树皮 加法 办法 回来 回答","许多 不许 到处 四处 方向 地方","作者：[唐代] 李峤","解落三秋叶，","能开二月花。","过江千尺浪，","入竹万竿斜。","风能吹落秋天金黄的树叶，能吹开春天美丽的鲜花。","刮过江面能掀千尺巨浪，吹进竹林能使万竿倾斜。","李峤(644～713) ，唐代诗人。字巨山。赵州赞皇（今属河北）人。李峤对唐代律诗和歌行的发展有一定的作用与影响。他前与王勃、杨炯相接，又和杜审言、崔融、苏味道并称“文章四友”。","小孩小孩你别馋，","过了腊八就是年。","腊八粥，喝几天，","哩哩啦啦二十三。","二十三，糖瓜粘。","二十四，扫房子。","二十五，磨豆腐。","二十六，去买肉。","二十七，宰公鸡。","二十八，把面发。","二十九，蒸馒头。","三十晚上熬一宿，","初一初二满街走。"]},{"id":46,"grade":"一年级下册","title":"1 春夏秋冬","paragraphs":["春风","夏雨","秋霜","冬雪","春风吹","夏雨落","秋霜降","冬雪飘","青草","红花","游鱼","飞鸟","池草青","山花红","鱼出水","鸟入林"]},{"id":47,"grade":"一年级下册","title":"2 姓氏歌","paragraphs":["你姓什么？我姓李。","什么李？木子李。","他姓什么？他姓张。","什么张？弓长张。","古月胡，口天吴，","双人徐，言午许。","中国姓氏有很多，","赵、钱、孙、李，","周、吴、郑、王，","诸葛、东方，","上官、欧阳……"]},{"id":48,"grade":"一年级下册","title":"3 小青蛙","paragraphs":["河水清清天气晴，","小小青蛙大眼睛。","保护禾苗吃害虫，","做了不少好事情。","请你爱护小青蛙，","好让禾苗不生病。"]},{"id":49,"grade":"一年级下册","title":"4 猜字谜","paragraphs":["（一）","左边绿，右边红，","左右相遇起凉风。","绿的喜欢及时雨，","红的最怕水来攻。","（二）","“言”来互相尊重，","“心”至令人感动，","“日”出万里无云，","“水”到纯净透明。"]},{"id":50,"grade":"一年级下册","title":"语文园地一","paragraphs":["识字 组词 读课文","计算 减法 列算式","图形 卡片 合唱团","见　万　王　羊","长　全　半　上","A B C D E F G","a b c d e f g","H I J K L M N","h i j k l m n","O P Q R S T","o p q r s t","U V W X Y Z","u v w x y z","祖 国 多 么 广 大","大 兴 安 岭 ，","雪 花 还 在 飞 舞 。","长 江 两 岸 ，","柳 枝 已 经 发 芽 。","海 南 岛 上 ，","到 处 盛 开 着 鲜 花 。","我 们 的 祖 国 多 么 广大。","作者：[唐代] 孟浩然","春眠不觉晓，","处处闻啼鸟。","夜来风雨声，","花落知多少。","春日里贪睡不知不觉天就亮了，到处可以听见小鸟的鸣叫声。","回想昨夜的阵阵风雨声，不知吹落了多少娇美的春花。","孟浩然（689年—740年），字浩然，号孟山人，襄州襄阳（今湖北襄阳）人，唐代著名的山水田园派诗人，世称“孟襄阳”。因他未曾入仕，又称之为“孟山人”。孟浩然生于盛唐，早年有志用世，在仕途困顿、痛苦失望后，尚能自重，不媚俗世，修道归隐终身。曾隐居鹿门山。40岁时，游长安，应进士举不第。曾在太学赋诗，名动公卿，一座倾服，为之搁笔。开元二十五年（737）张九龄招致幕府，后隐居。孟诗绝大部分为五言短篇，多写山水田园和隐居的逸兴以及羁旅行役的心情。其中虽不无愤世嫉俗之词，而更多属于诗人的自我表现。孟浩然的诗在艺术上有独特的造诣，后人把孟浩然与盛唐另一山水诗人王维并称为“王孟”，有《孟浩然集》三卷传世。","妞妞赶牛","妞妞赶牛河边走","牛牛要吃河边柳","妞妞护柳扭牛走","牛牛扭头顶妞妞","妞妞拗不过牛牛","低头捡起小石头","吓得牛牛扭头走"]},{"id":51,"grade":"一年级下册","title":"1 热爱中国共产党","paragraphs":["花儿喜欢太阳，","花儿在阳光下开放。","鸟儿喜欢蓝天，","鸟儿在天空中飞翔。","我们热爱中国共产党，","我们在党的怀抱里幸福成长。"]},{"id":52,"grade":"一年级下册","title":"2 吃水不忘挖井人","paragraphs":["瑞金城外有个村子叫沙洲坝，","毛主席在江西领导革命的时候，在那儿住过。","村子里没有水井，乡亲们吃水要到很远的地方去挑。","毛主席就带领战士和乡亲们挖了一口井。","解放以后，乡亲们在井旁边立了一块石碑，","上面刻着：“吃水不忘挖井人，时刻想念毛主席。”"]},{"id":53,"grade":"一年级下册","title":"3 我多想去看看","paragraphs":["妈妈告诉我，沿着弯弯的小路，就会走出天山。","遥远的北京，有一座雄伟的天安门，","广场上的升旗仪式非常壮观。","我对妈妈说，我多想去看看，我多想去看看！","爸爸告诉我，沿着宽宽的公路，就会走出北京。","遥远的新疆，有美丽的天山，","雪山上盛开着洁白的雪莲。","我对爸爸说，我多想去看看，我多想去看看！"]},{"id":54,"grade":"一年级下册","title":"语文园地二","paragraphs":["拼一拼，写一写","认一认，连一连","选 一 选，圈 一 圈","涂 一 涂，填 一 填。","试 一 试，练 一 练","日 名 星 早 阳","土 地 尘 场","作者：[唐代] 贾岛","松下问童子，","言师采药去。","只在此山中，","云深不知处。","苍松下询问年少的学童，他说他的师傅已经去山中采药了。","只知道就在这座大山里，可山中云雾缭绕不知道他的行踪。","贾岛（779～843年），字浪（阆）仙，唐代诗人。汉族，唐朝河北道幽州范阳县（今河北省涿州市）人。早年出家为僧，号无本。自号“碣石山人”。据说在洛阳的时候后因当时有命令禁止和尚午后外出，贾岛做诗发牢骚，被韩愈发现其才华。后受教于韩愈，并还俗参加科举，但累举不中第。唐文宗的时候被排挤，贬做长江主簿。唐武宗会昌年初由普州司仓参军改任司户，未任病逝。","快乐的节日","小鸟在前面带路，","风啊吹向我们。","我们像春天一样，","来到花园里，来到草地上。","鲜艳的红领巾，美丽的衣裳","像许多花儿开放。","花儿向我们点头，","白杨树哗啦啦响。","它们同美丽的小鸟","向我们祝贺，向我们歌唱。","它们都说世界上","有我们就更美丽。","感谢亲爱的祖国，","让我们自由地成长。","我们像小鸟一样，","等身上的羽毛长得丰满，","就勇敢地向着高空飞翔，","飞向我们的理想。","跳啊，跳啊，跳啊！","亲爱的叔叔阿姨们，","同我们一起过着快乐的节日。"]},{"id":55,"grade":"一年级下册","title":"4 小公鸡和小鸭子","paragraphs":["小公鸡和小鸭子一块儿出去玩。","他们走进草地里。","小公鸡找到了许多虫子，吃得很欢。","小鸭子捉不到虫子，急得直哭。","小公鸡看见了，捉到虫子就给小鸭子吃。","他们走到小河边。","小鸭子说：“公鸡弟弟，我到河里捉鱼给你吃。”","小公鸡说：“我也去。”","小鸭子说：“不行，不行，你不会游泳，会淹死的！”","小公鸡不信，偷偷地跟在小鸭子后面，也下了水。","小鸭子正在水里捉鱼，忽然听见小公鸡喊救命。","他飞快地游到小公鸡身边，让小公鸡坐在自己的背上。","小公鸡上了岸，笑着对小鸭子说：“鸭子哥哥，谢谢你。”"]},{"id":56,"grade":"一年级下册","title":"5 树和喜鹊","paragraphs":["从前，这里只有一棵树，","树上只有一个鸟窝，鸟窝里只有一只喜鹊。","树很孤单，喜鹊也很孤单。","后来，这里种了好多好多树，","每棵树上都有鸟窝，每个鸟窝里都有喜鹊。","树有了邻居，喜鹊也有了邻居。","每天天一亮，喜鹊们叽叽喳喳叫几声，","打着招呼一起飞出去了。","天一黑，他们又叽叽喳喳地一起飞回窝里，","安安静静地睡觉了。","树很快乐，喜鹊也很快乐。"]},{"id":57,"grade":"一年级下册","title":"6 怎么都快乐","paragraphs":["一个人玩，很好！","独自一人，静悄悄的，正好用纸折船，折马……","踢毽子，跳绳，搭积木，","当然还有看书，画画，听音乐……","两个人玩，很好！","讲故事得有人听才行，你讲我听，我讲你听。","还有下象棋，打羽毛球，坐跷跷板……","三个人玩，很好！","讲故事多个人听更有劲，你讲我们听，我讲你们听。","两个人甩绳子，你跳，我跳，轮流跳。","四个人玩，很好！","五个人玩，很好！","许多人玩，更好！","人多，什么游戏都能玩，拔河，老鹰捉小鸡，","打排球，打篮球，踢足球……","连开运动会也可以。"]},{"id":58,"grade":"一年级下册","title":"语文园地三","paragraphs":["音序查字法口诀","音序查字要记牢，先把首个字母找。","字母下面找音节，看看它在第几页。","作者：[唐代] 李白","李白乘舟将欲行，","忽闻岸上踏歌声。","桃花潭水深千尺，","不及汪伦送我情。","李白乘舟将要远行离去，忽听岸上传来踏歌之声。","即使桃花潭水深至千尺，也比不上汪伦送我之情。","李白（701年－762年） ，字太白，号青莲居士，又号“谪仙人”，唐代伟大的浪漫主义诗人，被后人誉为“诗仙”，与杜甫并称为“李杜”，为了与另两位诗人李商隐与杜牧即“小李杜”区别，杜甫与李白又合称“大李杜”。据《新唐书》记载，李白为兴圣皇帝（凉武昭王李暠）九世孙，与李唐诸王同宗。其人爽朗大方，爱饮酒作诗，喜交友。李白深受黄老列庄思想影响，有《李太白集》传世，诗作中多为醉时写就，代表作有《望庐山瀑布》《行路难》《蜀道难》《将进酒》《早发白帝城》等。","和大人一起读","谁和谁好","谁和谁好？","藤和瓜好，","它们手拉手，","不吵也不闹。","谁和谁好？","蜜蜂和花好，","蜜蜂来采蜜，","花儿仰脸笑。","谁和谁好","谁和谁好？","白云和风好，","风往哪里刮，","云往哪里跑。","谁和谁好？","我和同学好，","大家唱着歌，","一起上学校。"]},{"id":59,"grade":"一年级下册","title":"7 静夜思","paragraphs":["作者：[唐代] 李白","床前明月光，","疑是地上霜。","举头望明月，","低头思故乡。","明亮的月光洒在窗户纸上，好像地上泛起了一层白霜。","我抬起头来，看那天窗外空中的明月，不由得低头沉思，想起远方的家乡。","李白（701年－762年） ，字太白，号青莲居士，又号“谪仙人”，唐代伟大的浪漫主义诗人，被后人誉为“诗仙”，与杜甫并称为“李杜”，为了与另两位诗人李商隐与杜牧即“小李杜”区别，杜甫与李白又合称“大李杜”。据《新唐书》记载，李白为兴圣皇帝（凉武昭王李暠）九世孙，与李唐诸王同宗。其人爽朗大方，爱饮酒作诗，喜交友。李白深受黄老列庄思想影响，有《李太白集》传世，诗作中多为醉时写就，代表作有《望庐山瀑布》《行路难》《蜀道难》《将进酒》《早发白帝城》等。"]},{"id":60,"grade":"一年级下册","title":"8 夜色","paragraphs":["我从前胆子很小很小，","天一黑就不敢往外瞧。","妈妈把勇敢的故事讲了又讲，","可我一看窗外心就乱跳……","爸爸晚上偏要拉我去散步，","原来花草都像白天一样微笑。","从此再黑再黑的夜晚，","我也能看见小鸟怎样在月光下睡觉……"]},{"id":61,"grade":"一年级下册","title":"9 端午粽","paragraphs":["一到端午节，外婆总会煮好一锅粽子，盼着我们回去。","粽子是用青青的箬竹叶包的，里面裹着白白的糯米，","中间有一颗红红的枣。","外婆一掀开锅盖，煮熟的粽子就飘出一股清香来。","剥开粽叶，咬一口粽子，真是又黏又甜。","外婆包的粽子十分好吃，花样也多。","除了红枣粽，还有红豆粽和鲜肉粽。","我们在外婆家美滋滋地吃了之后，","外婆还会装一小篮粽子要我们带回去，分给邻居吃。","长大后我了解到，人们端午节吃粽子，","传说是为了纪念爱国诗人屈原。"]},{"id":62,"grade":"一年级下册","title":"语文园地四","paragraphs":["一册书  一支铅笔","一台电视  一部手机","一件上衣  一条裤子 一床棉被","胆子 样子 粽子","爸爸 妈妈 哥哥","眼睛 喜欢 故事","尊老爱幼 其乐融融","血浓于水 手足情深","同心协力 同甘共苦","天伦之乐 欢聚一堂","胖乎乎的小手","全家人都喜欢兰兰画的这张画。","爸爸刚下班回来，拿起画，看了又看，把画贴在了墙上。兰兰不明白，问：“我只是画了自己的小手哇！我有那么多画，您为什么只贴这一张呢？”","爸爸说：“这胖乎乎的小手替我拿过拖鞋呀！”","妈妈下班回来，看见画，笑着说：“这胖乎乎的小手给我洗过手绢哪！”","姥姥从厨房出来，一眼就看见了画上红润润的小手，说：“这胖乎乎的小手帮我挠过痒痒啊！”","兰兰明白了全家人为什么都喜欢这张画。她高兴地说：“等我长大了，小手变成了大手，它会帮你们做更多的事情！”"]},{"id":63,"grade":"一年级下册","title":"5 动物儿歌","paragraphs":["蜻蜓半空展翅飞，","蝴蝶花间捉迷藏。","蚯蚓土里造宫殿，","蚂蚁地上运食粮。","蝌蚪池中游得欢，","蜘蛛房前结网忙。"]},{"id":64,"grade":"一年级下册","title":"6 古对今","paragraphs":["古对今，","圆对方。","严寒对酷暑，","春暖对秋凉。","晨对暮，","雪对霜。","和风对细雨，","朝霞对夕阳。","桃对李，","柳对杨。","莺歌对燕舞，","鸟语对花香。"]},{"id":65,"grade":"一年级下册","title":"7 操场上","paragraphs":["打球","拔河","拍皮球","跳高","跑步","踢足球","铃声响，下课了。","操场上，真热闹。","跳绳踢毽丢沙包，","天天锻炼身体好。"]},{"id":66,"grade":"一年级下册","title":"8 人之初","paragraphs":["人之初，性本善，","性相近，习相远。","苟不教，性乃迁，","教之道，贵以专。","子不学，非所宜，","幼不学，老何为？","玉不琢，不成器，","人不学，不知义。"]},{"id":67,"grade":"一年级下册","title":"语文园地五","paragraphs":["有饭能吃饱，","有水把茶泡。","有足快快跑，","有手轻轻抱。","有衣穿长袍，","有火放鞭炮。","吃 叫 吹 唱","抱 拔 捉 拍","跑 跳 踢 跟","芝麻开花 —— 节节高","竹篮打水 —— 一场空","十五个吊桶打水 —— 七上八下","唐僧骑马咚那个咚，","后面跟着个孙悟空。","孙悟空，跑得快，","后面跟着个猪八戒。","猪八戒，鼻子长，","后面跟着个沙和尚。","沙和尚，挑着箩，","后面跟着个老妖婆。","老妖婆，真正坏，","骗了唐僧和八戒。","唐僧八戒真糊涂，","是人是妖分不清。","分不清，上了当，","多亏悟空眼睛亮。","眼睛亮，冒金光，","高高举起金箍棒。","金箍棒，有力量，","妖魔鬼怪消灭光。"]},{"id":68,"grade":"一年级下册","title":"池上","paragraphs":["作者：[唐代] 白居易","小娃撑小艇，","偷采白莲回。","不解藏踪迹，","浮萍一道开。","小娃撑着小船，偷偷地从池塘里采了白莲回来。","他不懂得掩藏自己的行踪，浮萍被船儿荡开，水面上留下了一条长长的水线。","白居易（772年－846年），字乐天，号香山居士，又号醉吟先生，祖籍太原，到其曾祖父时迁居下邽，生于河南新郑。是唐代伟大的现实主义诗人，唐代三大诗人之一。白居易与元稹共同倡导新乐府运动，世称“元白”，与刘禹锡并称“刘白”。白居易的诗歌题材广泛，形式多样，语言平易通俗，有“诗魔”和“诗王”之称。官至翰林学士、左赞善大夫。公元846年，白居易在洛阳逝世，葬于香山。有《白氏长庆集》传世，代表诗作有《长恨歌》《卖炭翁》《琵琶行》等。"]},{"id":69,"grade":"一年级下册","title":"小池","paragraphs":["作者：[宋代] 杨万里","泉眼无声惜细流，","树阴照水爱晴柔。","小荷才露尖尖角，","早有蜻蜓立上头。","泉眼悄然无声是因舍不得细细的水流，映在水里的树阴喜欢这晴天里柔和的风光。","小荷叶刚从水面露出尖尖的角，早就有一只小蜻蜓立在它的上头。","杨万里（1127年10月29日－1206年6月15日），字廷秀，号诚斋。吉州吉水（今江西省吉水县黄桥镇湴塘村）人。南宋著名诗人、大臣，与陆游、尤袤、范成大并称为“中兴四大诗人”。因宋光宗曾为其亲书“诚斋”二字，故学者称其为“诚斋先生”。杨万里一生作诗两万多首，传世作品有四千二百首，被誉为一代诗宗。他创造了语言浅近明白、清新自然，富有幽默情趣的“诚斋体”。杨万里的诗歌大多描写自然景物，且以此见长。他也有不少篇章反映民间疾苦、抒发爱国感情的作品。著有《诚斋集》等。"]},{"id":70,"grade":"一年级下册","title":"11 浪花","paragraphs":["我在沙滩上玩耍。","浪花看见了，迈着轻轻的步子走来，悄悄地挠我的小脚丫。","好痒啊!","笑得我眼泪都流出来了，它才哗哗哗地笑着跑回家。","一会儿，浪花又唱着笑着跑来了。","这次，它给我捧来雪白的贝壳、青青的小虾。","我的小篮子都装不下啦!","哗哗哗，浪花跑去又跑来，就像淘气的小娃娃。"]},{"id":71,"grade":"一年级下册","title":"12 荷叶圆圆","paragraphs":["荷叶圆圆的，绿绿的。","小水珠说：“荷叶是我的摇篮。”","小水珠躺在荷叶上，眨着亮晶晶的眼睛。","小蜻蜓说：“荷叶是我的停机坪。”","小蜻蜓立在荷叶上，展开透明的翅膀。","小青蛙说：“荷叶是我的歌台。”","小青蛙蹲在荷叶上，呱呱地放声歌唱。","小鱼儿说：“荷叶是我的凉伞。”","小鱼儿在荷叶下笑嘻嘻地游来游去，","捧起一朵朵很美很美的水花。"]},{"id":72,"grade":"一年级下册","title":"13 要下雨了","paragraphs":["小白兔弯着腰在山坡上割草。","天阴沉沉的，小白兔直起身子，伸了伸腰。","小燕子从他头上飞过。","小白兔大声喊：“燕子，燕子，你为什么飞得这么低呀？”","燕子边飞边说：“要下雨了，空气很潮湿，","虫子的翅膀沾了小水珠，飞不高。","我正忙着捉虫子呢！”","是要下雨了吗？","小白兔往前边池子里一看，小鱼都游到水面上来了。","小白兔跑过去，问：“小鱼，小鱼，今天怎么有空出来呀？”","小鱼说：“要下雨了，水里闷得很，我们到水面上来透透气。","小白兔，你快回家吧，小心淋着雨。”","小白兔连忙挎起篮子往家跑。","他看见路边有一大群蚂蚁，就把要下雨的消息告诉了蚂蚁。","一只大蚂蚁说：“是要下雨了，我们正忙着搬东西呢！”","小白兔加快步子往家跑。","他一边跑一边喊：“妈妈，妈妈，要下雨了！”","轰隆隆，天空响起了一阵雷声。","哗，哗，哗，大雨真的下起来了！"]},{"id":73,"grade":"一年级下册","title":"语文园地六","paragraphs":["冰棍 西瓜 绿豆汤","凉席 蚊香 花露水","蒲扇 竹椅 萤火虫","牵牛 织女 北斗星","小白兔割草。","小白兔在山坡上割草。","小白兔弯着腰在山坡上割草。","小鸟飞得真低呀","你写作业了吗","天安门前的人非常多","爸爸看见我来了开心地笑了","朝霞不出门，晚霞行千里。","有雨山戴帽，无雨半山腰。","早晨下雨当日晴，晚上下雨到天明。","蚂蚁搬家蛇过道，大雨不久要来到。","夏夜多美","夏夜，公园里静悄悄的。","水池里，睡莲刚闭上眼睛，就被呜呜的哭声惊醒了。她睁开眼睛一看，是一只小蚂蚁趴在一根水草上。睡莲问：“小蚂蚁，你怎么啦？”","小蚂蚁说：“我不小心掉进池塘，上不了岸啦！”","“快上来吧！” 睡莲弯弯腰，让他爬了上来。","小蚂蚁非常感激，连声说：“谢谢您，睡莲姑姑。”","睡莲说：“今晚就在这儿住下吧！你瞧，夏夜多美呀！”","小蚂蚁摇摇头，说：“我得回家。要不，爸爸妈妈会着急的。”","他们的话让正在睡莲叶子上休息的蜻蜓听见了。他问：“睡莲姑姑，有什么事吗？”","“小蚂蚁想回家，可我没办法送他。”"]},{"id":74,"grade":"一年级下册","title":"14 文具的家","paragraphs":["铅笔，只用了一次，就不知丢到哪里去了。","橡皮，只擦了一回，再想擦，就找不着了。","贝贝一回到家，就向妈妈要新的铅笔、新的橡皮。","妈妈说：“你怎么天天丢东西呢？”","贝贝眨着一双大眼睛，对妈妈说：“我也不知道。”","妈妈说：“贝贝，你有一个家，","每天放学后，你都平平安安地回家。","你要想想办法，让你的铅笔、橡皮和转笔刀也有自己的家呀！”","贝贝想起来了，她书包里的文具盒，","就是这些文具的家。","从此，每天放学的时候，","贝贝都要仔细检查，铅笔呀，橡皮呀，转笔刀哇，","所有的小伙伴是不是都回家了。"]},{"id":75,"grade":"一年级下册","title":"15 一分钟","paragraphs":["丁零零，闹钟响了。","元元打了个哈欠，翻了个身，心想：再睡一分钟吧，","就睡一分钟，不会迟到的。","过了一分钟，元元起来了。","他很快地洗了脸，吃了早饭，就背着书包上学去了。","到了十字路口，他看见前面是绿灯，","刚想走过去，红灯亮了。","他叹了口气，说：“要是早一分钟就好了。”","他等了一会儿，才走过十字路口。","他向停在车站的公共汽车跑去，","眼看就要到了，车子开了。","他又叹了口气，说：“要是早一分钟就好了。”","他等啊等，一直不见公共汽车的影子，","元元决定走到学校去。","到了学校，已经上课了。","元元红着脸，低着头，坐到了自己的座位上。","李老师看了看手表，说：“元元，今天你迟到了二十分钟。”","元元非常后悔。"]},{"id":76,"grade":"一年级下册","title":"16 动物王国开大会","paragraphs":["动物王国要开大会，老虎让狗熊通知大家。","狗熊用喇叭大声喊：“大家注意，动物王国要开大会，","请你们都参加！”一连喊了十遍。","狐狸跑来了，对狗熊说：“你喊一百遍，大会也开不起来。”","“为什么？”狗熊问。","“因为你没告诉大家，大会在哪一天开，","是今天，还是明天，还是……”","狗熊一听，伸了伸舌头，做了个鬼脸，","连忙说：“对，对，对！”于是就去问老虎。","老虎说：“大会就在明天开，你快去通知大家吧！”","狗熊又用喇叭大声喊：“大家注意，动物王国要在明天开大会，","请你们都参加！”一连喊了十遍。","大灰狼跑来对狗熊说：“你喊一百遍，大会也开不起来。”","“为什么？”狗熊问。","“因为你没告诉大家，在明天什么时候开，","上午还是下午，几点钟开。”","狗熊一听，说：“有道理，有道理！”","于是又去问老虎。","老虎说：“大会就在明天上午八点开，你再去通知大家吧！”","狗熊又用喇叭大声喊：“大家注意，动物王国要在明天上午八点开大会，","请你们都参加！”一连喊了十遍。","梅花鹿跑来问狗熊：“大会在哪儿开呀？你得说清楚。”","狗熊捶捶自己的脑袋，说：“我怎么没问清楚呢？”","于是又去问老虎。","“哎呀！忘了说地点。","大会在森林广场开，你再去通知大家吧！”老虎对狗熊说。","“请注意啦！”狗熊又用喇叭大声喊，","“明天上午八点，在森林广场开大会，","请大家准时参加！”一连喊了十遍。","这一次，大家都明白了。","第二天上午，动物们都来到森林广场，准时参加了大会。"]},{"id":77,"grade":"一年级下册","title":"17 小猴子下山","paragraphs":["有一天，小猴子下山来，走到一块玉米地里。","他看见玉米结得又大又多，非常高兴，就掰了一个，扛着往前走。","小猴子扛着玉米，走到一棵桃树下。","他看见满树的桃子又大又红，非常高兴，就扔了玉米，去摘桃子。","小猴子捧着几个桃子，走到一片瓜地里。","他看见满地的西瓜又大又圆，非常高兴，就扔了桃子，去摘西瓜。","小猴子抱着一个大西瓜往回走。","走着走着，他看见一只小兔子蹦蹦跳跳的，真可爱，就扔了西瓜，去追小兔子。","小兔子跑进树林里，不见了。","小猴子只好空着手回家去。"]},{"id":78,"grade":"一年级下册","title":"语文园地七","paragraphs":["卫生间","牙刷 刷牙","梳子 梳头","毛巾 擦手","香皂 洗澡","脸盆 洗脸","蝴蝶 蜻蜓 蚂蚁","鸡 鸭 鸦","猫 猴 狮","不知则问，不能则学。——《荀子》","一日无书，百事荒芜。—— 陈寿","读万卷书，行万里路。—— 董其昌","狐狸和乌鸦","狐狸在树林里找吃的。他来到一棵大树下，看见乌鸦正站在树枝上，嘴里叼着一片肉。狐狸馋得直流口水。","他眼珠一转，对乌鸦说：“亲爱的乌鸦，您好吗？” 乌鸦没有回答。","狐狸赔着笑脸说：“亲爱的乌鸦，您的孩子好吗？” 乌鸦看了狐狸一眼，还是没有回答。","狐狸又摇摇尾巴，说：“亲爱的乌鸦，您的羽毛真漂亮，麻雀比起您来，可就差多了。您的嗓子真好，谁都爱听您唱歌，您就唱几句吧！”","乌鸦听了狐狸的话，非常得意，于是唱了起来。“哇……” 乌鸦刚一开口，肉就掉了下来。","狐狸叼起肉，一溜烟跑掉了"]},{"id":79,"grade":"一年级下册","title":"18 棉花姑娘","paragraphs":["棉花姑娘生病了，叶子上有许多可恶的蚜虫。","她多么盼望有医生来给她治病啊！","燕子飞来了。","棉花姑娘说：“请你帮我捉害虫吧！”","燕子说：“对不起，我只会捉空中飞的害虫，你还是请别人帮忙吧！”","啄木鸟飞来了。","棉花姑娘说：“请你帮我捉害虫吧！”","啄木鸟说：“对不起，我只会捉树干里的害虫，你还是请别人帮忙吧！”","青蛙跳来了。","棉花姑娘高兴地说：“请你帮我捉害虫吧！”","青蛙说：“对不起，我只会捉水田里的害虫，你还是请别人帮忙吧！”","忽然，一群圆圆的小虫子飞来了，很快就把蚜虫吃光了。","棉花姑娘惊奇地问：“你们是谁呀？”","小虫子说：“我们身上有七个斑点，就像七颗星星，大家叫我们七星瓢虫。”","不久，棉花姑娘的病好了，长出了碧绿碧绿的叶子，","吐出了雪白雪白的棉花。","她咧开嘴笑啦！"]},{"id":80,"grade":"一年级下册","title":"19 咕咚","paragraphs":["木瓜熟了。","一个木瓜从高高的树上掉进湖里，咕咚！","兔子吓了一跳，拔腿就跑。","小猴子看见了，问他为什么跑。","兔子一边跑一边叫：“不好啦，‘咕咚’来了，可怕极了！”","小猴子一听，就跟着跑起来。","他一边跑一边大叫：“不好啦，不好啦，‘咕咚’来了，大家快跑哇！”","这一下可热闹了。","狐狸呀，山羊啊，小鹿哇，一个跟着一个跑起来。","大伙儿一边跑一边叫：“快逃命啊，‘咕咚’来了！”","大象看见了，也跟着跑起来。","野牛拦住他，问：“‘咕咚’在哪里，你看见了？”","大象说：“没看见，大伙儿都说‘咕咚’来了。”","野牛又问大伙儿，大伙儿也都说没看见。","最后问兔子，兔子说：“是我听见的，‘咕咚’就在那边的湖里。”","兔子领着大家来到湖边。","正好又有一个木瓜从高高的树上掉进湖里，咕咚！","大伙儿你看看我，我看看你，都笑了。"]},{"id":81,"grade":"一年级下册","title":"20 小壁虎借尾巴","paragraphs":["小壁虎在墙角捉蚊子，一条蛇咬住了他的尾巴。","小壁虎一挣，挣断尾巴逃走了。","没有尾巴多难看哪！","小壁虎想：向谁去借一条尾巴呢？","小壁虎爬呀爬，爬到小河边。","他看见小鱼摇着尾巴，在河里游来游去。","小壁虎说：“小鱼姐姐，您把尾巴借给我行吗？”","小鱼说：“不行啊，我要用尾巴拨水呢。”","小壁虎爬呀爬，爬到大树上。","他看见老牛甩着尾巴，在树下吃草。","小壁虎说：“牛伯伯，您把尾巴借给我行吗？”","老牛说：“不行啊，我要用尾巴赶蝇子呢。”","小壁虎爬呀爬，爬到房檐下。","他看见燕子摆着尾巴，在空中飞来飞去。","小壁虎说：“燕子阿姨，您把尾巴借给我行吗？”","燕子说：“不行啊，我要用尾巴掌握方向呢。”","小壁虎借不到尾巴，心里很难过。","他爬呀爬，爬回家里找妈妈。","小壁虎把借尾巴的事告诉了妈妈。","妈妈笑着说：“傻孩子，你转过身子看看。”","小壁虎转身一看，高兴得叫了起来：“我长出一条新尾巴啦！”"]},{"id":82,"grade":"一年级下册","title":"语文园地八","paragraphs":["口 + 少 = 吵","丁 + 页 = 顶","王 + 见 = 现","月 + 半 = 胖","飘 - 风 = 票","房 - 方 = 户","校 - 木 = 交","爸 - 巴 = 父","小熊住山洞","小熊一家住在山洞里，熊爸爸想砍一些树，盖一间新房子。","春天，熊爸爸带着小熊来到森林里。树上开满了花，小熊说：“爸爸，树上的花开得多漂亮啊！我们还是不要砍了吧！”","夏天，小熊和熊爸爸来到森林里。树上长满了绿油油的叶子，小熊舍不得，又说：“爸爸，树叶长得多绿呀！就别砍了吧！”","秋天，小熊和熊爸爸来到森林里。树上结着红红的果子，小熊对爸爸说：“树上结了那么多果子，我不忍心砍。”","冬天，小熊和熊爸爸来到森林里。熊爸爸刚举起斧头，忽然听到了树上鸟儿的声音，好像在说：“求求你，别毁了我们的家！” 小熊连忙对熊爸爸说：“爸爸，你砍了这棵树，小鸟们就没有家了，别砍了吧！”","就这样，一年又一年，小熊一家没有砍树，一直住在山洞里。森林里的动物都很感激小熊一家，给他们送来了好多鲜花和果子","作者：[明代] 唐寅","头上红冠不用裁，","满身雪白走将来。","平生不敢轻言语，","一叫千门万户开。","它头上的红色冠子不用裁剪是天生的，身披雪白的羽毛雄赳赳地走来。","一生之中它从来不敢轻易鸣叫，但是它叫的时候，千家万户的门都打开。","唐寅（1470—1523），字伯虎，一字子畏，号六如居士、桃花庵主、鲁国唐生、逃禅仙吏等，汉族，南直隶苏州吴县人。明代著名画家、文学家。据传他于明宪宗成化六年庚寅年寅月寅日寅时生。他玩世不恭而又才气横溢，诗文擅名，与祝允明、文征明、徐祯卿并称“江南四大才子（吴门四才子）”，画名更著，与沈周、文征明、仇英并称“吴门四家”。"]},{"id":83,"grade":"二年级上册","title":"1 小蝌蚪找妈妈","paragraphs":["池塘里有一群小蝌蚪，大大的脑袋，黑灰色的身子，甩着长长的尾巴，快活地游来游去。","小蝌蚪游哇游，过了几天，长出了两条后腿。他们看见鲤鱼妈妈在教小鲤鱼捕食，就迎上去，问：“鲤鱼阿姨，我们的妈妈在哪里？”鲤鱼妈妈说：“你们的妈妈四条腿，宽嘴巴。你们到那边去找吧！”","小蝌蚪游哇游，过了几天，长出了两条前腿。他们看见一只乌龟摆动着四条腿在水里游，连忙追上去，叫着：“妈妈，妈妈！”乌龟笑着说：“我不是你们的妈妈。你们的妈妈头顶上有两只大眼睛，披着绿衣裳。你们到那边去找吧！”","小蝌蚪游哇游，过了几天，尾巴变短了。他们游到荷花旁边，看见荷叶上蹲着一只大青蛙，披着碧绿的衣裳，露着雪白的肚皮，鼓着一对大眼睛。","小蝌蚪游过去，叫着：“妈妈，妈妈！”青蛙妈妈低头一看，笑着说：“好孩子，你们已经长成青蛙了，快跳上来吧！”他们后腿一蹬，向前一跳，蹦到了荷叶上。","不知什么时候，小青蛙的尾巴已经不见了。他们跟着妈妈，天天去捉害虫。"]},{"id":84,"grade":"二年级上册","title":"2 我是什么","paragraphs":["我会变。太阳一晒，我就变成汽。升到天空，我又变成无数极小极小的点儿，连成一片，在空中飘浮。有时候我穿着白衣服，有时候我穿着黑衣服，早晨和傍晚我又把红袍披在身上。人们叫我“云”。","我在空中越升越高，体温越来越低，变成了无数小水滴。小水滴聚在一起落下来，人们叫我“雨”。有时候我变成小硬球打下来，人们就叫我“冰雹”。到了冬天，我变成小花朵飘下来，人们又叫我“雪”。","平常我在池子里睡觉，在小溪里散步，在江河里奔跑，在海洋里跳舞，唱歌，开大会。","有时候我很温和，有时候我却很暴躁。我做过许多好事，灌溉田地，发动机器，帮助人们工作。我也做过许多坏事，淹没庄稼，冲毁房屋，给人们带来灾害。人们想出种种办法管住我，让我光做好事，不做坏事。","小朋友，你们猜猜，我是什么？"]},{"id":85,"grade":"二年级上册","title":"3 植物妈妈有办法","paragraphs":["孩子如果已经长大，","就得告别妈妈，四海为家。","牛马有脚，鸟有翅膀，","植物旅行又用什么办法？","蒲公英妈妈准备了降落伞，","把它送给自己的娃娃。","只要有风轻轻吹过，","孩子们就乘着风纷纷出发。","苍耳妈妈有个好办法，","她给孩子穿上带刺的铠甲。","只要挂住动物的皮毛，","孩子们就能去田野、山洼。","石榴妈妈的胆子挺大，","她不怕小鸟吃掉娃娃。","孩子们在鸟肚子里睡上一觉，","就会钻出来落户安家。","豌豆妈妈更有办法，","她让豆荚晒在太阳底下。","啪的一声，豆荚炸开，","孩子们就蹦着跳着离开妈妈。","植物妈妈的办法很多很多，","不信你就仔细观察。","那里有许许多多的知识，","粗心的小朋友却得不到它。"]},{"id":86,"grade":"二年级上册","title":"语文园地","paragraphs":["手套 帽子 登山鞋 运动裤","地图 水壶 帐篷 指南针","套 帽 登 鞋 裤","图 壶 帐 篷 指 针","作者：[宋代] 王安石","墙角数枝梅，","凌寒独自开。","遥知不是雪，","为有暗香来。","墙角有几枝梅花，正冒着严寒独自盛开。","远远的就知道洁白的梅花不是雪，因为有梅花的幽香传来。","王安石（1021年12月18日－1086年5月21日），字介甫，号半山，谥文，封荆国公。世人又称王荆公。汉族，北宋抚州临川人（今江西省抚州市临川区邓家巷人），中国北宋著名政治家、思想家、文学家、改革家，唐宋八大家之一。欧阳修称赞王安石：“翰林风月三千首，吏部文章二百年。老去自怜心尚在，后来谁与子争先。”传世文集有《王临川集》、《临川集拾遗》等。其诗文各体兼擅，词虽不多，但亦擅长，且有名作《桂枝香》等。而王荆公最得世人共传之诗句莫过于《泊船瓜洲》中的“春风又绿江南岸，明月何时照我还。”","狮子大王住在炎热的非洲。","夏天来了，狮子大王不停地叫着：“热啊，热啊。”河马说：“听说在南极有一种很冷很冷的东西，叫作冰。”","狮子大王听了，立刻给南极的企鹅写了一封信，请他寄一块冰来。","好多天以后，企鹅收到了信。他说：“啊，狮子大王想要一块冰，太容易了，我这里可是冰天雪地啊。”企鹅挑了一块冰，装在袋子里，给狮子大王寄去。","装冰的箱子先上了轮船，又上了飞机。","过了很多天，狮子大王收到了箱子。他打开一看，觉得好奇怪：“呀，怎么是一袋水？”","狮子大王生气地把箱子退回去了，还给企鹅写了一封信。","又过了很多天，企鹅收到了箱子和信。","狮子大王的信上写着：“我请你寄块冰来，你为什么寄来一袋水？”企鹅连忙把箱子打开：“这明明是冰嘛，怎么说是水呢？”看着袋子里的冰块，企鹅也糊涂了。","迎上去 追上去","穿衣裳 披红袍","甩甩头 摇摇头","我的脾气可怪了，有时候我很温和，有时候我却很暴躁。","平常我在池子里睡觉，在小溪里散步，在江河里奔跑，在海洋里跳舞，唱歌，开大会。"]},{"id":87,"grade":"二年级上册","title":"1 场景歌","paragraphs":["一只海鸥，一条帆船。","一艘军舰，一处港湾。","一方鱼塘，一块稻田。","一行垂柳，一座花园。","一道小溪，一座石桥。","一丛翠竹，一群飞鸟。","一面队旗，一把铜号。","一队“红领巾”，一片欢笑。"]},{"id":88,"grade":"二年级上册","title":"2 树之歌","paragraphs":["杨树高，榕树壮，","梧桐树叶像手掌。","枫树秋天叶儿红，","松柏四季披绿装。","木棉喜暖在南方，","桦树耐寒守北疆。","银杏水杉活化石，","金桂开花满院香。"]},{"id":89,"grade":"二年级上册","title":"3 拍手歌","paragraphs":["你拍一，我拍一，","动物世界很新奇。","你拍二，我拍二，","孔雀锦鸡是伙伴。","你拍三，我拍三，","雄鹰飞翔云彩间。","你拍四，我拍四，","天空雁群会写字。","你拍五，我拍五，","丛林深处有猛虎。","你拍六，我拍六，","黄鹂百灵唱不休。","你拍七，我拍七，","竹林熊猫在嬉戏。","你拍八，我拍八，","大小动物都有家。","你拍九，我拍九，","人和动物是朋友。","你拍十，我拍十，","保护动物是大事。"]},{"id":90,"grade":"二年级上册","title":"4 田家四季歌","paragraphs":["春季里，春风吹，","花开草长蝴蝶飞。","麦苗儿多嫩，桑叶儿正肥。","夏季里，农事忙，","采桑养蚕又插秧。","早起勤耕作，归来戴月光。","秋季里，稻上场，","谷像黄金粒粒香。","身体虽辛苦，心里喜洋洋。","冬季里，雪初晴，","新制棉衣暖又轻。","一年农事了，大家笑盈盈。"]},{"id":91,"grade":"二年级上册","title":"语文园地","paragraphs":["己所不欲，勿施于人。——《论语》","与朋友交，言而有信。——《论语》","不以规矩，不能成方圆。——《孟子》","正月山茶满盆开，","二月迎春初开放。","三月桃花红十里，","四月牡丹国色香。","五月石榴红似火，","六月荷花满池塘。","七月茉莉花如雪，","八月桂花满枝香。","九月菊花姿百态，","十月芙蓉正上妆。","冬月水仙案头供，","腊月寒梅斗冰霜。"]},{"id":92,"grade":"二年级上册","title":"4 曹冲称象","paragraphs":["古时候有个叫曹操的人。别人送他一头大象，他很高兴，带着儿子曹冲和官员们一同去看。","大象又高又大，身子像一堵墙，腿像四根柱子。官员们一边看一边议论：“这么大的象，到底有多重呢？”","曹操问：“谁有办法把这头大象称一称？”有的说：“得造一杆大秤，砍一棵大树做秤杆。”有的说：“有了大秤也不行啊，谁有那么大的力气提得起这杆大秤呢？”曹操听了直摇头。","曹冲才七岁，他站出来，说：“我有个办法。把大象赶到一艘大船上，看船身下沉多少，就沿着水面，在船舷上画一条线。再把大象赶上岸，往船上装石头，装到船下沉到画线的地方为止。然后称一称船上的石头。石头有多重，大象就有多重。”","曹操微笑着点了点头。他叫人照曹冲说的办法去做，果然称出了大象的重量。"]},{"id":93,"grade":"二年级上册","title":"5 玲玲的画","paragraphs":["玲玲得意地端详着自己画的《我家的一角》。这幅画明天就要参加评奖了。","“玲玲，时间不早了，快去睡吧！”爸爸又在催她了。","“好的，我把画笔收拾一下就去睡。”","就在这时候，水彩笔啪的一声掉到了纸上，把画弄脏了。玲玲伤心地哭了起来。","“怎么了，玲玲？”爸爸放下报纸问。","“我的画弄脏了，另画一张也来不及了。”","爸爸拿起画，仔细地看了看，说：“别哭，孩子。在这儿画点儿什么，不是很好吗？”","玲玲想了想，拿起笔，在弄脏的地方画了一只小花狗。小花狗眯着眼睛，懒洋洋地趴在楼梯上，整张画看上去更好了。玲玲满意地笑了。","爸爸看了，高兴地说：“看到了吧，孩子。好多事情并不像我们想象的那么糟。只要肯动脑筋，坏事有时也能变成好事。”"]},{"id":94,"grade":"二年级上册","title":"6 一封信","paragraphs":["爸爸出国了，要过半年才能回来。今天，露西想给爸爸写一封信。","妈妈还在厂里，露西早早回到家。她打开空调，又洗了一些土豆，削好后放在锅里。她朝窗外望了一眼。好了，她想，现在可以开始写信了。她拿出一沓纸，一支圆珠笔。","“亲爱的爸爸，”露西写道，“你不在，我们很不开心。以前每天早上你一边刮胡子，一边逗我玩。还有，家里的台灯坏了，我们修不好。从早到晚，家里总是很冷清。”","这时，妈妈回来了。她拍拍露西的肩膀，问：“是在给爸爸写信吗？”","“是的。可是我写得不好。”露西说着，把纸揉成一团。","“那我们一起重新写吧！”说着，妈妈在她身旁坐下来。","露西边说边写：“亲爱的爸爸……”","“我们过得挺好。”妈妈接着露西的话说。","露西写完这一句，想到了小狗希比希，写道：“太阳闪闪发光。阳光下，我们的希比希又蹦又跳。”","妈妈说：“请爸爸告诉我们，螺丝刀放在哪儿了。”","露西笑了，她记下妈妈的话，接着写道：“这样，我们就能自己修台灯了。”","“还有，下个星期天我们去看电影。”妈妈说。","“啊，太好啦！”露西叫了起来。","“爸爸，我们天天想你。”露西在信的结尾，画了一大束鲜花。"]},{"id":95,"grade":"二年级上册","title":"7 妈妈睡了","paragraphs":["妈妈睡了。妈妈哄我午睡的时候，自己先睡着了，睡得好熟，好香。","睡梦中的妈妈真美丽。明亮的眼睛闭上了，紧紧地闭着；弯弯的眉毛，也在睡觉，睡在妈妈红润的脸上。","睡梦中的妈妈好温柔。妈妈微微地笑着。是的，她在微微地笑着，嘴巴、眼角都笑弯了，好像在睡梦中，妈妈又想好了一个故事，等会儿讲给我听……","睡梦中的妈妈好累。妈妈的呼吸那么沉。她乌黑的头发粘在微微渗出汗珠的额头上。窗外，小鸟在唱着歌，风儿在树叶间散步，发出沙沙的响声，可是妈妈全听不到。她干了好多活儿，累了，乏了，她真该好好睡一觉。"]},{"id":96,"grade":"二年级上册","title":"语文园地","paragraphs":["弹钢琴  练舞蹈  唱京戏","画图画  捏泥人  下围棋","滚铁环  荡秋千  滑滑梯","弹 钢 琴 捏 泥","滚 铁 环 荡 滑 梯","官员们一边看一边议论。","爸爸一边刮胡子，一边逗露西玩。","老师一边说，一边拿着笔在纸上写。","作者：[唐代] 胡令能","蓬头稚子学垂纶，","侧坐莓苔草映身。","路人借问遥招手，","怕得鱼惊不应人。","一个头发蓬乱、面孔青嫩的小孩在河边学钓鱼，侧身坐在青苔上绿草遮映衬他的身影。","听到有过路的人问路远远地摆了摆手，不敢回应路人生怕惊动了鱼儿。","胡令能（785-826年），唐诗人，隐居圃田（河南中牟县）。唐贞元、元和时期人。家贫，年轻时以修补锅碗盆缸为生，人称“胡钉铰”。他的诗语言浅显而构思精巧，生活情趣很浓，现仅存七绝4首。唐贞元、元和时期人。圃田隐者，唐诗人少为负局锼钉之业。梦人剖其腹，以一卷书内之，遂能吟咏，远近号为胡钉铰。诗四首，皆写得十分生动传神、精妙超凡，不愧是仙家所赠之诗作。","王二小是儿童团员。他常常一边放牛，一边替八路军放哨。","有一天，日寇来扫荡，走到山口迷了路。敌人看见王二小在山坡上放牛，就叫他带路。","王二小装着顺从的样子走在前面，把敌人带进了八路军的埋伏圈。","突然，四面八方响起了枪声。敌人知道上了当，就杀害了小英雄王二小。","这时候，八路军从山上冲下来，消灭了全部敌人。","白云  乌云  朝霞  晚霞","雨点  霜冻  雪花  冰雹","小溪  河流  湖泊  海洋","含苞欲放  百花争艳","花红柳绿  春色满园","书籍是人类进步的阶梯。——高尔基"]},{"id":97,"grade":"二年级上册","title":"登鹳雀楼","paragraphs":["作者：[唐代] 王之涣","白日依山尽，","黄河入海流。","欲穷千里目，","更上一层楼。","站在高楼上，只见夕阳依傍着山峦慢慢沉落，滔滔黄河朝着大海汹涌奔流。","想要看到千里之外的风光，那就要再登上更高的一层楼。","王之涣（688年—742年），是盛唐时期的著名诗人，字季凌，汉族，绛州（今山西新绛县）人。豪放不羁，常击剑悲歌，其诗多被当时乐工制曲歌唱。名动一时，他常与高适、王昌龄等相唱和，以善于描写边塞风光著称。其代表作有《登鹳雀楼》、《凉州词》等。“白日依山尽，黄河入海流。欲穷千里目，更上一层楼”，更是千古绝唱。"]},{"id":98,"grade":"二年级上册","title":"望庐山瀑布","paragraphs":["作者：[唐代] 李白","日照香炉生紫烟，","遥看瀑布挂前川。","飞流直下三千尺，","疑是银河落九天。","香炉峰在阳光的照射下生起紫色烟霞，从远处看去瀑布好似白色绢绸悬挂山前。","高崖上飞腾直落的瀑布好像有几千尺，让人怀疑是银河从天上泻落到人间。","李白（701年－762年） ，字太白，号青莲居士，又号“谪仙人”，唐代伟大的浪漫主义诗人，被后人誉为“诗仙”，与杜甫并称为“李杜”，为了与另两位诗人李商隐与杜牧即“小李杜”区别，杜甫与李白又合称“大李杜”。据《新唐书》记载，李白为兴圣皇帝（凉武昭王李暠）九世孙，与李唐诸王同宗。其人爽朗大方，爱饮酒作诗，喜交友。李白深受黄老列庄思想影响，有《李太白集》传世，诗作中多为醉时写就，代表作有《望庐山瀑布》《行路难》《蜀道难》《将进酒》《早发白帝城》等。"]},{"id":99,"grade":"二年级上册","title":"9 黄山奇石","paragraphs":["中外闻名的黄山风景区在我国安徽省南部。那里景色秀丽神奇，尤其是那些怪石，有趣极了。","就说“仙桃石”吧，它好像从天上飞下来的一个大桃子，落在山顶的石盘上。","在一座陡峭的山峰上，有一只“猴子”。它两只胳膊抱着腿，一动不动地蹲在山头，望着翻滚的云海。这就是有趣的“猴子观海”。","“仙人指路”就更有趣了！远远望去，那巨石真像一位仙人站在高高的山峰上，伸着手臂指向前方。","每当太阳升起，有座山峰上的几块巨石，就变成了一只金光闪闪的雄鸡。它伸着脖子，对着天都峰不住地啼叫。不用说，这就是著名的“金鸡叫天都”了。","黄山的奇石还有很多，如“天狗望月”“狮子抢球”“仙女弹琴”。那些叫不出名字的奇形怪状的岩石，正等你去给它们起名字呢！"]},{"id":100,"grade":"二年级上册","title":"10 日月潭","paragraphs":["日月潭是我国台湾省最大的一个湖。它在台湾省中部的山区。那里群山环绕，树木茂盛，周围有许多名胜古迹。","日月潭很深，湖水碧绿。湖中央有个美丽的小岛，把湖水分成两半，北边像圆圆的太阳，叫日潭；南边像弯弯的月亮，叫月潭。","清晨，湖面上飘着薄薄的雾。天边的晨星和山上的点点灯光，隐隐约约地倒映在湖水中。","中午，太阳高照，整个日月潭的美景和周围的建筑，都清晰地展现在眼前。要是下起蒙蒙细雨，日月潭好像披上轻纱，周围的景物一片朦胧，就像童话中的仙境。","日月潭风光秀丽，吸引了许许多多的中外游客。"]},{"id":101,"grade":"二年级上册","title":"11 葡萄沟","paragraphs":["新疆吐鲁番有个地方叫葡萄沟，那里出产水果。五月有桑葚，六月有杏子、无花果，到了七月份，人们最喜爱的葡萄成熟了。","葡萄种在山坡的梯田上。茂密的枝叶向四面展开，就像搭起了一个个绿色的凉棚。葡萄一大串一大串地挂在绿叶底下，有红的、白的、紫的、淡绿的，五光十色，美丽极了。要是这时候你到葡萄沟去，热情好客的维吾尔族老乡，准会摘下最甜的葡萄，让你吃个够。","收下来的葡萄，有的运到城市去，有的运到晾房里制成葡萄干。晾房修在山坡上，四壁留着许多小孔，里面钉着许多木架子。成串的葡萄挂在架子上，利用流动的热空气，让水分蒸发掉，就成了葡萄干。这里生产的葡萄干颜色鲜，味道甜，非常有名。","葡萄沟真是个好地方。"]},{"id":102,"grade":"二年级上册","title":"语文园地","paragraphs":["昌  铺  调  硬","卧  限  乘  售","白色——雪白  米白  奶白","红色——火红  桃红  枣红","黄色——土黄  鹅黄  金黄","绿色——草绿  翠绿  墨绿","我发现在“白”字前面加上“雪”“米”“奶”，可以用来形容不同的白色。","有山皆图画，","无水不文章。","白马西风塞上，","杏花烟雨江南。","清风明月本无价，","近水远山皆有情。","雾锁山头山锁雾，","天连水尾水连天。","孩子们爱家乡，也爱画自己美丽的家乡。","涛涛的家乡在海边。他画的海那么蓝，那么宽。一艘艘船上装满了鱼和虾。那个在海边捡贝壳的孩子，就是涛涛。","山山的家乡在山里。她画的山那么高，水那么清。房前屋后都是又高又大的树。画上的山山，挎着小竹篮，正要到树林里去采蘑菇呢。","平平的家乡在平原。她画的平原那么平坦，那么宽广。有金黄的稻子，雪白的棉花，还有一大片一大片绿油油的菜地。屋前有鸡、鸭，屋后有几丛青翠的竹子。那个正在田野上奔跑的小女孩，就是平平。","青青的家乡在草原。他画的草原一眼望不到边。草长得又绿又密，羊群在草原上走来走去。一匹骏马从远处奔来，青青正骑在马上赶着羊群。","京京的家乡在城市。他画的城市那么美。宽宽的街道，高高的楼房，还有好几个街心公园。那个正跑向图书馆的小男孩，就是京京。","小朋友，你的家乡一定也很美，请你画出来吧！","柳条  云朵  枫叶","椅子  路灯  胡子  鞋","爸爸的鞋像小船。","弟弟的鞋像鸟窝。","八路军隐蔽在山里，敌人很难发现。","去还是不去？小明拿不定主意，感到很烦恼。","那美丽如画的山水，怎能不令人流连忘返？"]},{"id":103,"grade":"二年级上册","title":"12 坐井观天","paragraphs":["青蛙坐在井里。小鸟飞来，落在井沿上。","青蛙问小鸟：“你从哪儿来呀？”","小鸟回答说：“我从天上来，飞了一百多里，口渴了，下来找点儿水喝。”","青蛙说：“朋友，别说大话了！天不过井口那么大，还用飞那么远吗？”","小鸟说：“你弄错了。天无边无际，大得很哪！”","青蛙笑了，说：“朋友，我天天坐在井里，一抬头就能看见天。我不会弄错的。”","小鸟也笑了，说：“朋友，你是弄错了。不信，你跳出井来看一看吧。”"]},{"id":104,"grade":"二年级上册","title":"13 寒号鸟","paragraphs":["山脚下有一堵石崖，崖上有一道缝，寒号鸟就把这道缝当作自己的窝。石崖前面有一条河，河边有一棵大杨树，杨树上住着喜鹊。寒号鸟和喜鹊面对面住着，成了邻居。","几阵秋风，树叶落尽，冬天快要到了。","有一天，天气晴朗。喜鹊一早飞出去，东寻西找，衔回来一些枯草，就忙着做窝，准备过冬。寒号鸟却只知道出去玩，累了就回来睡觉。喜鹊说：“寒号鸟，别睡了。天气暖和，赶快做窝。”","寒号鸟不听劝告，躺在崖缝里对喜鹊说：“傻喜鹊，不要吵。太阳高照，正好睡觉。”","冬天说到就到，寒风呼呼地刮着。喜鹊住在温暖的窝里。寒号鸟在崖缝里冻得直打哆嗦，不停地叫着：“哆啰啰，哆啰啰，寒风冻死我，明天就做窝。”","第二天清早，风停了，太阳暖暖的，好像又是春天了。喜鹊来到崖缝前劝寒号鸟：“趁天晴，快做窝。现在懒惰，将来难过。”","寒号鸟还是不听劝告，伸伸懒腰，答道：“傻喜鹊，别啰嗦，天气暖和，得过且过。”","寒冬腊月，大雪纷飞。北风像狮子一样狂吼，崖缝里冷得像冰窖。寒号鸟重复着哀号：“哆啰啰，哆啰啰，寒风冻死我，明天就做窝。”","天亮了，太阳出来了，喜鹊在枝头呼唤寒号鸟。可是，寒号鸟已经在夜里冻死了。"]},{"id":105,"grade":"二年级上册","title":"14 我要的是葫芦","paragraphs":["从前，有个人种了一棵葫芦。细长的葫芦藤上长满了绿叶，开出了几朵雪白的小花。花谢以后，藤上挂了几个小葫芦。多么可爱的小葫芦啊！那个人每天都要去看几次。","有一天，他看见叶子上爬着一些蚜虫，心里想，有几个虫子怕什么！他盯着小葫芦自言自语地说：“我的小葫芦，快长啊，快长啊！长得赛过大南瓜才好呢！”","一个邻居看见了，对他说：“你别光盯着葫芦了，叶子上生了蚜虫，快治一治吧！”那个人感到很奇怪，说：“什么？叶子上的虫还用治？我要的是葫芦。”","没过几天，叶子上的蚜虫更多了。小葫芦慢慢地变黄了，一个一个都落了。"]},{"id":106,"grade":"二年级上册","title":"语文园地","paragraphs":["作者：[唐代] 柳宗元","千山鸟飞绝，","万径人踪灭。","孤舟蓑笠翁，","独钓寒江雪。","所有的山上，飞鸟的身影已经绝迹，所有道路都不见人的踪迹。","江面孤舟上，一位披戴着蓑笠的老翁，独自在漫天风雪中垂钓。","柳宗元（773年－819年），字子厚，唐代河东（今山西运城）人，杰出诗人、哲学家、儒学家乃至成就卓著的政治家，唐宋八大家之一。著名作品有《永州八记》等六百多篇文章，经后人辑为三十卷，名为《柳河东集》。因为他是河东人，人称柳河东，又因终于柳州刺史任上，又称柳柳州。柳宗元出身河东柳氏，与刘禹锡并称“刘柳”，与韩愈并称为“韩柳”，与王维、孟浩然、韦应物并称“王孟韦柳”。柳宗元一生留诗文作品达600余篇，其文的成就大于诗。骈文有近百篇，散文论说性强，笔锋犀利，讽刺辛辣。","从前，有个人坐船过江。一不小心，挂在他身上的宝剑掉进江里去了。那个人马上拿出小刀在船舷上刻了一个记号。","旁边的人催他：“还不赶快捞！在船舷上刻记号有什么用啊？”","那个人不慌不忙地指了指刻的记号，说：“不用着急，宝剑是从这儿掉下去的，等船靠了岸，我就从这儿跳下去，准能把宝剑捞上来。”","不言不语  只言片语","三言两语  千言万语","豪言壮语  少言寡语","自言自语  甜言蜜语","细长的葫芦藤上长满了绿叶，开出了几朵雪白的小花。","茂密的枝叶向四面展开，就像搭起了一个个绿色的凉棚。"]},{"id":107,"grade":"二年级上册","title":"15 八角楼上","paragraphs":["在井冈山艰苦斗争的年代，毛主席住在茅坪村的八角楼。每当夜幕降临的时候，八角楼上的灯就亮了。","这是个寒冬腊月的深夜，毛主席穿着单军衣，披着薄毯子，坐在竹椅上写文章。他右手握着笔，左手轻轻地拨了拨灯芯，灯光更加明亮了。凝视着这星星之火，毛主席在沉思，连毯子滑落下来也没有察觉到。就在这盏清油灯下，毛主席写下了许多光辉著作，照亮了中国革命胜利的道路。"]},{"id":108,"grade":"二年级上册","title":"16 朱德的扁担","paragraphs":["1928年，朱德同志带领队伍到井冈山，跟毛泽东同志带领的队伍会师了。红军在山上，山下不远处就是敌人。","红军要巩固井冈山根据地，粉碎敌人的围攻，需要储备足够的粮食。井冈山上生产的粮食不多，常常要抽出一些人到山下宁冈的茅坪去挑粮。从井冈山到茅坪，来回有五六十里，山高路陡，非常难走。可是每次挑粮，大家都争着去。","朱德同志也跟战士们一块儿去挑粮。他穿着草鞋，戴着斗笠，挑起粮食，跟大家一块儿爬山。白天挑粮爬山，晚上还常常整夜整夜地研究怎样跟敌人打仗。大家看了心疼，就把他那根扁担藏了起来。不料，朱德同志又找来一根扁担，写上“朱德的扁担”五个字。","大家见了，越发敬爱朱德同志，不好意思再藏他的扁担了。"]},{"id":109,"grade":"二年级上册","title":"17 难忘的泼水节","paragraphs":["火红火红的凤凰花开了，傣族人民一年一度的泼水节又到了。","1961年的泼水节，傣族人民特别高兴，因为敬爱的周恩来总理和他们一起过泼水节。","那天早晨，人们敲起象脚鼓，从四面八方赶来了。为了欢迎周总理，人们在地上撒满了凤凰花的花瓣，好像铺上了鲜红的地毯。一条条龙船驶过江面，一串串花炮升上天空。人们欢呼着：“周总理来了！”","周总理身穿对襟白褂、咖啡色长裤，头上包着一条水红色头巾，笑容满面地来到人群中。他接过一只象脚鼓，敲着欢乐的鼓点，踩着凤凰花铺成的“地毯”，同傣族人民一起跳舞。","开始泼水了。周总理一手端着盛满清水的银碗，一手拿着柏树枝蘸了水，向人们泼洒，为人们祝福。傣族人民一边欢呼，一边向周总理泼水，祝福他健康长寿。","清清的水，泼啊，洒啊！周总理和傣族人民笑啊，跳啊，是那么开心！","多么幸福啊，1961年的泼水节！","多么令人难忘啊，1961年的泼水节！"]},{"id":110,"grade":"二年级上册","title":"18 刘胡兰","paragraphs":["1947年1月12日，天阴沉沉的，国民党反动派包围了云周西村。由于叛徒的出卖，年轻的共产党员刘胡兰被捕了，关在一座庙里。","敌人问刘胡兰：“现在有人供出来你是共产党员！你们村里还有谁是？”刘胡兰回答：“就我一个！”敌人想收买刘胡兰，对她说：“说出来，就给你一份地。”刘胡兰大声回答：“给我一个金人，我也不说！”敌人又威胁他说：“不说就打死你！”刘胡兰愤怒地回答：“打死也不说！”刘胡兰像钢铁铸成似的，一点儿也不动摇。","敌人把刘胡兰拉到庙门口的广场上，当着她和乡亲们的面，铡死了被捕的六名革命群众 。敌人指着血淋淋的铡刀说：“再不说，也铡死你！”刘胡兰挺起胸膛说：“要杀要砍由你们，怕死不当共产党！”她迎着呼呼的北风，踏着烈士的鲜血，走到铡刀前。刘胡兰光荣地牺牲了，那年她才十五岁。","毛主席听到这个消息，亲笔为她写了题词：“生的伟大，死的光荣。“"]},{"id":111,"grade":"二年级上册","title":"语文园地","paragraphs":["轿车 救护车 摩托车 消防车","渔船 货船 油轮 科学考察船","轿 救 摩 托 防","渔 货 轮 科 考","有志者事竟成。——《后汉书》","志当存高远。——诸葛亮","穷且益坚，不坠青云之志。——王勃","很久很久以前，洪水经常泛滥。大水淹没了田地，冲毁了房屋，毒蛇猛兽到处伤害百姓和牲畜，人们的生活痛苦极了。","洪水给百姓带来了无数的灾难，必须治好它。当时，一个名叫鲧的人领着大家治水。他只知道筑坝挡水，九年过去了，洪水仍然没有消退。他的儿子禹继续治水。","禹离开了家乡，一去就是十三年。这十三年里，他到处奔走，曾经多次路过自己家门口。可是他认为治水要紧，一次也没有走进家门看一看。","禹吸取了鲧治水失败的教训，采用疏导的办法治水。他和大家一起，疏通了很多河道，让洪水通过河道，最后流到大海里去。洪水终于退了，毒蛇猛兽被驱赶走了，人们把家搬了回来。大家在被水淹过的土地上耕种，农业生产渐渐恢复了，百姓安居乐业，重新过上了幸福的生活。","盛开 盛饭 床铺 铺路","种子 种地 好人 好客","分别 水分 重新 重点","教室 教书 口号 号叫","干净 干活 每当 当作","一阵秋风吹过","树叶像蝴蝶一样飘落下来","我们去公园玩 公园里花真多呀","这棵树的叶子真奇怪 是什么树呢"]},{"id":112,"grade":"二年级上册","title":"夜宿山寺","paragraphs":["作者：[唐代] 李白","危楼高百尺，","手可摘星辰。","不敢高声语，","恐惊天上人。","山上寺院好似有百丈之高，站在上边仿佛都能摘下星辰。","不敢高声说话，唯恐惊动了天上的仙人。","李白（701年－762年） ，字太白，号青莲居士，又号“谪仙人”，唐代伟大的浪漫主义诗人，被后人誉为“诗仙”，与杜甫并称为“李杜”，为了与另两位诗人李商隐与杜牧即“小李杜”区别，杜甫与李白又合称“大李杜”。据《新唐书》记载，李白为兴圣皇帝（凉武昭王李暠）九世孙，与李唐诸王同宗。其人爽朗大方，爱饮酒作诗，喜交友。李白深受黄老列庄思想影响，有《李太白集》传世，诗作中多为醉时写就，代表作有《望庐山瀑布》《行路难》《蜀道难》《将进酒》《早发白帝城》等。"]},{"id":113,"grade":"二年级上册","title":"敕勒歌","paragraphs":["敕勒川，阴山下，","天似穹庐，笼盖四野。","天苍苍，野茫茫，","风吹草低见牛羊。","辽阔的敕勒平原，就在阴山脚下。","天空如毡制的圆顶大帐篷，笼罩着草原的四面八方。","天空是青苍蔚蓝的颜色，草原无边无际，一片茫茫。风儿吹过，牧草低伏，显露出原来隐没于草丛中的众多牛羊。"]},{"id":114,"grade":"二年级上册","title":"20 雾在哪里","paragraphs":["从前有一片雾，他是个淘气的孩子。","有一天，雾飞到海上。","“我要把大海藏起来。”于是，他把大海藏了起来。无论是海水、船只，还是蓝色的远方，都看不见了。","“现在我要把天空连同太阳一起藏起来。”于是，他把天空连同太阳一起藏了起来。霎时，四周变暗了，无论是天空，还是天空中的太阳，都看不见了。","雾来到岸边。","“现在我要把海岸藏起来。”雾把海岸藏了起来，同时也把城市藏了起来。房屋、街道、树木、桥梁，甚至行人和小黑猫，雾把一切都藏了起来，什么都看不见了。","他躲到城市的上空，说道：“现在，我该把谁藏起来呢？”看来，再也没有可藏的了。","“我要把自己藏起来。”","不久，大海连同船只，天空连同太阳，海岸连同城市，街道连同房屋和桥梁，都露出来了。路上走着行人。小黑猫也出现了，它摇着黑尾巴，悠闲地散步。","雾呢？消失了，不知到哪里去了。"]},{"id":115,"grade":"二年级上册","title":"21 雪孩子","paragraphs":["雪，下个不停，一连下了好几天。","这天早上，天晴了，兔妈妈要出门去。小白兔嚷起来：“妈妈，妈妈，我也要去！”","兔妈妈说：“好孩子，妈妈有事，你不能跟着去。”兔妈妈在门外的空地上给小白兔堆了个雪孩子。小白兔有了小伙伴，就不跟妈妈去了。","小白兔跳舞给雪孩子看，唱歌给雪孩子听。他玩累了，就回家去睡午觉。“屋子里真冷，赶快往火堆里添把柴吧！”","小白兔添了柴，把火烧得旺旺的，屋子里渐渐暖和了。他躺在床上，闭上眼睛，一会儿就睡着了。","火越烧越旺。哎呀，火把旁边的柴堆烧着了！小白兔睡得正香，他一点儿也不知道。","“不好了！小白兔家着火了！”雪孩子看见从小白兔家的窗户里冒出黑烟，蹿出火星。他一边喊，一边向小白兔家奔去。","“小白兔，小白兔！你在哪里？”雪孩子冲进屋里，冒着呛人的烟、烫人的火，找哇找哇，终于找到了小白兔。他连忙把小白兔抱起来，跑到屋外。","小白兔得救了，雪孩子却浑身水淋淋的。","这时候，树林里的小猴子、小山羊都赶来救火了。不一会儿，大家就把火扑灭了。","兔妈妈回来了，激动地说：“谢谢大家来救火，救了小白兔，谢谢大家！”","“咦，是谁救了小白兔？”小动物们说，“真得谢谢他呢！”","这时，救小白兔的雪孩子不见了。他已经化成水了。","不，雪孩子还在呢！瞧，太阳晒着晒着，他变成了很轻很轻的水汽。飞呀，飞呀，飞上天空，变成了一朵白云，一朵美丽的白云。"]},{"id":116,"grade":"二年级上册","title":"语文园地","paragraphs":["海滩 椰树 贝壳","沙漠 胡杨 骆驼","高原 雪莲 骏马","悬崖 青松 雄鹰","滩 椰 壳 漠","骆 驼 骏 悬 崖","棉被  泼水   纸巾  低头","带领  展现   战士  土地","散步  南瓜   今天  口令","带领  穿戴     果园  圆心","以后  已经     汽水  气体","再见  正在     心情  晴天","一九二九不出手，","三九四九冰上走，","五九六九，沿河看柳，","七九河开，八九雁来，","九九加一九，耕牛遍地走。","天空飘着一片霞，","水上游来一群鸭。","霞是五彩霞，","鸭是麻花鸭。","麻花鸭游进五彩霞，","五彩霞网住麻花鸭。","乐坏了鸭，","拍碎了霞，","分不清是鸭还是霞。","云开雾散  微风习习","冰天雪地  风雨交加","云雾缭绕  寒风刺骨","鹅毛大雪  电闪雷鸣","“我要把大海藏起来。”于是，雾把大海藏了起来。","调皮的风拿了我的手绢，擦过了汗，扔到地上；又拿了妹妹的圆帽子，当作铁环滚走了。"]},{"id":117,"grade":"二年级上册","title":"22 狐假虎威","paragraphs":["在茂密的森林里，有一只老虎正在寻找食物。一只狐狸从老虎身边窜过。老虎扑过去，把狐狸逮住了。","狐狸眼珠子骨碌碌一转，扯着嗓子问老虎：“你敢吃我？”","“为什么不敢？”老虎一愣。","“老天爷派我来做你们百兽的首领，你吃了我，就是违抗了老天爷的命令。我看你有多大的胆子！”","老虎被蒙住了，松开了爪子。","狐狸摇了摇尾巴，说：“我带你到百兽面前走一趟，让你看看我的威风。”","老虎跟着狐狸朝森林深处走去。狐狸神气活现，摇头摆尾；老虎半信半疑，东张西望。","森林里的野猪啦，小鹿啦，兔子啦，看见狐狸大摇大摆地走过来，跟往常很不一样，都很纳闷。再往狐狸身后一看，呀，一只大老虎！大大小小的野兽吓得撒腿就跑。","老虎信以为真。其实他受骗了。原来，狐狸是借着老虎的威风把百兽吓跑的。"]},{"id":118,"grade":"二年级上册","title":"23 纸船和风筝","paragraphs":["松鼠和小熊住在一座山上。松鼠住在山顶，小熊住在山脚。山上的小溪往下流，正好从小熊的家门口流过。","松鼠折了一只纸船，放在小溪里。纸船漂哇漂，漂到了小熊家门口。","小熊拿起纸船一看，乐坏了。纸船里放着一个小松果，松果上挂着一张纸条，上面写着：“祝你快乐！”","小熊也想折一只纸船送给松鼠，可是纸船不能漂到山上去。怎么办呢？他想了想，就扎了一只风筝。风筝乘着风，飘哇飘，飘到了松鼠家门口。","松鼠一把抓住风筝的线一看，也乐坏了。风筝上挂着一个草莓，风筝的翅膀上写着：“祝你幸福！”","纸船和风筝让他们俩成了好朋友。","可是有一天，他们俩为了一点儿小事吵了一架。山顶上再也看不到飘荡的风筝，小溪里再也看不到漂流的纸船了。","小熊很难过。他还是每天扎一只风筝，但是不好意思把风筝放起来，就把风筝挂在高高的树枝上。","松鼠也很难过。他还是每天折一只纸船，他也不好意思把纸船放进小溪，就把纸船放到屋顶上。","过了几天，松鼠再也受不了啦。他在一只折好的纸船上写了一句话：“如果你愿意和好，就放一只风筝吧！”他把这只纸船放进了小溪。","傍晚，松鼠看见一只美丽的风筝朝他飞来，高兴得哭了。他连忙爬上屋顶，取下纸船，把一只只纸船放到了小溪里。"]},{"id":119,"grade":"二年级上册","title":"24 风娃娃","paragraphs":["风妈妈有个可爱的风娃娃。风娃娃长大了，他想像妈妈一样去帮助人。风妈妈说：“到田野里去吧，在那里，你可以帮人们做很多事情。”","风娃娃来到田野，看见一架大风车正在慢慢转动，抽上来的水断断续续地流着。他深深地吸了一口气，鼓起腮使劲向风车吹去。风车一下子转得飞快！抽上来的水奔跑着，哗啦哗啦地向田里流去。秧苗喝足了水，笑着不住地点头。风娃娃高兴极了。","风娃娃又来到河边，看见许多船工正拉着一艘大船。他们弯着腰，流着汗，“嗨哟，嗨哟”喊着号子，可是船却走得很慢很慢。他急忙跑过去，对着船帆用力吹了口气，船飞快地跑了起来。船工们笑了，一边收起纤绳，一边向风娃娃表示感谢。","风娃娃想：帮助人们做好事，真容易，只要有力气就行。","他这么想着，来到一个广场上。那里有几个孩子正在放风筝。风娃娃看见了，赶紧过去用力吹。风筝在空中摇摇摆摆，有的还翻起了跟头。不一会儿，风筝被吹得无影无踪，孩子们伤心极了。","风娃娃却一点儿也不知道，他仍然东吹吹，西吹吹。就这样，风娃娃吹跑了人们晾晒的衣服，折断了路边新栽的小树……人们都生气了，纷纷责怪他。","风娃娃不敢再去帮忙了，他委屈地在天上转着，想着：我帮人们做事情，为什么他们还责怪我呢？风娃娃回家去问妈妈。妈妈说：“孩子，做事情光有好的愿望还不行，还要看是不是真的对别人有用。”"]},{"id":120,"grade":"二年级上册","title":"语文园地","paragraphs":["狼 猩猩 蛇 白鹤 鸽子","羚羊 蚯蚓 螃蟹 虾 蚕","狼 猩 鹤 鸽 羚","蚯 蚓 螃 蟹 虾 蚕","狼吞虎咽 龙飞凤舞","鸡鸣狗吠 惊弓之鸟","漏网之鱼 害群之马","胆小如鼠 如虎添翼","如鱼得水","清晨，小刺猬去森林里采果子。","在小路边，他看见一只小獾在学做木工。小獾已经做成了三个小板凳。板凳做得很粗糙。但是看得出，他做得很认真。","小刺猬走到小獾身边，拿起板凳仔细地看了看。他对小獾说：“你真能干，小板凳做得一个比一个好！”","“真的吗？”小獾高兴极了。","傍晚，小刺猬抱着几个红红的大苹果，往家里走。","小獾见小刺猬来了，高兴地迎上去。他送给小刺猬一把椅子。小刺猬不好意思地说：“我怎么能要你的椅子呢？我可没干什么呀！”","小獾拉着小刺猬的手，说：“在我有点儿泄气的时候，是你称赞了我，让我有了自信。瞧，我已经会做椅子了。这是我的一点儿心意，收下吧。”","小刺猬连忙拿出两个大苹果，对小獾说：“留下吧，这也是我的一点儿心意！”","小獾接过苹果闻了闻，说：“你的苹果香极了，我从来没有见过这么好的苹果。”","小刺猬也高兴极了，说：“谢谢你，你的称赞消除了我一天的疲劳！”"]},{"id":121,"grade":"二年级下册","title":"村居","paragraphs":["作者：[清代] 高鼎","草长莺飞二月天，","拂堤杨柳醉春烟。","儿童散学归来早，","忙趁东风放纸鸢。","农历二月，青草渐渐发芽生长，黄莺飞来飞去，轻拂堤岸的杨柳陶醉在春天的雾气中。","村里的孩子们早早就放学回家，赶紧趁着东风把风筝放上蓝天。","（1828年－1880年），字象一，一字拙吾，浙江仁和（今浙江省杭州市）人，清代诗人，有《拙吾诗文稿》。高鼎生活在鸦片战争之后，大约在咸丰年间（1851～1861），其人无甚事迹，一般人提到他，是他写了一首有名的有关放风筝的《村居》诗。"]},{"id":122,"grade":"二年级下册","title":"咏柳","paragraphs":["作者：[唐代] 贺知章","碧玉妆成一树高，","万条垂下绿丝绦。","不知细叶谁裁出，","二月春风似剪刀。","高高的柳树长满了嫩绿的新叶，轻垂的柳条像千万条轻轻飘动的绿色丝带。","不知道这细细的柳叶是谁裁剪出来的？是那二月的春风，它就像一把神奇的剪刀。","贺知章(659—744)，字季真，号四明狂客，汉族，唐越州（今绍兴）永兴(今浙江萧山)人，贺知章诗文以绝句见长，除祭神乐章、应制诗外，其写景、抒怀之作风格独特，清新潇洒，著名的《咏柳》、《回乡偶书》两首脍炙人口，千古传诵，今尚存录入《全唐诗》共19首。"]},{"id":123,"grade":"二年级下册","title":"2 找春天","paragraphs":["春天来了！春天来了！","我们几个孩子脱掉棉袄，冲出家门，奔向田野，去寻找春天。","春天像个害羞的小姑娘，遮遮掩掩，躲躲藏藏。我们仔细地找哇，找哇。","小草从地下探出头来，那是春天的眉毛吧？","早开的野花一朵两朵，那是春天的眼睛吧？","树木吐出点点嫩芽，那是春天的音符吧？","解冻的小溪叮叮咚咚，那是春天的琴声吧？","春天来了！我们看到了她，我们听到了她，我们闻到了她，我们触到了她。她在柳枝上荡秋千，在风筝尾巴上摇哇摇；她在喜鹊、杜鹃嘴里叫，在桃花、杏花枝头笑……"]},{"id":124,"grade":"二年级下册","title":"3 开满鲜花的小路","paragraphs":["邮递员黄狗在门口喊：“鼹鼠先生，您的包裹单！”","原来，长颈鹿大叔给鼹鼠先生寄来了一个包裹。","鼹鼠先生赶紧骑着摩托车，到邮局去领包裹。他回家后打开包裹，看见一堆小颗粒，可认不出是什么东西。","鼹鼠先生拿着包裹，来到松鼠太太家。他问松鼠太太：“长颈鹿大叔寄来一个包裹，您能帮我看看是什么东西吗？”","松鼠太太拿过来一看，里面空空的，什么也没有。原来，包裹破了，里面的东西不见了。看来都漏在来时的路上啦！鼹鼠先生很懊丧。","春天来了，鼹鼠先生要去松鼠太太家做客。啊，通往松鼠太太家的路，成了一条开满鲜花的小路。","鼹鼠先生路过刺猬太太家，正巧，刺猬太太走出门。看到门前开着一大片绚丽多彩的鲜花，她惊奇地说：“这是谁在我家门前种的花？多美啊！”","鼹鼠先生回答：“我不知道！”","鼹鼠先生经过狐狸太太家，正巧，狐狸太太走出门。看到门前开着一大片五颜六色的鲜花，她奇怪地问：“这是谁在我家门前种的花？真美啊！”","鼹鼠先生回答：“我不知道！”","鼹鼠先生来到松鼠太太门前。松鼠太太走出门，看见门前的小路上花朵簇簇，小松鼠、小刺猬和小狐狸在那里快活地蹦啊跳啊。","松鼠太太对鼹鼠先生说：“我知道了，去年长颈鹿大叔寄给你的是花籽。这是多么美好的礼物啊！”"]},{"id":125,"grade":"二年级下册","title":"4 邓小平爷爷植树","paragraphs":["1987年4月5日，是个令人难忘的日子。","这一天，碧空如洗，万里无云。在北京天坛公园植树的人群里，83岁高龄的邓小平爷爷格外引人注目。只见他手握铁锹，兴致勃勃地挖着树坑，额头已经满是汗珠，仍不肯休息。","一个树坑挖好了。邓爷爷精心地挑选了一棵茁壮的柏树苗，小心地移入树坑，又挥锹填了几锹土。他站到几步之外仔细看看，觉得不是很直，连声说：“不行，不行！”他又走上前把树苗扶正。","一棵绿油油的小柏树栽好了，就像战士一样笔直地站在那里。邓爷爷的脸上露出了满意的笑容。","今天，邓小平爷爷亲手栽种的柏树已经长大了，成了天坛公园一处美丽的风景。"]},{"id":126,"grade":"二年级下册","title":"语文园地","paragraphs":["湖心亭 咨询处 露天剧场","管理处 宝塔 餐厅","亭 咨 询 剧 管","理 宝 塔 餐 厅","种子睡在松软的泥土里。","什么睡在松软的泥土里？种子睡在哪里？种子睡在什么样的泥土里？","作者：[唐代] 白居易","离离原上草，","一岁一枯荣。","野火烧不尽，","春风吹又生。","原野上长满茂盛的青草，每年秋冬枯黄春来草色浓。","野火无法烧尽满地的野草，春风吹来大地又是绿茸茸。","远处芬芳的野草遮没了古道，阳光照耀下碧绿连荒城。","今天我又来送别老朋友，连繁茂的草儿也满怀离别之情。","白居易（772年－846年），字乐天，号香山居士，又号醉吟先生，祖籍太原，到其曾祖父时迁居下邽，生于河南新郑。是唐代伟大的现实主义诗人，唐代三大诗人之一。白居易与元稹共同倡导新乐府运动，世称“元白”，与刘禹锡并称“刘白”。白居易的诗歌题材广泛，形式多样，语言平易通俗，有“诗魔”和“诗王”之称。官至翰林学士、左赞善大夫。公元846年，白居易在洛阳逝世，葬于香山。有《白氏长庆集》传世，代表诗作有《长恨歌》《卖炭翁》《琵琶行》等。","沙沙沙，沙沙沙。春雨姑娘在绿色的叶丛中弹奏着乐曲，低声呼唤着沉睡的笋芽儿：“笋芽儿，醒醒啊，春天来啦！”","笋芽儿被叫醒了。她揉了揉眼睛，伸了伸懒腰，看看四周仍然一片漆黑，撒娇地说：“是谁在叫我啊？”","轰隆隆！轰隆隆！雷公公把藏了好久的大鼓重重地敲了起来。他用粗重的嗓音呼唤着笋芽儿。","笋芽儿扭动着身子，一个劲儿地向上钻。","妈妈见了，忙给笋芽儿穿上一件又一件衣服，还不停地唠叨：“别着凉，千万别着凉。”","笋芽儿终于钻出了地面。她睁开眼睛一看，啊，多么明亮、多么美丽的世界啊！桃花笑红了脸，柳树摇着绿色的长辫子，小燕子叽叽喳喳地叫着……笋芽儿看看这儿，看看那儿，怎么也看不够。她高兴地说：“多美好的春光啊！我要快快长大！”","春雨姑娘不断地爱抚她，滋润她。太阳公公照耀她，给她温暖。笋芽儿脱下了一件件衣服，长成了一株健壮的竹子。她站在山冈上，自豪地喊着“我长大啦！”"]},{"id":127,"grade":"二年级下册","title":"快乐读书吧","paragraphs":["故事里的儿童，有的顽皮、可爱，有的懂事、善良；有的过着跟我们相似的生活，有的会有意想不到的奇遇……","下面这些故事，都写了谁呢？他们的生活是怎样的？让我们读一读吧！","《神笔马良》","《七色花》","《一起长大的玩具》","《愿望的实现》","看书的时候，要学会看目录。目录告诉我们书里主要写了什么，要读的内容从哪一页开始。","你还读过哪些儿童故事呢？我们一起来分享吧！"]},{"id":128,"grade":"二年级下册","title":"5 雷锋叔叔，你在哪里","paragraphs":["沿着长长的小溪，","寻找雷锋的足迹。","雷锋叔叔，你在哪里，","你在哪里？","小溪说：","昨天，他曾路过这里，","抱着迷路的孩子，","冒着蒙蒙的细雨。","瞧，那泥泞路上的脚窝，","就是他留下的足迹。","顺着弯弯的小路，","寻找雷锋的足迹。","雷锋叔叔，你在哪里，","你在哪里？","小路说：","昨天，他曾路过这里，","背着年迈的大娘，","踏着路上的荆棘。","瞧，那花瓣上晶莹的露珠，","就是他洒下的汗滴。","乘着温暖的春风，","我们四处寻觅。","啊，终于找到了——","哪里需要献出爱心，","雷锋叔叔就出现在哪里。"]},{"id":129,"grade":"二年级下册","title":"6 千人糕","paragraphs":["一天，爸爸对孩子说：“今天我们来吃千人糕吧”","“爸爸，什么是千人糕？”孩子好奇地问。","“需要很多很多人才能做成的糕。”爸爸回答。","孩子想：这糕要很多很多人才能做成，一定特别大，也许比桌子还大吧？","爸爸端来一块糕，那糕看上去跟平时吃的糕没什么两样。难道它的味道很特别吗？孩子急忙尝了尝，笑了：“这就是平常吃过的米糕嘛！您给我买过。”","爸爸说：“是的，就是平常吃的米糕。你知道这糕是怎么做成的吗？”","孩子说：“是把大米磨成粉做的，还加了糖。”","爸爸说：“是啊，大米是用农民种的稻子加工出来的。农民种稻子需要种子、农具、肥料、水……”","爸爸接着说：“糖呢，是用甘蔗汁、甜菜汁熬出来的。甘蔗、甜菜也要有人种。熬糖的时候，要有工具，还得有火……就算米糕做好了，还得要人包装、送货、销售，这些又需要很多人的劳动。”","爸爸拿起面前的糕，说：“你看，一块平平常常的糕，经过很多很多人的劳动，才能摆在我们面前。”","孩子听了爸爸的话，仔细想了想，说：“爸爸，这糕的确应该叫‘千人糕’啊！”"]},{"id":130,"grade":"二年级下册","title":"7 一匹出色的马","paragraphs":["一个春天的傍晚，妈妈牵着妹妹，爸爸牵着我，一起到郊外去散步。我们沿着一条小河走。河水碧绿碧绿的，微风吹过，泛起层层波纹。河岸上垂下来的柳叶，拂过妈妈和爸爸的头发，我和妹妹看着都笑了。","路的一边是田野，葱葱绿绿的，非常可爱，像一片柔软的绿毯。","春天的郊外，景色异常美丽。我们一边看，一边走，路已经走了不少，却还恋恋不舍，不想回去。","当我们往回走的时候，妹妹求妈妈抱她：“我很累，走不动了，抱抱我。”","妈妈摇摇头，回答说：“不行啊，我也很累，抱不动你了。”","妹妹转过头求爸爸。爸爸不作声，他松开我的手，从路旁一株柳树下，拾起一根又长又细的枝条，把它递给了妹妹，说：“这是一匹出色的马，你走不动了，就骑着它回家吧。”","妹妹高兴地跨上“马”，蹦蹦跳跳地奔向前去。等我们回到家时，她已经在门口迎接我们，笑着说：“我早回来啦！”"]},{"id":131,"grade":"二年级下册","title":"语文园地","paragraphs":["教师  工程师  魔术师","建筑师  理发师","演员  营业员  服务员","裁判员  饲养员","程 魔 术 建 筑","演 营 务 判 饲 养","我更注意观察字的每一个笔画在田字格中的位置了。","写字的时候我能做到姿势正确，字也写得更端正了。","予人玫瑰，手有余香。","平时肯帮人，急时有人帮。","与其锦上添花，不如雪中送炭。","踮起脚尖儿，","走进安静的小院，","我们把一株紫丁香，","栽在老师窗前。","老师，老师，","就让它绿色的枝叶，","伸进您的窗口，","夜夜和您做伴。","老师——","绿叶在风里沙沙，","那是我们给您唱歌，","帮您消除一天的疲倦。","老师——","满树盛开的花儿，","那是我们的笑脸，","感谢您时时把我们挂牵。","夜深了，星星困得眨眼，","老师，休息吧，","让花香飘进您的梦里，","那梦啊，准是又香又甜。","田野","葱葱绿绿的","像一片柔软的绿毯","天上的云","雪白雪白的","好像一群小绵羊","大树","又粗又壮","就像……","这糕要很多很多人才能做成，一定特别大。","难道它的味道很特别吗？","一块平平常常的糕，经过很多很多人的劳动，才能摆在我们面前。","鼹鼠先生经过狐狸太太家，正巧，狐狸太太走出门。"]},{"id":132,"grade":"二年级下册","title":"1 神州谣","paragraphs":["我神州，称中华，","山川美，可入画。","黄河奔，长江涌，","长城长，珠峰耸。","台湾岛，隔海峡，","与大陆，是一家。","各民族，情谊浓，","齐奋发，共繁荣。"]},{"id":133,"grade":"二年级下册","title":"2 传统节日","paragraphs":["春节到，人欢笑，","贴窗花，放鞭炮。","元宵节，看花灯，","大街小巷人如潮。","清明节，雨纷纷，","先人墓前去祭扫。","过端午，赛龙舟，","粽香艾香满堂飘。","七月七，来乞巧，","牛郎织女会鹊桥。","过中秋，吃月饼，","十五圆月当空照。","重阳节，要敬老，","踏秋赏菊去登高。","转眼又是新春到，","全家团圆真热闹。"]},{"id":134,"grade":"二年级下册","title":"3 “贝”的故事","paragraphs":["一些生活在水里的动物，用贝壳保护自己的身体。甲骨文中的“贝”字，就像一种海贝的样子。","古时候，人们觉得贝壳很漂亮，很珍贵，喜欢把它们当作饰品戴在身上。而且贝壳可以随身携带，不容易损坏，于是古人还把贝壳当作钱币。所以，用“贝”作偏旁的字大多与钱财有关，比如，“赚、赔、购、贫、货”。"]},{"id":135,"grade":"二年级下册","title":"4 中国美食","paragraphs":["凉拌菠菜 香煎豆腐 红烧茄子","烤鸭 水煮鱼","葱爆羊肉 小鸡炖蘑菇","蒸饺 炸酱面 小米粥 蛋炒饭"]},{"id":136,"grade":"二年级下册","title":"语文园地","paragraphs":["甜津津   酸溜溜","辣乎乎   香喷喷","油腻腻   软绵绵","脆生生   硬邦邦","津 溜 辣 乎","喷 腻 绵 脆 邦","炒 烤 烧  煎 蒸 煮","怒 恋 感  慌 惊 怕","刺 刮 剑  分 剪 切","子鼠 丑牛 寅虎 卯兔","辰龙 巳蛇 午马 未羊","申猴 酉鸡 戌狗 亥猪","院子里有一棵小柳树和一棵小枣树。","小柳树的腰细细的，真好看。小柳树看看小枣树，树枝弯弯曲曲的，一点儿也不好看。小柳树说：“喂，小枣树，你的树枝多难看哪！你看我，多漂亮！”","春天，小柳树发芽了。过了几天，小柳树的芽变成小叶子，她穿上一身浅绿色的衣服，真美！她看看小枣树，小枣树还是光秃秃的。小柳树说：“喂，小枣树，你怎么不长叶子啊？你看我，多漂亮！”","又过了好些日子，小枣树才长出了小小的叶子。这时候，小柳树的叶子已经长得又细又长了。她在微风里得意地跳起舞来。","到了秋天，小枣树结了许多又大又红的枣子。人们把枣子打下来，坐在院子里，高高兴兴地吃起来。","小柳树看看自己，什么也没结。她想：从前我总是说枣树不好看，这回她该说我啦！可是过了一天又一天，小枣树什么也没说。小柳树实在忍不住了，就问小枣树：“你怎么不说我呀？”小枣树不明白，问道：“说你什么呀？”小柳树低下头，说：“说我不能像你那样结果子呗……”","小枣树温和地说：“你虽然不能结出人们喜欢的果子，可是一到春天，你就发芽长叶，比我绿得早；到了秋天，你有时比我落叶晚。再说，你长得也比我快，等你长大了，人们在树荫下乘凉，那有多好哇！”","小柳树听了，不好意思地笑了。"]},{"id":137,"grade":"二年级下册","title":"8 彩色的梦","paragraphs":["我有一大把彩色的梦，","有的长，有的圆，有的硬。","他们躺在铅笔盒里聊天，","一打开，就在白纸上跳蹦。","脚尖滑过的地方，","大块的草坪，绿了；","大朵的野花，红了；","大片的天空，蓝了，","蓝—得—透—明！","在葱郁的森林里，","雪松们拉着手，","请小鸟留下歌声。","小屋的烟囱上，","结一个苹果般的太阳，","又大——又红！","我的彩色铅笔，","是大森林的精灵。","我的彩色梦境，","有水果香，有季节风，","还有紫葡萄的叮咛，","在溪水里流动……"]},{"id":138,"grade":"二年级下册","title":"9 枫树上的喜鹊","paragraphs":["我们村的渡口旁有一棵枫树，我很喜欢它。它好像一把很大又很高的绿色太阳伞，一直打开着。它的绿荫遮蔽了村里的渡口。枫树上有一个喜鹊的窝，我喜欢极了。","是的，我喜欢站在枫树下，抬头看喜鹊的窝。我常常觉得喜鹊会跟我说话，我像童话书里那样，在心中称呼她喜鹊阿姨。","我真是喜欢极了。上个星期天早上，我正要撑着渡船到对岸的树林里去打柴，发现喜鹊阿姨的窝里有几只小喜鹊了。","我真是像童话书里那样，在心中称呼他们喜鹊弟弟。","从那天起，我一有空，便来到渡口边，站在枫树下看望我的喜鹊弟弟。喜鹊弟弟长得真快，好极了。我看见喜鹊阿姨站在窝边，一会儿教喜鹊弟弟唱歌，一会儿教他们做游戏，一会儿教他们学自己发明的拼音字母……","“鹊！鹊！鹊！”喜鹊阿姨教道。","我知道，这便是a、o、e。","喜鹊弟弟也跟着学：“鹊，鹊，鹊……”","今天早上，太阳从渡口对岸的山冈后面升上来了，我看见喜鹊阿姨站在窝边，指着上升的太阳，问喜鹊弟弟：“鹊！鹊鹊鹊？”","我懂得，她问话的意思是：“看！那是什么？”","喜鹊弟弟一齐快乐地回答：“鹊！鹊鹊！鹊鹊鹊！”","我懂得，喜鹊弟弟很快给出了答案：“妈妈，那是太阳！太阳升上来了！”","我真高兴啊！"]},{"id":139,"grade":"二年级下册","title":"10 沙滩上的童话","paragraphs":["海边的沙滩是我们的快乐天地。","在沙滩上，我们垒起城堡，城堡周围筑起围墙，围墙外再插上干树枝，那就是我们的树。","不知道谁说了一句：“这城堡里住着一个凶狠的魔王。”","有人接着补充：“他抢去了美丽的公主！”","第三个小伙伴说：“你们快听，公主在城堡里哭呢！”","就这样，我们编织着童话。","转眼间，我们亲手建造的城堡成了一座魔窟，我们也成了攻打魔窟的勇士。","我们一起商量怎样攻下那座城堡。","一个小伙伴说：“我驾驶飞机去轰炸。”","有人反驳：“那时候还没有飞机呢！”","我说：“挖地道，从地下装上火药，把城堡炸平。”","我的办法得到了大家的赞赏。于是我们趴在沙滩上，从四面八方挖着地道。","挖呀，挖呀，我们终于挖到了城堡下面，然后合力用手往上一抬，就把城堡给轰塌了。","我们欢呼着胜利，欢呼着炸死了魔王，欢呼着救出了公主。","但公主在哪儿？","忽然，我发现妈妈就站在我们身后，微笑着望着我们。","我大声说：“公主被我们救出来了，救出来了！在这儿，在这儿！”我抱住了妈妈。","大家跟着一起叫喊着，欢呼着。","妈妈开心地笑了。她一边笑一边说：“妈妈怎么能当公主呢？“","但我们这群孩子都坚持说：“她就是被我们救出来的公主”","真的，那时候，连我也忘记了她是我的妈妈！"]},{"id":140,"grade":"二年级下册","title":"11 我是一只小虫子","paragraphs":["当一只小虫子好不好？我的伙伴们都说：“当一只小虫子，一点儿都不好。”我们蹦蹦跳跳的时候，一定要看准地方，不然屁股会被苍耳刺痛的。一不留神，我们会蹦进很深很深的水里，被淹得昏头昏脑。其实，那深水只是小狗撒的一泡尿。孩子们都觉得毛茸茸的小鸟很可爱，但我们小虫子没有谁会喜欢小鸟。","不过，我觉得当一只小虫子还真不错。","早上醒来，我在摇摇晃晃的草叶上伸懒腰，用一颗露珠把脸洗干净，把细长的触须擦得亮亮的。如果能小心地跳到狗的身上，我们就可以到很远的地方去旅行。这可是免费的特快列车呀！","我有很多小伙伴，每一个都特别有意思。","走在外面一定要小心，别被屎壳郎撞伤，因为他们搬运食物的时候，从来不看路。螳螂很贪吃，总想把我吃掉，但真幸运，他没我跳得远。有些虫子脾气不太好，比如天牛，每次我说“天牛大婶，早上好”，她总是想顶我一下。","我喜欢当一只小虫子。当我很快乐的时候，会使劲叫哇叫，所以，如果你在夜晚听见草地里的歌声——你就一定能找到我！"]},{"id":141,"grade":"二年级下册","title":"语文园地","paragraphs":["陀螺  毽子","不倒翁  玩具枪","橡皮泥  七巧板","溜溜球  遥控坦克","陀 螺 毽 倒 翁","枪 橡 板 控 坦 克","失信不立。——《左传》","诚信者，天下之结也。——《管子》","小信成则大信立。——《韩非子》","晚上，妈妈到商店去买东西，宁宁在街灯下等妈妈。他站着没劲，独自玩起了手影戏。","他双手一屈一伸，在灯光前一照，墙壁上马上映出一个黑影来：走路一顿一顿，尖嘴巴一张一合，这是一只在找鸡妈妈的小鸡崽。","忽然，小鸡的对面也出现了一个手影。一对长耳朵，一个短尾巴，噗，噗，跳过来。哎呀，不能再跳过来，再跳要压着小鸡了。可是兔子挺霸道的，还在跳过来。噗！噗！宁宁回头一看，一个陌生的男孩也在做手影。","哼，谁怕你？宁宁手一变，墙上出现一只猫，喵，喵，向兔子扑去。","那个男孩吓了一跳，连忙将兔子变成了狗。汪汪汪，狗咬猫。","呜哇，呜哇，猫变成了大熊。","啊呜，啊呜，老虎要吃熊。","比老虎厉害的还有什么？宁宁想不起来，他差点儿哭了。","嗯，干吗要跟人吵架？还是跟他和好吧。宁宁马上变出一只鸽子来：尖尖的嘴，长长的翅膀，扑棱棱，鸽子飞了起来。","那个男孩愣了一阵，也变出了一只鸽子。","看，现在两只鸽子偎依在一起了。","妈妈出来了，她看见宁宁与一个陌生的男孩玩得正欢呢。"]},{"id":142,"grade":"二年级下册","title":"亡羊补牢","paragraphs":["从前有个人，养了几只羊。一天早上，他去放羊，发现羊少了一只。原来羊圈破了个窟窿，夜里狼从窟窿钻进去，把羊叼走了。","街坊劝他说：“赶紧把羊圈修一修，堵上那个窟窿吧！”","他说：“羊已经丢了，还修羊圈干什么？”","第二天早上，他去放羊，发现羊又少了一只。原来狼又从窟窿钻进去，把羊叼走了。","他很后悔没有听街坊的劝告，心想，现在修还不晚。他赶紧堵上那个窟窿，把羊圈修得结结实实的。从此，他的羊再也没丢过。"]},{"id":143,"grade":"二年级下册","title":"揠苗助长","paragraphs":["古时候有个人，他巴望自己田里的禾苗长得快些，天天到田边去看。可是，一天，两天，三天，禾苗好像一点儿也没有长高。他在田边焦急地转来转去，自言自语地说：“我得想个办法帮它们长。”","一天，他终于想出了办法，就急忙跑到田里，把禾苗一棵一棵往高里拔。从中午一直忙到太阳落山，弄得筋疲力尽。","他回到家里，一边喘气一边说：“今天可把我累坏了！力气总算没白费，禾苗都长高了一大截。”","他的儿子不明白是怎么回事，第二天跑到田里一看，禾苗都枯死了。"]},{"id":144,"grade":"二年级下册","title":"13 画杨桃","paragraphs":["有一次上图画课，老师把两个杨桃摆在讲桌上，要同学们画。我的座位在教室前排靠边的地方，讲桌上那两个杨桃的一端正对着我。我看到的杨桃根本不像平时看到的那样，而像是五个角的什么东西。我认认真真地看，老老实实地画，自己觉得画得很准确。","当我把这幅画交出去的时候，班里几个同学看见了，哈哈大笑起来。","“杨桃是这个样子的吗？”","“倒不如说是五角星吧！”","老师看了看这幅画，到我的座位上坐下来，审视了一下讲桌上的杨桃，然后回到讲桌前，举起我的那页画纸，问大家：","“这幅画画得像不像？”","“不像！”","“它像什么？”","“像五角星！”","老师的神情变得严肃了。半晌，他又问道：“画杨桃画成了五角星，好笑吗？”","“好——笑！”有几个同学抢着答道，同时发出嘻嘻的笑声。","于是，老师请这几个同学轮流坐到我的座位上。他对第一个坐下的同学说：“现在你看看那杨桃，像你平时看到的杨桃吗？”","“不像。”","“那么，像什么呢？”","“像……五……五角星。”","“好，下一个。”","老师让这几个同学回到自己的座位上，然后和颜悦色地说：“大家发现了吗？看的角度不同，杨桃的样子也就不一样。当我们看见别人把杨桃画成五角星的时候，不要忙着发笑，要看看人家是从什么角度看的。”","老师的教诲让我终生难忘。"]},{"id":145,"grade":"二年级下册","title":"14 小马过河","paragraphs":["马棚里住着一匹老马和一匹小马。","有一天，老马对小马说：“你已经长大了，能帮妈妈做点儿事吗？”小马连蹦带跳地说：“怎么不能？我很愿意帮您做事。”老马高兴地说：“那好啊，你把这半口袋麦子驮到磨坊去吧。”","小马驮起口袋，飞快地往磨坊跑去。跑着跑着，一条小河挡住了去路，河水哗哗地流着。小马为难了，心想：我能不能过去呢？如果妈妈在身边，问问她该怎么办，那多好啊！可是他离家已经很远了。","小马向四周望望，看见一头老牛在河边吃草，小马嗒嗒嗒跑过去，问道：“牛伯伯，请您告诉我，这条河，我能蹚过去吗？”老牛说：“水很浅，刚没小腿，能蹚过去。”","小马听了老牛的话，立刻跑到河边，准备蹚过去。突然，从树上跳下一只松鼠，拦住他大叫：“小马！别过河，别过河，你会淹死的！”小马吃惊地问：“水很深吗？”松鼠认真地说：“深得很哩！昨天，我的一个伙伴就是掉在这条河里淹死的！”","小马连忙收住脚步，不知道怎么办才好。他叹了口气，说：“唉！还是回家问问妈妈吧！”","小马甩甩尾巴，跑回家去。妈妈问他：“怎么回来啦？”小马难为情地说：“一条河挡住了去路，我……我过不去。”妈妈说：“那条河不是很浅吗？”小马说：“是啊！牛伯伯也这么说。可是松鼠说河水很深，还淹死过他的伙伴呢！”妈妈说：“那么河水到底是深还是浅呢？你仔细想过他们的话吗？”小马低下了头，说：“没……没想过。”妈妈亲切地对小马说：“孩子，光听别人说，自己不动脑筋，不去试试，是不行的。河水是深是浅，你去试一试就知道了。”","小马跑到河边，刚刚抬起前蹄，松鼠又大叫起来：“怎么？你不要命啦！”小马说：“让我试试吧！”他下了河，小心地蹚到了对岸。原来河水既不像老牛说的那样浅，也不像松鼠说的那样深。"]},{"id":146,"grade":"二年级下册","title":"语文园地","paragraphs":["厨房 厕所 车厢 大厦","洞穴 窟窿 窑洞 窄小","厨  厕  厢  厦","穴  窟  窿  窑  窄","教诲  寻找","伙伴  周围","明亮  柔软","我发现“寻”和“找”的意思相近，“寻找”的意思也和它们差不多。","冠必正，纽必结，","袜与履，俱紧切。","置冠服，有定位，","勿乱顿，致污秽。","唯德学，唯才艺，","不如人，当自砺。","若衣服，若饮食，","不如人，勿生戚。","一天，有一位老奶奶去看望她的两个儿子。","她先来到大儿子家。","大儿子是做蜜饯的，他门口的一大片地上，正晒着各种各样的果脯呢。","老奶奶看到儿子这么勤快，心里很高兴。她问大儿子：“儿子啊，你现在最盼望什么？”大儿子说：“我最盼望有太阳的好天气，最害怕下雨的坏天气。有了好天气，我的果脯就干得快啊。”","老奶奶离开的时候，对大儿子说：“儿子啊，我和你一起盼望有太阳的好天气。”","老奶奶又去了小儿子家。","小儿子是做雨伞的，他正在家里忙着呢。","老奶奶问小儿子：“儿子啊，你最盼望什么？”小儿子说：“我最盼望下雨的好天气，最害怕有太阳的坏天气。有了天天下雨的好天气，我的伞就好卖了。”","老奶奶回家以后，不知道怎么办才好，坐在门口哭。","一位老爷爷问她：“你为什么哭啊？”老奶奶说：“下雨天是坏天气，因为大儿子不能晒果脯了；大睛天也是坏天气，因为小儿子的雨伞就卖不出去了。”","老爷爷哈哈大笑起来，他说：“你可以倒过来想啊！晴天是好天气，晒果脯的大儿子会高兴；下雨也是好天气，做伞的小儿子会高兴。”","老奶奶想了想，一下子高兴起来了。她说：“对啊，不管是晴天还是下雨天，反正有一个儿子会高兴，每天都是好天气呢！”","微笑  狂笑  傻笑","笑眯眯  笑呵呵","眉开眼笑  破涕为笑","哈哈大笑  捧腹大笑","小马连蹦带跳地说：“怎么不能？我很愿意帮您做事。”","小马难为情地说：“一条河挡住了去路，我……我过不去。”","老师和颜悦色地说：“看的角度不同，杨桃地样子也就不一样。”"]},{"id":147,"grade":"二年级下册","title":"晓出净慈寺送林子方","paragraphs":["作者：[宋代] 杨万里","毕竟西湖六月中，","风光不与四时同。","接天莲叶无穷碧，","映日荷花别样红。","到底是西湖六月天的景色，风光与其它季节大不相同。","密密层层的荷叶铺展开去，一片无边无际的青翠碧绿，像与天相接，阳光下的荷花分外鲜艳娇红。","杨万里（1127年10月29日－1206年6月15日），字廷秀，号诚斋。吉州吉水（今江西省吉水县黄桥镇湴塘村）人。南宋著名诗人、大臣，与陆游、尤袤、范成大并称为“中兴四大诗人”。因宋光宗曾为其亲书“诚斋”二字，故学者称其为“诚斋先生”。杨万里一生作诗两万多首，传世作品有四千二百首，被誉为一代诗宗。他创造了语言浅近明白、清新自然，富有幽默情趣的“诚斋体”。杨万里的诗歌大多描写自然景物，且以此见长。他也有不少篇章反映民间疾苦、抒发爱国感情的作品。著有《诚斋集》等。"]},{"id":148,"grade":"二年级下册","title":"绝句","paragraphs":["作者：[唐代] 杜甫","两个黄鹂鸣翠柳，","一行白鹭上青天。","窗含西岭千秋雪，","门泊东吴万里船。","两只黄鹂在翠绿的柳树间鸣叫，一行白鹭直冲向蔚蓝的天空。","坐在窗前可以看见西岭千年不化的积雪，门前停泊着自万里外的东吴远行而来的船只。","杜甫（712－770），字子美，自号少陵野老，世称“杜工部”、“杜少陵”等，汉族，河南府巩县（今河南省巩义市）人，唐代伟大的现实主义诗人，杜甫被世人尊为“诗圣”，其诗被称为“诗史”。杜甫与李白合称“李杜”，为了跟另外两位诗人李商隐与杜牧即“小李杜”区别开来，杜甫与李白又合称“大李杜”。他忧国忧民，人格高尚，他的约1400余首诗被保留了下来，诗艺精湛，在中国古典诗歌中备受推崇，影响深远。759-766年间曾居成都，后世有杜甫草堂纪念。"]},{"id":149,"grade":"二年级下册","title":"16 雷雨","paragraphs":["满天的乌云，黑沉沉地压下来。树上的叶子一动不动，蝉一声也不出。","忽然一阵大风，吹得树枝乱摆。一只蜘蛛从网上垂下来，逃走了。","闪电越来越亮，雷声越来越响。","哗，哗，哗，雨下起来了。","雨越下越大。往窗外望去，树啊，房子啊，都看不清了。","渐渐地，渐渐地，雷声小了，雨声也小了。","天亮起来了。打开窗户，清新的空气迎面扑来。","雨停了。太阳出来了。一条彩虹挂在天空。蝉叫了。蜘蛛又坐在网上。池塘里水满了，青蛙也叫起来了。"]},{"id":150,"grade":"二年级下册","title":"17 要是你在野外迷了路","paragraphs":["要是你在野外迷了路，","可千万别慌张。","大自然有很多天然的指南针，","会帮助你辨别方向。","太阳是个忠实的向导，","它在天空给你指点方向。","中午的时候它在南边，","地上的树影正指着北方。","北极星是盏指路灯，","它永远高挂在北方。","要是你能认出它，","就不会在黑夜里乱闯。","要是碰上阴雨天，","大树也会来帮忙。","枝叶稠的一面是南方，","枝叶稀的一面是北方。","雪特别怕太阳，","沟渠里的积雪会给你指点方向。","看看哪边雪化得快，哪边化得慢，","就可以分辨北方和南方。","要是你在野外迷了路，","可千万别慌张。","大自然有很多天然的指南针，","需要你细细观察，多多去想。"]},{"id":151,"grade":"二年级下册","title":"18 太空生活趣事多","paragraphs":["航天员乘坐宇宙飞船飞往太空，空间站就是他们在太空的家。在太空中生活，说起来还挺有趣呢！","在空间站里，站着睡觉和躺着睡觉一样舒服。不过，要想睡个安稳觉，航天员必须钻入固定在舱壁上的睡袋里。不然，一不小心就会飘到别处去。","在空间站里活动也需要技巧。跟在地面上用腿脚行走不同，航天员在舱体里移动主要靠手臂。为了方便航天员在舱体中活动，舱壁上安装了很多特制的扶手。平时，航天员会依靠这些扶手或其他设施稳定自己的身体。","在空间站里，是没有办法用普通的杯子喝水的。因为水处于失重状态，即使把杯子倒过来，水也不会往下流。航天员要想喝到水，得使用一种带吸管的饮水袋，直接把水挤到嘴里。","航天员在太空中洗澡可不是一件容易的事。从喷头喷出的水总是飘浮在空中，为了解决这个问题，科研人员做了一个试验。他们设计了一个密封浴桶，在下边安装吸管，它可以把喷头喷出来的水朝一个方向吸。但洗完澡以后，航天员还要花很长时间清理身体上和浴桶里的水，实在太麻烦了。所以，现在航天员通常只用免洗湿巾擦拭身体，这就简单省事多了。","你看，在太空中生活，是不是很有趣？"]},{"id":152,"grade":"二年级下册","title":"语文园地","paragraphs":["博物馆 展览馆 科技馆","体育馆 研究所 派出所","哨所  诊所","博 馆 览 技","育 研 究 哨 诊","我带来儿童故事书放到了图书角，大家都很喜欢。","我常从图书角借书看，我能遵守《图书借阅公约》。","作者：[唐代] 李绅","春种一粒粟，","秋收万颗子。","四海无闲田，","农夫犹饿死。","春天播种下一粒种子，到了秋天就可以收获很多的粮食。","天下没有一块不被耕作的田，可仍然有种田的农夫饿死。","李绅（772—846）汉族，亳州（今属安徽）人，生于乌程（今浙江湖州），长于润州无锡（今属江苏）。字公垂。唐元和元年（806年），进士及第，补国子助教。与元稹、白居易交游甚密，他一生最闪光的部分在于诗歌，他是在文学史上产生过巨大影响的新乐府运动的参与者。作有《乐府新题》20首，已佚。著有《悯农》诗两首：“锄禾日当午，汗滴禾下土，谁知盘中餐，粒粒皆辛苦。”脍炙人口，妇孺皆知，千古传诵。《全唐诗》存其诗四卷。","一天，爸爸带川川去爬山。爬到半山腰，他们看见一位地质勘探队员，正趴在大石头上看着什么。川川走过去，奇怪地问：“叔叔，您在看什么？”","“我在看‘书’呢！”","“哪里有书啊？”","“岩石就是书啊！你看，这岩石一层一层的，不就像一册厚厚的书吗？”","川川认真地问：“这上面有字吗？”","“有。你来看，这是雨点儿留下的脚印，叫雨痕；这是波浪的足迹，叫波痕；还有这些闪光的、透明的，是矿物。它们都是字啊！”","川川又问：“这上面有图画吗？”","叔叔说：“有。你看，这儿有树叶，有贝壳，那儿还有一条小鱼呢！”","“这能说明什么呢？”","“它告诉我们，在很久很久以前，这里是一片长满树木的陆地。后来，陆地沉下去了，这里就变成了大海。又过了很多很多万年，海底慢慢上升，这里又变成了高山，就是我们脚下的这座山。”","“读这本岩石书有什么用呢？”川川总爱刨根问底。","叔叔说：“用处可大呢！它能告诉我们，哪里埋着煤炭，哪里藏着铁矿……把这本‘书’读懂，就能为国家找到更多的宝藏！”","“太好了，太好了！”川川高兴地说，“等我长大了，也要读懂这本最大的‘书’！”"]},{"id":153,"grade":"二年级下册","title":"19 大象的耳朵","paragraphs":["大象有一对大耳朵，像扇子似的，耷拉着。","这一天，大象正在路上慢慢地散步，遇到了小兔子。","小兔子说：“咦，大象啊，你的耳朵怎么耷拉下来了？”","大象说：“我生来就是这样啊。”","小兔子说：“你看，我的耳朵是竖着的，你的耳朵一定是出毛病了。”","后来，大象又遇到了小羊。小羊也说：“大象啊，你的耳朵怎么是耷拉着的呢？”","小鹿、小马，还有小老鼠，见到了大象，都要说他的耳朵。","大象也不安起来，他自言自语地说：“他们都这么说，是不是我的耳朵真的有毛病啦？我得让我的耳朵竖起来。”","怎么才能让耳朵竖起来呢？","每天，大象站着睡觉的时候，就用两根竹竿把耳朵撑起来。","可是，大象的耳朵眼儿里，经常有小虫子飞进去，还在里面跳舞，吵得他又头痛，又心烦。","最后，大象还是把他的耳朵放了下来。这样，虫子飞不进去了。有虫子来的话，大象只要把他的大耳朵一扇，就能把他们赶跑。","大象说：“我还是让耳朵耷拉着吧。人家是人家，我是我。”"]},{"id":154,"grade":"二年级下册","title":"20 蜘蛛开店","paragraphs":["有一只蜘蛛，每天蹲在网上等着小飞虫落在上面，好寂寞，好无聊啊。","蜘蛛决定开一家商店。卖什么呢？就卖口罩吧，因为口罩织起来很简单。","于是，蜘蛛在一间小木屋外面挂了一个招牌，上面写着：“口罩编织店，每位顾客只需付一元钱。”","顾客来了，是一只河马。河马嘴巴那么大，口罩好难织啊，蜘蛛用了一整天的工夫，终于织完了。","晚上，蜘蛛想：还是卖围巾吧，因为围巾织起来很简单。","第二天，蜘蛛的招牌换了，上面写着：“围巾编织店，每位顾客只需付一元钱。”","顾客来了，只见身子不见头。蜘蛛向上一看，原来是一只长颈鹿，他的脖子和大树一样高，脑袋从树叶间露出来，正对着蜘蛛笑呢。","蜘蛛织啊织，足足忙了一个星期，才织完那条长长的围巾。","蜘蛛累得趴倒在地上，心里想：还是卖袜子吧，因为袜子织起来很简单。","第二天，蜘蛛的招牌又换了，上面写着：“袜子编织店，每位顾客只需付一元钱。”","可是，蜘蛛看到顾客后，却吓得匆忙跑回网上。原来那位顾客竟是一条四十二只脚的蜈蚣！"]},{"id":155,"grade":"二年级下册","title":"21 青蛙卖泥塘","paragraphs":["青蛙住在烂泥塘里。他觉得这儿不怎么样，想把泥塘卖掉，换一些钱搬到城里住。","于是青蛙在泥塘边竖起一块牌子，上面写着“卖泥塘”三个字。","“卖泥塘喽，卖泥塘！”青蛙站在牌子边大声吆喝起来。一头老牛走过来，看了看泥塘，说：“这个水坑坑嘛，在里边打打滚倒挺舒服。不过，要是周围有些草就更好了。”","老牛不想买泥塘，走了。","青蛙想，要是在泥塘周围种些草，就能卖出去了。于是他就去采集草籽，播撒在泥塘周围的地上。","到了春天，泥塘周围长出了绿茵茵的小草。青蛙又站在牌子旁边，大声吆喝起来：“卖泥塘喽，卖泥塘！”一只野鸭飞来了，看了看泥塘，说：“这地方好是好，就是塘里的水太少了。”","野鸭没有买泥塘，飞走了。","青蛙想，要是能往泥塘里引些水，就能卖出去了。于是他跑到周围的山里找到泉水，又砍了些竹子，把竹子破开，一根一根接起来，把水引到泥塘里来。","等泥塘里灌足了水以后，青蛙又站在牌子旁，大声吆喝起来：“卖泥塘喽，卖泥塘！”可是泥塘还是没有卖出去。","小鸟飞来说，这里缺点儿树；蝴蝶飞来说，这里缺点儿花；小兔跑来说，这里还缺条路；小猴跑来说，这儿应该盖所房子；小狐狸说……每次听了小动物的话，青蛙都想：对！对！要是那样的话，泥塘准能卖出去。于是青蛙就照着他们的话去做，栽了树，种了花，修了路，还在泥塘旁边盖了房子。","“卖泥塘喽，卖泥塘！”有一天，青蛙又站在牌子旁吆喝起来，“多好的地方！有树，有花，有草，有水塘。你可以看蝴蝶在花丛中飞舞，听小鸟在树上唱歌。你可以在水里尽情游泳，躺在草地上晒太阳。这儿还有道路通到城里……”青蛙说到这里，突然愣住了，他想：这么好的地方，自己住挺好的，为什么要卖掉呢？","于是青蛙不再卖泥塘了。"]},{"id":156,"grade":"二年级下册","title":"22 小毛虫","paragraphs":["一条小毛虫趴在一片叶子上，用新奇的目光打量着周围的一切：大大小小的昆虫又是唱，又是跳，跑的跑，飞的飞……到处生机勃勃。只有它，这个可怜的小毛虫，既不会唱，也不会跑，更不会飞。","小毛虫费了九牛二虎之力，才挪动了一点点。当它笨拙地从一片叶子爬到另一片叶子上时，它觉得自己仿佛周游了整个世界。","尽管如此，它并不悲观失望，也不羡慕任何人。它懂得：每个人都有自己该做的事情。它，一条小小的毛虫，眼前最要紧的是学会抽丝纺织，为自己编织一间牢固的茧屋。","小毛虫一刻也没有迟疑，尽心竭力地工作着。它织啊，织啊，最后把自己从头到脚裹进了温暖的茧屋里。","“以后会怎样呢？”它在与世隔绝的茧屋里问。","“万事万物都有自己的规律！”小毛虫听到一个声音在回答，“你要耐心等待，以后会明白的。”","时辰到了，它清醒了过来，再也不是以前那条笨手笨脚的小毛虫。它灵巧地从茧子里挣脱出来，惊奇地发现自己身上生出了一对轻盈的翅膀，上面布满色彩斑斓的花纹。它愉快地舞动了一下双翅，如绒毛一般，从叶子上飘然而起。它飞啊飞，渐渐地消失在蓝色的雾霭之中。"]},{"id":157,"grade":"二年级下册","title":"语文园地","paragraphs":["扫帚 抹布 拖把 水桶 簸箕","扫地 擦玻璃 倒垃圾 摆桌椅","扫 帚 抹 拖 簸","箕 玻 璃 垃 圾","那棵大枫树好像一把又高又大的绿色太阳伞。","大象有一对大耳朵，像扇子似的，耷拉着。","绿油油的小柏树就像战士一样笔直地站在那里。","春雨惊春清谷天，","夏满芒夏暑相连。","秋处露秋寒霜降，","冬雪雪冬小大寒。","夜晚，月亮姑娘出来了，细细的，弯弯的，像眉毛。凉风吹得她有点儿冷，她想，还是找一位裁缝师傅做件衣裳吧！","裁缝师傅给她量了尺寸，让她四天以后来取。过了四天，月亮姑娘长胖了一点儿，好像弯弯的镰刀。她来取衣裳了。衣裳做得真漂亮，可惜太小，穿在身上连扣子也扣不上。","裁缝师傅决定重做一件，又给她量了尺寸，让她再过四天来取。过了四天，月亮姑娘又长胖了一点儿，像只核桃。她来取衣裳了。衣裳做得更漂亮，可惜连套也套不进去。","裁缝师傅涨红了脸，说：“我只好重做了。”又是四天过去了，月亮姑娘来取衣裳。裁缝师傅看到她变得圆圆的，像一只圆盘，吃了一惊：“啊？你又长胖了！”他叹了一口气，说：“唉，你的身材量不准，我没法给你做衣裳了。”","月亮姑娘看着那漂亮的衣裳，又望望自己圆圆的身子，不好意思地对裁缝师傅说：“不，老师傅，这不能怨您。不是您量不准，而是我每天都在变化。”","后来，月亮姑娘再也不找人做衣裳了。"]},{"id":158,"grade":"二年级下册","title":"23 祖先的摇篮","paragraphs":["爷爷说：","那原始森林","是我们祖先的摇篮。","真有意思，","这是多大的摇篮啊！","那浓绿的树荫","一望无边，","遮住了蓝天。","我想——","我们的祖先，","可曾在这些大树上","摘野果，","掏鹊蛋？","可曾在那片草地上","和野兔赛跑，","看蘑菇打伞？","那时候，","孩子们也在这里","逗小松鼠，","采野蔷薇吗？","也在这里，","捉红蜻蜓，","逮绿蝈蝈吗？","风儿吹动树叶","“沙沙，沙沙！”","那回忆","多么美好，","又那么遥远……","啊！","苍苍茫茫的原始森林，","我们祖先的摇篮！"]},{"id":159,"grade":"二年级下册","title":"24  羿射九日","paragraphs":["很久很久以前，在世界最东边的海上，生长着一棵大树叫扶桑。扶桑的枝头站着一个太阳，底下还有九个太阳。每天天快亮时，扶桑枝头的太阳就坐上两轮车，开始从东往西穿过天空。十个太阳每天轮换，给大地万物带来光明和温暖。","可是，有一天，这十个太阳觉得轮流值日太没意思啦，于是，他们一齐跑了出来，出现在天空中。十个太阳像十个大火球，炙烤着大地。","禾苗被晒枯了，土地被烤焦了，江河里的水快要蒸干了，连地上的沙石好像都要熔化了。人类的日子非常艰难。","神箭手羿决心帮助人们脱离苦海。他翻过九十九座高山，跨过九十九条大河，来到东海边。他登上一座大山，搭上神箭，拉开神弓，对准天上的一个太阳，嗖地就是一箭。那个太阳一下子爆裂开，一团团火球到处乱窜，接着，噗噗地掉在地上。","羿一口气射下了九个太阳，炎热渐渐退去。羿又伸手拔箭，准备射下最后一个太阳。这个太阳害怕极了，慌慌张张地躲进了大海里。","天上没有了太阳，整个世界一片黑暗。羿想，没有了太阳，就没有了光明和温暖，庄稼不能生长，人类和动物也没法活下去。于是，羿留下了最后一个太阳。","从此，太阳每天从东方升起，到西方落下。土地渐渐滋润起来，花草树木渐渐繁茂起来，江河奔腾欢唱，大地上重新现出了勃勃生机。"]},{"id":160,"grade":"二年级下册","title":"25 黄帝的传说","paragraphs":["相传五六千年前，有一个部落的首领名叫轩辕。他有很多创造发明，深受人们爱戴。大家推举他统领部落联盟，尊称他为“黄帝”。","造车","那时候，人们出远门都得靠步行，运东西也只能依靠人力，既不方便，又很辛苦。","有一年夏天，黄帝正在干活，突然一阵大风刮来，把他的草帽吹掉了。草帽是圆的，掉到地上后向前滚出了很远。这件事给了黄帝启发，他想，如果能做个架子，再装上像草帽一样能滚动的东西，就可以用来搬运东西了。于是，他号召部落民众，按照设想找来需要的材料，试了一次又一次，终于把车造出来，样子就像现在的独轮手推车。","后来，人们在使用过程中不断改进。发明了双轮车，又驯服了牛和马，用他们来代替人拉车，出远门、搬运东西方便多了。","造船","一个秋天的傍晚，黄帝干完活了，同大伙坐在河边休息。他看见水面上漂着许多树叶，其中一个叶片上有一只蚂蚁，虽然河水很深，蚂蚁却安安稳稳地在上面爬着。","黄帝指着那片树叶，高兴地对大家说：“你们看，蚂蚁待在树叶上，就能在河里浮着不沉下去。如果造一个像树叶一样浮在水面的东西，能让人待在上面，我们就可以在水上自由来去了”。大家听了，都觉得很有道理。","第二天，他们找来一根很粗很粗的树干，把它放进河里。可是，树干是圆的，人一爬上去，它就滚动起来，人在上面根本待不住。怎么办呢?他们一起商量，终于想出了办法，把树干中间的一段挖空，人在里面，果然能坐稳了。他们又用木头做了桨，就能在水面上自由行动了。","车和船的发明，使水陆交通得到了发展，为人们相互往来提供了便利，给人们的生活带来了很大的改善；"]},{"id":161,"grade":"二年级下册","title":"语文园地","paragraphs":["钩（钩子）   铲（铲子）","梅（梅花）   柿（柿子）","源（源头）   涨（涨潮）","炬（火炬）   灿（灿烂）","垮（垮掉）   坟（坟墓）","钩 铲 梅 柿 源","涨 炬 灿 垮 坟","神  祖  礼  福","冰  冷  冻  凉","补  袜  衫  被","海  流  洒  滴","作者：[清代] 查慎行","月黑见渔灯，","孤光一点萤。","微微风簇浪，","散作满河星。","漆黑无月的夜里，孤零零的一盏渔灯像萤火虫一样闪现在河面。","一阵微风吹来，河面漾起了层层细浪，水面上的光点随着波浪散开，如同满河星光。","查慎行（1650～1727） 清代诗人，当代著名作家金庸先祖。初名嗣琏，字夏重，号查田；后改名慎行，字悔余，号他山，赐号烟波钓徒，晚年居于初白庵，所以又称查初白。海宁袁花（今属浙江）人。康熙四十二年(1703)进士；特授翰林院编修，入直内廷。五十二年（1713），乞休归里，家居10余年。雍正四年（1726），因弟查嗣庭讪谤案，以家长失教获罪，被逮入京，次年放归，不久去世。查慎行诗学东坡、放翁，尝注苏诗。自朱彝尊去世后，为东南诗坛领袖。著有《他山诗钞》。","明朝出了一位伟大的医药学家，叫李时珍。","李时珍家世代行医。他的父亲医术很高，给穷人看病常常不收诊费。李时珍看到医生能救死扶伤，解除病人的痛苦，就从小立下志向，要像父亲一样为穷人看病。","李时珍处处留心向父亲学习，二十二岁开始给人看病，一面行医，一面研究药物。他发现旧的药物书有不少缺点：许多有用的药物没有记载；有些药物只记了个名称，没有说明形状和生长情况；还有一些药物记错了药性和药效。他想，病人吃错了药，那多危险啊，于是决定重新编写一部完善的药物书。","为了写这部药物书，李时珍不但在治病的时候注意积累经验，还到各地去采药。他不怕山高路远，不怕严寒酷暑，走遍了万水千山。他有时上山采药好几天不下山，饿了就吃些干粮，天黑了就在山上过夜。他走了上万里路，拜访了千百个医生、农民、渔民和猎人，向他们学到了书上没有的知识。他还冒着生命危险尝药材，判断药性和药效。","几年之后，他回到老家，开始写书。他用了整整二十七年，终于编写成了一部新的药物书，就是著名的《本草纲目》。","忽然  突然   立刻  马上","一瞬间  一眨眼","逐渐  渐渐   慢慢  徐徐","慢吞吞  慢悠悠","最后一个太阳害怕极了，慌慌张张地躲进了大海里。"]},{"id":162,"grade":"三年级上册","title":"1 大青树下的小学","paragraphs":["早晨，从山坡上，从坪坝里，从一条条开着绒球花和太阳花的小路上，走来了许多小学生，有汉族的，有傣族的，有景颇族的，还有阿昌族和德昂族的。大家穿戴不同，来到学校，都成了好朋友。那鲜艳的服装，把学校打扮得绚丽多彩。同学们向在校园里欢唱的小鸟打招呼，向敬爱的老师问好，向高高飘扬的国旗敬礼。","“当，当当！当，当当！”大青树上的铜钟敲响了。","上课了，不同民族的小学生，在同一间教室里学习。大家一起朗读课文，那声音真好听！这时候，窗外十分安静，树枝不摇了，鸟儿不叫了，蝴蝶停在花朵上，好像都在听同学们读课文。最有趣的是，跑来了两只猴子。这些山林里的朋友，是那样好奇地听着。下课了，大家在大青树下跳孔雀舞，摔跤，做游戏，招引来许多小鸟，连松鼠也赶来看热闹。","这就是我们可爱的小学，一所边疆的小学。古老的铜钟，挂在大青树粗壮的枝干上。凤尾竹的影子，在洁白的墙上摇晃……"]},{"id":163,"grade":"三年级上册","title":"2 花的学校","paragraphs":["当雷云在天上轰响，六月的阵雨落下的时候，湿润的东风走过荒野，在竹林中吹着风笛。","于是，一群一群的花从无人知道的地方突然跑出来，在绿草上跳舞，狂欢。","妈妈，我真的觉得那些花朵是在地下的学校里上学。","他们关了门做功课。如果他们想在放学以前出来游戏，他们的老师是要罚他们的。","雨一来，他们便放假了。","树枝在林中互相碰触着，绿叶在狂风里簌簌地响，雷云拍着大手。这时，花孩子们便穿了紫的、黄的、白的衣裳，冲了出来。","你可知道，妈妈，他们的家是在天上，在星星所住的地方。","你没有看见他们怎样地急着要到那儿去吗？你不知道他们为什么那样急急忙忙吗？","我自然能够猜得出他们是对谁扬起双臂来，他们也有他们的妈妈，就像我有我自己的妈妈一样。"]},{"id":164,"grade":"三年级上册","title":"3* 不懂就要问","paragraphs":["孙中山小时候在私塾读书。那时候上课，先生念，学生跟着念，咿咿呀呀，像唱歌一样。学生读熟了，先生就让他们一个一个地背诵。至于书里的意思，先生从来不讲。","一天，孙中山来到学校，照例把书放到先生面前，流利地背出前一天所学的功课。先生听了，连连点头。接着，先生在孙中山的书上又圈了一段，他念一句，叫孙中山念一句。孙中山会读了，就回到座位上练习背诵。孙中山读了几遍，就背下来了。可是，书里说的是什么意思，他一点儿也不懂。孙中山想：这样糊里糊涂地背，有什么用呢？于是，他壮着胆子站起来，问：“先生，您刚才让我背的这段书是什么意思?请您给我讲讲吧！”","这一问，把正在摇头晃脑高声念书的同学们吓呆了，课堂里霎时变得鸦雀无声。","先生拿着戒尺，走到孙中山跟前，厉声问道：“你会背了吗？”","“会背了。”孙中山说着，就把那段书一字不漏地背了出来。","先生收起戒尺，摆摆手让孙中山坐下，说：“我原想，书中的道理，你们长大了自然会知道的。现在你们既然想听，我就讲讲吧！”","先生讲得很详细，大家听得很认真。","后来，有个同学问孙中山：“你向先生提出问题，不怕挨打吗？”","孙中山笑了笑，说：“学问学问，不懂就要问。为了弄清楚道理，就是挨打也值得。”"]},{"id":165,"grade":"三年级上册","title":"语文园地","paragraphs":["作者：[清代] 袁枚","牧童骑黄牛，","歌声振林樾。","意欲捕鸣蝉，","忽然闭口立。","牧童骑在黄牛背上，嘹亮的歌声在树林里回荡。","牧童大概是想要捕捉那正在鸣叫的蝉，突然停止了行走，不再高声歌唱了。","袁枚（1716－1797）清代诗人、散文家。字子才，号简斋，晚年自号仓山居士、随园主人、随园老人。汉族，钱塘（今浙江杭州）人。乾隆四年进士，历任溧水、江宁等县知县，有政绩，四十岁即告归。在江宁小仓山下筑筑随园，吟咏其中。广收诗弟子，女弟子尤众。袁枚是乾嘉时期代表诗人之一，与赵翼、蒋士铨合称“乾隆三大家”。","摇头晃脑　披头散发","张牙舞爪　提心吊胆","面红耳赤　手忙脚乱","眼疾手快　口干舌燥","妈妈，我真的觉得那些花朵是在地下的学校里上学。","书里说的是什么意思，他一点儿也不懂。","孙中山笑了笑，说：“学问学问，不懂就要问。为了弄清楚道理，就是挨打也值得。”"]},{"id":166,"grade":"三年级上册","title":"山行","paragraphs":["作者：[唐代] 杜牧","远上寒山石径斜，","白云生处有人家。","停车坐爱枫林晚，","霜叶红于二月花。","深秋时节，沿着远处的石子铺成的倾斜小路上山，在那生出白云的地方居然还有几户人家。","停下马车是因为喜爱深秋枫林的晚景，经过深秋寒霜的枫叶，比二月的春花还要红。","杜牧（公元803－约852年），字牧之，号樊川居士，汉族，京兆万年（今陕西西安）人，唐代诗人。杜牧人称“小杜”，以别于杜甫。与李商隐并称“小李杜”。因晚年居长安南樊川别墅，故后世称“杜樊川”，著有《樊川文集》。"]},{"id":167,"grade":"三年级上册","title":"赠刘景文","paragraphs":["作者：[宋代] 苏轼","荷尽已无擎雨盖，","菊残犹有傲霜枝。","一年好景君须记，","最是橙黄橘绿时。","荷花凋谢连那擎雨的荷叶也枯萎了，只有那开败了菊花的花枝还傲寒斗霜。","一年中最好的光景你一定要记住，那就是橙子金黄、橘子青绿的秋末冬初的时节啊。","苏轼，（1037年1月8日-1101年8月24日）字子瞻、和仲，号铁冠道人、东坡居士，世称苏东坡、苏仙，汉族，眉州眉山（四川省眉山市）人，祖籍河北栾城，北宋著名文学家、书法家、画家，历史治水名人。苏轼是北宋中期文坛领袖，在诗、词、散文、书、画等方面取得很高成就。文纵横恣肆；诗题材广阔，清新豪健，善用夸张比喻，独具风格，与黄庭坚并称“苏黄”；词开豪放一派，与辛弃疾同是豪放派代表，并称“苏辛”；散文著述宏富，豪放自如，与欧阳修并称“欧苏”，为“唐宋八大家”之一。苏轼善书，“宋四家”之一；擅长文人画，尤擅墨竹、怪石、枯木等。与韩愈、柳宗元和欧阳修合称“千古文章四大家”。作品有《东坡七集》《东坡易传》《东坡乐府》《潇湘竹石图卷》《古木怪石图卷》等。"]},{"id":168,"grade":"三年级上册","title":"夜书所见","paragraphs":["作者：[宋代] 叶绍翁","萧萧梧叶送寒声，","江上秋风动客情。","知有儿童挑促织，","夜深篱落一灯明。","瑟瑟的秋风吹动梧桐树叶，送来阵阵寒意，江上秋风吹来不禁思念起自己的家乡。","忽然看到远处篱笆下的一点灯火，料想是孩子们在捉蟋蟀。","叶绍翁，南宋中期诗人，字嗣宗，号靖逸，处州龙泉人。祖籍建安（今福建建瓯），本姓李，后嗣于龙泉(今属浙江丽水)叶氏。生卒年不详。曾任朝廷小官。其学出自叶适，他长期隐居钱塘西湖之滨，与真德秀交往甚密，与葛天民互相酬唱。"]},{"id":169,"grade":"三年级上册","title":"5 铺满金色巴掌的水泥道","paragraphs":["一夜秋风，一夜秋雨。","我背着书包去上学时，天开始放晴了。","啊！多么明朗的天空。","可是，地面还是潮湿的，不时还能看见一个亮晶晶的水洼，映着一角小小的蓝天。","道路两旁的法国梧桐树，掉下了一片片金黄金黄的叶子。这一片片闪着雨珠的叶子，一掉下来，便紧紧地粘在湿漉漉的水泥道上了。","我走在院墙外的水泥道上。水泥道像铺上了一块彩色的地毯，这是一块印着落叶图案的、闪闪发光的地毯，从脚下一直铺到很远很远的地方，一直到路的尽头……","每一片法国梧桐树的落叶，都像一个金色的小巴掌，熨帖地、平展地粘在水泥道上。它们排列得并不规则，甚至有些凌乱，然而，这更增添了水泥道的美。","我一步一步小心地走着，一片一片仔细地数着。我穿着一双棕红色的小雨靴。你瞧，这多像两只棕红色的小鸟，在秋天金黄的叶丛间，愉快地蹦跳着，歌唱着……","要不是怕上课迟到，我会走得很慢很慢的。","一夜秋风，一夜秋雨。","当我背着书包去上学时，第一回觉得，门前的水泥道真美啊！"]},{"id":170,"grade":"三年级上册","title":"6 秋天的雨","paragraphs":["秋天的雨，是一把钥匙。它带着清凉和温柔，轻轻地，轻轻地，趁你没留意，把秋天的大门打开了。","秋天的雨，有一盒五彩缤纷的颜料。你看，它把黄色给了银杏树，黄黄的叶子像一把把小扇子，扇哪扇哪，扇走了夏天的炎热。它把红色给了枫树，红红的枫叶像一枚枚邮票，飘哇飘哇，邮来了秋天的凉爽。金黄色是给田野的，看，田野像金色的海洋。橙红色是给果树的，橘子、柿子你挤我碰，争着要人们去摘呢！菊花仙子得到的颜色就更多了，紫红的、淡黄的、雪白的……美丽的菊花在秋雨里频频点头。","秋天的雨，藏着非常好闻的气味。梨香香的，菠萝甜甜的，还有苹果、橘子，好多好多香甜的气味，都躲在小雨滴里呢！小朋友的脚，常被那香味勾住。","秋天的雨，吹起了金色的小喇叭，它告诉大家，冬天快要来了。小松鼠找来松果当粮食，小青蛙在加紧挖洞，准备舒舒服服地睡大觉。松柏穿上厚厚的、油亮亮的衣裳，杨树、柳树的叶子飘到树妈妈的脚下。它们都在准备过冬了。","秋天的雨，带给大地的是一曲丰收的歌，带给小朋友的是一首欢乐的歌。"]},{"id":171,"grade":"三年级上册","title":"7* 听听，秋的声音","paragraphs":["听听，","秋的声音，","大树抖抖手臂，","“唰唰”，","是黄叶道别的话音。","听听，","秋的声音，","蟋蟀振动翅膀，","“㘗 㘗”，","是和阳台告别的歌韵。","一排排大雁追上白云，","撒下一阵暖暖的叮咛；","一阵阵秋风掠过田野，","送来一片丰收的歌吟。","听听，","走进秋，","走进这辽阔透明的音乐厅，","你好好地去听","——秋的声音。","秋的声音，","在每一片叶子里，","在每一朵小花上，","在每一滴汗水里，","在每一颗饱满的谷粒里。","听听，","秋的声音，","从远方匆匆地来，","向远方匆匆地去。","听听，","我们去听秋的声音。"]},{"id":172,"grade":"三年级上册","title":"语文园地","paragraphs":["秋高气爽 天高云淡 秋风习习","一叶知秋 金桂飘香 层林尽染","五谷丰登 果实累累 春华秋实","春：暖和　春光明媚","夏：","秋：","冬：","听了老师的这番话，我憧憬着即将到来的一天，期待着在活动中有出色的表现。","小明打碎了家里的花瓶，心中有些忐忑不安，害怕爸爸妈妈会责备他。"]},{"id":173,"grade":"三年级上册","title":"8 卖火柴的小女孩","paragraphs":["天冷极了，下着雪，又快黑了。这是一年的最后一夜。在这又冷又黑的晚上，一个穷苦的小女孩，没戴帽子，赤着脚在街上走着。她从家里出来的时候还穿着一双拖鞋，但是有什么用呢？那是一双很大的拖鞋——那么大，一向是她妈妈穿的。她穿过马路的时候，两辆马车飞快地冲过来，吓得她把鞋都跑掉了。一只怎么也找不着，另一只叫一个男孩捡起来拿着跑了。他说，将来他有了孩子可以用它当摇篮。","小女孩只好赤着脚走，一双小脚冻得红一块青一块的。她的旧围裙里兜着许多火柴，手里还拿着一把。这一整天，谁也没买过她一根火柴，谁也没给过她一个硬币。","可怜的小女孩！她又冷又饿，哆哆嗦嗦地向前走。雪花落在她金黄的长头发上，那头发打成卷披在肩上，看上去很美丽，不过她没注意这些。每个窗子里都透出灯光来，街上飘着一股烤鹅的香味，因为这是一年的最后一夜——她可忘不了这个。","她在一座房子的墙角坐下来，蜷着腿缩成一团。她觉得更冷了。她不敢回家，因为她没卖掉一根火柴，没挣到一个钱，爸爸一定会打她的。再说，家里跟街上一样冷。他们头上只有个房顶，虽然最大的裂缝已经用草和破布堵住了，但风还是可以灌进来。","她的一双小手几乎冻僵了。啊，哪怕一根小小的火柴，对她也是有好处的！她敢从成把的火柴里抽出一根，在墙上擦燃了，来暖和暖和自己的小手吗？她终于抽出了一根。哧！火柴燃起来了，冒出火焰来了！她把小手拢在火焰上。多么温暖多么明亮的火焰啊，简直像一支小小的蜡烛。这是一道奇异的火光！小女孩觉得自己好像坐在一个大火炉前面，火炉装着闪亮的铜脚和铜把手，烧得旺旺的，暖烘烘的，多么舒服啊！唉，这是怎么回事呢？她刚把脚伸出去，想让脚也暖和一下，火柴灭了，火炉不见了。她坐在那儿，手里只有一根烧过了的火柴梗。","她又擦了一根。火柴燃起来了，发出亮光来了。亮光落在墙上，那儿忽然变得像薄纱那么透明，她可以一直看到屋里。桌上铺着雪白的台布，摆着精致的盘子和碗，肚子里填满了苹果和梅子的烤鹅正冒着香气。更妙的是这只鹅从盘子里跳下来，背上插着刀和叉，摇摇摆摆地在地板上走着，一直向这个穷苦的小女孩走来。这时候，火柴灭了，她面前只有一堵又厚又冷的墙。","她又擦着了一根火柴。这一回，她坐在美丽的圣诞树下。这棵圣诞树，比她去年圣诞节透过富商家的玻璃门看到的还要大，还要美。翠绿的树枝上点着几千支明晃晃的蜡烛，许多幅美丽的彩色画片，跟挂在商店橱窗里的一个样，在向她眨眼睛。小女孩向画片伸出双手。这时候，火柴又灭了。只见圣诞树上的烛光越升越高，最后成了在天空中闪烁的星星。有一颗星星落了下来，在天空中划出了一道细长的红光。“有一个什么人快要死了。”小女孩说。唯一疼她的奶奶活着的时候告诉过她∶一颗星星落下来，就有一个人要离去了。","她在墙上又擦着了一根火柴。这一回，火柴把周围全照亮了。奶奶出现在亮光里，是那么温和，那么慈爱。“奶奶！”小女孩叫起来，“啊！请把我带走吧！我知道，火柴一灭，您就会不见的，像那暖和的火炉，喷香的烤鹅，美丽的圣诞树一样，就会不见的！”","她赶紧擦着了一大把火柴，要把奶奶留住。一大把火柴发出强烈的光，照得跟白天一样明亮。奶奶从来没有像现在这样高大，这样美丽。奶奶把小女孩抱起来，搂在怀里。她俩在光明和快乐中飞走了，越飞越高，飞到那没有寒冷，没有饥饿，也没有痛苦的地方去了。","第二天清晨，这个小女孩坐在墙角，两腮通红，嘴上带着微笑。她死了，在旧年的最后一夜冻死了。新年的太阳升起来了，照在她小小的尸体上。小女孩坐在那儿，手里还捏着一把烧过了的火柴梗。","“她想给自己暖和一下……”人们说。谁也不知道她曾经看到过多么美丽的东西，她曾经多么幸福，跟着她奶奶一起向新年的幸福中走去。"]},{"id":174,"grade":"三年级上册","title":"9* 那一定会很好","paragraphs":["种子被泥土紧紧地包裹着，它不得不把身体缩成一团。“这真难受。”种子想，“我一定要站起来，大口大口地呼吸空气，那一定会很好。”","种子一边想一边努力生长。过了些日子，它长出细细的根、茎和两片小叶子，钻出地面，站在阳光下。","过了很多个日子，它长成了一棵高大的树。","高大的树能看到很远的地方，它看见人和动物在山路上走来走去，跑来跑去。“要是能做一棵会跑的树，那一定会很好。”树这么想着。","一天，一个农夫背了锯子和斧子来到树林里。这棵树的树叶向着农夫哗哗哗地拂动起来，农夫把树砍倒了。","农夫把树拖到自家院子里，花了好些日子，做成了一辆手推车。","农夫把谷子、土豆……还有调皮的儿子，放在手推车上，推着车在山路上跑来跑去。跑起来的时候，手推车听到耳边呼呼的风声，真舒服。","手推车为农夫服务了很多年，它慢慢变老了，跑起来的时候，骨头会吱吱嘎嘎地响。“要是我能停下来，坐着休息一会儿，那一定会很好。”手推车一边这么想着，一边费力地跑来跑去。","过了些日子，农夫和儿子一起把手推车拆了，用拆下来的旧木料做了把椅子。","椅子一用又是好多年。“我真是老了。”椅子想。它越来越觉得挺直腰背坐着很吃力，“要是我能躺下，那一定会很好。”","“现在，农夫的儿子也已经长成了真正的农夫。他把坐上去会吱呀摇晃的椅子拆了，锯成小木片，拼成美丽的木地板，铺在了阳台上。","木地板满意地舒展着身子，躺在阳台上，阳光照在身上，暖洋洋的，舒服极了。它觉得自己又变成了一棵树。"]},{"id":175,"grade":"三年级上册","title":"10 在牛肚子里旅行","paragraphs":["有两只小蟋蟀，一只叫青头，另一只叫红头。它们是一对非常要好的朋友。有一天，吃过早饭，青头对红头说：“咱们玩捉迷藏吧！”","“那让我先藏，你来找。”红头说。","“好吧！”青头说完，转过身子闭上眼睛。","红头向周围看了看，悄悄地躲在一个草堆里不作声了。","“藏好了吗？”青头大声问。","红头不说话，只露两只眼睛偷偷地看。它心想：我要是一答应，就会被青头发现。","正在这时，一头大黄牛从红头后面慢慢走过来。红头做梦也没有想到，大黄牛突然低下头来吃草。可怜的红头还没有来得及跳开，就和草一起被大黄牛卷到嘴里了。","“救命啊！救命啊！”红头拼命地叫起来。","“你在哪儿？”青头急忙问。","“我被牛吃了……正在它的嘴里……救命啊！救命啊！”","青头大吃一惊，它一下子蹦到牛身上。可是那头牛用尾巴轻轻一扫，青头就给摔到地上了。青头不顾身上的疼痛，一骨碌爬起来大声喊：“躲过它的牙齿，牛在这时候不会仔细嚼的，它会把你和草一起吞到肚子里去……”","“那我马上就会死掉。”红头哭起来。它和草已经一起进了牛的肚子。","青头又跳到牛身上，隔着肚皮和红头说话：“红头！不要怕，你会出来的！我听说，牛肚子里一共有四个胃，前三个胃是贮藏食物的，只有第四个胃才是管消化的！”","“可是，你说这些对我有什么用呢？”红头悲哀地说。","“当然有用。等一会儿牛休息的时候，它要把刚才吞进去的草重新送回嘴里，然后细嚼慢咽……你是勇敢的蟋蟀，你一定能出来的。”","“谢谢你！”红头的声音小得几乎听不见了。它咬着牙不让自己失去知觉。","红头在牛肚子里随着草一起移动。从第一个胃到了第二个胃，又从第二个胃回到了牛嘴里。这一下，红头又看见了光亮。可是，它已经一动也不能动了。","这时，青头爬到了牛鼻子上，用它的身体在牛鼻孔里蹭来蹭去。","“阿嚏！”牛打了一个喷嚏。红头随着一团草一下子给喷了出来。","红头看见自己的朋友，高兴地流下了眼泪：“谢谢你……”","青头笑眯眯地说：“不要哭，就当你在牛肚子里作了一次旅行吧！”"]},{"id":176,"grade":"三年级上册","title":"11* 一块奶酪","paragraphs":["蚂蚁队长集合好队伍，向大家宣布：“今天搬运粮食，只许出力，不许偷嘴。谁偷嘴就要处罚谁。“","一只小蚂蚁在队列里嘀咕：“要是偷嘴的是您呢？”蚂蚁队长说：“照样要受处罚。”","大家一听，都来劲了，争先恐后赶到运粮地点，抢着抬大的，搬重的，谁也不愿偷懒。","就在这时，蚂蚁队长发现了一块大奶酪。那块奶酪实在太大了，它左抬抬不起，右搬搬不动，只好叫来七八只小蚂蚁当助手。","奶酪多诱人啊！抬着它，不要说吃，单是闻闻，都要淌口水。小蚂蚁们嘴叼着它，要做到不趁机舔一下，那要有多大的毅力，多强的纪律性啊！","蚂蚁队长叼着奶酪的一角往前拽着，也许是用力过猛，一下就把那个角拽掉了。盯着那一点儿掉在地上的奶酪渣，蚂蚁队长想：丢掉，实在太可惜；趁机吃掉它，又要犯不许偷嘴的禁令。怎么办呢？它的心七上八下，只好下令：“休息一会儿！”","听到命令，大家放下奶酪，却不走开。","“大家分散开，哪里凉快就到哪里休息。”","大家依旧不动，眼睛望着别处，心却牵挂着那一点儿奶酪渣。","蚂蚁队长生气了。它登上一块大石板，突然下令：“注意啦，全体都有。稍息！立正！向后——转！齐步——走！”等小蚂蚁们消失在草丛中，他才大叫：“立——定！原地休息！”","这时，奶酪旁边只有蚂蚁队长，它要是偷嘴，谁也看不见。它低下头，嗅嗅那点儿奶酪渣，味道真香！可是，它犹豫了一会儿，终于一跺脚：“注意啦，全体都有。稍息！立正！向后——转！齐步——走！”","小蚂蚁们从四面八方的草丛里走拢来了。当它们重新聚到奶酪旁边时，蚂蚁队长命令年龄最小的一只蚂蚁：“这点儿奶酪渣是刚才弄掉的，丢了可惜，你吃掉它吧！”","大家又干起活来了，劲头比刚才更足，奶酪一会儿就被搬进洞里去了。"]},{"id":177,"grade":"三年级上册","title":"语文园地","paragraphs":["伸—申 （申请） 界—介（介绍）","棕—宗 （祖宗） 忆—乙（乙方）","试—式 （方式） 教—孝（孝顺）","申 介 绍 宗 乙 式 孝","灯不拨不亮，理不辩不明。","有理走遍天下，无理寸步难行。","一时强弱在于力，万古胜负在于理。","在那奇妙的王国里","在童话王国里，小蝌蚪四处寻找自己的妈妈，小壁虎着急地向别的动物借尾巴，雪孩子和小白兔在一 起嬉戏玩耍，王子和公主过上了幸福的生活......在那里，一切都有可能发生，一切都妙不可言。","你读过吗","《安徒生童话》创造了一个奇妙的童话王国，这是丹麦作家安徒生送给全世界孩子和大人共同的礼物。卖火柴的小女孩，善良的拇指姑娘，坚定的锡兵，历经磨难的丑小鸭......这些故事里的主人 公，一定会给你留下难以磨灭的印象。","“是的，我要和你一块儿去!”拇指姑娘说。她坐在鸟儿的背上，把脚搁在他展开的双翼上，同时用腰带把自己紧紧地系在他最结实的一根羽毛上。燕子就这样飞到空中，飞过了森林，飞过了海洋，飞过了常年积雪的高山。在寒冷的高空中，拇指姑娘冻得发起抖来。于是她就钻到鸟儿温暖的羽毛下面，只把她的小脑袋伸出来欣赏下面那些美丽的景致。","终于他们来到了温暖的国度，那儿的阳光更加明亮。田沟里、篱笆上，到处都结满了最美丽的绿色和紫色的葡萄。树林里到处挂着柠檬和橙子。","选自丹麦安徒生的《拇指姑娘》，叶君健译","相信你可以读更多","童话王国里还有许许多多动人的故事。","当你走进叶圣陶笔下《稻草人》的世界，你会知道在夜间的田野，星星怎样眨眼，月亮怎样微笑。你还会知道，田野里的人们有着怎样的辛苦和悲伤。","翻开德国格林兄弟搜集整理的《格林童话》，你能从一个个妙趣横生的故事中，感悟生活的真谛和做人的道理。灰姑娘虽然身处逆境,却仍然心怀美好，真诚待人；小裁缝勇敢乐观，用自己的智慧战胜了巨人……","童话王国中充满了爱与美，等待着你去漫游，去发现。"]},{"id":178,"grade":"三年级上册","title":"12 总也倒不了的老屋","paragraphs":["老屋已经活了一百多岁了，它的窗户变成了黑窟窿，门板也破了洞。它很久很久没人住了。","“好了，我到了倒下的时候了！”它自言自语着，准备往旁边倒去。","“等等，老屋！”一个小小的声音在它门前响起，“再过一个晚上，行吗？今天晚上有暴风雨，我找不到一个安心睡觉的地方。”","老屋低头看看，吃力地眯起眼睛：“哦，是小猫啊！好吧，我就再站一个晚上。”","第二天，天晴了。小猫从破窗户里跳了出来：“喵喵，谢谢！”","老屋说：“再见！好了，我到了倒下的时候了！”","“等等，老屋！”一个小小的声音在它门前响起，“再过二十几天，行吗？主人想拿走我的蛋，可是我想孵小鸡，我找不到一个安心孵蛋的地方。”","老屋低头看看，墙壁吱吱呀呀地响：“哦，是老母鸡啊。好吧，我就再站二十几天。”","二十多天后，老母鸡从门上的破洞里走了出来，九只小鸡从门板下面叽叽叫着钻了出来：“叽叽，谢谢！”","老屋说：“再见！好了，我到了倒下的时候了！”","“等等，老屋！”一个小极了的声音在它门前响起，不注意根本听不到，“请再站一会儿吧，我肚子好饿好饿，外面的树被砍光了，我找不到一个安心织网抓虫的地方。”","老屋低头看看，眼睛眯成一条缝：“哦，是小蜘蛛啊。好吧，我就再站一会儿。”","小蜘蛛飞快地爬进屋子，在墙角织了一张又大又漂亮的网。偶尔有虫子撞到网上，小蜘蛛马上爬过去把虫子吃掉。","“小蜘蛛，你吃饱了吗？”老屋问。","“没有，没有！”小蜘蛛一边忙着补网，一边回答，“老屋老屋，我给你讲个故事吧！”","老屋想，这倒很有意思。于是它就开始听小蜘蛛讲故事。","小蜘蛛的故事一直没讲完，因此，老屋到现在还站在那儿，边晒太阳，边听小蜘蛛讲故事。"]},{"id":179,"grade":"三年级上册","title":"13* 胡萝卜先生的长胡子","paragraphs":["胡萝卜先生常常为胡子发愁，因为他长着浓密的胡子，必须每天刮。","有一天，胡萝卜先生匆匆忙忙刮了胡子，就吃着果酱面包上街去了。因为他近视，就没有发现漏刮了一根胡子。这根胡子长在下巴的右边，胡萝卜先生吃果酱面包的时候，胡子沾到了甜甜的果酱。对一根胡子来说，果酱是多么好的营养品啊！","于是胡萝卜先生一步一步走的时候，这根胡子就在一点儿一点儿地变长。只要看看胡萝卜先生走了多长的路，就可以知道他的这根胡子已经长了多长了。","胡萝卜先生还在继续走，长胡子被风吹到了身体后面，他完全不知道。","在很远的街口，有一个男孩正在放风筝，线实在太短了，他的风筝只能飞过屋顶。","胡萝卜先生的胡子刚好在风里飘动着。“这绳子够长了，就是不知道够不够牢固。”小男孩说完就扯了扯胡子，他确定足够牢固，就剪了一段用来放风筝。","胡萝卜先生继续往前走，当他走过鸟太太家的树底下，鸟太太正在找绳子晾小鸟的尿布。","胡萝卜先生的胡子刚好在风里飘动着。","……"]},{"id":180,"grade":"三年级上册","title":"14* 小狗学叫","paragraphs":["从前，有一条不会叫的狗。它不会像狗一样叫，不会像猫一样叫，也不会像牛那样哞哞叫，更不会像马那样嘶鸣。它是一只孤零零的小狗，不知道怎么到了一个没有狗的国家。它并没有发现自己有什么毛病，是别人让它知道，不会叫其实是一种很大的缺陷。它们对它说：","“你怎么不叫？”","“我不会……我是外来的……”","“这算什么回答啊。你难道不知道狗是会叫的？”","“干吗要叫？”","“狗会叫，因为它们是狗。它们对过路的陌生人叫，对惹人讨厌的猫叫，对着满月叫。它们高兴的时候叫，紧张的时候叫，发怒的时候也叫。它们白天叫得多，但晚上也叫。”","“也许是这样，可我……”","“可你怎么啦？你这只狗可真特别。去，去！总有一天你会上新闻的。”","小狗不知道该怎么回答这些批评。它不会叫，也不知道怎么才能学会。","“你跟我学。”有一次，一只同情它的小公鸡对它说。那只小公鸡喔喔喔地叫了几声。","“我觉得很难。”小狗对小公鸡说道。","“不难，容易极了。你好好听着，看我的嘴，注意观察我，学我的样子。”","小公鸡又喔喔喔地叫起来。","小狗试着照小公鸡的样子做，但嘴里只发出一种滑稽的咯咯声，吓得旁边的小母鸡都逃走了。","“不要紧”，小公鸡说道，“第一次能这样就很不错了。你再试试，来！”小狗又试了一次，两次，三次，都没能成功。","从此，它天天都练习，从早到晚偷偷地练。有时候，为了更自由，它索性到树林里去练。","一天早晨，它在树林里练习，发出的喔喔喔的叫声是那么逼真，那么好听，那么洪亮。一只狐狸听到了，心里寻思着：公鸡终于来找我了，我得去感谢它的来访。狐狸真的去了，还没忘记带上刀叉和餐巾，因为对狐狸来说，没有比小公鸡更美味可口的午餐了。可以想象，当它看见啼叫的是一只狗而不是小公鸡时，该是多么失望啊！那只狗蹲坐着，一声又一声地喔喔叫着。","“哎呀！”狐狸说道，“原来是这样！你这是给我设了一个圈套啊！”","“一个圈套？”","“当然啦。你让我以为，是一只公鸡在树林里迷路了，而你却设下圈套想抓我。幸好我发现得及时。”","“我向你担保，我压根就没想抓你，我只是在这里练习。”","“练习？练习什么？”","“我在练习啼叫，现在差不多学会了。你听我叫得多好！”说完，它又洪亮地喔喔叫起来。","狐狸真想哈哈大笑。它在地上打着滚，捧着肚子，竭力忍着不笑出声来。小狗感到受了委屈，低着头，含着泪水默默走开了。","附近的一只杜鹃看着小狗走过去，很同情它。","“你怎么啦？”","“没什么。”","“那你为什么这样伤心？”","“唉……没什么好说的……因为我不会叫。”","“要是就因为这个，那我可以教你。你听我怎么叫，尽可能模仿我。咕咕……咕咕……咕咕……你听明白了吗？”","“我觉得很容易。”","容易极了，我从小就会这样叫。你试试！咕咕……咕咕……”","“咕……”小狗学着杜鹃叫，“咕……”","它那天试了，第二天、第三天又试了。一个星期过后，它已经学得相当不错了。小狗真高兴，心想：“我终于会叫了，现在别人再也不能取笑我了。”","就在那几天，人们开始打猎了，树林里来了很多猎人，里面还有百发百中的神枪手。哪怕是一只夜莺，他们也会给打下来。一个枪法很准的猎手经过那里，听见树丛中传来咕咕的叫声，就举枪瞄准，“砰！砰！”连开了两枪。","幸好没打中。子弹擦过小狗的耳边，就像连环画里画的那样。小狗拔腿就跑。它很诧异：那个猎人准是发疯了，竟然对狗开枪！","狗跑啊，跑啊……","第一种结局","狗跑啊，跑啊，它跑到了一片草地上，一头小母牛正在那里安详地吃草。","“你去哪儿啊？”","“我不知道。“","“那你就别走了。这里的青草特别鲜嫩。”","“唉，青草不能医治我的病······”","“你病啦？”","“可不是！我不会叫。”","“可是，这是世界上最容易的事！你听我叫：哞……哞……哞……还有比这更好听的叫声吗？”","第二种结局","狗跑啊，跑啊。它碰上了一个农民。","第三种结局","狗跑啊，跑啊，突然停住了，它听见一种奇怪的叫声：“汪汪，汪汪……”","这叫声像在对我说什么，狗想，尽管我搞不清这是什么动物在叫。”","“汪，汪······”"]},{"id":181,"grade":"三年级上册","title":"语文园地","paragraphs":["车轴　基础　阁楼","佳节　盲人　唐朝","轴 基 础 阁 佳 盲 唐","人心齐，泰山移。","二人同心，其利断金。","三个臭皮匠，顶个诸葛亮。","一个篱笆三个桩，一个好汉三个帮。","百发百中　四面八方　七上八下","百战百胜　四通八达　七嘴八舌","百依百顺　四平八稳　七手八脚","蚂蚁队长说：“照样要受处罚。”","“救命啊！救命啊！”红头拼命地叫起来。","“不要紧，”小公鸡说道，“第一次能这样就很不错了。”"]},{"id":182,"grade":"三年级上册","title":"15 搭船的鸟","paragraphs":["我和母亲坐着小船，到乡下外祖父家里去。我们坐在船舱里。天下着雨，雨点打在船蓬上，沙啦沙啦地响。船夫披着蓑衣在船后用力地摇着橹。","后来雨停了。我看见一只彩色的小鸟站在船头，多么美丽啊！它的羽毛是翠绿的，翅膀带着一些蓝色，比鹦鹉还漂亮。它还有一张红色的长嘴。","它什么时候飞来的呢？它静悄悄地停在船头不知有多久了。它站在那里做什么呢？难道它要和我们一起坐船到外祖父家里去吗？","我正想着，它一下子冲进水里，不见了。可是，没一会儿，它飞起来了，红色的长嘴衔着一条小鱼。它站在船头，一口把小鱼吞了下去。","母亲告诉我，这是一只翠鸟。哦，这只翠鸟搭了我们的船，在捕鱼吃呢。"]},{"id":183,"grade":"三年级上册","title":"16 金色的草地","paragraphs":["我们住在乡下，窗前是一大片草地。草地上长满了蒲公英。当蒲公英盛开的时候，这片草地就变成金色的了。","我和弟弟常常在草地上玩耍。有一次，弟弟跑在我前面，我装着一本正经的样子，喊：“谢廖沙！”他回过头来，我就使劲一吹，把蒲公英的绒毛吹到他的脸上。弟弟也假装打哈欠，把蒲公英的绒毛朝我脸上吹。就这样，这些并不引人注目的蒲公英，给我们带来了不少快乐。","有一天，我起得很早去钓鱼，发现草地并不是金色的，而是绿色的。中午回家的时候，我看见草地是金色的。傍晚的时候，草地又变绿了。这是为什么呢？我来到草地上，仔细观察，发现蒲公英的花瓣是合拢的。原来，蒲公英的花就像我们的手掌，可以张开、合上。花朵张开时，花瓣是金色的，草地也是金色的；花朵合拢时，金色的花瓣被包住了，草地就变成绿色的了。","多么可爱的草地！多么有趣的蒲公英！从那时起，蒲公英成了我们最喜爱的一种花。"]},{"id":184,"grade":"三年级上册","title":"习作例文","paragraphs":["我得好好写写我们家的小狗，它叫“王子”，是我们村里长得最花、毛色最漂亮的一只狗。它跑得特别快，我总也追不上它。不过“王子”很乖，它总是在前面等着我。","我教过“王子”认字，可是它连一个字母也没学会，不过它倒是挺爱上课的。我教它念“狗”的时候，它叫得最欢。它准是在想，这是在说它自己呀！“王子”还会数数，不过总共才会数到二。","它喜欢哼哼叫和汪汪叫。","“你要干什么？”“王子”在我面前哼哼时，我问它。","它汪地叫一声，晃一晃脑袋，表示想要出去。","“现在还想干什么？”当我们走出院子时，我接着问它。","“王子”又汪地叫一声，朝铁路那边跑去。","“你该一次说完哪！”我一边埋怨，一边跟在它后面跑。我知道“王子”想去那儿干什么，它喜欢同火车赛跑。每次都是它输，可它从不在乎。","每当有火车开过来，“王子”都以为能跑赢它。等到跑不动了，它便冲着远去的火车汪汪叫上几声，不知是允许火车开走呢，还是骂了火车一顿。","我的故乡在江南，我爱故乡的杨梅。","细雨如丝，一棵棵杨梅树贪婪地吮吸着春天的甘露。它们伸展着四季常绿的枝条，一片片狭长的叶子在雨雾中欢笑着。","端午节过后，杨梅树上挂满了杨梅。","杨梅圆圆的，和桂圆一样大小，遍身生着小刺。等杨梅渐渐长熟，刺也渐渐软了，平了。摘一个放进嘴里，舌尖触到杨梅那平滑的刺，是那样细腻而柔软。","杨梅先是淡红的，随后变成深红，最后几乎变成黑的了。它不是真的变黑，而是因为太红了，看上去像黑的。你轻轻咬开它，就可以看见那新鲜红嫩的果肉，嘴唇上舌头上同时染满了鲜红的汁水。","没有熟透的杨梅又酸又甜，熟透了就甜津津的，叫人越吃越爱吃。我小时候，有一次杨梅吃得太多，感觉牙齿又酸又软，连豆腐也咬不动了。我这才知道，杨梅虽然熟透了，酸味还是有的，因为它太甜，吃起来就不觉得酸了。吃多了杨梅再吃别的东西，才感觉到牙齿已经被它酸倒了。"]},{"id":185,"grade":"三年级上册","title":"望天门山","paragraphs":["作者：[唐代] 李白","天门中断楚江开，","碧水东流至此回。","两岸青山相对出，","孤帆一片日边来。","长江犹如巨斧，劈开天门雄峰，碧绿江水滚滚东流到这里，又回旋向北流去。","两岸青山互相对峙美景难分高下，一只小船从西边落日的地方悠悠驶来。","李白（701年－762年） ，字太白，号青莲居士，又号“谪仙人”，唐代伟大的浪漫主义诗人，被后人誉为“诗仙”，与杜甫并称为“李杜”，为了与另两位诗人李商隐与杜牧即“小李杜”区别，杜甫与李白又合称“大李杜”。据《新唐书》记载，李白为兴圣皇帝（凉武昭王李暠）九世孙，与李唐诸王同宗。其人爽朗大方，爱饮酒作诗，喜交友。李白深受黄老列庄思想影响，有《李太白集》传世，诗作中多为醉时写就，代表作有《望庐山瀑布》《行路难》《蜀道难》《将进酒》《早发白帝城》等。"]},{"id":186,"grade":"三年级上册","title":"饮湖上初晴后雨","paragraphs":["作者：[宋代] 苏轼","水光潋滟晴方好，","山色空蒙雨亦奇。","欲把西湖比西子，","淡妆浓抹总相宜。","在晴日阳光照耀下，西湖水波荡漾，光彩熠熠，美极了；雨天的西湖，山中云雾朦胧，缥缥渺渺，又显出另一番奇妙景致。","如果把美丽的西湖比作美人西施，那么淡妆浓抹都显得十分自然。","苏轼，（1037年1月8日-1101年8月24日）字子瞻、和仲，号铁冠道人、东坡居士，世称苏东坡、苏仙，汉族，眉州眉山（四川省眉山市）人，祖籍河北栾城，北宋著名文学家、书法家、画家，历史治水名人。苏轼是北宋中期文坛领袖，在诗、词、散文、书、画等方面取得很高成就。文纵横恣肆；诗题材广阔，清新豪健，善用夸张比喻，独具风格，与黄庭坚并称“苏黄”；词开豪放一派，与辛弃疾同是豪放派代表，并称“苏辛”；散文著述宏富，豪放自如，与欧阳修并称“欧苏”，为“唐宋八大家”之一。苏轼善书，“宋四家”之一；擅长文人画，尤擅墨竹、怪石、枯木等。与韩愈、柳宗元和欧阳修合称“千古文章四大家”。作品有《东坡七集》《东坡易传》《东坡乐府》《潇湘竹石图卷》《古木怪石图卷》等。"]},{"id":187,"grade":"三年级上册","title":"望洞庭","paragraphs":["作者：[唐代] 刘禹锡","湖光秋月两相和，","潭面无风镜未磨。","遥望洞庭山水翠，","白银盘里一青螺。","洞庭湖上月光和水色交相融和，湖面风平浪静，犹如未磨的铜镜。","皓月银辉之下，青翠的君山与清澈的洞庭水浑然一体，望去如同一只雕镂透剔的银盘里，放了一颗小巧玲珑的青螺。","刘禹锡（772年~842年），字梦得，籍贯河南洛阳，生于河南郑州荥阳，自述“家本荥上，籍占洛阳” ，自称是汉中山靖王后裔。唐朝时期大臣、文学家、哲学家，有“诗豪”之称。他的家庭是一个世代以儒学相传的书香门第。政治上主张革新，是王叔文派政治革新活动的中心人物之一。后来永贞革新失败被贬为朗州司马（今湖南常德）。据湖南常德历史学家、收藏家周新国先生考证刘禹锡被贬为朗州司马其间写了著名的“汉寿城春望”。"]},{"id":188,"grade":"三年级上册","title":"18 富饶的西沙群岛","paragraphs":["西沙群岛位于南海的西北部，是我国海南省三沙市的一部分。那里风景优美，物产丰富，是个可爱的地方。","西沙群岛一带海水五光十色，瑰丽无比：有深蓝的，淡青的，浅绿的，杏黄的。一块块，一条条，相互交错着。因为海底高低不平，有山崖，有峡谷，海水有深有浅，从海面看，色彩就不同了。","海底的岩石上生长着各种各样的珊瑚，有的像绽开的花朵，有的像分枝的鹿角。海参到处都是，在海底懒洋洋地蠕动。大龙虾全身披甲，划过来，划过去，样子挺威武。","鱼成群结队地在珊瑚丛中穿来穿去，好看极了。有的全身布满彩色的条纹；有的头上长着一簇红缨；有的周身像插着好些扇子，游动的时候飘飘摇摇；有的眼睛圆溜溜的，身上长满了刺，鼓起气来像皮球一样圆。各种各样的鱼多得数不清。正像人们说的那样，西沙群岛的海里一半是水，一半是鱼。","西沙群岛也是鸟的天下。岛上有一片片茂密的树林，树林里栖息着各种海鸟。遍地都是鸟蛋。树下堆积着一层厚厚的鸟粪，这是非常宝贵的肥料。","富饶的西沙群岛，是我们祖祖辈辈生活的地方。随着祖国建设事业的发展，可爱的西沙群岛，必将变得更加美丽，更加富饶。"]},{"id":189,"grade":"三年级上册","title":"19 海滨小城","paragraphs":["我的家乡在广东，是一座海滨小城。人们走到街道尽头，就可以看见浩瀚的大海。天是蓝的，海也是蓝的。海天交界的水平线上，有棕色的机帆船和 银白色的军舰来来往往。天空飞翔着白色的、灰色的海鸥，还飘着跟海鸥一样颜色的云朵。","早晨，机帆船、军舰、海鸥、云朵，都被朝阳镀上了一层金黄色。帆船上的渔民，军舰上的战士，他们的脸和胳臂也镀上了一层金黄色。","海边是一片沙滩，沙滩上遍地是各种颜色、各种花纹的贝壳。这里的孩子见得多了，都不去理睬这些贝壳，贝壳只好寂寞地躺在那里。远处响起了汽笛声，那是出海捕鱼的船队回来了。船上满载着银光闪闪的鱼，还有青色的虾和蟹，金黄色的海螺。船队一靠岸，海滩上就喧闹起来。","小城里每一个庭院都栽了很多树。有桉树、椰子树、橄榄树、凤凰树，还有别的许多亚热带树木。初夏，桉树叶子散发出来的香味，飘得满街满院都是。凤凰树开了花，开得那么热闹，小城好像笼罩在一片片红云中。","小城的公园更美。这里栽着许许多多榕树。一棵棵榕树就像一顶顶撑开的绿绒大伞，树叶密不透风，可以遮太阳，挡风雨。树下摆着石凳，每逢休息的日子，石凳上总是坐满了人。","小城的街道也美。除了沥青的大路，都是用细沙铺成的，踩上去咯吱咯吱地响，好像踩在沙滩上一样。人们把街道打扫得十分干净，甚至连一片落叶都没有。","这座海滨小城真是又美丽又整洁。"]},{"id":190,"grade":"三年级上册","title":"20 美丽的小兴安岭","paragraphs":["我国东北的小兴安岭，有数不清的红松、白桦、栎树……几百里连成一片，就像绿色的海洋。","春天，树木抽出新的枝条，长出嫩绿的叶子。山上的积雪融化了，雪水汇成小溪，淙淙地流着。溪里涨满了春水。小鹿在溪边散步，它们有的俯下身子喝水，有的侧着脑袋欣赏自己映在水里的影子。","夏天，树木长得葱葱茏茏，密密层层的枝叶把森林封得严严实实的，挡住了人们的视线，遮住了蓝蓝的天空。早晨，雾从山谷里升起来，整个森林浸在乳白色的浓雾里。太阳出来了，千万缕耀眼的金光穿过树梢，照射在工人宿舍门前的草地上。草地上盛开着各种各样的野花，红的、白的、黄的、紫的，真像个美丽的大花坛。","秋天，白桦和栎树的叶子变黄了，松柏显得更苍翠了。秋风吹来，落叶在林间飞舞。这时候，森林向人们献出了酸甜可口的山葡萄，又香又脆的榛子，鲜嫩的蘑菇和木耳，还有人参等名贵药材。","冬天，雪花在空中飞舞。树上积满了白雪。地上的雪厚厚的，又松又软，常常没过膝盖。西北风呼呼地刮过树梢。黑熊躲进自己的洞里冬眠。紫貂捕捉野兔当美餐。松鼠靠秋天收藏在树洞里的松子过日子，有时候还到枝头散散步，看看春天是不是快要来临。","小兴安岭一年四季景色诱人，是一座美丽的大花园，也是一座巨大的宝库。"]},{"id":191,"grade":"三年级上册","title":"语文园地","paragraphs":["作者：[唐代] 李白","朝辞白帝彩云间，","千里江陵一日还。","两岸猿声啼不住，","轻舟已过万重山。","清晨，我告别高入云霄的白帝城，江陵远在千里，船行只一日时间。","两岸猿声还在耳边不停地回荡，轻快的小舟已驶过万重青山。","李白（701年－762年） ，字太白，号青莲居士，又号“谪仙人”，唐代伟大的浪漫主义诗人，被后人誉为“诗仙”，与杜甫并称为“李杜”，为了与另两位诗人李商隐与杜牧即“小李杜”区别，杜甫与李白又合称“大李杜”。据《新唐书》记载，李白为兴圣皇帝（凉武昭王李暠）九世孙，与李唐诸王同宗。其人爽朗大方，爱饮酒作诗，喜交友。李白深受黄老列庄思想影响，有《李太白集》传世，诗作中多为醉时写就，代表作有《望庐山瀑布》《行路难》《蜀道难》《将进酒》《早发白帝城》等。","蝌蚪　飞蛾　螃蟹","鲤鱼　鲫鱼　鲨鱼","蝌 蚪 蛾 鲤 鲫 鲨","车站的人可真多······","我喜欢夏天的夜晚······"]},{"id":192,"grade":"三年级上册","title":"21 大自然的声音","paragraphs":["大自然有许多美妙的声音。","风，是大自然的音乐家。他会在森林里演奏他的手风琴。当他翻动树叶，树叶便像歌手一样，唱出各种不同的歌曲。不一样的树叶，有不一样的声音；不一样的季节，有不一样的音乐。当微风拂过，那声音轻轻柔柔的，好像呢喃细语，让人感受到大自然的温柔；当狂风吹起，整座森林都激动起来，合奏出一首雄伟的乐曲，那声音充满力量，令人感受到大自然的威力。","水，也是大自然的音乐家。下雨的时候，他喜欢玩打击乐器。小雨滴敲敲打打，一场热闹的音乐会便开始了。滴滴答答……叮叮咚咚……所有的树林，树林里的每片树叶；所有的房子，房子的屋顶和窗户，都发出不同的声音。当小雨滴汇聚起来，他们便一起唱着歌：小溪淙淙，流向河流，河流潺潺，流向大海；大海哗哗，汹涌澎湃。从一首轻快的山中小曲，唱到波澜壮阔的海洋大合唱。","动物是大自然的歌手。走在公园里，听听树上叽叽喳喳的鸟叫；坐在一棵树下，听听唧哩哩唧哩哩的虫鸣；在水塘边散步，听听青蛙的歌唱。你知道他们唱的是什么吗？他们的歌声好像告诉我们：“我在歌唱，我很快乐！”"]},{"id":193,"grade":"三年级上册","title":"22 读不完的大书","paragraphs":["我五六岁时，就喜欢到大自然中去寻找好玩的东西。高远的天空，广阔的大地，空中的浮云飞鸟，水里的虾蟹游鱼，地上的走兽昆虫、花草树木……世界万物，不仅好玩，还让人沉思和遐想。","小麻雀叽叽喳喳、蹦蹦跳跳的，叫人愉悦。老鹰在高空盘旋，展翅滑翔，突然猛扑而下，给人以雄健勇猛的感觉。蚂蚁搬家，井然有序，当两军对垒时，那勇敢忠贞的精神，真叫人敬佩。","植物的开花、结籽，暑寒荣枯，有着不同的趣味。花儿有红的、黄的、紫的、蓝的，形状有单瓣的、重瓣的，千姿百态。草的叶子各不相同，有长有短，有宽有窄，有的还带着刺。","我家房子前后栽有各种果树，有梨树、桃树、橘子树、柚子树，在不同的时间里，它们开不同的花，结不同的果。刚从树上摘下的果子，味道格外鲜美。","我最喜爱的，是我家屋后的两丛竹子和一株棕榈。竹子长得快，雨后春笋，一天长几寸，没几天就长得和我一样高了。微风吹来，沙沙的竹叶声，如同温柔的细语。池塘边的棕榈树高大挺拔，大蒲扇似的叶子在风中摇摆，一副超凡脱俗的样子。在秋高气爽的日子里，它倒映在池塘的水中，小鱼在倒影间游玩，又是另一种境界。","大自然是一本看不完的大画册，是一部永远读不完的大书，里面有无穷的奥秘，有无尽的乐趣。"]},{"id":194,"grade":"三年级上册","title":"23 父亲、树林和鸟","paragraphs":["父亲一生最喜欢树林和歌唱的鸟。","童年时，一个春天的黎明，父亲带着我从滹沱河岸的一片树林边走过。","父亲突然站定，朝幽深的雾蒙蒙的树林，上上下下的望了又望，用鼻子闻了又闻。","“林子里有不少鸟。”父亲喃喃着。","并没有看见一只鸟飞，并没有听到一声鸟叫。","我茫茫然地望着凝神静气的像树一般兀立的父亲。","父亲指着一棵树的一根树枝对我说：“看那里，没有风，叶子为什么在动？”","我仔细找，没有找到动着的那几片叶子。","“还有鸟味。”父亲轻声说，他生怕惊动鸟。","我只闻到浓浓的苦苦的草木气息，没有闻到什么鸟的气味。","“鸟也有气味？”","“有。树林里过夜的鸟总是一群，羽毛焐得热腾腾的。","黎明时，所有的鸟都抖动着羽毛，要抖净露水和湿气。","每一个张开的喙都舒畅地呼吸着，深深地呼吸着。","“鸟要准备歌唱了。”","父亲和我坐在树林边，鸟真的唱了起来。","“这是树林和鸟最快活的时刻。”父亲说。","我知道父亲此时也最快活。","过了几天，父亲对我说：“鸟最快活的时刻，飞离树枝的那一瞬间，容易被猎人打中。”","“为什么？”我惊愕地问。","父亲说：“黎明时的鸟，翅膀潮湿，飞起来沉重。”","我真高兴，父亲不是猎人。"]},{"id":195,"grade":"三年级上册","title":"语文园地","paragraphs":["作者：[唐代] 王昌龄","荷叶罗裙一色裁，","芙蓉向脸两边开。","乱入池中看不见，","闻歌始觉有人来。","采莲少女的绿罗裙融入到田田荷叶中，仿佛一色，少女的脸庞掩映在盛开的荷花间，相互映照。","混入莲池中不见了踪影，听到歌声四起才觉察到有人前来。","王昌龄 (698— 756），字少伯，河东晋阳（今山西太原）人。盛唐著名边塞诗人，后人誉为“七绝圣手”。早年贫贱，困于农耕，而立之年，始中进士。初任秘书省校书郎，又中博学宏辞，授汜水尉，因事贬岭南。与李白、高适、王维、王之涣、岑参等交厚。开元末返长安，改授江宁丞。被谤谪龙标尉。安史乱起，为刺史闾丘晓所杀。其诗以七绝见长，尤以登第之前赴西北边塞所作边塞诗最著，有“诗家夫子王江宁”之誉（亦有“诗家天子王江宁”的说法）。","它的声音小得几乎听不见了。","王老师急得直跺脚。","他跑得像兔子一样快。","妈妈累得……","小溪淙淙，流向河流；河流潺潺，流向大海；大海哗哗，汹涌澎湃。","遥远的夜空有一个弯弯的月亮，弯弯的月亮下面是那弯弯的小桥...."]},{"id":196,"grade":"三年级上册","title":"24 司马光","paragraphs":["群儿戏于庭，一儿登瓮，足跌没水中。众皆弃去，光持石击瓮破之，水迸，儿得活。","司马光和一群小孩子在庭院里面玩，一个小孩站在大缸上面，失足跌落缸中被水淹没，其他的小孩子都跑掉了，只有司马光拿石头砸开了缸，水从而流出，小孩子得以活命。"]},{"id":197,"grade":"三年级上册","title":"25 灰雀","paragraphs":["有一年冬天，列宁在郊外养病。他每天到公园散步。公园里有一棵高大的白桦树，树上有三只灰雀：两只胸脯是粉红的，一只胸脯是深红的。它们在树枝间来回跳动，婉转地歌唱，非常惹人喜爱。列宁每次走到白桦树下，都要停下来，仰望这三只欢快的灰雀，还经常给它们带来面包渣和谷粒。","一天，列宁又来到公园，走到白桦树下，发现那只胸脯深红的灰雀不见了。他在周围的树林中找遍了，也没有找到。","这时，列宁看见一个小男孩，就问：“孩子，你看见过一只深红色胸脯的灰雀吗？”","男孩说：“没……我没看见。”","列宁说：“一定是飞走了或者是冻死了。天气严寒，它怕冷。”","那个男孩本来想告诉列宁灰雀没有死，但又不敢讲。","列宁自言自语地说：“多好的灰雀呀，可惜再也飞不回来了。”","男孩看看列宁，说：“会飞回来的，一定会飞回来的。它还活着。”","列宁问：“会飞回来？”","“一定会飞回来！”男孩肯定地说。","第二天，列宁来到白桦树下，果然又看到那只灰雀欢蹦乱跳地在枝头歌唱。那个男孩站在白桦树旁，低着头。","列宁看看男孩，又看看灰雀，微笑着说：“你好！灰雀，昨天你到哪儿去了？”","当然，灰雀没有告诉列宁昨天它去哪儿了。列宁也没再问那个男孩，因为他已经知道，男孩是诚实的。"]},{"id":198,"grade":"三年级上册","title":"26 手术台就是阵地","paragraphs":["1939年春，齐会战斗打响了。气焰嚣张的日军刚刚到齐会一带就挨了当头一棒，被我军消灭了五百多人。","敌人不断反扑，战斗非常激烈。我军的伤员陆续从火线上抬下来。在离火线不远的一座小庙里，白求恩大夫正在给伤员做手术。他已经两天两夜没休息了，眼球上布满了血丝。突然，几发炮弹落在小庙前的空地上。硝烟滚滚，弹片纷飞，小庙被烟雾淹没了。白求恩仍然镇定地站在手术台旁。他接过助手递过来的镊子敏捷地从伤员的腹腔里取出一块弹片，丢在盘子里。","敌机不断地在上空吼叫。炮弹不断地在周围爆炸。师卫生部长匆匆赶来，对白求恩说：“师长决定让您和一部分伤员离开这里。”白求恩沉思了一会儿说：“我同意撤走部分伤员。至于我个人，要和战士们在一起，不能离开。”部长恳求说：“白求恩同志，这儿危险，让您离开这里，是战斗形势的需要哇！”白求恩说：“谢谢师长的关心。可是，手术台是医生的阵地。战士们没有离开他们的阵地，我怎么能离开自己的阵地呢？部长同志，请您转告师长，我是一名八路军战士，不是你们的客人。”白求恩低下头，继续给伤员做手术。","一连几发炮弹落在小庙的周围。庙的一角落下了许多瓦片。挂在门口的布帘烧着了，火苗向手术台扑过来。助手们赶忙把火扑灭。担架队抬起做过手术的伤员，迅速向后方转移。白求恩仍然争分夺秒地给伤员做手术，做了一个又一个。","齐会战斗进行了三天三夜，胜利结束了。白求恩大夫在手术台旁，连续工作了六十九个小时。"]},{"id":199,"grade":"三年级上册","title":"27* 一个粗瓷大碗","paragraphs":["中国人民革命军事博物馆里，陈列着一个粗瓷大碗，是赵一曼在东北抗日联军中担任团政治委员时用过的。这个碗，赵一曼仅仅用过一次，但是抗联的老战士都能认出来。因为这个碗有着一段令人感动的故事。","有一回，一场袭击日寇的战斗刚刚结束，小通讯员给赵一曼送来一个鼓鼓的挂包。打开一看，是个粗瓷大碗。赵一曼吃饭用的搪瓷缸子早就送给一个新战士了，通讯员一直想给她另找一个碗，好不容易在这次战斗中找到了，就连忙给她送来。","赵一曼看着这个碗，对通讯员说：“哪里拿来的，请你还到哪里去！”","“这……这……敌人都被消灭了，往哪里还啊！”通讯员为难地说。","开饭了。通讯员用这个大碗给赵一曼盛了满满一碗高粱米饭，他想：“这回我们政委该吃顿饱饭了。”","赵一曼一看，就知道是从病号灶盛来的。那些日子非常艰苦，抗联部队几个月来都是靠野菜、草根、橡子面充饥。有时候乡亲们冒着危险给部队送来一点儿粮食，但得留给伤病员吃。团长、政委和战士们一样，嘴边有几个月没沾过粮食了。赵一曼看到这碗高粱米饭，不禁想起战士们的艰苦生活，想起同志之间的友爱，想起通讯员对她的关心……","赵一曼端着碗轻轻走进炊事棚，趁人不注意的时候，把碗里的饭倒进锅里，又从另ー口锅里盛了半碗野菜粥。炊事员老李在旁边看得清楚，他没吭声，眼里却含着泪花。","第二天开饭的时候，赵一曼又没有碗了。小通讯员急得直叫：“我说政委同志啊，给你一百个碗也架不住你这么‘丢‘啊！","赵一曼笑着说：“是啊，什么时候才能不‘丢’碗呢？”","据后来“侦察”，这个粗瓷大碗已经成了七班的菜盆了。"]},{"id":200,"grade":"三年级上册","title":"语文园地","paragraphs":["睁 眨 瞪 瞅 瞧 目","眨眼　眼眶　怒目圆睁","目瞪口呆　耳闻目睹","眨 瞪 瞅 眶 睹","不迁怒，不贰过。——《论语》","爱人若爱其身。——《墨子》","仁者爱人，有礼者敬人。——《孟子》","与人善言，暖于布帛；伤人以言，深于矛戟。——《荀子》","我军的伤员陆续从火线上抬下来。","白求恩低下头，继续给伤员做手术。","白求恩大夫在手术台旁，连续工作了六十九个小时。"]},{"id":201,"grade":"三年级下册","title":"绝句","paragraphs":["作者：[唐代] 杜甫","迟日江山丽，","春风花草香。","泥融飞燕子，","沙暖睡鸳鸯。","沐浴在春光下的江河山川是如此秀丽，春风拂过送来阵阵花香。","泥土已经变得松软，燕子衔泥筑巢，暖和的沙子上睡着成双成对的鸳鸯。","杜甫（712－770），字子美，自号少陵野老，世称“杜工部”、“杜少陵”等，汉族，河南府巩县（今河南省巩义市）人，唐代伟大的现实主义诗人，杜甫被世人尊为“诗圣”，其诗被称为“诗史”。杜甫与李白合称“李杜”，为了跟另外两位诗人李商隐与杜牧即“小李杜”区别开来，杜甫与李白又合称“大李杜”。他忧国忧民，人格高尚，他的约1400余首诗被保留了下来，诗艺精湛，在中国古典诗歌中备受推崇，影响深远。759-766年间曾居成都，后世有杜甫草堂纪念。"]},{"id":202,"grade":"三年级下册","title":"惠崇春江晚景","paragraphs":["作者：[宋代] 苏轼","竹外桃花三两枝，","春江水暖鸭先知。","蒌蒿满地芦芽短，","正是河豚欲上时。","竹林外两三枝桃花初放，水中嬉戏的鸭子最先察觉到初春江水的回暖。","河滩上长满了蒌蒿，芦苇也长出短短的新芽，而河豚此时正要逆流而上，从大海回游到江河里来了。","苏轼，（1037年1月8日-1101年8月24日）字子瞻、和仲，号铁冠道人、东坡居士，世称苏东坡、苏仙，汉族，眉州眉山（四川省眉山市）人，祖籍河北栾城，北宋著名文学家、书法家、画家，历史治水名人。苏轼是北宋中期文坛领袖，在诗、词、散文、书、画等方面取得很高成就。文纵横恣肆；诗题材广阔，清新豪健，善用夸张比喻，独具风格，与黄庭坚并称“苏黄”；词开豪放一派，与辛弃疾同是豪放派代表，并称“苏辛”；散文著述宏富，豪放自如，与欧阳修并称“欧苏”，为“唐宋八大家”之一。苏轼善书，“宋四家”之一；擅长文人画，尤擅墨竹、怪石、枯木等。与韩愈、柳宗元和欧阳修合称“千古文章四大家”。作品有《东坡七集》《东坡易传》《东坡乐府》《潇湘竹石图卷》《古木怪石图卷》等。"]},{"id":203,"grade":"三年级下册","title":"三衢道中","paragraphs":["作者：[宋代] 曾几","梅子黄时日日晴，","小溪泛尽却山行。","绿阴不减来时路，","添得黄鹂四五声。","梅子成熟的时候，天天都是晴朗的好天气，乘小船走到小溪的尽头，再走山间小路。","山路上古树苍翠，与水路上的风景相比也毫不逊色，深林丛中传来几声黄鹂的欢鸣声，更增添了些幽趣。","曾几（1085--1166）中国南宋诗人。字吉甫，自号茶山居士。其先赣州（今江西赣县）人，徙居河南府（今河南洛阳）。历任江西、浙西提刑、秘书少监、礼部侍郎。曾几学识渊博，勤于政事。他的学生陆游替他作《墓志铭》，称他“治经学道之余，发于文章，雅正纯粹，而诗尤工。”后人将其列入江西诗派。其诗多属抒情遣兴、唱酬题赠之作，闲雅清淡。五、七言律诗讲究对仗自然，气韵疏畅。古体如《赠空上人》，近体诗如《南山除夜》等，均见功力。所著《易释象》及文集已佚。《四库全书》有《茶山集》8卷，辑自《永乐大典》。"]},{"id":204,"grade":"三年级下册","title":"2 燕子","paragraphs":["一身乌黑的羽毛，一对轻快有力的翅膀，加上剪刀似的尾巴，凑成了那样可爱的活泼的小燕子。","二三月的春日里，轻风微微地吹拂着，如毛的细雨由天上洒落着，千条万条的柔柳，红的白的黄的花，青的草，绿的叶，都像赶集似的聚拢来，形成了烂漫无比的春天。这时候，那些小燕子，那么伶俐可爱的小燕子，也由南方飞来，加入这光彩夺目的图画中，为春光平添了许多生趣。","小燕子带了它的剪刀似的尾巴，在阳光满地时，斜飞于旷亮无比的天空，叽的一声，已由这里的稻田上，飞到那边的高柳下了。","另有几只却在波光粼粼的湖面上横掠着，小燕子的翼尖或剪尾，偶尔沾了一下水面，那小圆晕便一圈一圈地荡漾开去。","那边还有飞倦了的几对，闲散地在纤细的电线上休憩——嫩蓝的春天，几支木杆，几痕细线连于杆与杆之间，线上停着几个小黑点，那便是燕子。多么有趣的一幅图画呀！"]},{"id":205,"grade":"三年级下册","title":"3 荷花","paragraphs":["清早，我到公园去玩，一进门就闻到一阵清香。我赶紧往荷花池边跑去。","荷花已经开了不少了。荷叶挨挨挤挤的，像一个个碧绿的大圆盘。白荷花在这些大圆盘之间冒出来。有的才展开两三片花瓣儿。有的花瓣儿全展开了，露出嫩黄色的小莲蓬。有的还是花骨朵儿，看起来饱胀得马上要破裂似的。","这么多的白荷花，一朵有一朵的姿势。看看这一朵，很美；看看那一朵，也很美。如果把眼前的一池荷花看作一大幅活的画，那画家的本领可真了不起。","我忽然觉得自己仿佛就是一朵荷花，穿着雪白的衣裳，站在阳光里。一阵微风吹过来，我就翩翩起舞，雪白的衣裳随风飘动。不光是我一朵，一池的荷花都在舞蹈。风过了，我停止了舞蹈，静静地站在那儿。蜻蜓飞过来，告诉我清早飞行的快乐。小鱼在脚下游过，告诉我昨夜做的好梦……","过了好一会儿，我才记起我不是荷花，我是在看荷花呢。"]},{"id":206,"grade":"三年级下册","title":"4* 昆虫备忘录","paragraphs":["复眼","我从一本书上知道蜻蜓有复眼，从那以后，就一直在琢磨复眼是怎么回事。“复眼”，想必是好多小眼睛合成一个大眼睛。那它怎么看东西呢？是每个小眼睛都看到一个小形象，合成一个大形象？还是每个小眼睛看到形象的一部分，合成一个完整的形象？总是琢磨不出来。","凡是有复眼的昆虫，视觉都很灵敏。蜻蜓就有复眼，苍蝇也有。你走近蜻蜓和苍蝇，还有一段距离，它们就发现了，噌——飞了。","我曾经想过：如果人长了一对复眼……","还是不要！那成什么样子！","花大姐","瓢虫款款地落下来了，折好它的黑绸衬裙——膜翅，顺顺溜溜；收拢硬翅，严丝合缝。","北京人把瓢虫叫作“花大姐”，好名字！","瓢虫，朱红的、瓷漆似的硬翅，上有小圆点，特别漂亮。圆点是有定数的，不能瞎点。小圆点，叫作“星”，有七星瓢虫、十四星瓢虫……星点不同。有的瓢虫吃蚜虫，是益虫；有的瓢虫吃马铃薯嫩叶，是害虫。我说，吃马铃薯嫩叶的瓢虫，你们就不能改改口味，也吃蚜虫吗?","独角仙","吃晚饭的时候，呜——扑！飞来一只独角仙，摔在灯下。它摔得很重，摔晕了。轻轻一捏，就捏住了。","独角仙，在甲虫里可能算是最大的，从头到脚，约有两寸。它的甲壳多为深色，挺硬的，头部尖端有一只犀牛一样的角。这家伙，是昆虫里的霸王。","独角仙的力气很大。北京隆福寺过去有独角仙卖，据说给它套上一辆泥制的小车，它拉着就走。","蚂蚱","河北人把尖头绿蚂蚱叫作“挂大扁儿”。我挺喜欢“挂大扁儿”这个名字。","尖头蚂蚱是国画家很喜欢画的。画草虫的很少有没画过蚂蚱的。齐白石、王雪涛都画过，我小时候也画过不少，因为它的形态好掌握，很好画。","蚂蚱飞起来会咯咯作响，不知道它是怎么弄出这种声音的。蚂蚱的膜翅是淡淡的桃红色的，非常好看。","还有一种“土蚂蚱”，身体粗短，方头，色黑如泥土，翅上有黑斑。这种蚂蚱，抓住它，它就吐出一泡褐色的口水，顶讨厌。"]},{"id":207,"grade":"三年级下册","title":"语文园地","paragraphs":["援（救援） 掷（投掷） 捞（打捞）","缚（束缚） 缭（缭乱） 络（网络）","资（资产） 贡（贡献） 贷（贷款）","援 掷 捞 缚 缭 络 资 贡 贷","作者：[唐代] 白居易","江南好，风景旧曾谙。","日出江花红胜火，春来江水绿如蓝。能不忆江南？","江南好，我对江南的美丽风景曾经是多么的熟悉。春天的时候，晨光映照的岸边红花，比熊熊的火焰还要红，碧绿的江水绿得胜过蓝草。怎能叫人不怀念江南？","白居易（772年－846年），字乐天，号香山居士，又号醉吟先生，祖籍太原，到其曾祖父时迁居下邽，生于河南新郑。是唐代伟大的现实主义诗人，唐代三大诗人之一。白居易与元稹共同倡导新乐府运动，世称“元白”，与刘禹锡并称“刘白”。白居易的诗歌题材广泛，形式多样，语言平易通俗，有“诗魔”和“诗王”之称。官至翰林学士、左赞善大夫。公元846年，白居易在洛阳逝世，葬于香山。有《白氏长庆集》传世，代表诗作有《长恨歌》《卖炭翁》《琵琶行》等。","水面的小圆晕一圈圏地（荡漾 飘荡）开去。","他们走在回家的路上，唱起了一首（轻巧 轻快）的歌曲。","这只小狗的鼻子真（灵巧 灵敏），老远就闻到了食物的气味。","一身乌黑的羽毛，一对轻快有力的翅膀，加上剪刀似的尾巴，凑成了那样可爱的活泼的小燕子。","独角仙的甲壳多为深色，挺硬的，头部尖端有一只犀牛一样的角。"]},{"id":208,"grade":"三年级下册","title":"5 守株待兔","paragraphs":["宋人有耕者，田中有株。兔走触株，折颈而死。因释其耒而守株，冀复得兔。兔不可复得，而身为宋国笑。","宋国有个种地的农民，他的田地中有一截树桩。一天，一只跑得飞快的野兔撞在了树桩上，折断了脖子死了。于是，他便放下他的农具日日夜夜守在树桩子旁边，希望能再得到一只兔子。然而野兔是不可能再次得到了，而他自己也被宋国人耻笑。"]},{"id":209,"grade":"三年级下册","title":"6 陶罐和铁罐","paragraphs":["国王的橱柜里有两个罐子，一个是陶的，一个是铁的。骄傲的铁罐看不起陶罐，常常奚落它。","“你敢碰我吗，陶罐子！”铁罐傲慢地问。","“不敢，铁罐兄弟。”陶罐谦虚地回答。","“我就知道你不敢，懦弱的东西！”铁罐说，带着更加轻蔑的神气。","“我确实不敢碰你，但并不是懦弱。”陶罐争辩说，“我们生来就是盛东西的，并不是来互相碰撞的。说到盛东西，我不见得就比你差。再说……”","“住嘴！”铁罐恼怒了，“你怎么敢和我相提并论！你等着吧，要不了几天，你就会破成碎片，我却永远在这里，什么也不怕。”","“何必这样说呢？”陶罐说，“我们还是和睦相处吧，有什么可吵的呢！”","“和你在一起，我感到羞耻，你算什么东西！”铁罐说，“走着瞧吧，总有一天，我要把你碰成碎片！”","陶罐不再理会铁罐。","时间在流逝，世界上发生了许多事情。王朝覆灭了，宫殿倒塌了。两个罐子遗落在荒凉的废墟上，上面覆盖了厚厚的尘土。","许多年过去了。有一天，人们来到这里，掘开厚厚的堆积物，发现了那个陶罐。","“哟，这里有一个罐子！”一个人惊讶地说。","“真的，一个陶罐！”其他的人都高兴地叫起来。","捧起陶罐，倒掉里面的泥土，清理干净，它还是那样光洁，朴素，美观。","“多美的陶罐！”一个人说，“小心点儿，千万别把它碰坏了，这是古代的东西，很有价值的。”","“谢谢你们！”陶罐兴奋地说，“我的兄弟铁罐就在我旁边，请你们把它也掘出来吧，它一定闷得不行了。”","人们立即动手，翻来覆去，把土都掘遍了，但是，连铁罐的影子也没见到。"]},{"id":210,"grade":"三年级下册","title":"7 鹿角和鹿腿","paragraphs":["丛林中，住着一只漂亮的鹿。","有一天，鹿口渴了，找到一个池塘，痛痛快快地喝起水来。池水清清的，像一面镜子。鹿忽然发现了自己倒映在水中的影子：“咦，这是我吗？”","鹿摆摆身子，水中的倒影也跟着摆动起来。他从来没有注意到自己是这么漂亮！他不着急离开了，对着池水欣赏自己的美丽：“啊！我的身段多么匀称，我的角多么精美别致，好像两束美丽的珊瑚！”","一阵清风吹过，池水泛起了层层波纹。鹿忽然看到了自己的腿，不禁噘起了嘴，皱起了眉头：“唉，这四条腿太细了，怎么配得上这两只美丽的角呢！”","鹿开始抱怨起自己的腿来。就在他没精打采地准备离开的时候，忽然听到远处传来一阵脚步声。他机灵地支起耳朵，不错，正是脚步声！鹿猛一回头，哎呀，一头狮子正悄悄地向自己逼近。","鹿不敢犹豫，撒开长腿就跑。有力的长腿在灌木丛中蹦来跳去，不一会儿，就把凶猛的狮子远远地甩在了后面。就在狮子灰心丧气不想再追的时候，鹿的角却被树枝挂住了。狮子赶紧抓住这个机会，猛扑过来。眼看就要追上了，鹿用尽全身力气，使劲一扯，才把两只角从树枝中挣脱出来，然后又拼命向前奔去。这次，狮子再也没有追上。","鹿跑到一条小溪边，停下脚步，一边喘气，一边休息。他叹了口气，说：“两只美丽的角差点儿让我送了命，可四条难看的腿却让我狮口逃生！”"]},{"id":211,"grade":"三年级下册","title":"8* 池子与河流","paragraphs":["“这是怎么回事？”池子对她的邻居河流说道，“我什么时候看见你，你总是滚滚滔滔！亲爱的姐姐，你难道不会疲劳？我总是看见，你一会儿背着沉重的货船，一会儿驮着长串的木筏，还有小划子啊小船，简直数也数不完。你几时才能抛开这样的生涯？要是换了我，说句老实话，我可真要愁死啦！我的命运有多好，比起来，你我相差竟这么大！固然，我并不出名，我没有出现在地图上，像你那样蜿蜒地贯穿全国，也没有行吟诗人为我弹琴歌唱。——这一切其实都是空的。可是，我安闲地躺在柔软的泥土里，像贵妇人躺在鸭绒垫上一样。我不用为大船和木筏操心，小划子有多重也用不着想，至多，有一两片树叶被微风吹落，在我的胸膛上轻轻摇荡。这清闲的生活无忧无虑，还有什么能够代替？任凭人世间忙忙碌碌，我只在睡梦中推究哲理。”","“啊，你在推究哲理？”河流说道，“水要流动才能保持清洁，这个自然规律，难道你已经忘掉？我是一条伟大的河流，那是因为我遵循着这条规律，不顾自身的安逸。我用源源不断的清洁的水，年年给人们带来利益。这就使我受到尊敬，光荣无比。也许，我将永远奔流不息；可你早被遗忘，不再有人提起。”","河流的话果然应验。河流至今长流不断，而可怜的池子却一年年淤塞，整个让青苔铺满，又让芦苇遮掩，到头来完全枯干。才能不利用就要衰退，它会逐渐磨灭；才能一旦让懒惰支配，它就一无所为。"]},{"id":212,"grade":"三年级下册","title":"语文园地","paragraphs":["邯郸学步 滥竽充数 掩耳盗铃","自相矛盾 刻舟求剑 画蛇添足","杞人忧天 井底之蛙 杯弓蛇影","小故事大道理","著名儿童文学家严文井曾说，寓言是一个魔袋，袋子很小，却能从里面取出很多东西来.....寓言故事一般比较短小，但背后往往藏着深刻的道理。","你读过吗","中国古代寓言凝结着中华民族的智慧。这些寓言故事题材广泛，形式活泼，读起来轻松有趣，既发人深省又好玩。读了下面这则寓言，你能体会到什么道理？","叶公好龙","古时候有个叶公，非常喜欢龙。他穿的衣服上绣着龙，戴的帽子上镶着龙，住的房子也一样，墙壁上画着龙，柱子上雕着龙。这些龙张牙舞爪，回旋盘绕，好像在云雾里飞翔。","天上的真龙听说叶公这么喜欢龙，就决定去拜访他。霎时间，乌云滚滚，雷电交加，真龙到了叶公家里，把头伸进了南窗，把尾巴绕到了北窗。","叶公见了真龙，吓得脸色发白，浑身发抖，连忙跑走了。原来他喜欢的不是真龙。","根据《新序·杂事》相关内容改写","相信你可以读更多","除了中国的寓言，还可以读一读其他国家的寓言。如伊索寓言、克雷洛夫寓言，都在世界上有很大的影响。","伊索寓言包含很多古希腊的民间故事,就像一个奇妙的动物王国。漫步其中，我们会看到吃不到葡萄反而说葡萄酸的狐狸，还会遇到咬死救命恩人的蛇·······","读克雷洛夫寓言时，我们会发现,很多故事都似曾相识，却被赋予了新的意义。老故事，新道理，这也是很多古老的寓言能够代代相传、历久弥新的原因。","快来打开世界寓言宝库的大门吧！","源源不断　津津有味","无忧无虑　无边无际","鹿忽然看到了自己的腿，不禁噘起了嘴，皱起了眉头：“唉，这四条腿太细了，怎么配得上这两只美丽的角呢！”","“真的，一个陶罐！”其他的人都高兴地叫起来。","通知","4月9日下午3点，请全体同学到操场集合，观看文艺表演","少先队大队部","4月7日","通知各班班长领取新校服。","通知全班同学参观博物馆。"]},{"id":213,"grade":"三年级下册","title":"元日","paragraphs":["作者：[宋代] 王安石","爆竹声中一岁除，","春风送暖入屠苏。","千门万户曈曈日，","总把新桃换旧符。","爆竹声中旧的一年已经过去，迎着和暖的春风开怀畅饮屠苏酒。","初升的太阳照耀着千家万户，都把旧的桃符取下换上新的桃符。","王安石（1021年12月18日－1086年5月21日），字介甫，号半山，谥文，封荆国公。世人又称王荆公。汉族，北宋抚州临川人（今江西省抚州市临川区邓家巷人），中国北宋著名政治家、思想家、文学家、改革家，唐宋八大家之一。欧阳修称赞王安石：“翰林风月三千首，吏部文章二百年。老去自怜心尚在，后来谁与子争先。”传世文集有《王临川集》、《临川集拾遗》等。其诗文各体兼擅，词虽不多，但亦擅长，且有名作《桂枝香》等。而王荆公最得世人共传之诗句莫过于《泊船瓜洲》中的“春风又绿江南岸，明月何时照我还。”"]},{"id":214,"grade":"三年级下册","title":"清明","paragraphs":["作者：[唐代] 杜牧","清明时节雨纷纷，","路上行人欲断魂。","借问酒家何处有？","牧童遥指杏花村。","江南清明时节细雨纷纷飘洒，路上的行旅之人个个都神情凄迷，烦闷不乐。","询问当地之人何处买酒消愁？牧童只是用手指了指杏花深处的村庄。","杜牧（公元803－约852年），字牧之，号樊川居士，汉族，京兆万年（今陕西西安）人，唐代诗人。杜牧人称“小杜”，以别于杜甫。与李商隐并称“小李杜”。因晚年居长安南樊川别墅，故后世称“杜樊川”，著有《樊川文集》。"]},{"id":215,"grade":"三年级下册","title":"九月九日忆山东兄弟","paragraphs":["作者：[唐代] 王维","独在异乡为异客，","每逢佳节倍思亲。","遥知兄弟登高处，","遍插茱萸少一人。","一个人独自在他乡作客，每逢节日加倍思念远方的亲人。","遥想兄弟们今日登高望远时，头上插满茱萸只少我一人。","王维（701年－761年，一说699年—761年），字摩诘(jié)，号摩诘居士。汉族，河东蒲州（今山西运城）人，祖籍山西祁县，唐朝诗人，有“诗佛”之称。苏轼评价其：“味摩诘之诗，诗中有画；观摩诘之画，画中有诗。”开元九年（721年）中进士，任太乐丞。天宝年间，拜吏部郎中、给事中。唐肃宗乾元年间任尚书右丞，世称“王右丞”。王维是盛唐诗人的代表，今存诗400余首，重要诗作有《相思》《山居秋暝》等。王维精通佛学，受禅宗影响很大。佛教有一部《维摩诘经》，是王维名和字的由来。王维诗书画都很有名，多才多艺，音乐也很精通。与孟浩然合称“王孟”。"]},{"id":216,"grade":"三年级下册","title":"10 纸的发明","paragraphs":["造纸术的发明，是中国对世界文明的伟大贡献之一。","早在几千年前，我们的祖先就创造了文字。可那时候还没有纸，要记录一件事情，就用刀把文字刻在龟甲和兽骨上，或者把文字铸刻在青铜器上。后来，人们又把文字写在竹片和木片上。这些竹片、木片用绳子穿起来，就成了一册书。但是，这种书很笨重，阅读、携带、保存都很不方便。古时候用“学富五车“形容一个人学问高，是因为书多的时候需要用车来拉。再后来，有了蚕丝织成的帛，就可以在帛上写字了。帛比竹片、木片轻便，但是价钱太贵，只有少数人能用，不能普及。","人们用蚕茧制作丝绵时发现，盛放蚕茧的篾席上，会留下一层薄片，可用于书写。考古学家发现，在两千年多年前的西汉时代，人们已经懂得了用麻来造纸。但麻纸比较粗糙，不便书写。","大约在一千九百年前的东汉时代，有个叫蔡伦的人，吸收了人们长期积累的经验，改进了造纸术。他把树皮、麻头、稻草、破布等原料剪碎或切断，浸在水里捣烂成浆；再把浆捞出来晒干，就成了一种既轻便又好用的纸。用这种方法造的纸，原料容易得到，可以大量制造，价格又便宜，能满足多数人的需要，所以这种造纸方法就传承下来了。","我国的造纸术首先传到邻近的朝鲜半岛和日本，后来又传到阿拉伯世界和欧洲，极大地促进了人类社会的进步和文化的发展，影响了全世界。"]},{"id":217,"grade":"三年级下册","title":"11 赵州桥","paragraphs":["河北省赵县的洨河上，有一座世界闻名的石拱桥，叫安济桥，又叫赵州桥。它是隋朝的石匠李春设计并参加建造的，到现在已经有一千四百多年了。","赵州桥非常雄伟。桥长五十多米，有九米多宽，这么长的桥，全部用石头砌成，下面没有桥礅，只有一个拱形的大桥洞，横跨在三十七米多宽的河面上。大桥洞顶上的左右两边，还各有两个拱形的小桥洞。平时，河水从大桥洞流过，发大水的时候，河水还可以从四个小桥洞流过。这种设计，在建桥史上是一个创举，既减轻了流水对桥身的冲击力，使桥不容易被大水冲毁，又减轻了桥身的重量，节省了石料。","这座桥不但坚固，而且美观。桥面两侧有石栏，栏板上雕刻着精美的图案：有的刻着两条相互缠绕的龙，嘴里吐出美丽的水花；有的刻着两条飞龙，前爪相互抵着，各自回首遥望；还有的刻着双龙戏珠。所有的龙似乎都在游动，真像活了一样。","赵州桥体现了劳动人民的智慧和才干，是我国宝贵的历史文化遗产。"]},{"id":218,"grade":"三年级下册","title":"12* 一幅名扬中外的画","paragraphs":["北宋时候，有位画家叫张择端。他画了一幅著名的画——《清明上河图》，画的是北宋都城汴京热闹的场面。这幅画有八九百年的历史，早已名扬中外，现在保存在北京故宫博物院里。","张择端画这幅画的时候，下了很大功夫。光是画上的人物，就有好几百多个：有从乡下来的农民，有撑船的船工，有做各种买卖的生意人，有留着长胡子的道士，有走江湖的医生，有摆小摊的摊贩，有官吏和读书人……三百六十行，哪一行的人都画在上面了。","画上的街市可热闹了。街上有挂着各种招牌的店铺。走在街上的，是来来往往、形态各异的人：有的骑着马，有的挑着担，有的赶着毛驴，有的推着独轮车，有的悠闲地在街上溜达。画面上的这些人，有的不到一寸，有的甚至只有黄豆那么大。别看画上的人小，每个人在干什么，都能看得清清楚楚。","最有意思的是桥北头的情景：一个人骑着马，正往桥下走。因为人太多，眼看就要撞上对面来的一乘轿子。就在这个紧急时刻，马笼头被一下子拽住了，这才没让马撞上那乘轿子。旁边两头运货的小毛驴正在下坡，脚下不稳。站在桥栏杆边欣赏风景的人被惊扰了，连忙回过头来……你看，张择端画的画，是多么传神啊！","《清明上河图》使我们看到了八九百年以前的古都风貌，看到了当时普通百姓的生活情景。"]},{"id":219,"grade":"三年级下册","title":"语文园地","paragraphs":["税务局　档案馆　咖啡馆","阅览室　废品收购站　农贸市场","税 档 咖 啡 阅 废 贸","剪碎或切断  浸  捣  捞  晒","有个叫蔡伦的人，吸收了人们长期积累的经验，改进了造纸术。他把树皮、麻头、稻草、破布等原料剪碎或切断，浸在水里捣烂成浆；再把浆捞出来晒干，就成了一种既轻便又好用的纸。","文房四宝：笔墨纸砚","雅人四好：琴棋书画","中医四诊：望闻问切","走在街上的，是来来往往、形态各异的人：有的骑着马，有的挑着担，有的赶着毛驴，有的推着独轮车，有的悠闲地在街上溜达。","桥面两侧有石栏，栏板上雕刻着精美的图案：有的刻着两条相互缠绕的龙，嘴里吐出美丽的水花；有的刻着两条飞龙，前爪相互抵着，各自回首遥望；还有的刻着双龙戏珠。"]},{"id":220,"grade":"三年级下册","title":"13 花钟","paragraphs":["鲜花朵朵，争奇斗艳，芬芳迷人。要是我们留心观察，就会发现，一天之内，不同的花开放的时间是不同的。凌晨四点，牵牛花吹起了紫色的小喇叭；五点左右，艳丽的蔷薇绽开了笑脸；七点，睡莲从梦中醒来；中午十二点左右，午时花开花了；下午三点，万寿菊欣然怒放；五点，紫茉莉苏醒过来；月光花在七点左右舒展开自己的花瓣；夜来香在晚上八点开花；昙花却在九点左右含笑一现……","不同的植物为什么开花的时间不同呢？有的植物开花的时间，与温度、湿度、光照有着密切的关系。比如，昙花的花瓣又大又娇嫩，白天阳光强，气温高，空气干燥，要是在白天开花，就有被灼伤的危险。深夜气温过低，开花也不适宜。长期以来，它适应了晚上九点左右的温度和湿度，到了那时，便悄悄绽开淡雅的花蕾，向人们展示美丽的笑脸。还有的花，需要昆虫传播花粉，才能结出种子，它们开花的时间往往跟昆虫活动的时间相吻合。","一位植物学家曾有意把不同时间开放的花种在一起，把花圃修建得像钟面一样，组成花的“时钟”。这些花在二十四小时内依次开放。你只要看看什么花刚刚开放，就知道大致是几点钟，这是不是很有趣？"]},{"id":221,"grade":"三年级下册","title":"14 蜜蜂","paragraphs":["听说蜜蜂有辨认方向的能力，无论飞到哪里，它总是可以回到原处。我想做个实验。","一天，我在我家草料棚的蜂窝里捉了一些蜜蜂，把它们放在纸袋里。我叫小女儿在蜂窝旁等着，自己带着蜜蜂，走了四公里路，打开纸袋，在它们身上做了白色记号，然后放了出来。二十只左右被闷了好久的蜜蜂向四面飞散，好像在寻找回家的方向。这时候刮起了狂风，蜜蜂飞得很低，几乎要触到地面，大概这样可以减少阻力。我想，它们飞得这么低，怎么能看到遥远的家呢？","在回家的路上，我推测蜜蜂可能找不到家了。没等我跨进家门，小女儿就冲过来，脸红红的，看上去很激动。她高声喊道：“有两只蜜蜂飞回来了！它们两点四十分回到蜂窝里，肚皮下面还沾着花粉呢。”","我放蜜蜂的时候是将近两点钟，也就是说，在大约三刻钟的时间里，那两只小蜜蜂飞了四公里路，这还包括了采花粉的时间。","傍晚时，我亲眼看到另外三只飞了回来，身上也都带着花粉。","第二天我检查蜂窝时，发现了十五只身上有白色记号的蜜蜂。","这样，二十只左右的蜜蜂，至少有十五只没有迷失方向，准确无误地回到了家。尽管它们逆风而飞，沿途都是一些陌生的景物，但它们确确实实飞回来了。","蜜蜂靠的不是超常的记忆力，而是一种我无法解释的本能。"]},{"id":222,"grade":"三年级下册","title":"15* 小虾","paragraphs":["院子里的葡萄架下，一口缸闲着。夏天，积了大半缸雨水。从葡萄架的空隙里漏下的阳光，洒落在水面上，像许多大大小小的圆镜。我想，这缸不正好用来养小鱼小虾吗？","我和邻居阿成哥跑到村边小溪里，在竹荫下静水处，轻轻掀开小石块，或者把手伸到大石块下，捉了一些小虾，带回家养在缸里。这些小虾，有的通体透明，像玻璃似的，这是才长大的；有的稍带灰黑色，甚至背上、尾巴上还积着泥，长着青苔，这是老的，大家叫它千年虾。","缸里的小虾十分有趣。它们有的独自荡来荡去，有的互相追逐，有的紧贴住缸壁。要是你用小竹枝去动动那些正在休息的小虾，它们会立即向别的安静的角落蹦去，一路上像生了气似的，不停地舞动着前面那双细长的腿，腿末端那副钳子一张一张的，胡须也一翘一翘地摆动着，连眼珠子也一突一突的。如果这时碰到正在闲游的同伴，说不定就要打起来。小虾的搏斗很激烈，蹦出水面是常有的事，有时还会蹦到缸外的地面上。","我觉得该让它们在缸里生活得更快乐些。后来，我就和阿成哥到小溪里采了一些水草，捡了些石块放在缸里。我们记得，小溪里的虾是挺喜欢钻到石块下面休息的。","有一天，我从缸里捉起几只较大的虾，发现它们的腹部藏着许多圆圆的卵。不久，缸里的小虾真的多了起来。","有时葡萄架上一片落叶掉进缸里，不一会儿，叶子下就会聚起许多小小的虾。"]},{"id":223,"grade":"三年级下册","title":"语文园地","paragraphs":["这时候刮起了狂风，蜜蜂飞得很低，几乎要触到地面，大概这样可以减少阻力。我想，它们飞得这么低，怎么能看到遥远的家呢？","这个路口总是很畅通，那个路口却总是堵车。两个路口才相距一百米，差别却这么大。到底是什么原因呢?","作者：[唐代] 韦应物","独怜幽草涧边生，","上有黄鹂深树鸣。","春潮带雨晚来急，","野渡无人舟自横。","唯独喜欢涧边幽谷里生长的野草，还有那树丛深处婉转啼鸣的黄鹂。","傍晚时分，春潮上涨，春雨淅沥，西涧水势顿见湍急，荒野渡口无人，只有一只小船悠闲地横在水面。","韦应物（生卒年不详），字义博，京兆杜陵（今陕西省西安市）人。唐朝官员、诗人，世称“韦苏州”“韦左司”“韦江州”。今传有10卷本《韦江州集》、两卷本《韦苏州诗集》、10卷本《韦苏州集》。散文仅存一篇。因出任过苏州刺史，世称“韦苏州”。诗风恬淡高远，以善于写景和描写隐逸生活著称。","我养了一只螃蟹，他眼睛、嘴巴都不怎么显眼，钳子倒是很大。它最爱显摆它的钳子了。有一次，我轻轻点了它下用一根小棍，它立刻转动身体，向我高高举起那剪刀似的大钳子。我又点了几下，它钳子越举越高，突然，整个身子翻了过去。它急了。腿和钳子在空中乱舞，好不容易才借助玻璃缸壁翻身过来。"]},{"id":224,"grade":"三年级下册","title":"16 宇宙的另一边","paragraphs":["我趴在窗台上，看着浩瀚的星空。","星光洒进我的眼睛，在我身体里汩汩流淌，告诉我一个秘密：很远很远的地方，宇宙的另一边，是这一边的倒影。那里有座一样的城市，有条一样的街道，街角处有栋一样的房子，房子里有个一样的孩子。","那个孩子是另一个我吗？当我从书包里拿出作业本的时候，他是不是正把作业本放回书包？当我气喘吁吁爬楼梯的时候，他是不是正下楼去？当我趴在窗台看着星空的时候，他会不会也趴在窗台，看着星空，想着我呢？我们的目光会在哪里相遇？","在宇宙的这一边，雪是在冬天下的；那么，在宇宙的另一边，雪是在夏天下的吗？在宇宙的这一边，太阳从东边升起；那么，在宇宙的另一边，太阳是从西边升起的吗？","在宇宙的这一边，石头是没有生命的；在宇宙的另一边，它会不会像花朵一样开放，或者像人一样行走？","早上，我背起书包出门向左走时，忽然想到，在宇宙的另一边，另一个我会出门向右走吗？","上课铃声响了，我们的第一节课是语文课。在宇宙的另一边，第一节是数学课吗？他们的数学课，会是什么样子的呢？","在宇宙的另一边，加法是这样的：大地万物加上一场大雪等于一片白茫茫，那时，无数的孩子会从家里冲出来，打雪仗、堆雪人、滑雪......这样，大地万物加上一场大雪又等于无数孩子的节日。","乘法是这样的：“早春二月”乘“竹外桃花三两枝”，再乘“春雨贵如油”，等于“春风又绿江南岸”，又等于“碧玉妆成一树高，万条垂下绿丝绦”，最后等于“儿童散学归来早，忙趁东风放纸鸢”。","正当我的思绪在茫茫宇宙中穿梭时，突然，耳边响起了语文老师的声音：“你在想什么呢？”","我有些尴尬。但在那一-瞬间，我决定把我知道的告诉大家：在宇宙的另一边，如果想写一篇关于风的习作，就得闭上眼睛，想象风的样子，慢慢地让自己也变成风，在空中飞啊飞，飞得越高，习作的分数就越高......","下课了，大家都围着我，想知道宇宙的另一边还有什么有趣的事情。是啊，关于宇宙的另一边，我们都想知道更多。到了晚上，我还要趴在窗台上，看着浩瀚的星空，穿越茫茫宇宙，飞到那个很远很远的地方，再去拜访宇宙另一边的那个“我”。"]},{"id":225,"grade":"三年级下册","title":"17 我变成了一棵树","paragraphs":["“英英，吃饭了！”","我在树下玩得好好的，一点儿都不想吃饭。","“英英，吃饭了！”妈妈的嗓门又大了许多。","我真希望变成一棵树，这样就没人在你玩的时候叫你吃饭了。我心里想着，就觉得身上痒痒的，低头一看，发现许多小树枝正从我身上冒出来。呀，我真的变成了一棵树！","你猜，我变的树上会长什么？当然不是苹果啦，梨也不对---对了，鸟窝！","我变的树上长满了各种形状的鸟窝：三角形的、正方形的、还有长方形的、圆形的、椭圆形的、菱形的……风一吹，它们就在枝头跳起了舞。","我会请小白兔、小刺猬、小松鼠、小鸭子、小鳄鱼、小狐狸住在里面，如果你喜欢也可以住进来。","你怎么住进来？别担心，我会弯下腰，让鸟窝离你很近很近，你只需轻轻一跳或者轻轻一爬，就像平时上你的小床那么容易。","傍晚的时候，妈妈背着一个大包过来了，我的心嗵嗵地跳着，震得树上的鸟窝都一动一动的，发出丁零丁零的声音。","“你好！”妈妈向我点了点头，“请问我可以住在那个三角形的鸟窝里吗?”","她不知道我变成了树！我有点儿高兴，又有些失望。一些树枝轻轻地垂下，妈妈顺着这些树枝爬了上来，坐在那个三角形的鸟窝里。","妈妈打开背包，从里面拿出好多东西：巧克力、香肠、面包、花生、牛奶……她把这些好吃的分给小动物们。他们一起在我的鸟窝里津津有味地吃了起来。","“咕噜噜……”我的肚子里发出一种怪怪的声音，把他们吓了一跳。他们也只是奇怪地互相望了一眼，又继续吃起来。","“咕噜噜……”我肚子里的声音越来越响了。这时候，我开始想念家里那些香喷喷的饭菜，好像还看见爸爸正在大口大口地啃着一块糖醋排骨。天哪，那可是我最喜欢吃的东西！","“咦，下雨了。”小狐狸抬头望了望，可天空中一丝乌云都没有。","“是你的牛奶打翻了吗？”小鳄鱼问小松鼠。","“你看，这不好好的嘛。”","“那么，可能是一只虫子撒的尿。”","“不对，是大树在哭。”小白兔发现了树干上不断往下滴的水珠。","唉，变成了树真麻烦。他们连水珠是从我的嘴巴里流出来的都不知道。","“小馋猫，肚子饿了，对吧？英英！”妈妈说话了，还对我眨了一下眼睛。","噢，最了解我的人到底还是妈妈。","哎呀，她是怎么知道我的秘密的？"]},{"id":226,"grade":"三年级下册","title":"习作例文","paragraphs":["想一想，一支老憋在抽屉里的铅笔，会有多少梦想？第一个梦想，是溜出教室。知道我要做什么吗？我要到山坡上，萌出嫩嫩的芽儿；还在头顶上，开出一朵漂亮的花儿。蝴蝶啊蜜蜂啊，就猜不出我是谁了。哈，多么好玩！多么开心！","第二个梦想，是跳进荷塘里。知道我要做什么吗？我要为小鱼虾，撑起阴凉的伞；伞上，还趴着大眼睛青蛙。有的在伞上歌唱，有的在伞下玩耍。哈，多么好玩！多么开心！","第三个梦想，是躲到菜园里去。知道我要做什么吗？我要在青叶间，长成长长的豆角；或者，伪装成嫩嫩的丝瓜。菜园里的派对马上开始！哈，多么好玩！多么开心！","第四个梦想，是来到小溪边。知道我要做什么吗？我要为玩水的鸟当船篙，为过河的蚂蚁当木筏。船上的、岸边的一齐喝彩！哈，多么好玩！多么开心！","第五个梦想，是跑到运动场上。知道我要做什么吗？我要当一会儿小松鼠的撑竿，当一阵儿小猴子的标枪。挂在脖子上的奖牌亮闪闪的。哈，多么好玩！多么开心！","谁也不知道，一支铅笔有多少梦想……就像种在稿纸上的字，发多少芽，开多少花，结多少童话。","有一条尾巴，它很自豪地说：“我拥有一只猫！”","拥有一只猫，这条尾巴真不得了。可是，一条尾巴怎么能有一只猫呢？难道，它把猫养在家里，或者把它关在笼子里，或者……哎，真是想不出来。","“用不着关，”这条尾巴得意地说，“我从出生开始，就拥有这只猫，无论它干什么，都听我的话，都跟在我身边。","尾巴那么小，它的猫应该特别特别小。会不会就是一只跳蚤？","跳蚤怎么会是猫呢？”尾巴说，“我这只猫特别乖，我天天骑着它满地跑。”","尾巴上的跳蚤听见它的话，哈哈大笑：“如果你有一只猫，那你为什么还跟着它到处跑？是猫有你这条尾巴，而不是你这条尾巴有一只猫。”","尾巴坚持自己的想法：“我就是有一只猫。我跟着它跑是因为我乐意。你看看小孩子，个个当爸爸妈妈的小尾巴，跟着他们跑。难道只能是爸爸妈妈有小孩子，不能是小孩子有爸爸妈妈吗？猫可以有一条尾巴，为什么尾巴就不能有一只猫？","另一条尾巴听到了，高兴地说：“哎呀，原来我有一只狗哇，真好！”原来，它是一条狗的尾巴。","狗生气了吗？没有，因为它也听见了猫尾巴的话。它跟在主人的身后，高兴地想：“对呀，原来我有一个人，真神奇！”"]},{"id":227,"grade":"三年级下册","title":"18 童年的水墨画","paragraphs":["溪边","垂柳把溪水当作梳妆的镜子，山溪像绿玉带一样平静。人影给溪水染绿了，钓竿上立着一只红蜻蜓。忽然扑腾一声人影碎了，草地上蹦跳着鱼儿和笑声。","江上","像刚下水的鸭群，扇动翅膀拍水戏耍。一双双小手拨动着浪花，你拨我溅笑哈哈。是哪个“水葫芦”一下钻入水中，出水时只见一阵水花两排银牙。","林中","松树刚洗过澡一身清清爽爽，松针上一串串雨珠明明亮亮。小蘑菇钻出泥土戴一顶斗笠，像一朵朵山花在树下开放。是谁一声欢叫把雨珠抖落，只见松林里一个个斗笠像蘑菇一样。"]},{"id":228,"grade":"三年级下册","title":"19 剃头大师","paragraphs":["我的表弟小沙天生胆小，他怕吃药，怕做噩梦，还怕剃头。","小沙每次都是被姑父押进理发店的，而且，姑父还得执一把木尺在一旁监督，否则，小沙准会夺门而逃。","店里的剃头师傅都不欢迎小沙这样的顾客，因为谁给他剃头，他就骂谁“害人精”，还用看仇人一样的目光怒视对方。","总是一个老剃头师傅来做小沙的冤家。老师傅耳朵不好，听不清小沙的抗议，而且，他有一把磨得锃亮的剃刀，所以，小沙只得规规矩矩由老师傅摆布。","最痛苦的是，老师傅习惯用一把老掉牙的推剪，它常常会咬住一绺头发不放，让小沙吃尽苦头。这还不算，老师傅眼神差了点儿，总把碎头发掉在小沙的脖子里，痒得小沙哧哧笑。你想想，这一会儿痛一会儿痒的，跟受刑一样。","最让小沙耿耿于怀的是，每次剃完头，姑父还要付双倍的钱给“害人精”。","这次，小沙的头发很长了。他知道姑父绝对不肯让他这样过年，可他又怕再去理发店受折磨，就央求我替他剪头发，并答应剪完后付给我五块钱。","其实，不给钱我也愿意，因为从来没有人肯把头交给我随便处置。我一连在他肩上拍了三下，表示：有你的，老弟。","小沙坐在凳子上，看我找出剪刀，才有些慌，说：“别剪破耳朵，你得发誓！","虽然以前没有干过这一行，可我好像有剃头的天分。我先把姑父的大睡衣给他围上，再摆出剃头师傅的架势，嚓嚓两剪刀，就剪下一堆头发。","“嗬！”小沙高兴了，“你真把头发剪下来了！”","我觉得自己像个剃头大师，剪刀所到之处，头发纷纷飘落，真比那老剃头师傅还熟练。这儿一剪刀，那儿一剪刀，不一会儿，姑父的睡衣就像一张熊皮，上面落满了黑头发。","很快，我就发现自己闯了祸。因为这样随意乱剪，头发长长短短，这儿翘起，那儿却短得不到一厘米。","“哎呀！”我叫起来，“坏了！”","小沙连忙摸耳朵，看它们还在，就无所谓了。我敢说，世界上再也没有比他更优秀的顾客了。","我剪掉了几根翘起的长发，又把头发修了修，可惜越修越糟，一些头发越剪越短，甚至露出了头皮。一眼望去，整个头上坑坑洼洼，耳朵边剪得小心，却像层层梯田。","我想稳住小沙，告诉他这是最时髦的发式，可他一照镜子，大叫一声 ，像见了鬼一样。","当然，我没得到那五块钱。这还不算倒霉，最倒霉的是小沙父子：小沙被迫去理发店剃了个和电灯泡一样的光头；姑父呢，那件睡衣上的头发怎么也清除不干净，他每天夜里都要爬起来两三次，捉跳蚤一样找身上的碎头发。"]},{"id":229,"grade":"三年级下册","title":"20 肥皂泡","paragraphs":["小的时候，游戏的种类很多，其中我最爱玩的是吹肥皂泡。","下雨的时节，不能到山上海边去玩，母亲总教我们在廊子上吹肥皂泡。她说阴雨时节天气潮湿，肥皂泡不容易破裂。","方法是把用剩的碎肥皂放在一只小木碗里，加上点儿水，和弄和弄，使它溶化，然后用一支竹笔套管，蘸上那黏稠的肥皂水，慢慢地吹起，吹成一个轻圆的网球大小的泡儿，再轻轻地一提，那轻圆的球儿便从管上落了下来，软悠悠地在空中飘游。若用扇子在下面轻轻地扇送，有时能飞得很高很高。","这肥皂泡，吹起来很美丽，五色的浮光，在那轻清透明的球面上乱转。若是扇得好，一个大球会分裂成两三个玲珑娇软的小球，四散分飞。有时吹得太大了，扇得太急了，这脆薄的球，会扯成长圆的形式，颤巍巍的，光影零乱。这时大家都悬着心，仰着头，屏住呼吸，--不久，这光丽的薄球就无声地散裂了，肥皂水落了下来，洒到眼睛里，大家都忽然低了头，揉出了眼泪。","那一个个轻清脆丽的小球，像一串美丽的梦，是我们自己小心地轻轻吹起的，吹了起来，又轻轻地飞起，是那么圆满，那么自由，那么透明，那么美丽。借着扇子的轻风，把她们一个个送上天去送过海去。到天上，轻轻地挨着明月，渡过天河跟着夕阳西去。或者轻悠悠地飘过大海，飞越山巅，又低低地落下，落到一个熟睡中的婴儿的头发上……目送着她们，我心里充满了快乐、骄傲与希望。"]},{"id":230,"grade":"三年级下册","title":"21* 我不能失信","paragraphs":["一个风和日丽的早晨，宋耀如一家用过早餐，准备到一位朋友家去做客。二女儿宋庆龄特别高兴，她早就盼着到这位伯伯家去了。伯伯家养的鸽子，尖尖的嘴巴，红红的眼睛，漂亮极啦！伯伯还说准备送她一只呢！","她刚走到门口，突然停住了脚步，皱起了眉头。","爸爸看见了，奇怪地问：“庆龄，你怎么不走啦？”","“爸爸，我不能去了！我昨天和小珍约好了，今天她来我们家，我教她叠花篮。”庆龄说。","“你不是一直想去伯伯家吗？改天再教小珍吧。”爸爸说完，拉起庆龄的手就要走。","“不行！不行！我走了，小珍来了会扑空的，那多不好啊！”庆龄边说边把手抽回来。","“那……回来你去小珍家解释一下，表示歉意，改天再教她叠花篮，好不好？”妈妈在一旁说。","“不，妈妈。您说过，做人要信守诺言。如果我忘记了这件事，见到她时向她道歉是可以的，但我已经想起来了，就不能失信了！”庆龄坚定地说。","“我明白了，我们的庆龄是个守信用的孩子。”妈妈望着庆龄笑了笑，说，“那你就留下来吧！”","送家里人出门后，庆龄一个人回到房间里，耐心地等候着。她一会儿拿起一本书看，一会儿又坐到琴凳上弹钢琴，平时很熟的曲子，今天却总是弹不准。可是，直到家里人吃过午饭回来，小珍也没有来。妈妈心疼地说：“我的女儿一个人在家，该多没意思啊！”庆龄仰起脸回答道：“一个人在家，是很没劲。可是，我并不后悔，因为我没有失信。”"]},{"id":231,"grade":"三年级下册","title":"语文园地","paragraphs":["旭日　岛屿　海滨　沙滩","瞭望　巡航　缆绳　铁锚","旭 屿 瞭 巡 缆 锚","见善则迁，有过则改。—《周易》","过而不改，是谓过矣。—《论语》","人谁无过？过而能改，善莫大焉。—《左传》","米饭没熟，还要再蒸一会儿。","平时很熟的曲子，今天却总是弹不准。","我很喜欢苹果的味道。","这本书越看越有味道。","我的表弟小沙天生胆小，他怕鬼，怕喝中药，怕做噩梦，还怕剃头。","他们高兴极了，唱了一首又一首的歌，还围在一起跳舞。"]},{"id":232,"grade":"三年级下册","title":"22 我们奇妙的世界","paragraphs":["这是一个奇妙的世界，一切看上去都是有生命的。","你看天空的珍藏——","清晨，太阳升起，带来新的一天。开始，天空呈粉红色，慢慢地变成了蔚蓝色，太阳就像一个大火球一样升起来了。","有时，云彩在蓝色的天空中飞行，如同经过雕饰一样，呈现出各种奇妙的形状，告诉我们许多奇妙的故事……","当云彩变得又黑又重时，雨点就会噼噼啪啪地降落到大地上。","雨后，我们会看到地上有许多水洼，就像有趣的镜子，映射着我们的脸。","一天结束了，落日的余晖不时变幻着颜色，好像有谁在天空涂上了金色、红色和紫色。","黑夜降临了，我们看见夜空中群星闪烁，就像千千万万支极小的蜡烛在发光。","再看大地的珍藏——","我们能看到植物生长的奇迹——极小的一粒种子种到地里，生根、发芽，不久就开花了，花很漂亮。","我们能看到各种颜色诱人的水果，圆润的鲜红色的樱桃，深紫色的李子，浅黄色的梨。","夏日，在大树下乘凉，我们会感叹，大树带来这么多绿荫。","秋天带着金黄色的光辉神奇地到来了，那时，道路上好像洒满了光芒。蝴蝶张开漂亮的翅膀在空中翩翩起舞。","鸟儿为了建造它们的房子，衔着泥土振翅飞翔。","我们领略秋风的劲吹——树枝颤动，树叶飘落。","冬天，我们看到了房檐上垂下的冰柱，它们好像一把把锋利的刀剑在阳光下闪耀，等到积雪融化时，从房檐上落下的小水滴，就像一颗颗珍珠。","只要我们仔细地观察、寻找，就能从极普通的事物中找到美——各种形状的卵石，三桅小船的模型，颜色各异的羽毛。","是的，世界上存在的奇妙的事物是无穷的，只要我们去寻找。"]},{"id":233,"grade":"三年级下册","title":"23 海底世界","paragraphs":["你可知道，大海深处是怎样的吗？","海面上波涛澎湃的时候，海底依然很宁静。最大的风浪，也只能影响到海面以下几十米深。阳光很难射进深海，水越深光线越暗，五百米以下就全黑了。在这一片黑暗的深海里，却有许多光点像闪烁的星星，那是有发光器官的深水鱼在游动。","海底是否没有一点儿声音呢？不是的。海底的动物常常在窃窃私语。你用水中听音器一听，就能听见各种声音：有的像蜜蜂一样嗡嗡，有的像小鸟一样啾啾，有的像小狗一样汪汪，还有的好像在打鼾……它们吃东西的时候发出一种声音，行进的时候发出另一种声音，遇到危险还会发出警报。","海里的动物，各有各的活动方法。海参靠肌肉伸缩爬行，每小时只能前进四米。有一种鱼身体像梭子，每小时能游几十千米，攻击其他动物的时候，比普通的火车还快。乌贼和章鱼能突然向前方喷水，利用水的反推力迅速后退。还有些贝类自己不动，却能巴在轮船底下作免费的长途旅行。","海底的植物差异也很大。它们的色彩多种多样，有褐色的，有紫色的，还有红色的。最大的海藻长达二三百米。最小的单细胞海藻，要用显微镜才能看清楚。","海底蕴藏着丰富的煤、铁、石油和天然气，还有陆地上储量很少的稀有金属。","海底真是个景色奇异、物产丰富的世界。"]},{"id":234,"grade":"三年级下册","title":"24 火烧云","paragraphs":["晚饭过后，火烧云上来了。霞光照得小孩子的脸红红的。大白狗变成红的了。红公鸡变成金的了。黑母鸡变成紫檀色的了。喂猪的老头儿在墙根靠着，笑盈盈地看着他的两头小白猪变成小金猪了。他刚想说“你们也变了……”，旁边走来个乘凉的人对他说：“您老人家必要高寿，您老是金胡子了。”","天上的云从西边一直烧到东边，红彤彤的，好像是天空着了火。","这地方的火烧云变化极多，一会儿红彤彤的，一会儿金灿灿的，一会儿半紫半黄，一会儿半灰半百合色。葡萄灰、梨黄、茄子紫，这些颜色天空都有。还有些说也说不出来、见也没见过的颜色。","一会儿，天空出现一匹马，马头向南，马尾向西。马是跪着的，像等人骑上它的背，它才站起来似的。过了两三秒钟，那匹马大起来了，腿伸开了，脖子也长了，尾巴却不见了。看的人正在寻找马尾巴，那匹马变模糊了。","忽然又来了一条大狗。那条狗十分凶猛，在向前跑，后边似乎还跟着好几条小狗。跑着跑着，小狗不知哪里去了，大狗也不见了。","接着又来了一头大狮子，跟庙门前的石头狮子一模一样，也那么大，也那样蹲着，很威武很镇静地蹲着。可是一转眼就变了，再也找不着了。","一时恍恍惚惚的，天空里又像这个又像那个，其实什么也不像，什么也看不清了。必须低下头，揉一揉眼睛，沉静一会儿再看。可是天空偏偏不等待那些爱好它的孩子。一会儿工夫，火烧云就下去了。"]},{"id":235,"grade":"三年级下册","title":"语文园地","paragraphs":["兵来将挡，水来土掩。","不入虎穴，焉得虎子。","眼见为实，耳听为虚。","近朱者赤，近墨者黑。","你可知道，那座山上的石头有多么奇妙吗？·······","你是否听说过······","寻物启事","昨天下午放学后，我把一件蓝色外套落在了操场上。如有拾到者，请与我联系，非常感谢!","三年级(1)班　李晓宇","5月20日"]},{"id":236,"grade":"三年级下册","title":"25 慢性子裁缝和急性子顾客","paragraphs":["故事发生在冬天。裁缝店里走进一位顾客。","顾客把一卷布料放到桌上，对裁缝说：“我想做件棉袄。我已经跑了三家裁缝店了。第一家说要到秋天才能做好。第二家问我有没有等到夏天的耐心。第三位师傅倒是强些，但他最早也要到开春才能交货。我可等不及，都没让他们做。告诉您，我和别的顾客不一样，我是个性子最急的顾客。请问师傅，您准备让我什么时候来取衣服——秋天？夏天？春天？……“","“不，”裁缝说，“就在冬天。”","裁缝又补充一句：“不过，我指的是明年冬天。”","顾客噌的一下子跳起来：“这么慢啊！”","裁缝说：“我和别的裁缝不一样，我是个性子最慢的裁缝啊。”","“那就算啦，我还是去找刚才的师傅吧。”顾客夹起布料就要走。","“别走，”裁缝把顾客叫住，“我知道您是个急性子。依我看，我做的活儿最适合您这种性子的顾客啦。”","急性子顾客挺纳闷：“为什么？”","“照您的性子，您肯定会一拿到衣服就穿在身上，不是吗？”裁缝说。","顾客说：“那当然。我可不愿意把新衣服藏在箱子里。”","裁缝说：“那么，您要是在别的季节拿到新棉袄，也不得不由着性子穿上。可是您无论在秋天、夏天还是春天穿一件棉袄，人家都会笑话您的。我呢，决不会让人笑话您。非但如此，在您穿上我做的美观大方的新棉袄的时候，大家还会围着您直夸奖，甚至羡慕您呢。”","这位顾客歪着头想了想，不得不承认裁缝说得有道理。于是，做衣服的事儿就算说定了。","不料，这位顾客第二天又跑到裁缝店来，说：“我不做棉袄了！”","“等到明年冬天，时间实在太长啦。”顾客提出，“把我那棉袄里的棉花拽掉，改成夹袄，让我提前在秋天就能穿上合时的新衣服吧。”","“不要棉花了，行啊。”裁缝答应了，“为您服务，没说的！“","顾客满意地走了。可是第三天他又来了。","“师傅，把我那夹袄的袖子剪去一截儿，改成夏天能穿的短袖衬衫吧，我实在等不及了。”","裁缝点点头：“剪袖子，只要咔嚓咔嚓两剪子，好办得很，没问题。”","又过了一天，那顾客再来的时候，裁缝笑着问他：“怎么，您那件短袖衬衫还能改成什么？”","顾客说：“对不起，麻烦您再给我改成春装吧。袖子嘛，把上次剪下来的再接上去就是啦。”","裁缝这回摇头了：“接上去的袖子多难看啊。”","“那您别管，只要能让我早些在春天穿上。您别忘了，我可是个急性子顾客啊。”","裁缝说：“亲爱的顾客，我要对您负责。我不会让您穿上这么难看的衣裳，这也坏了我的名声啊。”","顾客泄气了。但裁缝又拍拍他的肩，说：“您放心，凭我的手艺，不用接袖子也能给您做出一件最漂亮的春装。”","顾客感动极了：“那太谢谢啦。您真的不用接袖子？”","“根本不用。”裁缝解释说，“因为您的布在我的柜子里搁着，我还没开始裁料呢。”","顾客惊讶、恼怒地瞪大了眼睛！","“您可别忘了，”裁缝提醒他说，“我是个慢性子裁缝啊。”"]},{"id":237,"grade":"三年级下册","title":"26* 方帽子店","paragraphs":["这家帽子店从来没有做过别的帽子。","他们的橱窗里都是方帽子。第一顶是方的，第二顶是方的，第三顶还是方的……","问他们为什么只做方帽子，他们总是这样回答：“我们从来都是做方帽子，方帽子才是好帽子，不能改的。”","做帽子的人做方帽子，买帽子的人买方帽子。我们常常可以看见戴着方帽子的人在马路上走着。他们圆圆的脑袋藏在方帽子里，紧的地方太紧，宽的地方太宽，冬天戴着不太暖，夏天戴着却热得满头汗。舒服吗？真不舒服！","小孩子们觉得方帽子又奇怪又不舒服，他们想，圆圆的头为什么戴方帽子呢？圆的不行吗？","大人们总是这样回答：“因为一直以来都是这样的。”","小孩子们可不喜欢戴方方的帽子，他们喜欢用纸做出圆的、尖的、香蕉形的帽子，戴在头上，又舒服又漂亮。","“假如我们用布做成真的帽子……”一个小孩子说。","“那戴在头上就更舒服了。”另一个小孩子接着说。","他们设法找到一些布，试着做了几顶圆帽子，像碗一样扣在头上，很舒服。","街上人山人海。在密密麻麻的方帽子中，忽然出现了几顶圆帽子，方帽子店的主人大吃一惊。最让他吃惊的是，自己的儿子也戴了一顶圆帽子！","“快快把它丢掉！”方帽子店的主人抓起圆帽子，丢在地上。","“我要！我要！”儿子嚷嚷着。","“不懂事的孩子！好好的方帽子不戴，要戴圆帽子！”","儿子不理他，拾起圆帽子戴在头上，一溜烟似的跑了。","孩子们慢慢地长大了，想出了许多帽子的式样，碗形的、香蕉形的、圆筒形的……夏天戴宽边的香蕉形的草帽，冬天戴圆筒形的呢绒帽，春天和秋天戴碗形的布帽。","后来，方帽子店对面，又开了一家帽子店，橱窗里放着各式各样的帽子，却没有一顶是方的。方帽子店里摆放着方方正正的帽子，却没有一顶是圆的，玻璃橱窗里还贴了一张广告：“专卖从不改变的方的好帽子。”对面的新帽子店里也贴了一张广告：“专卖各式各样的舒服的好帽子。”","顾客们在方帽子店门前站一会儿，又到新帽子店门前站一会儿，不知道买哪一种好。他们在两家的橱窗前看了好久，最后还是进了新帽子店。","路上的行人已经变了样子，夏天戴着宽边的香蕉形的草帽，冬天戴着圆筒形的呢绒帽……","方帽子店的主人气得几乎昏过去！","日子一天天地过去，世界一天天在改变，那些不舒服的方帽子，慢慢地成为古董。"]},{"id":238,"grade":"三年级下册","title":"27 漏","paragraphs":["从前，有一户人家：一个老公公，一个老婆婆，还喂着一头黑脊背、白胸脯的小胖驴。","山上住着一只老虎，山下住着一个贼。老虎嘴馋，一心想着吃这头小胖驴；贼手痒，一心想着偷这头小胖驴。","一天晚上，下着蒙蒙小雨。老虎来了，贼也来了。老虎用爪在墙壁上抓，贼用手在屋顶上挖，不一会儿，墙被老虎抓了个窟窿，屋顶被贼挖了个窟窿。老虎钻进驴圈，贼也正想往下跳。忽然，老公公和老婆婆在里屋说起话来，老虎和贼吓得大气都不敢出了。","老公公说：“好像有什么声音在响？”","老婆婆说：“唉！管他狼哩，管他虎哩，我什么都不怕，就怕漏！”","老虎趴在驴圈里想：“翻山越岭我什么都见过，就是没见过‘漏’，莫非‘漏’比我还厉害？”","贼蹲在屋顶上想：“走南闯北我什么都听说过，就是没听说过‘漏’，莫非‘漏’比我还厉害？”","老虎吓得浑身发抖，贼听得腿脚发软。贼心里害怕，脚下一滑，扑通从屋顶的窟窿里跌下来，正巧摔到虎背上。老虎未料到房上会有东西掉下来，心想：“坏事，‘漏’捉我来了！”撒腿就往外跑。","贼栽得晕头转向，一摸是个毛乎乎的东西，心想：“坏事，‘漏’等着吃我哩！”拼命抱住虎脖子不敢松手。","老虎驮着贼，贼骑着老虎，跑哇，跑哇，累得老虎筋都快断了，颠得贼骨头架都快散了。跑着跑着，雨大了起来。前边有棵歪脖老树，老虎想：“‘漏’真厉害，像胶一样，粘住我了。到树跟前，得把它蹭下来，好逃命。”","贼也想：“‘漏’真厉害，旋风一样，停都不停，一定是驮到家再吃我。到树跟前，得想法蹿上去，好逃命。”","到了树跟前，老虎把身子一歪，贼顺势一纵，蹿到树上。老虎一边往前跑一边想：“终于甩掉‘漏’了！”贼一边往上爬一边想：“终于甩掉‘漏’了！”","雨越下越大。","老虎被雨一淋，清醒了许多，想想不甘心，还是要回去吃驴，就转身往回走。","贼被雨一淋，清醒了许多，想想不甘心，还是要回去偷驴，就下树准备往回走。","老虎走着走着，走到了歪脖老树跟前。贼又冷又饿，正在下树，看见走来一个黑乎乎的东西，心想：“‘漏’又来了，这下我可活不成了！”他赶忙往树梢上爬，总嫌离地太近，紧爬慢爬，咔嚓一声，树枝断了，一个倒栽葱摔了下来，顺着山坡往下滚。","老虎正走着，见天上掉下个黑乎乎的东西，响声又这么大，心想：“‘漏’又来了，这下我可活不成了！”赶紧逃跑。下过雨的山坡又湿又滑，老虎腿一软，顺着山坡往下滚。","老虎和贼一齐滚下了山坡，浑身沾满泥水，撞在了一块儿。他俩对看了一眼，同时惊恐地大喊：“‘漏’哇———”然后都吓昏了过去。","天快亮了，小胖驴在驴圈里安安稳稳地吃着干草。","老公公和老婆婆从炕头上坐了起来。滴答，滴答——他们抬头看看屋顶——唉，说怕漏，偏就又漏雨了！"]},{"id":239,"grade":"三年级下册","title":"28* 枣核","paragraphs":["古时候，在山脚下的一个村庄里有一户人家。家里只有夫妻两个人，他们成天盼着要个小孩，常常叹着气说：“咱哪怕有个枣核那么大的孩子也好哇！”没想到说了这个话不久，果然生了一个枣核那么大的孩子。夫妻俩欢喜得很，给孩子起了个名叫“枣核”。","一年又一年，枣核一点儿也不见长。爹说：“枣核呀，你真叫我白欢喜了一场！”娘说：“枣核呀，你一点儿不见长，我真为你愁得慌！”枣核说：“爹、娘，你们不用愁，别看我人小，一样能做事情。”","枣核很勤快，天天干活，学了很多的本领。他能扶犁，能赶驴，柴比别人打得多，因为别人上不去的地方他也能上去，他一蹦就能蹦到屋脊那么高。邻居们都夸枣核，枣核的爹娘非常高兴。","枣核不光勤快，也很聪明。有一年大旱，庄稼没收成，县衙门还派衙役向庄稼人要官粮。庄稼人纳不上粮，衙役就把牛、驴都牵走了。","牵走了牛、驴，大伙儿愁得很。枣核说：“大家都不用愁，我有办法！”有的人不相信，说：“我才不信咧，你别小人说大话啦！枣核也不争辩，只是说：不信，你们就等着看。”","到了晚上，枣核跑到县衙门拴牛、驴的院子外面，一蹦蹦进院子里。等衙役们睡着了，枣核解开缰绳，又一蹦蹦到驴耳朵里，“哦喝！哦喝！”大声吆喝着赶驴。衙役们从梦里跳了起来，惊慌地喊着：“有人进来牵驴啦！有人进来牵驴啦！”他们拿着大刀长枪到处搜人。","闹腾了一阵，衙役们什么也没搜着，刚刚躺下，又听到了吆喝声：“哦喝！哦喝！”于是衙役们又都跳了起来，还是没搜到人。可刚躺下，又听到吆喝声。折腾了大半夜，衙役们困得很，有一个衙役头了说：“不用管它，不知是个什么东西在作怪，咱们睡咱们的觉吧。”这时候枣核从驴耳朵里跳了出来，把门打开，赶着牲口回到了村子。","牲口没了，官府岂能善罢甘休。天一亮，县官就带着衙役去捉人。枣核蹦出来说：“牲口是我牵的，你们要怎么样？”","县官叫着说：“快给我绑起来！快给我绑起来！”","衙役们拿出铁链来绑枣核，噗的一声，枣核从铁链缝里蹦了出来，站在那里哈哈大笑。衙役们急得不知怎么办才好，县官说：“把他塞进钱褡里，背到大堂去！”","县官坐了大堂，把惊堂木一拍，说：“给我打！”","衙役们打这面，枣核蹦到那面去，打那面，枣核蹦到这面来，怎么也打不着。县官鼻子都气歪了，脸涨得通红，嚷道：“多加几个人，多拿几条棍，给我狠狠地打！”","枣核这次不往别处蹦，一蹦蹦到了县官的胡子上，抓着胡子荡秋千。县官直喊：“快打！快打！”衙役一棍子打下去，没打着枣核，却打着县官的下巴骨啦，把县官的牙都打了下来。满堂的人慌了起来，跑上前去照顾县官，枣核大摇大摆地走了。"]},{"id":240,"grade":"三年级下册","title":"语文园地","paragraphs":["作者：[唐代] 白居易","人间四月芳菲尽，","山寺桃花始盛开。","长恨春归无觅处，","不知转入此中来。","四月正是平地上百花凋零殆尽的时候，高山古寺中的桃花才刚刚盛放。","我常为春光逝去无处寻觅而惋惜，却不知它已经转到这里来。","白居易（772年－846年），字乐天，号香山居士，又号醉吟先生，祖籍太原，到其曾祖父时迁居下邽，生于河南新郑。是唐代伟大的现实主义诗人，唐代三大诗人之一。白居易与元稹共同倡导新乐府运动，世称“元白”，与刘禹锡并称“刘白”。白居易的诗歌题材广泛，形式多样，语言平易通俗，有“诗魔”和“诗王”之称。官至翰林学士、左赞善大夫。公元846年，白居易在洛阳逝世，葬于香山。有《白氏长庆集》传世，代表诗作有《长恨歌》《卖炭翁》《琵琶行》等。","咳嗽　呕吐　唠叨　嘀咕","谚语　谣言　告诫　辩论","咳 嗽 呕 吐 唠","叨 嘀 谚 谣 诫 辩","顾客噌的一下子跳起来：“这么慢啊！”","椰子扑通一声掉进水里。"]},{"id":241,"grade":"四年级上册","title":"1 观潮","paragraphs":["钱塘江大潮，自古以来被称为天下奇观。","农历八月十八是一年中传统的观潮日。这一天早上，我们来到了海宁市的盐官镇，据说这里是观潮最好的地方。我们随着观潮的人群，登上了海塘大堤。宽阔的钱塘江横卧在眼前。江面很平静，越往东越宽，在雨后的阳光下，笼罩着一层蒙蒙的薄雾。镇海古塔、中山亭和观潮台屹立在江边。远处，几座小山在云雾中若隐若现。江潮还没有来，海塘大堤上早已人山人海。大家昂首东望，等着，盼着。","午后一点左右，从远处传来隆隆的响声，好像闷雷滚动。顿时人声鼎沸，有人告诉我们，潮来了！我们踮着脚往东望去，江面还是风平浪静，看不出有什么变化。过了一会儿，响声越来越大，只见东边水天相接的地方出现了一条白线，人群又沸腾起来。","那条白线很快地向我们移来，逐渐拉长，变粗，横贯江面。再近些，只见白浪翻滚，形成一堵高高的水墙。浪潮越来越近，犹如千万匹白色战马齐头并进，浩浩荡荡地飞奔而来；那声音如同山崩地裂，好像大地都被震得颤动起来。","霎时，潮头奔腾西去，可是余波还在漫天卷地般涌来，江面上依旧风号浪吼。过了好久，钱塘江才恢复了平静。"]},{"id":242,"grade":"四年级上册","title":"2 走月亮","paragraphs":["秋天的夜晚，月亮升起来了，从洱海那边升起来了。","是在洱海里淘洗过吗？月盘是那样明亮，月光是那样柔和，照亮了高高的点苍山，照亮了村头的大青树，也照亮了，照亮了村间的大道和小路……","这时候，阿妈喜欢牵着我，在洒满月光的小路上走着，走着……啊，我和阿妈走月亮！","细细的溪水，流着山草和野花的香味，流着月光。灰白色的鹅卵石布满河床。哟，卵石间有多少可爱的小水塘啊，每个小水塘都抱着一个月亮！哦，阿妈，白天你在溪里洗衣裳，而我，用树叶做小船，运载许多新鲜的花瓣……哦，阿妈，我们到溪边去吧，去看看小水塘，看看水塘里的月亮，看看我采过野花的地方。","啊，我和阿妈走月亮……","村道已经修补过，坑坑洼洼的地方已经填上碎石和新土。就要收庄稼了，收庄稼前，要把道路修一修，补一补，这是村里的风俗。秋虫唱着，夜鸟拍打着翅膀，鱼儿跃出水面，泼剌声里银光一闪……从果园那边飘来果子的甜香，是雪梨，是火把梨，还是紫葡萄？都有。在坡头那片月光下的果园里，这些好吃的果子挂满枝头。沟水汩汩，很满意地响着。是啊，它旁边，是它浇灌过的稻田。哦，阿妈，这不就是我们家的地吗？春天，我们种的油菜开花了，我在田地里找兔草，我把蒲公英吹得飞啊飞……收了油菜，栽上水稻。看，稻谷就要成熟了，稻穗低垂着头，稻田像一块月光镀亮的银毯。哦，阿妈，我们到田埂上去吧，你不是说学校放假了，阿爸就要回来了吗？我们采哪一塘新谷招待阿爸呢？","啊，我和阿妈走月亮……","有时，阿妈给我讲月亮的故事，一个古老的传说；有时，却什么也不讲，只是静静地走着，走着。走过月光闪闪的溪岸，走过石拱桥，走过月影团团的果园，走过庄稼地和菜地……啊，在我仰起脸看阿妈的时候，我突然看见，美丽的月亮牵着那些闪闪烁烁的小星星，好像也在天上走着，走着……","多么奇妙的夜晚啊，我和阿妈走月亮！"]},{"id":243,"grade":"四年级上册","title":"秋晚的江上","paragraphs":["归巢的鸟儿，","尽管是倦了，","还驮着斜阳回去。","双翅一翻，","把斜阳掉在江上；","头白的芦苇，","也妆成一瞬的红颜了。"]},{"id":244,"grade":"四年级上册","title":"花牛歌","paragraphs":["花牛在草地里坐，","压扁了一穗剪秋罗。","花牛在草地里眠，","白云霸占了半个天。","花牛在草地里走，","小尾巴甩得滴溜溜。","花牛在草地里做梦，","太阳偷渡了西山的青峰。"]},{"id":245,"grade":"四年级上册","title":"4* 繁星","paragraphs":["我爱月夜，但我也爱星天。从前在家乡七八月的夜晚，在庭院里纳凉的时候，我最爱看天上密密麻麻的星星。","三年前，在南京我住的地方有一道后门，每晚我打开后门，便看见一个静寂的夜。下面是一片菜园，上面是星群密布的蓝天。星光在我们的肉眼里虽然微小，然而它使我们觉得光明无处不在。","如今在海上，每晚和繁星相对，我把它们认得很熟了。我躺在舱面上，仰望天空。深蓝色的天空里，悬着无数半明半昧的星。船在动，星也在动，它们是这样低，真是摇摇欲坠呢！渐渐地我的眼睛模糊了，我好像看见无数萤火虫在我的周围飞舞。海上的夜是柔和的，是静寂的，是梦幻的。我望着那许多认识的星，我仿佛看见它们在对我眨眼，我仿佛听见它们在小声说话。这时候我忘记了一切。在星的怀抱中我微笑着，我沉睡着。我觉得自己是一个小孩子，现在睡在母亲的怀里了。"]},{"id":246,"grade":"四年级上册","title":"语文园地","paragraphs":["作者：[唐代] 王维","空山不见人，","但闻人语响。","返景入深林，","复照青苔上。","幽静的山谷里看不见人，只听到人说话的声音。","落日的余光映入了深林，又照在幽暗处的青苔上。","王维（701年－761年，一说699年—761年），字摩诘(jié)，号摩诘居士。汉族，河东蒲州（今山西运城）人，祖籍山西祁县，唐朝诗人，有“诗佛”之称。苏轼评价其：“味摩诘之诗，诗中有画；观摩诘之画，画中有诗。”开元九年（721年）中进士，任太乐丞。天宝年间，拜吏部郎中、给事中。唐肃宗乾元年间任尚书右丞，世称“王右丞”。王维是盛唐诗人的代表，今存诗400余首，重要诗作有《相思》《山居秋暝》等。王维精通佛学，受禅宗影响很大。佛教有一部《维摩诘经》，是王维名和字的由来。王维诗书画都很有名，多才多艺，音乐也很精通。与孟浩然合称“王孟”。"]},{"id":247,"grade":"四年级上册","title":"5 一个豆荚里的五粒豆","paragraphs":["有一个豆荚，里面有五粒豌豆。豆荚和豌豆都是绿的，豌豆就以为整个世界都是绿的。豆荚在生长，豌豆也在生长。豌豆按照它们在家庭里的地位，坐成一排。太阳在外边照着，把豆荚晒得暖洋洋的。这里既温暖，又舒适；白天明亮，夜间黑暗。豌豆坐在那儿越长越大，它们想，我们得做点儿事情啊。","“难道我们永远就在这儿坐下去吗？”它们中的一个问，“老这样坐下去，我恐怕会变得僵硬起来。我觉得外面似乎发生了一些事情——我有这种预感！”","许多天过去了。豆荚变黄了，这几粒豌豆也变黄了。“整个世界都变黄啦！”它们说。","忽然，它们觉得豆荚震动了一下。豆荚被摘下，跟许多别的丰满的豆荚在一起，溜到一个衣服口袋里去了。","“我们不久就要被打开了！”豌豆们说。于是它们就等待这件事情的发生。","“我倒想要知道，我们之中谁会走得最远！”最小的一粒豌豆说。","“是的，事情马上就要揭晓了。”最大的那粒豌豆说。","啪！豆荚裂开来了。那五粒豌豆全都躺在一个孩子的手中。这个孩子紧紧地捏着它们，说可以当作玩具枪的子弹用。他马上把第一粒豌豆装进去，把它射了出去。","“现在我要飞到广阔的世界里去了！如果你能捉住我，就请来吧！”第一粒豌豆说完就飞走了。","“我，”第二粒说，“我将直接飞进太阳里去。这才像一粒豌豆呢，而且与我的身份非常相称！”于是，它也飞走了。","“我们到了哪儿，就在哪儿住下来。”接下来的两粒说，“不过，我们还得向前滚。”在被装进玩具枪之前，它们从小孩的手中滑落到地上，打起滚来。但这两粒豌豆最终还是被装进玩具枪里去了。它们说：“我们才会飞得最远呢！”","“该怎么样就怎么样吧！”最后的那一粒说。它被射到空中，落到顶楼窗子下面的一块旧板子上，正好钻进一个长满了青苔的裂缝里。青苔把它裹起来，它躺在那儿真可以说成了一个囚犯。","在这个小小的顶楼里住着一个穷苦的女人。她很强壮，很勤劳，每天擦火炉，劈木柴，干很多苦活，不过还是很穷。她有一个女儿，身体非常虚弱，躺在床上一整年了。小女孩安静地、耐心地整天在家里躺着，而她的母亲每天到外面去挣点儿生活费。","春天的一个早晨，当母亲准备出去工作的时候，阳光温和地从那个小窗子射进来，一直射到地上。","小女孩望着最低的那块窗玻璃说：“有个绿东西从窗玻璃旁边探出头来，它是什么呢？”","母亲向窗边走去，把窗户打开一半。“啊！”她说，“我的天，原来是一粒小豌豆在这里生了根，还长出小叶子来了。它是怎么钻进这个缝隙里去的？你现在有一个小花园了！”","母亲把小女孩的床搬得更靠近窗子，好让她看到这粒正在生长着的豌豆。","“妈妈，我觉得我好了一些！”晚上，这个小女孩说，“太阳今天在我身上照得怪暖和的。这粒豌豆长得好极了，我也会好起来的。我能爬起来，走到温暖的太阳光中去。”","“但愿如此。”母亲虽然不太相信，但还是仔细地用一根小棍子把这植物支起来，好使它不至于被风吹断，因为它使女儿对生命产生了希望。她从窗台上牵了一根绳子到窗框的上端去，使这棵豌豆苗可以顺着它向上生长。","它的确在向上长——人们每天都可以看到它在生长。","“真的，它现在要开花了！”这个母亲慢慢开始相信，她的孩子会好起来。她记起最近这孩子讲话时，要比以前愉快得多，而且最近几天她也能自己爬起来，坐在床上，用兴奋的眼光望着这一粒豌豆所形成的小花园。一星期以后，小女孩第一次能够坐一整个钟头。她快乐地坐在温暖的太阳光里。窗子打开了，她面前是一朵盛开的、紫色的豌豆花。小女孩低下头来，轻轻地吻了一下它柔嫩的叶子。这一天简直像一个节日。","其余的几粒豌豆呢？曾经想飞到广阔世界里去的那一粒，它落到了屋顶的水笕里，被一只鸽子吃掉了。那两粒在地上打滚的豌豆也没有走多远，也被鸽子吃掉了。它们还算有些实际的用途。那本来想飞进太阳里去的豌豆，却落到了水沟里，在脏水里躺了好几个星期，而且涨得大大的。","“我又胖又美！”这粒豌豆说，“我胖得要爆裂开来了。我想任何豌豆从来不曾、也永远不会达到这种地步的。我是五粒豌豆中最了不起的一粒。”","此刻，顶楼窗子旁那个小女孩——她的脸上洋溢着健康的光彩，她的眼睛发着亮光——正注视着豌豆花，快乐地微笑着，心里充满了感激。"]},{"id":248,"grade":"四年级上册","title":"6 夜间飞行的秘密","paragraphs":["清朗的夜空出现两个亮点，越来越近，才看清楚是一红一绿的两盏灯。接着传来了隆隆声，这是一架飞机在夜航。","在漆黑的夜里，飞机是怎么做到安全飞行的呢？要想了解其中的秘密，我们可以从蝙蝠说起。","蝙蝠能在夜里飞行，还能捕捉飞蛾和蚊子；而且无论怎么飞，从来没见过它跟什么东西相撞，即使一根极细的电线，它也能灵巧的避开。难道它的眼睛特别敏锐，能在漆黑的夜里看清楚所有的东西吗？","为了弄清楚这个问题，两百多年前，科学家做了一次实验。他们在一间屋子里横七竖八地拉了许多绳子，绳子上系了许多铃铛。然后把蝙蝠的眼睛蒙上，让它在屋子里飞。蝙蝠飞了几个钟头，铃铛一个也没响，那么多的绳子，它一根也没碰着。","科学家又做了两次实验：一次把蝙蝠的耳朵塞上，一次把蝙蝠的嘴封住，让它在屋子里飞。蝙蝠就像没头苍蝇似的到处乱撞，挂在绳子上的铃铛响个不停。","三次实验的结果证明，蝙蝠夜里飞行，靠的不是眼睛，而是靠嘴和耳朵配合起来探路的。","后来，科学家经过反复研究，终于揭开了蝙蝠能在夜里飞行的秘密。它一边飞，一边从嘴里发出超声波。而这种声音，人的耳朵听不见超声波，蝙蝠的耳朵却能听见。超声波向前传播时，遇到障碍物就反射回来，传到蝙蝠的耳朵里，蝙蝠就立刻改变飞行的方向。","知道蝙蝠在夜里如何飞行，你猜到飞机夜间飞行的秘密了吗？现代飞机上安装了雷达，雷达的工作原理与蝙蝠探路类似。雷达通过天线发出无线电波，无线电波遇到障碍物就反射回来，被雷达接收到，显示在荧光屏上。从雷达的荧光屏上，驾驶员能够清楚地看到前方有没有障碍物，所以飞机飞行就更安全了。"]},{"id":249,"grade":"四年级上册","title":"7 呼风唤雨的世纪","paragraphs":["20世纪是一个呼风唤雨的世纪。","是谁来呼风唤雨呢？当然是人类。靠什么呼风唤雨呢？靠的是现代科学技术。在20世纪100年的时间里，人类利用现代科学技术获得了那么多奇迹般的、出乎意料的发现和发明。正是这些发现和发明，使人类的生活大大改观，其改变的程度超过了人类历史上百万年的总和。","人类在上百万年的历史中一直很依赖自然，生活在一个慢吞吞、静悄悄、一到夜里就黑暗无光的世界。那时没有电灯，没有电视，没有收音机，也没有汽车。人们只能在神话中用“千里眼”“顺风耳”和腾云驾雾的神仙，来寄托自己的美好愿望。我们的祖先大概谁也没有料到，他们的那么多幻想在现代纷纷变成了现实。20世纪的成就，真可以用“忽如一夜春风来，千树万树梨花开”来形容。","20世纪，人类登上月球，潜入深海，洞察百亿光年外的天体，探索原子核世界的奥秘；20世纪，电视、程控电话、因特网以及民航飞机、高速火车、远洋船舶等，日益把人类居住的星球变成联系紧密的“地球村”。人类生活的舒适、方便，是连过去的王公贵族也不敢想的。科学在改变着人类的精神文化生活，也在改变着人类的物质生活。","1923年，英国数学家、哲学家伯特兰·罗素说：“归根到底，是科学使得我们这个时代不同于以往的任何时代。”现在，这句话依然适用。回顾20世纪的百年历程，科学的确创造了一个又一个神话，为人类创造了比以往任何时代都要美好的生活。在新的世纪里，现代科学技术必将继续创造一个个奇迹，不断改善我们的生活。"]},{"id":250,"grade":"四年级上册","title":"8* 蝴蝶的家","paragraphs":["我常想，下大雨的时候，青鸟、麻雀这些鸟都要躲避起来，蝴蝶怎么办呢？天是那样低沉，云是那样黑，雷、电、雨、风，吼叫着，震撼着，雨点密集地喧嚷着，风将银色的雨幕斜挂起来，世界几乎都被冲洗遍了，就连树林里也黑压压的、水淋淋的，到处都是湿的。这不是难为蝴蝶吗？","我一想起来就为蝴蝶着急，这样的天气它们能躲在哪里呢？它们的身体是那样轻盈，载不动一个水点；它们身上的彩粉是那样斑斓，一点儿水都不能沾；它们是那样柔弱，比一片树叶还无力，怎么禁得起这猛烈的风雨呢？想到这里，我简直没法再想下去了，心里是那样着急。","但是，一位小朋友非常确定地说：“它们和我们一样，肯定有家。下雨的时候，它们就会急忙飞回家里去哩！”不过它们的家在哪里呢？人们的屋宇里从没有见过有蝴蝶来避雨。麦田里呢？也不能避雨。树林里呢？到处是水珠滚坠。园里的花朵是它们的家吗？花朵自己已经被雨点打得抖个不停了，怎能容它们藏身呢？就连老树干的底面，也是顺下水来，湿漉漉的。蝴蝶的家到底在哪里呢？我真为蝴蝶着急了。","它们的家会不会是在桥下面呢？这也未可知，但是有一点可以确定：这里从没见过有蝴蝶落到石头上的呀！那它们会不会是藏在树叶下面？这倒有些说得过去，但我也从没见过蝴蝶在树叶下面避雨呀，而且树叶也经常被风吹得翻转不定，被雨冲刷得透湿，也不像是蝴蝶的家呀！我真为蝴蝶着急了。","一个女孩对我说：“雨后，蝴蝶就会重新出来，在阳光里飞。它们是那么高兴，那么鲜艳。我想，它们一定是藏在一个秘密的家里。它们的家一定美丽而香甜，不像家雀儿似的，一下雨就飞到人们的屋檐下避雨。一定是这样的。”","她的话说得倒是不错，但我却从来没有见到过下雨时蝴蝶藏身的地方。谁要是能说给我听，我就不着急了。"]},{"id":251,"grade":"四年级上册","title":"语文园地","paragraphs":["注—驻　抄—钞　赔—培","堵—赌　煤—媒　芬—氛","账贺　　樟杠　　狡猾","驻 钞 培 赌 媒 氛","账 贺 樟 杠 狡 猾","好问则裕，自用则小。——《尚书》","博学之，审问之，慎思之，明辨之，笃行之。——《礼记》","智能之士，不学不成，不问不知。——王充","人非生而知之者，孰能无惑？——韩愈"]},{"id":252,"grade":"四年级上册","title":"暮江吟","paragraphs":["作者：[唐代] 白居易","一道残阳铺水中，","半江瑟瑟半江红。","可怜九月初三夜，","露似真珠月似弓。","残阳倒映在江面上，霞光洒下，波光粼粼；江水一半呈现出深深的碧色，一半呈现出红色。","最可爱的是那九月初三之夜，露水像珍珠一样晶莹光亮，朗朗新月形如弯弓。","白居易（772年－846年），字乐天，号香山居士，又号醉吟先生，祖籍太原，到其曾祖父时迁居下邽，生于河南新郑。是唐代伟大的现实主义诗人，唐代三大诗人之一。白居易与元稹共同倡导新乐府运动，世称“元白”，与刘禹锡并称“刘白”。白居易的诗歌题材广泛，形式多样，语言平易通俗，有“诗魔”和“诗王”之称。官至翰林学士、左赞善大夫。公元846年，白居易在洛阳逝世，葬于香山。有《白氏长庆集》传世，代表诗作有《长恨歌》《卖炭翁》《琵琶行》等。"]},{"id":253,"grade":"四年级上册","title":"题西林壁","paragraphs":["作者：[宋代] 苏轼","横看成岭侧成峰，","远近高低各不同。","不识庐山真面目，","只缘身在此山中。","从正面、侧面看庐山山岭连绵起伏、山峰耸立，从远处、近处、高处、低处看都呈现不同的样子。","之所以辨不清庐山真正的面目，是因为我身处在庐山之中。","苏轼，（1037年1月8日-1101年8月24日）字子瞻、和仲，号铁冠道人、东坡居士，世称苏东坡、苏仙，汉族，眉州眉山（四川省眉山市）人，祖籍河北栾城，北宋著名文学家、书法家、画家，历史治水名人。苏轼是北宋中期文坛领袖，在诗、词、散文、书、画等方面取得很高成就。文纵横恣肆；诗题材广阔，清新豪健，善用夸张比喻，独具风格，与黄庭坚并称“苏黄”；词开豪放一派，与辛弃疾同是豪放派代表，并称“苏辛”；散文著述宏富，豪放自如，与欧阳修并称“欧苏”，为“唐宋八大家”之一。苏轼善书，“宋四家”之一；擅长文人画，尤擅墨竹、怪石、枯木等。与韩愈、柳宗元和欧阳修合称“千古文章四大家”。作品有《东坡七集》《东坡易传》《东坡乐府》《潇湘竹石图卷》《古木怪石图卷》等。"]},{"id":254,"grade":"四年级上册","title":"雪梅","paragraphs":["作者：[宋代] 卢钺","梅雪争春未肯降，","骚人阁笔费评章。","梅须逊雪三分白，","雪却输梅一段香。","梅花和雪花都认为各自占尽了春色，谁也不肯服输。难以评议梅与雪的高下，只得搁笔好好思量。","说句公道话，梅花须逊让雪花三分晶莹洁白，雪花却输给梅花一段清香。","卢钺，别名卢梅坡，宋朝末年人，具体生卒年、生平事迹不详，存世诗作也不多，与刘过是朋友，以两首《雪梅》流芳百世。"]},{"id":255,"grade":"四年级上册","title":"10 爬山虎的脚","paragraphs":["学校操场北边墙上满是爬山虎。我家也有爬山虎，从小院的西墙爬上去，在房顶上占了一大片地方。","爬山虎刚长出来的叶子是嫩红的，不几天叶子长大，就变成嫩绿的。爬山虎的嫩叶，不大引人注意，引人注意的是长大了的叶子。那些叶子绿得那么新鲜，看着非常舒服。叶尖一顺儿朝下，在墙上铺得那么均匀，没有重叠起来的，也不留一点儿空隙。一阵风拂过，一墙的叶子就漾起波纹，好看得很。","以前，我只知道这种植物叫爬山虎，可不知道它怎么能爬。今年，我注意了，原来爬山虎是有脚的。爬山虎的脚长在茎上。茎上长叶柄的地方，反面伸出枝状的六七根细丝，这些细丝很像蜗牛的触角。细丝跟新叶子一样，也是嫩红的。这就是爬山虎的脚。","爬山虎的脚触着墙的时候，六七根细丝的头上就变成小圆片，巴住墙。细丝原先是直的，现在弯曲了，把爬山虎的嫩茎拉一把，使它紧贴在墙上。爬山虎就是这样一脚一脚地往上爬。如果你仔细看那些细小的脚，你会想起图画上蛟龙的爪子。","爬山虎的脚要是没触着墙，不几天就萎了，后来连痕迹也没有了。触着墙的，细丝和小圆片逐渐变成灰色。不要瞧不起那些灰色的脚，那些脚巴在墙上相当牢固，要是你的手指不费一点儿劲，休想拉下爬山虎的一根茎。"]},{"id":256,"grade":"四年级上册","title":"11 蟋蟀的住宅","paragraphs":["居住在草地上的蟋蟀，差不多和蝉一样有名。它的出名不光由于它的唱歌，还由于它的住宅。","别的昆虫大多在临时的隐蔽所藏身。它们的隐蔽所得来不费功夫，弃去毫不可惜。蟋蟀和它们不同，不肯随遇而安。它常常慎重地选择住址，一定要排水优良，并且有温和的阳光。它不利用现成的洞穴。它的舒服的住宅是自己一点儿一点儿挖掘的，从大厅一直到卧室。","蟋蟀怎么会有建筑住宅的才能呢？它有特别好的工具吗？没有。蟋蟀并不是挖掘技术的专家，它的工具是那样柔弱，所以人们对它的劳动成果感到惊奇。","在儿童时代，我到草地上去捉蟋蟀，把它们养在笼子里，用菜叶喂它们。现在为了研究蟋蟀，我又搜索起它们的巢穴来。","在朝着阳光的斜坡上，青草丛中隐藏着一条倾斜的隧道，即使有骤雨，这里也立刻就会干的。隧道顺着地势弯弯曲曲，最多九寸深，一指宽，这便是蟋蟀的住宅。出口的地方总有一丛草半掩着，就像一座门。蟋蟀出来吃周围的嫩草，决不去碰这一丛草。那微斜的门口，经过仔细耙扫，收拾得很平坦。这就是蟋蟀的平台。当四周很安静的时候，蟋蟀就在这平台上弹琴。","屋子的内部没什么布置，但是墙壁很光滑。主人有的是时间，把粗糙的地方修理平整。大体上讲，住所是很简朴的，清洁、干燥，很卫生。假使我们想到蟋蟀用来挖掘的工具是那样简单，这座住宅真可以算是伟大的工程了。","蟋蟀盖房子大多是在十月，秋天初寒的时候。它用前足扒土，还用钳子似的大颚搬掉较大的土块。它用强有力的后足踏地。后腿上有两排锯，用它们将泥土推到后面，倾斜地铺开。","工作做得很快。蟋蟀钻到土底下干活，如果感到疲劳，它就在未完工的家门口休息一会儿，头朝着外面，触须轻微地摆动。不大一会儿，它又进去继续工作。我一连看了两个钟头，看得有些不耐烦了。","住宅的重要部分快完成了。洞已经挖了有两寸深，够宽敞的了。余下的是长时间的整修，今天做一点儿，明天做一点儿。这个洞可以随天气的变冷和它身体的增长而加深加阔。即使在冬天，只要天气温和，太阳晒到它住宅的门口，还可以看见蟋蟀从里面不断地抛出泥土来。"]},{"id":257,"grade":"四年级上册","title":"语文园地","paragraphs":["立了秋，把扇丢。","二八月，乱穿衣。","夏雨少，秋霜早。","八月里来雁门开，雁儿脚上带霜来。","一场秋雨一场寒，十场秋雨要穿棉。","八月暖，九月温，十月还有小阳春。"]},{"id":258,"grade":"四年级上册","title":"12 盘古开天地","paragraphs":["很久很久以前，天和地还没有分开，宇宙混沌一片，像个大鸡蛋。有个叫盘古的巨人，在混沌之中睡了一万八千年。","有一天，盘古醒来了，睁眼一看，周围黑乎乎一片，什么也看不见。他一使劲翻身坐了起来，只听咔嚓一声，“大鸡蛋”裂开了一条缝，一丝微光透了进来。巨人见身边有一把斧头，就拿起斧头，对着眼前的黑暗劈过去，只听见一声巨响，“大鸡蛋”碎了。轻而清的东西，缓缓上升，变成了天；重而浊的东西，慢慢下降，变成了地。","天和地分开后，盘古怕它们还会合在一起，就头顶天，脚踏地，站在天地当中，随着它们的变化而变化。天每天升高一丈，地每天加厚一丈，盘古的身体也跟着长高。","这样过了一万八千年，天升得高极了，地变得厚极了。盘古这个巍峨的巨人就像一根柱子，撑在天和地之间，不让它们重新合拢。又不知过了多少年，天和地终于成形了，盘古也精疲力竭，累得倒下了。","盘古倒下以后，他的身体发生了巨大的变化。他呼出的气息变成了四季的风和飘动的云；他发出的声音化作了隆隆的雷声；他的左眼变成了太阳，照耀大地，他的右眼变成了月亮，给夜晚带来光明；他的四肢和躯干变成了大地的四极和五方的名山；他的血液变成了奔流不息的江河；他的汗毛变成了茂盛的花草树木；他的汗水变成了滋润万物的雨露……","伟大的巨人盘古，用他的整个身体创造了美丽的世界。"]},{"id":259,"grade":"四年级上册","title":"13 精卫填海","paragraphs":["炎帝之少女，名曰女娃。女娃游于东海，溺而不返，故为精卫，常衔西山之木石，以堙于东海。","炎帝的小女儿，名叫女娃。有一次，女娃去东海游玩，溺水身亡，再也没有回来，因此化为精卫鸟。经常口衔西山上的树枝和石块，用来填塞东海。"]},{"id":260,"grade":"四年级上册","title":"14 普罗米修斯","paragraphs":["很久很久以前，地面上没有火，人们只好吃生的东西，在无边的黑暗中度过一个又一个长夜。就在这时候，有一位名叫普罗米修斯的天神来到了人间，看到人类没有火的悲惨情景，决心冒着生命危险，到天上去“盗”取火种。","有一天，当太阳车从天空驰过的时候，普罗米修斯跑到太阳车那里，从喷射着火焰的车轮上，拿了一颗火星，带到人间。自从有了火，人类就开始用它烧熟食物，驱寒取暖，并用火来驱赶危害人类安全的猛兽……","得知普罗米修斯从天上取走火种的消息，众神的领袖宙斯气急败坏，决定给普罗米修斯以最严厉的惩罚，吩咐火神立即执行。","火神赫淮斯托斯很敬佩普罗米修斯，悄悄对他说：“只要你向宙斯承认错误，归还火种，我一定请求他饶恕你。”","普罗米修斯摇摇头，坚定地回答：“为人类造福，有什么错？我可以忍受各种痛苦，但决不会承认错误，更不会归还火种！”","火神不敢违抗宙斯的命令，只好把普罗米修斯押到高加索山上。普罗米修斯的双手和双脚戴着铁环，被死死地锁在高高的悬崖上。他既不能动弹，也不能睡觉，日夜遭受着风吹雨淋的痛苦。尽管如此，普罗米修斯就是不向宙斯屈服。","狠心的宙斯又派了一只凶恶的鹫鹰，每天站在普罗米修斯的双膝上，用它尖利的嘴巴，啄食他的肝脏。白天，他的肝脏被吃光了，可是一到晚上，肝脏又重新长了出来。这样，普罗米修斯所承受的痛苦，永远没有了尽头。","许多年来，普罗米修斯一直被锁在那个可怕的悬崖上。","有一天，著名的大力士赫拉克勒斯经过高加索山。他看到普罗米修斯被锁在悬崖上，心中愤愤不平，便挽弓搭箭，射死了那只鹫鹰，又用石头砸碎了锁链。普罗米修斯——这位敢于从天上“盗”取火种的英雄，终于获得了自由。"]},{"id":261,"grade":"四年级上册","title":"15* 女娲补天","paragraphs":["自从女娲创造了人类，大地上到处欢声笑语，人们过着快乐幸福的生活。","不料有一年，天地忽然发生了一场大变动。天上露出一个大窟窿，地上也裂开了一道道黑黝黝的深沟，洪水从地下喷涌而出，各种野兽也从山林里跑出来残害人类。人们惊慌失措，四处奔逃，整个世界陷入了一片混乱和恐怖之中。","女娲看到这情景，难过极了，决心把天和地修补起来，让人类重新过上幸福的生活。","这可是一项巨大而又艰难的工作。女娲先从各地拣来赤、青、黄、白、黑五种颜色的石头，燃起神火熔炼。随着神火渐渐熄灭，五种颜色的石头被炼成了黏稠的石浆。女娲用这些石浆把天上的大窟窿修补好。从此，天上便有了五色的云霞。女娲担心补好的天再塌下来，于是又杀了一只大乌龟，斩下它的四条腿，竖立在大地的四方，把人类头顶上的天空撑起来，这样天就再没有了坍塌的危险。接着，她奋勇杀死了在中原一带作恶的黑龙，其他野兽见此情景，吓得纷纷逃回山林，再不敢到处流窜残害人类了。最后，女娲把芦苇烧成灰，撒到水中，芦灰越积越厚，把喷涌洪水的地缝也堵住了。","天和地终于恢复了平静，人类获得了新生。人们世世代代怀念着女娲，传颂着她的伟大功绩。"]},{"id":262,"grade":"四年级上册","title":"语文园地","paragraphs":["花圃　花卉　花蕾　花蕊","玫瑰　茉莉　牡丹　海棠","圃 卉 蕾 蕊 玫","茉 莉 牡 丹 棠","作者：[唐代] 李商隐","云母屏风烛影深，","长河渐落晓星沉。","嫦娥应悔偷灵药，","碧海青天夜夜心。","云母屏风上烛影暗淡，银河渐渐斜落晨星也隐没低沉。","嫦娥应该后悔偷取了长生不老之药，如今空对碧海青天夜夜孤寂。","李商隐（约813年-约858年），字义山，号玉溪（谿）生、樊南生，唐代著名诗人，祖籍河内（今河南省焦作市）沁阳，出生于郑州荥阳。他擅长诗歌写作，骈文文学价值也很高，是晚唐最出色的诗人之一，和杜牧合称“小李杜”，与温庭筠合称为“温李”，因诗文与同时期的段成式、温庭筠风格相近，且三人都在家族里排行第十六，故并称为“三十六体”。其诗构思新奇，风格秾丽，尤其是一些爱情诗和无题诗写得缠绵悱恻，优美动人，广为传诵。但部分诗歌过于隐晦迷离，难于索解，至有“诗家总爱西昆好，独恨无人作郑笺”之说。因处于牛李党争的夹缝之中，一生很不得志。死后葬于家乡沁阳（今河南焦作市沁阳与博爱县交界之处）。作品收录为《李义山诗集》。"]},{"id":263,"grade":"四年级上册","title":"16 麻雀","paragraphs":["我打猎回来，走在林荫路上。猎狗跑在我的前面。","突然，我的猎狗放慢脚步，悄悄地向前走，好像嗅到了前面有什么野物。","风猛烈地摇撼着路旁的白桦树。我顺着林荫路望去，看见一只小麻雀呆呆地站在地上，无可奈何地拍打着小翅膀。它嘴角嫩黄，头上长着绒毛，分明是刚出生不久，从巢里掉下来的。","猎狗慢慢地走近小麻雀，嗅了嗅，张开大嘴，露出锋利的牙齿。突然，一只老麻雀从一棵树上飞下来，像一块石头似的落在猎狗面前。它挓挲起全身的羽毛，绝望地尖叫着。","老麻雀用自己的身躯掩护着小麻雀，想拯救自己的幼儿。它准备着一场搏斗，可是因为紧张，它浑身发抖，发出嘶哑的声音。在它看来，猎狗是个多么庞大的怪物啊！可是它不能安然地站在高高的没有危险的树枝上，一种强大的力量使它飞了下来。","猎狗愣住了，它可能没料到老麻雀会有这么大的勇气，慢慢地，慢慢地向后退。","我急忙唤回我的猎狗，带着它走开了。"]},{"id":264,"grade":"四年级上册","title":"17 爬天都峰","paragraphs":["假日里，爸爸带我去黄山，爬天都峰。","我站在天都峰脚下抬头望：啊，峰顶这么高，在云彩上面哩！我爬得上去吗？再看看笔陡的石级，石级边上的铁链，似乎是从天上挂下来的，真叫人发颤！","忽然听到背后有人叫我：“小朋友，你也来爬天都峰？”","我回头一看，是一位白发苍苍的老爷爷，年纪比我爷爷还大哩！我点点头，仰起脸，问：“老爷爷，您也来爬天都峰？”","老爷爷也点点头，说：“对，咱们一起爬吧！”","我奋力向峰顶爬去，一会儿攀着铁链上，一会儿手脚并用向上爬，像小猴子一样……","爬呀爬，我和老爷爷，还有爸爸，终于都爬上了天都峰顶。","在鲫鱼背前，爸爸给我和老爷爷照了一张相，留作纪念。老爷爷拉拉我的小辫子，笑呵呵地说：“谢谢你啦，小朋友。要不是你的勇气鼓舞我，我还下不了决心哩！现在居然爬上来了！”","“不，老爷爷，我是看您也要爬天都峰，才有勇气向上爬的！我应该谢谢您！”","爸爸听了，笑着说：“你们这一老一小真有意思，都会从别人身上汲取力量！”"]},{"id":265,"grade":"四年级上册","title":"习作例文","paragraphs":["我家院子里有一棵大杏树。每年到了麦收时节，树上就结满了金黄的杏。从我家门前路过的人，总要望望那棵杏树，羡慕地说道：“嗬，好杏啊！”","杏树是奶奶亲手栽的，听奶奶说栽杏树的时候还没有我呢。有一回，我依偎在奶奶的怀里问她：“奶奶，咱们家树上的杏有多少个？”","“就像天上的星星一样，多得数不清。要不，你数数看。”","我仰着头数起来，“一、二、三……“数啊，数啊，数到后来就糊涂了。奶奶忍不住笑了。我不知道奶奶是笑我傻，还是笑杏多。","这一年，杏又熟了。有一天，奶奶正在做饭，忽然听见有孩子在哭。奶奶急忙走出去，原来是邻居家的小淘淘嘴馋摘杏，不小心从树上摔下来了。和他一起来的小伙伴见了奶奶都低下了头，不敢吱声。我没好气地说：“看我奶奶怎么收拾你们！”","奶奶走过去扶起小淘淘，给他揉揉腿，看他没伤着，就站起身往屋里走，又回过头来对孩子们说：“你们先别走。”","过了一会儿，奶奶拿了一根长竹竿从屋里出来了。她走到树下，挑熟了的杏往下打。她脚底下站不大稳，身子颤颤巍巍的。","杏一个接一个落在地上。我连忙弯腰去捡，不一会儿就捡了一围兜。奶奶把小淘淘和他的伙伴都叫了过来，一人分给五六个，剩下的几个给了我。看他们吃得那样香甜，奶奶嘴角露出微笑，转过头对我说：“要记住，杏熟了，让乡亲们都尝个鲜，果子大家吃，才真的香甜呢！”","听了奶奶的话，我点了点头。从那以后，我每年都照着奶奶的嘱咐，把熟透了的金黄金黄的杏分给小伙伴们吃，也送给邻居叔叔婶子们尝鲜。","每当我看见珍藏在抽屉里的那只精致的小木船，就想起陈明来。","上小学一年级的时候，陈明和我是同班同学。我们两家离得很近。每天我们一起上学，回家，一起温习功课。我们成了形影不离的好朋友，一直到四年级。","有一天，发生了一件不愉快的事。我们俩温习完功课，把自己在舰模小组做的小木船拿出来玩。我见他那只做得很精致，就拿在手上，翻过来掉过去地看，总舍不得放下。不料我一失手，啪的一声，小木船掉在地上，摔坏了。他一看，急了，哭着要我赔。我上前分辩说：“我不是故意的。”他生气地说：“谁叫你不小心，非赔不可！”","还用力推了我一下。我往后一退，正好一脚踩在小木船上，把它踩碎了。这一下，陈明更生气了。他拿起我的小木船，使劲摔在地上，用脚踩了两下，一把抓起书包，头也不回地走了。看着被他踩坏的小木船，我也气得说不出话来。我们的友谊从此破裂了。","转眼几个月过去了。有一天放学回家，我走在前面，陈明走在后面。我偷偷地回头看了他一眼，他右手插在裤兜里，裤兜胀得鼓鼓的，不知手里攥着什么。忽然，他几步追上了我，从裤兜里掏出一只精致的小木船来。我惊讶地望着他。他满脸通红，激动地说：“那次是我不好，不该弄坏你的船。明天我家就要搬走了，我做了这只船送给你，留个纪念吧！”说着，他把小木船塞到我手里。想想那天发生的事，本来是我的错，望着他那双热情的眼睛，我一句话也说不出来，只是紧紧地握住他的手。","陈明跟着爸爸妈妈搬到外地去了。那天以后，我们俩再也没有见过面。我把他送给我的小木船珍藏在抽屉里。一看见这只精致的小木船，我就好像看见陈明站在我的面前。"]},{"id":266,"grade":"四年级上册","title":"18 牛和鹅","paragraphs":["大家都说：牛的眼睛看人，觉得人比牛大，所以牛是怕人的；鹅的眼睛看人，觉得人比鹅小，所以鹅不怕人。","我们都很相信这句话。","所以我们看到牛，一点儿不害怕，敢用手拍它的背，摸它的肚子，甚至敢用树枝去触它的屁股呢！可是牛像是无所谓似的，只是眨眨眼，把尾巴甩几甩。有的孩子还敢扳牛角，叫它跪下来，然后骑到牛背上去。我那时虽然不敢这样，可是用拳头捶捶牛背还是敢的。","我们看到鹅，那就完全两样了：总是远远地站在安全的地方，才敢看它。要是在路上碰到鹅，就得绕个大圈子才敢走过去。","有一次，我们放学回家，走过池塘边，看见有四只大白鹅在靠近岸边的水里游。我们马上都不说话了，贴着墙壁，悄悄地走过去。我的心里很害怕，怕它们看见了会追过来。这时，有一个顽皮的孩子故意要引它们来，就吁哩哩哩地叫了一声。鹅听见了，就竖起头来，侧着眼睛看了看，竟爬到岸上，一摇一摆地、神气地朝我们走过来；还伸长脖子，嘎嘎地叫着，扑打着大翅膀，好像在它们眼里根本没有我们这些人似的。","孩子们惊呼起来，急急逃跑，鹅追得更快了。我吓得脚也软了，更跑不快。这时，带头的那只老公鹅就啪嗒啪嗒地跑了过来，嘎嘎，它赶上了我，嘎嘎，它张开嘴，一口就咬住了我当胸的衣襟，拉住我不放。在忙乱中，我的书包掉了，鞋子也弄脱了。我想，它一定要把我咬死了。我就又哭又叫，可是叫些什么，当时自己也不知道，大概是这样叫吧：“鹅要吃我了！鹅要咬死我了！”","也许是我的哭叫更惹怒了这只老公鹅。它用全身的力量来拖我，啄我，扇动翅膀来扑打我。我几乎被它拖倒了——因为当时我还很小，只不过跟它一样高呢！其他几只鹅在后面嘎嘎大叫着助威。","就在这时候，池塘里划来了一只小船，捉鱼的金奎叔从船里跳上岸，飞快地走了过来（这些，我都是后来才知道的，当时是完全昏乱了）。金奎叔是个结实的汉子，他的胳膊比我的腿还粗。他一把握住了鹅的长脖子。鹅用脚爪划他，用嘴啄他。可是金奎叔的力气是那么大，他轻轻地把鹅提了起来，然后就像摔一个酒瓶似的，呼的一下，把这只老公鹅摔到了半空中。它张开翅膀，啪啪啪地落到了池塘中。这一下，其余三只鹅也怕了，纷纷张开翅膀，跳进池塘里，向远处游去。","这一摔是那么痛快，远处的孩子们全笑了起来，我也挂着泪笑了。一切的恐怖，全消失了。因为在金奎叔的手里，鹅是那么弱，那么可笑，它，不过跟一个酒瓶子一样罢了！","金奎叔帮我穿上鞋，拾起书包，用大手摸摸我的头，说：“鹅有什么可怕的！看把你吓成这样。”","我说：“因为鹅把我们看得比它小哇！”","金奎叔说：“让它这样看好了！可是，它要是凭这点来欺负人，那咱们可不答应，就得掐住它的脖子，把它摔到池塘里去。记着，霖哥儿，下次可别怕它们。”","我记住金奎叔的话，从此不再怕鹅了。有什么可怕的！它虽然把我们看得比它小，可我们实在比它强啊！怕它干吗？果然，我不怕它，它也不敢咬我，碰到了，只是嘎嘎叫几声，扇几下翅膀，就摇摇摆摆走开了。","看到牛，我也不再无缘无故欺负它了，我觉得虽然它把我们看得比它大，可我们平白地去欺负它干吗？","直到现在，我还记着金奎叔的话。"]},{"id":267,"grade":"四年级上册","title":"19 一只窝囊的大老虎","paragraphs":["我念的那所小学每星期六下午全校开周会，会上总有文艺表演。由十二个班级轮流演出，每个学期一个班级至多轮到两次。","我一直没在台上露过面，看着同班的小朋友在台上又唱又跳，边说边比画，我真个羡慕得要死。我多想在台上露露脸，尝尝大家都看着我，给我鼓掌是什么味道。","有一回又逢到我们班表演，班主任在分派角色的时候，我殷切期待的目光可能引起了她的注意。分派到最后，她看了我半晌才下决心说：“就这样吧，你扮老虎。”","这一回我们班演的是《兄妹历险记》，中间有这么一段情节：兄妹俩在森林里迷了路，碰上一只大老虎。我就扮这只大老虎，用不着说话。","于是开始排练。我套上老虎皮，那是一件画着黑道道的黄布连衣裤，背后拖着一条硬邦邦的尾巴，穿上了手脚都不露。还得套上个纸糊的老虎头，那老虎头也是黄底子上画着黑道道，额头正中还有个“王”字。","这倒好，脸还是露不成。捧着严严实实的“头盔”，我正发愣。那个演哥哥的小朋友还故意逗我：“你会豁虎跳吗？”","“不会 。”我只好照实回答。","“不会豁虎跳算什么老虎？”他撇了撇嘴。","真没想到，事到临头还会出现危机。我看着老师的脸，就怕她改变主意。","老师真是个通情达理的好老师。她说：“不要紧，扮老虎不一定要豁虎跳。你先四脚着地爬上台，见了他们兄妹俩就站起来，啊呜啊呜叫着，向他们扑过去，他们逃，你就追。等到猎人上场，对你连开两枪，你就躺下来——死掉。记住了吗？”","“记住了！”我连忙答应。我有充分的自信。","“现在开始排练。你把老虎头套上。”","套上老虎头，一股霉糨糊味儿直冲脑门，眼前也一片模糊。亏得眼睛那儿挖了两个小窟窿，要不就什么也看不见了。","我弯下身子向前爬，老师在一旁不断地提示：“向前爬，再向前爬，快站起来，你没看见他们吗？向他们扑过去！唉，你怎么不叫哇？嗓门要大。别忘了你不是猫，你是一只大老虎。”","我还以为扮老虎是最容易不过的了，不用说话，不用露脸，没想到也这么难。","看来老师对我的演技并不满意，她倒没说什么。那位演哥哥的小朋友话可多了。他说我这只老虎太窝囊，连豁虎跳也不会，只会在地上爬。还说他从没见过不会豁虎跳的老虎。随他说去吧，我这个配角虽然配不上他，可是老师没撤换我，他也只好将就。","终于到了星期六，到了下午，到了我们班演出的那个时刻。","我穿上老虎皮，套上老虎头，紧张地等候在后台的上场口。忽然背后有人轻轻推了我一把。我知道推我的是老师，立刻弯下身子爬上场去，嘴里啊呜啊呜直叫。只听见台下一阵哄堂大笑，笑得我脸上一阵热。我已经明白，我笨拙的表演把全场的老师同学都逗乐了，他们从没见过这样窝囊的老虎。","我总算一直演到了躺下来死掉。到底怎么演完的，我一点儿也记不起来，只记得耳边的笑声接连不断。等到幕布拉下，我站起来摘下老虎头，满头满脸都是汗珠。","老师倒没说什么。那位演哥哥的小朋友唉声叹气地对我说：“你一出场就豁几个虎跳，那就强多了。”我没回答他，可是心里想：是啊，要是我会豁虎跳，这场戏就不至于砸锅了。","后来呢？后来我发誓，今后决不再扮演老虎。可是每回上动物园，我总要去看看老虎，想看看老虎是怎么豁虎跳的。可是老虎在笼子里不是打瞌睡，就是垂头丧气地踱来踱去，从没见过它们豁过什么虎跳。","为什么不会豁虎跳就不能扮老虎呢？为什么没豁虎跳就会惹起哄堂大笑呢？我至今还不明白。"]},{"id":268,"grade":"四年级上册","title":"20 陀螺","paragraphs":["在我的故乡，陀螺不叫陀螺，叫作“冰尜儿”，顾名思义，就是冰上的小家伙。","做冰尜儿用的是木头，柳木、榆木、松木、枣木、梨木都可以。抽打冰尜儿，当然是在冬季的冰天雪地里，最好的场所是冰面。好的冰尜儿尖部嵌一颗滚珠，转起来能增加许多妩媚。顶不济的，也要钉上一枚铁钉，否则转不了多少圈，尖部就会开裂。无论嵌上滚珠，还是钉上铁钉，冰尜儿都不会裂开，能毫无怨言地让你抽打，在冰面上旋转，舞蹈。","抽冰尜儿的小伙伴们，都爱比个高下。他们往往各站一角，奋力抽转自己的冰尜儿，让它朝对方撞去。这时你看吧，两只旋转的陀螺奋勇搏斗，旋风般撞向对手，刚一接触，又各自闪向一边，然后重整旗鼓再战——直到其中一方被撞翻才告一段落。赛陀螺每次都是体重个大的一方占上风。因此，只有小陀螺的大多在自家院子里玩，不拿到马路上去应战。况且小陀螺有个难听的绰号叫“角锥”，意思是小且细。抽打“角锥”的大多是拖鼻涕穿开裆裤的，他们的兴趣在于抽鞭子，对陀螺的质量往往不在意。","我从小就不甘人后，更不愿自己的陀螺像金兵见到岳家军，一战即败。于是四处寻找木头，为削出得心应手的陀螺，就差没把椅子腿拿来“废物利用”了。为此不知挨了多少责骂，可仍然不肯住手。然而一个孩子无论如何是削不出高质量的陀螺的，因此，曾有很长一段时间我的世界堆满乌云，快乐像过冬的燕子一般，飞到一个谁也看不到的地方去了。","这种懊恼终于引起了长辈的注意。我的叔叔，一位很有童心的年轻民警，答应在我生日那天送我一只陀螺。这消息曾使我一整天处于恍惚的状态，老想象着那只陀螺英武的风姿。","叔叔的礼物不错！","这只陀螺不是人工削出来的，而是一位木工在旋床上旋出来的，圆且光滑，如同一枚鸭蛋。虽然它远不如我想象中的那么漂亮，但我极高兴地接受了它。尤其当我看到这枚“鸭蛋”的下端已嵌上一粒大滚珠时，更是手舞足蹈，恨不得马上在马路上一显身手！","我的陀螺刚一露面，就招来了一顿嘲笑。的确，在各色帅气的陀螺面前，它长得不伦不类，该平的地方不平，该尖的地方不尖，看不出一丝一毫与同伴相斗的能力。这使我士气大减，只是在一旁抽打，不敢向任何人挑战。","然而世间许多事都是不可预料的，追求“和平”只是我的个人愿望，小伙伴们不甘寂寞，一个大陀螺的主人开始傲慢地向我挑衅。大陀螺摇头晃脑，挺着肚皮一次次冲过来，我的“鸭蛋”则不动声色地闪躲。一次次冲击，一次次闪躲，终于无法避开，它们狠狠地撞上了！","奇怪的是，我的陀螺个头小，却顽强得出奇！明明被撞翻在一边，一扭身又照样旋转起来。它圆头圆脑，好像上下左右都能找到支撑点似的。结果呢，大陀螺在这个始终立于不败之地的对手面前，彻底溃败了。","这真是个辉煌的时刻！我尝到了胜利的滋味，品到了幸运的甜头。无意中获得的“荣誉”，虽然小如微尘，对好胜的孩子来说，也足以陶醉许久了——直到现在我还能兴致勃勃地写下这些文字，便是一种有力的证明吧！","我的冰尜儿，木工随便旋出的小木头块，丑小鸭生出的一只丑鸭蛋，在童年的一个冬日里，给了我极大的欢乐和由衷的自豪。","这真应了一句古话：人不可貌相，海水不可斗量。"]},{"id":269,"grade":"四年级上册","title":"语文园地","paragraphs":["韭菜　芹菜　青蒜","辣椒　莲藕　红薯　芋头","韭 芥 芹 蒜 椒 藕 薯 芋","尺有所短，寸有所长。","差之毫厘，谬以千里。","一言既出，驷马难追。","机不可失，时不再来。","病从口入，祸从口出。","比上不足，比下有余。"]},{"id":270,"grade":"四年级上册","title":"出塞","paragraphs":["作者：[唐代] 王昌龄","秦时明月汉时关，","万里长征人未还。","但使龙城飞将在，","不教胡马度阴山。","依旧是秦汉时期的明月和边关，到如今多少战士万里出征不见回还。","只要龙城的飞将卫青如今还在，一定不会让敌人的铁蹄踏过阴山。","王昌龄 (698— 756），字少伯，河东晋阳（今山西太原）人。盛唐著名边塞诗人，后人誉为“七绝圣手”。早年贫贱，困于农耕，而立之年，始中进士。初任秘书省校书郎，又中博学宏辞，授汜水尉，因事贬岭南。与李白、高适、王维、王之涣、岑参等交厚。开元末返长安，改授江宁丞。被谤谪龙标尉。安史乱起，为刺史闾丘晓所杀。其诗以七绝见长，尤以登第之前赴西北边塞所作边塞诗最著，有“诗家夫子王江宁”之誉（亦有“诗家天子王江宁”的说法）。"]},{"id":271,"grade":"四年级上册","title":"凉州词","paragraphs":["作者：[唐代] 王翰","葡萄美酒夜光杯，","欲饮琵琶马上催。","醉卧沙场君莫笑，","古来征战几人回？","酒筵上甘醇的葡萄美酒盛满在夜光杯之中，正要畅饮时，马上琵琶也声声响起，仿佛催人出征。","如果醉卧在沙场上，也请你不要笑话，古来外出打仗的能有几人返回家乡？","王翰（公元687年~726年），字子羽，并州晋阳（今山西太原市）人，唐代边塞诗人。与王昌龄同时期，王翰这样一个有才气的诗人，其集不传。其诗载于《全唐诗》的，仅有14首。登进士第，举直言极谏，调昌乐尉。复举超拔群类，召为秘书正字。擢通事舍人、驾部员外。出为汝州长史，改仙州别驾。"]},{"id":272,"grade":"四年级上册","title":"夏日绝句","paragraphs":["作者：[宋代] 李清照","生当作人杰，","死亦为鬼雄。","至今思项羽，","不肯过江东。","活着就要当人中的俊杰，死了也要做鬼中的英雄。","人们到现在还思念项羽,只因他不肯偷生回江东。","李清照（1084年3月13日～1155年5月12日）号易安居士，汉族，山东省济南章丘人。宋代（南北宋之交）词人，婉约词派代表，有“千古第一才女”之称。所作词，前期多写其悠闲生活，后期多悲叹身世，情调感伤。形式上善用白描手法，自辟途径，语言清丽。论词强调协律，崇尚典雅，提出词“别是一家”之说，反对以作诗文之法作词。能诗，留存不多，部分篇章感时咏史，情辞慷慨，与其词风不同。有《易安居士文集》《易安词》，已散佚。后人有《漱玉词》辑本。今有《李清照集校注》。"]},{"id":273,"grade":"四年级上册","title":"22 为中华之崛起而读书","paragraphs":["新学年开始了，修身课上，奉天东关模范学校的魏校长向学生们提出了一个严肃的问题：“你们为什么而读书？”","“为家父而读书。”","“为明理而读书。”","“为光耀门楣而读书。”有人干脆这样回答。","有位同学一直默默地坐在那里，若有所思。魏校长注意到了，他打手势让大家安静下来，点名让那位同学回答。那位同学站了起来，清晰而坚定地回答道：","“为中华之崛起而读书！”","魏校长听了为之一振！他怎么也没想到，一个十二三岁的孩子，竟然有如此的抱负和胸怀！他睁大眼睛又追问了一句：“你再说一遍，为什么而读书？”","“为中华之崛起而读书！”","魏校长听了，连声赞叹：“好哇！为中华之崛起，有志者当效此生！”","这位同学是谁呢？他就是周恩来，后来成为了中华人民共和国的第一任总理。","周恩来出生于1898年。十二岁那年，他离开家乡江苏淮安，随回家探亲的伯父来到了东北。在奉天上学的时候，伯父告诉他，奉天有些地方被外国人占据了，不要随便去玩，有事也要绕着走，免得惹出麻烦没有地方说理。","少年周恩来疑惑不解，问道：“被外国人占据？为什么呢？”","“中华不振哪！”伯父叹了口气，没有再说什么。","十二岁的周恩来当然不能完全明白伯父的话，但是“中华不振”四个字和伯父沉郁的表情却让他难以忘怀。","一个星期天，周恩来背着伯父，约了一个同学来到了被外国人占据的地方。这一带果真和别处大不相同：街道上热闹非凡，往来的大多是外国人。","周恩来和同学一路上左顾右盼，忽然发现巡警局门前围着一群人。他们凑了过去，只见人群中有个女人正在哭诉着什么。一问才知道，这个女人的亲人被外国人的汽车轧死了，她原本指望巡警局给她撑腰，惩处这个外国人，谁知中国巡警不但不惩处肇事的外国人，反而训斥她。围观的中国人都紧握着拳头，但这是在被外国人占据的地盘里，谁又敢怎么样呢？大家只能劝慰这个不幸的女人。","此时的周恩来才真正体会到“中华不振”这四个字的沉重分量。怎么把祖国和人民从苦难和屈辱中拯救出来呢？这个问题像一团烈火一直燃烧在周恩来心中。所以，当修身课上魏校长提出为什么而读书这个问题时，就有了“为中华之崛起而读书”的响亮回答。"]},{"id":274,"grade":"四年级上册","title":"23 梅兰芳蓄须","paragraphs":["梅兰芳先生是闻名世界的京剧表演艺术家。他在舞台上唱旦角，为了演出的需要，总是把胡须剃得干干净净的。但他的一生中，有几年却是留着胡须的。","1937年，日军占领上海，梅兰芳被迫藏身租界，以躲避日本人的纠缠。1938年底，有人邀请他去香港演戏。演出结束后，梅兰芳在香港住了下来，深居简出，不再登台。对于一个视舞台为生活、视艺术为生命的人来说，不能演出，不能创作，无异于虚度生命。到了深夜，梅兰芳关紧门窗，拉上特制的厚窗帘，才能在寓所悄悄地细声吟唱，这对他来说已经很知足了。一个艺术大师就用这种方式坚持着对艺术的追求。","1941年12月香港沦陷。日本驻港司令官亲自出马，多次逼迫梅兰芳演戏。梅兰芳可以忍受生活的困顿，直面战争的危险，但他难以抵抗来自侵略者随时随地的骚扰。拒绝的借口都用尽了，梅兰芳最后只能蓄须明志，表示对日本帝国主义的抗议，表明不给侵略者演戏的决心。后来，梅兰芳不堪其扰，只好又回到了上海。","长期不演戏，没有了经济来源，又要养家，梅兰芳准备卖掉北京的房子。听说梅兰芳要卖房子，很多戏园子老板找上门来说：“梅先生，您何必卖房子，只要您把胡子一剃，一登台，还愁没钱花？”有的甚至说，只要签订演出合同，就预支二十两黄金给梅兰芳。但是，无论戏园子老板开出的条件多么优厚，梅兰芳全部拒绝了。他宁可卖房度日，也决不在日本侵略者的统治下登台演出。","一次，日本侵略军要庆祝“大东亚圣战”，要求他必须上台演出。梅兰芳斩钉截铁地说：“普通的演出我都不参加，这样的庆祝会当然更不会去了。”但是，拒绝演出总得要想出个办法啊。","梅兰芳找到一位当医生的好朋友，说明了自己的危险处境，请朋友设法让他生一场“大病”，以摆脱日本人。这个朋友被他的爱国精神感动了，决心帮助他渡过难关，于是给他打了伤寒预防针，人打了这种针就会连日发高烧。","日本人不相信梅兰芳病了，专门派了一个军医来检查。日本军医闯进梅兰芳的家，看见他盖着棉被躺在床上，床边桌子上放着很多药。军医用手摸了摸梅兰芳的额头，滚烫滚烫的，看不出破绽，只好认定梅兰芳得了重病，不能登台演出了。日本侵略者的妄想最终没有实现，梅兰芳为此差点儿丢了性命。","当抗日战争取得胜利的消息传来时，梅兰芳当即剃了胡须，高兴地向大家宣布：“胜利了，我该登台演出了！”前来看他演出的人太多了，很多人没有座位就站着看。","作为艺术家，梅兰芳先生高超的表演艺术让人喜爱，他的民族气节更令人敬佩！"]},{"id":275,"grade":"四年级上册","title":"24* 延安，我把你追寻","paragraphs":["像翩翩归来的燕子，","在追寻昔日的春光；","像茁壮成长的小树，","在追寻雨露和太阳。","追寻你，延河叮咚的流水，","追寻你，枣园梨花的清香，","追寻你，南泥湾开荒的镢头，","追寻你，杨家岭讲话的会场。","一排排高楼大厦像雨后春笋，","一件件家用电器满目琳琅；","我们永远告别了破旧的茅屋，","却忘不了延安窑洞温热的土炕。","宇宙飞船探索太空的奥秘，","电子计算机奏出美妙的交响；","我们毫不犹豫丢掉了老牛破车，","却不能丢宝塔山顶天立地的脊梁。","延安，你的精神灿烂辉煌！","一旦失去了你啊，","那就仿佛没有了灵魂，","怎能向美好的未来展翅飞翔？","啊！延安，我把你追寻，","追寻信念，追寻金色的理想；","追寻温暖，追寻明媚的春光；","追寻光明，追寻火红的太阳！"]},{"id":276,"grade":"四年级上册","title":"语文园地","paragraphs":["作者：[唐代] 高适","千里黄云白日曛，","北风吹雁雪纷纷。","莫愁前路无知己，","天下谁人不识君？","黄云蔽天，绵延千里，太阳黯淡无光，呼啸的北风刚刚送走了雁群，又带来了纷纷扬扬的大雪。","不要担心前路茫茫没有知己，普天之下哪个不识你呢？","高适（704—765年），字达夫，一字仲武，渤海蓨（今河北景县）人，后迁居宋州宋城（今河南商丘睢阳）。安东都护高侃之孙，唐代大臣、诗人。曾任刑部侍郎、散骑常侍，封渤海县侯，世称高常侍。于永泰元年正月病逝，卒赠礼部尚书，谥号忠。作为著名边塞诗人，高适与岑参并称“高岑”，与岑参、王昌龄、王之涣合称“边塞四诗人”。其诗笔力雄健，气势奔放，洋溢着盛唐时期所特有的奋发进取、蓬勃向上的时代精神。有文集二十卷。"]},{"id":277,"grade":"四年级上册","title":"25 王戎不取道旁李","paragraphs":["王戎七岁，尝与诸小儿游。看道边李树多子折枝，诸儿竞走取之，唯戎不动。人问之，答曰：“树在道边而多子，此必苦李。”取之，信然。","王戎七岁的时候，曾经和许多小孩一起嬉戏玩耍。他们看见路边李子树上果实累累，把树枝都压弯了。许多孩子都争相跑过去摘李子，只有王戎没有动。有人问他为什么不去摘李子，王戎回答说：“李树在路边竟然还有这么多李子，这一定是苦李子。”摘来一尝，的确如此。"]},{"id":278,"grade":"四年级上册","title":"26 西门豹治邺","paragraphs":["战国时期，魏国的国君派西门豹去管理漳河边上的邺县。西门豹到了那个地方，看到田地荒芜，人烟稀少，就找了位老大爷来，问他是怎么回事。","老大爷说：“都是河神娶媳妇给闹的。河神是漳河的神，每年要娶一个年轻漂亮的姑娘。要不给他送去，漳河就要发大水，把田地全淹了。”","西门豹问：“这话是谁说的？”","老大爷说：“巫婆说的。地方上的官绅每年出面给河神办喜事，硬逼着老百姓出钱。每闹一次，他们要收几百万钱，办喜事只花二三十万，多下来的就跟巫婆分了。”","西门豹问：“新娘是哪儿来的？”","老大爷说：“哪家有年轻的女孩，巫婆就带着人到哪家去选。有钱的人家花点儿钱就过去了，没钱的只好眼睁睁地看着女孩被他们拉走。到了河神娶媳妇那天，他们在漳河边放一条苇席，把女孩打扮好了，让她坐在苇席上，顺着水漂去。苇席先还是浮着的，到了河中心就连女孩一起沉下去了。有女孩的人家差不多都逃到外地去了，所以人口越来越少，这地方也越来越穷。”","西门豹问：“那么漳河发过大水没有呢？”","老大爷说：“没有发过。倒是夏天雨水少，年年干旱。”","西门豹说：“这样说来，河神还真灵啊。下一回他娶媳妇，请告诉我一声，我也去送送新娘。”","到了河神娶媳妇的日子，漳河边上站满了老百姓。西门豹带着卫士，真的来了，巫婆和官绅急忙迎接。那巫婆已经七十多岁了，背后跟着十来个穿着绸褂的女徒弟。","西门豹说：“把新娘领来让我看看。”巫婆叫徒弟把那个打扮好的姑娘领了来。西门豹一看，女孩满脸泪水。他回过头来对巫婆说：“不行，这个姑娘不漂亮，河神不会满意的。麻烦你去跟河神说一声，说我要选个漂亮的，过几天就送去。”说完，他叫卫士架起巫婆，把她投进了漳河。","巫婆在河里扑腾了几下就沉下去了。等了一会儿，西门豹对官绅的头子说：“巫婆怎么还不回来，麻烦你去催一催吧。”说完，又叫卫士把官绅的头子投进了漳河。","西门豹面对着漳河站了很久。那些官绅都提心吊胆，大气儿也不敢出。西门豹回过头来，看着他们说：“怎么还不回来，请你们去催催吧！”说着又要叫卫士把他们扔下漳河去。","官绅一个个吓得面如土色，跪下来磕头求饶，把头都磕破了，直淌血。西门豹说：“好吧，再等一会儿。”过了一会儿，他才说：“起来吧。看样子是河神把他们留下了。你们都回去吧。”","老百姓都明白了，巫婆和官绅都是骗钱害人的。从此，谁也不敢再提给河神娶媳妇，漳河也没有发大水。","西门豹发动老百姓开凿了十二条渠道，把漳河的水引到田里。庄稼得到灌溉，年年都获得好收成。"]},{"id":279,"grade":"四年级上册","title":"扁鹊治病","paragraphs":["有一天，名医扁鹊去拜见蔡桓侯。","扁鹊在蔡桓侯身边站了一会儿，说：“据我看来，您皮肤上有点儿小病。要是不治，恐怕会向体内发展。”蔡桓侯说：“我的身体很好，什么病也没有。”扁鹊走后，蔡桓侯对左右的人说：“这些做医生的，总喜欢给没有病的人治病。医治没有病的人，才容易显示自己的高明！”","过了十天，扁鹊又来拜见蔡桓侯，说道：“您的病已经发展到皮肉之间了，要是不治还会加深。”蔡桓侯听了很不高兴，没有理睬他。扁鹊只好退了出去。","十天后，扁鹊再一次来拜见，对蔡桓侯说：“您的病已经发展到肠胃里，再不治会更加严重。”蔡桓侯听了非常不高兴。扁鹊连忙退了出去。","又过了十天，扁鹊老远望见蔡桓侯，只看了几眼，就掉头跑了。蔡桓侯觉得奇怪，派人去问他：“扁鹊，你为什么一声不响就跑掉了？”扁鹊解释道：“病在皮肤上，用热敷就能够治好；发展到皮肉之间，用扎针的方法可以治好；即使发展到肠胃里，服几剂汤药也还能治好；一旦深入骨髓，只能等死，医生再也无能为力了。现在病已经深入骨髓，所以我不再请求给他医治！”","五天之后，蔡桓侯浑身疼痛，派人去请扁鹊给他治病。扁鹊早知道蔡桓侯要来请他，几天前就跑到秦国去了。不久，蔡桓侯病死了。"]},{"id":280,"grade":"四年级上册","title":"纪昌学射","paragraphs":["飞卫是一名射箭能手。有个叫纪昌的人，想学习射箭，就去向飞卫请教。","开始练习的时候，飞卫对纪昌说：“你要想学会射箭，首先应该下功夫练眼力。你要牢牢地盯住一个目标，不能眨眼！”纪昌回家之后，就开始练习起来。妻子织布的时候，他躺在织布机下面，睁大眼睛，死死盯住织布机的踏板。两年以后，纪昌的本领练得相当到家了——就是锋利的锥尖要刺到眼角了，他的眼睛也不眨一下。","纪昌对自己的成绩感到很满意，以为练得差不多了，就再次去拜见飞卫。飞卫对他说：“虽然你已经取得了不小的成绩，但你的眼力还不够。你要练到把极小的东西看得很大，把模糊难辨的东西看得很清楚，那时候再来见我。“纪昌记住了飞卫的话，回到家里，又开始练习起来。他用一根牛尾毛拴住一只虱子，把它吊在窗口，然后每天站在虱子旁边，聚精会神地盯着它。那只小虱子，在纪昌的眼里一天天大起来，练到后来，大得竟然像车轮一样。","取得了这样大的进步，纪昌赶紧跑到飞卫那里，报告了这个好消息。飞卫高兴地说：“你就要成功了！”于是，飞卫开始教他怎样开弓，怎样放箭。","后来，纪昌成了百发百中的射箭能手。"]},{"id":281,"grade":"四年级上册","title":"语文园地","paragraphs":["冈—纲（提纲） 受—授（传授）","奏—揍（挨揍） 建—键（键盘）","普—谱（乐谱） 秀—锈（生锈）","末—沫（泡沫） 专—砖（砖头）","广—矿（矿物） 宗—综（综合）","羊—氧（氧气） 具—俱（俱乐部）","纲 授 揍 键 谱 锈","阀 砖 矿 综 氧 俱","眉清目秀　亭亭玉立","明眸皓齿　文质彬彬","相貌堂堂　威风凛凛","膀大腰圆　短小精悍","容光焕发　鹤发童颜","慈眉善目　老态龙钟"]},{"id":282,"grade":"四年级下册","title":"四时田园杂兴（其二十五）","paragraphs":["作者：[宋代] 范成大","梅子金黄杏子肥，","麦花雪白菜花稀。","日长篱落无人过，","惟有蜻蜓蛱蝶飞。","初夏时节，金黄的梅子挂满枝头，杏子也变得鲜亮饱满，田里麦穗扬着白花，油菜花差不多落尽正在结籽。","白天变长了，大家都在田间忙碌，篱落边无人经过，只有蜻蜓和蝴蝶绕着篱笆飞来飞去。","范成大（1126-1193），字至能，号称石湖居士。汉族，平江吴县（今江苏苏州）人。南宋诗人。谥文穆。从江西派入手，后学习中、晚唐诗，继承了白居易、王建、张籍等诗人新乐府的现实主义精神，终于自成一家。风格平易浅显、清新妩媚。诗题材广泛，以反映农村社会生活内容的作品成就最高。他与杨万里、陆游、尤袤合称南宋“中兴四大诗人”。"]},{"id":283,"grade":"四年级下册","title":"宿新市徐公店","paragraphs":["作者：[宋代] 杨万里","篱落疏疏一径深，","树头新绿未成阴。","儿童急走追黄蝶，","飞入菜花无处寻。","稀稀落落的篱笆旁，一条小路通向远方，路旁树上的花瓣纷纷飘落，新叶刚刚长出还未形成树荫。","小孩子奔跑着追赶黄蝴蝶，可是蝴蝶飞入菜花丛中就再也找不到了。","杨万里（1127年10月29日－1206年6月15日），字廷秀，号诚斋。吉州吉水（今江西省吉水县黄桥镇湴塘村）人。南宋著名诗人、大臣，与陆游、尤袤、范成大并称为“中兴四大诗人”。因宋光宗曾为其亲书“诚斋”二字，故学者称其为“诚斋先生”。杨万里一生作诗两万多首，传世作品有四千二百首，被誉为一代诗宗。他创造了语言浅近明白、清新自然，富有幽默情趣的“诚斋体”。杨万里的诗歌大多描写自然景物，且以此见长。他也有不少篇章反映民间疾苦、抒发爱国感情的作品。著有《诚斋集》等。"]},{"id":284,"grade":"四年级下册","title":"清平乐·村居","paragraphs":["作者：[宋代] 辛弃疾","茅檐低小，溪上青青草。醉里吴音相媚好，白发谁家翁媪？","大儿锄豆溪东，中儿正织鸡笼。最喜小儿亡赖，溪头卧剥莲蓬。","草屋的茅檐又低又小，溪边长满了翠绿的小草。含有醉意的吴地方音，听起来温柔又美好，那满头白发的是谁家的公婆父老？","大儿子在小溪东边的豆田锄草，二儿子正在家里编织鸡笼。最喜欢的顽皮的小儿子，他正横卧在溪头草丛，剥着刚摘下的莲蓬。","辛弃疾（1140年5月28日－1207年10月3日），原字坦夫，后改字幼安，中年后别号稼轩，山东东路济南府历城县（今山东省济南市历城区）人。南宋官员、将领、文学家，豪放派词人，有“词中之龙”之称。与苏轼合称“苏辛”，与李清照并称“济南二安”。辛弃疾出生时，中原已为金兵所占。21岁参加抗金义军，不久归南宋。历任湖北、江西、湖南、福建、浙东安抚使等职。一生力主抗金。曾上《美芹十论》与《九议》，条陈战守之策。其词抒写力图恢复国家统一的爱国热情，倾诉壮志难酬的悲愤，对当时执政者的屈辱求和颇多谴责；也有不少吟咏祖国河山的作品。题材广阔又善化用前人典故入词，风格沉雄豪迈又不乏细腻柔媚之处。由于辛弃疾的抗金主张与当政的主和派政见不合，后被弹劾落职，退隐江西带湖。"]},{"id":285,"grade":"四年级下册","title":"2 乡下人家","paragraphs":["乡下人家总爱在屋前搭一瓜架，或种南瓜，或种丝瓜，让那些瓜藤攀上棚架，爬上屋檐。当花儿落了的时候，藤上便结出了青的、红的瓜，它们一个个挂在房前，衬着那长长的藤，绿绿的叶。青、红的瓜，碧绿的藤和叶，构成了一道别有风趣的装饰，比那高楼门前蹲着一对石狮子或是竖着两根大旗杆，可爱多了。","有些人家，还在门前的场地上种几株花，芍药，凤仙，鸡冠花，大丽菊，它们依着时令，顺序开放，朴素中带着几分华丽，显出一派独特的农家风光。还有些人家，在屋后种几十枝竹，绿的叶，青的竿，投下一片浓浓的绿荫。几场春雨过后，到那里走走，你常常会看见许多鲜嫩的笋，成群地从土里探出头来。","鸡，乡下人家照例总要养几只的。从他们的房前屋后走过，你肯定会瞧见一只母鸡，率领一群小鸡，在竹林中觅食；或是瞧见耸着尾巴的雄鸡，在场地上大踏步地走来走去。","他们的屋后倘若有一条小河，那么在石桥旁边，在绿树荫下，你会见到一群鸭子游戏水中，不时地把头扎到水下去觅食。即使附近的石头上有妇女在捣衣，它们也从不吃惊。","若是在夏天的傍晚出去散步，你常常会瞧见乡下人家吃晚饭的情景。他们把桌椅饭菜搬到门前，天高地阔地吃起来。天边的红霞，向晚的微风，头上飞过的归巢的鸟儿，都是他们的好友。它们和乡下人家一起，绘成了一幅自然、和谐的田园风景画。","秋天到了，纺织娘寄住在他们屋前的瓜架上。月明人静的夜里，它们便唱起歌来：“织，织，织，织啊！织，织，织，织啊！”那歌声真好听，赛过催眠曲，让那些辛苦一天的人们，甜甜蜜蜜地进入梦乡。","乡下人家，不论什么时候，不论什么季节，都有一道独特、迷人的风景。"]},{"id":286,"grade":"四年级下册","title":"3 天窗","paragraphs":["乡下的房子只有前面一排木板窗。暖和的晴天，木板窗扇扇打开，光线和空气都有了。","碰着大风大雨，或者北风呼呼叫的冬天，木板窗只好关起来，屋子里就黑得像地洞似的。","于是乡下人在屋顶开一个小方洞，装一块玻璃，叫作“天窗”。","夏天阵雨来了时，孩子们顶喜欢在雨里跑跳，仰着脸看闪电，然而大人们偏就不许。“到屋里来啊！”随着木板窗的关闭，孩子们也就被关在地洞似的屋里了。这时候，小小的天窗是你唯一的慰藉。","从那小小的玻璃，你会看见雨脚在那里卜落卜落跳，你会看见带子似的闪电一瞥；你想象到这雨，这风，这雷，这电，怎样猛厉地扫荡了这世界，你想象它们的威力比你在露天真实感到的要大十倍百倍。小小的天窗会使你的想象锐利起来！","晚上，当你被逼着上床去“休息”的时候，也许你还忘不了月光下的草地河滩。你偷偷地从帐子里伸出头来，仰起了脸。这时候，小小的天窗又是你唯一的慰藉！","你会从那小玻璃上面的一粒星，一朵云，想象到无数闪闪烁烁可爱的星，无数像山似的、马似的、巨人似的奇幻的云彩；你会从那小玻璃上面掠过的一条黑影，想象到这也许是灰色的蝙蝠，也许是会唱歌的夜莺，也许是霸气十足的猫头鹰……总之，夜的美丽神奇，立刻会在你的想象中展开。","发明这天窗的大人们，是应得感谢的。因为活泼会想的孩子们知道怎样从“无”中看出“有”，从“虚”中看出“实”，比任何他们看到的都更真切，更阔达，更复杂，更确实！"]},{"id":287,"grade":"四年级下册","title":"4* 三月桃花水","paragraphs":["是什么声音，像一串小铃铛，轻轻地走过村边？是什么光芒，像一匹明洁的丝绸，映照着蓝天？","啊，河流醒来了！三月的桃花水，舞动着绮丽的朝霞，向前流啊。有一千朵桃花，点点洒在河面，有一万个小酒窝，在水中回旋。","三月的桃花水，是春天的竖琴。","那忽大忽小的水声，应和着拖拉机的鸣响；那纤细的低语，是在和刚刚从雪被里伸出头来的麦苗谈心；那碰着岸边石块的叮当声，像是大路上车轮滚过的铃声……","三月的桃花水，是春天的明镜。","它看见燕子飞过天空，翅膀上裹着白云；它看见垂柳披上了长发，如雾如烟；它看见一群姑娘来到河边，水底立刻浮起一朵朵红莲，她们捧起了水，像抖落一片片花瓣……","啊，地上草如茵，两岸柳如眉，三月桃花水，叫人多沉醉。"]},{"id":288,"grade":"四年级下册","title":"语文园地","paragraphs":["风雨送春归，飞雪迎春到。已是悬崖百丈冰，犹有花枝俏。","俏也不争春，只把春来报。待到山花烂漫时，她在丛中笑。","品读了陆游的《卜算子·咏梅》，反用其原本的寓意而写了这首词。","风雨将春天送走了，飞雪又把春光迎来。正是悬崖结下百丈冰柱的时节，但仍然有花枝俏丽竞放。","俏丽但不掠春光之美，只是把春天的消息来报告。等到满山遍野开满鲜花之时，梅花却在花丛中欢笑。","繁华 璀璨 高楼林立","车水马龙 灯火辉煌","肥沃 静谧 炊烟袅袅","依山傍水 鸡犬相闻","天边的红霞，向晚的微风，头上飞过的归巢的鸟儿，都是他们的好友。它们和乡下人家一起，绘成了一幅自然、和谐的田园风景画。","飞翔的海鸥，金色的沙滩，白色的浪花，构成了迷人的海滨景观。"]},{"id":289,"grade":"四年级下册","title":"5 琥珀","paragraphs":["这个故事发生在很久很久以前，约莫算来，总有几万年了。","一个夏日，太阳暖暖地照着，海在很远的地方翻腾怒吼，绿叶在树上飒飒地响。","一只小苍蝇展开柔嫩的绿翅膀，在阳光下快乐地飞舞。它嗡嗡地穿过草地，飞进树林。那里长着许多高大的松树，太阳照得火热，可以闻到一股松脂的香味。","那只小苍蝇停在一棵大松树上。它伸起腿来掸掸翅膀，拂拭那长着一对红眼睛的圆脑袋。它飞了大半天，身上已经沾满了灰尘。","忽然，有个蜘蛛慢慢爬过来，想把那只苍蝇当作一顿美餐。它小心地划动长长的腿，沿着树干向下爬，离小苍蝇越来越近了。","晌午的太阳热辣辣地照射着整个树林。许多老松树渗出厚厚的松脂，松脂在太阳光里闪闪地发出金黄的光。","蜘蛛刚扑过去，突然发生了一件可怕的事情。一大滴松脂从树上滴下来，刚好落在树干上，把苍蝇和蜘蛛一齐包在里头。","小苍蝇不能掸翅膀了，蜘蛛也不能再想什么美餐了。两只小虫都淹没在老松树黏稠的黄色泪珠里。它们前俯后仰地挣扎了一番，终于不动了。","松脂继续滴下来，盖住了原来的，最后积成一个松脂球，把两只小虫重重包裹在里面。","几十年，几百年，几千年，时间一转眼就过去了。成千上万只绿翅膀的苍蝇和八只脚的蜘蛛来了又去了。谁也不会想到很久很久以前，有两只小虫被埋在一个松脂球里，挂在一棵老松树上。","后来，陆地渐渐沉下去，海水渐渐漫上来，逼近那古老的森林。有一天，水把森林淹没了，波浪不断冲刷着树干，甚至把树连根拔起。树断绝了生机，慢慢地腐烂了，剩下的只有那些松脂球，淹没在泥沙下面。","又是几千年过去了，那些松脂球成了化石。","海风猛烈地吹，澎湃的波涛把海里的泥沙卷到岸边。","有个渔民带着儿子走过海滩。那孩子赤着脚，他踩着了沙里的一块硬东西，就把它挖了出来。","“爸爸，你看！”他快活地叫起来，“这是什么？”","他爸爸接过来，仔细看了看。","“这是琥珀，孩子。”他高兴地说，“有两个小东西关在里面呢，一只苍蝇，一个蜘蛛。这是很少见的。”","在那块透明的琥珀里，两个小东西仍旧好好地躺着。我们可以看见它们身上的每一根毫毛，还可以想象它们当时在黏稠的松脂里怎样挣扎，因为它们的腿的四周显出好几圈黑色的圆环。从那块琥珀，我们可以推测发生在几千万年前的故事的详细情形，并且可以知道，在远古时代，世界上就已经有苍蝇和蜘蛛了。"]},{"id":290,"grade":"四年级下册","title":"6 飞向蓝天的恐龙","paragraphs":["说到恐龙，人们往往想到凶猛的霸王龙或者笨重、迟钝的马门溪龙；谈起鸟类，我们头脑中自然会浮现轻灵的鸽子或者五彩斑斓的孔雀。二者似乎毫不相干，但近年来发现的大量化石显示：在中生代时期，恐龙的一支经过漫长的演化，最终变成了凌空翱翔的鸟儿。","早在19世纪，英国学者赫胥黎就注意到恐龙和鸟类在骨骼结构上有许多相似之处。在研究了大量恐龙和鸟类化石之后，科学家们提出，鸟类不仅和恐龙有亲缘关系，而且很可能就是一种小型恐龙的后裔。根据这一假说，一些与鸟类亲缘关系较近的恐龙应该长有羽毛，但一直没有找到化石证据。20世纪末期，我国科学家在辽宁西部首次发现了保存有羽毛的恐龙化石，顿时使全世界的研究者们欣喜若狂。辽西的发现向世人展示了恐龙长羽毛的证据，给这幅古生物学家们描绘的画卷涂上了点睛之笔。","恐龙是如何飞向蓝天的呢？让我们穿越时空隧道，访问中生代的地球，看看这一演化过程吧！","地球上的第一种恐龙大约出现在两亿四千万年前。它和狗一般大小，两条后腿粗壮有力，能够支撑起整个身体。数千万年后，它的后代繁衍成一个形态各异的庞大家族。有些恐龙像它们的祖先一样两足奔跑，有些恐龙则用四足行走。有些恐龙身长几十米，重达数十吨；有些恐龙则身材小巧，体重只有几千克。有些恐龙凶猛异常，是茹毛饮血的食肉动物；有些恐龙则温顺可爱，以植物为食。其中，一些猎食性恐龙的身体逐渐变小，越来越像鸟类：骨骼中空，身体轻盈；脑颅膨大，行动敏捷；前肢越来越长，能像鸟翼一样拍打；体表长出美丽的羽毛，不再披着鳞片或鳞甲。它们中的一些种类可能为了躲避敌害或寻找食物而转移到树上生存。这些树栖的恐龙在树木之间跳跃、降落，慢慢具备了滑翔能力，并最终能够主动飞行。不过，另一种看法是，飞行并非始于树栖生活。有些科学家推测，一种生活在地面上的带羽毛的恐龙，在奔跑过程中学会了飞翔。不管怎样，科学家们认为：原本不会飞的恐龙最终变成了天之骄子——鸟类，它们飞向了蓝天，从此开辟了一个崭新的生活天地。","亿万年前，一种带羽毛的恐龙脱离同类，飞向蓝天，演化出今天的鸟类大家族。科学家们希望能够全面揭示这一历史进程。随着越来越多相关化石的发现，他们离这一愿望的实现已越来越近了。"]},{"id":291,"grade":"四年级下册","title":"7 纳米技术就在我们身边","paragraphs":["纳米技术是20世纪90年代兴起的高新技术。如果说20世纪是微米的世纪，21世纪必将是纳米的世纪。","什么是纳米技术呢？这得从纳米说起。纳米是非常非常小的长度单位，1纳米等于10亿分之一米。如果把直径为1纳米的小球放到乒乓球上，就好像把乒乓球放在地球上，可见纳米有多么小。纳米技术的研究对象一般在1纳米到100纳米之间，不仅肉眼根本看不见，就是普通的光学显微镜也无能为力。这种纳米级的物质拥有许多新奇的特性，纳米技术就是研究并利用这些特性造福人类的一门学问。","纳米技术就在我们身边。冰箱里如果使用一种纳米涂层，就会具有杀菌和除臭功能，能够使蔬菜保鲜期更长。有一种叫作“碳纳米管”的神奇材料，比钢铁结实百倍，而且非常轻，将来我们有可能坐上“碳纳米管天梯”到太空旅行。在最先进的隐形战机上，用到一种纳米吸波材料，能够把探测雷达波吸收掉，所以雷达根本看不见它。","纳米技术可以让人们更加健康。癌症很可怕，但如果在只有几个癌细胞的时候就能发现的话，死亡率会大大降低。利用极其灵敏的纳米检测技术，可以实现疾病的早期检测与预防。未来的纳米机器人甚至可以通过血管直达病灶，杀死癌细胞。生病的时候，需要吃药。现在吃一次药最多管一两天，未来的纳米缓释技术，能够让药物效力缓慢地释放出来，服一次药可以管一周，甚至一个月。","纳米技术将给人类的生活带来深刻的变化。在不远的将来，我们的衣食住行都会有纳米技术的影子。"]},{"id":292,"grade":"四年级下册","title":"8* 千年梦圆在今朝","paragraphs":["飞离地球、遨游太空是中华民族很久以来的梦想。在古代就有“嫦娥奔月”的神话，有人飞上天、空中飞车的传说，还有“鲲鹏展翅”“九天揽月”的奇妙想象。富有激情和超凡想象力的炎黄子孙，在千百年的岁月流转之中，不断地尝试实现自己的美好愿望。","传说，我国明代的官员万户，是世界历史上第一个试验利用火箭上天的人。他把四十七支火箭安装在椅子背后，自己坐在椅子上，手拿两只大风筝，叫人点火发射。随着一声巨响，他消失在了火焰和烟雾中。尽管他的火箭飞行尝试没有成功，但万户仍然被国际航天史学家公认为人类飞行探索的先驱。为了纪念他，国际天文学联合会将月球上的一座环形山命名为“万户”。","万户那种勇于实践的探索精神，极大地震撼和鼓舞着人们。数百年来，坚定而执着的炎黄子孙，在实现飞天梦的过程中，遭受了无数失败，付出了惨重代价，但是，始终没有放弃飞离地球的努力。","1949年，中华人民共和国成立，中华民族的历史掀开了崭新的一页，中国的航天事业也呈现出勃勃生机。毛泽东主席在苏联第一颗人造卫星上天之后的第二年——1958年，庄重地表示：“我们也要搞人造卫星。”经过十多年的努力，1970年4月24日，寂寞而辽阔的太空中，第一次响起了中国人的声音，那穿越苍穹的《东方红》乐曲，让海内外华人振奋不已。中国成为世界上第五个能够发射卫星的国家。","在准备发射人造卫星的同时，中国科学家满怀希望地开始了载人航天技术的探索。1992年9月21日，党中央决定实施载人航天工程，一百一十多个单位直接承担了研制、建设和发射任务。经过广大科技人员、工人和解放军官兵十余年的不懈努力，2003年10月15日早晨9时，在酒泉卫星发射中心，随着一声震耳欲聋的巨响，我国自行研制的“神舟五号”飞船被送上太空。火箭宛若一条巨龙，划过一道绚丽的曲线，瞬间便消失在了苍穹之中。10月16日早晨6时23分，飞船在环绕地球十四圈后成功返回着陆场。航天员杨利伟在即将登机返回北京的时候，用三句话概括了他的太空旅行:“飞船运行正常。我自我感觉良好。我为祖国感到骄傲。”","我国首次载人航天飞行的成功，向全世界宣告：中国已经成为第三个独立掌握载人航天技术的国家。","“神舟五号”成功发射的第二年，我国正式实施探月工程。2007年10月24日，我国成功发射第一颗月球探测卫星“嫦娥一号”，成为世界上第四个掌握月球探测技术的国家。这是我国航天事业的又一座里程碑。2019年1月3日，“嫦娥四号”探测器实现了人类首次月球背面软着陆，并传回了第一张月背近距离拍摄的清晰的月表形貌图。随后，“嫦娥四号”着陆器与它的月球车“玉兔二号”，顺利进行了互相拍摄，带有五星红旗的着陆器和月球车，在月球背面留下了历史性的珍贵影像。"]},{"id":293,"grade":"四年级下册","title":"语文园地","paragraphs":["滨—宾（宾馆） 洁—吉（吉利）","减—咸（咸菜） 挑—兆（预兆）","挺—廷（宫廷） 预—予（赠予）","中—肿（肿胀） 介—阶（台阶）","止—趾（脚趾） 凡—巩（巩固）","正—政（政府） 刘—浏（浏览）","宾 吉 咸 兆 廷 予","肿 阶 趾 巩 政 浏","作者：[唐代] 杜甫","黄师塔前江水东，","春光懒困倚微风。","桃花一簇开无主，","可爱深红爱浅红？","黄师塔前江水向东流去，温暖的春天使人困倦，只想倚着春风小憩。","一株无主的桃花开得正盛，究竟是爱深红还是更爱浅红呢？","杜甫（712－770），字子美，自号少陵野老，世称“杜工部”、“杜少陵”等，汉族，河南府巩县（今河南省巩义市）人，唐代伟大的现实主义诗人，杜甫被世人尊为“诗圣”，其诗被称为“诗史”。杜甫与李白合称“李杜”，为了跟另外两位诗人李商隐与杜牧即“小李杜”区别开来，杜甫与李白又合称“大李杜”。他忧国忧民，人格高尚，他的约1400余首诗被保留了下来，诗艺精湛，在中国古典诗歌中备受推崇，影响深远。759-766年间曾居成都，后世有杜甫草堂纪念。","十万个为什么","为什么铁会生锈？为什么面包放久了会发硬？为什么水能带走脏东西？……你想知道这些问题的答案吗？快来读一读科普作品吧！","你读过吗","说到科普读物，就一定会提到苏联作家米•伊林的《十万个为什么》。他在这本书中，带着我们进行了一次屋内旅行，对自来水龙头、炉子、桌子、灶台、锅架、餐具柜、衣橱等，提出了许多看似简单，却不那么容易回答的问题。","这本书不仅内容有趣，语言也非常生动。","你们家里每天总有人生炉子，煮马铃薯。也许你自己就很会生炉子或煮马铃薯。可是请你解释一下：为什么炉子里的柴会毕剥作响？为什么烟会走烟筒出去，而不向屋里冒？煤油燃烧的时候，从哪里来的烟？为什么烘烤的马铃薯有一层硬皮，煮的却没有？恐怕你不能理解明白吧。或者问你：水为什么能灭火？我的一位熟人回答说：“水能灭火，因为它又湿又冷。”可是煤油也又湿又冷，你倒是试试用煤油来灭火吧！不，你还是不试为好，一试就得报火警了。你看，问题挺简单，可是要回答它却不那么容易。我再给你猜十二个关于最简单事物的谜，你愿意不愿意？","——选自苏联米•伊林的《十万个为什么》，","董纯才、邹信然、祝修恒译，有改动","相信你可以读更多","我们还可以读一读中国的《十万个为什么》。这套丛书涵盖了数学、物理、化学、生物等领域。书中提出了许多有趣的问题：乘坐热气球能环游世界吗？时光能倒流吗？为什么飞机不像鸟儿一样扇翅飞行？地球究竟正在变冷还是变暖？……读读这套书，试着找找问题的答案吧！","我国还有许多优秀的科普作品，如李四光的《看看我们的地球》、高士其的《灰尘的旅行》、贾兰坡的《人类起源的演化过程》。读了这些作品，你一定会为科学世界里有那么多的奥秘而惊奇。","地球上的第一种恐龙和狗一般大小，两条后腿粗壮有力，能够支撑起整个身体。","如果把直径为1纳米的小球放到乒乓球上，相当于把乒乓球放在地球上，可见纳米有多么小。","有一种叫作“碳纳米管”的神奇材料，比钢铁结实百倍。"]},{"id":294,"grade":"四年级下册","title":"繁星（七一）","paragraphs":["这些事——","是永不漫灭的回忆：","月明的园中，","藤萝的叶下，","母亲的膝上。"]},{"id":295,"grade":"四年级下册","title":"繁星（一三一）","paragraphs":["大海啊！","哪一颗星没有光？","哪一朵花没有香？","哪一次我的思潮里","没有你波涛的清响？"]},{"id":296,"grade":"四年级下册","title":"繁星（一五九）","paragraphs":["母亲啊！","天上的风雨来了，","鸟儿躲到它的巢里；","心中的风雨来了，","我只躲到你的怀里。"]},{"id":297,"grade":"四年级下册","title":"10 绿","paragraphs":["好像绿色的墨水瓶倒翻了，","到处是绿的……","到哪儿去找这么多的绿：","墨绿、浅绿、嫩绿、","翠绿、淡绿、粉绿……","绿得发黑、绿得出奇；","刮的风是绿的，","下的雨是绿的，","流的水是绿的，","阳光也是绿的。","所有的绿集中起来，","挤在一起，","重叠在一起，","静静地交叉在一起。","突然一阵风，","好像舞蹈教练在指挥，","所有的绿就整齐地","按着节拍飘动在一起……"]},{"id":298,"grade":"四年级下册","title":"11 白桦","paragraphs":["在我的窗前，","有一棵白桦，","仿佛涂上银霜，","披了一身雪花。","毛茸茸的枝头，","雪绣的花边潇洒，","串串花穗齐绽，","洁白的流苏如画。","在朦胧的寂静中","玉立着这棵白桦，","在灿灿的金晖里","闪着晶亮的雪花。","白桦四周徜徉着","姗姗来迟的朝霞，","它向白雪皑皑的树枝","又抹一层银色的光华。"]},{"id":299,"grade":"四年级下册","title":"12* 在天晴了的时候","paragraphs":["在天晴了的时候，","该到小径中去走走：","给雨润过的泥路，","一定是凉爽又温柔；","炫耀着新绿的小草，","已一下子洗净了尘垢；","不再胆怯的小白菊，","慢慢地抬起它们的头，","试试寒，试试暖，","然后一瓣瓣地绽透；","抖去水珠的凤蝶儿，","在木叶间自在闲游，","把它的饰彩的智慧书页，","曝着阳光一开一收。","到小径中去走走吧，","在天晴了的时候：","赤着脚，携着手，","踏着新泥，涉过溪流。","新阳推开了阴霾了，","溪水在温风中晕皱，","看山间移动的暗绿——","云的脚迹——它也在闲游。"]},{"id":300,"grade":"四年级下册","title":"语文园地","paragraphs":["屈原　陶渊明　孟浩然　杜甫","韩愈　刘禹锡　范仲淹　龚自珍","屈 渊 孟 甫 韩","愈 禹 锡 仲 龚","诗和音乐一样，生命全在节奏。——朱光潜","诗是人类向未来寄发的信息，诗给人类以朝向理想的勇气。——艾青","诗是强烈感情的自然流露，它源于宁静中回忆起来的情感。——【英国】华兹华斯","在我的窗前，有一棵白桦，仿佛涂上银霜，披了一身雪花。","白雾与远天晴空连在一起，晶白中透着淡蓝、青苍，一碧万顷。","那草滩的绿，绿得娇嫩；那菜花的黄，黄得蓬勃；而那湖水的蓝，又是蓝得多么醉人啊！","这些事——是永不漫灭的回忆；月明的园中，藤萝的叶下，母亲的膝上。","春天的早晨，怎样的可爱呢！融冶的风，飘扬的衣袖，静悄的心情。"]},{"id":301,"grade":"四年级下册","title":"13 猫","paragraphs":["猫的性格实在有些古怪。","说它老实吧，它的确有时候很乖。它会找个暖和的地方，成天睡大觉，无忧无虑，什么事也不过问。可是，它决定要出去玩玩，就会出走一天一夜，任凭谁怎么呼唤，它也不肯回来。说它贪玩吧，的确是啊，要不怎么会一天一夜不回家呢？可是，它听到老鼠的一点儿响动，又是多么尽职。它屏息凝视，一连就是几个钟头，非把老鼠等出来不可！","它要是高兴，能比谁都温柔可亲：用身子蹭你的腿，把脖子伸出来让你给它抓痒，或是在你写作的时候，跳上桌来，在稿纸上踩印几朵小梅花。它还会丰富多腔地叫唤，长短不同，粗细各异，变化多端。在不叫的时候，它还会咕噜咕噜地给自己解闷。这可都凭它的高兴。它若是不高兴啊，无论谁说多少好话，它也一声不出，连半朵小梅花也不肯印在稿纸上！","它什么都怕，总想藏起来。可是它又那么勇猛，不要说见着小虫和老鼠，就是遇上蛇也敢斗一斗。","这种古怪的小动物，真让人觉得可爱。","满月的小猫们就更好玩了，腿脚还不稳，可是已经学会淘气。妈妈的尾巴，一根鸡毛，都是它们的好玩具，耍个没完没了。一玩起来，它们不知要摔多少跟头，但是跌倒了马上起来，再跑再跌。它们的头撞在门上，桌腿上，和彼此的头上，撞疼了也不哭。它们的胆子越来越大，逐渐开辟新的游戏场所。它们到院子里来了。院中的花草可遭了殃。它们在花盆里摔跤，抱着花枝打秋千，所过之处，枝折花落。你见了，绝不会责打它们，它们是那么生气勃勃，天真可爱！"]},{"id":302,"grade":"四年级下册","title":"14 母鸡","paragraphs":["我一向讨厌母鸡。听吧，它由前院嘎嘎到后院，由后院再嘎嘎到前院，没完没了，并且没有什么理由，讨厌！有的时候，它不这样乱叫，而是细声细气的，有什么心事似的，颤颤巍巍的，顺着墙根，或沿着田坝，那么扯长了声如怨如诉，使人心中立刻结起个小疙瘩来。","它永远不反抗公鸡，有时候却欺侮最忠厚的鸭子。更可恶的是遇到另一只母鸡的时候，它会下毒手，趁其不备，狠狠地咬一口，咬下一撮儿毛来。","到下蛋的时候，它差不多是发了狂，恨不能让全世界都知道它这点儿成绩；就是聋人也会被它吵得受不了。","可是，现在我改变了心思，我看见一只孵出一群小雏鸡的母鸡。","不论是在院里，还是在院外，它总是挺着脖儿，表示出世界上并没有可怕的东西。一只鸟儿飞过，或是什么东西响了一声，它立刻警戒起来：歪着头听；挺着身儿预备作战；看看前，看看后，咕咕地警告鸡雏要马上集合到它身边来。","发现了一点儿可吃的东西，它咕咕地紧叫，啄一啄那个东西，马上便放下，让它的儿女吃。结果，每一只鸡雏的肚子都圆圆地下垂，像刚装了一两个汤圆儿似的，它自己却消瘦了许多。假若有别的大鸡来抢食，它一定出击，把它们赶出老远，连大公鸡也怕它三分。","它教鸡雏们啄食，掘地，用土洗澡，一天不知教多少次。它还半蹲着，让它们挤在它的翅下、胸下，得一点儿温暖。它若伏在地上，鸡雏们有的便爬到它的背上，啄它的头或别的地方，它一声也不哼。","在夜间若有什么动静，它便放声啼叫，顶尖锐，顶凄惨，无论多么贪睡的人都得起来看看，是不是有了黄鼠狼。","它负责、慈爱、勇敢、辛苦，因为它有了一群鸡雏。它伟大，因为它是鸡母亲。一个母亲必定就是一位英雄。","我不敢再讨厌母鸡了。"]},{"id":303,"grade":"四年级下册","title":"15 白鹅","paragraphs":["这白鹅，是一位即将远行的朋友送给我的。我抱着这雪白的“大鸟”回家，放在院子里。它伸长了头颈，左顾右盼，我一看这姿态，想道：“好一个高傲的动物！”","鹅的高傲，更表现在它的叫声、步态和吃相中。","鹅的叫声，音调严肃郑重，似厉声呵斥。它的旧主人告诉我：养鹅等于养狗，它也能看守门户。后来我看到果然如此：凡有生客进来，鹅必然厉声叫嚣；甚至篱笆外有人走路，它也要引吭大叫，不亚于狗的狂吠。","鹅的步态，更是傲慢了。大体上与鸭相似，但鸭的步调急速，有局促不安之相；鹅的步调从容，大模大样的，颇像京剧里的净角出场。它常傲然地站着，看见人走来也毫不相让；有时非但不让，竟伸过颈子来咬你一口。","鹅的吃饭，常常使我们发笑。我们的鹅是吃冷饭的，一日三餐。它需要三样东西下饭：一样是水，一样是泥，一样是草。先吃一口冷饭，再喝一口水，然后再到别处去吃一口泥和草。大约这些泥和草也有各种可口的滋味。这些食料并不奢侈，但它的吃法，三眼一板，一丝不苟。譬如吃了一口饭，倘若水盆放在远处，它一定从容不迫地大踏步走上前去，饮一口水，再大踏步走去吃泥、吃草。吃过泥和草再回来吃饭。","这样从容不迫地吃饭，必须有一个人在旁侍候，像饭馆里的堂倌一样。因为附近的狗，都知道我们这位鹅老爷的脾气，每逢它吃饭的时候，狗就躲在篱边窥伺。等它吃过一口饭，踏着方步去喝水、吃泥、吃草的当儿，狗就敏捷地跑过来，努力地吃它的饭。鹅老爷偶然早归，伸颈去咬狗，并且厉声叫骂，狗立刻逃往篱边，蹲着静候；看它再吃了一口饭，再走开去喝水、吃泥、吃草的时候，狗又敏捷地跑上来，把它的饭吃完，扬长而去。等到鹅再来吃饭的时候，饭罐已经空空如也。鹅便昂首大叫，似乎责备人们供养不周。这时我们便替它添饭，并且站着侍候。因为邻近狗很多，一狗方去，一狗又来蹲着窥伺了。","我们不胜其烦，以后便将饭罐和水盆放在一起，免得它走远去，让鸡、狗偷饭吃。然而它所必需的泥和草，所在的地点远近无定。为了找这些食物，它仍是要走远去的。因此鹅吃饭时，非有一个人侍候不可，真是架子十足！"]},{"id":304,"grade":"四年级下册","title":"语文园地","paragraphs":["杆—肝(肝脏)—秆(麦秆)","消—俏(俏丽)—峭(陡峭)","捕—哺(哺育)—浦(黄浦江)","轮—沦(沦落)—抡(抡拳)","换—涣(涣散)—焕(焕发)","骏—俊(英俊)—峻(严峻)","肝 秆 俏 峭 哺 浦","沦 抡 涣 焕 俊 峻","作者：[唐代] 罗隐","不论平地与山尖，","无限风光尽被占。","采得百花成蜜后，","为谁辛苦为谁甜？","无论是在平地，还是在山峰，极其美好的风景都被蜜蜂占有。","蜜蜂啊，你采尽百花酿成了花蜜，到底为谁付出辛苦，又想让谁品尝香甜？","罗隐（833年2月16日—910年1月26日），字昭谏，新城（今浙江省杭州市富阳区新登镇）人，唐代诗人。生于公元833年（大和七年），大中十三年（公元859年）底至京师，应进士试，历七年不第。咸通八年（公元867年）乃自编其文为《谗书》，益为统治阶级所憎恶，所以罗衮赠诗说：“谗书虽胜一名休”。后来又断断续续考了几年，总共考了十多次，自称“十二三年就试期”，最终还是铩羽而归，史称“十上不第”。黄巢起义后，避乱隐居九华山，光启三年（公元887年），55岁时归乡依吴越王钱镠，历任钱塘令、司勋郎中、给事中等职。公元909年（五代后梁开平三年）去世，享年77岁。"]},{"id":305,"grade":"四年级下册","title":"16 海上日出","paragraphs":["为了看日出，我常常早起。那时天还没有大亮，周围非常清静，船上只有机器的响声。","天空还是一片浅蓝，颜色很浅。转眼间天边出现了一道红霞，慢慢地在扩大它的范围，加强它的亮光。我知道太阳要从天边升起来了，便不转眼地望着那里。","果然，过了一会儿，在那个地方出现了太阳的小半边脸，红是真红，却没有亮光。太阳好像负着重荷似的一步一步，慢慢地努力上升，到了最后，终于冲破了云霞，完全跳出了海面，颜色红得非常可爱。一刹那间，这个深红的圆东西，忽然发出了夺目的亮光，射得人眼睛发痛。它旁边的云片也突然有了光彩。","有时太阳走进了云堆中，它的光线却从云里射下来，直射到水面上。这时候要分辨出哪里是水，哪里是天，倒也不容易，因为我就只看见一片灿烂的亮光。","有时天边有黑云，而且云片很厚，太阳出来，人眼还看不见。然而太阳在黑云里放射的光芒，透过黑云的重围，替黑云镶了一道发光的金边。后来太阳才慢慢地冲出重围，出现在天空，甚至把黑云也染成了紫色或者红色。这时候发亮的不仅是太阳、云和海水，连我自己也成了光亮的了。","这不是很伟大的奇观吗？"]},{"id":306,"grade":"四年级下册","title":"17 记金华的双龙洞","paragraphs":["4月14日，我在浙江金华，游北山的双龙洞。","出金华城大约五公里到罗店，过了罗店就渐渐入山。公路盘曲而上。山上开满了映山红，无论花朵还是叶子，都比盆栽的杜鹃显得有精神。油桐也正开花，这儿一丛，那儿一簇，很不少。山上沙土呈粉红色，在别处似乎没有见过。粉红色的山，各色的映山红，再加上或浓或淡的新绿，眼前一片明艳。","一路迎着溪流。随着山势，溪流时而宽，时而窄，时而缓，时而急，溪声也时时变换调子。入山大约五公里就来到双龙洞口，那溪流就是从洞里出来的。","在洞口抬头望，山相当高，突兀森郁，很有气势。洞口像桥洞似的，很宽。走进去，仿佛到了个大会堂，周围是石壁，头上是高高的石顶，在那里聚集一千或是八百人开个会，一定不觉得拥挤。泉水靠着洞口的右边往外流。这是外洞。","在外洞找泉水的来路，原来从靠左边的石壁下方的孔隙流出。虽说是孔隙，可也容得下一只小船进出。怎样小的小船呢？两个人并排仰卧，刚合适，再没法容第三个人，是这样小的小船。船两头都系着绳子，管理处的工人先进内洞，在里边拉绳子，船就进去，在外洞的工人拉另一头的绳子，船就出来。我怀着好奇的心情独个儿仰卧在小船里，自以为从后脑到肩背，到臀部，到脚跟，没有一处不贴着船底了，才说一声“行了”，船就慢慢移动。眼前昏暗了，可是还能感觉左右和上方的山石似乎都在朝我挤压过来。我又感觉要是把头稍微抬起一点儿，准会撞破额角，擦伤鼻子。大约行了两三丈的水程吧，就登陆了。这就到了内洞。","内洞一团漆黑，什么都看不见。工人提着汽油灯，也只能照见小小的一块地方，余外全是昏暗，不知道有多么宽广。工人高高举起汽油灯，逐一指点洞内的景物。先看到的是蜿蜒在洞顶的双龙，一条黄龙，一条青龙。我顺着他的指点看，有点儿像。其他那些石钟乳和石笋，这是什么，那是什么，大都依据形状想象成神仙、动物以及宫室、器用，名目有四十多。这些石钟乳和石笋，形状变化多端，再加上颜色各异，即使不比作什么，也很值得观赏。","在洞里走了一转，觉得内洞比外洞大得多，大概有十来进房子那么大。泉水靠着右边缓缓地流，声音轻轻的。上源在深黑的石洞里。","我排队等候，又仰卧在小船里，出了洞。"]},{"id":307,"grade":"四年级下册","title":"习作例文","paragraphs":["北京的颐和园是个美丽的大公园。","进了颐和园的大门，绕过大殿，就来到有名的长廊。绿漆的柱子，红漆的栏杆，一眼望不到头。这条长廊有七百多米长，分成二百七十三间。每一间的横槛上都有五彩的画，画着人物、花草、风景，几千幅画没有哪两幅是相同的。长廊两旁栽满了花木，这一种花还没谢，那一种花又开了。微风从左边的昆明湖上吹来，使人神清气爽。","走完长廊，就来到了万寿山脚下。抬头一看，一座八角宝塔形的三层建筑耸立在半山腰上，黄色的琉璃瓦闪闪发光。那就是佛香阁。下面的一排排金碧辉煌的宫殿，就是排云殿。","登上万寿山，站在佛香阁的前面向下望，颐和园的景色大半收在眼底。葱郁的树丛，掩映着黄的绿的琉璃瓦屋顶和朱红的宫墙。正前面，昆明湖静得像一面镜子，绿得像一块碧玉。游船、画舫在湖面慢慢地滑过，几乎不留一点儿痕迹。向东远眺，隐隐约约可以望见几座古老的城楼和城里的白塔。","从万寿山下来，就是昆明湖。昆明湖围着长长的堤岸，堤上有好几座式样不同的石桥，两岸栽着数不清的倒垂的杨柳。湖中心有个小岛，远远望去，岛上一片葱绿，树丛中露出宫殿的一角。游人走过长长的石桥，就可以去小岛上玩。这座石桥有十七个桥洞，叫十七孔桥。桥栏杆上有上百根石柱，柱子上都雕刻着小狮子。这么多的狮子，姿态不一，没有哪两只是相同的。","颐和园到处有美丽的景色，说也说不尽，希望你有机会去细细游赏。","七月的新疆，最理想的是骑马上天山。","进入天山，戈壁滩上的炎暑被远远地抛在后边，迎面送来的雪山寒气，会使你感到像秋天似的凉爽。蓝天衬着高耸的巨大的雪峰，太阳下，雪峰间的云影就像白缎上绣了几朵银灰色的花。融化的雪水，从峭壁断崖上飞泻下来，像千百条闪耀的银链，在山脚下汇成冲激的溪流，浪花往上抛，形成千万朵盛开的白莲。每到水势缓慢的洄水涡，都有鱼儿在欢快地跳跃。这个时候，饮马溪边，你骑在马上，可以俯视阳光透射到的清澈的水底。在五彩斑斓的溪水和石子之间，鱼群闪闪的鳞光映着雪水清流，给寂静的天山增添了无限生机。","再往里走，天山显得越来越美。白皑皑群峰的雪线以下，是蜿蜒无尽的翠绿的原始森林，密密的塔松像撑开的巨伞，重重叠叠的枝丫，漏下班班点点细碎的日影。骑马穿行林中，只听见马蹄溅起漫流在岩石上的水的声音，使密林显得更加幽静。","走进天山深处，山色逐渐变得柔嫩，山形也逐渐变得柔美。这里溪流缓慢，萦绕着每一个山脚。在轻轻荡漾着的溪流的两岸，满是高过马头的野花，五彩缤纷，像织不完的锦缎那么绵延不断，像天边的霞光那么灿烂耀眼，像高空的彩虹那么绚丽夺目。马走在花海中，显得格外矫健；人浮在花海上，显得格外精神。在马上你用不着离鞍，只要稍一伸手就可以捧到满怀心爱的鲜花。","虽然天山这时并不是春天，但是有哪一个春天的花园能比得过这时天山的无边繁花呢？"]},{"id":308,"grade":"四年级下册","title":"囊萤夜读","paragraphs":["胤恭勤不倦，博学多通。家贫不常得油，夏月则练囊盛数十萤火以照书，以夜继日焉。","晋朝人车胤谨慎勤劳而不知疲倦，知识渊博，学问精通。他家境贫寒，不能经常得到灯油。夏天的夜晚，车胤就用白绢做成透光的袋子，装几十只萤火虫照着书本，夜以继日地学习着。"]},{"id":309,"grade":"四年级下册","title":"铁杵成针","paragraphs":["磨针溪，在象耳山下。世传李太白读书山中，未成，弃去。过是溪，逢老媪方磨铁杵。问之，曰：“欲作针。”太白感其意，还卒业。","磨针溪是在象耳山脚下。世世代代相传李白在山中读书的时候，没有完成好自己的学业，就放弃学习离开了。他路过一条小溪，遇见一位老妇人在磨铁棒，于是问她在干什么，老妇人说：“我想把它磨成针。”李白被她的精神感动，就回去完成学业。"]},{"id":310,"grade":"四年级下册","title":"19 小英雄雨来（节选）","paragraphs":["一","晋察冀边区的北部有一条还乡河，河里长着很多芦苇。河边有个小村庄。芦花开的时候，远远望去，黄绿的芦苇上好像盖了一层厚厚的白雪。风一吹，鹅毛般的苇絮就飘飘悠悠地飞起来，把这几十家小房屋都罩在柔软的芦花里。因此，这村就叫芦花村。十二岁的雨来就是这村的。","雨来最喜欢这条紧靠着村边的还乡河。每到夏天，雨来和铁头、三钻儿，还有很多小朋友，好像一群鱼，在河里钻上钻下，藏猫猫，狗刨，立浮，仰浮。雨来仰浮的本领最高，能够脸朝天在水里躺着，不但不沉底，还要把小肚皮露在水面上。","妈妈不让雨来耍水，怕出危险。有一天，妈妈见雨来从外面进来，光着身子，浑身被太阳晒得黝黑发亮。妈妈知道他又去耍水了，把脸一沉，叫他过来，扭身就到炕上抓笤帚。雨来一看要挨打了，撒腿就往外跑。","妈妈紧跟着追出来。雨来一边跑一边回头看。糟了！眼看要追上了。往哪儿跑呢？铁头正赶着牛从河沿回来，远远地向雨来喊：“往河沿跑！往河沿跑！”雨来听出了话里的意思，转身就朝河沿跑。妈妈还是死命追着不放，到底追上了，可是雨来浑身光溜溜的像条小泥鳅，怎么也抓不住。只听见扑通一声，雨来扎进河里不见了。妈妈立在河沿上，望着渐渐扩大的水圈直发愣。","忽然，远远的水面上露出个小脑袋来。雨来像小鸭子一样抖着头上的水，用手抹一下眼睛和鼻子，嘴里吹着气，望着妈妈笑。","二","秋天。","爸爸从集上卖苇席回来，同妈妈商量：“看见了区上的工作同志，说是孩子们不上学念书不行，起码要上夜校。叫雨来上夜校吧。要不，将来闹个睁眼瞎。”","夜校就在三钻儿家的豆腐房里，房子很破。教夜课的是东庄学堂里的女老师，穿着青布裤褂，胖胖的，剪着短发。女老师走到黑板前面，屋里嗡嗡嗡嗡说话的声音立刻停止了，只听见哗啦哗啦翻课本的声音。雨来从口袋里掏出课本，这是用土纸油印的，软鼓囊囊的。雨来怕揉坏了，向妈妈要了一块红布，包了个书皮，上面用铅笔歪歪斜斜地写了“雨来”两个字。雨来把书放在腿上，翻开书。","女老师斜着身子，用手指点着黑板上的字，念着：","“我们是中国人，","我们爱自己的祖国。”","大家就随着女老师的手指，齐声轻轻地念起来：","“我们—是—中国人，","我们—爱—自己的—祖国。”","三","有一天，雨来从夜校回到家，躺在炕上，背诵当天晚上学会的课文。可是背了不到一半，他就睡着了。","不知什么时候，门吱扭响了一声。雨来睁开眼，看见闪进一个黑影。妈妈划了根火柴，点着灯，一看，原来是爸爸出外卖席子回来了。他肩上披着子弹袋，腰里插着手榴弹，背上还背着一杆长长的步枪。爸爸怎么忽然这样打扮起来了呢？","爸爸对妈妈说：“鬼子又‘扫荡’了，民兵都到区上集合，要一两个月才能回来。”雨来问爸爸：“爸爸，远不远？”爸爸把手伸进被里，摸着雨来光溜溜的脊背，说：“这哪有准儿呢？说远就远，说近就近。”爸爸又转过脸对妈妈说：“明天你到东庄他姥姥家去一趟，告诉他舅舅，就说区上说的，叫他赶快把村里的民兵带到区上去集合。”妈妈问：“区上在哪儿？”爸爸装了一袋烟，吧嗒吧嗒抽着，说：“叫他们在河北一带村里打听。”","雨来还想说什么，可是门哐啷响了一下，就听见爸爸走出去的脚步声。不大一会儿，什么也听不见了，只从街上传来一两声狗叫。","第二天，吃过早饭，妈妈就到东庄去，临走说晚上才能回来。过了晌午，雨来吃了点儿剩饭，因为看家，不能到外面去，就趴在炕上念他那红布包着的识字课本。","忽然听见街上咕咚咕咚有人跑，把屋子震得好像摇晃起来，窗户纸哗啦哗啦响。","雨来一骨碌下了炕，把书塞在怀里就往外跑，刚要迈门槛，进来一个人，雨来正撞在这个人的怀里。他抬头一看，是李大叔。李大叔是区上的交通员，常在雨来家落脚。","随后听见日本鬼子呜哩哇啦地叫。李大叔忙把墙角那盛着一半糠皮的缸搬开。雨来愣住了：“咦！这是什么时候挖的洞呢？”李大叔跳进洞里，说：“把缸搬回原地方，你就快到别的院里去，对谁也不许说。”","十二岁的雨来使尽气力，才把缸挪回到原地。","雨来刚到堂屋，见十几把雪亮的刺刀从前门进来，他撒腿就往后院跑。背后咔啦一声枪栓响，有人大声叫道：“站住！”雨来没理他，脚下像踩着风，一直朝后院跑去。只听见子弹向他头上嗖嗖地飞来。可是后院没有门，把雨来急出一身冷汗。靠墙有一棵桃树，雨来抱着树就往上爬。鬼子已经追到树底下，伸手抓住雨来的脚，往下一拉，雨来就摔在地上。鬼子把他两只胳膊向背后一拧，捆绑起来，推推搡搡回到屋里。","四","鬼子把前后院都翻遍了。","屋子里遭了劫难，连枕头都给刺刀挑破了。炕沿上坐着个鬼子军官，两眼红红的，用中国话对雨来说：“小孩，问你话，不许撒谎！”他突然望着雨来的胸脯，张着嘴，眼睛睁得圆圆的。","雨来低头一看，原来刚才一阵子挣扎，识字课本从怀里露出来了。鬼子一把抓在手里，翻着看了看，问他：“谁给你的？”雨来说：“捡来的！”","鬼子露出满口金牙，做了个鬼脸，温和地对雨来说：“不要害怕！小孩，皇军是爱护的！”说着，就叫人给他松绑。","雨来把手放下来，觉得胳膊发麻发痛。扁鼻子军官用手摸着雨来的脑袋，说：“这本书谁给你的，没有关系，我不问了。别的话要统统告诉我！刚才有个人跑进来，看见没有？”雨来用手背抹了一下鼻子，嘟嘟囔囔地说：“我在屋里，什么也没看见。”","扁鼻子军官把书扔在地上，伸手往皮包里掏。雨来心里想：“掏什么呢？找刀子？鬼子生了气要挖小孩眼睛的！”只见他掏出来的却是一把雪白的糖块。","扁鼻子军官把糖往雨来手里一塞，说：“吃！你吃！你得说出来他在什么地方！”他又伸出那个戴金戒指的手指，说：“这个，金的，也给你！”","雨来没有接他的糖，也没有回答他。","旁边一个鬼子嗖地抽出刀来，瞪着眼睛要向雨来头上劈。扁鼻子军官摇摇头。两个人叽叽咕咕说了一阵。那鬼子向雨来横着脖子翻白眼，使劲把刀放回鞘里。","扁鼻子军官压住肚里的火气，用手轻轻地拍着雨来的肩膀，说：“我最喜欢小孩。那个人，你看见没有？说啊！”","雨来摇摇头，说：“我在屋里，什么也没看见。”","扁鼻子军官的目光立刻变得凶恶可怕，他向前弓着身子，伸出两只大手。啊！那双手就像鹰的爪子，扭着雨来的两只耳朵，向两边拉。雨来疼得直咧嘴。鬼子又抽出一只手来，在雨来的脸上打了两巴掌，又把他脸上的肉揪起一块，咬着牙拧。雨来的脸立刻变成白一块，青一块，紫一块。鬼子又向他胸脯上打了一拳。雨来打个趔趄，后退几步，后脑勺正碰在柜板上，但立刻又被抓过来，肚子撞在炕沿上。","雨来半天才喘过气来，脑袋里像有一窝蜂，嗡嗡地叫。他两眼直冒金星，鼻子流着血。一滴一滴的血滴下来，溅在课本那几行字上：","“我们是中国人，","我们爱自己的祖国。”","鬼子打得累了，雨来还是咬着牙，说：“没看见！”","扁鼻子军官气得暴跳起来，嗷嗷地叫：“枪毙，枪毙！拉出去，拉出去！”","五","太阳已经落下去。蓝蓝的天上飘着的浮云像一块一块红绸子，映在还乡河上，像开了一大朵一大朵鸡冠花。苇塘的芦花被风吹起来，在上面飘飘悠悠地飞着。","芦花村里的人听到河沿上响了几枪。老人们含着泪，说：","“雨来是个好孩子！死得可惜！”","“有志不在年高。”","芦花村的孩子们，雨来的好朋友铁头和三钻儿几个人，听到枪声都呜呜地哭了。","六","李大叔在地洞里等了好久，不见雨来来搬缸，就往另一个出口走。他试探着推开洞口的石板，扒开苇叶，院子里空空的，一个人影也没有，四处也不见动静。忽然听见街上有人吆喝：“豆腐啦！卖豆腐啦！”这是芦花村的暗号，李大叔知道敌人已经走远了。","可是怎么不见雨来呢？他跑到街上，看见许多人往河沿跑，一打听，才知道雨来被鬼子打死在河里了！","李大叔脑袋轰的一声，眼泪就流下来了。他一股劲地跟着人们向河沿跑。","到了河沿，别说尸首，连一滴血也没看见。","大家呆呆地在河沿上立着。还乡河静静的，河水打着漩涡哗哗地向下流去。虫子在草窝里叫着。不知谁说：“也许鬼子把雨来扔在河里，冲走了！”","大家就顺着河岸向下找。突然铁头叫起来：“啊！雨来！雨来！”","在芦苇丛里，水面上露出个小脑袋来。雨来还是像小鸭子一样抖着头上的水，用手抹一下眼睛和鼻子，扒着芦苇，向岸上的人问道：“鬼子走了？”","“啊！”大家都高兴得叫起来，“雨来没有死！雨来没有死！”","原来枪响以前，雨来就趁鬼子不防备，一头扎到河里去了。鬼子慌忙向水里打枪，可是我们的小英雄雨来已经从水底游到远处去了。"]},{"id":311,"grade":"四年级下册","title":"20* 我们家的男子汉","paragraphs":["我们家里有一个男子汉，那是姐姐的孩子。姐姐生下他后，就和姐夫到安徽去了，把他留在家中由我们来照看。","他对食物的兴趣","“他吃饭很爽气。”带他的保姆这么说他。确实，他吃饭吃得很好，量很多，范围很广——什么都要吃，而且吃得极有滋味。叫人看了不由得也会嘴馋起来。当然，和所有的孩子一样，他不爱吃青菜，可是我对他说：“不吃青菜会死的。”他便吃了，吃得很多。他不愿死，似乎是深感活着的乐趣的。他对所有的滋味都有兴趣，为了吃一客小笼包子，他可以耐心地等上三刻钟；他会为他喜欢吃的东西编儿歌一样的谜语。当实在不能再吃了的时候，他便吃自己的大拇指，吃得十分专心，以至前边的嘴唇都有些翘了起来。当《少林寺》风靡全国时，他也学会了一套足以乱真的醉拳。耍起来，眼神都恍惚了，十分入迷。他向往着去少林寺当和尚。可是我们告诉他，当和尚不能吃荤。他说：“用肉汤拌饭可以吗？”“不可以。”“那么棒冰可以吃吗？”他小心地问，是问“棒冰”，而不是冰激凌，甚至不是雪糕。“那山上恐怕是没有棒冰的。”我们感到非常抱歉。","他对独立的要求","不知从什么时候起，和他出去，他不愿让人牵他的手了。一只胖胖的小手在我的手掌里，像一条倔强的活鱼一样挣扎着。有一次，我带他去买东西，他提出要让他自己买。我给了他一角钱。他攥着钱，走近了柜台，忽然又胆怯起来。我说：“你递上钱，我帮你说好了。”“不要，不要，我自己说。”他说。到了柜台前，他又嘱咐我一句：“你不要讲话啊！”营业员终于过来了，他神情有点儿紧张，勇敢地开口了：“同志，买，买，买……”他忘了要买什么东西了。我终于忍不住了：“买一包山楂片。”他好久没说话，潦草地吃着山楂片，神情有些沮丧，我有点儿后悔起来。后来，他会自个儿拿着五个汽水瓶和一元钱到门口小店换橘子水了。他是一定要自己去的。假如我不放心，跟在他后面，他便停下脚步不走了：“你回去，回去嘛！”我只得由他去了。他买橘子水日益熟练起来，情绪日益高涨，最终变成了一种可怕的狂热。为了能尽快地拿着空瓶再去买，他便努力地喝橘子水。一个炎热的中午，我从外面回来，见他正在门口小店买橘子水。他站在冰箱前面，露出半个脑袋。营业员只顾和几个成年人做生意，看都不看他一眼。他满头大汗地，耐心地等待着。我很想走过去帮他叫一声“同志”，可最后还是忍住了。","他面对生活挑战的沉着","当他满两周岁的时候，我们决定把他送进托儿所。去的那天早晨，他一声不吭，很镇静地四下打量着。当别的孩子哭的时候，他才想起来哭。哭声嘹亮，并无伤感，似乎只为了参加一个仪式。每天早上，送他去托儿所都很容易，不像我们姐妹几个小时候那样，哭着闹着不肯去。问他喜欢托儿所吗，他说：“不喜欢。”可是他明白了自己不得不去，也就坦然地接受了这个现实，不作任何无效的挣扎。据老师说，他吃饭很好，睡觉很好，唱歌游戏都很好，只不过有点儿拘束。然而，他迅速地熟悉起来，开始交朋友，打架。每天去接他，都要听老师几句抱怨。","他四岁那年，他的保姆病了，回乡了，他终于要去安徽了。他是极不愿意去的。走的前一天，他对外婆说：“外婆，你不要我了，把我扔出去了。”外婆几乎动摇了，想把他留下。那时候，上海到合肥，每天只有一班火车，人很多。车门被行李和人堵满了，大人们只好先挤上车，把他留在月台上。他着急地喊起来：“我怎么办呢？”我安慰他：“上不去，就不走了。”他仍然很着急，认为自己是非走不可的。姐姐说：“让他从窗口爬进来吧！”我把他抱了起来，他勇敢地抓住窗框，两只脚有力地蹬着车厢，攀上了窗口。窗口边的旅客不约而同地伸手去抱他。他推开那些妨碍他的手，抓住一双最得力的，蹿进了车厢，淹没在拥挤的人群里了。","这就是我们家的男子汉。看着他一点儿一点儿长大，他的脸盘的轮廓，他的手掌上的细纹，他的身体，他的力气，他的智慧，他的性格，还有他的性别，那样神秘地一点儿一点儿鲜明，突出，扩大，再扩大，实在是一件最最奇妙的事情。"]},{"id":312,"grade":"四年级下册","title":"21* 芦花鞋","paragraphs":["这里出产一种冬天穿的芦花鞋。","那鞋的制作工序是：先将上等的芦花采回来，然后将它们均匀地搓进草绳里，再编织成鞋。那鞋很厚实，像暖和和的鸟窝。","收罢秋庄稼，青铜家就已决定：今年冬闲时，全家人一起动手，编织一百双芦花鞋，然后让青铜背着，到油麻地镇上去卖。","这是家里的一笔收入，一笔很重要的收入。想到这笔收入，全家人都很兴奋，觉得心里亮堂堂的，未来的日子亮堂堂的。","青铜拿着一只大布口袋，钻进芦苇荡的深处，挑那些毛茸茸的、蓬松松的、闪着银光的芦花，将它们从穗上捋下来。头年的不要，只采当年的。那芦花很像鸭绒，看着，心里就觉得暖和。妹妹葵花跟着青铜，一起走进芦苇荡。她仰起头来，不停地寻觅着，见到特别漂亮的一穗，她不采，总是喊：“哥，这儿有一穗！”青铜闻声，就会赶过来。见到葵花手指着的那一穗真是好花，就会笑眯眯的。","当第一双男鞋和第一双女鞋分别从爸爸和妈妈的手中编织出来时，全家人都很开心。两双鞋，在一家人手里传来传去地看个没够。","这两双芦花鞋，实在是太好看了。那柔软的芦花，竟像是长在上面的一般。被风一吹，那花都往一个方向倾覆而去，露出金黄的稻草来。让人想到落在树上的鸟，风吹起时，细软的绒毛被吹开，露出身子来。两双鞋，既像四只鸟窝，又像两对鸟。","青铜一家，老老少少，将所有空闲都用在了芦花鞋的编织上。他们编织了一百零一双鞋。第一百零一双是为青铜编的。青铜也应该有一双新的芦花鞋。","接下来的日子里，青铜天天背着几十双芦花鞋到油麻地镇上去卖。那些芦花鞋实在太招人喜欢了，一双一双地卖了出去，仅仅过了三天，就只剩下十一双了。","天下了一夜大雪，积雪足有一尺厚，早晨门都很难推开。雪还在下。","奶奶对青铜说：“今天就别去镇上卖鞋了。”爸爸妈妈也都对青铜说：“剩下的十一双，一双是给你的，还有十双，卖得了就卖，卖不了就留着自家人穿。”葵花也一个劲地说：“哥，今天就别去卖鞋了。”","但青铜却坚持着今天一定要去镇上。他对奶奶他们说：“今天天冷，更会有人买鞋的。”","妈妈说：“那你选一双穿上，不然就别去了。”","青铜同意了。他挑了一双适合他的芦花鞋，将脚洗得干干净净，穿上了。然后拿起余下的十双芦花鞋，朝大人们摇摇手，便跑进了风雪里。","到了镇上一看，街上几乎没有人，只有大雪不住地抛落在空寂的街面上。不一会儿，挂在绳子上的十双芦花鞋就落满了雪。","对面屋子里围炉烤火的人招呼青铜：“进屋里来吧，这里能看到你的鞋，丢不了。”青铜摇了摇手，坚持守在芦花鞋旁。","到了中午，雪大了起来，成团成团地往下抛落。望着漫天大雪，青铜在心里不住地说着：“买鞋的，快来吧！买鞋的，快来吧！……”","雪在他的祈求中，渐渐停了。青铜将芦花鞋一双双取下，把落在上面的积雪扑打干净后，重又挂到绳子上。","这时，街上走来一行路过这里的城里人，马上要过年了，他们要从这里坐轮船回城里去。他们或背着包，或提着包，一路说笑着，一路咯吱咯吱地踩着雪走过来。青铜没有招呼他们。因为他认为，城里人是不会买他的芦花鞋的，他们只穿布棉鞋和皮棉鞋。","但他们走过芦花鞋时，却有几个人停住了。其余的见这几个人停住了，也都停住了。那十双被雪地映照着的芦花鞋，一下吸引住了他们。其中肯定有一两个是搞艺术的，看着这些鞋，嘴里啧啧啧地感叹不已。他们忘记了它们的用途，只是觉得它们好看——不是一般地好看，而是特别地好看。他们一个个走上前来，用手抚摸着它们——这一抚摸，使他们对这些鞋更加喜欢。还有几个人将它们拿到鼻子底下闻了闻，一股稻草香，在这清新的空气里，格外分明。","一个人说：“买一双回去挂在墙上，倒不错。”好几个人点头，并各自取了一双，唯恐下手晚了，被别人拿了去。","一共九个人，都拿了芦花鞋，其中一个人拿了两双，十双鞋都在他们手中了。接下来就是谈价钱。青铜一直疑惑着，直到人家一个劲地问他多少钱一双，他才相信他们真的要买这些鞋。他没有因为他们的眼神里闪现出来的那份欣喜而涨价，还是报了他本来想卖的价。他们都觉得便宜，二话没说，就付了钱。青铜抓着一大把钱，站在雪地上，一时竟有点儿反应不过来。","天睛了，四周一片明亮。青铜沿着来时的路往回走着。","有一个人朝他追了过来，并在他身后大声喊着：“孩子，你停一停！”青铜停下了，转过身去，疑惑地望着向他跑过来的人。那人跑到青铜跟前，说：“我看到他们买的芦花鞋了，心里好喜欢，你还有卖的吗？”青铜摇了摇头，心里很为那人感到遗憾。那人失望地一摊手，并叹息了一声。青铜望着那个人，心里觉得有点儿对不住他。","那人掉头朝轮船码头走去。","青铜掉头往家走去。","走着走着，青铜放慢了脚步。他的目光落在了自己脚上的那双芦花鞋上。雪在芦花鞋下咯吱咯吱地响着。他越走越慢，后来停下了。他看看天空，看看雪地，最后又把目光落在了自己脚上的芦花鞋上。","他觉得双脚暖和和的。","但过了一会儿，他将右脚从芦花鞋里拔了出来，站在了雪地上。他的脚板顿时感到了一股针刺般的寒冷。他又将左脚从芦花鞋里拔了出来，站在了雪地上。又是一股刺骨的寒冷。他弯下腰，捡起了那双芦花鞋，放到眼前看着。因为一路上都是雪，那双鞋竟然没有一丝污迹，看上去完全是一双新鞋。他笑了笑，掉头朝那个人追了过去。","他的赤脚踏过积雪时，溅起了一蓬蓬雪屑……"]},{"id":313,"grade":"四年级下册","title":"语文园地","paragraphs":["作者：[唐代] 李白","众鸟高飞尽，","孤云独去闲。","相看两不厌，","只有敬亭山。","山中群鸟一只只高飞远去，天空中的最后一片白云也悠然飘走。","敬亭山和我对视着，谁都看不够，看不厌，看来理解我的只有这敬亭山了。","李白（701年－762年） ，字太白，号青莲居士，又号“谪仙人”，唐代伟大的浪漫主义诗人，被后人誉为“诗仙”，与杜甫并称为“李杜”，为了与另两位诗人李商隐与杜牧即“小李杜”区别，杜甫与李白又合称“大李杜”。据《新唐书》记载，李白为兴圣皇帝（凉武昭王李暠）九世孙，与李唐诸王同宗。其人爽朗大方，爱饮酒作诗，喜交友。李白深受黄老列庄思想影响，有《李太白集》传世，诗作中多为醉时写就，代表作有《望庐山瀑布》《行路难》《蜀道难》《将进酒》《早发白帝城》等。","囊萤夜读 悬梁刺股 凿壁偷光","铁杵成针 程门立雪 手不释卷","妈妈还是死命追着不放，到底追上了，可是雨来浑身光溜溜的像条小泥鰍，怎么也抓不住。","雨来像小鸭子一样抖着头上的水，用手抹一下眼睛和鼻子,嘴里吹着气，望着妈妈笑。","那双手就像鹰的爪子，扭着雨来的两只耳朵，向两边拉。","她似乎感到德军那几双恶狼般的眼睛都盯在越来越短的蜡烛上。","她跳着轻快的舞蹈。","那个小偷远远地盯着柜台里的珠宝。"]},{"id":314,"grade":"四年级下册","title":"芙蓉楼送辛渐","paragraphs":["作者：[唐代] 王昌龄","寒雨连江夜入吴，","平明送客楚山孤。","洛阳亲友如相问，","一片冰心在玉壶。","冷雨连夜洒遍吴地江天，清晨送走你后，独自面对着楚山离愁无限！","到了洛阳，如果洛阳亲友问起我来，就请转告他们，我的心依然像玉壶里的冰那样晶莹纯洁！","王昌龄 (698— 756），字少伯，河东晋阳（今山西太原）人。盛唐著名边塞诗人，后人誉为“七绝圣手”。早年贫贱，困于农耕，而立之年，始中进士。初任秘书省校书郎，又中博学宏辞，授汜水尉，因事贬岭南。与李白、高适、王维、王之涣、岑参等交厚。开元末返长安，改授江宁丞。被谤谪龙标尉。安史乱起，为刺史闾丘晓所杀。其诗以七绝见长，尤以登第之前赴西北边塞所作边塞诗最著，有“诗家夫子王江宁”之誉（亦有“诗家天子王江宁”的说法）。"]},{"id":315,"grade":"四年级下册","title":"塞下曲（夜黑雁飞高）","paragraphs":["作者：[唐代] 卢纶","月黑雁飞高，","单于夜遁逃。","欲将轻骑逐，","大雪满弓刀。","死寂之夜，乌云遮月，天边大雁惊飞，单于的军队想要趁着夜色悄悄潜逃。","正想要带领轻骑兵一路追赶，大雪纷纷扬扬落满了身上的弓刀。","卢纶（739年—799年），字允言，河中蒲州（今山西永济县）人。唐代诗人，大历十才子之一。唐玄宗天宝末年举进士，遇乱不第；唐代宗朝又应举， 屡试不第。大历六年，经宰相元载举荐，授阌乡尉；后由宰相王缙荐为集贤学士，秘书省校书郎，升监察御史。出为陕州户曹、河南密县令。之后元载、王缙获罪，遭到牵连。唐德宗朝，复为昭应县令，出任河中元帅浑瑊府判官，官至检校户部郎中。不久去世。著有《卢户部诗集》。"]},{"id":316,"grade":"四年级下册","title":"墨梅","paragraphs":["作者：[元代] 王冕","我家洗砚池头树，","朵朵花开淡墨痕。","不要人夸好颜色，","只留清气满乾坤。","我家洗砚池边有一棵梅树，朵朵开放的梅花都像是用淡淡的墨汁点染而成。","它不需要别人夸奖颜色多么好看，只是要将清香之气弥漫在天地之间。","王冕（1310年～1359年），字元章，号煮石山农，亦号食中翁、梅花屋主等，浙江省绍兴市诸暨枫桥人，元朝著名画家、诗人、篆刻家。他出身贫寒，幼年替人放牛，靠自学成才。有《竹斋集》3卷，续集2卷。一生爱好梅花，种梅、咏梅，又攻画梅。所画梅花花密枝繁，生意盎然，劲健有力，对后世影响较大。存世画迹有《南枝春早图》《墨梅图》《三君子图》等。能治印，创用花乳石刻印章，篆法绝妙。《明史》有传。"]},{"id":317,"grade":"四年级下册","title":"23 黄继光","paragraphs":["1952年10月，上甘岭战役打响了。这是朝鲜战场上最激烈的一次阵地战。","黄继光所在的营已经持续战斗了四天四夜，第五天夜晚接到上级的命令，要在黎明之前夺下被敌人占领的597.9高地。","进攻开始了，大炮在轰鸣。战士们占领了一个又一个山头，就要到达597.9高地的主峰了。突然，敌人一个火力点凶猛地射击起来。战士们屡次突击，都被比雨点还密的枪弹压了回来。","东方升起了启明星，营参谋长看看表，已经四点多了。如果不很快摧毁这个火力点，在黎明前就攻不下597.9高地的主峰，已经夺得的那些山头就会全部丢失。","黄继光愤怒地注视着敌人的火力点，他转过身来坚定地对营参谋长说：“参谋长，请把这个任务交给我吧！”营参谋长紧握着黄继光的手，说：“好，我相信你一定能完成这个光荣而艰巨的任务。”","黄继光带上两个战士，拿了手雷，喊了一声：“让祖国人民听我们胜利的消息吧！”，便向敌人的火力点爬去。","敌人发现他们了。几发照明弹升上天空，黑夜变成了白天。炮弹在他们周围爆炸。他们冒着浓烟，冒着烈火，匍匐前进。一个战士牺牲了，另一个战士也负伤了。摧毁火力点的重任落在了黄继光一个人的肩上。","火力点里的敌人把机枪对准黄继光，子弹像冰雹一样射过来。黄继光肩上腿上都负了伤。他用尽全身的力气，更加顽强地向前爬，还有二十米，十米……近了，更近了。","啊！黄继光突然站起来了！在暴风雨一样的子弹中站起来了！他举起右臂，手雷在探照灯的光亮中闪闪发光。","轰！敌人的火力点塌了半边，黄继光晕倒了。战士们赶紧冲上去，不料才冲到半路，敌人的机枪又叫起来，战士们被压在山坡上。","天快亮了，规定的时间马上到了。营参谋长正在着急，只见黄继光又站起来了！他张开双臂，向喷射着火舌的火力点猛扑上去，用自己的胸膛堵住了敌人的枪口。","“冲啊！为黄继光报仇！”喊声惊天动地。战士们像海涛一样向上冲，占领了597.9高地，消灭了阵地上的全部敌人。"]},{"id":318,"grade":"四年级下册","title":"24 “诺曼底”号遇难记","paragraphs":["1870年3月17日夜晚，哈尔威船长照例走着从南安普敦到根西岛这条航线。大海上夜色正浓，烟雾弥漫。船长站在驾驶室里，小心翼翼地驾驶着他的“诺曼底号”。乘客们都进入了梦乡。","“诺曼底号”是一艘大轮船，在英伦海峡也许可以算得上是最漂亮的邮船之一。它装货容量六百吨，船体长二百二十英尺，宽二十五英尺。海员们都说它很“年轻”，因为它才七岁，是1863年造的。","雾越来越浓了，轮船使出南安普敦河后，来到茫茫大海上，距离埃居伊山脉估计有十五海里。轮船缓缓行驶着。这时大约凌晨四点钟。","周围一片漆黑，船桅的梢尖隐约可辨。","像这类英国船，晚上出航是没有什么可怕的。","突然，沉沉夜雾中冒出一枚黑点，它好似一个幽灵，又仿佛一座山峰。只见一个阴森森的往前翘起的船头，突破黑暗，在一片浪花中飞驶过来。那是“玛丽号”，一艘装有螺旋推进器的大轮船，它从敖德萨起航，船上载着五百吨小麦，行驶速度非常快，负载又特别大。它笔直地朝着“诺曼底号”逼了过来。","眼看就要撞船，已经没有任何办法避开它了。一瞬间，大雾中似乎耸起许许多多船只的幻影，人们还没来得及一一看清，就要死在临头，葬身鱼腹了。","全速前进的“玛丽号”向“诺曼底号”的侧舷撞过去，在它的船身上剖开一个大窟窿。","由于这一猛撞，“玛丽号”自己也受了伤，终于停了下来。","“诺曼底号”上有二十八名船员和一名女服务员，还有三十一名乘客，其中十二名是妇女。","震荡可怕极了。一刹那间，男人、女人、小孩，所有的人都奔到甲板上，人们半裸着身子，奔跑着，尖叫着，哭泣着，惊恐万状，一片混乱。海水哗哗往里灌，汹涌湍急，势不可当。轮机火炉被海浪呛得嘶嘶地直喘粗气。","船上没有封舱用的防漏隔墙。哈尔威船长站在指挥台上，大声吼喝：“全体安静，注意听命令！把救生艇放下去。妇女先走，其他乘客跟上，船员断后。必须把六十人救出去！”","实际上一共有六十一人，但是他把自己给忘了。","船员赶紧解开救生艇的绳索。大家一窝蜂拥了上去，这股你推我搡的势头，险些把小艇都弄翻了。奥克勒福大副和三名工头拼命想维持秩序，但整个人群因为猝然而至的变故简直都像疯了似的，乱得不可开交。几秒钟前大家还在酣睡，蓦地，而且，立时立刻，就要丧命，这怎么不叫人失魂落魄！","就在这时，船长威严的声音压倒了一片呼号和嘈杂，黑暗中人们听到这一段简短有力的对话：","“洛克机械师在哪儿？”","“船长叫我吗？”","“炉子怎么样了？”","“海水淹了。”","“火呢？”","“灭了。”","“机器怎样？”","“停了。”","船长喊了一声：“奥克勒福大副？”","大副回答：“到！”","船长问道：“还有多少分钟？”","“二十分钟。”","“够了，”船长说，“让每个人都下到小艇上去。奥克勒福大副，你的手枪在吗？”","“在，船长。”","“哪个男人胆敢抢在女人前面，你就开枪打死他。”","大家立时不出声了。没有一个人违抗他的意志，人们感到有一个伟大的灵魂出现在他们的上空。","“玛丽号”也放下救生艇，赶来搭救由于它肇祸而遇难的人员。","救援工作进行得井然有序，几乎没有发生什么争执或殴斗。事情总是这样，哪里有可卑的利己主义，哪里也会有悲壮的舍己救人。","哈尔威巍然屹立在他的船长岗位上，指挥着，主宰着，领导着大家。他把每件事和每个人都考虑到了，面对惊慌失措的众人，他镇定自若，仿佛他不是给人而是给灾难下达命令，就连失事的船舶似乎也听从他的调遣。","过了一会儿，他喊道：“把克莱芒救出去！”","克莱芒是见习水手，还不过是个孩子。","轮船在深深的海水中慢慢下沉。","人们尽力加快速度划着小艇在“诺曼底号”和“玛丽号”之间来回穿梭。","“快干！”船长又叫道。","二十分钟到了，轮船沉没了。","船头先下去，须臾，海水把船尾也浸没了。","哈尔威船长一个手势也没有做，一句话也没有说，犹如铁铸，纹丝不动，随着轮船一起沉入了深渊。人们透过阴惨惨的雾气，凝视着这尊黑色的雕像徐徐沉进大海。","哈尔威船长的生命就这样结束了。","在英伦海峡上，没有任何一个海员能与他相提并论。","他一生都要求自己忠于职守，履行做人之道。面对死亡，他又践行了一次英雄的壮举。"]},{"id":319,"grade":"四年级下册","title":"25 挑山工","paragraphs":["在泰山上，随处都可以碰到挑山工。他们肩上搭一根光溜溜的扁担，扁担两头的绳子挂着沉甸甸的货物。登山的时候，他们一条胳膊搭在扁担上，另一条胳膊随着步子有节奏地一甩一甩，使身体保持平衡。他们走的路线是折尺形的，从台阶左侧起步，斜行向上，登上七八级，到了台阶右侧，就转过身子，反方向斜行，到了左侧再转回来。每转一次身，扁担换一次肩。这样曲折向上登，才能使挂在扁担前头的东西不碰到台阶，还可以省些力气。担了重物，如果照一般登山的人那样直往上走，膝盖会受不住的。但是路线曲折，就会使路程加长。挑山工登山走的路程大约比游人多一倍！","奇怪的是挑山工花的时间并不比游人多。你轻快地从他们身边走过，以为把他们远远地甩在后边了。你在什么地方饱览壮丽的山色，或者在道边诵读凿在石壁上的古人的题句，或者在喧闹的溪流边洗脸洗脚，他们已经不声不响地从你身旁走过，悄悄地走到前头去了。等你发现，你会大吃一惊，以为他们像仙人那样，是腾云驾雾赶上来的。","有一次，我同几个画友去泰山写生，就遇到过这种情况。我们在山下买登山用的青竹杖，遇到一个挑山工，矮个子，脸黑生生的，眉毛很浓，四十来岁，敞开的白土布褂子中间露出鲜红的背心。他扁担一头拴着几张木凳子，另一头捆着五六个青皮西瓜。我们很快就超过了他。到了回马岭那条陡直的山道前，我们累了，舒展身子躺在一块被山风吹得干干净净的大石头上歇歇脚。我们发现那个挑山工就坐在对面的草地上抽烟。随后，我们跟他差不多同时起程，很快就把他甩在后边，直到看不见他了。等到爬上半山的五松亭，我们看见有个人在那株姿态奇特的古松下整理挑子，那正是他。他把褂子脱掉了，光穿着红背心，现出健美的黑黝黝的肌肉。我很惊异，走过去跟他攀谈起来。这位山民倒不拘束，挺爱说话。他告诉我，他家住在山脚下，他天天挑货上山，干了近二十年了，一年四季，一天一个来回。","我把心中那个不解之谜说了出来：“我看你们走得很慢，怎么反而常常跑到我们前头去了呢？你们有什么近道吗？”","他听了，黑生生的脸上显出一丝得意的神色。他说：“我们哪里有近道，还不是和你们走的同一条道？你们肩膀上没有挑子，是走得快，可是一路上东看西看，玩玩闹闹，总得停下来嘛！我们跟你们不一样，不像你们那么随便，高兴怎么就怎么。一步踩不实不行，更不能耽误工夫。我们得一个劲往前走。别看我们慢，走长了就跑到你们前边去了。”","我心悦诚服地点着头，感到这位山民的几句朴素的话，似乎包蕴着意味深长的哲理。没等我细细体味，他担起挑子又起程了。","从泰山回来，我画了一幅画——在陡直的似乎没有尽头的山道上，一个穿红背心的挑山工给肩头的重物压弯了腰，他一步一步地向上攀登。这幅画一直挂在我的书桌前，因为我需要它。"]},{"id":320,"grade":"四年级下册","title":"语文园地","paragraphs":["和蔼 慷慨 贤惠 悲戚","临危不惧　彬彬有礼","焦躁不安　心急如焚","蔼 慷 慨 贤 戚 惧 彬 躁 焚","天行健，君子以自强不息。——《周易》","胜人者有力，自胜者强。——《老子》","不怨天，不尤人。——《论语》","生于忧患而死于安乐。——《孟子》"]},{"id":321,"grade":"四年级下册","title":"26 宝葫芦的秘密（节选）","paragraphs":["我来给你们讲个故事。可是我先得介绍介绍我自己：我姓王，叫王葆。我要讲的，正是我自己的一件事情，是我和宝葫芦的故事。","你们也许要问：“什么？宝葫芦？就是传说故事里的那种宝葫芦吗？”","不错，正是那种宝葫芦。","可是我要声明，我并不是什么神仙，也不是什么妖怪。我和你们一样，是一个平平常常的普通人。你们瞧，我是一个少先队员，我也和你们一样，很爱听故事。","至于宝葫芦的故事，那我从小就知道了。那是我奶奶讲给我听的。奶奶每逢要求我干什么，就得给我讲个故事。这是我们的规矩。","“乖小葆，来，奶奶给你洗个脚。”奶奶总是一面撵我，一面招手。","“我不干，我怕烫。”我总是一面溜开，一面摆手。","“不烫啊。冷了好一会儿了。”","“那，我怕冷。”","奶奶撵上了我，说洗脚水刚好不烫也不冷，非洗不可。","我只好让步。不过我有一个条件：“你爱洗就让你洗。你可得讲个故事。”就这么着，奶奶讲了个宝葫芦的故事。","“好小葆，别动！”奶奶刚给我洗了脚，忽然又提出一个新的要求来，“让我给你剪一剪……”","什么！剪脚指甲啊？那不行！我光着脚丫，一下地就跑。可是胳膊给奶奶拽住了。没有办法。","不过我得提出我的条件：“那，非得讲故事。”于是奶奶又讲了一个——又是宝葫芦的故事。","我就这么着，从很小的时候起，听奶奶讲故事，一直听到我十来岁。奶奶每次讲的都不一样。上次讲的是张三劈面撞见了一位神仙，得了一个宝葫芦。下次讲的是李四出去远足旅行，一游游到了龙宫，得到了一个宝葫芦。王五呢，他因为是一个好孩子，肯让奶奶给他换衣服，所以得到了一个宝葫芦。至于赵六得的一个宝葫芦——那是掘地掘出来的。","不管张三也好，李四也好，一得到了这个宝葫芦，可就幸福极了，要什么有什么。张三想：“我要吃水蜜桃。”立刻就有一盘水蜜桃。李四希望有一条大花狗，马上就冒出了那么一条——冲着他摇尾巴，舔他的手。","后来呢？后来不用说，他们全都过上了好日子。","我听了这些故事，常常就联系到自己：“我要是有了一个宝葫芦，我该怎么办？我该要些什么？”","一直到我长大了，有时候还想起它来。我有几次对着一道算术题发愣，不知道要怎么列式子，就由“8”字想到了宝葫芦——假如我有这么一个，那可就省心了。","我和同学们比赛种向日葵，我家里的那几棵长得又瘦又长，上面顶着一个小脑袋，可怜巴巴的样儿，比谁的也比不上。我就又想到了那个宝贝：“那，我得要一棵最好最好的向日葵，长得不能再棒的向日葵。”可那只不过是幻想罢了。","可我总还是要想到它。那一天我和科学小组的同学闹翻了，我又想到了它。“要是我有那么一个葫芦，那……”"]},{"id":322,"grade":"四年级下册","title":"27 巨人的花园","paragraphs":["每天下午，孩子们放学后，总喜欢到巨人的花园里去玩。","这是一个很可爱的大花园。园里长满了柔嫩的青草，草丛中到处露出星星似的美丽花朵。还有十二棵桃树，春天开出淡红色和珍珠色的鲜花，秋天结出丰硕的果子。小鸟们在树上唱着悦耳的歌，歌声是那么动听，孩子们都停止了游戏来听他们唱歌。“我们在这儿多么快乐！”孩子们欢叫着。","有一天，巨人回来了。之前，他离家去看朋友，在那里一住就是七年。现在他回到家，看见孩子们正在花园里玩。","“你们在这儿做什么？”他叱责道。孩子们吓得跑开了。","“我自己的花园就是我自己的花园，”巨人自言自语道，“这是随便什么人都懂得的。除了我自己以外，我不允许任何人在里面玩。”于是他在花园的四周砌了一道高墙，挂出一块布告牌:","禁止入内","违者重惩","那些可怜的孩子们现在没有地方玩了，只能在高墙外面转来转去，谈论着墙内美丽的花园。“我们从前在那儿是多么快乐啊！”他们都这样说。","春天来了，乡下到处开着小花，到处有小鸟歌唱。单单在巨人的花园里，仍旧是冬天的景象。小鸟不肯在他的花园里唱歌，因为那里没有孩子们的踪迹；桃树也忘了开花；偶尔有一朵美丽的花从草丛中伸出头来，可是一看见那块布告牌，就马上缩回到地里睡觉去了。高兴的只有雪和霜两位。他们嚷道:“春天把这个花园忘记了，我们一年到头都可以住在这儿啦！”雪用他的白色大衣覆盖着青草，霜把所有的树枝涂成了银色。他们还请来北风同住。北风身上裹着皮衣，整天在花园里呼啸着。他说：“这是个好地方，我们一定要请雹来玩一玩。”于是雹也来了。他每天总要在屋顶上闹三个钟头，然后又在花园里绕着圈子用力跑。","“我不懂为什么春天来得这样迟，”巨人坐在窗前，望着窗外那凄凉的花园，“我盼望天气快点儿变好。”","可是春天始终没有来，夏天也没有来。秋天给每个花园带来了金色果实，但巨人的花园却什么也没有。","一天早晨，巨人还在睡觉，忽然听见了动人的音乐。他以为是国王的乐队从门外走过，其实是一只小小的梅花雀在窗外唱歌。他很久没有听见小鸟在花园里唱歌了，觉得这是全世界最动听的音乐。这时，雹停止了疯闹，北风也不再吼叫，一缕阳光从窗外射进来。“春天到底来了。”巨人说。他跳下床往外看。","他看见一幅奇特的景象。孩子们从墙上一个小洞爬进花园里来了，他们都坐在桃树上面。桃树看见孩子们回来十分高兴，纷纷用花朵把自已装饰起来，还在孩子们头上轻轻地舞动胳膊。小鸟们快乐地飞舞歌唱。花儿们也从绿草丛中伸出头来。这的确是很可爱的景象。只有一个角落还是冬天。这是花园里最远的角落，一个小男孩正站在那里。他太小了，手还挨不到树枝，只好在树旁转来转去，哭得很厉害。这棵可怜的树仍然满身盖着雪和霜，北风还在树顶上吼叫。“快爬上来，孩子！”桃树一面对小男孩说，一面尽可能地把树枝垂下去，然而孩子还是太小了。","巨人看见这个情景，心也软了。他对自己说：“我多么自私啊！现在我明白为什么春天不肯到这儿来了。”他十分后悔自己先前的举动。","他轻轻地走下楼，静悄悄地打开前门，走进花园里。孩子们看见他，非常害怕，立刻逃走了，花园里又出现了冬天的景象。只有那个小男孩没有跑开，因为他的眼里充满了泪水，看不见巨人走过来。巨人悄悄地走到他后面，轻轻抱起他，放到树枝上。这棵树马上开花了，小鸟们也飞来歌唱。小男孩伸手搂住巨人，亲吻着他的脸颊。别的孩子看见巨人不再像先前那样凶狠了，也都跑了回来。春天也跟着一起回来了。巨人对他们说：“孩子们，花园现在是你们的了。”他拿出一把大斧子，拆除了围墙。","从那以后，巨人的花园又成了孩子们的乐园。孩子们站在巨人的脚下，爬上巨人的肩膀，尽情地玩耍。","许多年过去，巨人老了。他不能再跟孩子们一块儿玩了，只能坐在椅子上看孩子们玩各种游戏，同时也欣赏着他自己的花园。他说：“我有许多美丽的花，可孩子们却是最美丽的花。”"]},{"id":323,"grade":"四年级下册","title":"28* 海的女儿","paragraphs":["在海的远处，水是那么蓝，像最美丽的矢车菊花瓣；又是那么清，像最明亮的玻璃。同时它又是那么深，深得任何铁锚都达不到底。要想从海底一直达到水面，必须把许多许多教堂的尖塔一个一个地叠起来才成。海底的人就住在这下面。","不过，千万不要以为那儿只是一片铺满了白沙的海底。不是的，那儿生长着最奇异的树木和其他植物。它们的枝干和叶子是那么柔软，只要水轻微地流动一下，它们就摇动起来，好像活的一样。鱼儿们在这些枝叶中间游来游去，像是天空中的飞鸟。海里最深的地方有一座海王的宫殿。它的墙是用珊瑚砌成的，尖顶的高窗子是用最亮的琥珀做成的，屋顶上铺着黑色的蚌壳，它们随着水的流动可以自动开合。这简直太好看了，因为每一个蚌壳里面都含有亮晶晶的珍珠。随便哪一颗珍珠都可以成为王后皇冠上最耀眼的装饰品。","住在海底的海王已经独自生活了好多年，他的老母亲为他管理着家务。她是一个聪明的女人，可是对于自己高贵的出身总感到不可一世，因此她的尾巴上老是戴着一打牡蛎——其余的显贵只能每人戴上半打。除此以外，她是值得大加称赞的，特别是因为她非常爱那些小小的海公主——她的孙女们。她们是六个美丽的女孩，而她们之中，那位最年幼的要算是最美丽的了。她的皮肤光滑柔嫩，像玫瑰的花瓣；她的眼睛是蔚蓝色的，像最深的湖水。不过跟其他公主一样，她没有腿，她的下身是一条鱼尾。","她们可以把漫长的日子消磨在王宫里，在墙上长着鲜花的大厅里。那些琥珀镶的大窗子是开着的，鱼儿向她们游去，正如我们打开窗子的时候，燕子会飞进来一样。不过鱼儿会一直游向这些公主，在她们手里找东西吃，让她们抚摸自己。","宫殿外面有一座很大的花园，里边生长着许多火红和深蓝色的树木。树上的果子亮得像黄金，花朵开得像燃烧着的火，枝干和叶子在不停地摇动。地上全是最细的沙子，蓝得像硫黄发出的光焰。在那儿，处处都闪烁着一种奇异的蓝色光彩。你很容易以为自己是在高高的空中而不是在海底，你的头上和脚下全是一片蓝天。当海非常沉静的时候，你可以瞥见太阳：它像一朵紫色的花，从它的花萼里射出各种颜色的光。","在花园里，每一位公主都有自己的一小块地方，在那里她们可以随意栽种。有的把自己的花坛布置得像一条鲸鱼，有的觉得最好把自己的花坛布置得像一个小人鱼。可是最年幼的那位却把自己的花坛布置得圆圆的，像一轮太阳，同时她也只种像太阳一样红的花。她是一个古怪的孩子，不大爱讲话，总是静静地在想着什么。当姐姐们从沉船中弄来新奇的东西装点花园的时候，她除了火红的花以外，只想要一个美丽的大理石像。这石像是一个美丽的男子，它是用一块洁白的石头雕刻出来的，跟一条遭难的船一同沉到海底。在石像旁边，她种了一株像玫瑰花那样红的垂柳。这树长得非常茂盛，它新鲜的枝叶垂向石像，一直垂到那蓝色的沙底。它的倒影带有一种紫蓝的色调。像它的枝条一样，这影子也从不静止：树根和树顶看起来好像在做着亲昵的游戏。","她最大的乐趣是听关于我们人类世界的故事。她的老祖母不得不把自己所知道的关于船只和城市、人类和动物的知识全都讲给她听。特别使她感到美好的事情是：地上的花能散发出香气，而海底的花却不能；地上的森林是绿色的，而且在树枝间游来游去的鱼儿会唱得那么清脆和好听。老祖母所说的“鱼儿”其实就是小鸟，但是假如她不这样讲的话，小公主就听不懂她的故事了，因为小公主还从来没有看到过一只小鸟。","“等你满了十五岁，”老祖母说，“我就准许你浮到水面上去。那时你可以坐在月光底下的石头上面，看巨大的船只从你身边驶过。你也可以看到树林和城市。”","在一年之内，她最大的姐姐就要满十五岁了。可是其余的呢——她们一个比一个小一岁。因此，小公主还要足足地等五个年头才能从海底浮上来，来看看我们的世界。不过，每一位公主都答应大家说，她要把自己第一天看到和发现的东西讲给大家听，因为她们的老祖母所讲的确实不太够——她们希望了解的东西真不知有多少！","她们谁也没有那位最年幼的妹妹渴望得厉害，而她恰恰要等最久，同时她是那么地沉默和富于深思。不知道有多少个夜晚，她站在开着的窗子旁边，透过深蓝色的水朝上面凝望，凝望着鱼儿摆动它们的尾巴和翅。她还看到月亮和星星——当然，它们射出的光显得比较弱，但是透过海水，它们看起来要比我们人眼看到的大得多。假如有一块类似黑云的东西在它们下面浮过去的话，她便知道，这如果不是一条鲸鱼从她上面游过，就是一条装载着许多旅客的船在航行。可是那些旅客们怎么也想不到，他们下面有一位美丽的小人鱼，正朝着他们的船伸出一双洁白的小手。","现在，那位最大的公主已经到了十五岁，可以浮到水面上去了。"]},{"id":324,"grade":"四年级下册","title":"语文园地","paragraphs":["少年不知勤学苦，","老来方知读书迟。","一日读书一日功，","一日不读十日空。","学习不怕根底浅，","只要迈步总不迟。","书山有路勤为径，","学海无涯苦作舟。","这时候，小小的天窗是你唯一的慰藉。","每当我伤心难过时，总会得到好朋友小杰的安慰。","这个字怎么写？我忘记了。","任岁月潺潺流淌，不能忘怀的，始终是老师深情的目光。"]},{"id":325,"grade":"五年级上册","title":"1 白鹭","paragraphs":["白鹭是一首精巧的诗。","色素的配合，身段的大小，一切都很适宜。","白鹤太大而嫌生硬，即使如粉红的朱鹭或灰色的苍鹭，也觉得大了一些，而且太不寻常了。","然而白鹭却因为它的常见，而被人忘却了它的美。","那雪白的蓑毛，那全身的流线型结构，那铁色的长喙，那青色的脚，增之一分则嫌长，减之一分则嫌短，素之一忽则嫌白，黛之一忽则嫌黑。","在清水田里，时有一只两只白鹭站着钓鱼，整个的田便成了一幅嵌在玻璃框里的画。田的大小好像是有心人为白鹭设计的镜匣。","晴天的清晨，每每看见它孤独地站立于小树的绝顶，看来像是不安稳，而它却很悠然。这是别的鸟很难表现的一种嗜好。人们说它是在望哨，可它真是在望哨吗？","黄昏的空中偶见白鹭的低飞，更是乡居生活中的一种恩惠。那是清澄的形象化，而且具有生命了。","或许有人会感到美中不足，白鹭不会唱歌。但是白鹭本身不就是一首很优美的歌吗？","——不，歌未免太铿锵了。","白鹭实在是一首诗，一首韵在骨子里的散文诗。"]},{"id":326,"grade":"五年级上册","title":"2 落花生","paragraphs":["我们家的后园有半亩空地。母亲说：“让它荒着怪可惜的，你们那么爱吃花生，就开辟出来种花生吧。”我们姐弟几个都很高兴，买种，翻地，播种，浇水，没过几个月，居然收获了。","母亲说：“今晚我们过一个收获节，请你们的父亲也来尝尝我们的新花生，好不好？”母亲把花生做成了好几样食品，还吩咐就在后园的茅亭里过这个节。","那晚的天色不大好，可是父亲也来了，实在很难得。","父亲说：“你们爱吃花生吗？”","我们争着回答：“爱！”","“谁能把花生的好处说出来？”","姐姐说：“花生的味道很美。”","哥哥说：“花生可以榨油。”","我说：“花生的价钱便宜，谁都可以买来吃，都喜欢吃。这就是它的好处。”","父亲说：“花生的好处很多，有一样最可贵。它的果实埋在地里，不像桃子、石榴、苹果那样，把鲜红嫩绿的果实高高地挂在枝上，使人一见就生爱慕之心。你们看它矮矮地长在地上，等到成熟了，也不能立刻分辨出来它有没有果实，必须挖起来才知道。”","我们都说是，母亲也点点头。","父亲接下去说：“所以你们要像花生，它虽然不好看，可是很有用。”","我说：“那么，人要做有用的人，不要做只讲体面，而对别人没有好处的人。”","父亲说：“对。这是我对你们的希望。”","我们谈到深夜才散。花生做的食品都吃完了，父亲的话却深深地印在我的心上。"]},{"id":327,"grade":"五年级上册","title":"3 桂花雨","paragraphs":["中秋节前后，正是故乡桂花盛开的时节。","小时候，我无论对什么花，都不懂得欣赏。父亲总是指指点点地告诉我，这是梅花，那是木兰花……但我除了记些名字外，并不喜欢。我喜欢的是桂花。桂花树的样子笨笨的，不像梅树那样有姿态。不开花时，只见到满树的叶子；开花时，仔细地在树丛里寻找，才能看到那些小花。可是桂花的香气，太迷人了。","故乡靠海，八月是台风季节。桂花一开，母亲就开始担心了：“可别来台风啊！”母亲每天都要在前后院子走一回，嘴里念着：“只要不来台风，我就可以收几大箩。送一箩给胡家老爷爷，送一箩给毛家老婆婆，他们两家糕饼做得多。”","桂花盛开的时候，不说香飘十里，至少前后左右十几家邻居，没有不浸在桂花香里的。桂花成熟时，就应当“摇”。摇下来的桂花，朵朵完整、新鲜。如果让它开过了，落在泥土里，尤其是被风吹落，比摇下来的香味就差多了。","摇花对我来说是件大事，我总是缠着母亲问：“妈，怎么还不摇桂花呢？”母亲说：“还早呢，花开的时间太短，摇不下来的。”可是母亲一看天上布满阴云，就知道要来台风了，赶紧叫大家提前摇桂花。这下，我可乐了，帮大人抱着桂花树，使劲地摇。摇哇摇，桂花纷纷落下来，我们满头满身都是桂花。我喊着：“啊！真像下雨，好香的雨呀！”","桂花摇落以后，挑去小枝小叶，晒上几天太阳，收在铁盒子里，可以加在茶叶里泡茶，过年时还可以做糕饼。全年，整个村子都浸在桂花的香气里。","我念中学的时候，全家到了杭州。杭州有一处小山，全是桂花树，花开时那才是香飘十里。秋天，我常到那儿去赏桂花。回家时，总要捡一大袋桂花给母亲。可是母亲说：“这里的桂花再香，也比不上家乡院子里的桂花。”","于是，我又想起了在故乡童年时代的“摇花乐”，还有那摇落的阵阵桂花雨。"]},{"id":328,"grade":"五年级上册","title":"4* 珍珠鸟","paragraphs":["真好！朋友送我一对珍珠鸟，放在一个简易的竹条编成的笼子里，笼内还有一卷干草，那是小鸟舒适又温暖的巢。","有人说，这是一种怕人的鸟。","我把鸟笼挂在窗前。那儿还有一大盆异常茂盛的法国吊兰。我便用吊兰长长的、串生着小绿叶的垂蔓蒙盖在鸟笼上。它们就像躲进深幽的丛林一样安全，从中传出的笛儿般又细又亮的叫声，也就格外轻松自在了。小鸟的影子就在这中间隐约闪动，看不完整，有时连笼子也看不出，却见它们可爱的鲜红小嘴从绿叶中伸出来。","我很少扒开垂蔓瞧它们，它们便渐渐敢伸出小脑袋瞅瞅我。我们就这样一点点熟悉了。","三个月后，那一团越发繁茂的垂蔓里边，发出一种尖细又娇嫩的鸣叫。我猜到，是它们有了雏儿。我呢，决不掀开叶片往里看，连添食加水时也不睁大好奇的眼睛去惊动它们。过不多久，忽然有一个更小的脑袋从叶间探出来。哟，雏儿！正是这小家伙！","它小，就能轻易地由疏格的笼子里钻出来。瞧，多么像它的父母：红嘴红脚，灰蓝色的毛，只是后背还没生出珍珠似的圆圆的白点。它好肥，整个身子好像一个蓬松的球儿。","起先，这小家伙只在笼子四周活动，随后就在屋里飞来飞去，一会儿落在柜顶上，一会儿神气十足地站在书架上，啄着书脊上那些大文豪的名字，一会儿把灯绳撞得来回摇动，跟着逃到画框上去了。只要大鸟在笼里生气地叫一声，它就立即飞回笼里去。","我不管它。这样久了，打开窗子，它最多只在窗框上站一会儿，决不飞出去。","渐渐它胆子大了，就落在我的书桌上。它先是离我较远，见我不去伤害它，便一点点挨近，然后蹦到我的杯子上，俯下头来喝茶，再偏过脸瞧瞧我的反应。我只是微微一笑，依旧写东西。它就放开胆子跑到稿纸上，绕着我的笔尖蹦来蹦去，跳动的小红爪子在纸上发出嚓嚓的响声。","我不动声色地写，默默享受着这小家伙亲近的情意。这样，它完全放心了，索性用那涂了蜡似的小红嘴，嗒嗒地啄着我颤动的笔尖。我用手抚一抚它细腻的绒毛，它也不怕，反而友好地啄两下我的手指。","白天，它这样淘气地陪伴我；天色入暮，它就在父母再三的呼唤声中，飞向笼子，扭动滚圆的身子，挤开那些绿叶钻进去。","有一天，我伏案写作时，它居然落到我的肩上。我手中的笔不觉停了，生怕惊跑它。待一会儿，扭头看，这小家伙竟趴在我的肩头睡着了，银灰色的眼睑盖住眸子，小红爪子刚好被胸脯上长长的绒毛盖住。我轻轻抬一抬肩，它没醒，睡得好熟！还咂咂嘴，难道在做梦？","我笔尖一动，流泻下一时的感受：","信赖，往往创造出美好的境界。"]},{"id":329,"grade":"五年级上册","title":"语文园地","paragraphs":["我发现本单元的课文写的都是事物，有的蕴含着作者浓浓的感情，有的引发了作者深深的思考。","琦君笔下的桂花雨，不仅带给她许多童年的快乐回忆，也寄托了她浓浓的思乡之情，使我很受感动。","《落花生》中，作者借花生朴实无华、用处很多的特点说明做人的道理，让我深受启发。","它的果实埋在地里，不像桃子、石榴、苹果那样，把鲜红嫩绿的果实高高地挂在枝上，使人一见就生爱慕之心。白鹭色素的配合，身段的大小，一切都很适宜。白鹤太大而嫌生硬，即使如粉红的朱鹭或灰色的苍鹭，也觉得大了一些，而且太不寻常了。青、红的瓜，碧绿的藤和叶，构成了一道别有风趣的装饰，比那高楼门前蹲着一对石狮子或是竖着两根大旗杆，可爱多了。","开辟","让它荒着怪可惜的，你们那么爱吃花生，就开辟出来种花生吧","人工智能的出现为人类的生活开辟了一片新天地。","姿态","桂花树的样子笨笨的，不像梅树那样有姿态。","大家以全新的姿态迎接新年的到来。","温和","（形容气候）","（形容性格）","作者：[唐代] 虞世南","垂緌饮清露，","流响出疏桐。","居高声自远，","非是藉秋风。","蝉垂下像帽缨一样的触角吸吮着清澈甘甜的露水，连续不断的鸣叫声从稀疏的梧桐树枝间传出。","蝉正是因为在高处它的声音才能传得远，并非是凭借秋风的力量。","虞世南（558年－638年7月11日），字伯施，汉族，越州余姚（今浙江省慈溪市观海卫镇鸣鹤场）人。南北朝至隋唐时期书法家、文学家、诗人、政治家，凌烟阁二十四功臣之一。陈朝太子中庶子虞荔之子、隋朝内史侍郎虞世基之弟。虞世南善书法，与欧阳询、褚遂良、薛稷合称“初唐四大家”。日本学界称欧阳询、褚遂良、虞世南为“初唐三大家”。其所编的《北堂书钞》被誉为唐代四大类书之一，是中国现存最早的类书之一。原有诗文集三十卷，但已散失不全。民国张寿镛辑成《虞秘监集》 四卷。"]},{"id":330,"grade":"五年级上册","title":"5 搭石","paragraphs":["我的家乡有一条无名小溪，五六个小村庄分布在小溪的两岸。小溪的流水常年不断。每年汛期，山洪暴发，溪水猛涨。山洪过后，人们出工、收工、赶集、访友，来来去去，必须脱鞋挽裤。进入秋天，天气变凉，家乡的人们会根据水的深浅，从河的两岸找来一些平整方正的石头，按照二尺左右的间隔，在小溪里横着摆上一排，让人们从上面踏着过去，这就是搭石。","搭石，构成了家乡的一道风景。秋凉以后，人们早早地将搭石摆放好。如果别处都有搭石，唯独这一处没有，人们会责备这里的人懒惰。上了点儿年岁的人，无论怎样急着赶路，只要发现哪块搭石不平稳，一定会放下带的东西，找来合适的石头搭上，再在上边踏上几个来回，直到满意了才肯离去。","家乡有一句“紧走搭石慢过桥”的俗语。搭石，原本就是天然石块，踩上去难免会活动，走得快才容易保持平衡。人们走搭石不能抢路，也不能突然止步。如果前面的人突然停住，后边的人没处落脚，就会掉进水里。每当上工、下工，一行人走搭石的时候，动作是那么协调有序！前面的抬起脚来，后面的紧跟上去。嗒嗒的声音，像轻快的音乐；清波漾漾，人影绰绰，给人画一般的美感。","经常到山里的人，大概都见过这样的情景：如果有两个人面对面同时走到溪边，总会在第一块搭石前止步，招手示意，让对方先走；等对方过了河，两人再说上几句家常话，才相背而行。假如遇上老人来走搭石，年轻人总要俯下身子背老人过去，人们把这看成理所当然的事。","一排排搭石，任人走，任人踏，它们联结着故乡的小路，也联结着乡亲们美好的情感。"]},{"id":331,"grade":"五年级上册","title":"6 将相和","paragraphs":["战国时，秦国很强大，常常进攻别的国家。","有一回，赵王得了一件无价之宝，叫和氏璧。秦王知道了，就写了一封信给赵王，说是愿意拿十五座城换这块璧。","赵王接到信后非常着急，立即召集大臣来商议。大家说秦王不过是想把和氏璧骗到手罢了，不能上他的当；可要是不答应，又怕他派兵来进攻。","正在为难的时候，有人说有个叫蔺相如的人，勇敢机智，也许他能解决这个难题。","赵王把蔺相如找来，问他该怎么办。","蔺相如想了一会儿，说：“如果秦国提出用城换璧，我国却不答应，那理亏的是我们。如果我们把和氏璧给了秦国，秦国却不给我们十五座城，那理亏的就是他们。我愿意带着和氏璧到秦国去。如果秦王真的拿十五座城来换，我就把璧交给他；如果他不肯交出十五座城，我一定把璧完好无缺地送回来。”于是赵王就派蔺相如带着和氏璧去了秦国。","蔺相如到了秦国，进宫见了秦王，献上和氏壁。秦王双手捧住璧，一边看一边称赞，绝口不提十五座城的事。蔺相如看这情形，知道秦王没有拿城换璧的诚意，就上前一步，说：“这块璧有点儿小毛病，让我指给您看。”秦王听他这么一说，就把和氏璧交给蔺相如。蔺相如捧着璧，往后退了几步，靠着柱子站定。他怒发冲冠，说：“我看您并不想交付十五座城。现在璧在我手里，您要是强逼我，我的脑袋就和璧一起撞碎在这柱子上！”说着，他举起和氏璧就要向柱子上撞。秦王怕他真的把璧撞碎了，连忙说一切都好商量，就叫人拿出地图，把允诺划归赵国的十五座城指给他看。蔺相如说和氏璧是无价之宝，要举行个隆重的典礼，他才能交出来。秦王只好跟他约定了举行典礼的日期。","蔺相如反复思量，觉得秦王还是不会信守承诺的，一到客舍，就叫手下人化了装，带着和氏璧抄小路先回赵国去了。到了举行典礼那一天，蔺相如进宫见了秦王，说：“秦国的国君历来不守信用，我怕有负赵王所托，已经让人把和氏璧送回赵国了。如果您有诚意，先把十五座城交给我国，我国马上派人把壁送来。我们怎么敢为了一块璧而得罪强大的秦国呢？我知道欺骗了您是死罪，您可以杀了我，但请好好考虑我的话。”秦王没有办法，只得客客气气地把蔺相如送回了赵国。","这就是“完璧归赵”的故事。蔺相如立了功，赵王封他做上大夫。","过了几年，秦王约赵王在渑池会面。赵王胆怯，不敢去。但蔺相如和大将军廉颇认为对秦王不能示弱，还是去的好，赵王才决定动身，让蔺相如随行。廉颇带着军队送他们到边境上，作好了抵御秦军的准备。","赵王到渑池与秦王会面。秦王要赵王鼓瑟。赵王不好推辞，鼓了一段。秦王就叫人记录下来，说在渑池会上，秦王令赵王鼓瑟。","蔺相如看秦王存心侮辱赵王，便向前走了几步，说：“赵王听说秦王擅长秦国的音乐，希望您能击缶助兴。”秦王很生气，拒绝了。蔺相如再次上前要求，秦王还是拒绝。蔺相如说：“您现在离我只有五步远。如果您不答应，我就跟您同归于尽！”秦王左右的卫士想杀了蔺相如，但蔺相如怒目圆睁，厉声呵斥，卫士竟不敢上前。秦王被逼得没办法，只好敲了一下缶。蔺相如也叫人记录下来，说在渑池会上，秦王为赵王击缶。","秦国的大臣不甘心，继续发难，但蔺相如毫不示弱，直到会面结束，秦王也没占到便宜。秦王知道廉颇已经在边境上作好了准备，不敢拿赵王怎么样，只好让赵王回去。","蔺相如在渑池会上又立了功。赵王封蔺相如为上卿，职位比廉颇还高。","廉颇很不服气，他对别人说：“我廉颇立下了那么多战功，他蔺相如就靠一张嘴，反而爬到我头上去了。要是我碰见他，一定要让他下不来台！”蔺相如听说了，就请病假不上朝，免得跟廉颇见面。","有一天，蔺相如坐车出去，远远看见廉颇过来了，他赶紧叫车夫把车往回赶。蔺相如的门客们可看不顺眼了，对蔺相如说：“您见了廉颇像老鼠见了猫似的，为什么要怕他呢？”蔺相如说：“诸位请想一想，廉将军和秦王比，谁厉害？”门客们说：“当然是秦王厉害！”蔺相如说：“秦王我都不怕，还会怕廉将军吗？秦王之所以不敢进攻我们赵国，就是因为有我们两个人在。如果我们俩闹不和，就会削弱赵国的力量，秦国必然乘机来攻打我们。我之所以避着廉将军，为的是我们赵国啊！”","蔺相如的话传到了廉颇的耳朵里。廉颇静下心来想了想，觉得自己为了争一口气，就不顾国家利益，真不应该。于是，他脱下战袍，背上绑着荆条，到蔺相如门上请罪。蔺相如见廉颇来请罪，连忙出来迎接。从此以后，他们俩成了好朋友，同心协力保卫赵国。"]},{"id":332,"grade":"五年级上册","title":"7 什么比猎豹的速度更快","paragraphs":["也许你跑得很快。不过要是你跟猎豹或鸵鸟赛跑的话，就一点儿赢的希望也没有了。","人在奋力奔跑的时候，最大速度能够达到44千米每小时。这个速度跟鸵鸟比起来差远了——鸵鸟奔跑的最大速度约72千米每小时。在两条腿的动物里面，鸵鸟应该算是奔跑的世界冠军。","比鸵鸟跑得更快的动物就要数猎豹了。猎豹奔跑的最大速度可达110千米每小时。猎豹才是陆地上跑得最快的动物。","但是游隼向下俯冲时的速度更快，超过320千米每小时。这个速度是汽车在高速公路上飞速行驶时速度的两到三倍。它俯冲时的速度比任何一种动物奔跑时的速度都要快。","不过，游隼还是没有飞机飞行的速度快。在喷气式飞机飞行的高度，声音传播的速度大约是1050千米每小时，而一些高速喷气式飞机的飞行速度是声速的数倍。如果你对着一个以超音速移动的人大喊，他是什么都听不见的。因为声音根本就追不上他。","乘坐喷气式飞机去旅行，速度绝对是够快的了。但是，如果你想到月球上去，就需要搭乘速度更快的工具了。对！我们需要一枚火箭。为了摆脱地心引力，飞到浩瀚的太空中，火箭的速度要比喷气式飞机的速度快得多才行。火箭的最大速度能达到4万千米每小时，是声速的30多倍。进入太空之后，即使关掉发动机，火箭仍可以继续前进。","看！前面呼啸而过的东西是什么？跟它的速度一比，火箭就好像是静止的一样。那是流星体！流星体是太空中一种较小的天体。有的流星体运动的最大速度能达到25万千米每小时，是火箭运动速度的6倍多。","现在，你一定会认为流星体是人们所能见到的速度最快的物体。不过，还有比流星体运动速度快得多的东西，而且它就在我们身边。只要我们按下手电筒的开关，立刻会出现一束光柱。光的速度是惊人的，大约是30万千米每秒，比流星体的速度要快几千倍！如果按照光速运动，我们一秒钟就可以沿着地球赤道转7圈多，真是令人难以置信！"]},{"id":333,"grade":"五年级上册","title":"8 冀中的地道战","paragraphs":["1942到1944那几年，日本侵略军在冀中平原上“大扫荡”，还修筑了封锁沟和封锁墙，十里一碉，八里一堡，想搞垮我们的人民武装。","为了粉碎敌人的“扫荡”，冀中人民在中国共产党的领导下，创造了新的斗争方式，这就是地道战。","说起地道战，简直是个奇迹。在广阔平原的地底下，挖了不计其数的地道，横的，竖的，直的，弯的，家家相连，村村相通。敌人来了，我们就钻到地道里去，让他们扑个空;敌人走了，我们就从地道里出来，照常种地过日子，有时候还要打击敌人。靠着地道这种坚强的堡垒，冀中平原上的人民坚持了敌后游击战争。","地道的式样有一百多种。就拿任丘的来说吧，村里的地道挖在街道下面，跟别村相通的地道挖在庄稼地下面。地道有四尺多高，个儿高的人弯着腰可以通过；地道的顶离地面三四尺，不妨碍上面种庄稼。地道里每隔一段距离就有一个大洞，洞顶用木料撑住，很牢靠。大洞四壁又挖了许多小洞，有的住人，有的拴牲口，有的搁东西，有的作厕所。一个大洞容得下一百来人，最大的能容二百多人。洞里经常准备着开水、干粮、被子、灯火，在里面住上个三五天不成问题。洞里有通到地面的气孔，从气孔里还能漏下光线来。气孔的口子都开在隐蔽的地方，敌人很难发现。人藏在洞里，既不气闷，又不嫌暗。有的老太太把纺车也搬进来，还嗡嗡嗡地纺线呢。","地道的出口也开在隐蔽的地方，外面堆满荆棘。有的还在旁边挖一个陷坑，坑里插上尖刀或者埋上地雷，上面用木板虚盖着，板上铺些草，敌人一踏上去就翻下坑里送了命。在地道里，离出口不远的地方挖几个特别坚固的洞，民兵拿着武器在洞里警戒；拐弯的地方挖一些岔道，叫“迷惑洞”，敌人万一进来了，分不清哪条是死道，哪条是活道。进了死道，就有地雷埋在那儿等着他们；就算进了活道，他们也过不了关口。原来地道里每隔一段就有个很窄的“孑口”，只能容一个人爬过去。只要一个人拿一根木棒，就可以把“孑口”守住，真是“一夫当关，万夫莫开”。","敌人尝到了地道的厉害，想方设法来破坏，什么火攻啊，水攻啊，毒气攻啊，都用遍了。大家又想出了许多妙法来防备。洞口准备着土和沙，可以用来灭火。“孑口”上装着吊板，如果敌人放毒气，就把吊板放下来挡住，不让毒气往里透。对付水攻的法子更妙了，把地道跟枯井暗沟连接起来，敌人放水的时候，水从洞口进来，就流到枯井暗沟里去了。任敌人想出什么毒辣的法子也不怕，因为各个村子的地道是相通的，大不了转移到旁的村子去。","人在地道里怎么能了解地面上的情况呢？民兵指挥部派出一些人分布在各处，发现了敌情就吆喝起来，一个接一个，一直传到指挥部里。老百姓管这种吆喝叫“无线电”。地道里面可就用“有线电”了，一根铁丝牵住一个小铜铃，这儿一拉，那儿就响，拉几下表示什么意思是早就约好了的。为了打击敌人，什么办法都想出来了，人民的智慧是无穷无尽的。","有了地道战这个斗争方式，敌人毒辣透顶的“扫荡”被粉碎了。冀中平原上的人民不但坚持了生产，还有力地打击了敌人，在我国抗日战争史上留下了惊人的奇迹。"]},{"id":334,"grade":"五年级上册","title":"语文园地","paragraphs":["为了提高阅读的速度，我们要集中注意力，尽量连词成句地读，不要一个字一个字地读，更不要回读。","带着问题读也可以加快阅读的速度。遇到不懂地词语，在不影响理解课文内容的情况下可以先不管它，继续往下读。","读得快还要想得快，要做到一边读一边想，抓住关键词句，才能及时捕捉有用的信息。","俗话说：“熟能生巧。”让我们不断练习，努力做到眼睛看得快，脑子想得快。","不饱食以终日，不弃功于寸阴。——葛洪","盛年不重来，一日难再晨。及时当勉励，岁月不待人。——陶渊明","莫等闲，白了少年头，空悲切。——岳飞","多少事，从来急；天地转，光阴迫。一万年太久，只争朝夕。——毛泽东","我廉颇立下了那么多战功，他蔺相如就靠一张嘴，反而爬到我头上去了。","只要我们按下手电筒的开关，立刻会出现一束光柱。光的速度是惊人的，大约是30万千米每秒，比流星体的速度要快几千倍！","在广阔平原的地底下，挖了不计其数的地道，横的，竖的，直的，弯的，家家相连，村村相通。","左右为难","大家说秦王不过是想把和氏璧骗到手罢了，不能上他的当；可要是不答应，又怕他派兵来进攻。","奋不顾身","杨靖宇正在奋力还击敌人，右手腕忽然受了伤，他就用左手继续向敌人射击。不多时，他的腹部又中了一弹，鲜血直流。他咬紧牙关，猛然起身，连发两枪，击毙了两个日本鬼子。","喋喋不休","悠然自得"]},{"id":335,"grade":"五年级上册","title":"9 猎人海力布","paragraphs":["在我国的一些地区，流传着一个动人的民间故事。","从前有一个猎人，名叫海力布。他热心帮助别人，每次打猎回来，总是把猎物分给大家，自己只留下很少的一份。大家都非常尊敬他。","有一天，海力布到深山去打猎，忽然听见天上有呼救声。他抬头一看，一只老鹰抓着一条小白蛇正从他头上方飞过。他急忙搭箭开弓，对准老鹰射去。老鹰受了伤，丢下小白蛇逃了。","海力布对小白蛇说：“可怜的小东西，快回家去吧！”小白蛇说：“敬爱的猎人，您是我的救命恩人，我要报答您。我是龙王的女儿，您跟我回去，我爸爸一定会好好酬谢您。我爸爸的宝库里有许多珍宝，您要什么都可以。如果您都不喜欢，可以要我爸爸含在嘴里的那颗宝石。只要嘴里含着那颗宝石，就能听懂各种动物说的话。”海力布想，珍宝我倒不在乎，能听懂动物的话，对一个猎人来说，实在是太好了。他问小白蛇：“真有这样一颗宝石吗？”小白蛇说：“真的。但是动物说什么话，您只能自己知道。如果对别人说了，您就会变成一块石头。”","海力布点点头，跟着小白蛇到了龙宫。老龙王对海力布十分感激，要重谢他，于是把他领进宝库，让他自已挑选珍宝，爱什么就拿什么。海力布什么珍宝也不要，他对龙王说：“如果您真想给我点儿东西作纪念，请把您嘴里含着的那颗宝石送给我吧。”龙王低头想了一会儿，就把嘴里含的宝石吐出来，送给了海力布。","海力布临走的时候，小白蛇跟了出来，再三叮嘱他说：“敬爱的猎人，您要记住，无论动物说了什么话，都不要对别人说。如果说了，您马上就会变成石头，永远不能复活了！”海力布谢过小白蛇，就回家了。","海力布有了这颗宝石，打猎方便极了。他把宝石含在嘴里，能听懂飞禽走兽的语言，能知道哪座山上有哪些动物。从此以后，他每次打猎回来，分给大家的猎物更多了。这样过了几年。有一天，他正在深山里打猎，忽然听见一群鸟在议论着什么。仔细一听，那只带头的鸟说：“咱们赶快飞到别处去吧！今天晚上，这里的大山要崩塌，大地要被洪水淹没，不知道要淹死多少人呢！”","海力布听到这个消息，大吃一惊。他急忙跑回家对大家说：“咱们赶快搬到别处去吧！这个地方不能住了！”大家听了感到很奇怪，住得好好的，为什么要搬家呢？尽管海力布焦急地催促大家，可是谁也不相信他。海力布急得掉下了眼泪，说：“我可以发誓，我说的话千真万确。相信我的话吧，赶快搬走！再晚就来不及了！”有个老人对海力布说：“海力布，你是我们的好邻居，我们知道你从来不说谎话。可是今天你让我们搬家，你总得说清楚哇。咱们在这山下住了好几代啦，老老小小这么多人，搬家可不容易呀！”","海力布知道着急也没有用，不把为什么要搬家说清楚，大家是不会相信的。再一迟延，灾难就要夺去乡亲们的生命。要救乡亲们，只有牺牲自己。他想到这里，就镇定地对大家说：“今天晚上，这里的大山要崩塌，洪水要淹没大地。你们看，鸟都飞走了。”接着，他就把怎么得到宝石，怎么听见一群鸟议论避难，以及为什么不能把听来的消息告诉别人，都原原本本照实说了。海力布刚说完，就变成了一块石头。","大家看见海力布变成了石头，都非常后悔，非常悲痛。他们含着眼泪，念着海力布的名字，扶着老人，领着孩子，赶着牛羊，往很远的地方走去。他们走在路上，忽然乌云密布，狂风怒号，接着就是倾盆大雨。半夜里，只听一声震天动地的巨响，大山崩塌了，洪水涌了出来，把他们住的村子淹没了。","人们世世代代纪念海力布。据说现在还能找到那块叫“海力布”的石头呢。"]},{"id":336,"grade":"五年级上册","title":"10 牛郎织女（一）","paragraphs":["古时候有个孩子，爹娘都死了，跟着哥哥嫂子过日子。哥哥嫂子待他很不好，叫他吃剩饭，穿破衣裳，夜里在牛棚里睡。牛棚里没床铺，他就睡在干草上。他每天放牛。那头牛跟他很亲密，用温和的眼神看着他，有时候还伸出舌头舔舔他的手，怪有意思的。哥哥嫂子见着他总是爱理不理的，仿佛他一在眼前，就浑身不舒服。两相比较，他也乐得跟牛一块儿出去，一块儿睡。","他没名字，人家见他每天放牛，就叫他牛郎。","牛郎照看那头牛挺周到。一来是牛跟他亲密；二来呢，他想，牛那么勤勤恳恳地干活，不好好照看它，怎么对得起它呢？他总是挑很好的草地，让牛吃嫩嫩的青草；家里吃的干草，筛得一点儿土也没有。牛渴了，他就牵着它到小溪的上游，让它喝干净的水。夏天天气热，就在树林里休息；冬天天气冷，就在山坡上晒太阳。他把牛身上刷得干干净净，不沾一点儿草叶、土粒。夏天，一把蒲扇不离手，把成群乱转的牛虻都赶跑了。牛棚也打扫得干干净净。在干干净净的地方住，牛舒服，自己也舒服。","牛郎随口哼几支小曲儿，没人听他的，可是牛摇摇耳朵闭闭眼，好像听得挺有味儿。牛郎心里想什么，嘴里就说出来，没人听他的，可是牛咧开嘴，笑嘻嘻的，好像明白他的意思。他常常把看见的、听见的事告诉牛，有时候跟它商量一些事。牛好像全了解，虽然没说话，可是眉开眼笑的，他也就满意了。自然，有时候他还觉得美中不足，要是牛能说话，把了解的和想说的都一五一十地说出来，那该多好呢。","一年一年过去，牛郎渐渐长大了。哥哥嫂子想独占爹娘留下来的家产，把他看成眼中钉。一天，哥哥把牛郎叫到跟前，装得很亲热的样子说：“你如今长大了，也该成家立业了。老人家留下一点儿家产，咱们分了吧。一头牛，一辆车，都归你；别的归我。”","嫂子在旁边，三分像笑七分像发狠，说：“我们挑顶有用的东西给你，你知道吗？你要知道好歹，赶紧离开这儿。天还早，能走就走吧。”","牛郎听哥哥嫂子这么说，想了想，说：“好，我这就走！”他想哥哥嫂子既然这样对待他，他又何必恋恋不舍呢？那辆车不稀罕，幸亏那头老牛归了他，亲密的伙伴还在一块儿，离不离开家有什么关系？","他就牵着老牛，拉着破车，头也不回，一直往前走，走出村子，走过树林，走到山里。从那以后，他白天上山打柴，柴装满一车，就让老牛拉着，到集市上去换粮食；夜晚就让老牛在车旁边休息，自己睡在车上。过了些日子，他在山前边盖了一间草房，又在草房旁边开辟了一块地，种些庄稼，这就算安了家。","一天晚上，他走进草房，忽然听见一声“牛郎”，他从没听见过这个声音。是谁叫他呢？回头一看，微弱的星光下，老牛嘴一张一合的，正在说话。","老牛真会说话了！","牛郎并不觉得奇怪，像是听惯了它说话似的，就转过身子去听。","老牛说：“明天黄昏时候，你翻过右边那座山，山那边是一片树林，树林前边是一个湖，那时候会有些仙女在湖里戏水。她们的纱衣放在草地上，你要捡起那件粉红色的纱衣，跑到树林里等着，跟你要纱衣的那个仙女就是你的妻子。这个好机会你可别错过了。”","“知道了。”牛郎高兴地回答。","第二天黄昏时候，牛郎翻过右边的那座山，穿过树林，走到湖边。湖面映着晚霞的余光，蓝紫色的波纹晃晃荡荡。他听见有女子的笑声，顺着声音看，果然有好些个女子在湖里戏水。他沿着湖边走，没几步，就看见草地上放着好些纱衣，花花绿绿的，件件都那么漂亮。里头果然有一件粉红色的纱衣，他就拿起来，转身走进树林。","他静静地等着，过了一会儿，就听见女子们上岸的声音。只听见一个说：“不早了，咱们赶紧回去吧！咱们偷偷地到人间来，要是老人家知道了，不知道要怎么罚咱们呢！”过了一会儿，又听见一个说：“怎么，你们都走啦？难得来一趟，多自在啊，也不多玩一会儿。——哎呀！我的纱衣哪儿去了？谁瞧见了？”","牛郎听到这儿，从树林里走出来，双手托着纱衣，说：“姑娘，别着急，你的纱衣在这儿。”","姑娘穿上纱衣，一边梳她长长的黑头发，一边跟牛郎谈话。牛郎把自己的情形一五一十地说了。姑娘听得出了神，又同情他，又爱惜他，就把自己的情形也告诉了他。","原来姑娘是天上王母娘娘的外孙女，织得一手好彩锦，名字叫织女。每天早晨和傍晚，王母娘娘拿她织的彩锦装饰天空，那就是灿烂的云霞，什么东西也没它美丽。王母娘娘需要的彩锦多，就叫织女成天成夜地织，一会儿也不许休息。织女身子老在机房里，手老在梭子上，劳累不用说，自由也没有了，等于关在监狱里，实在难受。她常常想，人人说天上好，天上好，天上有什么好呢？没有自由，又看不见什么。她总想离开天上，到人间去，哪怕是一天半天呢，也可以见识见识人间的景物。她把这个想法跟别的仙女说了，别的仙女也都说早有这种想法。那天下午，王母娘娘喝千年酿的葡萄酒，多喝了点儿，靠在宝座上直打瞌睡，看样子不见得马上就醒。仙女们见机会难得，就你拉我、我拉你地溜出来，一齐飞到人间。她们飞到湖边，看见湖水清得可爱，就跳下去戏水。织女关在机房里太久了，现在能够在湖水里无拘无束地玩，心里真痛快，想多玩一会儿，没想到就落在了后边。","牛郎听完织女的话，就说：“姑娘，既然天上没什么好，你就不用回去了。你能干活，我也能干活，咱们两个结了婚，一块儿在人间过一辈子吧。”","织女想了想，说：“你说得很对，咱们结婚，一块儿过日子吧。”","他们俩手拉着手，穿过树林，翻过山头，回到草房。牛郎把老牛指给织女看，说它就是从小到大相依为命的伴儿。织女拍拍老牛的脖子，用腮帮挨挨它的耳朵，算是跟它行见面礼。老牛眉开眼笑地朝她看，仿佛说：“正是这个新娘子。”"]},{"id":337,"grade":"五年级上册","title":"11* 牛郎织女（二）","paragraphs":["从此牛郎在地里耕种，织女在家里纺织。有时候，织女也帮助牛郎干些地里的活。两个人勤劳节俭，日子过得挺美满。转眼间两三个年头过去了，他们生了一个男孩和一个女孩。到孩子能说话的时候，晚上得空，织女就指着星星，给孩子们讲些天上的故事。天上虽然富丽堂皇，可是没有自由，她不喜欢。她喜欢人间的生活：跟牛郎一块儿干活，她喜欢；逗着兄妹俩玩，她喜欢；看门前小溪的水活泼地流过去，她喜欢；听晓风晚风轻轻地吹过树林，她喜欢。两个孩子听她这么说，就偎在她怀里，叫一声“娘”，回过头来又叫一声“爹”。她乐极了，可是有时候也发愁。愁什么呢？她没告诉牛郎。她是怕外祖母知道她在这儿会来找她。","一天，牛郎去喂牛，那头衰老的牛又说话了，眼眶里满是眼泪，说：“我快不行了，不能帮你们下地干活了……我死以后，你把我的皮留着。碰见什么紧急事，你就披上我的皮……”老牛没说完就死了。夫妻两个痛哭了一场，留下老牛的皮，把老牛的尸骨埋在草房后边的山坡上。","再说天上，仙女们溜到人间洗澡的事到底让王母娘娘知道了。王母娘娘罚她们，把她们关在黑屋子里。她尤其恨织女，竟敢留在人间不回来，简直是有意败坏她的门风，损害她的尊严。她发誓要把织女捉回来，哪怕织女藏在泰山底下的石缝里，大海中心的珊瑚礁上，也一定要抓回来，给她顶厉害的惩罚。","王母娘娘派了好些天兵天将到人间察访，察访了好久，才知道织女在牛郎家里，跟牛郎做了夫妻。一天，她亲自到牛郎家里，可巧牛郎在地里干活，她就一把抓住织女往外走。织女的男孩见那老太婆怒气冲冲地拉着织女走，就跑过来拉住织女的衣裳。王母娘娘狠狠一推，孩子倒在地上，她就带着织女一齐飞起来。织女心里恨极了，望着两个可爱的孩子，一时不知该怎么办，只喊了一句：“快去找你爹！”","牛郎跟着男孩赶回家，只见梭子放在织了半截的布匹上，灶上的饭正冒着热气，女孩坐在门前哭。他决定上天去追，把织女救回来。可是怎么能上天呢？他忽然想起老牛临死前说的话，这不正是紧急事吗？他赶紧披上牛皮，找出两个筐，一个筐里放一个孩子，挑起来就往外跑。一出屋门，他就飞起来了，耳边的风呼呼直响。飞了一会儿，望见妻子和老太婆了，他就喊“我来了”，两个孩子也连声喊“娘”。越飞越近，眼看要赶上了，王母娘娘拔下头上的玉簪往背后一划，糟了，牛郎的前边忽然出现一条天河。天河很宽，波浪很大，牛郎飞不过去了。","从此以后，牛郎在天河的这边，织女在天河的那边，只能远远地望着，不能生活在一块儿了。他们就成了天河两边的牵牛星和织女星。","织女受了很厉害的惩罚，可是不肯死心，一定要跟牛郎一块儿过日子。日久天长，王母娘娘也拗不过她，就允许她每年农历七月初七跟牛郎会一次面。","每年的这一天，成群的喜鹊在天河上边搭起一座桥，让牛郎、织女在桥上会面。就因为这件事，每逢那一天，人们很少看见喜鹊，它们都往天河那儿搭桥去了。还有人说，那一天夜里，要是在葡萄架下边静静地听着，还可以听见牛郎、织女在桥上亲亲密密地说话呢。"]},{"id":338,"grade":"五年级上册","title":"语文园地","paragraphs":["鼻子都气歪了 气急败坏","前怕狼后怕虎 畏首畏尾","盼星星盼月亮 望眼欲穿","打开天窗说亮话 直言不讳","吃水不忘挖井人 饮水思源","一只狼看见小羊在河边饮水，想找借口把他吃掉。狼指责小羊把水弄脏了，小羊说自己在下游，不可能弄脏上游的水。狼又说小羊去年骂过他，小羊说那时自己还没有出生。狼恼羞成怒地说：“即使你辩解得再好，我也不会放过你。”于是，他就把小羊吃了。","狼来到小溪边，看见小羊在那儿喝水。狼非常想吃小羊，就故意找碴儿，说：“你把我喝的水弄脏了！你安的什么心？”小羊吃了一惊，温和地说：“我怎么会把您喝的水弄脏呢？您站在上游，水是从您那儿流","到我这儿来的，不是从我这儿流到您那儿去的。”狼气冲冲地说：“就算这样吧，你也还是个坏家伙！我听说，去年你在背地里说我的坏话！”可怜的小羊喊道：“啊，亲爱的狼先生，那是不可能的，去年我还没有出生啊！”狼不想再争辩了，龇着牙，逼近小羊，大声嚷道：“你这个坏蛋！说我坏话的不是你，就是你爸爸，反正都一样。”说着就往小羊身上扑去，吃掉了小羊。","作者：[唐代] 林杰","七夕今宵看碧霄，","牵牛织女渡河桥。","家家乞巧望秋月，","穿尽红丝几万条。","七夕佳节，人们纷纷抬头仰望浩瀚天空，就好像能看见牛郎织女渡过银河在鹊桥上相会。","家家户户都在一边观赏秋月，一边乞巧，穿过的红线都有几万条了。","林杰(831—847)字智周，福建人，唐代诗人。小时候非常聪明，六岁就能赋诗，下笔即成章。又精书法棋艺。卒，年仅十七。《全唐诗》存其诗两首。《乞巧》是唐代诗人林杰描写民间七夕乞巧盛况的名诗。农历七月初七夜晚，俗称“七夕”，又称“女儿节”“少女节”。是传说中隔着“天河”的牛郎和织女在鹊桥上相会的日子。过去，七夕的民间活动主要是乞巧，所谓乞巧，就是向织女乞求一双巧手的意思。乞巧最普遍的方式是对月穿针，如果线从针孔穿过，就叫得巧。这一习俗唐宋最盛。"]},{"id":339,"grade":"五年级上册","title":"快乐读书吧","paragraphs":["从前有座山","从前有座山，山里有座庙，","庙里有个老和尚在给小和尚讲故事。","讲的是什么故事呢？","从前有座山……","在你很小的时候，爷爷奶奶也许就给你讲过这个故事。像这样耳熟能详","的民间故事还有很多，我们一起找来读一读吧。","你读过吗","田螺姑娘，梁山伯与祝英台，八仙过海……它们都是我国民间故事中的经典。人们将对美好生活的期盼化成了一个个民间故事。你讲，我听；我讲，他听。就这样口耳相传，直到今天仍旧吸引着我们。","从前，有个年轻人，独自种着几亩田过活。他每天天还没亮就起床，吃完了早饭，就带了午饭到田里去耕作。直到太阳落山的时候，他才回家自己做晚饭吃。衣服脏了自己洗，鞋袜破了就自己缝缝补补。","有一天，他到田里去耕作，捡回一个大田螺。那是一个青艳艳像宝玉一样的田螺，他舍不得吃，就养在灶头旁边的水缸里。水缸里的水变得特别清，看不到一点儿污泥。","第二天晚上，年轻人从田里耕作回来，一进门，就看见灶上热气腾腾的，屋子里也收拾得干干净净、整整齐齐。他揭开锅盖一看，饭做好了，菜也做好了。他感到很奇怪……","他把这情形告诉了隔壁的老太太。老太太说：“一定是田螺姑娘来帮了你的忙。”","以上是中国民间故事《田螺姑娘》的片段。阅读我国的民间故事，你不仅能领略到动人的情节，还能认识许多精彩的人物，如机智的徐文长、聪慧的巧姑。","作为一种口头艺术，民间故事一般有固定的类型和重复的段落，这是为了在讲述中方便记忆，同时加深听众的印象。","民间故事寄托着人们朴素的愿望：正义却弱小的主人公总是能够打败强大的对手；心地善良的穷苦人最终会丰衣足食，过上幸福的生活……","相信你可以读更多","民间故事存在于世界上的每一个角落。","欧洲各国的民间故事精彩纷呈。你可以跟随小牧羊人，踏上寻找三只会唱歌的苹果的旅途；你可以听到伊凡与灰额猫、山羊、绵羊在聊天；你还可以看到狡猾又幽默的列那狐是如何捉弄其他动物的，那些故事一定会让你捧腹大笑。","在遥远的非洲大地，大家会在闲暇的时候，让一个人来领唱优美的故事，听众则伴以合唱。鳄鱼幻想着晒太阳就能长出翅膀，大象被人类通迫着逃离家乡却仍然坚持回乡……这些意味深远的民间故事就这样口耳相传，代代传诵。让我们一起阅读它们，感受非洲大地上别样的风情。"]},{"id":340,"grade":"五年级上册","title":"示儿","paragraphs":["作者：[宋代] 陆游","死去元知万事空，","但悲不见九州同。","王师北定中原日，","家祭无忘告乃翁。","原本知道死去之后就什么也没有了，只是感到悲伤，没能见到国家统一。","当大宋军队收复了中原失地的那一天时，你们举行家祭时不要忘了告诉我！","陆游（1125年11月13日－1210年1月26日），字务观，号放翁，汉族，越州山阴（今浙江绍兴）人，尚书右丞陆佃之孙，南宋文学家、史学家、爱国诗人。陆游生逢北宋灭亡之际，少年时即深受家庭爱国思想的熏陶。宋高宗时，参加礼部考试，因受宰臣秦桧排斥而仕途不畅。孝宗时赐进士出身。中年入蜀，投身军旅生活。嘉泰二年（1202年），宋宁宗诏陆游入京，主持编修孝宗、光宗《两朝实录》和《三朝史》，官至宝章阁待制。晚年退居家乡。创作诗歌今存九千多首，内容极为丰富。著有《剑南诗稿》《渭南文集》《南唐书》《老学庵笔记》等。"]},{"id":341,"grade":"五年级上册","title":"题临安邸","paragraphs":["作者：[宋代] 林升","山外青山楼外楼，","西湖歌舞几时休？","暖风熏得游人醉，","直把杭州作汴州。","西湖四周青山绵延楼阁望不见头，湖面游船上的歌舞几时才能停休？","温暖馥郁的香风把人吹得醉醺醺的，简直是把杭州当成了那汴州。","林升，字云友，又字梦屏，温州横阳亲仁乡荪湖里林坳（今属苍南县繁枝林坳）人，（《水心集》卷一二有《与平阳林升卿谋葬父序》）。大约生活在南宋孝宗朝（1106-1170年），是一位擅长诗文的士人。事见《东瓯诗存》卷四。《西湖游览志余》录其诗一首。"]},{"id":342,"grade":"五年级上册","title":"已亥杂诗","paragraphs":["作者：[清代] 龚自珍","九州生气恃风雷，","万马齐喑究可哀。","我劝天公重抖擞，","不拘一格降人材。","只有依靠风雷激荡般的巨大力量才能使中国大地焕发勃勃生机，然而社会政局毫无生气终究是一种悲哀。","我奉劝上天要重新振作精神，不要拘泥一定规格以降下更多的人才。","龚自珍（1792年8月22日－1841年9月26日），字璱人，号定盦（一作定庵）。汉族，浙江仁和（今杭州）人。晚年居住昆山羽琌山馆，又号羽琌山民。清代思想家、诗人、文学家和改良主义的先驱者。龚自珍曾任内阁中书、宗人府主事和礼部主事等官职。主张革除弊政，抵制外国侵略，曾全力支持林则徐禁除鸦片。48岁辞官南归，次年卒于江苏丹阳云阳书院。他的诗文主张“更法”、“改图”，揭露清统治者的腐朽，洋溢着爱国热情，被柳亚子誉为“三百年来第一流”。著有《定盦文集》，留存文章300余篇，诗词近800首，今人辑为《龚自珍全集》。著名诗作《己亥杂诗》共315首。多咏怀和讽喻之作。"]},{"id":343,"grade":"五年级上册","title":"13 少年中国说（节选）","paragraphs":["故今日之责任，不在他人，而全在我少年。少年智则国智，少年富则国富，少年强则国强，少年独立则国独立，少年自由则国自由，少年进步则国进步，少年胜于欧洲则国胜于欧洲，少年雄于地球则国雄于地球。","红日初升，其道大光。河出伏流，一泻汪洋。潜龙腾渊，鳞爪飞扬。乳虎啸谷，百兽震惶。鹰隼试翼，风尘吸张。奇花初胎，矞矞皇皇。干将发硎，有作其芒。天戴其苍，地履其黄。纵有千古，横有八荒。前途似海，来日方长。","美哉，我少年中国，与天不老！壮哉，我中国少年，与国无疆！"]},{"id":344,"grade":"五年级上册","title":"14 圆明园的毁灭","paragraphs":["圆明园的毁灭是中国文化史上不可估量的损失，也是世界文化史上不可估量的损失！","圆明园在北京西北郊，是一座举世闻名的皇家园林。它由圆明园、绮春园和长春园组成，所以也叫圆明三园。此外，还有许多小园，分布在圆明园东、西、南三面，众星拱月般环绕在圆明园周围。","圆明园中，有金碧辉煌的殿堂，也有玲珑剔透的亭台楼阁；有象征着热闹街市的“买卖街”，也有象征着田园风光的山乡村野。园中许多景物都是仿照各地名胜建造的，如海宁的安澜园、苏州的狮子林、杭州西湖的平湖秋月；还有很多景物是根据古代文人的诗情画意建造的，如蓬岛瑶台、武陵春色。园中不仅有民族建筑，还有西洋景观。漫步园内，有如漫游在天南海北，饱览着中外风景名胜；流连其间，仿佛置身在幻想的境界里。","圆明园不但建筑宏伟，还收藏着最珍贵的历史文物：上自先秦时代的青铜礼器，下至唐、宋、元、明、清历代的名人书画和各种奇珍异宝。所以，它又是当时世界上最大的博物馆、艺术馆。","1860年10月6日，英法联军侵入北京，闯进圆明园。他们把园内凡是能拿得动的东西，统统掠走；拿不动的，就用大车或牲口搬运；实在运不走的，就任意破坏、毁掉。为了销毁罪证，10月18日和19日，三千多名侵略者奉命在园内放火。大火连烧三天，烟云笼罩了整个北京城。我国这一园林艺术的瑰宝 、建筑艺术的精华，就这样化为一片灰烬。"]},{"id":345,"grade":"五年级上册","title":"15* 小岛","paragraphs":["无边无际的大海上，有一座小岛，远远望去，像一片云在天边浮着。这里树少，草少，土也很少，却驻扎着一群海军士兵。","将军上岛时正是这儿比较凉快的时候，但也有二十多摄氏度。没法子，谁叫这儿离赤道近呢。在小岛转一圈也用不了十分钟，所以，到第五分钟时，将军就发现了问题。","“岛那边是什么东西，搞得那么神秘？是暗堡？”将军说着就走了过去，才看清那儿用礁石围成一圈，上面用油布遮挡着。掀开油布一角，竟露出一片绿油油的菜地。","将军不由得一愣。他知道，在这个地方，蔬菜是很难生长的。因为主要吃罐头，有的战士上岛一段时间后，就会牙龈溃烂，嘴里起泡。从大陆上运来的蔬菜，还没上岛，就要烂掉一大半。看着眼前绿油油的菜地，将军真怀疑自己是在做梦：“这是怎么弄出来的？”","队长说，他是北方人，从大棚种菜得到启示，就搞了这个油布棚，北方大棚是为防冻，这个棚却是防晒和防盐。菜地里的土，大部分是战士们从老家一口袋一口袋背来的。","“从老家？”将军纳闷，“就近的海岛上有土，不也行吗？”","“是啊，可战士们愿意从家乡背，连菜种也是从老家带来的。您看，不少北方的菜在这里都活了。”","将军弯腰细看:好家伙，小小一块菜地，菜的种类还挺多。","“晚饭后，我们就可以把油布都掀开，让您看看菜地的全貌。”队长自豪而又神秘地一笑。","将军的眼光抓住了这一笑，心想：小鬼，还有什么瞒着我呢！就说：“好，我就在晚饭后来看。”","同行的秘书着急了：“首长，不是定了赶回舰上吃晚饭的吗？”","将军当然不会忘。还是他自己定下的规矩：在这一海域，为了减轻岛上的负担，吃住必须返回军舰。但现在，他对随行人员说：“你们乘快艇返回。我在岛上不光吃晚饭，还要吃明天的早饭。”","大家都很吃惊。秘书马上问队长：“晚上岛上吃什么？”","将军白了他一眼：“吃什么？战士们吃什么我就吃什么。”","他问身边的队长：“欢迎不欢迎？”","队长心里很矛盾，说：“欢迎是欢迎，可您的身体……","将军又问围过来的战士们：“你们欢迎吗？”","“欢迎！”","将军点点头。他要住下来，可不是因为队长那一笑。他是想，要是这里种菜的法子真能推广，那对这一带守岛部队的作用可太大了。这种问题看起来很小，却直接关系到部队的战斗力。","晚饭时，队长陪将军来到部队，办公桌上摆了好几个盘子，有罐头，还有几种鲜鱼。将军知道这儿有鱼不稀奇，也就没说什么，坐下来拿起了筷子。就在这时，炊事员端来一个盘子，将军一看，脸色马上变了。那是一盘小白菜。","“这是谁的主意？”将军问道。","队长不知说什么好：“大家的……”","“大家的？哼！”将军重重地放下筷子，起身，“我说和战士们一起吃，你劝我说我去了他们会拘束，我就听了你的。现在倒好！我问你，战士们有蔬菜吃吗？”","“一个星期吃一次。”队长声音小了。","“我问的是今天。走，去看他们吃什么！”","队长急了：“首长，您别去了。这盘菜您一定要吃下去，要不，您会后悔的。”将军一愣，不明白队长说的什么意思。","队长想了想，对将军说：“您等一下。”然后跑了出去。过了一会儿，他又跑了回来，指着窗外：“首长，您看。”","将军顺着队长指的方向看去——","那一片油布已经翻开，露出了一大块菜地，那绿油油的一片，竟构成了一幅中国地图。","将军一阵沉吟，凝视着那片绿色。","“全国的省份，一大半有土在这里。岛上的战士知道您身体不大好，又上了年纪，一致要求务必让您吃上蔬菜……大家不是把您看成首长，而是一个长辈。”队长在边上小声地说。","将军觉得鼻子有些发酸，就别过脸去，刚好看见那盘小白菜。","他怔了一下，走过去端起来，大步走了出去。","饭堂里，战士们正在吃饭，见将军进来，都停住了筷子。将军看了看他们桌子上的罐头，喉咙哽了一下，说:“同志们……“停了一下，又说：“孩子们，我给大家分菜，每人一筷子。”","战士们怕烫似的马上躲远。将军没有追过去，也知道自己没法追。他站在原地，一时不知怎么办才好。终于，他眼睛一亮，看到了饭桌边上的一桶汤。他走过去，把手中的菜倒进汤里，而后拿起汤勺，在桶里搅了几下。随后，他舀起一勺汤。","没有人招呼，战士们自觉地围了过来。一勺一勺的菜汤舀到了战士们的碗里。将军看到不少人的眼角有些晶亮，自己的鼻子又开始发酸，本来想说些什么，脑子乱了，只张了张嘴……","清晨，将军离开了小岛。回望小岛，他看到那片绿色上面，一轮鲜红的太阳正在升起。","他向着太阳，向着那片绿色，也向着小岛，行了一个标准的军礼。"]},{"id":346,"grade":"五年级上册","title":"语文园地","paragraphs":["举世闻名 臭名远扬","兴高采烈 得意忘形","足智多谋 诡计多端","呕心沥血 处心积虑","它由圆明园、绮春园和长春园组成，所以也叫圆明三园。此外，还有许多小园，分布在圆明园东、西、南三面，众星拱月般环绕在圆明园周围。","它的果实埋在地里，不像桃子、石榴、苹果那样，把鲜红嫩绿的果实高高地挂在枝上，使人一见就生爱慕之心。","太平盛世 国泰民安","丰衣足食 安居乐业","政通人和 人寿年丰","夜不闭户 路不拾遗","多事之秋 兵荒马乱","流离失所 生灵涂炭","家破人亡 哀鸿遍野","民不聊生 内忧外患"]},{"id":347,"grade":"五年级上册","title":"16 太阳","paragraphs":["有这么一个传说，古时候，天上有十个太阳，晒得地面寸草不生。人们热得受不了，就找一个箭法很好的人射掉九个，只留下一个，地面上才不那么热了。其实，太阳离我们约有一亿五千万千米远。到太阳上去，如果步行，日夜不停地走，差不多要走三千五百年；就是坐飞机，也要飞二十几年。这么远，箭哪能射得到呢？","我们看到太阳，觉得它并不大，实际上它大得很，约一百三十万个地球的体积才能抵得上一个太阳。因为太阳离地球太远了，所以看上去只有一个盘子那么大。","太阳会发光，会发热，是个大火球。太阳的温度很高，表面温度有五千多摄氏度，就是钢铁碰到它，也会变成气体。","太阳虽然离我们很远很远，但是它和我们的关系非常密切。有了太阳，地球上的庄稼和树木才能发芽，长叶，开花，结果；鸟、兽、虫、鱼才能生存，繁殖。如果没有太阳，地球上就不会有植物，也不会有动物。我们吃的粮食、蔬菜、水果、肉类，穿的棉、麻、毛、丝，都和太阳有密切的关系。埋在地下的煤炭，看起来好像跟太阳没有关系，其实离开太阳也不能形成，因为煤炭是由远古时代的植物埋在地层底下变成的。","地面上的水被太阳晒着的时候，吸收了热，变成了水蒸气。空气上升时，温度下降，其中的水蒸气凝成了无数的小水滴，飘浮在空中，变成云。云层里的小水滴越聚越多，就变成雨或雪落下来。","太阳晒着地面，有些地区吸收的热量多，那里的空气就比较热；有些地区吸收的热量少，那里的空气就比较冷。空气有冷有热，才能流动，成为风。","太阳光有杀菌的作用，我们可以利用它来预防和治疗疾病。","地球上的光明和温暖都是太阳送来的。如果没有太阳，地球上将到处是黑暗，到处是寒冷，没有风、雪、雨、露，没有草、木、鸟、兽，自然也不会有人。一句话，没有太阳，就没有我们这个美丽可爱的世界。"]},{"id":348,"grade":"五年级上册","title":"17 松鼠","paragraphs":["松鼠是一种漂亮的小动物，乖巧，驯良，很讨人喜欢。它们面容清秀，眼睛闪闪发光，身体矫健，四肢轻快。玲珑的小面孔，衬上一条帽缨形的美丽尾巴，显得格外漂亮。它们的尾巴老是翘起来，一直翘到头上，自己就躲在尾巴底下歇凉。它们常常直竖着身子坐着，像人们用手一样，用前爪往嘴里送东西吃。可以说，松鼠最不像四足兽了。","松鼠不躲藏在地底下，经常在高处活动，像飞鸟一样住在树顶上，满树林里跑，从这棵树跳到那棵树。它们在树上做窝，摘果实，喝露水。只有树被风刮得太厉害了，才到地上来。在平原地区是很少看到松鼠的。它们不接近人的住宅，也不待在小树丛里，只喜欢住在高大的老树上。在清朗的夏夜，可以听到松鼠在树上跳着叫着，互相追逐。它们好像很怕强烈的日光，白天躲在窝里歇凉，晚上出来奔跑、玩耍、吃东西。","松鼠不像山鼠那样，一到冬天就蛰伏不动。它们是十分警觉的，只要有人触动一下松鼠所在的大树，它们就从树上的窝里跑出来躲到树枝底下，或者逃到别的树上去。松鼠轻快极了，总是小跳着前进，有时也连蹦带跑。它们的爪子是那样锐利，动作是那样敏捷，一棵很光滑的高树，一忽儿就爬上去了。松鼠在秋天拾榛子，塞到老树空心的缝隙里，塞得满满的，留到冬天吃。在冬天，它们也常用爪子把雪扒开，在雪下面找榛子。","松鼠的窝通常搭在树枝分杈的地方，又干净又暖和。它们搭窝的时候，先搬些小木片，错杂着放在一起，再用些干苔藓编扎起来，然后把苔藓挤紧、踏平，使那建筑物足够宽敞、足够坚实。这样，它们可以带着儿女住在里面，既舒适又安全。窝口朝上，端端正正，很狭窄，勉强可以进出。窝口有一个圆锥形的盖，把整个窝遮蔽起来，下雨时雨水向四周流去，不会落在窝里。","松鼠通常一胎生三四个。小松鼠的毛是灰褐色的，过了冬就换毛，新换的毛比脱落的毛颜色深些。它们用爪子和牙齿梳理全身的毛，身上总是光光溜溜、干干净净的。"]},{"id":349,"grade":"五年级上册","title":"习作例文","paragraphs":["不少人看到过象，都说象是很大的动物。其实还有比象大得多的动物，那就是鲸。目前已知最大的鯨约有一百六十吨重。我国发现过一头近四十吨重的鲸，约十八米长，一条舌头就有十几头大肥猪那么重。它要是张开嘴，人站在它嘴里，举起手来还摸不到它的上腭，四个人围着桌子坐在它的嘴里看书，还显得很宽敵。","鲸生活在海洋里，因为体形像鱼，许多人管它叫鲸鱼。其实它不属于鱼类，而是哺乳动物。在很远的古代，鲸的祖先跟牛羊的祖先一样，生活在陆地上。后来环境发生了变化，鲸的祖先生活在靠近陆地的浅海里。又经过了很长很长的时间，它们的前肢和尾巴渐渐变成了鳍，后肢完全退化了，整个身子成了鱼的样子，适应了海洋的生活。","鲸的种类很多，总的来说可以分为两大类：一类是须鲸，没有牙齿；一类是齿鲸，有锋利的牙齿。","鲸吃什么呢？须鲸主要吃虾和小鱼。它们在海洋里游的时候，张着大嘴，把许多小鱼小虾连同海水一齐吸进嘴里，然后闭上嘴，把海水从须板中间滤出来，把小鱼小虾吞进肚子里，有的一顿就可以吃两吨多。齿鲸主要以乌贼、鱼类为食，有的还能捕食大鱼和海兽。它们遇到大鱼和海兽，就凶猛地扑上去，用锋利的牙齿撕咬，很快就吃掉了。有一种号称“海中之虎”的虎鲸，常常好几十头结成一群，围住一头三十多吨重的长须鯨，几个小时就能把它吃光。","鯨跟牛羊一样用肺呼吸，这也说明它不属于鱼类。鲸的鼻孔长在脑袋顶上，呼气的时候浮出海面，从鼻孔喷出来的气形成一股水柱，就像花园里的喷泉一样：等肺里吸足了气，再潜入水中。鲸每隔一段时间必须呼吸一次。不同种类的鲸喷出的气形成的水柱也不一样：须鲸的水柱是垂直的，又细又高；齿鲸的水柱是倾斜的，又粗又矮。有经验的人根据水柱的形状，就能判断出鲸的种类和大小。","鲸每天都要睡觉，睡觉的时候，总是几头聚在一起。它们通常会找一个比较安全的地方，头朝里，尾巴向外，围成一圈，静静地浮在海面上。如果听到什么声响，它们立即四散游开。","鲸是胎生的，幼鲸靠吃母鲸的奶长大，这些特征也说明鲸是哺乳动物。长须鲸刚生下来就有六米多长，一两吨重，两三年就可以长成大鲸。鲸的寿命很长，一般可以活几十年，有的甚至能活近一百年。","风无影无形，我们怎样才能知道它是从哪个方向吹来的呢？可以借助一些容易随风飘动的物体，比如风向袋，根据它飘动的方向判断风向。","制作风向袋可以分为下面几个步骤：","第一，准备竹竿、细铁丝、粗铁丝、尖嘴钳、尼龙纱巾或其他较轻的纺织品、塑料绳、针线等材料和工。","第二，缝制口袋。用尼龙纱巾缝一个圆锥形口袋，袋口直径约10厘米，袋长40~50厘米。用细铁丝做一个和袋口一样大小的圆圈，用针线把细铁丝固定在袋口处，把袋口撑开。","第三，剪下4根长约10厘米的塑料绳，在袋口边缘分别扎4个小洞。将4根塑料绳的一头分别穿过4个小洞，绑在铁丝圈上，另一头绑在一起，打一个结实的绳结。","第四，拿一根细铁丝，在离竹竿顶端10厘米处缠2~3圈，不要缠太紧，做一个可以在竹竿上自由滑动的细铁丝圈。离细铁丝圈上下各1~2厘米处，用尖嘴钳把粗铁丝在竹竿上紧紧缠绕3~4圈，这样细铁丝圈就只能在缠紧的粗铁丝圈之间上下滑动。再剪下一根15厘米长的塑料绳，一头绑在之前打好的绳结上，另一头绑在竹竿的细铁丝圈上，把口袋系在竹竿上。","将竹竿固定在空旷的场地上，在观察前确认东西南北的准确方位。当风向袋随风飘动时，观察它飘动的方向。风向袋飘动的反方向就是风向。"]},{"id":350,"grade":"五年级上册","title":"18 慈母情深","paragraphs":["我一直想买一本长篇小说——《 青年近卫军》。书价一元多钱。","母亲还从来没有一次给过我这么多钱。我也从来没有向母亲一次要过这么多钱。","但我想有一本《青年近卫军》，想得整天失魂落魄。","我从同学家的收音机里听到过几次《青年近卫军》的连续广播。那时我家的破收音机已经卖了，被我和弟弟妹妹们吃进了肚子里。","在自己对自己的怂恿之下，我来到母亲上班的地方，向母亲要钱。母亲那一年被铁路工厂辞退了，为了每月二十七元的收入，又在一个加工棉胶鞋帮的街道小厂上班。","那是我第一次到母亲为我们挣钱的那个地方。","空间非常低矮，低矮得使人感到压抑。不足二百平米的厂房，四壁潮湿颓败。七八十台破缝纫机一行行排列着，七八十个都不算年轻的女人忙碌在自己的缝纫机旁。因为光线阴暗，每个女人的头上方都吊着一只灯泡。正是酷暑炎夏，窗不能开，七八十个女人的身体和七八十只灯泡所散发的热量，使我感到犹如身在蒸笼。","我呆呆地将那些女人扫视一遍，却发现不了我的母亲。","七八十台破缝纫机发出的噪声震耳欲聋。","“你找谁？”一个老头对我大声嚷。","“找我妈！”","“你妈是谁？”","我大声说出了母亲的名字。","“那儿！”","老头朝最里边的一个角落一指。","我穿过一排排缝纫机，走到那个角落，看见一个极其瘦弱的脊背弯曲着，头凑到缝纫机板上。周围几只灯泡烤着我的脸。","“妈—”","“妈—”","背直起来了，我的母亲。转过身来了，我的母亲。褐色的口罩上方，一对眼神疲惫的眼睛吃惊地望着我，我的母亲的眼睛……","母亲大声问：“你来干什么？”","“我……。”","“有事快说，别耽误妈干活！”","“我……要钱……”","我本已不想说出“要钱”两字，可是竟说出来了！","“要钱干什么？”","“买书……”","“多少钱？”","“一元五角就行……”","母亲掏衣兜，掏出一卷揉得皱皱的毛票，用皲裂的手指数着。","旁边一个女人停止踏缝纫机，向母亲探过身，喊：“大姐，别给！没你这么当妈的！供他们吃，供他们穿，供他们上学，还供他们看闲书哇！”接着又对我喊：“你看你妈这是在怎么挣钱？你忍心朝你妈要钱买书哇？”","母亲却已将钱塞在我手里了，大声回答那个女人：“谁叫我们是当妈的呀！我挺高兴他爱看书的！”","母亲说完，立刻又坐了下去，立刻又弯曲了背，立刻又将头俯在缝纫机板上了，立刻又陷入手脚并用的机械忙碌状态……","那一天我第一次发现，母亲原来是那么瘦小！那一天我第一次觉得自己长大了，应该是一个大人了。","我鼻子一酸，攥着钱跑了出去……","那天，我用那一元五角钱给母亲买了一听水果罐头。","“你这孩子，谁叫你给我买水果罐头的！不是你说买书，妈才舍不得给你这么多钱呢！”","那一天母亲数落了我一顿。数落完，又给我凑足了买《青年近卫军》的钱。我想我没有权利用那钱再买任何别的东西，无论为我自己还是为母亲。","就这样，我有了第一本长篇小说……"]},{"id":351,"grade":"五年级上册","title":"19 父爱之舟","paragraphs":["是昨夜梦中的经历吧，我刚刚梦醒！","朦胧中，父亲和母亲在半夜起来给蚕宝宝添桑叶……每年卖茧子的时候，我总跟在父亲身后，卖了茧子，父亲便给我买枇杷吃……","我又见到了姑爹那只小渔船。父亲送我离开家乡去报考学校和上学，总是要借用姑爹那只小渔船。他同姑爹一起摇船送我。带了米在船上做饭，晚上就睡在船上，这样可以节省饭钱和旅店钱。我们不肯轻易上岸，花钱住旅店的教训太深了。有一次，父亲同我住了一间最便宜的小客栈，半夜我被臭虫咬醒，身上都是被咬的大红疙瘩。父亲心疼极了，叫来茶房，掀开席子让他看满床乱爬的臭虫和我身上的疙瘩。茶房说没办法，要么加点儿钱换个较好的房间。父亲动心了，但我年纪虽小却早已深深体会到父亲挣钱的艰难。他平时节省到极点，自己是一分冤枉钱也不肯花的，我反正已被咬了半夜，只剩下后半夜，就不肯再加钱换房间。","恍恍惚惚我又置身于两年一度的庙会中，能去看看这盛大的节日的确是无比的快乐，我高兴极了。我看各样彩排着的戏人边走边唱，看踩高跷走路，看虾兵、蚌精、牛头、马面……人山人海，卖小吃的挤得密密层层，各式各样的糖果点心、鸡鸭鱼肉都有。我和父亲都饿了，我多馋啊！但不敢，也不忍心叫父亲买。父亲从家里带了粽子，找个偏僻的地方，父子俩坐下吃凉粽子。吃完粽子，父亲觉得我太委屈了，领我到小摊上吃了碗热豆腐脑，我叫他也吃，他就是不吃。卖玩意儿的也不少，彩色的纸风车、布老虎、泥人、竹制的花蛇……虽然不可能花钱买玩意儿，但父亲很理解我那恋恋不舍的心思，回家后他用几片玻璃和彩色纸屑等糊了一个万花筒，这便是我童年唯一的也是最珍贵的玩具了。万花筒里那千变万化的图案花样，是我最早的抽象美的启迪者吧！","父亲经常说要我念好书，最好将来到外面当个教员，所以我从来不缺课，不逃学。读初小的时候，遇上大雨大雪天，路滑难走，父亲便背着我上学。我背着书包伏在他背上，双手撑起一把结结实实的大黄油布雨伞。他扎紧裤脚，穿一双深筒钉鞋，将棉袍的下半截撩起扎在腰里，腰里那条极长的粉绿色丝绸汗巾可以围腰两三圈，那还是母亲出嫁时的陪嫁呢。","初小毕业时，我考取了鹅山高小。要住在鹅山当寄宿生，就要缴饭费、宿费、学杂费，书本费也贵了，于是家里粜稻、卖猪，每学期开学要凑一笔不少的钱。钱很紧，但家里愿意把钱都花在我身上。我拿着凑来的钱去缴学费，感到十分心酸。父亲送我到学校，替我铺好床，他回家时，我偷偷哭了。这是我第一次真正心酸的哭，与在家里撒娇的哭、发脾气的哭、打架的哭都大不一样，是人生道路中品尝到的新滋味了。","我唯一的法宝就是考试，从未落过榜。我又要去报考无锡师范了。","为了节省路费，父亲又向姑爹借了他家的小渔船，同姑爹两人摇船送我到无锡。时值暑天，为避免炎热，夜晚便开船，父亲和姑爹轮换摇櫓，让我在小舱里睡觉。但我也睡不好，因为确确实实已意识到考不取的严重性，自然更未能领略到满天星斗、小河里孤舟缓缓夜行的诗画意境。船上备一只泥灶，自己煮饭吃，小船兼做旅店和饭店，节省了食宿费。只是我们的船不敢停到无锡师范附近，怕被别的考生及家长见了嘲笑。","老天不负苦心人，他的儿子考取了。送我去入学的时候，依旧是那只小船，依旧是姑爹和父亲轮换摇船。不过父亲不摇橹的时候，便抓紧时间为我缝补棉被，因我那长期卧病的母亲未能给我备齐行装。我从舱里往外看，父亲那弯腰低头缝补的背影挡住了我的视线。后来我读到朱自清先生的《背影》时，这个船舱里的背影也就分外明显，永难磨灭了！不仅是背影时时在我眼前显现，鲁迅笔下的乌篷船对我而言也永远是那么亲切。虽然姑爹小船上盖的只是破旧的篷，远比不上绍兴的乌篷船精致，但姑爹的小渔船仍然是那么亲切，那么难忘……我什么时候能够用自己手中的笔，把那只载着父爱的小船画出来就好了！","……醒来，枕边一片湿。"]},{"id":352,"grade":"五年级上册","title":"20* “精彩极了”和“糟糕透了”","paragraphs":["记得八九岁的时候，我写了第一首诗。母亲一念完那首诗，眼睛亮亮的，兴奋地嚷着：“巴迪，真是你写的吗？多美的诗啊！精彩极了！”她搂住了我，赞扬声雨点般落到我身上。我既腼腆又得意扬扬，点头告诉她这首诗确实是我写的。她高兴得再次拥抱了我。","“妈妈，爸爸下午什么时候回来？”我红着脸问。我有点儿迫不及待，想立刻让父亲看看我写的诗。“他晚上七点钟回来。”母亲摸着我的脑袋，笑着说。","整个下午我都怀着一种自豪感等待父亲回来。我用最漂亮的花体字把诗认认真真地重新誊写了一遍，还用彩色笔在它的周围描上一圈花边。将近七点钟的时候，我悄悄走进饭厅，满怀信心地把它放在餐桌父亲的位置上。","七点。七点一刻。七点半。父亲还没有回来。我实在等不及了。我敬仰我的父亲，他是一家电影公司的重要人物，写过好多剧本。他一定会比母亲更加赞赏我这首精彩的诗。","快到八点钟时，父亲终于推门而入。他进了饭厅，目光被餐桌上的那首诗吸引住了。我紧张极了。","“这是什么？”他伸手拿起了我的诗。","“亲爱的，发生了一件奇妙的事。巴迪写了一首诗，精彩极了……”母亲上前说道。","“对不起，我自己会判断的。”父亲开始读诗。","我把头埋得低低的。诗只有十行，可我觉得他读了几个小时。","“我看这首诗糟糕透了。”父亲把诗扔回原处。我的眼睛湿润了，头也沉重得抬不起来。","“亲爱的，我真不懂你是什么意思！”母亲嚷道，“这不是在你的公司里。巴迪还是个孩子，这是他写的第一首诗，他需要鼓励。”","“我不明白，”父亲并不退让，“难道世界上糟糕的诗还不够多吗？”","我再也受不了了。我冲出饭厅，跑进自己的房间，扑到床上失声痛哭起来。饭厅里，父母还在为那首诗争吵着。","几年后，当我再拿起那首诗，不得不承认父亲是对的，那的确是一首相当糟糕的诗。不过母亲还是一如既往地鼓励我，因此我还一直在写作。有一次，我鼓起勇气给父亲看了一篇我新写的短篇小说。“写得不怎么样，但也不是毫无希望。”根据父亲的批语，我学着进行修改，那时我还未满十二岁。","现在我已经有了很多作品，出版了一部部小说、 戏剧和电影剧本。我越来越体会到我当初是多么幸运。我有个慈祥的母亲，她常常对我说：“巴迪，这是你写的吗？精彩极了！”我还有个严厉的父亲，他总是皱着眉头，说：“这个糟糕透了。”一个作家，应该说生活中的每一个人，都需要来自母亲的力量，这种爱的力量是灵感和创作的源泉。但是仅有这个是不全面的，它可能会把人引入歧途，所以还需要警告的力量来平衡，需要有人时常提醒你：“小心，注意，总结，提高。”","这些年来，我少年时代听到的这两种声音一直交织在我的耳际。“精彩极了！”“糟糕透了！”“精彩极了！”“糟糕透了！”……它们像两股风不断地向我吹来。我谨慎地把握住我生活的小船，使它不被哪一股风刮倒。我从心底里知道，“精彩极了”也好，“糟糕透了”也好，这两个极端的断言有一个共同的出发点，那就是爱。在爱的鼓舞下，我努力地向前驶去。"]},{"id":353,"grade":"五年级上册","title":"语文园地","paragraphs":["就这样，我有了第一本长篇小说…… 于是，我又想起了在故乡童年时代的“摇花乐”，还有那摇落的阵阵桂花雨。 我从心底里知道，“精彩极了”也好，“糟糕透了”也好，这两个极端的断言有一个共同的出发点，那就是爱。在爱的鼓舞下，我努力地向前驶去。","空间非常低矮，低矮得使人感到压抑。不是二百平来的厂房，四壁潮湿颓败。七八十台破缝纫机一行行排列着，七八十个都不算年轻的女人忙碌在自己的缝纫机旁。因为光线阴暗，每个女人的头上方都吊着一只灯泡。正是酷暑炎夏，窗不能开，七八十个女人的身体和七八十只灯泡所散发的热量，使我感到犹如身在蒸笼。","我看各样彩排着的戏人边走边唱，看踩高跷走路，看虾兵、蚌精、牛头、马面……人山人海，卖小吃的挤得密密层层，各式各样的糖果点心、鸡鸭鱼肉都有。我和父亲都饿了，我多馋啊！但不敢，也不忍心叫父亲买。","那一天我第一次发现，母亲原来是那么瘦小！那一天我第一次觉得自己长大了，应该是一个大人了。","这是我第一次真正心酸的哭，与在家里撒娇的哭、发脾气的哭、打架的哭都大不一样，是人生道路中品尝到的新滋味了。","克勤于邦，克俭于家。——《尚书》","居安思危，戒奢以俭。——魏征","由俭入奢易，由奢入俭难。——司马光","一粥一饭，当思来处不易；半丝半缕，恒念物力维艰；——朱用纯"]},{"id":354,"grade":"五年级上册","title":"山居秋暝","paragraphs":["作者：[唐代] 王维","空山新雨后，","天气晚来秋。","明月松间照，","清泉石上流。","竹喧归浣女，","莲动下渔舟。","随意春芳歇，","王孙自可留。","新雨过后山谷里空旷清新，初秋傍晚的天气特别凉爽。","明月映照着幽静的松林间，清澈泉水在山石上淙淙淌流。","竹林里传来喧闹声，知是少女洗衣归来，莲叶轻摇知是上游荡下轻舟。","任凭春天的花草消失，眼前的秋景足以让我流连久居。","王维（701年－761年，一说699年—761年），字摩诘(jié)，号摩诘居士。汉族，河东蒲州（今山西运城）人，祖籍山西祁县，唐朝诗人，有“诗佛”之称。苏轼评价其：“味摩诘之诗，诗中有画；观摩诘之画，画中有诗。”开元九年（721年）中进士，任太乐丞。天宝年间，拜吏部郎中、给事中。唐肃宗乾元年间任尚书右丞，世称“王右丞”。王维是盛唐诗人的代表，今存诗400余首，重要诗作有《相思》《山居秋暝》等。王维精通佛学，受禅宗影响很大。佛教有一部《维摩诘经》，是王维名和字的由来。王维诗书画都很有名，多才多艺，音乐也很精通。与孟浩然合称“王孟”。"]},{"id":355,"grade":"五年级上册","title":"枫桥夜泊","paragraphs":["作者：[唐代] 张继","月落乌啼霜满天，","江枫渔火对愁眠。","姑苏城外寒山寺，","夜半钟声到客船。","月亮已落下乌鸦啼叫寒气满天，面对江边枫树与船上渔火，我忧愁难眠。","姑苏城外那寒山古寺，半夜里敲响的钟声传到了我乘坐的客船。","张继（约715~约779）字懿孙，汉族，襄州人（今湖北襄阳人）。唐代诗人，他的生平不甚可知。据诸家记录，仅知他是天宝十二年（公元七五三年）的进士。大历中，以检校祠部员外郎为洪州（今江西南昌市）盐铁判官。他的诗爽朗激越，不事雕琢，比兴幽深，事理双切，对后世颇有影响。但可惜流传下来的不到50首。他的最著名的诗是《枫桥夜泊》。"]},{"id":356,"grade":"五年级上册","title":"长相思","paragraphs":["作者：[清代] 纳兰性德","山一程，水一程，身向榆关那畔行，夜深千帐灯。","风一更，雪一更，聒碎乡心梦不成，故园无此声。","将士们马不停蹄地向着山海关进发。夜已经深了，千万个帐篷里都点起了灯。","帐篷外风声不断，雪花不住，嘈杂的声音打碎了思乡的梦，想到远隔千里的家乡没有这样的声音啊。","纳兰性德（1655－1685），满洲人，字容若，号楞伽山人，清代最著名词人之一。其诗词“纳兰词”在清代以至整个中国词坛上都享有很高的声誉，在中国文学史上也占有光彩夺目的一席。他生活于满汉融合时期，其贵族家庭兴衰具有关联于王朝国事的典型性。虽侍从帝王，却向往经历平淡。特殊的生活环境背景，加之个人的超逸才华，使其诗词创作呈现出独特的个性和鲜明的艺术风格。流传至今的《木兰花令·拟古决绝词》——“人生若只如初见，何事秋风悲画扇？等闲变却故人心，却道故人心易变。”富于意境，是其众多代表作之一。"]},{"id":357,"grade":"五年级上册","title":"22 鸟的天堂","paragraphs":["我们吃过晚饭，热气已经退了。太阳落下了山坡，只留下一段灿烂的红霞在天边。","我们走过一段石子路，很快就到了河边。在河边大树下，我们发现了几只小船。","我们陆续跳上一只船。一个朋友解开了绳，拿起竹竿一拨，船缓缓地动了，向河中心移去。","河面很宽，白茫茫的水上没有一点儿波浪。船平静地在水面移动。三支桨有规律地在水里划，那声音就像一支乐曲。","在一个地方，河面变窄了。一簇簇树叶伸到水面上。树叶真绿得可爱。那是许多株茂盛的榕树，看不出主干在什么地方。","当我说许多株榕树的时候，朋友们马上纠正我的错误。一个朋友说那里只有一株榕树，另一个朋友说是两株。我见过不少榕树，这样大的还是第一次看见。","我们的船渐渐逼近榕树了。我有机会看清它的真面目，真是一株大树，枝干的数目不可计数。枝上又生根，有许多根直垂到地上，伸进泥土里。一部分树枝垂到水面，从远处看，就像一株大树卧在水面上。","榕树正值茂盛的时期，好像在把它的全部生命力展示给我们看。那么多的绿叶，一簇堆在另一簇上面，不留一点儿缝隙。那翠绿的颜色，明亮地照耀着我们的眼睛，似乎每一片绿叶上都有一个新的生命在颤动。这美丽的南国的树！","船在树下泊了片刻。岸上很湿，我们没有上去。朋友说这里是“鸟的天堂”，有许多鸟在这树上做巢，农民不许人去捉它们。我仿佛听见几只鸟扑翅的声音，等我注意去看，却不见一只鸟的影子。只有无数的树根立在地上，像许多根木桩。土地是湿的，大概涨潮的时候河水会冲上岸去。“鸟的天堂”里没有一只鸟，我不禁这样想。于是船开了，一个朋友拨着桨，船缓缓地移向河中心。","第二天，我们划着船到一个朋友的家乡去。那是个有山有塔的地方。从学校出发，我们又经过那“鸟的天堂”。","这一次是在早晨。阳光照耀在水面，在树梢，一切都显得更加光明了。我们又把船在树下泊了片刻。","起初周围是静寂的。后来忽然起了一声鸟叫。我们把手一拍，便看见一只大鸟飞了起来。接着又看见第二只，第三只。我们继续拍掌，树上就变得热闹了，到处都是鸟声，到处都是鸟影。大的，小的，花的，黑的，有的站在树枝上叫，有的飞起来，有的在扑翅膀。","我注意地看着，眼睛应接不暇，看清楚了这只，又错过了那只，看见了那只，另一只又飞起来了。一只画眉飞了出来，被我们的掌声一吓，又飞进了叶丛，站在一根小枝上兴奋地叫着，那歌声真好听。","当小船向着高塔下面的乡村划去的时候，我回头看那被抛在后面的茂盛的榕树。我感到一点儿留恋。昨天是我的眼睛骗了我，那“鸟的天堂”的确是鸟的天堂啊！"]},{"id":358,"grade":"五年级上册","title":"23* 月迹","paragraphs":["我们这些孩子，什么都觉得新鲜，又常常什么都觉得不满足。中秋的夜里，我们在院子里盼着月亮，好久却不见出来，便坐回中堂里，放了竹窗帘儿闷着，缠着奶奶说故事。奶奶是会说故事的，说了一个，我们还要她再说一个……奶奶突然说：“月亮进来了！”","我们看时，那竹窗帘儿里果然有了月亮，款款地悄没声儿地溜进来，出现在窗前的穿衣镜上了：原来月亮是长了腿的，爬着那竹帘格儿，先是一个白道儿，再是半圆，渐渐地爬得高了，穿衣镜上的圆便满盈了。我们都高兴起来，又都屏住气儿，生怕那是个尘影儿变的，会一口气吹跑了呢。月亮还在竹帘儿上爬，那满圆儿却慢慢儿又亏了，末了，便全没了踪迹，只留下一个空镜，一个失望。奶奶说：“它走了，它是匆匆的。你们快出去寻月吧。”","我们都跑了出来，它果然就在院子里，但再也不是那么一个满满的圆了。满院子的白光，是玉玉的，银银的，灯光也没有这般亮的。院子的中央处，是那棵粗粗的桂树，疏疏的枝，疏疏的叶，桂花还没有开，却有了累累的骨朵儿了。我们都走近去，不知道那个满圆儿去哪儿了，却疑心这骨朵儿是繁星儿变的；抬头看着天空，星儿似乎就比平日少了许多。月亮正在头顶，明显大多了，也圆多了，清清晰晰看见里边有个什么东西。","“奶奶，那月上是什么呢？”我问。","“是树，孩子。”奶奶说。","“什么树呢？”","“桂树。”","我们都面面相觑了，倏忽间，哪儿好像有了一种气息，就在我们身后袅袅，到了头发梢儿上，添了一种淡淡的痒痒的感觉。似乎我们已在月里了，那月桂分明就是我们身后的这一棵了。","奶奶瞧着我们，就笑了：“傻孩子，那里边已经有了人呢。”","“谁？”我们都吃惊了。","“嫦娥。”奶奶说。","“嫦娥是谁？”","“一个女子。”","哦，一个女子。我想：月亮里，地该是银铺的，墙该是玉砌的，那么好个地方，配住的一定是十分漂亮的女子了。","“有三妹漂亮吗？”","“和三妹一样漂亮的。”","三妹就乐了：“啊啊，月亮是属于我的了！”","三妹是我们中最漂亮的，我们都羡慕起来；望着她的狂样儿，心里却有了一丝嫉妒。我们便争执起来，每个人都说月亮是属于自己的。","奶奶说：“月亮是每个人的，它并没走，你们去找它吧。”","我们越发觉得奇了，便在院里找起来。妙极了，它真没有走掉，我们很快就在葡萄叶儿上、瓷花盆儿上、爷爷的锹刃儿上找到了。我们来了兴趣，竟寻出院门。","院门外是一条小河。河水细细的，却漫着一大片的净沙，全没白日那么的粗糙，灿烂地闪着银光。我们从沙滩上跑过去，弟弟刚站到河的上湾，就大呼小叫：“月亮在这儿！”","妹妹几乎同时在下湾喊道：“月亮在这儿！”","我两处去看了，两处的水里都有月亮，沿着河边跑，哪一处的水里都有月亮了。我们都看向天上，我突然又在弟弟妹妹的眼睛里看见了小小的月亮。我想，我的眼睛里也一定是会有的。噢，月亮竟是这么多的：只要你愿意，它就有了哩。","我们坐在沙滩上，掬着沙，瞧那光辉……正像奶奶说的那样：它是属于我们的，每个人的。我们又仰起头来看那天上的月亮，月亮白光光的，在天空上。我突然觉得，我们有了月亮，那无边无际的天空也是我们的了。"]},{"id":359,"grade":"五年级上册","title":"语文园地","paragraphs":["夕阳西下，乌鸦归巢。","夕阳斜照西山时，动人的是点点归鸦急急匆匆地朝窠里飞去。","院子的中央，有一棵桂树。","院子的中央处，是那棵粗粗的桂树，疏疏的枝，疏疏的叶，桂花还没有开，却有了累累的骨朵儿了。","作者：[唐代] 张志和","西塞山前白鹭飞，","桃花流水鳜鱼肥。","青箬笠，","绿蓑衣，","斜风细雨不须归。","西塞山前白鹭在自由地翱翔，江岸桃花盛开，江水中肥美的鳜鱼欢快地游来游去。","渔翁头戴青色斗笠，身披绿色蓑衣，冒着斜风细雨，悠然自得地垂钓，连下了雨都不回家。","张志和（732年—774年？），唐代诗人，字子同，初名龟龄，号玄真子。祁门县灯塔乡张村庇人，祖籍浙江金华，先祖湖州长兴房塘。张志和三岁就能读书，六岁做文章，十六岁明经及第，先后任翰林待诏、左金吾卫录事参军、南浦县尉等职。后有感于宦海风波和人生无常，在母亲和妻子相继故去的情况下，弃官弃家，浪迹江湖。著作有《玄真子》十二卷三万字，《大易》十五卷，有《渔夫词》五首、诗七首传世。"]},{"id":360,"grade":"五年级上册","title":"24 古人谈读书","paragraphs":["一","知之为知之，不知为不知，是知也。","敏而好学，不耻下问。","默而知之，学而不厌，诲人不倦。","我非生而知之者，好古，敏以求之者也；","学如不及，犹恐失之。","吾尝终日不食，终夜不寝，以思，无益，不如学也。","——《论语》","二","余尝谓读书有三到，谓心到、眼到、口到。心不在此，则眼不看仔细，心眼既不专一，却只漫浪诵读，决不能记，记亦不能久也。三到之中，心到最急。心既到矣，眼口岂不到乎?","——宋【朱熹】","天资聪明而又好学的人，不以向地位比自己低、学识比自己差的人请教为耻。知道就是知道，不知道就是不知道，这才是真正的智慧。默默地记住所学的知识，学习不觉得满足，教人不知道疲倦。","我曾经说：读书讲究“三到”，即读书时要专心，要认真看，要诵读。心思不在书本上，那么眼睛就不会仔细看；心和眼既然没有专注统一，却只是随随便便地读，那么一定不会记住，就算记住了，也记不长久。这三到中，心到最重要。若心神集中了，眼和口还会不集中吗？","士人读书，第一要有志向，第二要有见识，第三要有恒心。有志气则绝对不会甘心居于下等；有见识则知道学无止境，不敢稍有心得就自我满足，像河伯观海，井底之蛙观天，这都是没有见识的；有恒心则必然没有干不成的事情。有志、有识、有恒，三者缺一不可。"]},{"id":361,"grade":"五年级上册","title":"25 忆读书","paragraphs":["一谈到读书，我的话就多了！","我会认字后不到几年，就开始读书。倒不是四岁时读母亲教给我的国文教科书，而是七岁时开始自己读“话说天下大势，分久必合，合久必分……”的《三国演义》。","那时，我的舅父杨子敬先生每天晚饭后，必给我们几个表兄妹讲一段《三国演义》，我听得津津有味，什么“宴桃园豪杰三结义，斩黄巾英雄首立功”，真是好听极了。但是他讲了半个钟头，就停下去干他的公事了。我只好带着对故事下文的无限期待，在母亲的催促下含泪上床。","此后，我决定咬了牙拿起一本《三国演义》，自己一知半解地读了起来，居然越看越明白。虽然字音都读得不对，比如说把“凯”念作“岂”，把“诸”念作“者”之类，因为只学过那个字的一半。","我第一次读《三国演义》，读到关羽死了，哭了一场，便把书丢下了。第二次再读时，到诸葛亮死了，又哭了一场，又把书丢下了。后来忘了是什么时候才把全书读到“分久必合”的结局。","因为看《三国演义》引起了我对章回小说的兴趣，对于那部述说“官迫民反”的《水浒传》尤其欣赏。那部书里着力描写的人物，如林冲、武松、鲁智深，都有极其生动的性格，虽然因为作者要凑成三十六天罡七十二地煞，勉勉强强地凑满了一百零八人的数目，但我觉得比没有人物个性的《荡寇志》要强多了。","《红楼梦》是我在十二三岁时看的，起初我对它的兴趣并不大，贾宝玉的女声女气，林黛玉的哭哭啼啼都使我厌烦。还是到了中年以后再拿起这部书看时，才尝到“满纸荒唐言，一把辛酸泪”所包含的一个朝代和家庭兴亡盛衰的滋味。","总而言之，统而言之，我这一辈子读到的中外文艺作品不能算太少。我永远感到读书是我生命中最大的快乐！从读书中我还得到了做人处世要独立思考的大道理，这都是从修身课本中得不到的。","我自1980年到日本访问回来后，即因腿伤闭门不出，“行万里路”做不到了，“读万卷书”便是我唯一的消遣。我每天都会得到许多书刊，知道了许多事情，也认识了许多人物。同时，书看多了，我也会挑选、比较。比如说看了精彩的《西游记》就会丢下烦琐的《封神榜》，看了人物栩栩如生的《水浒传》就不会看索然无味的《荡寇志》。对于现代的文艺作品，那些写得朦朦胧胧的、堆砌了许多华丽词句的、无病而呻的文字，我一看就从脑中抹去。但是那些满带着真情实感、十分质朴浅显的篇章，哪怕只有几百上千字，也往往使我心动神移，不能自已！","书看多了，从中也得到了一个体会，物怕比，人怕比，书也怕比，“不比不知道，一比吓一跳”。","因此，某年的“六一”国际儿童节，有个儿童刊物要我给儿童写几句指导读书的话，我只写了九个字，就是：","读书好，多读书，读好书。"]},{"id":362,"grade":"五年级上册","title":"26* 我的“长生果”","paragraphs":["书，被人们称为人类文明的“长生果”。这个比喻，我觉得特别亲切。","像蜂蝶飞过花丛，像泉水流经山谷，我每忆及少年时代，就禁不住涌起愉悦之情。在记忆中，少年时代的读书生活恰似一幅流光溢彩的画页，也似一阕跳跃着欢快音符的乐章。","我最早的读物是被孩子们叫作“香烟人”的小画片。那是一种比火柴盒略大的硬纸片，正面印画，背面印字，是每盒香烟中的附赠物。遇到大人让孩子买烟，这美差往往被男孩抢了去，我们女孩只落了个眼羡的份儿。男孩子集得多了，就开始比赛用手掌刮“香烟人”，看谁刮得远。这时，我就卖力地呐喊助威，为的是最后能在赢家手里饱览那一大沓画片。这些印着“水浒”“三国”故事的小画片，是我最早见到的连环画。","开始我看得津津有味，天长日久，就感到不过瘾了。","后来，我看到几本真正的连环画。一位爱好美术的小学教师，他有几套连环画，我看得如醉如痴：《七色花》引得我浮想联翩，《血泪仇》又叫我泪落如珠。后来，哥哥的朋友们送了我几册小书：《刘胡兰小传》《卓娅和舒拉的故事》《古丽雅的道路》……只要手中一有书，我就忘了吃、忘了睡。","渐渐地，连环画一类的小书已不能使我满足了，我又发现了一块“绿洲”——小镇的文化站有几百册图书！我每天一放下书包就直奔那里。几个月的工夫，这个小图书馆所有的文艺书籍，我差不多都借阅了。我读得很快，囫囵吞枣，大有“不求甚解”的味道。吸引我的首先是故事，是各种人物的命运遭遇，他们的悲欢离合常常使我牵肠挂肚。","莎士比亚说：“书籍是全世界的营养品。”像我这样对阅读如饥似渴的少年，它的功用更是不言而喻。醉心阅读使我得到了报偿。从小学三年级开始，我的作文便常常居全班之冠。阅读也大大扩展了我的想象力，在家对着一面花纹驳杂的石墙，我会待上半天，构想种种神话传说。","记得有一次，作文的题目是“秋天来了”。老师读了一段范文之后，当大多数同学千篇一律地开始写“秋天来了，树叶黄了，一片一片地飘到了地上”时，我心里忽然掠过了不安分的一念：大家都这样写多没意思！我要用自己的眼睛去看秋天，用自己的感受去写秋天。","我把秋天比作一个穿着金色衣裙的仙女，她那轻飘的衣袖拂去了太阳的焦热，将明亮和清爽撒给大地；她用宽大的衣衫挡着风寒，却捧起沉甸甸的果实奉献人间。人们都爱秋天，爱她的天高气爽，爱她的云淡日丽，爱她的香飘四野。秋天，使农民的笑容格外灿烂。","于是，我的作文得了个“甲优”，老师在文中又圈又点，并将它作为范文在班上朗读。","这小小的光荣，使我悟得一点道理：作文，首先构思要别出心裁，落笔也要有点与众不同的“鲜味”才好。这些领悟自然是课外读物的馈赠。","后来，我又不满足于只看一般的故事书了，学校图书馆那丰富的图书又像磁石一样吸引着我。那些古今中外的大部头小说使我着迷，我把所有课余时间都花在借阅图书上。这时我养成了做笔记的习惯：记书中优美的词语，记描写的精彩段落。做笔记锻炼了我的记忆力，也增强了我的理解力。","有一次命题作文写“一件不愉快的往事”，我的情绪分外激动，觉得自己得到了一个大显身手的好机会：小时候受过的一次委屈，平常积累的那些描写苦恼心境的词语，像酵母似的发挥了作用。我从一个清冷的黄昏开始写，以月亮的美丽皎洁和周围人的嬉笑，来反衬一个受委屈的小女孩的孤独和寂寞。写着写着，我禁不住眼泪汪汪。这篇充满真情实感的作文又得到了好评，被用大字誊抄出来贴在教室的墙上。可是，看到老师用红笔圈出我写的月亮“像一轮玉盘嵌在蓝色的天幕中”这句话，说这个“嵌”字用得特别传神时，我脸红了。我不能心安理得地接受这个赞誉——因为这句描写和这个“特别传神”的“嵌”字，是我看了巴金先生的《家》后念念不忘的词句。","于是，我又悟出了一点道理：作文，要写真情实感；作文练习，开始离不开借鉴和模仿，但是真正打动人心的东西，应该是自己呕心沥血的创造。"]},{"id":363,"grade":"五年级上册","title":"语文园地","paragraphs":["书，被人们称为人类文明的“长生果”。","莎士比亚说：“书籍是全世界的营养品。”","一本你喜爱的书就是一位朋友，也是一处你随时想去就去的故地。","作者：[宋代] 朱熹","半亩方塘一鉴开，","天光云影共徘徊。","问渠那得清如许？","为有源头活水来。","半亩大的方形池塘像一面镜子一样打开，天光、云影在水面上闪耀浮动。","要问池塘里的水为何这样清澈呢？是因为有永不枯竭的源头源源不断地为它输送活水。","昨天夜晚江边的春水大涨，那艘大船就像一片羽毛一般轻盈。","以往花费许多力量也不能推动它，今天却能在江水中央自在漂流。","朱熹（1130年9月15日～1200年4月23日），行五十二，小名沋郎，小字季延，字元晦，一字仲晦，号晦庵，晚称晦翁，又称紫阳先生、考亭先生、沧州病叟、云谷老人、逆翁。谥文，又称朱文公。汉族，祖籍南宋江南东路徽州府婺源县（今江西省婺源），出生于南剑州尤溪（今属福建三明市）。南宋著名的理学家、思想家、哲学家、教育家、诗人、闽学派的代表人物，世称朱子，是孔子、孟子以来最杰出的弘扬儒学的大师。","作者：[宋代] 朱熹","昨夜江边春水生，","蒙冲巨舰一毛轻。","向来枉费推移力，","此日中流自在行。","半亩大的方形池塘像一面镜子一样打开，天光、云影在水面上闪耀浮动。","要问池塘里的水为何这样清澈呢？是因为有永不枯竭的源头源源不断地为它输送活水。","昨天夜晚江边的春水大涨，那艘大船就像一片羽毛一般轻盈。","以往花费许多力量也不能推动它，今天却能在江水中央自在漂流。","朱熹（1130年9月15日～1200年4月23日），行五十二，小名沋郎，小字季延，字元晦，一字仲晦，号晦庵，晚称晦翁，又称紫阳先生、考亭先生、沧州病叟、云谷老人、逆翁。谥文，又称朱文公。汉族，祖籍南宋江南东路徽州府婺源县（今江西省婺源），出生于南剑州尤溪（今属福建三明市）。南宋著名的理学家、思想家、哲学家、教育家、诗人、闽学派的代表人物，世称朱子，是孔子、孟子以来最杰出的弘扬儒学的大师。"]},{"id":364,"grade":"五年级下册","title":"四时田园杂兴（其三十一）","paragraphs":["作者：[宋代] 范成大","昼出耘田夜绩麻，","村庄儿女各当家。","童孙未解供耕织，","也傍桑阴学种瓜。","白天去田里从事田间劳动，夜晚在家中搓麻线，村中男男女女各有各的家务劳动。","小孩子虽然不会耕田织布，也在那桑树荫下学着种瓜。","范成大（1126-1193），字至能，号称石湖居士。汉族，平江吴县（今江苏苏州）人。南宋诗人。谥文穆。从江西派入手，后学习中、晚唐诗，继承了白居易、王建、张籍等诗人新乐府的现实主义精神，终于自成一家。风格平易浅显、清新妩媚。诗题材广泛，以反映农村社会生活内容的作品成就最高。他与杨万里、陆游、尤袤合称南宋“中兴四大诗人”。"]},{"id":365,"grade":"五年级下册","title":"稚子弄冰","paragraphs":["作者：[宋代] 杨万里","稚子金盆脱晓冰，","彩丝穿取当银钲。","敲成玉磬穿林响，","忽作玻璃碎地声。","儿童早晨起来，将冻结在铜盆里的冰块脱下，用彩线穿起来当钲。","敲出的声音像玉磬一般穿越树林，忽然冰锣敲碎落地，发出玉石摔碎般的声音。","杨万里（1127年10月29日－1206年6月15日），字廷秀，号诚斋。吉州吉水（今江西省吉水县黄桥镇湴塘村）人。南宋著名诗人、大臣，与陆游、尤袤、范成大并称为“中兴四大诗人”。因宋光宗曾为其亲书“诚斋”二字，故学者称其为“诚斋先生”。杨万里一生作诗两万多首，传世作品有四千二百首，被誉为一代诗宗。他创造了语言浅近明白、清新自然，富有幽默情趣的“诚斋体”。杨万里的诗歌大多描写自然景物，且以此见长。他也有不少篇章反映民间疾苦、抒发爱国感情的作品。著有《诚斋集》等。"]},{"id":366,"grade":"五年级下册","title":"村晚","paragraphs":["作者：[宋代] 雷震","草满池塘水满陂，","山衔落日浸寒漪。","牧童归去横牛背，","短笛无腔信口吹。","池塘四周长满了水草，池塘里的水几乎溢出了塘岸，山像是衔着落日似地倒映在波光荡漾的水面上。","放牛的孩子横坐在牛背上，慢慢的朝家而去，拿着短笛随便地吹奏着不成调的曲子。","雷震，宋朝，生平不详。或以为眉州(今四川眉山)人，宋宁宗嘉定年间进士。又说是南昌(今属江西)人，宋度宗咸淳元年(1265)进士。其诗见《宋诗纪事》卷七十四。"]},{"id":367,"grade":"五年级下册","title":"2 祖父的园子","paragraphs":["我家有一个大花园，这花园里蜜蜂、蝴蝶、蜻蜓、蚂蚱，样样都有。蝴蝶有白蝴蝶、黄蝴蝶。这种蝴蝶小，不太好看。好看的是大红蝴蝶，满身带着金粉。蜻蜓是金的，蚂蚱是绿的。蜜蜂则嗡嗡地飞着，满身绒毛，落到一朵花上，胖乎乎，圆滚滚，就像一个小毛球似的不动了。","花园里边明晃晃的，红的红，绿的绿，新鲜漂亮。","据说这花园，从前是一个果园。祖母喜欢养羊，羊把果树给啃了，果树渐渐地都死了。到我有记忆的时候，园子里就只有一棵樱桃树、一棵李子树，因为樱桃和李子都不大结果子，所以觉得它们并不存在。小的时候，只觉得园子里边就有一棵大榆树。这榆树在园子的西北角上，来了风，榆树先呼叫，来了雨，榆树先冒烟。太阳一出来，榆树的叶子就发光了，它们闪烁得和沙滩上的蚌壳一样。","祖父整天都在园子里，我也跟着他在里面转。祖父戴一顶大草帽，我戴一顶小草帽；祖父栽花，我就栽花；祖父拔草，我就拔草。祖父种小白菜的时候，我就跟在后边，用脚把那下了种的土窝一个一个地溜平。哪里会溜得准，不过是东一脚西一脚地瞎闹。有时不但没有把菜种盖上，反而把它踢飞了。","祖父铲地，我也铲地。因为我太小，拿不动锄头，祖父就把锄头杆拔下来，让我单拿着那个锄头的“头”来铲。其实哪里是铲，不过是伏在地上，用锄头乱钩一阵。我认不得哪个是苗，哪个是草，往往把韭菜当做野草割掉，把狗尾草当做谷穗留着。","祖父发现我铲的那块地还留着一片狗尾草，就问我：“这是什么？”","我说：“谷子。”","祖父大笑起来，笑够了，把草拔下来，问我：“你每天吃的就是这个吗？”","我说：“是的。”","我看祖父还在笑，就说：“你不信，我到屋里拿来给你看。","我跑到屋里拿了一个谷穗，远远地抛给祖父，说：“这不是一样的吗？”","祖父把我叫过去，慢慢讲给我听，说谷子是有芒针的，狗尾草却没有，只是毛嘟嘟的，很像狗尾巴。","我并不细看，不过马马虎虎承认下来就是了。一抬头，看见一个黄瓜长大了，我跑过去摘下来，吃黄瓜去了。黄瓜还没有吃完，我又看见一只大蜻蜓从旁边飞过，于是丢下黄瓜又去追蜻蜓了。蜻蜓飞得那么快，哪里会追得上？好在一开始我也没有存心一定要追上，跟着蜻蜓跑了几步就又去做别的了。采一朵倭瓜花，捉一个绿蚂蚱，把蚂蚱腿用线绑上，绑了一会儿，线头上只拴着一条腿，而不见蚂蚱了。","玩腻了，我又跑到祖父那里乱闹一阵。祖父浇菜，我也过来浇，但不是往菜上浇，而是拿着水瓢，拼尽了力气，把水往天空一扬，大喊着：“下雨啰！下雨啰！”","太阳在园子里是特别大的，天空是特别高的。太阳光芒四射，亮得使人睁不开眼睛，亮得蚯蚓不敢钻出地面来，蝙蝠不敢从黑暗的地方飞出来。凡是在太阳下的，都是健康的、漂亮的。拍一拍手，仿佛大树都会发出声响；叫一两声，好像对面的土墙都会回答似的。","花开了，就像睡醒了似的。鸟飞了，就像在天上逛似的。虫子叫了，就像在说话似的。一切都活了，要做什么，就做什么。要怎么样，就怎么样，都是自由的。倭瓜愿意爬上架就爬上架，愿意爬上房就爬上房。黄瓜愿意开一朵花，就开一朵花，愿意结一个瓜，就结一个瓜。若都不愿意，就是一个瓜也不结，一朵花也不开，也没有人问它。玉米愿意长多高就长多高，它若愿意长上天去，也没有人管。蝴蝶随意地飞，一会儿从墙头上飞来一对黄蝴蝶，一会儿又从墙头上飞走一只白蝴蝶。它们是从谁家来的，又飞到谁家去？太阳也不知道。","天空蓝悠悠的，又高又远。","可是白云一来，一大团一大团的，从祖父的头上飘过，好像要压到祖父的草帽了。","我玩累了，就在房子底下找个阴凉的地方睡着了。不用枕头，不用席子，把草帽遮在脸上就睡了。"]},{"id":368,"grade":"五年级下册","title":"3* 月是故乡明","paragraphs":["每个人都有个故乡，每个人的故乡都有个月亮。人人都爱自己故乡的月亮。","但是，如果只有孤零零一个月亮，未免显得有点儿孤单。因此，在中国古代诗文中，总有什么东西给月亮当陪衬，最多的是山和水，比如“山高月小”“三潭印月”，不可胜数。我的故乡是在山东西北部的大平原上。我小的时候，从来没有见过山，也不知山为何物。我曾幻想，山大概是一个圆而粗的柱子吧，顶天立地，好不威风。后来到了济南，才见到山，恍然大悟：山原来是这个样子啊！因此，我在故乡望月，从来不同山联系。像苏东坡说的“月出于东山之上，徘徊于斗牛之间”，完全是我无法想象的。","至于水，我故乡的小村子里却到处都是。几个大苇坑占了村子面积的一多半。在我这个小孩子眼中，虽不能像洞庭湖“八月湖水平”那样有气派，但也颇有烟波浩渺之势。到了夏天，黄昏后，我躺在坑边场院的地上，数天上的星星。有时候在古柳下面点起篝火，然后上树一摇，成群的知了飞落下来，比白天用嚼烂的麦粒去粘要容易得多。我天天晚上乐此不疲，天天盼望黄昏早早来临。","到了更晚的时候，我走到坑边，抬头看到晴空一轮明月，清光四溢，与水里的那个月亮相映成趣。我当时虽然还不懂什么叫诗兴，可觉得心中油然有什么东西在萌动。有时候在坑边玩很久，才回家睡觉。在梦中见到两个月亮叠在一起，清光更加晶莹澄澈。","我在故乡只待了六年，以后就离乡背井，漂泊天涯。在济南住了十多年，在北京度过四年，又回到济南待了一年，然后在欧洲住了近十一年，又回到北京，到现在已经四十多年了。在这期间，我曾到过将近三十个国家，看到过许许多多的月亮。在风光旖旎的瑞士莱芒湖上，在无边无垠的非洲大沙漠中，在碧波万顷的大海中，在巍峨雄奇的高山上，我都看到过月亮。这些月亮应该说都是美妙绝伦的，我都非常喜欢。但是，看到它们，我立刻就会想到故乡苇坑上面和水中的那个小月亮。对比之下，我感到这些广阔世界的大月亮，无论如何比不上我那心爱的小月亮。不管我离开故乡多远，我的心立刻就飞回去了。我的小月亮，我永远忘不掉你！","我现在年事已高，住的朗润园是燕园胜地。夸大一点儿说，此地有茂林修竹，绿水环流，还有几座土山点缀其间，风光无疑是绝妙的。每逢望夜，一轮当空，月光闪耀于碧波之上，上下空蒙，一碧数顷，荷香远溢，宿鸟幽鸣，真不能不说是赏月胜地。荷塘月色的奇景，就在我的窗外。然而，每逢这样的良辰美景，我想到的却仍然是故乡苇坑里的那个平凡的小月亮。","月是故乡明，我什么时候能够再看到故乡的月亮啊！"]},{"id":369,"grade":"五年级下册","title":"4* 梅花魂","paragraphs":["故乡的梅花又开了。一年一度，那朵朵冷艳、缕缕幽芳的梅花，总让我想起飘泊他乡、葬身异国的外祖父。","我出生在东南亚的星岛，从小和外祖父生活在一起。外祖父年轻时读了不少经、史、诗、词，又能书善画，在星岛文坛颇负盛名。我很小的时候，外祖父常常抱着我，坐在花梨木大交椅上，一遍又一遍、不厌其烦地教我读唐诗宋词。每当读到“独在异乡为异客，每逢佳节倍思亲”“春草明年绿，王孙归不归”“自在飞花轻似梦，无边丝雨细如愁”之类的句子，常会有一颗两颗冰凉的泪珠落在我的腮边、手背。这时候，我会拍着手笑起来：“外公哭了！外公哭了！”老人总是摇摇头，长长地叹一口气，说：“莺儿，你还小呢，不懂！”","外祖父家中有不少古玩，我偶尔摆弄，老人也不甚在意。唯独书房里那一幅老干虬枝的墨梅图，他分外爱惜，家人碰也碰不得。我五岁那年，有一回到书房玩耍，不小心在上面留了个脏手印，外祖父顿时拉下脸来。有生以来，我第一次听到他训斥我母亲：“孩子要管教好，这清白的梅花，是能玷污的吗？”训罢，便用刀片轻轻刮去污迹，又用细绸子慢慢抹净。看见慈祥的外祖父大发脾气，我心里又害怕又奇怪：一幅画而已，有什么稀罕的呢？","有一天，母亲忽然跟我说：“莺儿，我们要回中国去！”","“干吗要回去呢？”","“那儿才是我们的祖国啊！”","哦！祖国，就是那拥有长江、黄河、万里长城的地方吗？我欢呼起来，小小的心充满了欢乐。","可是，我马上想起外祖父，我亲爱的外祖父。我问母亲：“外公走吗？”","“外公年纪太大了……”","我跑进外祖父的书房，老人正躺在藤椅上。我说：“外公，您也回祖国去吧！”","想不到外祖父竟像小孩子一样，呜呜呜地哭了起来……","离别的前一天早上，外祖父早早地起了床，把我叫到书房里，郑重地递给我一卷白杭绸包着的东西。我打开一看，原来是那幅墨梅图，就说：“外公，这不是您最宝贵的画吗？”","“是啊，莺儿，你要好好保存！这梅花，是我们中国最有名的花。旁的花，大抵是春暖才开花。她却不一样，愈是寒冷，愈是风欺雪压，花开得愈精神，愈秀气。她是最有品格、最有灵魂、最有骨气的！几千年来，我们中华民族出了许多有气节的人物，他们不管历经多少磨难，不管受到怎样的欺凌，从来都是顶天立地，不肯低头折节。他们就像这梅花一样。一个中国人，无论在怎样的境遇里，总要有梅花的秉性才好！”","回国的那一天正是元旦，虽然热带是无所谓隆冬的，但腊月天气，也毕竟凉飕飕的。外祖父把我们送到码头。风撩乱了老人平日梳理得整整齐齐的银发，我觉得外祖父一下子衰老了许多。","船快开了，母亲只好狠下心来，拉着我登上大客轮。想不到眼含泪水的外祖父也随着上了船，递给我一块手绢——雪白的细亚麻布上绣着血色的梅花。","当年的我，还过于稚嫩，并不懂得，我带走的，岂止是我慈爱的外祖父珍藏的一幅丹青、几朵血梅？我带走的，是身在异国的华侨老人一颗眷恋祖国的赤子心啊！"]},{"id":370,"grade":"五年级下册","title":"语文园地","paragraphs":["太阳光芒四射，亮得使人睁不开眼睛，亮得蚯蚓不敢钻出地面来，蝙蝠不敢从黑暗的地方飞出来。","八月，天多热。鸡热得耷拉着翅膀，狗热得吐出舌头，蝉热得不知如何是好。","在风光旖旎的瑞士莱芒湖上，在无边无垠的非洲大沙漠中，在碧波万顷的大海中，在巍峨雄奇的高山上，我都看到过月亮。……对比之下，我感到这些广阔世界的大月亮，无论如何比不上我那心爱的小月亮。","这里的桂花再香，也比不上家乡院子里的桂花。","虽然姑爹小船上盖的只是破旧的蓬，远比不上绍兴的乌篷船精致，但姑爹的小渔船仍然是那么亲切，那么难忘……","作者：[唐代] 孟郊","慈母手中线，","游子身上衣。","临行密密缝，","意恐迟迟归。","谁言寸草心，","报得三春晖。","慈祥的母亲手里把着针线，为即将远游的孩子赶制新衣。","临行前一针针密密地缝缀，怕儿子回来得晚衣服破损。","谁说像小草那样微弱的孝心，能报答得了像春晖普泽的慈母恩情？","孟郊，(751～814)，唐代诗人。字东野。汉族，湖州武康（今浙江德清）人，祖籍平昌（今山东临邑东北），先世居洛阳（今属河南）。唐代著名诗人。现存诗歌500多首，以短篇的五言古诗最多，代表作有《游子吟》。有“诗囚”之称，又与贾岛齐名，人称“郊寒岛瘦”。元和九年，在阌乡(今河南灵宝)因病去世。张籍私谥为贞曜先生。"]},{"id":371,"grade":"五年级下册","title":"5 草船借箭","paragraphs":["周瑜对诸葛亮心怀妒忌。","有一天，周瑜请诸葛亮商议军事，说∶“我们就要跟曹军交战了。水上交战，用什么兵器最好？”诸葛亮说∶“用弓箭最好。”周瑜说∶“对，先生跟我想的一样。现在军中缺箭，想请先生负责赶造十万支。这是公事，希望先生不要推却。”诸葛亮说∶“都督委托，当然照办。不知道这十万支箭什么时候用？”周瑜问∶“十天造得好吗？”诸葛亮说∶“既然就要交战，十天造好，必然误了大事。”周瑜问∶“先生预计几天可以造好？”诸葛亮说∶“只要三天。”周瑜说∶“军情紧急，可不能开玩笑。”诸葛亮说∶“怎么敢跟都督开玩笑？我愿意立下军令状，三天造不好，甘受重罚。”周瑜很高兴，叫诸葛亮当面立下军令状，又摆了酒席招待他。诸葛亮说∶“今天来不及了。从明天算起，到第三天，请派五百个军士到江边来搬箭。”诸葛亮喝了几杯酒就走了。","鲁肃对周瑜说∶“十万支箭，三天怎么造得成呢？诸葛亮说的是假话吧？”周瑜说∶“是他自己说的，我可没逼他。我得吩咐军匠们，叫他们故意迟延，造箭用的材料不给他准备齐全。到时候造不成，定他的罪，他就没话可说了。你去探听探听，看他怎么打算，回来报告我。”","鲁肃见了诸葛亮。诸葛亮说∶“三天之内要造十万支箭，得请你帮帮我的忙。”鲁肃说∶“都是你自找的，我怎么帮得了你的忙？”诸葛亮说∶“你借给我二十条船，每条船上要三十多名军士。船用青布幔子遮起来，还要一千多个草把子，排在船的两边。我自有妙用。第三天管保有十万支箭。不过不能让都督知道。他要是知道了，我的计划就完了。”","鲁肃答应了。他不知道诸葛亮借船有什么用，回来报告周瑜，果然不提借船的事，只说诸葛亮不用竹子、翎毛、胶漆这些材料。周瑜疑惑起来，说∶“到了第三天，看他怎么办！”","鲁肃私自拨了二十条快船，每条船上配三十多名军士，照诸葛亮说的，布置好青布幔子和草把子，等诸葛亮调度。第一天，不见诸葛亮有什么动静；第二天，仍然不见诸葛亮有什么动静；直到第三天四更时候，诸葛亮秘密地把鲁肃请到船里。鲁肃问他∶“你叫我来做什么？”诸葛亮说∶“请你一起去取箭。”鲁肃问∶“哪里去取？”诸葛亮说∶“不用问，去了就知道。”诸葛亮吩咐把二十条船用绳索连接起来，朝北岸开去。","这时候大雾漫天，江上的人连面对面都看不清。五更时分，船已经靠近曹军的水寨。诸葛亮下令把船头朝西，船尾朝东，一字摆开，又叫船上的军士一边擂鼓，一边呐喊。鲁肃吃惊地说∶“如果曹兵出来，怎么办？”诸葛亮笑着说∶“雾这么大，曹操一定不敢派兵出来。我们只管饮酒取乐，雾散了就回去。”","曹操得知江上的动静后，就下令说∶“江上雾很大，敌人忽然来攻，必有埋伏，我们看不清虚实，不要轻易出动。拨水军弓弩手朝他们射箭便是。”然后，他又派人去旱寨调来六千名弓弩手，到江边支援水军。一万多名弓弩手一齐朝江中放箭，箭好像下雨一样。诸葛亮又下令把船掉过来，船头朝东，船尾朝西，仍旧擂鼓呐喊，逼近曹军水寨受箭。","到雾散时，诸葛亮下令返回。船两边的草把子上都插满了箭。诸葛亮吩咐军士们齐声高喊“谢谢曹丞相的箭”。曹操知道上了当，可是诸葛亮那边船轻水急，已经驶出二十多里，要追也来不及了。","二十条船靠岸的时候，周瑜派来搬箭的五百个军士已经等在江边了。每条船有五六千支箭，二十条船总共有十万多支。鲁肃见了周瑜，告诉他借箭的经过。周瑜大吃一惊，长叹道∶“诸葛亮神机妙算，我真比不上他！”"]},{"id":372,"grade":"五年级下册","title":"6 景阳冈","paragraphs":["武松在路上行了几日，来到阳谷县地面。此去离县治还远。当日晌午时分，走得肚中饥渴，望见前面有一个酒店，挑着一面招旗在门前，上头写着五个字道∶“三碗不过冈。”武松入到里面坐下，把梢棒倚了，叫道∶“主人家，快把酒来吃。”只见店主人把三只碗，一双箸，一碟热菜，放在武松面前，满满筛一碗酒来。武松拿起碗，一饮而尽，叫道∶“这酒好生有气力！主人家，有饱肚的买些吃酒。”酒家道∶“只有熟牛肉。”武松道∶“好的切二三斤来吃酒。”店家去里面切出二斤熟牛肉，做一大盘子将来，放在武松面前，随即再筛一碗酒。武松吃了道∶“好酒！”又筛下一碗，恰好吃了三碗酒，再也不来筛。武松敲着桌子叫道∶“主人家，怎的不来筛酒？”酒家道∶“客官要肉便添来。”武松道∶“我也要酒，也再切些肉来。”酒家道∶“肉便切来，添与客官吃，酒却不添了。”武松道∶“却又作怪。”便问主人家道：“你如何不肯卖酒与我吃？”酒家道∶“客官，你须见我门前招旗，上面明明写道‘三碗不过冈’。”武松道∶“怎地唤做三碗不过冈？”酒家道∶“俺家的酒，虽是村酒，却比老酒的滋味。但凡客人来我店中吃了三碗的，便醉了，过不得前面的山冈去。因此唤做‘三碗不过冈’。若是过往客人到此，只吃三碗，更不再问。”武松笑道∶“原来恁地。我却吃了三碗，如何不醉？”酒家道∶“我这酒叫做‘透瓶香’，又唤做‘出门倒’。初入口时，醇醲好吃，少刻时便倒。”武松道：“休要胡说。没地不还你钱，再筛三碗来我吃。”酒家见武松全然不动，又筛三碗。武松吃道：“端的好酒！主人家，我吃一碗，还你一碗钱，只顾筛来。”酒家道：“客官休只管要饮，这酒端的要醉倒人，没药医。”武松道：“休得胡说！便是你使蒙汗药在里面，我也有鼻子。”店家被他发话不过，一连又筛了三碗。武松道：“肉便再把二斤来吃。”酒家又切了二斤熟牛肉，再筛了三碗酒。武松吃得口滑，只顾要吃，去身边取出些碎银子，叫道：“主人家，你且来看我银子，还你酒肉钱勾么？”酒家看了道：“有余，还有些贴钱与你。”武松道：“不要你贴钱，只将酒来筛。”酒家道：“客官，你要吃酒时，还有五六碗酒哩，只怕你吃不的了。”武松道：“就有五六碗多时，你尽数筛将来。”酒家道：“你这条长汗，倘或醉倒了时，怎扶的你住？”武松答道：“要你扶的不算好汉。”酒家再筛了六碗酒与武松吃了。绰了梢棒，立起身来道：“我却又不曾醉。”走出门前来，笑道：“却不说‘三碗不过冈’！”手提梢棒便走。","酒家赶出来叫道∶“客官那里去？”武松立住了，问道∶“叫我做甚么？我又不少你酒钱，唤我怎地？”酒家叫道∶“我是好意。你且回来我家看官司榜文。”武松道∶“甚么榜文？”酒家道∶“如今前面景阳冈上，有只吊睛白额大虫，晚了出来伤人，坏了三二十条大汉性命。官司如今杖限打猎捕户，擒捉发落。冈子路口两边人民，都有榜文。可教往来客人，结伙成队，于巳、午、未三个时辰过冈，其余寅、卯、申、酉、戌、亥六个时辰，不许过冈。更兼单身客人，不许白日过冈，务要等伴结伙而过。这早晚正是未末申初时分，我见你走都不问人，枉送了自家性命。不如就我此间歇了，等明日慢慢凑的三二十人，一齐好过冈子。”武松听了，笑道∶“我是清河县人氏，这条景阳冈上少也走过了一二十遭，几时见说有大虫！你休说这话来吓我！便有大虫，我也不怕。”酒家道∶“我是好意救你。你不信时，进来看官司榜文。”武松道∶“便真个有虎，老爷也不怕。你留我在家里歇，莫不半夜三更要谋我财，害我性命，却把大虫吓我？”酒家道∶“你看么！我是一片好心，反做恶意，倒落得你恁地说。你不信我时，请尊便自行。”","那酒店里主人摇着头，自进店里去了。这武松提了梢棒，大着步自过景阳冈来。约行了四五里路，来到冈子下，见一大树，刮去了皮，一片白，上写两行字。武松也颇识几字，抬头看时，上面写道∶“近因景阳冈大虫伤人，但有过往客商，可于巳、午、未三个时辰，结伙成队过冈。请勿自误。”武松看了，笑道∶“这是酒家诡诈，惊吓那等客人，便去那厮家里宿歇。我却怕甚么！”横拖着梢棒，便上冈子来。那时已有申牌时分。这轮红日，厌厌地相傍下山。武松乘着酒兴，只管走上冈子来。走不到半里多路，见一个败落的山神庙。行到庙前，见这庙门上贴着一张印信榜文。武松住了脚读时，上面写道：","“阳谷县示：为这景阳冈上新有一只大虫，近来伤害人命。见今杖限各乡里正并猎户人等，打捕未获。如有过往客商人等，可于巳、午、未三个时辰，结伴过冈。其余时分及单身客人，白日不许过冈。恐被伤害性命不便。各宜知悉。”","武松读了印信榜文，方知端的有虎。欲待发步再回酒店里来，寻思道∶“我回去时，须吃他耻笑，不是好汉，难以转去。”存想了一回，说道∶“怕甚么！且只顾上去，看怎地！”武松正走，看看酒涌上来，便把毡笠儿背在脊梁上，将梢棒绾在肋下，一步步上那冈子来。回头看这日色时，渐渐地坠下去了。此时正是十月间天气，日短夜长，容易得晚。武松自言自语道∶“那得甚么大虫！人自怕了，不敢上山。”武松走了一直，酒力发作，焦热起来，一只手提着梢棒，一只手把胸膛前袒开，踉踉跄跄，直奔过乱树林来。见一块光挞挞大青石，把那梢棒倚在一边，放翻身体，却待要睡，只见发起一阵狂风来。","那一阵风过处，只听得乱树背后扑地一声响，跳出一只吊睛白额大虫来。武松见了，叫声“呵呀！”从青石上翻将下来，便拿那条梢棒在手里，闪在青石边。那个大虫又饥又渴，把两只爪在地下略按一按，和身望上一扑，从半空里撺将下来。武松被那一惊，酒都做冷汗出了。说时迟，那时快。武松见大虫扑来，只一闪，闪在大虫背后。那大虫背后看人最难，便把前爪搭在地下，把腰胯一掀，掀将起来。武松只一躲，躲在一边。大虫见掀他不着，吼一声，却似半天里起个霹雳，振得那山冈也动。把这铁棒也似虎尾倒竖起来，只一剪。武松却又闪在一边。原来那大虫拿人，只是一扑，一掀，一剪，三般提不着时，气性先自没了一半。那只大虫又剪不着，再吼了一声，一兜兜将回来。武松见那大虫复翻身回来，双手抡起梢棒，尽平生气力，只一棒，从半空劈将下来。只听得一声响，簌簌地将那树连枝带叶劈脸打将下来。定睛看时，一棒劈不着大虫。原来慌了，正打在枯树上，把那条梢棒折做两截，只拿得一半在手里。那大虫咆哮，性发起来，翻身又只一扑，扑将来。武松又只一跳，却退了十步远。那只大虫却好把两只前爪搭在武松面前。武松将半截棒丢在一边，两只手就势把大虫顶花皮揪住，一按按将下来。那只大虫急要挣扎，早没了气力。被武松尽气力纳定，那里肯放半点儿松宽。武松把只脚望大虫面门上、眼睛里只顾乱踢。那大虫咆哮起来，把身底下扒起两堆黄泥，做了一个土坑。武松把那大虫嘴直按下黄泥坑里去。那只大虫吃武松奈何得没了些气力。武松把左手紧紧地揪住顶花皮，偷出右手来，提起铁锤般大小拳头，尽平生之力，只顾打。打得五七十拳，那大虫眼里、口里、鼻子里、耳朵里都迸出鲜血来。那武松尽平昔神威，仗胸中武艺，半歇儿把大虫打做一堆，却似躺着一个锦布袋。","武松放了手，来松树边寻那打折的棒橛，拿在手里，只怕大虫不死，把棒橛又打了一回。那大虫气都没了。武松再寻思道∶“我就地拖得这死大虫下冈子去。”就血泊里用双手来提时，那里提得动？原来使尽了气力，手脚都疏软了。","武松再来青石坐了半歇，寻思道∶“天色看看黑了，倘或又跳出一只大虫来时，我却怎地斗得他过？且挣扎下冈子去，明早却来理会。”就石头边寻了毡笠儿，转过乱树林边，一步步挨下冈子来。"]},{"id":373,"grade":"五年级下册","title":"7* 猴王出世","paragraphs":["海外有一国土，名曰傲来国。国近大海，海中有一座名山，唤为花果山。那座山正当顶上，有一块仙石。其石有三丈六尺五寸高，有二丈四尺围圆。四面更无树木遮阴，左右倒有芝兰相衬。盖自开辟以来，每受天真地秀，日精月华，感之既久，遂有灵通之意。内育仙胞，一日迸裂，产一石卵，似圆球样大。因见风，化作一个石猴。那猴在山中，却会行走跳跃，食草木，饮涧泉，采山花，觅树果；与狼虫为伴，虎豹为群，獐鹿为友，猕猿为亲；夜宿石崖之下，朝游峰洞之中。","一朝天气炎热，与群猴避暑，都在松阴之下顽耍。一群猴子耍了一会儿，却去那山涧中洗澡。见那股涧水奔流，真个似滚瓜涌溅。古云：“禽有禽言，兽有兽语。”众猴都道：“这股水不知是那里的水。我们今日赶闲无事，顺涧边往上溜头寻看源流，耍子去耶！”喊一声，都拖男挈女，唤弟呼兄，一齐跑来，顺涧爬山，直至源流之处，乃是一股瀑布飞泉。众猴拍手称扬道：“好水！好水！原来此处远通山脚之下，直接大海之波。”又道：“那一个有本事的，钻进去寻个源头出来，不伤身体者，我等即拜他为王。”连呼了三声，忽见丛杂中跳出一个石猴，应声高叫道：“我进去！我进去！”他瞑目蹲身，将身一纵，径跳入瀑布泉中，忽睁睛抬头观看，那里边却无水无波，明明朗朗的一架桥梁。他住了身，定了神，仔细再看，原来是座铁板桥。桥下之水，冲贯于石窍之间，倒挂流出去，遮闭了桥门。却又欠身上桥头，再走再看，却似有人家住处一般，真个好所在。看罢多时，跳过桥中间，左右观看，只见正当中有一石碣。碣上有一行楷书大字，镌着“花果山福地，水帘洞洞天”。","石猴喜不自胜，急抽身往外便走，复瞑目蹲身，跳出水外，打了两个呵呵道：“大造化！大造化！”众猴把他围住，问道：“里面怎么样？水有多深？”石猴道：“没水！没水！原来是一座铁板桥。桥那边是一座天造地设的家当。”众猴道：“怎见得是个家当？”石猴笑道：“这股水乃是桥下冲贯石窍，倒挂下来遮闭门户的。桥边有花有树，乃是一座石房。房内有石锅、石灶、石碗、石盆、石床、石凳。中间一块石碣上，镌着‘花果山福地，水帘洞洞天’。真个是我们安身之处。里面且是宽阔，容得千百口老小。我们都进去住，也省得受老天之气。”","众猴听得，个个欢喜。都道：“你还先走，带我们进去，进去！”石猴却又瞑目蹲身，往里一跳，叫道：“都随我进来！进来！”那些猴有胆大的，都跳进去了；胆小的，一个个伸头缩颈，抓耳挠腮，大声叫喊，缠一会，也都进去了。跳过桥头，一个个抢盆夺碗，占灶争床，搬过来，移过去，正是猴性顽劣，再无一个宁时，只搬得力倦神疲方止。石猴端坐上面道：“列位呵，‘人而无信，不知其可’。你们才说有本事进得来，出得去，不伤身体者，就拜他为王。我如今进来又出去，出去又进来，寻了这一个洞天与列位安眠稳睡，各享成家之福，何不拜我为王？”众猴听说，即拱伏无违。一个个序齿排班，朝上礼拜，都称“千岁大王”。自此，石猴高登王位，将“石”字隐了，遂称美猴王。"]},{"id":374,"grade":"五年级下册","title":"8* 红楼春趣","paragraphs":["一语末了，只听窗外竹子上一声响，恰似窗屉子倒了一般，众人吓了一跳。丫鬟们出去瞧时，帘外丫头子们回道：“一个大蝴蝶风筝，挂在竹梢上了。”众丫鬟笑道：“好一个齐整风筝！不知是谁家放的，断了线。咱们拿下他来。”宝玉等听了，也都出来看时，宝玉笑道：“我认得这风筝，这是大老爷那院里嫣红姑娘放的。拿下来给他送过去罢。”紫鹃笑道：“难道天下没有一样的风筝，单他有这个不成？二爷也太死心眼儿了！我不管，我且拿起来。”探春笑道：“紫鹃也太小器，你们一般有的，这会子拾人走了的，也不嫌个忌讳？“黛玉笑道：“可是呢。把咱们的拿出来，咱们也放放晦气。”","丫头们听见放风筝，巴不得一声儿，七手八脚，都忙着拿出来：也有美人儿的，也有沙雁儿的。丫头们搬高墩，捆剪子股儿，一面拨起籰子来。宝钗等立在院门前，命丫头们在院外敞地下放去。宝琴笑道：“你这个不好看，不如三姐姐的一个软翅子大凤凰好。”宝钗回头向翠墨笑道：“你去把你们的拿来也放放。”","宝玉又兴头起来，也打发个小丫头子家去，说：“把昨儿赖大娘送的那个大鱼取来。”小丫头去了半天，空手回来，笑道：“晴雯姑娘昨儿放走了。”宝玉道：“我还没放一遭儿呢！”探春笑道：“横竖是给你放晦气罢了！”宝玉道：“再把大螃蟹拿来罢。”丫头去了，同了几个人，扛了一个美人并籰子来，回说：“袭姑娘说：昨儿把螃蟹给了三爷了，这一个是林大娘才送来的，放这一个罢。”宝玉细看了一回，只见这美人做的十分精致，心中欢喜，便叫：“放起来！”","此时探春的也取了来了，丫头们在那山坡上已放起来。宝琴叫丫头放起一个大蝙蝠来，宝钗也放起个一连七个大雁来，独有宝玉的美人儿，再放不起来。宝玉说丫头们不会放，自己放了半天，只起房高，就落下来，急的头上的汗都出来了。众人都笑他，他便恨的摔在地下，指着风筝说道：“要不是个美人儿，我一顿脚跺个稀烂！”黛玉笑道：“那是顶线不好。拿去叫人换好了，就好放了。再取一个来放罢。”","宝玉等大家都仰面看天上这几个风筝起在空中。一时风紧，众丫鬟都用绢子垫着手放。黛玉见风力紧了，过去将籰子一松，只听“豁喇喇”一阵响，登时线尽，风筝随风去了。黛玉因让众人来放。众人都说：“林姑娘的病根儿都放了去了，咱们大家都放了罢。”于是丫头们拿过一把剪子来，铰断了线，那风筝飘飘飖飖随风而去。一时只有鸡蛋大，一展眼只剩下一点黑星儿，一会儿就不见了。众人仰面说道：“有趣，有趣！”说着，有丫头来请吃饭，大家方散。"]},{"id":375,"grade":"五年级下册","title":"语文园地","paragraphs":["榜文 印信 驿站 郎中","店家 客舍 货郎 墨客","但有过往客商，可于巳、午、未三个时辰，结伙成队过冈。请勿自误。","石猴喜不自胜，急抽身往外便走，复瞑目蹲身，跳出水外。","众猴听说，即拱伏无违。一个个序齿排班，朝上礼拜，都称“千岁大王”。","身穿金甲亮堂堂，头戴金冠光映映。手举金箍棒一根，足踏云鞋皆相称。一双怪眼似明星，两耳过肩查又硬。","身长八尺，面如冠玉，头戴纶巾，身披鹤氅，飘飘然有神仙之概。","身躯凛凛，相貌堂堂。一双眼光射寒星，两弯眉浑如刷漆。胸脯横阔，有万夫难敌之成风；语话轩昂，吐千丈凌云之志气。","作者：[唐代] 王维","人闲桂花落，","夜静春山空。","月出惊山鸟，","时鸣春涧中。","寂静的山谷中，只有春桂花在无声地飘落，宁静的夜色中春山一片空寂。","月亮升起月光照耀大地时惊动了山中栖鸟，在春天的溪涧里不时地鸣叫。","王维（701年－761年，一说699年—761年），字摩诘(jié)，号摩诘居士。汉族，河东蒲州（今山西运城）人，祖籍山西祁县，唐朝诗人，有“诗佛”之称。苏轼评价其：“味摩诘之诗，诗中有画；观摩诘之画，画中有诗。”开元九年（721年）中进士，任太乐丞。天宝年间，拜吏部郎中、给事中。唐肃宗乾元年间任尚书右丞，世称“王右丞”。王维是盛唐诗人的代表，今存诗400余首，重要诗作有《相思》《山居秋暝》等。王维精通佛学，受禅宗影响很大。佛教有一部《维摩诘经》，是王维名和字的由来。王维诗书画都很有名，多才多艺，音乐也很精通。与孟浩然合称“王孟”。"]},{"id":376,"grade":"五年级下册","title":"快乐读书吧","paragraphs":["诸葛亮足智多谋，李逵鲁莽刚猛，孙悟空神通广大，林黛玉多愁善感……让我们一起漫步中国古典名著长廊，走近这些人物，品读精彩故事。","你读过吗","漫漫取经路上，有妖魔鬼怪，有刀山火海，也有师徒四人坚定的背影和永不停歇的脚步。让我们随着唐僧、孙悟空、猪八戒和沙僧的脚步，体验《西游记》中险境迭出的取经之旅。三打白骨精、大战红孩儿、女儿国遇险、真假美猴王、三借芭蕉扇……一个个扣人心弦的故事会吸引我们一口气读下去。","请看第六十一回“猪八戒助力败魔王，孙行者三调芭蕉扇”中，神通广大的孙悟空与同样变化多端的牛魔王斗法的精彩情形。","这大圣收了金箍棒，捻诀念咒，摇身一变，变作一个海东青，飕的一翅，钻在云眼里，倒飞下来，落在天鹅身上，抱住颈项嗛眼。那牛王也知是孙行者变化，急忙抖抖翅，变作一只黄鹰，返来嗛海东青。行者又变作一个乌凤，专一赶黄鹰。牛王识得，又变作一只白鹤，长唳一声，向南飞去。行者立定，抖抖翎毛，又变作一只丹凤，高鸣一声。那白鹤见凤是鸟王，诸禽不敢妄动，刷的一翅，淬下山崖，将身一变，变作一只香獐，乜乜些些，在崖前吃草。行者认得，也就落下翅来，变作一只饿虎，剪尾跑蹄，要来赶獐作食。魔王慌了手脚，又变作一只金钱花斑的大豹，要伤饿虎。行者见了，迎着风，把头一幌，又变作一只金眼狻猊，声如霹雳，铁额铜头，复转身要食大豹。牛王着了急，又变作一个人熊，放开脚，就来擒那狻猊。行者打个滚，就变作一只赖象，鼻似长蛇，牙如竹笋，撒开鼻子，要去卷那人熊。","——选自明代吴承恩的《西游记》第六十一回","作者用生动的语言将这激烈的场面描写得动人心魄，快翻开《西游记》，看看更多精彩的故事吧！","古代长篇小说多是章回体。这些作品里，一回或若干回组成一个相对完整的小故事，连起来就串成了一个长篇故事。","我很喜欢读回目，只要看一下某一回的标题，就可以猜出它主要讲了什么故事。","相信你可以读更多","还有很多中国古典名著等着我们去阅读。","煮酒论英雄、火烧赤壁、千里走单骑……无论是气势磅礴的战争场面，还是运筹帷握的谋略，我们都能在《三国演义》中读到，从中领略历史的风云变幻。","鲁智深倒拔垂杨柳，吴用智取生辰纲，宋江率军三打祝家庄，扈三娘比武招亲……《水浒传》中到处都是英雄的豪情壮志。","宝玉和众人结社赋诗，恣意畅快；黛玉葬花、凄美缠绵；湘云醉卧芍药丛，娇憨烂漫……在《红楼梦》里，既有儿女情长，风花雪月，也有盛衰变幻，人情冷暖。"]},{"id":377,"grade":"五年级下册","title":"从军行","paragraphs":["作者：[唐代] 王昌龄","青海长云暗雪山，","孤城遥望玉门关。","黄沙百战穿金甲，","不破楼兰终不还。","青海湖上乌云密布，遮得连绵雪山一片黯淡。边塞古城，玉门雄关，远隔千里，遥遥相望。","守边将士身经百战，铠甲磨穿，壮志不灭，不打败进犯之敌，誓不返回家乡。","王昌龄 (698— 756），字少伯，河东晋阳（今山西太原）人。盛唐著名边塞诗人，后人誉为“七绝圣手”。早年贫贱，困于农耕，而立之年，始中进士。初任秘书省校书郎，又中博学宏辞，授汜水尉，因事贬岭南。与李白、高适、王维、王之涣、岑参等交厚。开元末返长安，改授江宁丞。被谤谪龙标尉。安史乱起，为刺史闾丘晓所杀。其诗以七绝见长，尤以登第之前赴西北边塞所作边塞诗最著，有“诗家夫子王江宁”之誉（亦有“诗家天子王江宁”的说法）。"]},{"id":378,"grade":"五年级下册","title":"秋夜将晓出篱门迎凉有感","paragraphs":["作者：[宋代] 陆游","三万里河东入海，","五千仞岳上摩天。","遗民泪尽胡尘里，","南望王师又一年。","万里长的黄河奔腾向东流入大海，千仞高的华山耸入云霄触青天。","中原人民在胡人压迫下眼泪已流尽，他们盼望王师北伐盼了一年又一年。","陆游（1125年11月13日－1210年1月26日），字务观，号放翁，汉族，越州山阴（今浙江绍兴）人，尚书右丞陆佃之孙，南宋文学家、史学家、爱国诗人。陆游生逢北宋灭亡之际，少年时即深受家庭爱国思想的熏陶。宋高宗时，参加礼部考试，因受宰臣秦桧排斥而仕途不畅。孝宗时赐进士出身。中年入蜀，投身军旅生活。嘉泰二年（1202年），宋宁宗诏陆游入京，主持编修孝宗、光宗《两朝实录》和《三朝史》，官至宝章阁待制。晚年退居家乡。创作诗歌今存九千多首，内容极为丰富。著有《剑南诗稿》《渭南文集》《南唐书》《老学庵笔记》等。"]},{"id":379,"grade":"五年级下册","title":"闻官军收河南河北","paragraphs":["作者：[唐代] 杜甫","剑外忽传收蓟北，","初闻涕泪满衣裳。","却看妻子愁何在，","漫卷诗书喜欲狂。","白日放歌须纵酒，","青春作伴好还乡。","即从巴峡穿巫峡，","便下襄阳向洛阳。","剑外忽然传来收蓟北的消息，刚刚听到时涕泪满衣裳。","回头看妻子和孩子哪还有一点的忧伤，胡乱地卷起诗书欣喜若狂。","日光照耀放声高歌痛饮美酒，趁着明媚春光与妻儿一同返回家乡。","心想着就从巴峡穿过巫峡，经过了襄阳后又直奔洛阳。","杜甫（712－770），字子美，自号少陵野老，世称“杜工部”、“杜少陵”等，汉族，河南府巩县（今河南省巩义市）人，唐代伟大的现实主义诗人，杜甫被世人尊为“诗圣”，其诗被称为“诗史”。杜甫与李白合称“李杜”，为了跟另外两位诗人李商隐与杜牧即“小李杜”区别开来，杜甫与李白又合称“大李杜”。他忧国忧民，人格高尚，他的约1400余首诗被保留了下来，诗艺精湛，在中国古典诗歌中备受推崇，影响深远。759-766年间曾居成都，后世有杜甫草堂纪念。"]},{"id":380,"grade":"五年级下册","title":"10 青山处处埋忠骨","paragraphs":["一","中南海，毛主席的卧室。","写字台上，放着那封从朝鲜前线志愿军司令部发来的，由司令员彭德怀拟定的电报。","我们今日7时已进入防空洞，毛岸英同3个参谋在房子内。11时敌机4架经过时，他们4人已出来。敌机过后，他们4人返回房子内，忽又来敌机4架，投下近百枚燃烧弹，命中房子，当时有二名参谋跑出，毛岸英及高瑞欣未及跑出被烧死。其他无损失。","从见到这封电报起，毛泽东整整一天没说一句话，只是一支接着一支地吸着烟。桌子上的饭菜已经热了几次。岸英是毛主席最心爱的长子，毛主席在他身上倾注了无限的父爱。当年，地下党的同志们冒着生命危险找到了岸英，把他送到毛主席身边。后来岸英去苏联留学，回国后毛泽东又亲自把爱子送到农村锻炼。那一次次的分离，岸英不都平平安安回到自己的身边来了吗？这次怎么会……“岸英！岸英！”毛主席用食指按着紧锁的眉头，情不自禁地喃喃着。","二","秘书走了进来。","“主席，志愿军司令部来电请示中央军委，是否将岸英的遗骨运回国内。”秘书凑近毛主席，轻声说：“ 朝鲜方面向主席表示慰问，说岸英同志是为朝鲜人民的解放事业牺牲的，也是朝鲜人民的儿子，要求把岸英安葬在朝鲜。”","毛主席不由自主地站了起来，仰起头，望着天花板，强忍着心中的悲痛，目光中流露出无限的眷恋。岸英奔赴朝鲜时，他因为工作繁忙，未能见上一面，谁知竟成了永别！“儿子活着不能相见，就让我见见遗骨吧！”毛主席想。然而，他很快打消了这种念头。他若有所思地说道：“哪个战士的血肉之躯不是父母所生？不能因为我是主席，就要搞特殊。不是有千千万万志愿军烈士安葬在朝鲜吗？岸英是我的儿子，也是朝鲜人民的儿子，就尊重朝鲜人民的意愿吧。”","秘书将电报记录稿交毛主席签字的一瞬间，毛主席下意识地踌躇了一会儿，那神情分明在说，难道岸英真的回不来了？父子真的不能相见了？毛主席黯然的目光转向窗外，右手指指写字台，示意秘书将电报记录稿放在上面。","第二天早上，秘书来到毛主席的卧室。毛主席已经出去了，签过字的电报记录稿被放在了枕头上，下面是被泪水打湿的枕巾。","青山处处埋忠骨，何须马革裹尸还。"]},{"id":381,"grade":"五年级下册","title":"11 军神","paragraphs":["重庆临江门外，一个德国人开设的诊所里，医生沃克端坐在桌后。他头也不抬，冷冷地问：“你叫什么名字？”","“刘大川。”","“年龄？”","“二十四岁。”","“什么病？”","“土匪打伤了眼睛。”","沃克医生站起身，熟练地解开病人右眼上的绷带。他愣住了，蓝色的眼睛里闪出一丝惊疑。他重新审视着眼前这个人，冷冷地问：“你是干什么的？”","“邮局职员。”","“你是军人！”沃克医生一针见血地说，“我当过军医，这么重的伤势，只有军人才能这样从容镇定！”","病人微微一笑，说：“沃克医生，你说我是军人，我就是军人吧。”","沃克医生的目光柔和下来，他吩咐护士：“准备手术。”","沃克医生正在换手术服，护士跑来，低声告诉他病人拒绝使用麻醉剂。沃克医生的眉毛扬了起来，他走进手术室，生气地说：“年轻人，在这儿要听医生的指挥！”","病人平静地回答：“沃克医生，眼睛离脑子太近，我担心施行麻醉会影响脑神经。而我，今后需要一个非常清醒的大脑！”","沃克医生再一次愣住了，竟有点儿口吃地说：“你，你能忍受吗？你的右眼需要摘除坏死的眼球，把烂肉和新生的息肉一刀刀割掉！”","“试试看吧。”","手术台上，一向从容镇定的沃克医生，这次双手却有些颤抖，他额上汗珠滚滚，护士帮他擦了一次又一次。最后他忍不住开口对病人说：“你挺不住可以哼叫。”","病人一声不吭，他双手紧紧抓住身下的白床单，手背青筋暴起，汗如雨下。他越来越使劲，崭新的白床单居然被抓破了。","脱去手术服的沃克医生擦着汗走过来，由衷地说：“年轻人，我真担心你会晕过去。”","病人脸色苍白。他勉力一笑，说：“我一直在数你的刀数。”","沃克医生吓了一跳，不相信地问：“我割了多少刀？”","“七十二刀。”","沃克医生惊呆了，大声嚷道：“你是一个真正的男子汉，一块会说话的钢板！你堪称军神！”","“你过奖了。”","沃克医生的脸上浮现出慈祥的神情。他想说什么又忍住了，挥手让护士出去，然后关上手术室的门，注视着病人，说：“告诉我，你的真名叫什么？”","“刘伯承。”","沃克医生肃然起敬：“啊，久仰久仰，认识你很荣幸。”刘伯承友好地把手伸了过去。"]},{"id":382,"grade":"五年级下册","title":"12* 清贫","paragraphs":["我从事革命斗争，已经十余年了。在这长期的奋斗中，我一向是过着朴素的生活，从没有奢侈过。经手的款项，总在数百万元；但为革命而筹集的金钱，是一点一滴都用之于革命事业的。这在国方的伟人们看来，颇似奇迹，或认为夸张；而矜持不苟，舍己为公，却是每个共产党员具备的美德。所以，如果有人问我身边有没有一些积蓄，那我可以告诉你一桩趣事。","就在我被俘的那一天——一个最不幸的日子，有两个国方兵士，在树林中发现了我，而且猜到了我是什么人，他们满肚子热望在我身上搜出一千或八百大洋，或者搜出一些金镯金戒指一类的东西，发个意外之财。哪知道从我上身摸到下身，从袄领捏到袜底，除了一只时表和一支自来水笔，一个铜板都没有搜出。他们于是被激怒了，猜疑我是把钱藏在哪里，不肯拿出来。他们之中有一个，左手拿着一个木柄榴弹，右手拉出榴弹中的引线，双脚拉开一步，做出要抛掷的姿势，用凶恶的眼光盯住我，威吓地吼道：","“赶快将钱拿出来，不然就是一炸弹，把你炸死去！”","“哼！你不要做出那难看的样子来吧！我确实一个铜板都没有存，想从我这里发洋财，是想错了。”我微笑着，淡淡地说。","“你骗谁！像你这样当大官的人会没有钱！”拿榴弹的兵士坚决不相信。","“绝不会没有钱的，一定是藏在哪里，我是老出门的，骗不得我。”另一个兵士一面说，一面弓着背将我的衣角裤裆过细地捏，总企望着有新的发现。","“你们要相信我的话，不要瞎忙吧！我不比你们国民党当官，个个都有钱，我今天确实是一个铜板也没有，我们革命不是为着发财！”我再次向他们解释。","等他们确知在我身上搜不出什么的时候，也就停手不搜了；又在我藏躲的地方周围，低头注目搜寻了一番，也毫无所得。他们是多么失望啊！那个持弹欲放的兵士，也将拉着的引线，仍旧塞进榴弹的木柄里，转过来抢夺我的表和水笔。后来彼此说定表和笔卖出钱来平分，才算无话。他们用怀疑而又惊异的目光，对我自上而下地望了几遍，就同声命令：“走吧！”","是不是还要问问我家里有没有一些财产？请等一下，让我想一想，啊，记起来了，有的有的，但不算多。去年暑天我穿的几套旧的汗褂裤，与几双缝上底的线袜，已交给我的妻放在深山坞里保藏着——怕国军进攻时，被人抢了去，准备今年暑天拿出来再穿；那些就算是我唯一的财产了。但我说出那几件“传世宝”来，岂不要叫那些富翁们齿冷三天？！","清贫，洁白朴素的生活，正是我们革命者能够战胜许多困难的地方！","一九三五年五月二十六日写于囚室"]},{"id":383,"grade":"五年级下册","title":"语文园地","paragraphs":["从见到这封电报起，毛主席整整一天没说一句话，只是一支接着一支地吸着烟。","黄继光愤怒地注视着敌人的火力点，他转过身来坚定地对营参谋长说：“参谋长，请把这个任务交给我吧！”","将军看了看他们桌子上的罐头，喉咙哽了一下，说：“同志们……”停了一下，又说：“孩子们，我给大家分菜，每人一筷子。”","手术台上，一向从容镇定的沃克医生，这次双手却有些颤抖，他额上汗珠滚滚，护士帮他擦了一次又一次。","平时遇到不顺心的事我都能一笑而过，可是这件事让我实在无法释然，胸口总像是什么堵住了似的，白天心神不宁，晚上也无法入睡。","作者：[唐代] 王之涣","黄河远上白云间，","一片孤城万仞山。","羌笛何须怨杨柳，","春风不度玉门关。","黄河好像从白云间奔流而来，玉门关孤独地耸峙在高山中。","何必用羌笛吹起那哀怨的《杨柳曲》去埋怨春光迟迟不来呢，原来玉门关一带春风是吹不到的啊！","友人在黄鹤楼与我辞别，在柳絮如烟、繁花似锦的阳春三月去扬州远游。","孤船帆影渐渐消失在碧空尽头，只看见滚滚长江向天际奔流。","王之涣（688年—742年），是盛唐时期的著名诗人，字季凌，汉族，绛州（今山西新绛县）人。豪放不羁，常击剑悲歌，其诗多被当时乐工制曲歌唱。名动一时，他常与高适、王昌龄等相唱和，以善于描写边塞风光著称。其代表作有《登鹳雀楼》、《凉州词》等。“白日依山尽，黄河入海流。欲穷千里目，更上一层楼”，更是千古绝唱。","作者：[唐代] 李白","故人西辞黄鹤楼，","烟花三月下扬州。","孤帆远影碧空尽，","唯见长江天际流。","黄河好像从白云间奔流而来，玉门关孤独地耸峙在高山中。","何必用羌笛吹起那哀怨的《杨柳曲》去埋怨春光迟迟不来呢，原来玉门关一带春风是吹不到的啊！","友人在黄鹤楼与我辞别，在柳絮如烟、繁花似锦的阳春三月去扬州远游。","孤船帆影渐渐消失在碧空尽头，只看见滚滚长江向天际奔流。","李白（701年－762年） ，字太白，号青莲居士，又号“谪仙人”，唐代伟大的浪漫主义诗人，被后人誉为“诗仙”，与杜甫并称为“李杜”，为了与另两位诗人李商隐与杜牧即“小李杜”区别，杜甫与李白又合称“大李杜”。据《新唐书》记载，李白为兴圣皇帝（凉武昭王李暠）九世孙，与李唐诸王同宗。其人爽朗大方，爱饮酒作诗，喜交友。李白深受黄老列庄思想影响，有《李太白集》传世，诗作中多为醉时写就，代表作有《望庐山瀑布》《行路难》《蜀道难》《将进酒》《早发白帝城》等。"]},{"id":384,"grade":"五年级下册","title":"13 人物描写一组","paragraphs":["“要不――摔跤。”","“是吗？”小胖墩儿跳起来，立刻退后两步，一闪身脱了单褂儿，叉着腰说，“来吧，是一叉一搂的，还是随便摔？”","小嘎子在家里跟人摔跤，一向仗着手疾眼快，从不单凭力气，自然不跟他一叉一搂。两人把“枪”和“鞭”放在门墩儿上，各自虎势儿一站，公鸡鹐架似的对起阵来。起初，小嘎子精神抖擞，欺负对手傻大黑粗，动转不灵，围着他猴儿似的蹦来蹦去，总想使巧招，下冷绊子，仿佛很占了上风。可是小胖墩儿也是个摔跤的惯手，塌着腰，合了裆，鼓着眼珠子，不露一点儿破绽。两个人走马灯似的转了三四圈，终于三抓两挠，揪在了一起。这一来，小嘎子可上了当：小胖墩儿膀大腰粗，一身牛劲儿，任你怎么推拉拽顶，硬是扳他不动。小嘎子已有些沉不住气，刚想用脚腕子去钩他的腿，不料反给他把脚别住了。小胖墩趁势往旁侧里一推，咕咚一声，小嘎子摔了个仰面朝天。","他的身量与筋肉都发展到年岁前边去了。二十来岁，他已经很大很高，虽然肢体还没被年月铸成一定的格局，可是已经像个成人了——一个脸上身上都带出天真淘气的样子的大人。看着那高等的车夫，他计划着怎样杀进他的腰去，好更显出他的铁扇面似的胸与直硬的背。扭头看看自己的肩，多么宽，多么威严！杀好了腰，再穿上肥腿的白裤，裤脚用鸡肠子带儿系住，露出那对“出号”的大脚！是的，他无疑可以成为最出色的车夫，傻子似的他自己笑了。","他没有什么模样，使他可爱的是脸上的精神。头不很大，圆眼，肉鼻子，两条眉很短很粗，头上永远剃得发亮；腮上没有多余的肉，脖子可是几乎与头一边儿粗；脸上永远红扑扑的，特别亮的是颧骨与右耳之间一块不小的疤——小时候在树下睡觉，被驴啃了一口。他不甚注意他的模样，他爱自己的脸正如同他爱自己的身体，都那么结实硬棒，他把脸仿佛算在四肢之内，只要硬棒就好。是的，到城里以后，他还能头朝下，倒着立半天。这样立着，他觉得，他就很像一棵树，上下没有一个地方不挺脱的。","自此，严监生的病，一日重似一日，再不回头。诸亲六眷都来问候。五个侄子穿梭的过来陪郎中弄药。到中秋已后，医家都不下药了。把管庄的家人都从乡里叫了上来。病重得一连三天不能说话。晚间挤了一屋的人，桌上点着一盏灯。严监生喉咙里痰响得一进一出，一声不倒一声的，总不得断气，还把手从被单里拿出来，伸着两个指头。大侄子走上前来问道：“二叔，你莫不是还有两个亲人不曾见面？”他就把头摇了两三摇。二侄子走上前来问道：“二叔，莫不是还有两笔银子在那里，不曾吩咐明白？”他把两眼睁的的溜圆，把头又狠狠摇了几摇，越发指得紧了。奶妈抱着哥子插口道：“老爷想是因两位舅爷不在跟前，故此记念。”他听了这话，把眼闭着摇头，那手只是指着不动。赵氏慌忙揩揩眼泪，走近上前道：“爷，别人都说的不相干，只有我晓得你的意思！你是为那灯盏里点的是两茎灯草，不放心，恐费了油。我如今挑掉一茎就是了。”说罢，忙走去挑掉一茎。众人看严监生时，点一点头，把手垂下，登时就没了气。"]},{"id":385,"grade":"五年级下册","title":"14 刷子李","paragraphs":["刷子李专干粉刷这一行。他要是给您刷好一间屋子，屋里什么都不用放，单坐着，就如同神仙一般快活。最让人叫绝的是，他刷浆时必穿一身黑，干完活，身上绝没有一个白点。别不信！他还给自己立下一个规矩，只要身上有白点，白刷不要钱。","但这是传说。人信也不会全信。行外的没见过的不信，行内的生气愣说不信。","一年的一天，刷子李收个徒弟叫曹小三。当徒弟的开头都是端茶、点烟、跟在屁股后边提东西。曹小三当然早就听说过师傅那手绝活，一直半信半疑，这回非要亲眼瞧瞧。","那天，曹小三头一次跟师傅出去干活，到镇南道给姓李的人家新造的楼房刷浆。到了那儿，刷子李跟管事的人一谈，曹小三才知道师傅派头十足。照他的规矩一天只刷一间屋子。这楼房大小九间屋，得刷九天。干活前，他把随身带的一个四四方方的小包袱打开，果然一身黑衣黑裤，一双黑布鞋。穿上这身黑，就好像跟地上一桶白浆较上了劲。","一间屋子，一个屋顶四面墙，先刷屋顶后刷墙。屋顶尤其难刷，蘸了稀溜溜粉浆的板刷往上一举，谁能一滴不掉？一掉准掉在身上。可刷子李一举刷子，就像没有蘸浆。但刷子划过屋顶，立时匀匀实实一道白，白得透亮，白得清爽。有人说这蘸浆的手法有高招，有人说这调浆的配料有秘方。曹小三哪里看得出来？只见师傅的手臂悠然摆来，悠然摆去，如同伴着鼓点，和着琴音，每一摆刷，那长长的带浆的毛刷便在墙面啪地清脆一响，极是好听。啪啪声里，一道道浆，衔接得天衣无缝，刷过去的墙面，真好比平平整整打开一面雪白的屏障。可是曹小三最关心的还是刷子李身上到底有没有白点。","刷子李干活还有一个规矩。每刷完一面墙，必得在凳子上坐一会儿，抽一袋烟，喝一碗茶，再刷下一面墙。此刻，曹小三借着给师傅倒水点烟的机会，拿目光仔细搜索刷子李的全身。每一面墙刷完，他搜索一遍，居然连一个芝麻大小的粉点也没发现。他真觉得这身黑色的衣服有种神圣不可侵犯的威严。","当刷子李刷完最后一面墙，坐下来，曹小三给他点烟时，竟然瞧见刷子李裤子上出现一个白点，黄豆大小。黑中白，比白中黑更扎眼。完了，师傅露馅了，他不是神仙，往日传说中那如山般的形象轰然倒去。他怕师父难堪，不敢说，也不敢看，可忍不住还要扫一眼。","这时候，刷子李忽然朝他说话：“小三，你瞧见我裤子上的白点了吧？你以为师傅的能耐有假，名气有诈，是吧？傻小子，你再仔细瞧瞧吧——”","说着，刷子李手指捏着裤子轻轻往上一提，那白点即刻没了，再一松手，白点又出现，奇了！他凑上脸用神再瞧，那白点原来是一个小洞！刚才抽烟时不小心烧的。里边的白衬裤从小洞透出来，看上去就跟粉浆落上去的白点一模一样！","刷子李看着曹小三发怔发傻的模样，笑道：“好好学本事吧！”","曹小三学徒的头一天，见到听到学到的，恐怕别人一辈子也不一定能明白呢。"]},{"id":386,"grade":"五年级下册","title":"习作例文","paragraphs":["我的朋友容容是一个助人为乐的人。","我订了一份报纸，每天早上，容容总是搬着椅子，爬上去，踮起脚，从大门口的邮箱里取出报纸来，然后爬下椅子，奔来把报纸交给我：“任叔叔，报纸来啦！”","不知从什么时候开始，这已经成了她的习惯，而且她认为这是一项“权利”，是绝不能让别人侵犯的。","有一天，我忘了尊重她的权利，自己去把报纸取来了。我正在看报，容容走来，她看看我手里的报纸，忽然噘起嘴，挺委屈地走了。过了一会儿我听到她的哭声和奶奶又骂又哄的声音。起初我没在意，后来忽然感到这似乎跟报纸的事有些关系，过去一打听，果然她是为了报纸的事在发脾气。我连忙把报纸送回大门口去。容容就不哭了，又搬着椅子去把报纸取来交给我，才又高兴起来。容容就是这么忠于职守。","一天我下班回家，容容给我拿来一封信，是我的一个老同学从外地寄来的。容容似乎对信产生了浓厚的兴趣，等我看完信，她好奇地问：“任叔叔，这是什么？”","“这是信。”","“信是什么？","“信就是信。譬如说，我有个好朋友，我有话跟他讲，我就可以写一封信寄给他。信封上写个名字，就可以寄了。”","那么我也可以寄信给好朋友吗？”","“当然可以，如果你有好朋友的话。”我笑着说。","“就拿这样的信封寄吗？”","“对！”","“到哪儿去寄呢？”","“往邮简里一塞就行。我们大门外边不就有个邮筒吗？”","“知道啦！知道啦！”她高兴地说。","不知什么时候，她把我的信封拿去玩了，我也没在意。不料过了一天，邮递员通知我说有一封“欠资待领”的信，叫我到邮局去领。我连忙上邮局付了邮资，领出信来看，啊，原来又是那位老同学寄来的。这家伙开什么玩笑，信封上贴了张用过的旧邮票。拆开信一看，啊？难道他疯了？信封里连半张纸也没有，却装着一片梧桐树叶。真是奇怪！我把叶子翻来覆去看了半天，怎么也猜不出它藏着什么奥妙。我十分纳闷。回到家里，容容却跟在我旁边，老用种异样的眼光看着我，似乎准备告诉我什么秘密。过了一会儿，她似乎忍不住了，就拉住我，在我耳边轻轻地说：“任叔叔，我告诉你，我给你寄了一封信！真正的信！”","“什么？”我好奇地问。","“我今天给你寄了一封信，就用那个信封寄的。里面藏着一片叶子……”","不等她说完，我就大笑起来，几乎把肚子都笑疼了。原来那封“欠资待领”的信就是她寄的啊！","放学以后，孩子们又来到这片空地。他们分成两拨儿，把书包和帽子堆起来当球门，就拉开阵势赛起来。小弟弟小妹妹被吸引过来了，路过的大个子叔叔也坐到场边，欣赏他们这场球赛。","看那个留平头的小守门员，他身着深蓝色的运动衣，浅蓝色的短裤，脚穿运动鞋，戴着手套。只见他分腿弯腰，上身前倾，目光警惕地注视着前方，膝盖磕破了也毫不在意，真像个专业的足球守门员！他想着自己可千万不能大意，绝不让对手冲破最后一道防线。站在小守门员身后的，是个腆着肚子的小男孩儿。他好像是候补的，一心想着快点儿上场，好显一显身手，扑住几个险球。","比赛进入白热化阶段，小守门员和观众们紧紧盯着球场中的足球。那个戴红帽子的小女孩生怕别人挡住她，往外探着身子。那个扎蝴蝶结的女孩索性站了起来。搂着小弟弟的“红领巾”可能来迟了，他坐在最边上，也全神贯注地注视着局势的发展。不知谁家的漂亮白狗跟主人一块儿来了。它对球赛没兴趣，正卧在场边闭目养神呢。","那个抱着洋娃娃的小女孩跟别人不大一样，腰挺得直直的，脸上没有什么表情，好像胜负都跟她不相干。旁边的那个戴帽子的小男孩却显得挺紧张，也许是头一回看到这样激烈的球赛。","那位大个子叔叔始终面带笑容，看得津津有味。孩子们踢得太精彩了，也许勾起了他小时候踢球的美好回忆。"]},{"id":387,"grade":"五年级下册","title":"15 自相矛盾","paragraphs":["楚人有鬻盾与矛者，誉之曰：“吾盾之坚，物莫能陷也。”又誉其矛曰：“吾矛之利，于物无不陷也。”或曰：“以子之矛陷子之盾，何如？”其人弗能应也。夫不可陷之盾与无不陷之矛，不可同世而立。","有一个楚国人，既卖盾又卖矛。他夸耀自己的盾，说：“我的盾坚固无比，没有什么东西能够穿透它。”又夸耀自己的矛，说：“我的矛锋利极了，任何坚固的东西都穿得透。”有人问他：“如果用您的矛刺您的盾，结果会怎么样呢？”那人一句话也回答不上来。什么都不能刺穿的盾与什么都能刺穿的矛，不可能同时存在于这个世界上。"]},{"id":388,"grade":"五年级下册","title":"16 田忌赛马","paragraphs":["孙膑是齐国大将田忌的门客，田忌对他非常赏识。","田忌经常同齐威王及贵族们赛马。孙膑看了几场比赛后发现，大家的马脚力相差不多，而且都能分成上、中、下三等。","一天，孙膑对田忌说：“将军，我有个办法，保证能让您在赛马时获胜。”","田忌问道：“你是说换几匹更好的马？”","孙膑说：“一匹也不用换。”","田忌有些不明白：“那怎么能有赢的把握呢？”","孙膑胸有成竹地说：“将军请放心，按照我的主意办，一定能让您赢。”","田忌很信任孙膑，决定全听他的。","于是，他同齐威王及贵族们约好一起赛马。","田忌和齐威王的对阵就要开始了。比赛双方摩拳擦掌，跃跃欲试。观众们也兴致勃勃地猜测着比赛结果。就在这时，孙膑把田忌请到一边，悄悄地把办法告诉了他。","第一场，田忌先用下等马对齐威王的上等马，齐威王的马遥遥领先。田忌输了，但他不动声色，一点儿都不着急。","接着，第二场比赛开始了。田忌用上等马对齐威王的中等马，胜了第二场。田忌微微一笑。","第三场，田忌用中等马对齐威王的下等马，又胜了一场。田忌满意地笑了。","比赛结束了。田忌胜两场输一场，赢了齐威王。","齐威王好奇地问田忌：“你这样安排马的出场顺序，是不是有人给你出谋划策了？”","田忌如实相告，并引荐了孙膑。后来，齐威王任命孙膑为军师。"]},{"id":389,"grade":"五年级下册","title":"17 跳水","paragraphs":["一艘环游世界的帆船正往回航行。这一天风平浪静，水手们都在甲板上。一只猴子在人群里钻来钻去，模仿人的动作，惹得大家哈哈大笑。它显然知道大家拿它取乐，因而更加放肆起来。","船长的儿子才十一二岁，他也笑得很开心。猴子忽然跳到他面前，摘下他的帽子戴在自己的头上，很快地爬上了桅杆。水手们又大笑起来，只有那个孩子哭笑不得，眼巴巴地望着猴子坐在桅杆的第一根横木上，摘下帽子来用牙齿咬，用爪子撕，好像故意逗他生气。孩子吓唬它，朝着它大喊大叫。猴子不但不理，还撕得更凶了。","水手们笑得更欢了，孩子却气得脸都红了。他脱了上衣，爬上桅杆去追猴子。他攀着绳子爬到第一根横木上，正要伸手去夺帽子，猴子比他更灵巧，转身抓着桅杆又往上爬。","“你逃不了！”孩子一边追赶一边喊。猴子还不时回过头来逗孩子生气。爬到了桅杆的顶端，它用后脚钩住绳子，把帽子挂在最高的那根横木的一头，然后坐在桅杆的顶端，扭着身子，龇牙咧嘴做着怪样。横木的一头离桅杆一米多。孩子气极了，他的手放开了绳子和桅杆，张开胳膊，摇摇晃晃地走上横木去取帽子。这时候，甲板上的水手全都吓呆了。孩子只要一失足，直摔到甲板上就没命了。即使他走到横木那头拿到了帽子，也难以回转身来。有个人吓得大叫了一声。孩子听到叫声往下一望，两条腿不由得发起抖来。","正在这时候，船长从船舱里出来，手里拿着一支枪。他本来是想打海鸥的，看见儿子在桅杆顶端的横木上，就立刻瞄准儿子，喊道：“向海里跳！快！不跳我就开枪了！”孩子心惊胆战，站在横木上摇摇晃晃的，没听明白爸爸的话。船长又喊：“向海里跳！不然我就开枪了！一！二！”刚喊出“三”，孩子纵身从横木上跳了下来。","扑通一声，孩子像颗炮弹一样扎进了海里。二十来个勇敢的水手已经跳进了大海：四十秒钟——大家已经觉得时间太长了。等孩子一浮上来，水手们就立刻抓住了他，把他救上了甲板。"]},{"id":390,"grade":"五年级下册","title":"语文园地","paragraphs":["吾盾之坚 坚固","弗能应 应答","道旁李 道路","溺而不返 返回","冀复得兔 重复","守株待兔 守候","二十来个勇敢的水手已经跳进了大海：四十秒钟——大家已经觉得时间太长了。等孩子一浮上来，水手们就立刻抓住了他，把他救上了甲板。","几十年，几百年，几千年，时间一转眼就过去了。成千上万只绿翅膀的苍蝇和八只脚的蜘蛛来了又去了。","豆蔻年华：指女子十三四岁的年纪。","及笄：指女子年满十五岁。","弱冠：指男子二十岁左右的年纪。","而立：指人三十岁。","不惑：指人四十岁。","花甲：指人六十岁。","古稀：指人七十岁。","期颐：指人一百岁。"]},{"id":391,"grade":"五年级下册","title":"18 威尼斯的小艇","paragraphs":["威尼斯是世界闻名的水上城市，河道纵横交错，小艇成了主要的交通工具。","威尼斯的小艇有二三十英尺长，又窄又深，有点儿像独木舟；船头和船艄向上翘起，像挂在天边的新月；行动轻快灵活，仿佛田沟里的水蛇。","我们坐在船舱里，皮垫子软软的像沙发一般。小艇穿过一座座形式不同的石桥。我们打开窗帘，望望耸立在两岸的古建筑，跟来往的船只打招呼，有说不完的情趣。","船夫的驾驶技术特别好。行船的速度极快，来往船只很多，他操纵自如，毫不手忙脚乱。不管怎么拥挤，他总能左拐右拐地挤过去。遇到极窄的地方，他总能平稳地穿过，而且速度非常快，还能急转弯。两边的建筑飞一般地倒退，我们的眼睛忙极了，不知看哪一处好。","商人夹了大包的货物，匆匆走下小艇，沿河做生意。青年妇女在小艇里高声谈笑。许多孩子由保姆伴着，坐着小艇到郊外去呼吸新鲜的空气。老人带了全家，坐着小艇上教堂去作祷告。","半夜，戏院散场了，一大群人拥出来，走上了各自雇好的小艇。簇拥在一起的小艇一会儿就散开了，消失在弯曲的河道中，远处传来一片哗笑和告别的声音。水面上渐渐沉寂，只见月亮的影子在水中摇晃。高大的石头建筑耸立在河边，古老的桥梁横在水上，大大小小的船都停泊在码头上。静寂笼罩着这座水上城市，古老的威尼斯又沉沉地入睡了。"]},{"id":392,"grade":"五年级下册","title":"19 牧场之国","paragraphs":["荷兰，是水之国，花之国，也是牧场之国。","一条条运河之间的绿色低地上，黑白花牛，白头黑牛，白腰蓝嘴黑牛，在低头吃草。有的牛背上盖着防潮的毛毡。牛群吃草时非常专注，有时站立不动，仿佛正在思考着什么。牛犊还未长大，却有了端庄的仪态。老牛好似牛群的家长，无比威严。极目远眺，四周全是碧绿的丝绒般的草原和黑白两色的花牛。这就是真正的荷兰。","这就是真正的荷兰。碧绿色的低地镶嵌在一条条运河之间，成群的骏马，匹匹膘肥体壮。除了深深的野草遮掩着的运河，没有什么能够阻挡它们飞驰到远方。辽阔无垠的原野似乎归它们所有，它们是这个自由王国的主人和公爵。","在绿色的草原上，白色的绵羊悠然自得。黑色的猪群不停地呼噜着，像是对什么表示赞许。成千上万的小鸡，成群结队的长毛山羊，在见不到一个人影的绿草地上，安闲地欣赏着这属于它们自己的王国。这就是真正的荷兰。","到了傍晚，才看见有人驾着小船过来，坐上小板凳，给严肃沉默的奶牛挤奶。金色的晚霞铺在西天，远处偶尔传来汽笛声，接着又是一片寂静。在这里，谁都不叫喊吆喝，牛脖子上的铃铛也没有响声，挤奶的人更是默默无言。运河之中，装满奶桶的船只在舒缓平稳地行驶。满载着一罐一罐牛奶的汽车、火车，不停地开往城市。车船过后，一切又恢复了平静。最后一抹晚霞也渐渐消失了，整个天地都暗了下来。狗不叫了，圈里的牛也不再发出哞哞声，马也忘记了踢马房的挡板。沉睡的牲畜，无声的低地，漆黑的夜晚，只有远处的几座灯塔在闪烁着微弱的光。","这就是真正的荷兰。"]},{"id":393,"grade":"五年级下册","title":"金字塔夕照","paragraphs":["九月的开罗是金色的。","在金色的夕阳下，金色的田野，金色的沙漠，连尼罗河的河水也泛着金光，而那古老的金字塔啊，简直像是用纯金铸成的。远远望去，它像漂浮在沙海中的三座金山，似乎一切金色的光源，都是从它那里放射出来的。你看，天上地下，黄澄澄，金灿灿，一片耀眼的色调，一幅多么开阔而又雄浑的画卷啊！","从少小时候起，我就听到过许多有关金字塔的传说，向往着它神秘的风采。如今，当我来到金字塔下，望着这人间的奇迹，更禁不住思绪激荡。我不知道“金字塔”这个译名中的“金”，最早是怎么得来的。不管出于什么考虑，我认为都是绝妙的。你看金字塔多像一个“金”的汉字。几千年来，在人们的心目中，它不愧是熠熠发光的珍宝，人类劳动和智慧的结晶，它无疑比金子还要贵重。","有人说金字塔的白昼和月夜，各有各的情趣，各有各的美，但我觉得最令人难忘的，恐怕还是这大漠夕照中金字塔的色彩。那一片迷人的金色，简直把你融进一个神奇的境界，使你充满豪迈的感受和无边的遐想，不由自主地产生一种怀古的幽思……"]},{"id":394,"grade":"五年级下册","title":"语文园地","paragraphs":["两边的建筑飞一般地倒退，我们的眼睛忙极了，不知看哪一处好。","车船过后，一切又恢复了平静。最后一抹晩霞也渐渐消失了，整个天地都暗了下来。狗不叫了，圈里的牛也不再发出哞哞声，马也忘记了踢马房的挡板。","放学后的校园  群鸟飞过湖面  火车进站","在金色的夕阳下，金色的田野，金色的沙漠，连尼罗河的河水也泛着金光，而那古老的金字塔啊，简直像是用纯金铸成的。 站在白色大理石铺的地上，眼里看到的是纯白的大理石，脚下踩的是纯白的大理石；陵墓是纯白的大理石，栏杆是纯白的大理石，四个高塔也是纯白的大理石。你被裹在一片纯白的光辉中，仿佛给这个白色的奇迹压住了，给这纯白的光辉网牢了。","作者：[宋代] 翁卷","绿遍山原白满川，","子规声里雨如烟。","乡村四月闲人少，","才了蚕桑又插田。","初夏季节，江南的山间原野，到处绿油油的，满河的流水，映着天光，白茫茫一片。在如烟似雾的细雨中，杜鹃鸟不时地鸣叫着，催促着农事。","乡村的四月正是最忙的时候，刚刚结束了蚕桑的事又要插秧了。","翁卷，字续古，一字灵舒，乐清（今属浙江）人。工诗，为“永嘉四灵”之一。曾领乡荐（《四库提要》作“尝登淳佑癸卯乡荐”，《乐清县志》承此，而近人以为是淳熙癸卯，相差一个甲子。衡诸翁卷生平，前者过早，后者过尽，疑都不确），生平未仕。以诗游士大夫间。有《四岩集》，《苇碧轩集》。清光绪《乐清县志》卷八有传。"]},{"id":395,"grade":"五年级下册","title":"21 杨氏之子","paragraphs":["作者：[南北朝] 刘义庆","梁国杨氏子九岁，甚聪惠。孔君平诣其父，父不在，乃呼儿出。为设果，果有杨梅。孔指以示儿曰：“此是君家果。”儿应声答曰：“未闻孔雀是夫子家禽。”","梁国一户姓杨的人家家里有一个九岁的儿子，非常聪明。孔君平来拜见他的父亲，恰巧他父亲不在，于是便叫他出来。他为孔君平端来水果，水果中有杨梅，孔君平指着杨梅给孩子看，并说：“这是你家的水果。”杨氏子马上回答说：“没听说孔雀是先生您家的鸟。”","刘义庆（403年 - 444年），彭城郡彭城县（今江苏省徐州市）人，南朝宋宗室、文学家。宋武帝刘裕的侄子。袭封南郡公，永初元年（420年）封临川王，征为侍中。文帝元嘉时，历仕秘书监、丹阳尹、尚书左仆射、中书令、荆州刺史等。著有《徐州先贤传》《江左名士传》《世说新语》。"]},{"id":396,"grade":"五年级下册","title":"22 手指","paragraphs":["我们每个人，都随时随地随身带着十根手指，永不离身。一只手上的五根手指，各有不同的姿态，各具不同的性格，各有所长，各有所短。","大拇指在五指中，形状实在算不上美。身体矮而胖，头大而肥，构造简单，比人家少一个关节。但在五指中，却是最肯吃苦的。例如拉胡琴，总由其他四指按弦，却叫他相帮扶住琴身；水要喷出来，叫他死力抵住；血要流出来，叫他拼命按住；重东西要翻倒去，叫他用劲顶住；要读书了，叫他翻书页；要进门了，叫他揿电铃。讨巧的事，却轮不上他。例如招呼人，都由其他四指上前点头，他只能呆呆站在一旁；给人搔痒，人舒服后，感谢的是其他四指。","常与大拇指合作的是食指。他的姿态可不如其他三指窈窕，都是直直落落的强硬的线条。他的工作虽不如大拇指吃力，却比大拇指复杂。拿笔的时候，全靠他推动笔杆；遇到危险的事，都要他去试探或冒险；秽物、毒物、烈物，他接触的机会最多；刀伤、烫伤、轧伤、咬伤，他消受的机会最多。他具有大拇指所没有的“机敏”，打电话、扳枪机必须请他，打算盘、拧螺丝、解纽扣等，虽有大拇指相助，终是要他主干的。","五指中地位最优、相貌最堂皇的，无如中指。他居于中央，左右都有屏障。他个子最高，无名指、食指贴身左右，像关公左右的关平、周仓，左膀右臂，片刻不离。他永远不受外物冲撞，所以曲线优美，处处显示着养尊处优的幸福。每逢做事，名义上他是参加的，实际并不出力。他因为身体最长，取物时，往往最先碰到物，好像取得这物是他一人的功劳，其实，他碰到之后就退在一旁，让大拇指和食指去出力，他只在旁略为扶衬而已。","无名指和小指，体态秀丽，样子可爱，然而，能力薄弱也无过于他们了。无名指多用于研脂粉、蘸药末、戴戒指。小指的用处则更渺小，只是掏掏耳朵、抹抹鼻涕而已。他们也有被重用的时候，在丝竹管弦上，他们的能力不让于别人。舞蹈演员的手指不是常作兰花状吗？这两根手指正是这朵“兰花”中最优美的两瓣。除了这等享乐的风光事以外，遇到工作，他们只是其他手指的附庸。","手上的五指，我只觉得姿态与性格，有如上的差异，却无爱憎在其中。手指的全体，同人群的全体一样，五根手指如果能一致团结，成为一个拳头，那就根根有用，根根有力量，不再有什么强弱、美丑之分了。"]},{"id":397,"grade":"五年级下册","title":"23* 童年的发现","paragraphs":["我在九岁的时候就发现了有关胚胎发育的规律，这完全是我独立思考的结果。","听完这句话，你大概忍不住会哈哈大笑，愿意笑你就笑吧，反正笑声不会给你招来祸患。我跟你可不同，事情过去了三年，有一次我想起了自己的发现，情不自禁笑出了声音，竟使我当众受到了惩罚。","我的发现起始于梦中飞行。每天夜里做梦我都飞，我对飞行是那样迷恋，只要双脚一点，轻轻跃起，就能离开地面飞向空中。后来，我甚至学会了滑翔，在街道上空，在白桦树梢头，在青青的草地和澄澈的湖面上盘旋。我的身体是那样轻盈，可以随心所欲，运转自如，凭着双臂舒展和双腿弹动，似乎想去哪里就能飞到哪里。","我以为在同学中间只有我一个人具有飞行的天赋。可是，有一天我终于弄明白了，每到夜晚，我的小伙伴们也都会在梦中飞腾。那天，我们几个人决定去见我们的老师，让他来解答这个奇妙的问题。","“梦里飞行，说明你们是在长身体啊！”老师解释说。","“为什么只有晚上睡觉时才长？”","“白天你们太淘气，妨碍细胞的生长。到了晚上，细胞就不停地繁殖。”","“那为什么人在生长的时候就要飞呢？这究竟是什么道理？”","“这是你们的细胞回想起了远古时代，那个时候，人还是飞鸟。”","“人怎么会是鸟？”我们万分惊讶。","“岂止是鸟！人是由简单生命进化来的。最开始是草履虫，后来是鱼，是青蛙，是猴子……所有这些知识，等你们升入高年级，上课时老师都会给你们讲解。”","高年级，离我们是那样遥远，而飞行却仍在继续。和老师的一次谈话，更加激发了我的想象力。我渴望弄明白，人究竟是怎么来的。我想得是那样痴迷，以至于从河里抓到一条鱼，我都会翻来覆去地看个仔细，恨不得从鱼身上发现将来的人应该具有的某些特征。","乡村的孩子从小就知道母亲怀胎九个月才生下婴儿。“为什么是九个月呢？”我绞尽脑汁思考这个问题的答案。想啊想啊，嘿！终于想出了眉目：“哈！这就跟画地图差不多。地上的距离很远很远，在地图上画出来只不过几厘米。人是由细胞构成的……从细胞变成小鱼，经过了很长时间。现在，这一段时间就折合成一个月。从小鱼变成青蛙又得经过很长时间，又折合成一个月。这样推算下来，到变化成人，正好是九个月。”我的发现竟是如此简单明了，我为此感到格外高兴。我想，大概还没有人发现这个道理。","又过了三四年，我上了六年级。老师开始给我们上生物课。有一次，年轻的女教师板着面孔一本正经讲人的起源，讲人的发育和进化。这时候，我清清楚楚听见老师说，有的科学家认为，母腹中的胎儿再现了从简单生命进化成人的过程。当时教室里安静得出奇，大家都默不作声。我忽然想起了自己的发现，情不自禁地笑出了声音。老师狠狠地瞪了我一眼。","“费奥多罗夫！……你笑什么？再笑就从教室里出去！”","“奥尔加·伊万诺夫娜，我……我想起了自己的发现……”","教室里一阵笑声。奥尔加·伊万诺夫娜气得脸色苍白，大步朝我走来。","“费奥多罗夫！……你立刻从教室里出去……”","我的脸由于困窘和羞愧一下子涨得通红。这时候我意识到，老师误解了我的笑声，以为我的笑不怀好意。幸亏她没有容我解释，不然的话，同学们听见我说自己三年前就发现了“进化论”，还不笑塌房顶！不过，被轰出教室，站在外面，我倒想出了一条自我安慰的理由，我明白了——世界上的重大发现，有时还会给人带来被驱逐和被迫害的风险。"]},{"id":398,"grade":"五年级下册","title":"语文园地","paragraphs":["他个子最高，无名指、食指贴身左右，像关公左右的关平、周仓，左膀右臂，片刻不离。","这个体操运动员在高低杠上的动作真灵巧，就像猴子在树林中攀缘、穿行。","但在五指中，大拇指却是最肯吃苦的。例如拉胡琴，总由其他四指按弦，却叫他相帮扶住琴身；水要喷出来，叫他死力抵住；血要流出来，叫他拼命按住；重东西要翻倒去，叫他用劲顶住；要读书了，叫他翻书页；要进门了，叫他揿电铃。","君子喻于义，小人喻于利。——《论语》","君子坦荡荡，小人长戚戚。——《论语》","恻隐之心，仁之端也。——《孟子》","多行不义，必自毙。——《左传》","人有耻，则能有所不为。——《朱子语类》"]},{"id":399,"grade":"六年级上册","title":"1 草原","paragraphs":["这次，我看到了草原。那里的天比别处的更可爱，空气是那么清鲜，天空是那么明朗，使我总想高歌一曲，表示我满心的愉快。在天底下，一碧千里，而并不茫茫。四面都有小丘，平地是绿的，小丘也是绿的。羊群一会儿上了小丘，一会儿又下来，走在哪里都像给无边的绿毯绣上了白色的大花。那些小丘的线条是那么柔美，就像只用绿色渲染，不用墨线勾勒的中国画那样，到处翠色欲流，轻轻流入云际。这种境界，既使人惊叹，又叫人舒服，既愿久立四望，又想坐下低吟一首奇丽的小诗。在这境界里，连骏马和大牛有时候都静立不动，好像回味着草原的无限乐趣。","我们访问的是陈巴尔虎旗。汽车走了一百五十里，才到达目的地。一百五十里全是草原。再走一百五十里，也还是草原。草原上行车十分洒脱，只要方向不错，怎么走都可以。初入草原，听不见一点儿声音，也看不见什么东西，除了一些忽飞忽落的小鸟。走了许久，远远地望见了一条迂回的明如玻璃的带子——河！牛羊多起来，也看到了马群，隐隐有鞭子的轻响。快了，快到了。忽然，像被一阵风吹来似的，远处的小丘上出现了一群马，马上的男女老少穿着各色的衣裳，群马疾驰，襟飘带舞，像一条彩虹向我们飞过来。这是主人来到几十里外欢迎远客。见到我们，主人们立刻拨转马头，欢呼着，飞驰着，在汽车左右与前面引路。静寂的草原热闹起来：欢呼声，车声，马蹄声，响成一片。车跟着马飞过小丘，看见了几座蒙古包。","蒙古包外，许多匹马，许多辆车。人很多，都是从几十里外乘马或坐车来看我们的。主人们下了马，我们下了车。也不知道是谁的手，总是热乎乎地握着，握住不放。大家的语言不同，心可是一样。你说你的，我说我的，总的意思是民族团结互助。","也不知怎的，就进了蒙古包。奶茶倒上了，奶豆腐摆上了，主客都盘腿坐下，谁都有礼貌，谁都又那么亲热，一点儿不拘束。不大一会儿，好客的主人端进来大盘的手抓羊肉。干部向我们敬酒，七十岁的老翁向我们敬酒。我们回敬，主人再举杯，我们再回敬。这时候，鄂温克族姑娘们戴着尖尖的帽子，既大方，又稍有点儿羞涩，来给客人们唱民歌。我们同行的歌手也赶紧唱起来，歌声似乎比什么语言都更响亮，都更感人，不管唱的是什么，听者总会露出会心的微笑。","饭后，小伙子们表演套马、摔跤，姑娘们表演了民族舞蹈。客人们也舞的舞，唱的唱，还要骑一骑蒙古马。太阳已经偏西，谁也不肯走。是啊！蒙汉情深何忍别，天涯碧草话斜阳！"]},{"id":400,"grade":"六年级上册","title":"2 丁香结","paragraphs":["今年的丁香花似乎开得格外茂盛，城里城外，都是一样。城里街旁，尘土纷嚣之间，忽然呈出两片雪白，顿使人眼前一亮，再仔细看，才知是两行丁香花。有的宅院里探出半树银妆，星星般的小花缀满枝头，从墙上窥着行人，惹得人走过了还要回头望。","城外校园里丁香更多。最好的是图书馆北面的丁香三角地，种有十数棵的白丁香和紫丁香。月光下白的潇洒，紫的朦胧。还有淡淡的幽雅的甜香，非桂非兰，在夜色中也能让人分辨出，这是丁香。","在我断断续续住了近三十年的斗室外，有三棵白丁香。每到春来，伏案时抬头便看见檐前积雪。雪色映进窗来，香气直透毫端。人也似乎轻灵得多，不那么浑浊笨拙了。从外面回来时，最先映入眼帘的，也是那一片莹白，白下面透出参差的绿，然后才见那两扇红窗。我经历过的春光，几乎都是和这几树丁香联系在一起的。那十字小白花，那样小，却不显得单薄。许多小花形成一簇，许多簇花开满一树，遮掩着我的窗，照耀着我的文思和梦想。","古人诗云“芭蕉不展丁香结”“丁香空结雨中愁”。在细雨迷蒙中，着了水滴的丁香格外妩媚。花墙边两株紫色的，如同印象派的画，线条模糊了，直向窗前的莹白渗过来。让人觉得，丁香确实该和微雨连在一起。","只是赏过这么多年的丁香，却一直不解，何以古人发明了丁香结的说法。今年一次春雨，久立窗前，望着斜伸过来的丁香枝条上一柄花蕾。小小的花苞圆圆的，鼓鼓的，恰如衣襟上的盘花扣。我才恍然，果然是丁香结。","丁香结，这三个字给人许多想象。再联想到那些诗句，真觉得它们负担着解不开的愁怨了。每个人一辈子都有许多不顺心的事，一件完了一件又来。所以丁香结年年都有。结，是解不完的；人生中的问题也是解不完的，不然，岂不太平淡无味了吗？"]},{"id":401,"grade":"六年级上册","title":"宿建德江","paragraphs":["作者：[唐代] 孟浩然","移舟泊烟渚，","日暮客愁新。","野旷天低树，","江清月近人。","把船停泊在烟雾弥漫的沙洲旁，日落时新愁又涌上了心头。","原野无边无际，远处的天空比近处的树林还要低；江水清清，明月仿似更与人相亲。","孟浩然（689年—740年），字浩然，号孟山人，襄州襄阳（今湖北襄阳）人，唐代著名的山水田园派诗人，世称“孟襄阳”。因他未曾入仕，又称之为“孟山人”。孟浩然生于盛唐，早年有志用世，在仕途困顿、痛苦失望后，尚能自重，不媚俗世，修道归隐终身。曾隐居鹿门山。40岁时，游长安，应进士举不第。曾在太学赋诗，名动公卿，一座倾服，为之搁笔。开元二十五年（737）张九龄招致幕府，后隐居。孟诗绝大部分为五言短篇，多写山水田园和隐居的逸兴以及羁旅行役的心情。其中虽不无愤世嫉俗之词，而更多属于诗人的自我表现。孟浩然的诗在艺术上有独特的造诣，后人把孟浩然与盛唐另一山水诗人王维并称为“王孟”，有《孟浩然集》三卷传世。"]},{"id":402,"grade":"六年级上册","title":"六月二十七日望湖楼醉书","paragraphs":["作者：[宋代] 苏轼","黑云翻墨未遮山，","白雨跳珠乱入船。","卷地风来忽吹散，","望湖楼下水如天。","翻滚的乌云像泼洒的墨汁，还没有完全遮住山峦，白色的雨点似珍珠乱蹦乱跳窜上船。","忽然间卷地而来的狂风吹散了满天的乌云，而那风雨后望湖楼下的西湖湖面像天空一般开阔而且平静。","苏轼，（1037年1月8日-1101年8月24日）字子瞻、和仲，号铁冠道人、东坡居士，世称苏东坡、苏仙，汉族，眉州眉山（四川省眉山市）人，祖籍河北栾城，北宋著名文学家、书法家、画家，历史治水名人。苏轼是北宋中期文坛领袖，在诗、词、散文、书、画等方面取得很高成就。文纵横恣肆；诗题材广阔，清新豪健，善用夸张比喻，独具风格，与黄庭坚并称“苏黄”；词开豪放一派，与辛弃疾同是豪放派代表，并称“苏辛”；散文著述宏富，豪放自如，与欧阳修并称“欧苏”，为“唐宋八大家”之一。苏轼善书，“宋四家”之一；擅长文人画，尤擅墨竹、怪石、枯木等。与韩愈、柳宗元和欧阳修合称“千古文章四大家”。作品有《东坡七集》《东坡易传》《东坡乐府》《潇湘竹石图卷》《古木怪石图卷》等。"]},{"id":403,"grade":"六年级上册","title":"西江月·夜行黄沙道中","paragraphs":["作者：[宋代] 辛弃疾","明月别枝惊鹊，清风半夜鸣蝉。稻花香里说丰年，听取蛙声一片。","七八个星天外，两三点雨山前。旧时茅店社林边，路转溪桥忽见。","皎洁的月光从树枝间掠过，惊飞了枝头喜鹊，清凉的晚风吹来仿佛听见了远处的蝉叫声。田里稻花飘香，蛙声阵阵，似乎在告诉人们今年是一个丰收年。","天边几颗星星忽明忽暗，山前下起了淅淅沥沥的小雨。往日的小茅草屋还在土地庙的树林旁，道路转过溪水的源头，它便忽然出现在眼前。","辛弃疾（1140年5月28日－1207年10月3日），原字坦夫，后改字幼安，中年后别号稼轩，山东东路济南府历城县（今山东省济南市历城区）人。南宋官员、将领、文学家，豪放派词人，有“词中之龙”之称。与苏轼合称“苏辛”，与李清照并称“济南二安”。辛弃疾出生时，中原已为金兵所占。21岁参加抗金义军，不久归南宋。历任湖北、江西、湖南、福建、浙东安抚使等职。一生力主抗金。曾上《美芹十论》与《九议》，条陈战守之策。其词抒写力图恢复国家统一的爱国热情，倾诉壮志难酬的悲愤，对当时执政者的屈辱求和颇多谴责；也有不少吟咏祖国河山的作品。题材广阔又善化用前人典故入词，风格沉雄豪迈又不乏细腻柔媚之处。由于辛弃疾的抗金主张与当政的主和派政见不合，后被弹劾落职，退隐江西带湖。"]},{"id":404,"grade":"六年级上册","title":"4* 花之歌","paragraphs":["我是大自然的话语，大自然说出来，又收回去，藏在心间，然后又说一遍……","我是星星，从苍穹坠落在绿茵中。","我是诸元素之女：冬将我孕育，春使我开放，夏让我成长，秋令我昏昏睡去。","我是亲友之间交往的礼品，我是婚礼的冠冕，我是生者赠予死者最后的祭献。","清早，我同晨风一道将光明欢迎；傍晚，我又与群鸟一起为它送行。","我在原野上摇曳，使原野风光更加旖旎；我在清风中呼吸，使清风芬芳馥郁。我微睡时，黑夜星空的千万颗亮晶晶的眼睛对我察看；我醒来时，白昼的那只硕大无朋的独眼向我凝视。","我饮着朝露酿成的琼浆，听着小鸟的鸣啭、歌唱；我婆娑起舞，芳草为我鼓掌。我总是仰望高空，对光明心驰神往；我从不顾影自怜，也不孤芳自赏。而这些哲理，人类尚未完全领悟。"]},{"id":405,"grade":"六年级上册","title":"语文园地","paragraphs":["作者：[唐代] 孟浩然","故人具鸡黍，","邀我至田家。","绿树村边合，","青山郭外斜。","开轩面场圃，","把酒话桑麻。","待到重阳日，","还来就菊花。","老朋友准备丰盛的饭菜，邀请我到他田舍做客。","翠绿的树林围绕着村落，一脉青山在城郭外隐隐横斜。","推开窗户面对谷场菜园，共饮美酒，闲谈农务。","等到九九重阳节到来时，我还要来这里观赏菊花。","孟浩然（689年—740年），字浩然，号孟山人，襄州襄阳（今湖北襄阳）人，唐代著名的山水田园派诗人，世称“孟襄阳”。因他未曾入仕，又称之为“孟山人”。孟浩然生于盛唐，早年有志用世，在仕途困顿、痛苦失望后，尚能自重，不媚俗世，修道归隐终身。曾隐居鹿门山。40岁时，游长安，应进士举不第。曾在太学赋诗，名动公卿，一座倾服，为之搁笔。开元二十五年（737）张九龄招致幕府，后隐居。孟诗绝大部分为五言短篇，多写山水田园和隐居的逸兴以及羁旅行役的心情。其中虽不无愤世嫉俗之词，而更多属于诗人的自我表现。孟浩然的诗在艺术上有独特的造诣，后人把孟浩然与盛唐另一山水诗人王维并称为“王孟”，有《孟浩然集》三卷传世。","我是亲友之间交往的礼品，我是婚礼的冠冕，我是生者赠予死者最后的祭献。","漓江的水真静啊，静得让你感觉不到它在流动；漓江的水真清啊，清得可以看见江底的沙石；漓江的水真绿啊，绿得仿佛那是一块无瑕的翡翠。","花开了，就像睡醒了似的。鸟飞了，就像在天上逛似的。虫子叫了，就像在说话似的。","我在原野上摇曳，使原野风光更加旖旎；我在清风中呼吸，使清风芬芳馥郁。我微睡时，黑夜星空的千万颗亮晶晶的眼睛对我察看；我醒来时，白昼的那只硕大无朋的独眼向我凝视。","太阳晒着地面，有些地区吸收的热量多，那里的空气就比较热；有些地区吸收的热量少，那里的空气就比较冷。空气有冷有热，才能流动，成为风。"]},{"id":406,"grade":"六年级上册","title":"5 七律·长征","paragraphs":["红军不怕远征难，","万水千山只等闲。","五岭逶迤腾细浪，","乌蒙磅礴走泥丸。","金沙水拍云崖暖，","大渡桥横铁索寒。","更喜岷山千里雪，","三军过后尽开颜。","红军不怕万里长征路上的一切艰难困苦，把千山万水都看得极为平常。","五岭山脉绵延不绝，可在红军眼里不过像翻腾着的细小波浪；乌蒙山高大雄伟，在红军眼里也不过像在脚下滚过的泥丸。","金沙江浊浪滔天，湍急的流水拍击着高耸的山崖，溅起阵阵雾水，像是冒出蒸汽一样。大渡河险桥横架，晃动着凌空高悬的根根铁索，寒意阵阵。","更加令人欣喜的是千里岷山，皑皑白雪，红军翻越过去以后人人心情开朗，个个笑逐颜开。"]},{"id":407,"grade":"六年级上册","title":"6 狼牙山五壮士","paragraphs":["1941年秋，日寇集中兵力，向我晋察冀根据地大举进犯。当时，七连奉命在狼牙山一带坚持游击战争。经过一个多月英勇奋战，七连决定向龙王庙转移，把掩护群众和连队转移的任务交给了六班。","为了拖住敌人，七连六班的五个战士一边痛击追上来的敌人，一边有计划地把大批敌人引上了狼牙山。他们利用险要的地形，把冲上来的敌人一次又一次地打了下去。班长马宝玉沉着地指挥战斗，让敌人走近了，才下命令狠狠地打。副班长葛振林打一枪就大吼一声，好像细小的枪口喷不完他的满腔怒火。战士宋学义扔手榴弹总要把胳膊抡一个圈，好使出浑身的力气。胡德林和胡福才这两个小战士把脸绷得紧紧的，全神贯注地瞄准敌人射击。敌人始终不能前进一步。在崎岖的山路上，横七竖八地躺着许多敌人的尸体。","五位战士胜利地完成了掩护任务，准备转移。面前有两条路：一条通往主力转移的方向，走这条路可以很快追上连队，可是敌人紧跟在身后；另一条是通向狼牙山的顶峰棋盘陀，那儿三面都是悬崖绝壁。走哪条路呢？为了不让敌人发现群众和连队主力，班长马宝玉斩钉截铁地说了一声：“走！”带头向棋盘陀走去。战士们热血沸腾，紧跟在班长后面。他们知道班长要把敌人引上绝路。","五位壮士一面向顶峰攀登，一面依托大树和岩石向敌人射击。山路上又留下了许多具敌人的尸体。到了狼牙山峰顶，五位壮士居高临下，继续向紧跟在身后的敌人射击。不少敌人坠落山涧，粉身碎骨。班长马宝玉负伤了，子弹都打完了，只有胡福才手里还剩下一颗手榴弹。他刚要拧开盖子，马宝玉抢前一步，夺过手榴弹插在腰间，猛地举起一块大石头，大声喊道：“同志们！用石头砸！”顿时，石头像雹子一样，带着五位壮士的决心，带着中国人民的仇恨，向敌人头上砸去。山坡上传来一阵叽里呱啦的叫声，敌人纷纷滚落深谷。","又一群敌人扑上来了。马宝玉嗖的一声拔出手榴弹，拧开盖子，用尽全身气力扔向敌人。随着一声巨响，手榴弹在敌群中开了花。","五位壮士屹立在狼牙山顶峰，眺望着群众和部队主力远去的方向。他们回头望望还在向上爬的敌人，脸上露出胜利的喜悦。班长马宝玉激动地说：“同志们，我们的任务胜利完成了！”说罢，他把那支从敌人手里夺来的枪砸碎了，然后走到悬崖边上，像每次发起冲锋一样，第一个纵身跳下深谷。战士们也昂首挺胸，相继从悬崖往下跳。狼牙山上响起了他们壮烈豪迈的口号声：","“打倒日本帝国主义！”","“中国共产党万岁！”","这是英雄的中国人民坚强不屈的声音！这声音惊天动地，气壮山河！"]},{"id":408,"grade":"六年级上册","title":"7 开国大典","paragraphs":["1949年10月1日，中华人民共和国中央人民政府成立，在首都北京举行典礼。参加开国大典的，有中华人民共和国中央人民政府主席、副主席、各位委员，有中国人民政治协商会议全体代表，有工人、农民、学校师生、机关工作人员、城防部队，总数达三十万人。观礼台上还有外宾。","会场在天安门广场。广场呈丁字形。丁字形一横的北面是一道河，河上并排架着五座白石桥；再北面是城墙，城墙中央高高耸起天安门的城楼。丁字形的一竖向南直伸到中华门。在一横一竖的交点的南面，场中挺立着一根电动旗杆。","主席台设在天安门城楼上。城楼檐下，八盏大红宫灯分挂两边。靠着城楼左右两边的石栏，八面红旗迎风招展。","丁字形的广场汇集了从四面八方来的群众队伍。早上六点钟起，就有群众的队伍入场了。人们有的擎着红旗，有的提着红灯。进入会场后，按照预定的地点排列。工人队伍中，有从老远的长辛店、丰台、通县来的铁路工人，他们清早到了北京车站，一下火车就直奔会场。郊区的农民是五更天摸着黑起床，步行四五十里路赶来的。到了正午，天安门广场已经成了人的海洋，红旗翻动，像海上的波浪。","下午三点整，会场上爆发出一阵排山倒海的掌声，中华人民共和国中央人民政府主席毛泽东出现在主席台上，跟群众见面了。三十万人的目光一齐投向主席台。","中央人民政府秘书长林伯渠宣布典礼开始。中央人民政府主席、副主席、各位委员就位。接着，毛泽东主席宣布：“中华人民共和国中央人民政府今天成立了！”","这庄严的宣告，这雄伟的声音，使全场三十万人一齐欢呼起来。这庄严的宣告，这雄伟的声音，经过无线电广播，传到长城内外，传到大江南北，使全中国人民的心一齐欢跃起来。","接着，升国旗。毛主席亲自按动连通电动旗杆的电钮，新中国的国旗——五星红旗在雄壮的义勇军进行曲中徐徐上升。三十万人一齐脱帽肃立，一齐抬起头，瞻仰这鲜红的国旗。五星红旗升起来了，表明中国人民从此站起来了。","升旗的时候，礼炮响起来。每一响都是五十四门大炮齐发，一共二十八响。起初是全场肃静，只听见炮声和乐曲声，只听见国旗和其他许多旗帜飘拂的声音，到后来，每声炮响后，全场就响起一阵雷鸣般的掌声。","接着，毛主席在群众一阵又一阵的掌声中宣读中央人民政府的公告。他用强有力的语调向全世界发出新中国的声音。他读到“选举了毛泽东为中央人民政府主席”这一句的时候，广场上的人们热爱领袖的心情融成一阵热烈的欢呼。观礼台上同时响起一阵掌声。","毛主席宣读公告完毕，阅兵式开始。中国人民解放军朱德总司令任检阅司令员，聂荣臻将军任阅兵总指挥。朱总司令和聂将军同乘汽车，先检阅部队，然后朱总司令回到主席台，宣读中国人民解放军总部的命令。受检阅的部队就由聂将军率领，在《中国人民解放军进行曲》的乐曲声中，由东往西，缓缓进场。","开头是海军两个排，雪白的帽子，跟海洋一个颜色的蓝制服。接着是步兵一个师，以连为单位，列成方阵，齐步行进。接着是炮兵一个师，野炮、榴弹炮等各式各样的炮，都排成一字形的横列前进。接着是一个战车师，各种装甲车和坦克车两辆或三辆一排，整整齐齐地前进；战士们挺着胸膛站在战车上，像钢铁巨人一样。接着是一个骑兵师，“红马连”一色红马，“白马连”一色白马，六马并行，马腿的动作完全一致。以上这些部队，全都以相等的距离和相同的速度经过主席台前。当战车部队经过的时候，人民空军的飞机也一队队排成人字形，飞过天空。毛主席首先向空中招手。群众看见了，都把头上的帽子、手里的报纸和别的东西抛上天去，欢呼声盖过了飞机的隆隆声。","两个半钟头的检阅，广场上不断地欢呼，不断地鼓掌，一个高潮接着一个高潮。群众差不多把嗓子都喊哑了，把手掌都拍麻了，还觉得不能够表达自已心里的欢喜和激动。","阅兵式完毕，已经是傍晚的时候。天安门广场上的灯笼火把全都点起来，一万支礼花陆续射入天空。天上五颜六色的火花结成彩，地上千千万万的灯火一片红。群众游行就在这时候开始。游行队伍分东西两个方向出发，他们擎着灯，舞着火把，高呼“中国共产党万岁！”“中华人民共和国万岁！”“中央人民政府万岁！”他们一队一队按照次序走，走到正对天安门的白石桥前，就举起灯笼火把，高声欢呼“毛主席万岁！”“毛主席万岁！”毛主席在城楼上主席台前边，向前探着身子，不断地向群众挥手，不断地高呼“人民万岁！”“同志们万岁！”","晚上九点半，游行队伍才完全走出会场。两股“红流”分头向东城、西城的街道流去，光明充满了整个北京城。"]},{"id":409,"grade":"六年级上册","title":"8* 灯光","paragraphs":["我爱到天安门广场走走，尤其是晚上。广场上千万盏灯静静地照耀着周围的宏伟建筑，令人心头光明而又温暖。","清明节前的一个晚上，我又漫步在广场上，忽然背后传来一声赞叹：“多好啊！”我心头微微一震，是什么时候听到过这句话来着？噢，对了，那是很久以前了。于是，我沉入了深深的回忆。","1947年的初秋，当时我是战地记者。挺进豫皖苏平原的我军部队，把国民党军五十七师紧紧地包围在一个叫沙土集的村子里。激烈的围歼战就要开始了。天黑的时候，我摸进一片茂密的沙柳林，在匆匆挖成的交通沟里找到了突击连，来到了郝副营长的身边。","郝副营长是一 位著名的战斗英雄，虽然只有二十二岁，已经打过不少仗了。今晚就由他带领突击连去攻破守敌的围墙，为全军打通歼灭敌军的道路。大约一切准备工作都完成了，这会儿，他正倚着交通沟的胸墙坐着，一手拿着火柴盒，夹着自制的烟卷，一手轻轻地划着火柴。他并没有点烟，却借着微弱的亮光看摆在双膝上的一本破旧的书。书上有一幅插图，画的是一盏吊着的电灯，一个孩子正在灯下聚精会神地读书。他注视着那幅图，默默地沉思着。","“多好啊！”他在自言自语。突然，他凑到我的耳朵边轻轻地问：“记者，你见过电灯吗？”","我不由得一愣，摇了摇头，说：“没见过。”我说的是真话。我从小生活在农村，真的没见过电灯。","“听说一按电钮，那玩意就亮了，很亮很亮。”他又划着一根火柴，点燃了烟，又望了一眼图画，深情地说：“赶明儿胜利了，咱们也能用上电灯，让孩子们都在那样亮的灯光底下学习，该多好啊！”他把头靠在胸墙上，望着漆黑的夜空，完全陷入了对未来的憧憬里。","半个小时以后，我刚回到团指挥所，战斗就打响了。三发绿色的信号弹升上天空，接着就是震天动地的炸药包爆炸声。守敌的围墙被炸开一个缺口，突击连马上冲了进去。没想到后续部队遭到敌人炮火猛烈的阻击，在黑暗里找不到突破口，和突击连失去了联系。","整个团指挥所的人都焦急地钻出了地堡，望着黑黑魆魆的围墙。突然，黑暗里出现一星火光，一闪，又一闪。这火光虽然微弱，对于寻找突破口的部队来说已经足够亮了，战士们靠着这微弱的火光冲进了围墙。围墙里响起了一片喊杀声。","后来才知道，在这千钧一发的时刻，是郝副营长划着了火柴，点燃了那本书，举得高高的，为后续部队照亮了前进的路。可是，火光暴露了他自己，他被敌人的机枪打中了。","这一仗，我们消灭了敌人的一个整编师。战斗结束后，我们把郝副营长埋在茂密的沙柳丛里。这位年轻的战友为了让孩子们能够在电灯底下学习，不惜牺牲自己的生命，他自己却没有来得及见一见电灯。","事情已经过去很长时间了。在天安门前璀璨的华灯下面，我又想起这位亲爱的战友来。"]},{"id":410,"grade":"六年级上册","title":"9* 我的战友邱少云","paragraphs":["天亮以前，我们在391高地的山坳里，找了一条比较隐蔽的山沟潜伏起来。","太阳渐渐爬上山头，晒干了我们身上的寒霜，早上冻麻了的腿也开始暖和起来。我们本来打算趁这时候在温暖的阳光下睡一会儿，因为已经熬了整整一夜，而且当天晚上还有激烈的战斗在等着，需要养养精神，好完成晚上的战斗任务，可是我怎么也合不上眼睛。谁能趴在敌人的鼻子底下睡大觉呢？","我发现这条干涸的小山沟并不十分隐蔽。我们离敌人太近了，前面几十米就是敌人的前沿阵地。我们不但可以看见敌人设置的铁丝网和胸墙，而且可以看见敌人主阵地上的地堡和火力点，甚至连敌人的谈话声都听得见。可以想见，敌人居高临下，发现我们当然更容易。我们必须僵卧着一动不动，一声低低的咳嗽或者轻轻地蜷下腿，都可能被敌人发觉。","我们全靠身上的伪装掩护自己。我看了一下前面，班长和几个战士都伏在枯黄的茅草里，身上也披着厚厚的茅草作为伪装，猛一看去，很难发现他们。我又看了看伏在不远处的邱少云，他也全身伪装，隐蔽得更好，相隔这么近，我都几乎找不到他。","我们的炮兵不断地向敌人阵地上轰击，山顶上不时地腾起一团的青烟，敌人阵地前沿的地堡一个接一个地被掀翻了。炮兵的轰击不但推毁了敌人的一部分工事，便于我们晚上突击，而且把敌人打得躲进隐蔽洞里，又保证了我们潜伏部队的安全。","看到山顶上敌人被我军炮火轰击的情景，我只盼望快点儿天黑好痛痛快快地打一仗。看看太阳，却老是停在原来的地方，就像钉住了似的。","约莫11点钟的时候，突然一发烟幕弹飞来，在我们附近爆炸了，","一排一排的炮弹跟着打过来。显然，狡猾的敌人对他们阵地前沿的安全极不放心，又没有胆量冒着我军的炮火到这一带来搜索，只好把看家本领“火力警戒”拿出来了。","我们附近的荒草着火了，火苗子呼呼地蔓延着，烧得枯黄的茅草毕毕剥剥地响。恶毒的敌人竟使用燃烧弹来进行搜索了。","不一会儿，火已经烧到我面前，火苗子一伸一伸的，烤得我脸上热辣辣地疼。幸而面前有一堆不长草的乱石头挡着,火才没烧到我身上。","忽然，一阵浓重的棉布焦味钻进我的鼻子，我扭头一看，哎呀！","火烧到了邱少云身上！他的棉衣已经烧着了，浑身火苗乱窜，看样子是溅上了燃烧弹的油液。趁着风势，一团烈火把他整个包围了。","这个时候，邱少云如果迅速从火堆里跳出来，就地打几个滚身上的火是可以扑灭的。我们卧在他附近的任何一个人，如果跳过去把他拉出来，扯掉他着火的棉衣，也能救出自己的战友。但是这样一来，我们就会被山头上敌人的哨兵发觉，那么不仅是我们这个班要牺牲在这里，也不仅是埋伏在我们身后的整个潜伏部队要受到重大损失，更严重的是我们准备了好久的这次作战计划要完全落空。","我的心紧缩着，我担心这个年轻的战士会实在忍耐不住突然跳起来，或者突然叫出声来。我几次回过头来，不敢朝他那儿看，不忍看着我的战友被活活烧死，但是我又忍不住不看。我心里像刀绞一般，眼泪模糊了我的眼睛。","烈火在我的战友邱少云身上烧了半个多钟头才渐渐熄灭。这个伟大的战士，像千斤巨石，伏在那儿纹丝不动，直到牺牲前的最后一息，都没发出哪怕是极轻微的一声呻吟。","黄昏时，我们勇猛地冲上了敌人的阵地。在391高地上沸腾着激动人心的口号：“为邱少云同志报仇！”","我当时的感觉，仿佛邱少云同志并没有牺牲，他和我们一起向敌人冲锋！","我永远忘不了那一天——1952年10月12日。"]},{"id":411,"grade":"六年级上册","title":"语文园地","paragraphs":["捐躯赴国难，视死忽如归。——曹植","祖宗疆土，当以死守，不可以尺寸与人。——李纲","位卑未敢忘忧国。——陆游","起初是全场肃静，只听见炮声和乐曲声，只听见国旗和其他许多旗帜飘拂的声音。那里的天比别处的更可爱，空气是那么清新，天空那么明朗，使我总想高歌一曲，表示我满心的愉快。","清明节前的一个晚上，我又漫步在广场上，忽然背后传来一声赞叹：“多好啊！”","“我还有作业还没完成，不能和你一起去玩了。”我婉言谢绝了伙伴的邀请。","“既然这样，你以后再也不要找我借书了！”话一出口，我就后悔了。","妈妈俯下身子盯着我的眼睛，一脸焦急：“你的眼睛怎么肿了？”","这两个句子分别用“赞叹”“婉言谢绝”代替了“说”。我还想到了“谈论讲解、窃窃私语……”","也可以不用与“说”有关的词语……"]},{"id":412,"grade":"六年级上册","title":"10 竹节人","paragraphs":["我们小时候的玩具，都是自己做的，也只能自己做。只要有一个人做了一件新鲜玩意，大家看了有趣，很快就能风靡全班，以至全校。","有一段时间，我们全迷上了斗竹节人。","把毛笔杆锯成寸把长的一截，这就是竹节人的脑袋连同身躯了，在上面钻一对小眼，供装手臂用。再锯八截短的，分别当四肢。用一根纳鞋底的线把它们穿在一起，就成了。锯的时候要小心，弄不好一个个崩裂，前功尽弃。","那一段时间，妈妈怪我总是把毛笔弄丢，而校门口卖毛笔的老头则生意特别好。","教室里的课桌破旧得看不出年纪，桌面上是一道道豁开的裂缝，像黄河长江，一不小心。铅笔就从裂缝里掉下去了。","而现在，这些裂缝正好用来玩竹节人。","仔细想来，那个发明这竹节人的家伙，准也是坐这种课桌长大的。","把穿着九个竹节的鞋线嵌入课桌裂缝里，在下面一拉紧，那立在裂缝上的竹节们就站成一个壮士模样，叉腿张胳膊，威风凛凛，跟现今健美比赛中那脖子老粗、浑身疙瘩肉的小伙子差不多。","将鞋线一松一紧，那竹节人就手舞之、身摆之地动起来。两个竹节人放在一起，那就是搏斗了，没头没脑地对打着，不知疲倦，也永不会倒下。","有时其中一个的线卡住了，那“斗士”便显出一副呆头呆脑的傻样子，挺着肚子净挨揍。","竹节人手上系上一根冰棍棒，就成了手握金箍棒的孙悟空，号称“齐天小圣”，四个字歪歪斜斜刻在竹节人背上，神气！","找到两根针织机上废弃的钩针，装在竹节人手上，就成了窦尔敦的虎头双钩。把“金钩大王”刻在竹节人的胸口，神气！","用铅皮剪一把偃月刀，用铁丝系一绺红丝线做一柄蛇矛，给那竹节人装上，再挖空心思取一个更威风、更吓人、叫得更响的名号。","破课桌，俨然一个剑拔弩张的古战场。","还有同学别出心裁，想技高一筹，给竹节人粘上一个橡皮雕成的脑袋，做一套纸盔甲。一有机会，便得意扬扬招呼大伙来观摩。谁知弄巧成拙，中看不中用，没打几个回合，那粘上的脑袋连盔甲被它自已手里的大刀磕飞了，于是对方大呼胜利。","其实，竹节人的动作压根不由扯线人做主，那不过是在竹节间的线一紧一松间的胡乱耸动而已，可看上去，却挺像是那么回事。","黑虎掏心！泰山压顶！双龙抢珠！","咚锵咚锵咚咚锵！咚咚锵！","下课时，教室里摆开场子，吸引了一圈黑脑袋，攒着观战，还跺脚拍手，咋咋呼呼，好不热闹。常要等老师进来，才知道已经上课，便一哄作鸟兽散。","上课了，意兴依然不减，手痒痒的，将课本竖在面前当屏风，跟同桌在课桌上又搏将起来，这会儿，嘴里不便咚锵。","偏偏后面的同学不知趣，看得入了迷，伸长脖子，恨不能从我们肩膀上探过来，被那虎视眈眈的老师看出了破绽。","老师大步流星走过来，怒气冲冲伸手一拂，“屏风”颓然倒了，一切秘密暴露无遗。不消说，费了许多功夫做出来的，建立了赫赫伟绩，鏖战犹酣的两个竹节人被一把抓去。","下课后，眼巴巴看别的同学重新开战，玩得欢，不禁沮丧得要命，便一起悄悄溜到办公室窗户下的冬青丛里转悠，希望老师能像往常一样，把没收的东西扯散了，随手扔出窗外。","蹲着身子，瞪大眼，可一无所获。正悻悻然准备离去，却见同桌趴在窗玻璃旁看得津津有味。","我也凑过去，一探头，咦，看见了什么？","只见老师在他自己的办公桌上，玩着刚才收去的那竹节人。双手在抽屉里扯着线，嘴里念念有词，全神贯注，忘乎所以，一点儿也没注意到我们在偷看。","他脸上的神情，跟我们玩得入迷时一模一样。","于是，我跟同桌相视一笑，虽两手空空，但心满意足，轻手轻脚地溜了。","方才的那份小小的怨恨和沮丧化为乌有。"]},{"id":413,"grade":"六年级上册","title":"11 宇宙生命之谜","paragraphs":["古时候，科学不发达，人们一直向往着“天上的世界”。于是，有了许许多多的故事：嫦娥奔月，仙女下凡，蟠桃盛会……现在，科学发达了，人们知道那都是古人编出来的。但是，地球之外的太空中是否有生命存在，仍然是一个吸引人的问题。","从理论上说，宇宙是无限的。地球只是太阳系中的一颗行星，而太阳系只是银河系中一个极小的部分，银河系对宇宙来说又是沧海一粟。整个银河系中有几千亿颗恒星，类似太阳系这样的天体系统为数不少，其中肯定有与地球类似的行星。可以猜测，地球绝不是有生命存在的唯一天体。但是，人类至今尚未找到另外一颗存在生命的星球。","哪些天体上可能有生命存在呢？这个天体又必须具备什么样的条件呢？人们了解了生命起源的过程之后，认为至少应有这样几个条件：一是适合生物生存的温度，一般应在－50～150℃之间；二是必要的水分，生命物质诸如蛋白质、核酸的活力都和水紧密相关，没有水，也就没有生命；三是适当成分的大气，虽然已发现少数厌氧菌能在没有氧气的条件下生存，但氧气和二氧化碳对于生命的存在是极为重要的；四是要有足够的光和热，为生命系统提供能源。","根据这些条件，科学家首先对太阳系除地球以外的其他行星进行了分析。水星离太阳最近，朝向太阳的一面表面温度达到300 ~ 400℃，不可能存在生命。金星是一颗缺氧、 缺水，有着浓厚云层的行星，太阳辐射和云层造成的“温室效应”，使得金星表面温度极高，不可能有生命存在。木星、土星、天王星和海王星离太阳很远，它们的表面温度，一般都低于－140°C，因此，也不可能有生命存在。","太阳系中唯一还可能存在生命的行星是火星。火星与地球有不少相似之处：地球自转一圈是23小时56分4秒，火星自转一圈是24小时37分22.6秒；地球自转轴与公转轨道平面有66度34分的倾角，而火星的倾角约66度1分，所以火星和地球昼夜长短相近，而且也有四季更替。更有趣的是，1877年，意大利的一位天文学家观察到火星表面有很多纵横的黑色线条，人们猜测这是火星人开挖的运河。人们还观察到火星表面的颜色随着季节而变化，有人认为这是火星表面植物随着季节的变化而改变了颜色。","为了揭开火星神秘的面纱，科学家们决定利用探测器对火星作近距离的观测。1971年，美国发射的“水手9号”探测器进入了环绕火星飞行的轨道，给火星拍摄了大量的照片。这些照片表明，意大利天文学家观察到的所谓“运河”，原来是一连串的暗环形山和暗的斑点。通过近距离观测还发现，以前观察到的火星表面上所谓颜色的四季变化，并不是植物的生长和枯萎造成的，而是风把火星表面上的尘土吹来吹去引起的颜色明暗变化。","科学家们还发现：火星是一个非常干燥的星球，在它的大气中虽然找到了水汽，但含量极少，只有地球上沙漠地区的1%；火星的大气层非常稀薄，96%是二氧化碳，氧气含量极少；火星表面温度很低；火星上没有磁场，它的大气层中又没有臭氧层，因而不能抵御紫外线和各种宇宙线的照射。所有这些因素都说明，在火星上生命难以存在。","为了对火星作进一步的考察，1975年，美国发射了两个名叫“海盗号”的探测器。这两个探测器在火星着陆，进行了一系列的分析和测试，得到两个重要结果：一是在火星的土壤中未检测到有机分子；二是在对火星表面取样的培养中，未发现微生物的存在。这证明，在探测器着陆的地区，火星表面没有生命存在。科学家又提出，生命物质是否会存在于火星的岩层之中呢？这有待进一步研究。","人们至今尚未在地球以外的太空中找到生命，但仍然相信遥远的太空存在着生命。近年来，科学家对落在地球上的一些陨石进行分析，发现陨石上存在有机分子，说明太空可能存在生命。","地球之外是否有生命存在，是人类一直探索的宇宙之谜。"]},{"id":414,"grade":"六年级上册","title":"12* 故宫博物院","paragraphs":["材料一","在北京城的中心，有一座城中之城，这就是紫禁城。现在人们叫它故宫，也叫故宫博物院。这是明清两代的皇宫，是我国现存的最大最完整的古代宫殿建筑群，有六百多年历史了。","紫禁城的城墙十米多高，有四座城门：南边午门，北边神武门，东西两边分别是东华门、西华门。宫城呈长方形，占地七十二万平方米。城墙外是五十多米宽的护城河。城墙的四角，各有一座玲珑奇巧的角楼。故宫建筑群规模宏大，建筑精美，布局统一，集中体现了我国古代建筑艺术的独特风格。","从天安门往里走，沿着一条笔直的大道穿过端门，就到了午门的前面。午门俗称“五凤楼”，是紫禁城的正门。走进午门，是一个宽阔的广场，弯弯的内金水河像一条玉带横贯东西，河上是五座精美的汉白玉石桥。桥的北面是太和门，一对威武的铜狮守卫在门的两侧。","进了太和门，就来到紫禁城的中心——三大殿：太和殿、中和殿、保和殿。三座大殿矗立在八米多高的白石台基上。台基有三层，每层的边缘都有汉白玉栏杆围绕着，栏杆上面刻着龙凤流云，四角和望柱下面伸出一千多个圆雕螭首，螭首嘴里都有一个小圆洞，是台基的排水管道。","太和殿俗称金銮殿，高二十八米，面积两千三百八十多平方米，是故宫最大的殿堂。在湛蓝的天空下，那金黄色的琉璃瓦重檐屋顶，显得格外辉煌。殿檐斗拱、额枋、梁柱，装饰着青蓝点金和贴金彩画。正面是十二根红色大圆柱，金琐窗，朱漆门，同台基上的白色栏杆相互衬映，色彩鲜明，雄伟壮丽。","大殿正中是一个约两米高的朱漆方台，上面安放着金漆雕龙宝座，背后是雕龙屏。方台两旁有六根高大的蟠龙金柱，每根大柱上都盘绕着矫健的金龙。仰望殿顶，中央藻井有一条巨大的雕金蟠龙，从龙口里垂下一颗银白色大圆珠，周围环绕着六颗小珠，龙头、宝珠正对着下面的宝座。梁枋间彩画绚丽，有双龙戏珠、单龙翔舞，有行龙、升龙、降龙，多态多姿，龙身周围还衬托着流云火焰。","三大殿建在紫禁城的中轴线上。这条线也是北京城的中轴线，向南从午门到天安门延伸到正阳门、永定门，往北从神武门到地安门、鼓楼，全长约八公里。","太和殿是举行重大典礼的地方。皇帝即位、生日、婚礼和元旦等，都在这里接受朝贺。每逢大典，皇帝端坐在宝座上，殿外的白石台基上下，文武百官分列左右，中间御道两边排列着仪仗，大殿廊下，鸣钟击磬，乐声悠扬。台基上的香炉和铜龟、铜鹤里点起檀香或松柏枝，烟雾缭绕。","太和殿后面是中和殿。这是一座亭子形大殿，殿顶把四道垂脊攒在一起，正中安放着一个大圆镏金宝顶，轮廓非常优美。举行大典时，皇帝先在这里休息。","中和殿后面是保和殿。雍正以后，这里是举行最高一级考试——殿试的地方。","从保和殿出来，下了石级是一个长方形小广场。广场西起隆宗门，东到景运门。它把紫禁城分为前后两大部分。广场以南，主要建筑是三大殿和东西两侧的文华殿、武英殿，叫“前朝”。广场北面乾清门以内叫“内廷”，是皇帝和后妃们起居生活的地方，主要建筑有乾清宫、交泰殿、坤宁宫和东六宫、西六宫。","乾清宫是皇帝处理日常政务、批阅各种奏章的地方，后来还在这里接见外国使节。","乾清宫后面是交泰殿，交泰殿后面是坤宁宫。坤宁宫是皇后宫，也是皇帝结婚的地方。","乾清宫、交泰殿、坤宁宫合称“后三宫”。布局和前三殿基本一样，但庄严肃穆的气氛减少了，彩画图案也有明显的变化。前三殿的图案以龙为主，后三宫凤凰逐渐增加，出现了双凤朝阳、龙凤呈祥的彩画，还有飞凤、舞凤、凤凰牡丹等图案。","后三宫往北是御花园。御花园面积不是很大，有大小建筑二十多座，但毫无拥挤和重复的感觉。这里的建筑布局、环境气氛，和前几部分迥然不同。亭台楼阁、池馆水榭，掩映在青松翠柏之中；假山怪石、花坛盆景、藤萝翠竹，点缀其间。来到这里，仿佛进入苏州园林。","从御花园出顺贞门，就到了紫禁城的北门——神武门，对面就是景山。据说景山是明代修建紫禁城的时候，用护城河中挖出的泥土堆起来的，现在成了风景优美的景山公园。站在景山的高处望故宫，重重殿宇，层层楼阁，道道宫墙，错综相连而又井然有序。这样宏伟的建筑群，这样和谐统一的布局，不能不令人惊叹。","——选自黄传惕的《故宫博物院》，有改动","材料二","现在见到的太和门，是清末光绪十五年（1889）重修的。光绪十四年十二月十五日深夜，太和门西的贞度门失火，向东延烧太和门、昭德门以及整个太和殿南庑。由于当时消防器材不全及灭火水源不足，大火烧了两天才被扑灭。起火原因是贞度门值夜班的护军富山、双奎，把旧洋油灯挂在贞度门东山墙后檐柱上睡了觉。时间一久，油灯烧着柱子，四更火起，借着大风，烧个不停。事后这二人都被处了绞刑。","这是一场不大不小的火灾，但时机不好，一个多月后，即转年正月二十六日，正是光绪帝大婚的吉日。大婚纳彩、迎娶都必经太和门。时间紧迫，又值天寒地冻，修复三门肯定来不及。于是，宫中请来市面上扎彩棚的能工巧匠，按原建筑面貌复制，其高卑广狭，乃至檐角小兽、大吻雕镂，无不惟妙惟肖，即使宫中人员也看不出真伪，而且高逾数丈竟风吹不摇。这样总算应付过了大婚。","——选自姜舜源的《故宫史话》，有改动","材料三","故宫博物院欢迎您！","北京故宫(旧称紫禁城)是明清两代的皇家宫殿。","1961年，经国务院批准，故宫被定为全国重点文物保护单位。1987年，被联合国教科文组织列入世界文化遗产名录。","自2011年7月2日起，故宫博物院实行自南向北单向参观路线：午门(南门)只作为参观入口，观众一律从午门进入故宫；神武门(北门)只作为参观出口，观众参观结束后可由神武门或东华门(东门)离开故宫。","（资料来源：2016年12月的故宫博物院官方网站）"]},{"id":415,"grade":"六年级上册","title":"语文园地","paragraphs":["作者：[宋代] 朱熹","胜日寻芳泗水滨，","无边光景一时新。","等闲识得东风面，","万紫千红总是春。","风和日丽之时在泗水的河边踏青，无边无际的风光焕然一新。","谁都可以看出春天的面貌，春风吹地百花开放、万紫千红，到处都是春天的景致。","朱熹（1130年9月15日～1200年4月23日），行五十二，小名沋郎，小字季延，字元晦，一字仲晦，号晦庵，晚称晦翁，又称紫阳先生、考亭先生、沧州病叟、云谷老人、逆翁。谥文，又称朱文公。汉族，祖籍南宋江南东路徽州府婺源县（今江西省婺源），出生于南剑州尤溪（今属福建三明市）。南宋著名的理学家、思想家、哲学家、教育家、诗人、闽学派的代表人物，世称朱子，是孔子、孟子以来最杰出的弘扬儒学的大师。","下课时，教室里摆开场子，吸引了一圈黑脑袋，攒着观战，还跺脚拍手，咋咋呼呼，好不热闹。常要等老师进来，才知道已经上课。","偏偏后面的同学不知趣，看得入了迷，伸长脖子，恨不能从我们肩膀上探过来。","只见罗丹一会儿上前，一会儿后退，嘴里叽里咕嚕的，好像在跟谁说悄悄话;忽然眼睛闪着异样的光，似乎在跟谁激烈地争吵。他把地板踩得吱吱响，手不停地挥动……一刻钟过去了，半小时过去了，罗丹越干越有劲，情绪更加激动了。他像喝醉了酒一样，整个世界对他来讲好像已经消失了——大约过了一个小时，罗丹才停下来，对着塑像痴痴地微笑，然后轻轻地舒了口气。","人们认为天体上若有生命存在，至少应有这样几个条件:一是适合生物生存的温度，一般应在-50~ 150℃之间;二是必要的水分，生命物质诸如蛋白质、核酸的活力都和水紧密相关，没有水，也就没有生命;三是适当成分的大气，虽然已发现少数厌氧菌能在没有氧气的条件下生存，但氧气和二氧化碳对于生命的存在是极为重要的；四是要有足够的光和热，为生命系统提供能源。"]},{"id":416,"grade":"六年级上册","title":"13 桥","paragraphs":["黎明的时候，雨突然大了。像泼。像倒。","山洪咆哮着，像一群受惊的野马，从山谷里狂奔而来，势不可当。","村庄惊醒了。人们翻身下床，却一脚踩进水里。是谁惊慌地喊了一嗓子，一百多号人你拥我挤地往南跑。近一米高的洪水已经在路面上跳舞了。人们又疯了似的折回来。","东面、西面没有路。只有北面有座窄窄的木桥。","死亡在洪水的狞笑声中逼近。","人们跌跌撞撞地向那木桥拥去。","木桥前，没腿深的水里，站着他们的党支部书记，那个全村人都拥戴的老汉。","老汉清瘦的脸上淌着雨水。他不说话，盯着乱哄哄的人们。他像一座山。","人们停住脚，望着老汉。","老汉沙哑地喊话：“桥窄！排成一队，不要挤！党员排在后边！”","有人喊了一声：“党员也是人。”","老汉冷冷地说：“可以退党，到我这儿报名。”","竟没人再喊。一百多人很快排成队，依次从老汉身边奔上木桥。","水渐渐蹿上来，放肆地舔着人们的腰。","老汉突然冲上前，从队伍里揪出一个小伙子，吼道：“你还算是个党员吗？排到后面去！”老汉凶得像只豹子。","小伙子瞪了老汉一眼，站到了后面。","木桥开始发抖，开始痛苦地呻吟。","水，爬上了老汉的胸膛，最后，只剩下了他和小伙子。","小伙子推了老汉一把，说：“你先走。”","老汉吼道：“少废话，快走。”他用力把小伙子推上木桥。","突然，那木桥轰的一声塌了。小伙子被洪水吞没了。","老汉似乎要喊什么，猛然间，一个浪头也吞没了他。","一片白茫茫的世界。","五天以后，洪水退了。","一个老太太，被人搀扶着，来这里祭奠。","她来祭奠两个人。","她丈夫和她儿子。"]},{"id":417,"grade":"六年级上册","title":"14 穷人","paragraphs":["渔夫的妻子桑娜坐在火炉旁补一张破帆。屋外寒风呼啸，汹涌澎湃的海浪拍击着海岸，溅起一阵阵浪花。海上正起着风暴，外面又黑又冷，这间渔家的小屋里却温暖而舒适。地扫得干干净净，炉子里的火还没有熄，食具在搁板上闪闪发亮。挂着白色帐子的床上，五个孩子正在海风呼啸声中安静地睡着。丈夫清早驾着小船出海，这时候还没有回来。桑娜听着波涛的轰鸣和狂风的怒吼，感到心惊肉跳。","古老的钟发哑地敲了十下，十一下……始终不见丈夫回来。桑娜沉思：丈夫不顾惜身体，冒着寒冷和风暴出去打鱼，她自己也从早到晚地干活，还只能勉强填饱肚子。孩子们没有鞋穿，不论冬夏都光着脚跑来跑去；吃的是黑面包，菜只有鱼。不过，孩子们都还健康，没什么可抱怨的。桑娜倾听着风暴的声音。“他现在在哪儿？老天啊，保佑他，救救他，开开恩吧！”她自言自语着。","睡觉还早。桑娜站起身来，把一块很厚的围巾包在头上，提着马灯走出门去。她想看看灯塔上的灯是不是亮着，丈夫的小船能不能望见。海面上什么也看不见。风掀起她的围巾，卷着被刮断的什么东西敲打着邻居小屋的门。桑娜想起了傍晚就想去探望的那个生病的女邻居。“ 没有一个人照顾她啊！”桑娜一边想一边敲了敲门。她侧着耳朵听，没有人答应。","寡妇的日子真困难啊！”桑娜站在门口想，“孩子虽然不算多——只有两个，可是全靠她一个人张罗，如今又加上病。唉，寡妇的日子真难过啊！进去看看吧！”","桑娜一次又一次地敲门，仍旧没有人答应。","“喂，西蒙！”桑娜喊了一声，心想，莫不是出什么事了？她猛地推开门。","屋子里没有生炉子，又潮湿又阴冷。桑娜举起马灯，想看看病人在什么地方。首先投入眼帘的是对着门的一张床，床上仰面躺着她的女邻居。她一动不动。桑娜把马灯举得更近一些，不错，是西蒙。她头往后仰着，冰冷发青的脸上显出死的宁静，一只苍白僵硬的手像要抓住什么似的，从稻草铺上垂下来。就在这死去的母亲旁边，睡着两个很小的孩子，都是卷头发、圆脸蛋，身上盖着旧衣服，蜷缩着身子，两个浅黄头发的小脑袋紧紧地靠在一起。显然，母亲在临死的时候，拿自己的衣服盖在他们身上，还用旧头巾包住他们的小脚。孩子呼吸均匀而平静，睡得正香甜。","桑娜用头巾裹住睡着的孩子，把他们抱回家里。她的心跳得很厉害，自己也不知道为什么要这样做，但是觉得非这样做不可。她把这两个熟睡的孩子放在床上，让他们同自己的孩子睡在一起，又连忙把帐子拉好。","桑娜脸色苍白，神情激动。她忐忑不安地想：“他会说什么呢？这是闹着玩的吗？自己的五个孩子已经够他受的了……是他来啦？……不，还没来！……为什么把他们抱过来啊？……他会揍我的！那也活该，我自作自受……嗯，揍我一顿也好！”","门吱嘎一声，仿佛有人进来了。桑娜一惊，从椅子上站起来。","“不，没有人！天啊，我为什么要这样做？……如今叫我怎么对他说呢？……”桑娜沉思着，久久地坐在床前。","门突然开了，一股清新的海风冲进屋子。魁梧黧黑的渔夫拖着湿淋淋的被撕破了的渔网，一边走进来，一边说：“嘿，我回来啦，桑娜！”","“哦，是你！”桑娜站起来，不敢抬起眼睛看他。","“瞧，这样的夜晚！真可怕！”","“是啊，是啊，天气坏透了！哦，鱼打得怎么样？”","“糟糕，真糟糕！什么也没有打到，还把网给撕破了。倒霉，倒霉！天气可真厉害！我简直记不起几时有过这样的夜晚了，还谈得上什么打鱼！还好，总算活着回来啦。……我不在，你在家里做些什么呢？”","渔夫说着，把网拖进屋里，坐在炉子旁边。","“我？”桑娜脸色发白，说，“我嘛……缝缝补补……风吼得这么凶，真叫人害怕。我可替你担心呢！”","“是啊，是啊，”丈夫喃喃地说，“这天气真是活见鬼！可是有什么办法呢！”","两个人沉默了一阵。","“你知道吗？”桑娜说，“咱们的邻居西蒙死了。”","“哦？什么时候？”","“我也不知道，大概是昨天。唉！她死得好惨啊！两个孩子都在她身边，睡着了。他们那么小……一个还不会说话，另一个刚会爬……”桑娜沉默了。","渔夫皱起眉，他的脸变得严肃、忧虑。“嗯，是个问题！”他搔搔后脑勺说，“嗯，你看怎么办？得把他们抱来，同死人待在一起怎么行！哦，我们，我们总能熬过去的！快去！别等他们醒来。”","但桑娜坐着一动不动。","“你怎么啦？不愿意吗？你怎么啦，桑娜？”","“你瞧，他们在这里啦。”桑娜拉开了帐子。"]},{"id":418,"grade":"六年级上册","title":"15 金色的鱼钩","paragraphs":["1935年秋天，红四方面军进入草地，许多同志得了肠胃病。我和两个小同志病得实在赶不上队伍了，指导员派炊事班长照顾我们，让我们走在后面。","炊事班长快四十岁了，个子挺高，背有点儿驼，四方脸，高颧骨，脸上布满了皱纹。全连数他岁数大，对大家又特别亲，大伙都叫他“老班长”。","三个病号走不快，一天只走二十来里路。一路上，老班长带我们走一阵歇一阵。到了宿营地，他就到处去找野菜，和着青稞面给我们做饭。不到半个月，两袋青稞面吃完了。饥饿威胁着我们。老班长到处找野菜，挖草根，可是光吃这些东西怎么行呢？老班长看我们一天天瘦下去，他整夜整夜地合不拢眼，其实，这些天他比我们瘦得还厉害呢！","一天，他在一个水塘边给我们洗衣裳，忽然看见一条鱼跳出水面。他喜出望外地跑回来，取出一根缝衣针，烧红了，弯成个钓鱼钩。这天夜里，我们就吃到了新鲜的鱼汤。尽管没有调料，可我们觉得没有比这鱼汤更鲜美的了，端起碗来吃了个精光。","从那以后，老班长尽可能找有水塘的地方宿营，把我们安顿好，就带着鱼钩出去了。第二天，他总能端着热气腾腾的鲜鱼野菜汤给我们吃。虽然我们还是一天一天衰弱下去，但比起光吃草根野菜毕竟好多了。可是老班长自己呢，我从来没见他吃过一点儿鱼。","有一次，我禁不住问他：“老班长，你怎么不吃鱼啊？”","他摸了摸嘴，好像回味似的说：“吃过了。我一起锅就吃，比你们还先吃呢。”","我不信，等他收拾完碗筷走了，就悄悄地跟着他。走近一看，啊！我不由得呆住了。他坐在那里捧着搪瓷碗，嚼着几根草根和我们吃剩下的鱼骨头，嚼了一会儿，就皱紧眉头硬咽下去。我觉得好像有万根钢针扎着喉管，失声喊起来：“老班长，你怎么……”","老班长猛抬起头，看见我目不转睛地看着他手里的搪瓷碗，就支吾着说：“我，我早就吃过了。看到碗里还没吃干净，扔了怪可惜的……”","“不，我全知道了。”我打断了他的话。","老班长转身朝两个小同志睡觉的地方看了一眼，一把把我搂到身边，轻声说：“小声点儿，小梁！咱们俩是党员，你既然知道了，可不要再告诉别人。”","“可是，你也要爱惜自己啊！”","“不要紧，我身体还硬实！”他抬起头，望着夜色弥漫的草地，好久，才用低沉的声音说：“指导员把你们三个人交给我，他临走的时候说：“他们年轻。一路上，你是上级，是保姆，是勤务员啊，无论多么艰苦，都要把他们带出草地。小梁，你看这草地，无边无涯，没个尽头。我估计，还要二十天才能走出去。熬过这二十天不简单啊！眼看你们的身子一天比一天衰弱，只要哪一天吃不上东西，说不定就会起不来，真有个三长两短，我怎么去向党报告呢？难道我能说：‘指导员，我把同志们留在草地上，我自己克服困难出来啦！’”","“可是，你总该跟我们一起吃一点儿啊！” “不行，太少啦。”他轻轻地摇摇头，“小梁，说真的，弄点儿吃的不容易啊！有时候等了半夜，也不见鱼上钩。为了弄一点儿鱼饵，我翻了多少草皮也找不到一条蚯蚓……还有，我的眼睛坏了，天色一暗，找野菜就得一棵一棵地摸……”","我再也忍不住了，抢着说：“老班长，以后我帮你一起找，我看得见。”","“不，咱们不是早就分好工了吗？再说，你的病也不轻，不好好休息会撑不住的。” 我还坚持我的意见。老班长忽然严厉地说：“小梁同志，共产党员要服从党的分配。你的任务是坚持走路，安定两个小同志的情绪，增强他们的信心！”","望着他那十分严峻的脸，我一句话也说不上来，竟扑倒在他怀里哭了。 第二天，老班长端来的鱼汤特别少，每个搪瓷碗里只有小半条猫鱼，上面漂着一丁点儿野菜。他笑着说：“吃吧，就是少了点儿。唉！一条好大的鱼已经上了钩，又跑啦！” 我端起搪瓷碗，觉得这个碗有千斤重，怎么也送不到嘴边。两个小同志不知道为什么，也端着碗不往嘴边送。老班长看到这情况，收敛了笑容，眉头拧成了疙瘩。他说：“怎么了，吃不下？要是不吃，咱们就走不出这草地。同志们，为了革命，你们必须吃下去。小梁，你不要太脆弱！”最后这句话是严厉的，意思只有我知道。","我把碗端到嘴边，泪珠大颗大颗地落在热气腾腾的鱼汤里。我悄悄背转身，擦擦眼睛，大口大口地咽着鱼汤。老班长看着我们吃完，脸上的皱纹舒展开了，嘴边露出了一丝笑意。可是我的心里好 像塞了铅块似的，沉重极了。","挨了一天又一天，渐渐接近草地的边了，我们的病却越来越重。我还能勉强挺着走路，那两个小同志连直起腰来的力气也没有了。老班长虽然瘦得只剩皮包骨头，眼睛深深地陷了下去，但是还一直用饱满的情绪鼓励着我们。我们就这样扶一段，搀一段，终于走到了草地边上。远处，重重叠叠的山峰已经看得见了。","这天上午，老班长快活地说：“同志们，咱们在这儿停一下，好好弄点儿吃的，鼓一鼓劲，一口气走出草地去。”说罢，他就拿起鱼钩找水塘去了。","我们的精神特别好，四处去找野菜，拾干草，好像过节似的。但是过了好久，还不见老班长回来。我们四面寻找，最后在一个水塘旁边找到了他，他已经昏迷不醒了。","我们都慌了。过雪山的时候有过不少这样的例子，战士用惊人的毅力支持着自己的生命，但是一倒下去就再也起不来了。要挽救老班长，最好的办法是让他赶快吃些东西。","我们立即分了工，我去钓鱼，剩下的一个人照料老班长，一个人生火。 我蹲在水边，心里不停地念叨：“鱼啊！快些来吧！这是挽救一个革命战士的生命啊！”可是，等了好久，还不见鱼上钩。好容易看到漂在水面的芦秆动了一下，赶紧扯起钓竿，还是空的…… 当我俯下身子，把鱼汤送到老班长嘴边的时候，老班长已经奄奄一息了。他微微地睁开眼睛，看见我端着的鱼汤，头一句话就说：“小梁，别浪费东西了。我……我不行啦。你们吃吧！还有二十多里路，吃完了，一定要走出去！” “老班长，你吃啊！我们抬也要把你抬出去！”我几乎要哭出来了。","“不，你们吃吧。你们一定要走出草地去！见着指导员，告诉他，我没完成党交给我的任务，没把你们照顾好。看，你们都瘦得……”","老班长用粗糙的手无力地抚摸我的头。突然间，他的手垂了下去。 “老班长！老班长！”我们失声叫着。但老班长还是慢慢地闭上了眼睛。","我们扑在老班长身上，抽噎着，很久很久。 擦干了眼泪，我把老班长留下的鱼钩小心地包起来，放在贴身的衣兜里。我想，等革命胜利以后，一定要把它送到革命烈士纪念馆去，让我们的子子孙孙都来瞻仰它。在这个长满了红锈的鱼钩上，闪烁着灿烂的金色的光芒！"]},{"id":419,"grade":"六年级上册","title":"语文园地","paragraphs":["作者：[唐代] 贺知章","少小离家老大回，","乡音无改鬓毛衰。","儿童相见不相识，","笑问客从何处来。","年少时离乡老年才归家，我的乡音虽未改变，但鬓角的毛发却已经疏落。","家乡的儿童们看见我，没有一个认识我。他们笑着询问我：你是从哪里来的呀？","贺知章(659—744)，字季真，号四明狂客，汉族，唐越州（今绍兴）永兴(今浙江萧山)人，贺知章诗文以绝句见长，除祭神乐章、应制诗外，其写景、抒怀之作风格独特，清新潇洒，著名的《咏柳》、《回乡偶书》两首脍炙人口，千古传诵，今尚存录入《全唐诗》共19首。","张飞睁圆环眼，隐隐见后军青罗伞盖、旄钺旌旗来到，料得是曹操心疑，亲自来看。飞乃厉声大喝曰：“我乃燕人张翼德也！谁敢与我决一死战？”声如巨雷。曹军闻之，尽皆股栗。","桑娜脸色苍白，神情激动。她忐忑不安地想：“他会说什么呢？这是闹着玩的吗？自己的五个孩子已经够他受的了……是他来啦？……不，还没来！……为什么把他们抱过来啊？他会揍我的！那也活该,我自作自受……嗯，揍我一顿也好！”","我的心紧缩着，我担心这个年轻的战士会实在忍耐不住突然跳起来，或者突然叫出声来。我几次回过头来，不敢朝他那儿看，不忍看着我的战友被活活烧死，但是我又忍不住不看。我心里像刀绞一般，眼泪模糊了我的眼睛。"]},{"id":420,"grade":"六年级上册","title":"快乐读书吧","paragraphs":["我们从出生起，就踏上了成长之旅。很多作家的作品讲述了成长的故事，这些故事的主人公有的是和我们同龄的孩子。他们的生活，有欢笑和喜悦，也有磨难和痛苦。这些或甜或苦的经历，教他们一步步向前，勇敢地面对未来。","相信你可以读更多成长的故事各不相同，却同样带给我们感动。","我们知道小英雄雨来的故事，雨来为掩护交通员被鬼子抓住后机智逃脱了。《小英雄雨来》这本书还写了雨来给八路军送鸡毛信，和小伙伴们制造假地雷迷惑敌人、为八路军站岗放哨……在抗日战争中，雨来不断成长，完成了多项重要任务，最终如愿参加了游击队。","《爱的教育》是意大利作家亚米契斯的日记体小说，原名《心》。作者在序言中说：“这部书是特地奉献给九岁到十三岁的小学生的。”书中以小学生的口吻，讲述了一个四年级小男孩的成长故事。故事中的人物主要是学生、老师以及学生父母等平凡的人。小说写出了他们对祖国和人民、父母和兄弟姐妹、老师和同学深厚而真挚的爱。","精彩的成长故事还有很多，让我们找来读一读，和同学交流你的收获。","《童年》是苏联作家高尔基的小说。故事的主人公阿廖沙三岁丧父后，随母亲投奔外祖父。外祖父粗野自私，经常毒打孩子们，曾把阿廖沙打得失去知觉。除了脾气暴躁的外祖父，这个家庭里还有两个为争夺财产整日争吵、打架的舅舅。阿廖沙经常惊惧不安，还好有慈祥善良的外祖母安慰他、保护他。","《童年》以孩子的视角来讲述故事，给这个充满伤痛的故事蒙上了一层天真烂漫的色彩。","那时我病得很重，刚能勉强起身。我清楚地记得，我病着的时候，开始是父亲开开心心地照顾着我，后来他突然不见了，照顾我的人换成了外祖母，一个很奇怪的人。","“你从哪儿过来啊？”我问她。","她回答：“从上面来，从下城来，不是过来，是坐船来！人怎么能自己从水上过来呢，真是个小迷糊！”","这真可笑，又是上又是下的，让人糊涂。上面，楼上住的是几个染了大胡子的波斯人，而地下室住了一个卖羊皮的黄皮肤卡尔梅克老头。下楼梯可以从扶手上滑下去，要是摔倒的话就滚下去，这我一清二楚。可是这关水什么事？简直都乱套了。","“我怎么就迷糊呢？”","“因为你吵得人迷糊啊。”她说完也笑了起来。","——选自高尔基的《童年》，黄枚译","外祖母的爱，仿佛黑暗中的明灯，照亮了阿廖沙的心。除了外祖母，善良、乐观、富于同情心的“小茨冈”，忠厚老实的老工人格里高利，献身于科学的知识分子“好事儿”，以及阿廖沙遇到的其他许许多多好人，都让他感受到了人世间的温暖和美好，让他面对苦难依然保持对生活的勇气和信心。","很多小说中人物众多，理清人物关系能够帮助我们更好地读懂故事。如,《童年》中出现了数十个人物，不容易分清楚，但他们都是围绕着主人公阿廖沙塑造的，弄明白他们和阿廖沙之间的关系，就不难分清了。","小说生动的故事情节会给我们留下较深的印象，这些情节让我们记住了一个个性格各异的人物。"]},{"id":421,"grade":"六年级上册","title":"16 夏天里的成长","paragraphs":["夏天是万物迅速生长的季节。","生物从小到大，本来是天天长的，不过夏天的长是飞快的长，跳跃的长，活生生的看得见的长。你在棚架上看瓜藤，一天可以长出几寸；你到竹子林、高粱地里听声音，在叭叭的声响里，一夜可以多出半节。昨天是苞蕾，今天是鲜花，明天就变成了小果实。一块白石头，几天不见，就长满了苔藓；一片黄泥土，几天不见，就变成了草坪菜畦。邻家的小猫小狗小鸡小鸭，个把月不过来，再见面，它已经有了妈妈的一半大。","草长，树木长，山是一天一天地变丰满。稻秧长，甘蔗长，地是一天一天地高起来。水长，瀑布长，河也是一天一天地变宽变深。俗话说：“不热不长，不热不大。”随着太阳威力的增加，温度的增加，什么都在生长。最热的时候，连铁路的铁轨也长，把连接处的缝隙几乎填满。柏油路也软绵绵的，像是高起来。","一过夏天，小学生有的成了中学生，中学生有的成了大学生。升级、跳班，快点儿，慢点儿，总是要长。北方农家的谚语说：“六月六，看谷秀。”又说：“处暑不出头，割谷喂老牛。”农作物到了该长的时候不长，或是长得太慢，就没有收成的希望。人也是一样，要赶时候，赶热天，尽量地用力地长。"]},{"id":422,"grade":"六年级上册","title":"17 盼","paragraphs":["有一天，妈妈下班回来，递给我一个扁扁的纸盒子。我打开一看，是一件淡绿色的、透明的新雨衣。我立刻就抖开雨衣往身上穿。怎么？雨衣上竟然还长着两只袖筒，不像那种斗篷式的：手在雨衣里缩着，什么也干不了。穿上这件情况就不同了，管你下雨不下雨，想干什么就干什么。","我一边想，一边在屋里走来走去，戴上雨帽，又抖抖袖子，把雨衣弄得窸窸窣窣响。直到妈妈一声喊：“蕾蕾，你疯啦？嫌身上没长痱子吗？”我才赶忙把雨衣脱下来。摸摸后背，衬衫已经让汗水浸湿了，浑身凉冰冰的。","我开始盼着变天。可是一连好多天，白天天上都是瓦蓝瓦蓝的，夜晚又变成满天星斗。我的雨衣一直安安静静地躺在盒子里，盒子一直安安静静地躺在衣柜里。每天放学路上我都在想：太阳把天烤得这样干，还能长云彩吗？为什么我一有了雨衣，天气预报就总是“晴”呢？","有一天，快到家时，路边的小杨树忽然沙啦啦地喧闹起来，就像在嘻嘻地笑。还用问，这是起了风。一会儿，几朵厚墩墩的云彩飘游过来，把太阳也给遮盖住了。天一下子变了脸色。路上行人都加快了走路的速度，我却放慢了脚步，心想，雨点儿打在头上，才是世界上最美的事呢！果然，随着几声闷雷，头顶上真的落上了几个雨点儿。我又伸手试了试周围，手心里也落上了两三个雨点儿。我兴奋地仰起头，甩打着书包就大步跑进了楼门。","“妈妈！”我嚷着奔进厨房。","“蕾蕾回来得正好，快把头发擦擦，准备听英语讲座！”","“可是……还差半小时啊。”我嘟囔着，心想，你怎么就不向窗外看一眼呢？","“那就休息一下。”妈妈说完，只听吱的一声响，原来她正往热油锅里放蒜薹呢。","“我今天特别特别不累。妈妈，我给你买酱油去吧，啊？”我央求着。","“你看，酱油我下班带回来了。”妈妈冲我笑了笑，好像猜着了我的心思。","“可是……不是还要炖肉吗？炖肉得放好多好多酱油呢。”我一边说，一边用眼瞟着窗外，生怕雨停了。","“我什么时候说过要炖肉？”妈妈焖上米饭，转过身来看了我两眼。","“你没说，爸爸可说过。”这话一出口，我就脸红了。因为我没见爸爸，也没人告诉我要炖什么肉。","“真的吗？”妈妈问。","我不再说话，也不敢再去看妈妈，急忙背过身子盯住碗架，上边的瓶瓶罐罐确实满满当当，看来不会有出去买东西的希望了。再看看屋里的闹钟，六点二十，我只好打开电视，不声不响地听英语讲座。","吃过晚饭，雨还在不停地下着，嗒嗒嗒地打着玻璃窗，好像是敲着鼓点逗引我出去。我跑到窗前，不住地朝街上张望着。望着望着又担心起来：要是今天雨都下完了，那明天还有雨可下吗？最好还是留到明天吧。","说来也怪，雨果真像我希望的那样停了。四周一下子变得那样安静。我推开窗子，凉爽的空气扑了过来，还带点儿腥味。路灯照着大雨冲刷过的马路，马路上像铺了一层明晃晃的玻璃；路灯照着路旁的小杨树，小杨树上像挂满了珍珠玛瑙。可雨点儿要是淋在淡绿色的雨衣上呢，那一定比珍珠玛瑙还好看。我扑到自己的床上，一心想着明天雨点儿打在雨衣上的事。","第二天早晨一睁眼，四周还是静悄悄的。我决心不再想什么雨不雨的。谁知等我背着书包走到街上，脑门又落上了几滴水珠。我还以为是树上掉下来的，直到我仰着头躲开树，甜丝丝的雨点儿又滴到我嘴唇上时，我的心才又像要从嗓子里蹦出来一样。我几步跑回家，理直气壮地打开柜门，拿出雨衣冲妈妈说：","“妈妈，下呢，还在下呢！”","妈妈一歪头冲我笑了笑，帮我系好扣，戴上帽子。我挺着脖子，小心翼翼地跑下了楼梯。","我走在街上，甩着两只透明的绿袖子，觉得好像雨点儿都特别爱往我的雨衣上落。它们在我的头顶和肩膀上起劲儿地跳跃：滴答，滴答滴答……"]},{"id":423,"grade":"六年级上册","title":"习作例文","paragraphs":["我爸爸是一个工厂的计划科科长，擅长订计划。在家里，他也给我们订了计划。妈妈有学习电子技术的计划，外婆有学习烹调的计划，我有作息计划、复习功课计划，他自己有读书计划、读报计划、做家务计划，每个人还有如何订计划的计划、如何督促各人执行计划的计划……","爸爸执行计划一丝不苟。比如他的家务计划规定，每天定时开关气窗，他就照章办事，到了关气窗的时间，哪怕外面打雷下雨，雨水打湿了窗帘，打湿了写字台上他正在拟订的计划，他也是先关气窗后关门窗；又如按照他的计划，全家人九点休息，时钟敲过九下，爸爸便大声宣布：“今天各项计划都已胜利完成，最后一项计划开始——睡觉！”","在爸爸的计划之下，我能有自己的计划吗？","晚上，爸爸的钥匙响过一连串的“交响乐”后，他便对我说：“烽烽，你要放暑假了，我们订一个暑假计划吧！”","一到订计划的时候，爸爸便眉飞色舞。“七时起床，八时做语文作业，九时读外语，十时……”他每写上一条，我就像多上一道线的陀螺，被搞得晕头转向。","望着那长长的计划，我试探地问：“爸爸，这计划中是不是加一条游泳啊什么的……”","“什么？”爸爸仿佛不认识我似的瞪了我好一会儿，“我订的计划是最最全面的。你看，午睡、吃饭、休息，什么都有了。”于是爸爸又订了一个如何执行计划的计划：作业由他亲自检查，午睡、吃饭由外婆监督。","这是一个铁路线上的小站，只有慢车才停靠两三分钟。","快车转瞬间疾驰而过，旅客们甚至连站名还来不及看清楚。","就在这转瞬间，你也许看到一间红瓦灰墙的小屋，月台上几根漆成淡蓝色的木栅栏，或者还有三五个人影。而这一切又立即消失了，火车两旁依然是逼人而来的山崖和巨石。","这是一个在北方山区常见的小站。月台左面有一张红榜，上面用大字标明了二百四十一天安全无事故的记录，贴着竞赛优胜者的照片。红榜旁边是一块小黑板，上面用白粉笔写着当天的天气预报和早晨的报纸摘要。出站口的旁边贴着一张讲卫生的宣传画。月台上，有两三个挑着箩筐的农民，正准备上车进城。几步以外，站上的两位工作人员正在商量着什么。","月台中间有一个小小的喷水池，显然是经过精心设计的。喷水池中间堆起一座小小的假山，假山上栽着一棵尺把高的小树。喷泉从小树下面的石孔喷出来，水珠四射，把假山上的小宝塔洗得一尘不染。","月台的两头种了几株杏树，花开得正艳，引来一群蜜蜂。蜜蜂嗡嗡地边歌边舞，点缀着这个宁静的小站。","小站上没有钟，也没有电铃。站长吹一长声哨子，刚到站的火车跟着长啸一声，缓缓地离开小站，继续自己的征途。","这个小站坐落在山坳里。站在月台上向四周望去，只看到光禿禿的石头山，没有什么秀丽的景色。可是就在这儿，就在这个小站上，却出现了一股活泼的喷泉，几树灿烂的杏花。","这喷泉，这杏花，给旅客们带来了温暖的春意。"]},{"id":424,"grade":"六年级上册","title":"浪淘沙","paragraphs":["作者：[唐代] 刘禹锡","九曲黄河万里沙，","浪淘风簸自天涯。","如今直上银河去，","同到牵牛织女家。","弯弯曲曲的黄河，挟带着泥沙，浪涛汹涌，奔腾万里，从遥远的天边滚滚而来。","如今好像要直飞上高空的银河，请带上我一起去寻访牛郎织女的家。","刘禹锡（772年~842年），字梦得，籍贯河南洛阳，生于河南郑州荥阳，自述“家本荥上，籍占洛阳” ，自称是汉中山靖王后裔。唐朝时期大臣、文学家、哲学家，有“诗豪”之称。他的家庭是一个世代以儒学相传的书香门第。政治上主张革新，是王叔文派政治革新活动的中心人物之一。后来永贞革新失败被贬为朗州司马（今湖南常德）。据湖南常德历史学家、收藏家周新国先生考证刘禹锡被贬为朗州司马其间写了著名的“汉寿城春望”。"]},{"id":425,"grade":"六年级上册","title":"江南春","paragraphs":["作者：[唐代] 杜牧","千里莺啼绿映红，","水村山郭酒旗风。","南朝四百八十寺，","多少楼台烟雨中。","辽阔的江南，到处莺歌燕舞，绿树红花相映，水边村寨山麓城郭处处酒旗飘动。","南朝遗留下的许多座古寺， 如今有多少笼罩在这朦胧烟雨之中。","杜牧（公元803－约852年），字牧之，号樊川居士，汉族，京兆万年（今陕西西安）人，唐代诗人。杜牧人称“小杜”，以别于杜甫。与李商隐并称“小李杜”。因晚年居长安南樊川别墅，故后世称“杜樊川”，著有《樊川文集》。"]},{"id":426,"grade":"六年级上册","title":"书湖阴先生壁","paragraphs":["作者：[宋代] 王安石","茅檐长扫净无苔，","花木成畦手自栽。","一水护田将绿绕，","两山排闼送青来。","茅舍庭院由于经常打扫，洁净得没有一丝青苔，花木规整成行成垄都是主人亲自栽种的。","庭院外一条小河环绕着大片碧绿的禾苗，两座山峰仿佛要推开门，给主人送上满山的青翠。","王安石（1021年12月18日－1086年5月21日），字介甫，号半山，谥文，封荆国公。世人又称王荆公。汉族，北宋抚州临川人（今江西省抚州市临川区邓家巷人），中国北宋著名政治家、思想家、文学家、改革家，唐宋八大家之一。欧阳修称赞王安石：“翰林风月三千首，吏部文章二百年。老去自怜心尚在，后来谁与子争先。”传世文集有《王临川集》、《临川集拾遗》等。其诗文各体兼擅，词虽不多，但亦擅长，且有名作《桂枝香》等。而王荆公最得世人共传之诗句莫过于《泊船瓜洲》中的“春风又绿江南岸，明月何时照我还。”"]},{"id":427,"grade":"六年级上册","title":"19 只有一个地球","paragraphs":["据有幸飞上太空的宇航员介绍，他们在天际遨游时遥望地球，映入眼帘的是一个晶莹的球体，上面蓝色和白色的纹痕相互交错，周围裹着一层薄薄的水蓝色“纱衣”。地球，这位人类的母亲，这个生命的摇篮，是那样的美丽壮观，和蔼可亲。","但是，在群星璀璨的宇宙中，地球是一个半径约为6400千米的星球。同茫茫宇宙相比，地球是渺小的。它只有这么大，不会再长大。","地球所拥有的自然资源也是有限的。拿矿产资源来说，它不是谁的恩赐，而是经过几百万年，甚至几亿年的地质变化才形成的。地球是无私的，它向人类慷慨地提供矿产资源。但是，如果不加节制地开采，必将加速地球上矿产资源的枯竭。","人类生活所需要的水资源、土地资源、生物资源等，本来是可以不断再生，长期给人类作贡献的。但是，因为人们随意毁坏自然资源，不顾后果地滥用化学品，不但使它们不能再生，还造成了一系列生态灾难，给人类生存带来了严重的威胁。","有人会说，宇宙空间不是大得很吗，那里有数不清的星球，在地球资源枯竭的时候，我们不能移居到别的星球上去吗？","科学家已经证明，至少在以地球为中心的40万亿千米的范围内，没有适合人类居住的第二个星球。人类不能指望地球被破坏以后再移居到别的星球上去。","不错，科学家们提出了许多设想，例如，在火星或者月球上建造移民基地。但是，即使这些设想能实现，也是遥远的事情。再说，又有多少人能够去居住呢？","“我们这个地球太可爱了，同时又太容易破碎了！”这是宇航员遨游太空目睹地球时发出的感叹。","只有一个地球，如果它被破坏了，我们别无去处。如果地球上的各种资源都枯竭了，我们很难从别的地方得到补充。我们要精心地保护地球，保护地球的生态环境。让地球更好地造福于我们的子孙后代吧！"]},{"id":428,"grade":"六年级上册","title":"20* 青山不老","paragraphs":["窗外是参天的杨柳。院子在山沟里，山上全是树。我们盘腿坐在土炕上，就像坐在船上，四周全是绿色的波浪，风一吹，树梢卷过涛声，叶间闪着粼粼的波光。","我知道这条山沟所处的大环境。这是中国的晋西北，是西伯利亚大风常来肆虐的地方，是干旱、霜冻、沙尘暴等与生命作对的怪物盘踞之地。过去，这里风吹沙起，能一直埋到城头。当地县志记载：“风大作时，能逆吹牛马使倒行，或擎之高二三丈而坠。”就在如此险恶的地方，我对面这个手端一杆旱烟袋的瘦小老头，竟创造了这块绿洲。","我还知道这个院子里的小环境。一排三间房，就剩下老者一人。老人每天早晨抓把柴煮饭，带上干粮扛上铁锹进沟上山；晚上回来，吃过饭，抽袋烟睡觉。六十五岁那年，他组织了七位老汉开始治理这条沟，现在已有五人离世。他可敬的老伴，与他风雨同舟一生；一天他栽树回来时，发现她已静静地躺在炕上过世了。他已经八十一岁，知道终有一天自己也会爬不起来。他唯一的女儿三番五次地从城里回来，要接他去享清福，他不走。他觉得种树是命运的选择，屋后的青山就是生命的归宿。","他敲着旱烟锅不紧不慢地说着，村干部在旁边恭敬地补充着……十五年啊，绿化了八条沟，造了七条防风林带，三千七百亩林网，这是多么了不起的奇迹。去年冬天，他用林业收入资助每户村民买了一台电视机——他还有宏伟设想，还要栽树，直到自己爬不起来为止。","在屋里说完话，老人陪我们到沟里去看树。杨树、柳树，如臂如股，劲挺在山洼、山腰。看不见它们的根，山洪涌下的泥埋住了树的下半截，树却勇敢地顶住了山洪的凶猛。这山已失去了原来的坡形，依着一层层的树形成一层层的梯。老人说：“这树下的淤泥有两米厚，都是好土啊。”是的，保住了这黄土，我们才有这绿树；有了这绿树，我们才守住了这片土。","看完树，我们在村口道别。老人拄着拐杖，慢慢迈进他那个绿风荡漾的小院。我不禁鼻子一酸——也许老人进去后就再也出不来了。作为一个山野老农，他就这样来实现自己的价值。他已经将自己的生命转化为另一种东西。他是真正与山川共存、与日月同辉了。","这位普通老人让我领悟到：青山是不会老的。"]},{"id":429,"grade":"六年级上册","title":"21* 三黑和土地","paragraphs":["农民一有了土地，","就把整个生命投入了土地。","活像旱天的鹅，","一见了水就连头带尾巴钻进水里。","恨不得把每一块土，","都送到舌头上，","是咸是甜，","自己先来尝一尝。","恨不得自己变成一粒种子，","躺在土里试一试，","看温暖不温暖，","合适不合适。","三黑就是这样的翻着土地。","从东到西，从南到北，","每一寸土都给翻起，","每一块土疙瘩都给细细打碎。","地翻好，又耙了几遍，","耙得又平又顺溜，","看起来","好像妇女们刚梳的头。","这么松散的地，","简直是一张软床，","叫人想在上面打滚，","想在上面躺一躺。","三黑","从来没睡过这么好的床，","今天准备好了，","叫麦籽儿睡上。","这么好的床，","麦籽儿躺下去挺舒服，","就想发芽，","赶紧钻出来吸些雨露。","三黑耙过地，","坐下来歇一歇。","看见自己种的荞麦已经开花，","白霎霎的像一片雪。","荞麦地里","还有两个蝈蝈儿在叫唤，","吱吱吱……","叫得人心里痒抓抓的好喜欢。","小时候因为逮蝈蝈儿，","常常挨骂，","爹娘骂：不好好拾柴火。","地主骂：蹚坏了他的庄稼。","现在","蝈蝈儿就在自己地里叫，","他想招呼从地头路过的那个孩子：","“快去逮吧，你听，叫得多好！”","他又在打算：","明年要跟人合伙，","把地浇得肥肥的，","让庄稼长得更好，收得更多。","再买头小毛驴，","打完场赶着送公粮；","驮着老伴儿","看闺女，上东庄。","三黑一边耙地，一边想着：","翻身的人儿心里真甜。","他笑嘻嘻的，连嘴都合不上。","地里的蝈蝈儿也叫得更欢。"]},{"id":430,"grade":"六年级上册","title":"语文园地","paragraphs":["为了生活环境更舒适，人们在城市里种植了大量的花草树木。这些树木花草是城市的“绿色卫士”，守护着城市的环境。人们把它们比作“城市之肺”，是十分形象和贴切的。因为这些“绿色卫士”，不仅能吸收空气中的二氧化碳，调节城市空气，而且能降低灰尘污染——叶子表面的绒毛和黏液能吸附飘尘，阻止灰尘微粒蔓延。","五行：金、木、水、火、土","五谷：稻、麦、黍、菽、稷","五音：宫、商、角、徵、羽","五彩：黄、青、赤、白、黑"]},{"id":431,"grade":"六年级上册","title":"伯牙鼓琴","paragraphs":["伯牙鼓琴，锺子期听之。方鼓琴而志在太山，锺子期曰：“善哉乎鼓琴，巍巍乎若太山”。少选之间而志在流水，锺子期又曰：“善哉乎鼓琴，汤汤乎若流水。”锺子期死，伯牙破琴绝弦，终身不复鼓琴，以为世无足复为鼓琴者。","伯牙弹琴，锺子期听他弹琴。伯牙在弹琴时心里想着高山，锺子期说：“你弹得真好呀，像大山一样高峻。”不一会儿，伯牙心里又想到流水，锺子期又说：“你弹得真好呀，就像那奔腾不息的流水。”锺子期死了以后，伯牙摔琴断弦，终生不再弹琴，认为世上再没有值得他为之弹琴的人了。"]},{"id":432,"grade":"六年级上册","title":"书戴嵩画牛","paragraphs":["作者：[宋代] 苏轼","蜀中有杜处士，好书画，所宝以百数。有戴嵩《牛》一轴，尤所爱，锦囊玉轴，常以自随。","一日曝书画，有一牧童见之，拊掌大笑，曰：“此画斗牛也。牛斗，力在角，尾搐入两股间，今乃‘掉’尾而斗，谬矣。”处士笑而然之。古语有云：“耕当问奴，织当问婢。”不可改也。","蜀中有一位杜处士，喜好书画，珍藏的书画作品有数百件。其中有戴嵩画的《斗牛图》一幅，他特别喜爱，于是用锦缎作画套，又用玉装饰卷轴，并经常随身携带。","有一天，他晾晒书画，一个牧童看到了这幅画，拍手大笑，说道：“这画上画的是角斗的牛吗？牛在互相争斗时，力量用在角上，尾巴夹在两条后腿中间，但这幅画却画成牛摇着尾巴互相争斗，错了。”杜处士笑了笑，认为牧童的话是对的。古人说：“种田要问耕种的农民，织布要问织绢的婢女。”这个道理是不变的。","苏轼，（1037年1月8日-1101年8月24日）字子瞻、和仲，号铁冠道人、东坡居士，世称苏东坡、苏仙，汉族，眉州眉山（四川省眉山市）人，祖籍河北栾城，北宋著名文学家、书法家、画家，历史治水名人。苏轼是北宋中期文坛领袖，在诗、词、散文、书、画等方面取得很高成就。文纵横恣肆；诗题材广阔，清新豪健，善用夸张比喻，独具风格，与黄庭坚并称“苏黄”；词开豪放一派，与辛弃疾同是豪放派代表，并称“苏辛”；散文著述宏富，豪放自如，与欧阳修并称“欧苏”，为“唐宋八大家”之一。苏轼善书，“宋四家”之一；擅长文人画，尤擅墨竹、怪石、枯木等。与韩愈、柳宗元和欧阳修合称“千古文章四大家”。作品有《东坡七集》《东坡易传》《东坡乐府》《潇湘竹石图卷》《古木怪石图卷》等。"]},{"id":433,"grade":"六年级上册","title":"23 月光曲","paragraphs":["两百多年前，德国有个音乐家叫贝多芬，他谱写了许多著名的乐曲。其中有一首著名的钢琴曲叫《月光曲》，传说是这样谱成的。","有一年秋天，贝多芬去各地旅行演出，来到莱茵河边的一个小镇上。一天夜晚，他在幽静的小路上散步，听到断断续续的钢琴声从一所茅屋里传出来，弹的正是他的曲子。","贝多芬走近茅屋，琴声忽然停了，屋子里有人在谈话。一个姑娘说：“这首曲子多难弹哪！我只听别人弹过几遍，总是记不住该怎样弹，要是能听一听贝多芬自己是怎样弹的，那有多好哇！”一个男的说：“是呀，可是音乐会的入场券太贵了，咱们又太穷。”姑娘说：“哥哥，你别难过，我不过随便说说罢了。”","贝多芬听到这里，推开门，轻轻地走了进去。茅屋里点着一支蜡烛。在微弱的烛光下，男的正在做皮鞋。窗前有架旧钢琴，前面坐着一个十六七岁的姑娘，脸很清秀，可是眼睛失明了。","皮鞋匠看见进来个陌生人，站起来问：“先生，您找谁？走错门了吧？”贝多芬说：“不，我是来弹一首曲子给这位姑娘听的。”","姑娘连忙站起来让座。贝多芬坐在钢琴前面，弹起盲姑娘刚才弹的那首曲子。盲姑娘听得入了神，一曲弹完，她激动地说：“弹得多纯熟哇！感情多深哪！您，您就是贝多芬先生吧？”","贝多芬没有回答，他问盲姑娘：“您爱听吗？我再给您弹一首吧。”","一阵风把蜡烛吹灭了。月光照进窗子，茅屋里的一切好像披上了银纱，显得格外清幽。贝多芬望了望站在他身旁的兄妹俩，借着清幽的月光，按起了琴键。","皮鞋匠静静地听着。他好像面对着大海，月亮正从水天相接的地方升起来。微波粼粼的海面上，霎时间洒满了银光。月亮越升越高，穿过一缕一缕轻纱似的微云。忽然，海面上刮起了大风，卷起了巨浪。被月光照得雪亮的浪花，一个连一个朝着岸边涌过来……皮鞋匠看看妹妹，月光正照在她那恬静的脸上，照着她睁得大大的眼睛。她仿佛也看到了，看到了她从来没有看到过的景象—月光照耀下的波涛汹涌的大海。","兄妹俩被美妙的琴声陶醉了。等他们醒过神来，贝多芬早已离开了茅屋。他飞奔回客店，花了一夜工夫，把刚才弹的曲子——《月光曲》记录了下来。"]},{"id":434,"grade":"六年级上册","title":"24* 京剧趣谈","paragraphs":["马鞭","中国古人时常要骑马。可骑马在舞台上没办法表现，舞台方圆太小，马匹是无法驰骋的。真马出现在舞台上，演员也怕它失去控制。京剧继承、发展了中国传统戏曲的表现手段，终于战胜了这种尴尬——用一根小小的马鞭就彻底解决了，而且解决得无比漂亮。这种表演方式十分符合中国的美学。巨大的马匹被整个省略，但骑马人那种特定和优美的姿态却鲜明地显现出来。同时这一根虚拟的马鞭，给演员以无穷无尽的表演自由：可以高扬，可以低垂；可以跑半天还在家门口，可以一抬手就走了一百里。马鞭本身具备一种装饰的美，而且不同人物在使用马鞭时，也各自形成了一套约定俗成的方法。","马鞭是实在的道具，是可感觉可使用的。京剧还有一些虚拟的道具，但一样可感觉可使用。比如《拾玉镯》中小姑娘纳鞋底，鞋底是实的，针线可是虚的，但在演员手里，“无”远远胜过了“有”。","再比如宴席上的酒壶酒杯。主人一声吩咐“酒宴摆下——”仆人立刻把酒壶酒杯端上舞台。主人和客人举杯喝酒，一杯又一杯，但就是不见吃饭吃菜，可客人也一样“饱”了。京剧一般是不把饭碗搬上舞台的，一旦真用，那就得“狠狠做戏”。比如《金玉奴》中有一个细节，小生演员用饭碗喝完豆汁，又用嘴去舔筷子，如果没有这一“舔”，那饭碗也就完全不必拿上舞台。","亮相","京剧还有一种奇特之处：双方正在对打，激烈到简直是风雨不透，台下看的人非常紧张，一个个大气儿不敢出，都把眼睛睁得大大的，唯恐在一眨眼间，谁就把对方给“杀”了。然而也怪，就在双方打得不可开交之际，那紧张而又整齐的锣鼓声忽然一停，人物的动作也戛然而止——双方脸对着脸，眼睛对着眼睛，兵器对着兵器，一切都像被某种定身术给制服了！小孩子和外宾忍不住要问：“如果他们当中哪个先‘醒’了，拿起兵器朝着对方一刺，对方不就‘完’了吗？”","问得有理，但这恰恰是京剧艺术的高妙之处。俗话说“一动不如一静”，古诗也说“此时无声胜有声”，讲的就是这种情况。静，越发能显示武艺的高强，越发能显示必胜的信心。","还有一种“刀(枪)下场”，可以视为动态的亮相。双方正在交战，一方被打败，跑下去了。可胜利一方不紧追，反而留在原地，抡圆了胳膊把手中的兵器(刀或枪)耍了个风雨不透。这，哪里还是戏剧？这，不是太像杂技了吗？您说得太对了，这就是京剧中的杂技成分，自古如此，如今还保留着。它的存在，就是为了突显人物的英雄气概。"]},{"id":435,"grade":"六年级上册","title":"语文园地","paragraphs":["高山流水 天籁之音","余音绕梁 黄钟大吕","轻歌曼舞 行云流水","巧夺天工 惟妙惟肖","画龙点睛 笔走龙蛇","妙笔生花 栩栩如生","亮相 行当 压轴 行头","跑龙套 唱白脸 花架子 对台戏","粉墨登场 字正腔圆 有板有眼 科班出身","玩具小台灯制作说明书","材料:","半个乒乓球，一个瓶盖，一段铅丝，一块橡皮泥。","做法:","1.在半个乒乓球中间钻个小洞，当灯罩。","2.在瓶盖中间钻个小洞，从洞中穿进铅丝，铅丝一端弯一点儿，钩住盖底。在靠近洞的盖面和盖底处用橡皮泥把铅丝粘牢。","3.把铅丝的另一端插入乒乓球的小洞里。把洞的两边粘牢。铅丝的头上用红橡皮泥做一个小灯泡。"]},{"id":436,"grade":"六年级上册","title":"25 少年闰土","paragraphs":["深蓝的天空中挂着一轮金黄的圆月，下面是海边的沙地，都种着一望无际的碧绿的西瓜，其间有一个十一二岁的少年，项带银圈，手捏一柄钢叉，向一匹猹尽力的刺去。那猹却将身一扭，反从他的胯下逃走了。","这少年便是闰土。我认识他时，也不过十多岁，离现在将有三十年了；那时我的父亲还在世，家景也好，我正是一个少爷。那一年，我家是一件大祭祀的值年。这祭祀，说是三十多年才能轮到一回，所以很郑重；正月里供祖像，供品很多，祭器很讲究，拜的人也很多，祭器也很要防偷去。我家只有一个忙月(我们这里给人做工的分三种：整年给一定人家做工的叫长年；按日给人做工的叫短工；自己也种地，只在过年过节以及收租时候来给一定的人家做工的称忙月)，忙不过来，他便对父亲说，可以叫他的儿子闰土来管祭器的。","我的父亲允许了；我也很高兴，因为我早听到闰土这名字，而且知道他和我仿佛年纪，闰月生的，五行缺土，所以他的父亲叫他闰土。他是能装弶捉小鸟雀的。","我于是日日盼望新年，新年到，闰土也就到了。好容易到了年末，有一日，母亲告诉我，闰土来了，我便飞跑的去看。他正在厨房里，紫色的圆脸，头戴一顶小毡帽，颈上套一个明晃晃的银项圈，这可见他的父亲十分爱他，怕他死去，所以在神佛面前许下愿心，用圈子将他套住了。他见人很怕羞，只是不怕我，没有旁人的时候，便和我说话，于是不到半日，我们便熟识了。","我们那时候不知道谈些什么，只记得闰土很高兴，说是上城之后，见了许多没有见过的东西。","第二日，我便要他捕鸟。他说：","“这不能。须大雪下了才好。我们沙地上，下了雪，我扫出一块空地来，用短棒支起一个大竹匾，撒下秕谷，看鸟雀来吃时，我远远地将缚在棒上的绳子只一拉，那鸟雀就罩在竹匾下了。什么都有：稻鸡，角鸡，鹁鸪，蓝背……”","我于是又很盼望下雪。","闰土又对我说：","“现在太冷，你夏天到我们这里来。我们日里到海边检贝壳去，红的绿的都有，鬼见怕也有，观音手也有。晚上我和爹管西瓜去，你也去。”","“管贼么？”","“不是。走路的人口渴了摘一个瓜吃，我们这里是不算偷的。要管的是獾猪，刺猬，猹。月亮地下，你听，啦啦的响了，猹在咬瓜了。你便捏了胡叉，轻轻地走去……”","我那时并不知道这所谓猹的是怎么一件东西——便是现在也没有知道——只是无端的觉得状如小狗而很凶猛。","“他不咬人吗？”","“有胡叉呢。走到了，看见猹了，你便刺。这畜生很伶俐，倒向你奔来，反从胯下窜了。他的皮毛是油一般的滑……”我素不知道天下有这许多新鲜事：海边有如许五色的贝壳；西瓜有这样危险的经历，我先前单知道他在水果店里出卖罢了。","“我们沙地里，潮汛要来的时候，就有许多跳鱼儿只是跳，都有青蛙似的两个脚……”","阿！闰土的心里有无穷无尽的希奇的事，都是我往常的朋友所不知道的。他们不知道一些事，闰土在海边时，他们都和我一样只看见院子里高墙上的四角的天空。","可惜正月过去了，闰土须回家里去，我急得大哭，他也躲到厨房里，哭着不肯出门，但终于被他父亲带走了。他后来还托他的父亲带给我一包贝壳和几支很好看的鸟毛，我也曾送他一两次东西，但从此没有再见面。"]},{"id":437,"grade":"六年级上册","title":"26 好的故事","paragraphs":["灯火渐渐地缩小了，在预告石油的已经不多；石油又不是老牌，早熏得灯罩很昏暗。鞭爆的繁响在四近，烟草的烟雾在身边：是昏沉的夜。","我闭了眼睛，向后一仰，靠在椅背上；捏着《初学记》的手搁在膝髁上。","我在蒙胧中，看见一个好的故事。","这故事很美丽，幽雅，有趣。许多美的人和美的事，错综起来像一天云锦，而且万颗奔星似的飞动着，同时又展开去，以至于无穷。","我仿佛记得曾坐小船经过山阴道，两岸边的乌桕，新禾，野花，鸡，狗，丛树和枯树，茅屋，塔，伽蓝，农夫和村妇，村女，晒着的衣裳，和尚，蓑笠，天，云，竹，……都倒影在澄碧的小河中，随着每一打桨，各各夹带了闪烁的日光，并水里的萍藻游鱼，一同荡漾。诸影诸物，无不解散，而且摇动，扩大，互相融和；刚一融和，却又退缩，复近于原形。边缘都参差如夏云头，镶着日光，发出水银色焰。凡是我所经过的河，都是如此。","现在我所见的故事也如此。水中的青天的底子，一切事物统在上面交错，织成一篇，永是生动，永是展开，我看不见这一篇的结束。","河边枯柳树下的几株瘦削的一丈红，该是村女种的罢。大红花和斑红花，都在水里面浮动，忽而碎散，拉长了，如缕缕的胭脂水，然而没有晕。茅屋，狗，塔，村女，云，……也都浮动着。大红花一朵朵全被拉长了，这时是泼剌奔迸的红锦带。带织入狗中，狗织入白云中，白云织入村女中……。在一瞬间，他们又将退缩了。但斑红花影也已碎散，伸长，就要织进塔，村女，狗，茅屋，云里去。","现在我所见的故事清楚起来了，美丽，幽雅，有趣，而且分明。青天上面，有无数美的人和美的事，我一一看见，一一知道。","我就要凝视他们……","我正要凝视他们时，骤然一惊，睁开眼，云锦也已皱蹙，凌乱，仿佛有谁掷一块大石下河水中，水波陡然起立，将整篇的影子撕成片片了。我无意识地赶忙捏住几乎坠地的《初学记》，眼前还剩着几点虹霓色的碎影。","我真爱这一篇好的故事，趁碎影还在，我要追回他，完成他，留下他。我抛了书，欠身伸手去取笔，——何尝有一丝碎影，只见昏暗的灯光，我不在小船里了。","但我总记得见过这一篇好的故事，在昏沉的夜……","一九二五年二月二十四日。"]},{"id":438,"grade":"六年级上册","title":"27* 我的伯父鲁迅先生","paragraphs":["伯父鲁迅先生在世的时候，我年纪还小，根本不知道鲁迅是谁，以为伯父就是伯父，跟任何人的伯父一样。伯父去世了，他的遗体躺在万国殡仪馆的礼堂里，许多人都来追悼他，向他致敬，有的甚至失声痛哭。数不清的挽联挂满了墙壁，大大小小的花圈堆满了整间屋子。送挽联送花圈的有工人，有学生，各色各样的人都有。那时候我有点儿惊异了，为什么伯父得到这么多人的爱戴？我呆呆地望着来来往往吊唁的人，想到我永远见不到伯父的面了，听不到他的声音了，也得不到他的爱抚了，泪珠就一滴一滴地掉下来。","就在伯父去世那一年的正月里，一个星期六的下午，爸爸妈妈带我到伯父家里去。那时候每到周末，我们姐妹三个轮流跟随着爸爸妈妈到伯父家去团聚。这一天在晚餐桌上，伯父跟我谈起《水浒传》里的故事和人物。不知道伯父怎么会知道我读了《水浒传》，大概是爸爸告诉他的吧。老实说，我读《水浒传》不过囫囵吞枣地看一遍，只注意紧张动人的情节；那些好汉的个性，那些复杂的内容，全搞不清楚，有时候还把这个人做的事情安在那个人身上。伯父问我的时候，我就张冠李戴地乱说一气。伯父摸着胡子，笑了笑，说：“哈哈！还是我的记性好。”听了伯父这句话，我又羞愧，又悔恨，比挨打挨骂还难受。从此，我读什么书都不再马马虎虎了。","那天临走的时候，伯父送我两本书，一本是《表》，一本是《小约翰》。伯父已经去世多年了，这两本书我还保存着。","有一次，在伯父家里，大伙儿围着一张桌子吃晚饭。我望望爸爸的鼻子，又望望伯父的鼻子，对他说：“大伯，您跟爸爸哪儿都像，就是有一点不像”。","“哪一点不像呢？”伯父转过头来，微笑着问我。他嚼着东西，嘴唇上的胡子跟着一动一动的。","“爸爸的鼻子又高又直，您的呢，又扁又平。”我望了他们半天才说。","“你不知道，”伯父摸了摸自己的鼻子，笑着说，“我小的时候，鼻子跟你爸爸的一样，也是又高又直的。”","“那怎么——”","“可是到了后来，碰了几次壁，把鼻子碰扁了。”","“碰壁？”我说，“您怎么会碰壁呢？是不是您走路不小心？”","“你想，四周黑洞洞的，还不容易碰壁吗？”","“哦！”我恍然大悟，“墙壁当然比鼻子硬得多了，怪不得您把鼻子碰扁了。”","在座的人都哈哈大笑起来。","有一年的除夕，我们全家都到伯父家里去了。伯父买了许多爆竹和花筒给我们。我们都胆小得很，没有一个人敢放，伯父和爸爸就替我们放。他们每人捧了一大堆，走到天井里去。我们掩着耳朵，躲在玻璃门后面，睁大了眼睛望着他们。四扇玻璃门，我们三个和海婴一人占一扇。伯母和妈妈站在我们旁边。","爸爸放的是爆竹，声音真大，可怕极了，虽然关紧了门，掩住了耳朵，也照样听得见。我们紧张极了，气都不敢透一口。","爸爸放完爆竹，轮到伯父放花筒了。火花在我们眼前飞舞，艳丽的色彩映照在伯父的脸上。我突然注意到他脸上的表情，那么慈祥，那么愉快，眉毛，眼睛，还有额上一条条的皱纹，都现出他心底的欢笑来。那时候，他的脸上充满了自然而和谐的美，是我从来没看见过的。","有一天黄昏，呼呼的北风怒号着，天色十分阴暗。街上的人都匆匆忙忙赶着回家。爸爸妈妈拉着我的手，到伯父家去。走到离伯父家门口不远的地方，看见一个拉黄包车的坐在地上呻吟，车子扔在一边。","我们走过去，看见他两只手捧着脚，脚上没穿鞋，地上淌了一摊血。他听见脚步声，抬起头来，饱经风霜的脸上现出难以忍受的痛苦。","“怎么了？”爸爸问他。","“先生，”他那灰白的抽动着的嘴唇里发出低微的声音，“没留心，踩在碎玻璃上，玻璃片插进脚底了。疼得厉害，回不了家啦！”","爸爸跑到伯父家里，不一会儿，就跟伯父拿了药和纱布出来。他们把那个拉车的扶上车子，一个蹲着，一个半跪着，爸爸拿镊子夹出碎玻璃片，伯父拿硼酸水给他洗干净。他们又给他敷上药，扎好绷带。","拉车的感激地说：“我家离这儿不远，这就可以支持着回去了。两位好心的先生，我真不知道怎么谢你们！”","伯父又掏出一些钱来给他，叫他在家里休养几天，把剩下的药和绷带也给了他。","天黑了，路灯发出微弱的光。我站在伯父家门口看着他们，突然感到深深的寒意，摸摸自己的鼻尖，冷得像冰，脚和手也有些麻木了。我想，这么冷的天，那个拉车的怎么能光着脚拉着车在路上跑呢？","伯父和爸爸回来的时候，我就问他们。伯父的回答我现在记不清了，只记得他的话很深奥，不容易懂。我抬起头来，要求他给我详细地解说。这时候，我清清楚楚地看见，而且现在也清清楚楚地记得，他的脸上不再有那种慈祥的愉快的表情了，他变得那么严肃。他没有回答我，只把枯瘦的手按在我的头上，半天没动，最后深深地叹了一口气。","伯父逝世以后，我见到他家的女佣阿三。阿三是个工人的妻子，她丈夫失了业，她愁得两只眼睛起了蒙，看东西不清楚，模模糊糊的像隔着雾。她跟我谈起伯父生前的事情。她说：“周先生自己病得那么厉害，还三更半夜地写文章。有时候我听着他一阵阵接连不断地咳嗽，真替他难受。他对自己的病一点儿也不在乎，倒常常劝我多休息，不叫我干重活儿。”","的确，伯父就是这样的一个人，他为自己想得少，为别人想得多。"]},{"id":439,"grade":"六年级上册","title":"28 有的人——纪念鲁迅有感","paragraphs":["有的人活着，","他已经死了；","有的人死了，","他还活着。","有的人","骑在人民头上：“啊，我多伟大！”","有的人","俯下身子给人民当牛马。","有的人","把名字刻入石头，想“不朽”；","有的人","情愿作野草，等着地下的火烧。","有的人","他活着别人就不能活；","有的人","他活着为了多数人更好地活。","骑在人民头上的","人民把他摔垮；","给人民作牛马的","人民永远记住他！","把名字刻入石头的","名字比尸首烂得更早；","只要春风吹到的地方","到处是青青的野草。","他活着别人就不能活的人，","他的下场可以看到；","他活着为了多数人更好地活的人，","群众把他抬举得很高，很高。"]},{"id":440,"grade":"六年级上册","title":"语文园地","paragraphs":["无情未必真豪杰，怜子如何不丈夫。——鲁迅《答客诮》","其实地上本没有路，走的人多了，也便成了路。——鲁迅《故乡》","惟有民魂是值得宝贵的，惟有他发扬起来，中国才有真进步。——鲁迅《学界的三魂》","我们从古以来，就有埋头苦干的人，有拼命硬干的人，有为民请命的人，有舍身求法的人……这就是中国的脊梁。——鲁迅《中国人失掉自信力了吗》","少年闰土  狼牙山五壮士  军神","开国大典  “诺曼底号”遇难记","草船借箭  竹节人  桥  芦花鞋","在牛肚子里旅行","“精彩极了”和“糟糕透了”","慢性子裁缝和急性子顾客","饱经风霜的脸 饱经风霜的老屋","饱经风霜的大树","树林的深处 秋天的深处 心灵的深处"]},{"id":441,"grade":"六年级下册","title":"1 北京的春节","paragraphs":["按照北京的老规矩，春节差不多在腊月的初旬就开始了。“腊七腊八，冻死寒鸦”，这是一年里最冷的时候。可是，到了严冬，不久便是春天，所以人们并不因为寒冷而减少过年与迎春的热情。在腊八那天，家家都熬腊八粥。这种特制的粥是祭祖祭神的，可是细一想，它倒是农业社会一种自傲的表现——这种粥是用各种米，各种豆，与各种干果（杏仁、核桃仁、瓜子、荔枝肉、桂圆肉、莲子、花生米、葡萄干、菱角米……）熬成的。这不是粥，而是小型的农业展览会。","腊八这天还要泡腊八蒜。把蒜瓣放到高醋里，封起来，为过年吃饺子用。到年底，蒜泡得色如翡翠，醋也有了些辣味，色味双美，使人忍不住要多吃几个饺子。在北京，过年时，家家吃饺子。","从腊八起，铺户就加紧上年货，街上增加了货摊子——卖春联的、卖年画的、卖蜜供的、卖水仙花的等等，他们都是只在这个季节才会出现的。这些摊子都是让孩子们的心跳的更快一些。在胡同里，吆喝的声音也比平时更多更复杂，其中也有仅在腊月才出现的，像卖松枝的、薏仁米的、年糕的等等。","孩子们准备过年，第一件事就是买杂拌儿。这是用各种干果（花生、胶枣、榛子、栗子等）与蜜饯掺和成的，普通的带皮，高级的没有皮——例如普通的用带皮的榛子，高级的就用榛仁。孩子们喜欢吃这些零七八碎儿，即使没有饺子吃，也必须买杂拌儿。他们的第二件事是买爆竹，特别是男孩子们。恐怕第三件事才是买玩意儿——风筝、 空竹、口琴等，和年画。","孩子们忙乱，大人们也紧张。他们必须预备过年吃的喝的用的一切，也必须赶快给孩子做新鞋新衣，好在新年时显出万象更新的气象。","腊月二十三过小年。差不多就是过春节的“彩排”。在老年间，这天晚上家家祭灶王，从一擦黑儿，鞭炮就响起来，人们随着鞭炮声把灶王的纸像焚化，美其名曰送灶王上天。在前几天，街上就有好多卖麦芽糖与江米糖的，糖形或为长方块或为大小瓜形。按旧日的说法，用糖粘住灶王的嘴，他到了天上就不会向玉帝报告家中的坏事了。现在还有卖糖的，但是只由大家享用，并不再粘灶王的嘴了。","过了二十三，大家就更忙，春节眨眼就到了啊。在除夕以前，家家必须把春联贴好，必须大扫除一次，名曰扫房。必须把肉、鸡、鱼、青菜、年糕什么的都预备充足，至少足够吃用一个星期的——按老习惯，铺户多数关五天门，到正月初六才开张。假若不预备下几天的吃食，临时不容易补充。","除夕真热闹。家家赶做年菜，到处是酒肉的香味。老少男女都穿起新衣，门外贴好红红的对联，屋里贴好了各色的年画，哪一家都是灯火通宵，不许间断，鞭炮声日夜不绝。在外边做事的人，除非万不得已，必定赶回家来，吃团圆饭，祭祖。这一夜，除了很小的孩子，没有什么人睡觉，都要守岁。","初一的光景与除夕截然不同：除夕，街上挤满了人；初一，铺户都上着板子，门前堆着昨夜燃放的爆竹纸皮，全城都在休息。","男人们在午前就出动，到亲戚家、朋友家拜年。女人们在家中接待客人。城内城外许多寺院开放，任人游览，小贩们在庙外摆摊，卖茶、食品和各种玩具。北城外的大钟寺、西城外的白云观、南城的火神庙（厂甸）是最有名的。可是，开庙最初的两三天，并不十分热闹，因为人们正忙着彼此贺年，无暇顾及。到了初五初六，庙会开始风光起来。小孩子们特别热心去逛，为的是到城外看看野景，可以骑毛驴，还能买到那些新年特有的玩具。白云观外的广场上有赛轿车赛马的，在老年间，据说还有赛骆驼的。这些比赛不是为争谁第一谁第二，而是在观众面前表演骡马与骑者的美好姿态和娴熟技能。","多数铺户在初六开张，又放鞭炮，从黎明到清早，全城鞭炮声不绝。虽然开了张，可是除了卖吃食与其他重要日用品的铺子，大家并不很忙，铺中的伙计们还可以轮流着去逛庙会、逛天桥和听戏。","元宵（汤圆）上市，春节的又一个高潮到了。除夕是热闹的，可是没有月光；元宵节呢，恰好是明月当空。大年初一是体面的，家家门前贴着鲜红的春联，人们穿着新衣裳，可是它还不够美；元宵节，处处悬灯结彩，整条大街像是办喜事，火炽而美丽。有名的老铺都要挂出几百盏灯来：有的一律是玻璃的，有的清一色是牛角的，有的都是纱灯；有的通通彩绘《红楼梦》或《水浒传》故事，有的图案各式各样。这在当年，也是一种广告。灯一悬起，任何人都可以进到铺中参观，晚间灯中点上蜡烛，观者就更多。这广告可不庸俗。干果店在灯节还要做一批杂拌儿生意，所以每每独出心裁，制成各样的冰灯，或用麦苗做成一两条碧绿的长龙，把顾客招来。","孩子们买各种花炮燃放，即使不跑到街上去淘气，在家中也照样能有声有光地玩耍。家中也有灯：走马灯、宫灯、各形各色的纸灯，还有纱灯，里面有小铃，到时候就叮叮地响。大家还必须吃元宵啊。这的确是美好快乐的日子。","一眨眼，到了残灯末庙，学生该去上学，大人又去照常做事，春节在正月十九结束了。腊月和正月，在农村正是大家最闲在的时候。过了灯节，天气转暖，大家就又去忙着干活儿了。北京虽是城市，可是它也跟着农村一齐过年，而且过得分外热闹。"]},{"id":442,"grade":"六年级下册","title":"2 腊八粥","paragraphs":["初学喊爸爸的小孩子，会出门叫洋车了的大孩子，嘴巴上长了许多白胡子的老孩子，提到腊八粥，谁不是嘴里就立时生一种甜甜的腻腻的感觉呢。把小米、饭豆、枣、栗、白糖、花生仁合拢来，糊糊涂涂煮成一锅，让它在锅中叹气似的沸腾着，单看它那叹气样儿，闻闻那种香味，就够咽三口以上的唾沫了，何况是，大碗大碗地装着，大匙大匙朝嘴里塞灌呢！","住方家大院的八儿，今天喜得快要发疯了。他一个人进进出出灶房，看到一大锅粥正在叹气，碗盏都已预备整齐，摆到灶边好久了，但妈妈总是说时候还早。","他妈妈正拿起一把锅铲在粥里搅和。锅里的粥也像是益发浓稠了。","“妈，妈，要到什么时候才……。”","“要到夜里！”其实他妈妈所说的夜里，并不是上灯以后。但八儿听了这种松劲的话，眼睛可急红了。锅中的粥，有声无力的叹气还在继续。","“那我饿了！”八儿要哭的样子。","“饿了，也得到太阳落下时才准吃。”","饿了，也得到太阳落下时才准吃。你们想，妈妈的命令，看羊还不够资格的八儿，难道还能设什么法来反抗吗？并且八儿所说的饿，也不可靠，不过因为一进灶房，就听到那锅中叹气又像是正在嘟囔的东西，因好奇而急于想尝尝这奇怪东西罢了。","“妈，妈，等一下我要吃三碗！我们只准大哥吃一碗。大哥同爹都吃不得甜的，我们俩光吃甜的也行……妈，妈，你吃三碗我也吃三碗，大哥同爹只准各吃一碗，一共八碗，是吗？”","“是啊！孥孥说得对。”","“要不然我吃三碗半，你就吃两碗半……”","“噗……”锅内又叹了声气。八儿回过头来，也不过看到一股淡淡烟气往上一冲而已！","锅中的一切，对八儿来说，只能猜想：栗子已稀烂到认不清楚了吧，饭豆会煮得浑身肿胀了吧，花生仁儿吃来总该是面面的了！枣子必大了三四倍——要是真的干红枣也有那么大，那就妙极了！糖若放多了，它会起锅巴……“妈，妈，你抱我起来看看吧！”于是妈妈就如八儿所求的把他抱了起来。","“呃……”他惊异得喊起来了，锅中的一切已进了他的眼中。","这不能不说是奇怪呀，栗子跌进锅里，不久就得粉碎，那是他知道的。他曾见过跌进黄焖鸡锅子里的一群栗子，不久就融掉了。饭豆煮得肿胀，那也是往常熬粥时常见的事。花生仁儿脱了它的红外套，这是不消说的事。锅巴，正是围了锅边成一圈。总之，一切都成了如他所猜的样子了，但他却没想到今日粥的颜色是深褐。","“怎么，黑的！”八儿同时想起了染缸里的脏水。","“枣子同赤豆搁多了。”妈妈解释的结果，是拣了一枚大得特别吓人的赤枣给了八儿。","虽说是枣子同饭豆搁得多了一点儿，但大家都承认味道是比普通的粥要好吃得多了。","晚饭桌边，靠着妈妈斜立着的八儿，肚子已成了一面小鼓了。在他身边桌上那两支筷子，很浪漫地摆成一个十字。桌上那大青花碗中的半碗陈腊肉，八儿的爹同妈也都奈何它不来了。"]},{"id":443,"grade":"六年级下册","title":"寒食","paragraphs":["作者：[唐代] 韩翃","春城无处不飞花，","寒食东风御柳斜。","日暮汉宫传蜡烛，","轻烟散入五侯家。","暮春长安城处处柳絮飞舞、落红无数，寒食节东风吹拂着皇城中的柳树。","傍晚汉宫传送蜡烛赏赐王侯近臣，袅袅的轻烟飘散到天子宠臣的家中。","韩翃，唐代诗人。字君平，南阳（今河南南阳）人。是“大历十才子”之一。天宝13年（754）考中进士，宝应年间在淄青节度使侯希逸幕府中任从事，后随侯希逸回朝，闲居长安十年。建中年间，因作《寒食》诗被唐德宗所赏识，因而被提拔为中书舍人。韩翃诗笔法轻巧，写景别致，在当时传诵很广。"]},{"id":444,"grade":"六年级下册","title":"迢迢牵牛星","paragraphs":["迢迢牵牛星，","皎皎河汉女。","纤纤擢素手，","札札弄机杼。","终日不成章，","泣涕零如雨。","河汉清且浅，","相去复几许。","盈盈一水间，","脉脉不得语。","在银河东南牵牛星遥遥可见，在银河之西织女星明亮皎洁。","织女正摆动柔长洁白的双手，织布机札札地响个不停。","一整天也没织成一段布，哭泣的眼泪如同下雨般零落。","这银河看起来又清又浅，两岸相隔又有多远呢？","虽然只相隔了一条银河，但也只能含情脉脉相视无言。"]},{"id":445,"grade":"六年级下册","title":"十五夜望月","paragraphs":["作者：[唐代] 王建","中庭地白树栖鸦，","冷露无声湿桂花。","今夜月明人尽望，","不知秋思落谁家。","庭院地面雪白树上栖息着鹊鸦，秋露无声无息打湿了院中桂花。","今天晚上人们都仰望当空明月，不知道这秋思之情落在了谁家？","王建（768年—835年），字仲初，颍川（今河南许昌）人，唐朝诗人。出身寒微，一生潦倒。曾一度从军，约46岁始入仕，曾任昭应县丞、太常寺丞等职。后出为陕州司马，世称王司马。与张籍友善，乐府与张齐名，世称张王乐府。"]},{"id":446,"grade":"六年级下册","title":"4* 藏戏","paragraphs":["世界上还有几个剧种是戴着面具演出的呢？","世界上还有几个剧种在演出时是没有舞台的呢？","世界上还有几个剧种一部戏可以演出三五天还没有结束的呢？","还是从西藏僧人唐东杰布的传奇故事讲起吧。","那时候，雅鲁藏布江上没有一座桥，数不清的牛皮船被掀翻在野马脱缰般的激流中，许多涉水过江的百姓被咆哮的江水吞噬。于是，年轻的僧人唐东杰布许下宏愿，发誓架桥，为民造福。一无所有的唐东杰布，招来的只有一阵哄堂大笑。","于是就有了这样一段传奇。唐东杰布在山南琼结认识了能歌善舞的七兄妹，组成了西藏的第一个藏戏班子，用歌舞说唱的形式，表演历史故事和传说，劝人行善积德，出钱出力，共同修桥。随着雄浑的歌声响彻雪山旷野，有人献出钱财，有人布施铁块，有人送来粮食，更有大批的渔民、工匠、流浪汉跟着他们，从一个架桥工地走到另一个架桥工地。随着铁索桥一座接着一座地架起来，藏戏的种子也随之撒遍了雪域高原。","身无分文的唐东杰布就这样在雅鲁藏布江上留下了58座铁索桥，同时，成为藏戏的开山鼻祖。","传说，唐东杰布在母亲的肚子里待了80年，出生时头发胡子都白了。因此，在藏戏里，他的面具是白色的，前额饰有日月，两颊贴着短发，眉眼嘴角永远带着神秘的笑。","在藏戏里，身份相同的人物所戴的面具，其颜色和形状基本相同。","国王的面具是红色的，红色代表威严。","王妃的面具是绿色的，绿色代表柔顺。","巫女的面具半黑半白，代表其两面三刀。","妖魔的面具青面獠牙，以示压抑和恐怖。","村民的面具则用白布或黄布缝制，眼睛和嘴唇处挖出窟窿，以示朴实敦厚。","雪山江河作背景，草原大地作背景。表演藏戏的艺人们席地而唱，不要幕布，不要灯光，不要道具，只要一鼓、一钹为其伴奏。他们别无所求，只要有观众就行。","观众团团围坐，所有的剧情全靠艺人们用说唱来描述。艺人们唱着，说着，跳着，在面具下演绎着各种故事。面具运用象征、夸张的手法，使戏剧中的人物形象突出、性格鲜明，这是藏戏面具在长期发展的过程中得以保留的原因之一。","西藏地广人稀，生活节奏比较缓慢。表现在藏戏中，情节可以任意拖延，艺人们的唱腔、舞蹈动作可以随意发挥，一段戏可以一而再、再而三地重复，观众也在吃喝玩耍中看戏，双方随心所欲、优哉游哉，一出戏演他个三五天毫不稀奇。","藏戏就是这样，一代一代地师传身授下去。"]},{"id":447,"grade":"六年级下册","title":"语文园地","paragraphs":["有名的老铺都要挂出几百盏灯来:有的一律是玻璃的，有的清一色是牛角的，有的都是纱灯。","全校运动会上，大山在短跑比赛中勇夺第一，志杰在跳高比赛中喜获金牌，思雨在跳远比赛中摘得桂冠，宁宁在游泳比赛中拔得头筹。","青青园中葵，","朝露待日晞。","阳春布德泽，","万物生光辉。","常恐秋节至，","焜黄华叶衰。","百川东到海，","何时复西归？","少壮不努力，","老大徒伤悲！","园中的葵菜都郁郁葱葱，晶莹的朝露等待阳光照耀。","春天给大地普施阳光雨露，万物生机盎然欣欣向荣。","常恐那肃杀的秋天来到，树叶儿黄落百草也凋零。","百川奔腾着向东流入大海，何时才能重新返回西境？","年轻力壮的时候不奋发图强，到老来悲伤也没用了。"]},{"id":448,"grade":"六年级下册","title":"5 鲁滨逊漂流记（节选）","paragraphs":["梗概","从前，有一个叫鲁滨逊的英国人。他喜欢航海和冒险，到过世界上的很多地方，碰到过许多危险，但他一点儿也不畏惧，希望走遍天涯海角。","有一次，鲁滨逊乘船前往非洲，途中遇上大风，船严重受损，同伴们在乘小艇逃生时都死在海里，只有他一个人被大浪冲到海岛边。这是一个无名的、没有人居住的荒岛，到处是乱石野草。他又累又饿，心里想：流落到这种地方，怎样活下去呢？","等到潮水退了，鲁滨逊看到那大船竟然还浮在海面上，离岸并不远。他游到船边，用船上的桅杆、木板制成了木筏运送从船上带来的物品。在船舱里，鲁滨逊找到很多可以用、可以吃的东西，陆续搬到岸上。没有淹死的一条狗、两只猫陪着他，这使他在凄凉中感到一丝安慰。","鲁滨逊走遍荒岛，在山坡上选择了一块有水源、可以防御野兽的地方，用木头和船帆搭起一座简陋的帐篷。那儿可以看到海面，他希望瞧见过往的船只，以便请求救援。","鲁滨逊在岛上定居下来，过着寂寞的生活。船上搬下来的食物越来越少，要想活下去，就得想办法。","他每天要么拿着枪，带着狗到森林里去打猎，要么到海边去捕鱼，还把捕到的活山羊畜养起来。后来他竟有了成群的山羊，可以常喝羊奶，吃羊肉。鲁滨逊从船上搬来的东西里还有一些麦子，由于被老鼠啃过了，他就随意把他们丢撒在地上，没想到不久竟长出了嫩芽，后来又结出了穗子。他用这点儿麦种反复种收，到了第四年，终于吃到了自己种的粮食。","很多年过去了。有一天，鲁滨逊忽然发现海边沙滩上出现了人的脚印。他惊恐万分，猜想这一定是附近的野人留下来的。他担心这些野人会来吃掉他。于是在住所前的空地上密密麻麻地插上树枝做防御，又把羊分在几个地方圈养。他在这种不安的心情下又生活了两年。后来，鲁滨逊再一次看到野人留下的生火的痕迹和满地的人骨，他不由得联想到他们野蛮的宴会。鲁滨逊在恐惧之中开始考虑怎样对付这些可能出现的野人。","又过了几年，有一天，鲁滨逊看到三十多个野人乘着小木船上了岸。他们拖出两个倒霉的同伴，杀了其中一个人，另一个则挣扎着逃跑。他逃的方向正是鲁滨逊住所的方向。鲁滨逊决心救下这个逃跑的野人，于是开枪打死了追赶他的两个野人。他给救下的野人取名“星期五”。“星期五”很快成了他的好帮手，他们愉快地生活在岛上，扩大了粮食种植面积，又增加了几个羊圈，晒了很多葡萄干。鲁滨逊差不多淡忘了要回到英国、回到文明社会的想法。","有一天清晨，鲁滨逊被“星期五”喊醒，原来，有一艘英国船只正在附近停泊着。他发现这艘船上发生了叛乱，水手们绑架了船长。鲁滨逊和“星期五”救出了船长，船长愉快地答应带他们回英国去。","在荒岛上度过了二十八年后，鲁滨逊终于回到了英国。","节选","我现在处在一个令人忧伤的、没有言语交流的生活场景中，也许这种生活在世界上是前所未有的。但我必须接受这种生活，并且一天一天过下去。根据我的估算，我是在9月30日登上了这个荒无人烟的岛。当时正是秋分前后，太阳正好在我的头顶上，所以我估计自己是在北纬9度22分的地方。","在岛上待了十一二天以后，我忽然想到，由于没有本子、笔和墨水，我将没法估算日子，甚至分不清休息日和工作日。为了避免这种情况，我用刀子在一根大木杆上刻了一些字，并把它做成一个大十字架，竖在我第一次登岸的地方，上面刻着：“1659年9月30日，我在这里登岸。”在这根方木杆的侧面，我每天用刀子刻一道痕，每第七道刻痕比其他的长一倍，每月第一天的刻痕再长一倍，这样，我就有了日历。","我几次到船上去，取出了许多东西。有几件虽然不值什么钱，对我来说却很有用，比如笔、墨水，还有纸，在船长、大副、炮手和木匠保管的物品中找到的几个包裹、三四个罗盘、几台数学仪器，还有日晷、望远镜、地图和航海类的书籍。我把它们一股脑堆在一起，以备不时之需。","还要提到的是，我们的船上有一条狗和两只猫。那两只猫是我带上岸的；至于那条狗，是在我带着第一批货上岸的第二天，它自己从船上跳出来，游上岸到我这儿来的，在以后的许多年里是我可信任的仆役。我不稀罕它给我弄来什么东西，也不稀罕它同我做伴，我只需要它同我聊聊天，但是它却办不到。找到了笔、墨水和纸之后，我尽最大的可能节省使用。只要我还有墨水，就能把事情记得非常准确。但是墨水用完以后，我就办不到了，因为我想尽办法还是制造不出墨水来。","尽管我收罗了这么多东西，还是缺少许多，比如墨水，还有用来挖土或者运土的铲子、鹤嘴锄、铁锨，以及针线。至于内衣之类，虽然缺乏，但我很快就习惯了。","没有工具，干什么都困难重重。我几乎花了一年工夫才完全布置好我那个用栅栏围起来的小小的住所。那些尖桩或者圆桩沉得很，我要使出全力才举得起来。我花了好长的时间才砍下那些木材，并且在林子里加工好，再花上更长的时间把它们运回家。也就是说，我需要花两天时间砍成一根木桩并运回来，在第三天才把它打进地里。我最初用一根很沉的木棒打桩，后来想到了用铁撬棒打。尽管如此，打起桩来还是很费劲，而且非常麻烦。","但是，我既然不得不干这活儿，又有的是时间，有什么必要介意呢？这活儿要是干完了的话，除了在岛上转悠，寻找吃的以外，那我也没有其他的事可干了。","我现在开始认真考虑我的处境。我一一记下我经历的事情，并不是想把自身的遭遇传给后人看，而是要把一直萦系在我心头，不断折磨着我的想法吐露出来。我的理智现在已经逐渐能够控制我的沮丧心情，我开始尽可能地安慰自己，把我遇到的凶险和幸运做个对比，使自己能够心平气和。我按照商业簿记中借方和贷方的格式，如实记录了我所遇到的幸与不幸：","坏处：我被抛弃在一座可怕的荒岛上，没有重见天日的希望。","好处：但是我还活着，没有像我的伙伴们一样被淹死。","坏处：我被单独剔出来，与世隔绝，受尽苦难。","好处：但是，我也免于死亡，而 船上其他人员都已丧命。","坏处：我被从人类中分离出来，成为一个孤独的人。","好处：但是，我在这片荒芜的土地上既没有挨饿，也没有奄奄待毙。","坏处：我没有衣服穿。","好处：但是，我身处热带，即使有衣服也不用穿。","坏处：我没有任何防御力量或者手段来抵抗人或野兽的侵袭。","好处：但是，在这里我看不见会伤害我的野兽，在非洲海岸上，我却看见过。要是我的船在那儿倾覆，该怎么办呢？","坏处：没有人可以同我说话，或者宽慰我。","好处：但是，船漂到了离岸很近的地方，我取出了很多必需品，有些甚至够我用一辈子。","总的来说，这是世界上少有的叫人受尽折磨的处境，但是其中也有一些值得宽慰的东西。这场世界上苦难最深重的经历告诉世人：在困境中，我们可以把好处和坏处对照起来看，并且从中找到一些东西来宽慰自己。","现在，我对自己的处境稍稍有了一点儿焉知非福的想法，我不再远眺大海，一心想看到船的踪影了。我着手调整我的生活方式，尽我可能把一切安排得舒舒服服。"]},{"id":449,"grade":"六年级下册","title":"6* 骑鹅旅行记（节选）","paragraphs":["男孩简直不敢相信他会变成小狐仙。“这大概是一场梦，一种幻觉吧！”他想，“过一会儿我肯定还会再变成一个人。”","他站在镜子前面闭上眼睛，过了好几分钟才睁开。当时他估计怪样子肯定消失了。可是怪样子并没有消失，他仍然像刚才一样小。从别的方面看，他和以前完全一样。他那淡黄的头发、鼻子上的雀斑、皮裤和袜子上的补丁都和过去一模一样，只不过变得很小很小罢了。","他发现，光那样站着等待是无济于事的，一定得想别的办法。他觉得最聪明的做法就是去找小狐仙讲和。","他忽然想起，曾听母亲讲过，小狐仙平时都是住在牛棚里的。他立刻决定到那里去看看是否能找到小狐仙。幸好房门半开着，不然他还够不到锁，无法开门呢，而现在他没碰到任何障碍就跑了出去。","门廊外面的那块地板上有一只麻雀在跳来跳去。他一看见男孩就叫了起来：“叽叽，叽叽，快看放鹅娃尼尔斯！快看拇指大的小人儿！快看拇指大的小人儿尼尔斯·豪尔耶松！”","院子里的鹅和鸡立即掉过头来盯着男孩，并发出了一阵使人无法忍受的咯咯声。“咯咯里咕，”公鸡叫道，“他活该，咯咯里咕，他扯过我的鸡冠！”","然而最奇怪的是，男孩竟听懂了他们说的话。他大为吃惊，就一动不动地站在台阶上听了起来。“这可能是因为我变成了小狐仙的缘故吧！”他自语着，“肯定是由于这个原因，我才听懂了禽兽说的话。”","那些鸡没完没了地叫着“他活该，他活该……”他实在无法忍受，捡起一块石头朝他们扔了过去，并骂道：“住嘴，你们这群乌合之众！”","可是他没有想到，他已不再是原来的样子，鸡根本就不怕他。整群鸡都跑到他身边，站在他周围叫着：“咕咕咕，你活该！咕咕咕，你活该！”","男孩想摆脱他们，但是那些鸡在他后面追着叫着，都快把他的耳朵吵聋了。如果不是家里养的那只猫走了出来，他是怎么也溜不掉的。那些鸡一看见猫便住了嘴，装着聚精会神的样子在地上刨虫子吃。","男孩马上跑到猫跟前。“亲爱的猫咪，”他说，“院子里各个角落和暗洞你不是都很熟悉吗？请你告诉我，在哪里能找到小狐仙？”","猫没有立刻回答。他坐下来，把尾巴精心地在腿前盘成了一个圆圈，两眼盯着男孩。那是一只大黑猫，脖子下面有个白斑点。他的皮毛平滑，在阳光下闪闪发亮。他的爪子收缩着，灰白的眼睛眯成了一条细缝，样子十分温柔。","“我知道小狐仙住在什么地方，”他低声说，“但是这并不等于说我愿意告诉你。”","“亲爱的猫咪，你可得帮我的忙啊！”男孩说，“你没看见他把我变成什么样子了吗？”","猫稍稍睁了睁眼睛，里面射出了一道寒光。他先得意扬扬地念了一阵经，然后才说。“要我，帮你的忙？是不是因为你经常揪我的尾巴？”","这时男孩恼怒了。他已经完全忘了他现在是多么弱小无力。“怎么着？我还要揪你的尾巴！”他说着便向猫扑了过去。","转眼间，猫摇身一变，男孩几乎不敢相信他还是刚才那个动物。他全身的毛都竖了起来，拱起腰，伸直了腿，四脚抓地，尾巴变得粗而短，两耳朝后，嘴里嘶叫着，瞪大的眼睛冒着火星。","男孩对猫并不示弱，反而向前逼近了一步。这时猫突然一跃，径直朝他扑了过去，把他摔倒在地，跳到他身上，前爪按住他的胸口，对着他的咽喉张开了大嘴。","男孩感觉到猫的爪子穿过他的背心和衬衣，刺进了他的皮肤，锋利的犬牙触到了他的咽喉。他拼命地喊着救命。","可是一个人也没有来。他断定，他死亡的时刻到了。正在这时，他又觉得猫把爪子收了回去，松开了他的喉咙。","“好了，”猫说，“这回够了，看在女主人的面上，这次我饶了你。我只想让你知道，咱们俩现在究竟谁厉害。”","接着，猫就走开了，看上去像他来的时候一样温柔和善。男孩羞得连一句话也说不出来，赶紧溜到牛棚里去找小狐仙了。","牛棚里只有三头牛。但男孩进去的时候，却是吼声四起，一片混乱，听起来至少是三十头。","“你过来，”名叫五月玫瑰的牛说，“我给你一蹄子，让你永远不能忘记！”","“你过来，”名叫金百合的牛说，“我要让你在我的角上跳舞。”","“你过来，我也叫你尝尝你去年夏天经常用木鞋打我的滋味！”名叫星星的牛吼道。","“你过来，你曾经把马蜂放进我的耳朵，现在我要报仇！”金百合叫着。","五月玫瑰在她们中间年纪最大、最聪明，而且也最生气。“你过来，”她说，“你做的事都应该遭报应了。你曾多次从你母亲腿下抽走她挤奶时坐的小凳，你多次在你母亲提着奶桶走过时伸脚绊倒她，你多次气得她站在这里流眼泪！”","男孩想对她们说，过去他对她们不好，现在后悔了，只要告诉他小狐仙在哪里，以后他就再也不捣蛋了。但是牛都不听他说话。她们吵闹得非常凶，他真担心哪头牛会挣断缰绳，所以他觉得还是趁早溜掉为妙。","他垂头丧气地从牛棚里走了出来。院子里不会有人帮他寻找小狐仙，这他是能够理解的。在这种情况下，即使找到小狐仙，可能也没有多大用处。","他爬到了长满荆棘和黑莓藤蔓攀缘的厚石头围墙上，坐在那里环顾着自己的家。那是一座用石头砌墙、木头作支架的白色小房子。其他附属的房屋也很小，耕地窄得几乎连马都无法在上面打滚。可是这地方无论怎么小怎么穷，对他来说已经够好的了。他现在除了在牛棚的地上找个洞以外，再也不能要求更好的住所了。","这天天气好极了。水渠里流水潺潺，树上嫩芽满枝，小鸟在耳边欢唱。而他却坐在那里十分难过，再也没有什么东西能引起他的兴致。","他从来没有见过天空像这样蓝。候鸟都回来了。他们从海外飞来，越过了波罗的海直奔斯密格虎克，正向北飞行。鸟的种类很多，但是别的鸟他都不认识，只认识那些排成“人”字形的大雁。","有几群大雁已经飞了过去。他们飞得很高，但是仍然能够听见他们的叫声：“现在飞向高山，现在飞向高山。”","当大雁们看到在院子里漫游的家鹅时，就一边朝大地低飞，一边喊着：“跟我们来吧！跟我们来吧！现在飞向高山。”","家鹅不由得抬起头，听着大雁的叫声。他们回答说：“我们在这里生活得很好！我们在这里生活得很好！”","如前所说，这天天气格外晴朗，空气清新，春风拂面，这时飞行真是一种享受。随着一群一群的大雁飞过，家鹅越来越动心了。他们中间有几只扇着翅膀跃跃欲试，但是一只老母鹅总是说：“别犯傻！你们一定会受冻挨饿的。”","大雁的呼叫却使一只年轻的雄鹅真的动了心。“再过来一群我就跟着他们飞走。”他说。","真的又过来一群大雁，他们照样呼唤。那只年轻的雄鹅答道：“等一等！等一等！我就来。”","他张开翅膀朝天空飞去。但是他没有飞行的习惯，于是又落到了地上。","大雁们还是听到了他的叫声。他们掉过头来慢慢地朝回飞，看他是不是真要跟着去。","“等一等！等一等！”他一面叫着一面进行新的尝试。","男孩坐在围墙上，这一切都听得一清二楚。","“如果这只大雄鹅飞走，可是一个很大的损失，”他想，“父母从教堂回来时，雄鹅不见了，他们会伤心的。”","当他这样想的时候，他又忘记了他是多么弱小无力。他一下子从墙上跳下来，跑进鹅群里，用双臂抱住了雄鹅的脖子。“你可千万不要飞走啊！”他喊道。","恰恰就在这一瞬间，雄鹅学会了怎样腾空而起。他来不及抖掉男孩就飞向了天空。","雄鹅飞得那么快，男孩都感到头晕目眩了。等他想到应该放开雄鹅的脖子时，已经到了高空。如果他现在一松手，肯定会掉到地上摔死。","要想舒服一点儿，他唯一能做的就是设法爬到鹅背上去。他费了九牛二虎之力总算爬了上去。然而要在翅膀中间光滑的脊背上坐稳，也不是一件容易的事，何况翅膀还在不停地扇动。为了不滑下去，他不得不用两手紧紧地抓住雄鹅的羽毛。"]},{"id":450,"grade":"六年级下册","title":"7* 汤姆·索亚历险记（节选）","paragraphs":["到了星期二的黄昏，圣彼得斯堡镇仍然笼罩在一片悲伤之中，两个走失的孩子还没有找到。镇上的人们已经为他们作了公开的祈祷，还有许许多多的人私下里为这两个孩子作了祈祷，诚心诚意地祈求他们平平安安，但是依然没有从洞里传来好消息。大多数搜索的人已经放弃了搜寻孩子这件事，回到镇上继续干他们平日的活儿去了，他们认为孩子明摆着是找不回来了。撒切尔太太病得厉害，大部分时间都在说胡话。人们听见她呼喊孩子，看见她每次抬起头侧耳听上好久，然后一边呻吟着一边软弱无力地垂下头去，那情景真是让人心碎。波莉姨妈已经陷入了悲痛和绝望之中，她那满头的灰发几乎全变白了。到了晚上，镇上停止了一切活动，整个小镇被蒙上了悲伤与凄惨的阴影。","半夜时分，镇上传来了发疯般的钟声。不一会儿，街道上就挤满了衣衫不整却欣喜若狂的人，他们高声喊着：“快来看！找到他俩了！”人们叮叮当当地敲响了铁碗铜盆，嘀嘀嗒嗒的喇叭声与人们的喧嚷声汇成了一片。大家成群结队地拥向河岸，去迎接那两个乘敞篷车归来的孩子。车子由欢呼着的村民拉着，簇拥着。前来迎接的人们加入了这支回小镇的队伍，他们迈着雄壮有力的步伐，浩浩荡荡地穿过大街，欢呼声一浪高过一浪。","整个小镇灯火通明，谁也没有再回去睡觉。这是这个小镇前所未有的最辉煌的一个夜晚。在孩子们回来后的半个小时，镇上的人排着队来到撒切尔法官家，搂着两个获救的孩子又亲又吻，同时还使劲握住撒切尔太太的手，满肚子的话想说又说不出，泪水如雨，洒了一地。","波莉姨妈真是高兴到了极点，撒切尔太太也是如此。然而，等派到山洞里的信使把这个喜讯报告给她的丈夫时，快乐才会变得十全十美。汤姆躺在一张沙发上，身边围满了热切的听众。他给他们讲着这次精彩的历险过程，同时还夸张地吹嘘了一番,最后又描述了他怎样离开贝琪去探险，如何在风筝线能达到的情况下顺着那两条通道向前探路，又是怎么去探索第三条通道，直到风筝线不够用了为止。正当他转身往回走时，突然发现远处有一小块亮光，好像是太阳光，于是他放下风筝线朝它摸索着走了过去。他把肩和头从一个小洞中探了出来，竟看见宽阔的密西西比河正从下面滚滚流过！如果碰巧是晚上,他绝不会看见那一小块太阳光，也就找不到这条通道了。他又讲述了他怎样回去找贝琪，告诉了她这个好消息，而她却让他别拿这些无聊的谎话来烦她，因为她很累，知道自已快要死了,她也愿意死掉。他还讲了自己如何费尽口舌说服了贝琪，当她摸索着爬到洞口，看见那一小块太阳光时，怎样兴奋得不得了，简直就要高兴死了。他还说自己怎样先爬出洞口，然后又帮助贝琪爬了出来，他们是如何坐在那里高兴得大声哭了起来，一些人怎样乘着小船打那儿经过,他俩又是怎样呼喊着他们，告诉他们自己的遭遇。他也描述了起初这些人如何不相信这荒唐离奇的故事，因为他们说：“你们是在河的下游，离那个峡谷里的山洞有五英里远呢。”然后他们就将他俩扶上船，划到一户人家，给他俩吃了晚饭，让他们歇息了两三个小时，随后便把他们送回了家。","汤姆和贝琪很快发现，在洞里所遭受的三天三夜的疲劳和饥饿,是不可能马上恢复过来的。星期三和星期四整整两天，他们一直卧床不起，好像越躺越难受，浑身没有一点儿力气。汤姆星期四稍微能下地活动一会儿，星期五就能到镇上逛逛了，到了星期六差不多完全恢复正常了。但贝琪直到星期天才能够到户外走走，看上去好像刚得了一场大病似的。","汤姆听说哈克病了，星期五便去看他，谁知道被挡在了门外，星期六、星期天一连两天也都没让他进去。过了星期天，他可以每天去看哈克了，但是哈克的家人告诫他不能透露他的探险经过,也不要谈及任何令人兴奋的话题。道格拉斯寡妇守在旁边，看汤姆是否遵守规定。回到家里，汤姆才听说卡迪夫山发生的事,还得知那个“衣衫褴褛的人”的尸体最后在渡船码头附近被发现了，很可能是在逃跑途中溺水而死的。","汤姆从山洞里获救两个星期之后，哈克已经强壮多了，也不怕听令人激动的话题了。汤姆又去看望哈克，他想,有一些话题正是哈克感兴趣的。撒切尔法官的家离哈克住的地方不远，于是汤姆就顺道去看了看贝琪。法官和他的几个朋友逗他滔滔不绝地讲了起来，有的人还用嘲弄的口吻问他是否还想再去那个山洞走一趟。汤姆说，他认为他不会在意的。法官说：","“还有一些人和你一样想去山洞看看呢，汤姆,这一点是毫无疑问的。但是我们已经采取了防范措施，以后谁也不会再在那个山洞里迷路了。”","“为什么？”","“因为两周前我就找人用锅炉钢板把山洞的洞口封上了，然后又上了三道锁，钥匙在我这里。”","汤姆的脸立刻变得煞白。","“怎么了，孩子!喂，快来人哪!快拿杯水来！”","有人拿过一杯水，一下子泼在了汤姆的脸上。","“啊，现在没事了。你怎么了，汤姆？”","“哎呀，法官，印江·乔埃还在洞里呢！”"]},{"id":451,"grade":"六年级下册","title":"语文园地","paragraphs":["镇上的人排着队来到撒切尔法官家，搂着两个获救的孩子又亲又吻，......泪水如雨，洒了一地。","过了二十三，大家就更忙了，春节眨眼就到了啊。","住方家大院的八儿，今天喜得快要发疯了。","饿 安静 厚 盼望 喜欢","这是这个小镇前所未有的最辉煌的一个夜晚。","满肚子的话想说又说不出，泪水如雨，洒了一地。","译者：俞东明、陈海庆","这天晚上的伟大场面是这个小镇从来没有见到过的。","想说话又说不出来——然后像流水似的涌出，到处都像下雨一般掉了满地的眼泪。","译者：张友松","这是小镇经历过的最激动人心的一夜。","想说什么但什么也说不出来——一路出去时如下雨似的洒了满地的眼泪。","译者：成时","读书须用意，一字值千金。","莫道君行早，更有早行人。","听君一席话，胜读十年书。","路遥知马力，日久见人心。","近水知鱼性，近山识鸟音。"]},{"id":452,"grade":"六年级下册","title":"快乐读书吧","paragraphs":["每一本名著都是独一无二的花朵。当你漫步在世界名著花园中，与心仪的书籍不期而遇，一定会惊喜地停下脚步。","你读过吗","《鲁滨逊漂流记》就是这样一本令人无限惊讶的书。翻开它，你会看到一个人如何在绝境中变成自己的国王，一座岛如何从荒芜之地变成微型的文明社会。二十八年，鲁滨逊凭借自己勇往直前的精神和辛勤的劳动，成就了一段传奇。","这本书面世后，吸引了不少学者对其进行评论。","它就是我们学习的课本，我们关于自然科学的一切谈话，都不过是对它的一个注释罢了。——[法国]卢梭","经典是那些你经常听人家说“我正在重读......”而不是“我正在读......”的书。......《鲁滨逊漂流记》无疑是一部值得逐字逐行重读的小说。——[意大利]卡尔维诺","有些名著读起来比较难，不像流行读物那样通俗易懂，但想到能成为经典的书不简单，是人类智慧的结晶，你就会让自己沉下心来读，越读越有味。","先大致了解名著的写作背景，能帮助我们理解作品的内容和价值。读的时候如果能做一些读书笔记，收获就更大了。","相信你可以读更多","在这个单元里，我们接触了几本世界名著，它们不仅有引人人胜的情节，还有复杂的内涵，正因为如此，读起来才更有乐趣。《鲁滨逊漂流记》背后鲜明的时代烙印，《骑鹅旅行记》字里行间的怀乡之情，《汤姆·索亚历险记》对自由的向往和对社会的讽刺，都需要我们慢慢去发现，去品味。","刘易斯·卡罗尔创作的《爱丽丝漫游奇境》也是如此。小说的主人公爱丽丝掉进兔子洞后，一段如梦如幻的旅程在我们眼前展开。这本书表面上荒诞不经：渡鸦像一张写字台，柴郡猫的身体消失后笑容还停留在空中.....但在奇异的情节背后，隐藏着严密的逻辑。卡罗尔是英国著名的数学家，读着他写的那些看似疯狂的话，就像在做一场高难度的智力游戏，同时你又能从幽默的语言之中，看到作者对现实的些许嘲弄。","我们可以在页面的空白处随时写下自己的感触。","读到特别喜欢的段落，可以摘抄在笔记本中，并把页码标注出来。","遇到人物关系比较复杂的情况，可以画一个人物图谱，以便阅读时随时查阅。","读完整本书以后，还可以写出全书的结构，以及作者在书中想要表达的一些想法。"]},{"id":453,"grade":"六年级下册","title":"8 匆匆","paragraphs":["燕子去了，有再来的时候；杨柳枯了，有再青的时候；桃花谢了，有再开的时候。但是，聪明的，你告诉我，我们的日子为什么一去不复返呢？——是有人偷了他们吧：那是谁？又藏在何处呢？是他们自己逃走了吧：现在又到了哪里呢？","我不知道他们给了我多少日子，但我的手确乎是渐渐空虚了。在默默里算着，八千多日子已经从我手中溜去，像针尖上一滴水滴在大海里，我的日子滴在时间的流里，没有声音，也没有影子。我不禁头涔涔而泪潸潸了。","去的尽管去了，来的尽管来着，去来的中间，又怎样地匆匆呢？早上我起来的时候，小屋里射进两三方斜斜的太阳。太阳他有脚啊，轻轻悄悄地挪移了，我也茫茫然跟着旋转。于是——洗手的时候，日子从水盆里过去；吃饭的时候，日子从饭碗里过去；默默时，便从凝然的双眼前过去；我觉察他去得匆匆了，伸出手遮挽时，他又从遮挽着的手边过去；天黑时，我躺在床上，他便伶伶俐俐地从我身上跨过，从我脚边飞去了；等我睁开眼和太阳再见，这算又溜走了一日；我掩面叹息，但是新来的日子的影儿又开始在叹息里闪过了。","在逃去如飞的日子里，在千门万户的世界里的我能做些什么呢？只有徘徊罢了，只有匆匆罢了。在八千多日的匆匆里，除徘徊外，又剩些什么呢？过去的日子如轻烟，被微风吹散了，如薄雾，被初阳蒸融了。我留着些什么痕迹呢？我何曾留着像游丝样的痕迹呢？我赤裸裸来到这世界，转眼间也将赤裸裸地回去吧？但不能平的，为什么偏要白白走这一遭啊？","你聪明的，告诉我，我们的日子为什么一去不复返呢？"]},{"id":454,"grade":"六年级下册","title":"9 那个星期天","paragraphs":["我还记得我的第一次盼望。那是一个星期天，从早晨到下午，一直到天色昏暗下去。","那个星期天母亲答应带我出去，去哪儿已经记不清了，可能是动物园，也可能是别的什么地方。总之她很久之前就答应了，就在那个星期天带我出去玩，这不会错。一个人平生第一次盼一个日子，都不会错。而且就在那天早晨，母亲也还是这样答应的：去，当然去。我想到底是让我盼来了。","起床，刷牙，吃饭，那是个春天的早晨，阳光明媚。走吗？等一会儿，等一会儿再走。我跑出去，站在街门口，等一会儿就等一会儿。我藏在大门后，藏了很久。我知道不会是那么简单的一会儿，我得不出声地躲藏一会儿。母亲出来了，可我忘了吓唬她，她手里怎么提着菜篮？您说了去！等等，买完菜，买完菜就去。买完菜马上就去吗？嗯。","这段时光不好挨。我踏着一块块方砖跳，跳房子，等母亲回来。我看着天看着云彩走，等母亲回来，焦急又兴奋。我蹲在院子的地上，用树枝拨弄着一个蚁穴，爬着去找更多的蚁穴。院子里就我一个孩子，没人跟我玩。我坐在草丛里翻看一本画报，那是一本看了多少回的电影画报。那上面有一群比我大的女孩子，一个个都非常漂亮。我坐在草丛里看她们，想象她们的家，想象她们此刻在干什么，想象她们的兄弟姐妹和她们的父母，想象她们的声音。去年的荒草丛里又有了绿色，院子很大，空空落落。","母亲买菜回来却又翻箱倒柜忙开了。走吧，您不是买菜回来就走吗？好啦好啦，没看我正忙呢吗？真奇怪，该是我有理的事啊？不是吗，我不是一直在等着，母亲不是答应过了吗？整个上午我就跟在母亲腿底下：去吗？去吧，走吧，怎么还不走啊？走吧……我就这样念念叨叨地追在母亲的腿底下，看她做完一件事又去做一件事。我还没有她的腿高，那两条不停顿的腿至今都在我眼前晃动，它们不停下来，它们好几次绊在我身上，我好几次差点儿绞在它们中间把它们碰倒。","下午吧，母亲说，下午，睡醒午觉再去。去，母亲说，下午，准去。但这次怨我，怨我自己，我把午觉睡过头了。醒来时我看见母亲在洗衣服。要是那时就走还不晚。我看看天，还不晚。还去吗？去。走吧？洗完衣服。这一次不能原谅。我不知道那堆衣服要洗多久，可母亲应该知道。我蹲在她身边，看着她洗。我一声不吭，盼着。我想我再不离开半步，再不把觉睡过头。我想衣服一洗完我马上拉起她就走，决不许她再耽搁。我看着盆里的衣服和盆外的衣服，我看着太阳，看着光线，我一声不吭。看着盆里揉动的衣服和绽开的泡沫，我感觉到周围的光线渐渐暗下去，渐渐地凉下去沉郁下去，越来越远越来越飘渺，我一声不吭，忽然有点儿明白了。","我现在还能感觉到那光线漫长而急遽的变化，孤独而惆怅的黄昏到来，并且听得见母亲咔嚓咔嚓搓衣服的声音，那声音永无休止就像时光的脚步。那个星期天。就在那天。母亲发现男孩儿蹲在那儿一动不动，发现他在哭，在不出声地流泪。我感到母亲惊惶地甩了甩手上的水，把我拉过去拉进她的怀里。我听见母亲在说，一边亲吻着我一边不停地说：“噢，对不起，噢，对不起……”那个星期天，本该是出去的，去哪儿记不得了。男孩儿蹲在那个又大又重的洗衣盆旁，依偎在母亲怀里，闭上眼睛不再看太阳，光线正无可挽回地消逝，一派荒凉。"]},{"id":455,"grade":"六年级下册","title":"习作例文","paragraphs":["钟声响了，第一堂课是语文。以前我上语文课时总是懒洋洋提不起劲，奇怪，今天我翻开语文书，别有一番滋味，我的脑子也不再胡思乱想，全神贯注地听张先生授课。我为什么忽然会喜欢上语文课，觉得张先生每一句话都那么动听？这一堂课好像过得特别快，一下子就听到了下课钟声。","放学回家，我一口气读完张先生送给我的书。这本书先浅显地介绍中文的发展，然后分述了中文的特点，最后讲述学好中文的方法。我一下子对中文了解了很多很多。我有点儿怪张先生，为什么不早点儿送这本书给我，让我早点儿知道中文的丰富和优美。","我放下书，走到爸爸跟前，问他：“爸爸，我们将来移民到中美洲，我还有机会学习中文吗？”","爸爸说：“我正为这件事操心。那边华侨很少，没有为华侨办的学校。到了那边，你就要学习西班牙文。我担心你会渐渐忘记了中文。”","我听后吓了一跳。我拿起一张报纸，单是大字标题就有不少字不认识，不要说报纸的内文了。我现在念五年级，可是因为我过去不喜欢语文课，实在学得不好，实际上大约只有三四年级的程度。我张皇地拿出语文书，急急温习今天教过的课文，觉得课文内容饶有趣味。我又拿出纸用笔反复写新学的生字。我一想起自己顶多还有一个月学习中文的时间，心里就难过，真希望把整本语文书一下子全学会。","我一连两次默书都得到八十分，张先生每次都鼓励我；最近一次默书，我居然一个字也没有错，得到一百分！语文课上，张先生拿出我的默书簿，翻开第一页给大家看，然后又翻到最后一页，高高举起让同学们看。张先生说：“陈小允是我们学习的好榜样。你们看，他学期开始默书总不合格，现在却得了一百分！”","有谁知道我心里的痛！唉，语文课，在我深深喜欢上你的时候，我就要离开你了，我将要学习另一种完全不同的语言了，想到这里，我噙着泪。坐在我旁边的叶志聪看见，大惊说：“张先生，陈小允哭啦！”","同学们都奇怪地注视着我。张先生走到我身旁，亲切地抚着我的头，说：“小允，是为你的进步而哭吗？”","我擦拭着泪水，站起来，鸣咽着说：“张先生，我下星期要离开这里了，我们全家移民到危地马拉，我……我再没有机会学习中文了。”","泪水模糊了眼睛，我看不见同学和张先生的反应，只知道全班忽然异样地沉寂。张先生轻抚着我的头，叫我坐下。","离开这里的日子越来越近了。同学们纷纷在我的纪念册上留言，叮嘱我不要忘记中国，不要忘记中文。","这天，是我最后一次上语文课了，张先生带来一扎用鸡皮纸封好的包裹，她对全体同学说：“陈小允是最后一天和大家相叙了。我们祝福他在国外健康快乐地成长。我没有什么送给他，只送他一套小学六年级到中学五年级的语文课本，希望他远离祖国后还可以好好自修，不要忘记母语。”","我接过这套书，心里非常难过。下课后，同学们都围上来，有人送我一本字典，有人送我一本故事书。他们的热情，使我热泪盈眶。","别了，我亲爱的老师，我亲爱的同学。我一定不会忘记中文，我会把我的默书簿一生一世留在身边，常常翻阅。我会激励自己把中文自修好，像这本默书簿的成绩那样。","童年的大院里，住的都是引车卖浆者流，生活不大富裕，日子各有各的过法。","冬天，屋子里冷，特别是晚上睡觉的时候，被窝里冰凉如铁，那时家里连个暖水袋都没有。母亲有主意，中午的时候，她把被子抱到院子里，晾到太阳底下。其实，这样的法子很古老，几乎各家都会这样做。有意思的是，母亲把被子从绳子上取下来，抱回屋里，赶紧就把被子叠好，铺成被窝状，晚上睡觉我钻进去时，被子里还是暖乎乎的连被套的棉花味道都烤了出来，很香的感觉。母亲对我说：“我这是把老阳儿叠起来了。”母亲一直用老家话，把太阳叫老阳儿。“阳儿”读成“爷儿”音。","从母亲那里，我总能听到好多新词。把老阳儿叠起来让我觉得新鲜。太阳也可以如卷尺或纸或布一样，能够折叠自如吗？在母亲那里，可以。阳光便能够从中午最热烈的时候，一直储存到晚上我钻进被窝里，温暖的气息和味道，让我感觉到阳光的另一种形态，如同母亲大手的抚摸，比暖水袋温馨许多。","街坊毕大妈，靠摆摊儿养活一家老小。她家门口有一口半人多高的大水缸，冬天用它来储存大白菜，夏天它还有特殊的用处。夏天到来时，每天中午，毕大妈都要接满一缸自来水，骄阳似火，毒辣辣地照到下午，晒得缸里的水都有些烫手了。水能够溶解糖，溶解盐，水还能够溶解阳光，这大概是童年时候我最大的发现了。溶解糖的水变甜，溶解盐的水变咸，溶解了阳光的水变暖，变得犹如母亲温暖的怀抱。","毕大妈的孩子多。黄昏，她家的孩子放学了，毕大妈把孩子们都叫过来，一个个排队洗澡。毕大妈用盆舀的就是缸里的水，正温乎，孩子们连玩带洗，大呼小叫，噼里啪啦的，溅起一盆的水花，个个演出一场哪吒闹海。","那时候，各家都没有现在普及的热水器，洗澡一般都是用火烧热水，像毕大妈这样给孩子洗澡，在我们大院是独一份。母亲对我说：“看人家毕大妈，把老阳儿煮在水里面了！”","我得佩服母亲用词的准确和生动，一个“煮”字，让太阳成了居家过日子必备的一种物件，柴米油盐酱醋茶这开门七件事之后，还得加上一件，即母亲说的老阳儿。","真的，谁家都离不开柴米油盐酱醋茶，但是，谁家又离得开老阳儿呢？如同清风朗月不用一文钱一样，老阳儿也不用花一分钱，对所有人都大方且一视同仁，而柴米油盐酱醋茶却样样都得花钱买才行。不过，如母亲和毕大妈这样将阳光派上如此用法的人家，也不多。这样的用法，需要一点儿智慧和温暖的心，更需要在艰苦日子里磨炼出的一点儿本事。阳光成了居家过日子的一把好手，陪伴着母亲和毕大妈一起，让那些庸常而艰辛的琐碎日子变得有滋有味。"]},{"id":456,"grade":"六年级下册","title":"马诗","paragraphs":["作者：[唐代] 李贺","大漠沙如雪，","燕山月似钩。","何当金络脑，","快走踏清秋。","平沙万里，在月光下像铺上一层白皑皑的霜雪。连绵的燕山山岭上，一弯明月当空，如弯钩一般。","什么时候才能给它戴上金络头，在秋高气爽的疆场上驰骋，建立功勋呢？","李贺（约公元790年-约817年），字长吉，汉族，唐代河南福昌（今河南洛阳宜阳县）人，家居福昌昌谷，后世称李昌谷，是唐宗室郑王李亮后裔。“长吉体”诗歌的开创者，有“诗鬼”之称，是与“诗圣”杜甫、“诗仙”李白、“诗佛”王维相齐名的唐代著名诗人。著有《昌谷集》。李贺是中唐的浪漫主义诗人，与李白、李商隐称为唐代三李。有“太白仙才，长吉鬼才”之说。李贺是继屈原、李白之后，中国文学史上又一位颇享盛誉的浪漫主义诗人。李贺长期的抑郁感伤，焦思苦吟的生活方式，元和八年（813年）因病辞去奉礼郎回昌谷，27岁英年早逝。"]},{"id":457,"grade":"六年级下册","title":"石灰吟","paragraphs":["作者：[明代] 于谦","千锤万凿出深山，","烈火焚烧若等闲。","粉骨碎身浑不怕，","要留清白在人间。","石灰石经过千锤万凿才得以从深山里开采出来，它把熊熊烈火的焚烧当作很平常的一件事。","即使粉身碎骨也毫不惧怕，只要把高尚气节留在人世间。","于谦（1398年5月13日－1457年2月16日），字廷益，号节庵，官至少保，世称于少保。汉族，明朝浙江杭州钱塘县人。因参与平定汉王朱高煦谋反有功，得到明宣宗器重，担任明朝山西河南巡抚。明英宗时期，因得罪王振下狱，后释放，起为兵部侍郎。土木堡之变后英宗被俘，郕王朱祁钰监国，擢兵部尚书。于谦力排南迁之议，决策守京师，与诸大臣请郕王即位。瓦剌兵逼京师，督战，击退之。论功加封少保，总督军务，被迫与先遣使议和，使英宗得归。天顺元年因“谋逆”罪被冤杀。谥曰忠肃。有《于忠肃集》。于谦与岳飞、张煌言并称“西湖三杰”。"]},{"id":458,"grade":"六年级下册","title":"竹石","paragraphs":["作者：[清代] 郑燮","咬定青山不放松，","立根原在破岩中。","千磨万击还坚劲，","任尔东西南北风。","紧紧咬住青山毫不放松，原来是由于根深深地扎在了岩石缝隙中。","历经无数的磨难和打击身骨仍然坚劲，任凭你刮东西南北风。","郑板桥（1693—1765）清代官吏、书画家、文学家。字克柔，汉族，江苏兴化人。一生主要客居扬州，以卖画为生。“扬州八怪”之一。其诗、书、画均旷世独立，世称“三绝”，擅画兰、竹、石、松、菊等植物，其中画竹已五十余年，成就最为突出。著有《板桥全集》。康熙秀才、雍正举人、乾隆元年进士。中进士后曾历官山东范县、山东潍县知县，有惠政。以请臻饥民忤大吏，乞疾归。"]},{"id":459,"grade":"六年级下册","title":"11 十六年前的回忆","paragraphs":["1927年4月28日，我永远忘不了那一天。那是父亲的被难日，离现在已经十六年了。","那年春天，父亲每天夜里回来得很晚。每天早晨，不知道什么时候他又出去了。有时候他留在家里，埋头整理书籍和文件。我蹲在旁边，看他把书和有字的纸片投到火炉里去。","我奇怪地问他∶“爹，为什么要烧掉呢？怪可惜的。”","待了一会儿，父亲才回答∶“不要了就烧掉。你小孩子家知道什么！”","父亲一向是慈祥的，从没有骂过我们，更没有打过我们。我总爱向父亲问许多幼稚可笑的问题。他不论多忙，对我的问题总是很感兴趣，总是耐心地讲给我听。这一次不知道为什么，父亲竟这样含糊地回答我。","后来听母亲说，军阀张作霖要派人来检查。为了避免党组织被破坏，父亲只好把一些书籍和文件烧掉。才过了两天，果然出事了。工友阎振三一早上街买东西，直到夜里还不见回来。第二天，父亲才知道他被抓到警察厅里去了。我们心里都很不安，为这位工友着急。","局势越来越严峻，父亲的工作也越来越紧张。他的朋友劝他离开北京，母亲也几次劝他。父亲坚决地对母亲说∶“不是常对你说吗？我是不能轻易离开北京的。你要知道现在是什么时候，这里的工作多么重要。我哪能离开呢？”母亲只好不再说什么了。","可怕的一天果然来了。4月6日的早晨，妹妹换上了新夹衣，母亲带她到儿童娱乐场去散步了。父亲在里间屋里写字，我坐在外间的长木椅上看报。短短的一段新闻还没看完，就听见啪，啪……几声尖锐的枪声，接着是一阵纷乱的喊叫。","“什么？爹！”我瞪着眼睛问父亲。","“没有什么，不要怕。星儿，跟我到外面看看去。”","父亲不慌不忙地向外走去。我紧跟在他身后，走出院子，暂时躲在一间僻静的小屋里。","一会儿，外面传来一阵沉重的皮鞋声。我的心剧烈地跳动起来，用恐惧的眼光瞅了瞅父亲。","“不要放走一个！”窗外响起粗暴的吼声。穿灰制服和长筒皮靴的宪兵，穿便衣的侦探，穿黑制服的警察，一拥而入，挤满了这间小屋。他们像一群魔鬼似的，把我们包围起来。他们每人拿着一把手枪，枪口对着父亲和我。在军警中间，我发现了前几天被捕的工友阎振三。他的胳膊上拴着绳子，被一个肥胖的便衣侦探拉着。","那个满脸横肉的便衣侦探指着父亲问阎振三∶“你认识他吗？”","阎振三摇了摇头。他那披散的长头发中间露出一张苍白的脸，显然是受过苦刑了。","“哼！你不认识？我可认识他。”侦探冷笑着，又吩咐他手下的那一伙，“看好，别让他自杀！”","他们仔细地把父亲全身搜了一遍。父亲保持着他那惯有的严峻态度，没有向他们讲任何道理。因为他明白，对他们是没有道理可讲的。","残暴的匪徒把父亲绑起来，拖走了。我也被他们带走了。在高高的砖墙围起来的警察厅的院子里，我看见母亲和妹妹也都被带来了。我们被关在女拘留所里。","十几天过去了，我们始终没看见父亲。有一天，我们正在啃手里的窝窝头，听见警察喊我们母女的名字，说是提审。","在法庭上，我们跟父亲见了面。父亲仍旧穿着他那件灰布旧棉袍，可是没戴眼镜。我看到了他那乱蓬蓬的长头发下面的平静而慈祥的脸。","“爹！”我忍不住喊出声来。母亲哭了，妹妹也跟着哭起来了。","“不许乱喊！”法官拿起惊堂木重重地在桌子上拍了一下。","父亲瞅了瞅我们，没有说一句话。他的神情非常安定，非常沉着。他的心被一种伟大的力量占据着。这个力量就是他平日对我们讲的——他对于革命事业的信心。","“这是我的妻子。”他指着母亲说。接着他又指了一下我和妹妹，“这是我的两个孩子。”","“她是你最大的孩子吗？”法官指着我问父亲。","“是的，我是最大的。”我怕父亲说出哥哥来，就这样抢着说了。我不知道当时哪里来的机智和勇敢。","“不要多嘴！”法官怒气冲冲的，又拿起他面前那块木板狠狠地拍了几下。","父亲立刻就会意了，接着说∶“她是我最大的孩子。我的妻子是个乡下人。我的孩子年纪都还小，她们什么也不懂。一切都跟她们没有关系。”父亲说完了这段话，又望了望我们。","法官命令把我们押下去。我们就这样跟父亲见了一面，匆匆分别了。想不到这竟是我们最后一次见面。","28日黄昏，警察叫我们收拾行李出拘留所。","我们回到家里，天已经全黑了。第二天，舅老爷到街上去买报。他是从街上哭着回来的，手里无力地握着一份报。我看到报上用头号字登着“李大钊等昨已执行绞刑”，立刻感到眼前蒙了一团云雾，昏倒在床上了。母亲伤心过度，昏过去三次，每次都是刚刚叫醒又昏过去了。","过了好半天，母亲醒过来了，她低声问我∶“昨天是几号？记住，昨天是你爹被害的日子。”","我又哭了，从地上捡起那张报纸，咬紧牙，又勉强看了一遍，低声对母亲说∶“妈，昨天是4月28日。”"]},{"id":460,"grade":"六年级下册","title":"12 为人民服务","paragraphs":["我们的共产党和共产党所领导的八路军、新四军，是革命的队伍。我们这个队伍完全是为着解放人民的，是彻底地为人民的利益工作的。张思德同志就是我们这个队伍中的一个同志。","人总是要死的，但死的意义有不同。中国古时候有个文学家叫做司马迁的说过：“人固有一死，或重于泰山，或轻于鸿毛。”为人民利益而死，就比泰山还重；替法西斯卖力，替剥削人民和压迫人民的人去死，就比鸿毛还轻。张思德同志是为人民利益而死的，他的死是比泰山还要重的。","因为我们是为人民服务的，所以，我们如果有缺点，就不怕别人批评指出。不管是什么人，谁向我们指出都行。只要你说得对，我们就改正。你说的办法对人民有好处，我们就照你的办。“精兵简政”这一条意见，就是党外人士李鼎铭先生提出来的；他提得好，对人民有好处，我们就采用了。只要我们为人民的利益坚持好的，为人民的利益改正错的，我们这个队伍就一定会兴旺起来。","我们都是来自五湖四海，为了一个共同的革命目标，走到一起来了。我们还要和全国大多数人民走这一条路。我们今天已经领导着有九千一百万人口的根据地，但是还不够，还要更大些，才能取得全民族的解放。我们的同志在困难的时候，要看到成绩，要看到光明，要提高我们的勇气。中国人民正在受难，我们有责任解救他们，我们要努力奋斗。要奋斗就会有牺牲，死人的事是经常发生的。但是我们想到人民的利益，想到大多数人民的痛苦，我们为人民而死，就是死得其所。不过，我们应当尽量地减少那些不必要的牺牲。我们的干部要关心每一个战士，一切革命队伍的人都要互相关心，互相爱护，互相帮助。","今后我们的队伍里，不管死了谁，不管是炊事员，是战士，只要他是做过一些有益的工作的，我们都要给他送葬，开追悼会。这要成为一个制度。这个方法也要介绍到老百姓那里去。村上的人死了，开个追悼会。用这样的方法，寄托我们的哀思，使整个人民团结起来。"]},{"id":461,"grade":"六年级下册","title":"13 董存瑞舍身炸暗堡","paragraphs":["1948年5月25日，攻城的大炮震撼着整个隆化城，解放隆化的战斗打响了。战士们像潮水一般冲向敌军司令部所在地——隆化中学。嗒嗒嗒......从一座桥上，突然喷出几条火舌，封锁了我军前进的道路。那座桥架在隆化中学墙外的一条旱河上。狡猾的敌人在桥的两侧筑了墙，顶上加了盖，构成了一座暗堡。冲锋的部队被压在一个小土坡下面，抬不起头。冲在最前面的一个战士倒下了。","董存瑞瞪着敌人的暗堡，两眼迸射出仇恨的火花。他跑到连长身边，坚决地说:“连长，我去炸掉它！”","“连长，我掩护！”战友郅顺义也恳切地说。","连长和指导员商量了一下，同意了他们的请求。“同志们，扔手榴弹!”连长给战士们下了命令。","董存瑞抱起炸药包，郅顺义背起两兜手榴弹，同时跃出战壕，冲了上去。他们互相配合，郅顺义扔一阵手榴弹，董存瑞就向前跃进几步；郅顺义再扔一阵，董存瑞再跃进几步。跟在后面的战友把一捆捆手榴弹送到郅顺义手里。","敌人的机枪更疯狂了，子弹扑哧扑哧打在董存瑞身边，激起了点点尘土，四周冒起了白烟。董存瑞夹紧炸药包，一会儿忽左忽右地匍匐前进，一会儿又向前滚上好几米。敌人的机枪一齐向董存瑞扫射，在他面前交织成一道火网。突然，他身子一震，左腿中了一枪。他用手一摸，全是血。这时，他离暗堡只有几十米了。他隐蔽在一小块凹地里。郅顺义接二连三地扔手榴弹。趁着腾起的黑烟，董存瑞猛冲到桥下。","董存瑞看看四周，这座桥有一人多高，两边是光滑的斜坡。炸药包放在哪儿呢?他想把炸药包放在河沿上，试了两次，都滑了下来。要是把炸药包放在河床上，又无法炸毁暗堡。就在这时候，嘹亮的冲锋号响了，惊天动地的喊杀声由远而近。在这万分紧急的关头，董存瑞昂首挺胸，站在桥底中央，左手托起炸药包，顶住桥底，右手猛地一拉导火索。导火索哧哧地冒着白烟，闪着火花，火光照亮了他那钢铸一般的脸。一秒钟、两秒钟......他像巨人一样挺立着，两眼放射着坚毅的光芒。他抬头眺望远方，用尽力气高喊着:“同志们，为了新中国，冲啊！”","巨大的响声震得地动山摇，前进的道路炸开了。战士们冲过烟雾，沿着董存瑞开辟的道路杀向敌军司令部，消灭了全部敌人。胜利的红旗在隆化中学上空迎风飘扬。"]},{"id":462,"grade":"六年级下册","title":"语文园地","paragraphs":["千磨万击还坚劲，任尔东西南北风。","不要人夸好颜色，只留清气满乾坤。","荷尽已无擎雨盖，菊残犹有傲霜枝。","父亲仍旧穿着他那件灰布旧棉袍，可是没戴眼镜。我看到了他那乱蓬蓬的长头发下面的平静而慈祥的脸。","扁鼻子军官的目光立刻变得凶恶可怕，他向前弓着身子，伸出两只大手。啊！那双手就像鹰的爪子，扭着雨来的两只耳朵，向两边拉。","他没有什么模样，使他可爱的是脸上的精神。头不很大，圆眼，肉鼻子，两条眉很短很粗，头上永远剃得发亮；腮上没有多余的肉，脖子可是几乎与头一边儿粗。","有意栽花花不发，","无心插柳柳成荫。","良药苦口利于病，","忠言逆耳利于行。","树欲静而风不止，","子欲养而亲不待。","常将有日思无日，","莫把无时当有时。","书到用时方恨少，","是非经过不知难。"]},{"id":463,"grade":"六年级下册","title":"学弈","paragraphs":["弈秋，通国之善弈者也。使弈秋诲二人弈，其一人专心致志，惟弈秋之为听；一人虽听之，一心以为有鸿鹄将至，思援弓缴而射之。虽与之俱学，弗若之矣。为是其智弗若与？曰：非然也。"]},{"id":464,"grade":"六年级下册","title":"两小儿辩日","paragraphs":["孔子东游，见两小儿辩斗，问其故。","一儿曰：“我以日始出时去人近，而日中时远也。”","一儿曰：“我以日初出远，而日中时近也。”","一儿曰：“日初出大如车盖，及日中则如盘盂，此不为远者小而近者大乎？”","一儿曰：“日初出沧沧凉凉，及其日中如探汤，此不为近者热而远者凉乎？”","孔子不能决也。","两小儿笑曰：“孰为汝多知乎？”","孔子到东方游历，途中遇见两个小孩在争辩，便问他们争辩的原因。","有一个小孩说：“我认为太阳刚升起时距离人近，而到中午的时候距离人远。”","另一个小孩说：“我认为太阳刚刚升起的时候，距离人比较远，而正午的时候距离人比较近。”","一个小孩说：“太阳刚升起的时候大得像一个车盖，等到正午就小得像一个盘子，这不是远处的看着小而近处 的看着大吗？”","另一个小孩说：“太阳刚升起的时候清凉而略带寒意，等到正午的时候像手伸进热水里一样热，这不是近的时候感觉热而远的时候感觉凉吗？”","孔子不能判决谁对谁错。","两个孩子笑着说：“谁说你知识渊博呢？”"]},{"id":465,"grade":"六年级下册","title":"15 真理诞生于一百个问号之后","paragraphs":["有人说过这样一句话：真理诞生于一百个问号之后。其实，这句话本身就是一个真理。","纵观千百年来的科学技术发展史，那些在科学领域有所建树的人，都善于从细微的、司空见惯的现象中发现问题，不断发问，不断解决疑问，追根求源，最后把“？”拉直变成“！”，找到真理。","波义耳是17世纪英国著名的化学家。一天，他急匆匆地向自己的实验室走去，路过花圃时，阵阵醉人的香气扑鼻而来，他这才发现花圃里的花已经开了。他摘下几朵紫罗兰插入一个盛水的烧瓶中，然后开始和助手们做实验。不巧的是，一个助手不慎把一滴盐酸溅到了紫罗兰上，爱花的波义耳急忙把冒烟的紫罗兰冲洗了一下，重新插入花瓶中。谁知过了一会儿，溅上盐酸的花瓣竟奇迹般地变红了。波义耳立即敏感地意识到，紫罗兰中有一种物质遇到盐酸会变红。那么，这种物质到底是什么？别的植物中会不会有同样的物质？别的酸对这种物质会有什么样的反应？这一奇怪的现象以及一连串的问题，促使波义耳进行了许多实验。由此他发现，大部分花草受酸或碱的作用都会改变颜色，其中以石蕊地衣中提取的紫色浸液最明显:它遇酸变成红色，遇碱变成蓝色。利用这一特点，波义耳制成了实验中常用的酸碱试纸——石蕊试纸。从那以后，这种试纸一直被广泛应用于化学实验中。","无独有偶。20世纪初的一天，因病住院的德国气象学家魏格纳正无聊地看着墙上的世界地图，突然发现南美洲东海岸的凸出部分与非洲西海岸的凹陷部分，竟然不可思议地互相吻合！魏格纳被自己偶然的发现惊呆了。这不会是一种巧合吧？他将地图上的一块块陆地作了比较，结果发现，从海岸线的情形看，地球上所有的大陆都能较好地吻合在一起。病愈之后，魏格纳开始认真地研究这个有趣的现象。他阅读了大量的相关文献，同时搜集古生物学方面的证据。他注意到，一位名叫米歇尔逊的生物学家发现，在美国东海岸有一种蚯蚓，欧洲西海岸的同纬度地区也有这种蚯蚓，而在美国西海岸却没有这种蚯蚓。魏格纳认为，这种蚯蚓的分布情况正说明，欧洲大陆与美洲大陆本来是连在一起的，否则，蚯蚓即使是插上翅膀也难以飞渡重洋。1915年，魏格纳系统整理了他的“大陆漂移学说”，出版了《海陆的起源》一书，在地质学界产生了重大影响。","更有趣的是一位名叫阿瑟林斯基的俄裔美国睡眠研究专家。一次，他发现儿子在睡觉的时候，眼珠忽然转动起来。他感到很奇怪：为什么睡觉时眼珠会转动？这会不会与做梦有关？会是什么关系呢？阿瑟林斯基带着一连串的疑问，对自己八岁的儿子进行了实验，结果表明：脑电波的变化与做梦有关。接着，他又对二十名成年人进行了反复的观察实验，最后得出结论：睡眠中眼珠快速转动的时候，人的脑电波也会发生较大的变化，这是人最容易做梦的阶段。阿瑟林斯基的研究成果，成为心理学家研究做梦的重要依据。","在科学史上，这样的事例还有很多，这说明科学并不神秘，真理并不遥远。只要你见微知著，善于发问并不断探索，那么，当你解决了若干个问号之后，就有可能发现真理。","当然，见微知著、善于发问并不断探索的能力，不是凭空产生的。正像数学家华罗庚说过的，科学的灵感，绝不是坐等可以等来的。如果说科学领域的发现有什么偶然的机遇的话，那么这种“偶然的机遇”只会给那些善于独立思考的人，给那些具有锲而不舍精神的人。"]},{"id":466,"grade":"六年级下册","title":"16 表里的生物","paragraphs":["我小时候住在一座小城里，城里没有工厂，所以也没有机器的声音。我那时以为凡能发出声音的，都是活的生物。早晨有鸟叫得很好听，夜里有狗吠得很怕人，夏天蝉在绿树上叫，秋晚有各种的虫在草丛中唱不同的歌曲。钟楼上的钟不是活的，有时却洪亮地响起来，那是有一个老人在敲；街心有时响着三弦的声音，那是一个盲人在弹。哪里有死的东西会自己走动，并且能自动地发出和谐的声音呢？","可是父亲怀里的表有时放在桌子上，不但它的秒针会自己走动，而且它坚硬的表盖里还会发出清脆的声音：滴答，滴答……没有一刻的休息，这声音比蝉鸣要柔和些，比虫的歌曲要单调些。","一天，我对父亲说：","“我爱听这表的声音。”","我一边说一边向着表伸出手去。父亲立刻把我的手拦住了，他说：","“只许听，不许动。”","停了一会儿，他又添上一句：","“小孩儿不许动表。”","他这么说，就更增加了表的神秘。“不许动”，里边该是什么东西在响呢？我对于它的好奇心一天比一天增加。树上的蝉，草里的虫，都不会轻易被人看见，我想：表里边一定也有一个蝉或虫一类的生物吧，这生物被父亲关在表里，不许小孩子动。","越不许我动，我越想动，但是我又不敢，因此很痛苦。这样过了许多天。父亲一把表放在桌子上，我的眼睛就再也离不开它。有一次，父亲也许看我的样子太可怜了，也许自己有什么高兴的事，他对我笑着说：“你来，我给你看看表里是什么在响，可是只许看，不许动。”","没有请求，父亲就自动给我看，我高兴极了，同时我的心也加速跳动。父亲取出一把小刀，把表盖拨开，我的面前立即呈现出一个美丽的世界：蓝色的、红色的小宝石，钉住几个金黄色的齿轮，里边还有一个小尾巴似的东西不停地摆来摆去。这小世界不但被表盖保护着，还被一层玻璃蒙着。我看得入神，唯恐父亲再把这美丽的世界盖上。但是，过了一会儿，父亲还是把表盖上了。父亲的表里边真是好看。","此后我就常常请求父亲把他的表打开给我看，有时父亲答应我，有时也拒绝我，这要看他高兴不高兴。有一回，父亲又把表打开了，我问：","“为什么还蒙着一层玻璃呢？”","“这就是叫你只许看，不许动。”父亲回答。","“为什么呢？”我又问。","“这摆来摆去的是一个小蝎子的尾巴，一动就要蛰你。”","我吓了一跳，蝎子是多么丑恶而恐怖的东西，为什么把它放在这样一个美丽的世界里呢？但是我也感到愉快，证实我的猜测没有错：表里边有一个活的生物。我继续问：","“为什么把那样可怕的东西放在这么好的表里？”","父亲没有回答。我只想，大半因为它有好听的声音吧。但是一般的蝎子都没有这么好听的声音，也许这里边的蝎子与一般的不同。","后来我见人就说：“我有蟋蟀在钵子里，蝈蝈儿在葫芦里，鸟儿在笼子里；父亲却有一个小蝎子在表里。”","这样的话我不知说了多久，也不知道到什么时候才不说了。"]},{"id":467,"grade":"六年级下册","title":"17* 他们那时候多有趣啊","paragraphs":["那天晚上，玛琪甚至把这件事记在自己的日记里了。在2155年5月17日这一天她写道：“今天，托米发现了一本真正的书！”","这是一本很旧的书。玛琪的爷爷有一次告诉过她，当他还是一个小孩子的时候，他的爷爷对他讲，曾经有那么一个时候，所有的故事都是印在纸上的。","玛琪和托米翻着这本书，书页已经发黄，皱皱巴巴的。他们读到的字全都静止不动，不像他们通常在荧光屏上看到的那样，顺序移动。真是有趣极了，你说是不是？读到后面，再翻回来看前面的一页时，刚刚读过的那些字仍然停留在原地。","玛琪问：“你在哪儿找到这本书的？”","“在我们家。”托米指了一下，可并没有抬起头，因为他正在全神贯注地看书。“在顶楼上。”他又说。","“书里写的什么？”","“学校。”","玛琪脸上露出鄙夷不屑的神情：“学校？学校有什么好写的？我讨厌学校。”玛琪一向讨厌学校，可现在她比以往任何时候都更憎恶它。那个机器老师一次又一次地给她做地理测验，她一次比一次答得糟，最后她的妈妈发愁地摇了摇头，把教学视察员找了来。","视察员把机器老师调好以后，拍拍她的脑袋，笑着对她妈妈说：“这不是小姑娘的错，琼斯太太。我认为是这个机器里的地理部分调得太快了些，这种事是常有的。我把它调慢了，已经适合于十岁左右孩子们的水平了。说实在的，她总的学习情况够令人满意的了。”说着，他又拍 了拍玛琪的脑袋。","玛琪失望极了，她本来希望他把这个机器老师拿走。他们有一次就把托米的老师搬走了将近一个月之久，因为历史那部分的装置完全显示不出图像了。","所以她对托米说：“怎么会有人写学校呢？”","托米非常高傲地瞧了她一眼：“因为那不是我们这种类型的学校，傻瓜。那是几百年前的那种老式学校。”接着他一字一顿地说：“几世纪前。”","玛琪很难过。“嗯，我不知道古时候他们有什么样的学校。”她从他肩膀后面看了一会儿那本书，开口说：“不管怎么说，他们得有一个老师吧？”","“当然，他们有个老师，可不是我们这样的老师。是一个真人！”","“一个真人？真人怎么会是老师呢？”","“是这样的，他只不过给孩子们讲讲课，留些作业，提提问题。”","“真人可没那么聪明。”","“当然聪明啦。我爸爸就和我的机器老师知道得一样多。”","玛琪不打算争吵下去，便说：“我可不想让一个陌生人到我家里来教我功课。”","拖米尖声大笑。“你不知道的事太多了，玛琪。那些老师才不到你家里来上课呢。他们有一个专门的地方，所有的孩子都到那儿去上学。”","“所有的孩子都学一样的功课吗？”","“那当然，如果他们的年龄一样的话。”","“可我妈妈说，一个老师是需要调整的，好适合他所教的每个孩子的智力。另外，对每个孩子的教法都应该是不同的。”","“他们那时候恰好不是那么做的。如果你不喜欢书里说的这些事，你就干脆别读这本书。”","“我没说我不喜欢。”玛琪急忙说。她很想知道那些有趣的学校是怎么回事。","他们还没看完一半，玛琪的妈妈就喊了起来：“玛琪！该上课了！”","玛琪叹了口气，去上课了。她脑子里还在想着当她爷爷的爷爷是个小孩子的时候，他们上的那种老式学校。附近所有的孩子都到一处去上学，他们在校园里笑啊、喊啊，他们一起坐在课堂里上课；上完一天的课，就一块儿回家。他们学的功课都一样，这样，在做作业的时候他们就可以互相帮助，有问题还可以互相讨论。","而且他们的老师是真人……","机器老师正在屏幕上显现出这样的字：“我们把½和¼ 这两个分数加在一起──”","玛琪想，在过去的日子里，那些孩子一定非常热爱他们的学校。她想，他们那时候多有趣啊！"]},{"id":468,"grade":"六年级下册","title":"语文园地","paragraphs":["走马观花 自愧弗如 声泪俱下","不以为然 过犹不及 赴汤蹈火","正像数学家华罗庚说过的，科学的灵感，绝不是坐等可以等来的。","中国古时候有个文学家叫做司马迁的说过:“人固有一死，或重于泰山，或轻于鸿毛。”","穷则变，变则通，通则久。——《周易》","苟日新，日日新，又日新。——《礼记》","青，取之于蓝而青于蓝。——《荀子》","苟利于民，不必法古；苟周于事，不必循旧。——《淮南子》"]},{"id":469,"grade":"六年级下册","title":"综合性学习","paragraphs":["1942年正月新春，我不满六周岁，就到邻村小学读书。","这个小学坐落在关帝庙的后殿，只有一位老师，教四个年级。四个年级四个班，四个班只有四十人。","老师姓田，十七岁就开始了小学教师生涯，执教四十年，桃李满门，弟子不下三千。","田老师很有口才，文笔也好。","开学头一天，我们排队进入教室。每个一年级小学生，配备一个三年级的学兄带笔。田老师先给二年级和四年级学生上课，让三年级的学兄把着一年级学弟的小手，描红摹纸。","红摹纸上，一首小诗：","一去二三里，烟村四五家。","亭台六七座，八九十枝花。","轮到给一年级上课时，田老师先把这首诗念一遍，串讲一遍，然后，以这四句诗为内容，编出一段故事，讲得娓娓动听。","我还记得，故事的大意是：","一个小孩儿，牵着妈妈的衣襟儿，去姥姥家，一口气走出了二三里。娘儿俩路过一个小村子，只有四五户人家，正在做午饭，家家冒炊烟。两个人走累了，看见路边有六七座亭子，就走过去歇脚。亭子外边，花开得茂盛，小孩儿越看越喜爱，伸出指头点数，嘴里念叨着“……八枝，九枝，十枝”。他想折下一枝来，戴在耳朵上，把自己打扮得像个迎春小喜神儿。他刚要动手，妈妈喝住他，说：“你折一枝，他折一枝，后边歇脚的人就不能看景了。”小孩儿听了妈妈的话，就缩回了手。后来，花越开越多，数也数不过来了，此地就变成一座大花园……","我听得入迷，恍如身临其境，田老师的话戛然而止，我却仍在发呆，直到三年级的学兄捅了我一下，我才惊醒。","那时候，田老师每讲一课，都要编一个引人入胜的故事，一、二、三、四年级的课文都是如此。我在田老师门下受业四年，听到上千个故事，有如春雨点点入地。","从事文学创作需要丰富的想象力，在这方面田老师培育了我，给我开了窍。","我回家乡去，在村边、河畔、堤坡，遇到田老师拄杖散步，仍然像四十年前的一年级小学生那样，恭恭敬敬地向他行礼。谈起往事，我深深感谢他在我那幼小的心田上，播下了文学的种子。老师摇摇头，说：“这不过是无心插柳柳成荫啊！”","十年树木，百年树人；插柳之恩，终身难忘。","1972年的5月，我正上高二。学校里举办“红五月”征文比赛，我投了稿，是一篇很长的作文，题目叫“补考”。","一天上午，我们正在操场劳动，有同学跑过来告诉我：“获奖征文在报栏里贴出来了，有你的！上面打满了红双圈。”那时候，老师们批阅作文，喜欢在认为最好的词句下面画红双圈。我很兴奋，立刻就想去看看，却又矜持，不愿在同学面前显出我的迫不及待。挨到中午，校园里寂静无人时，我像做贼样地溜到报栏前，傻乎乎地笑着，独自欣赏我的打满了红双圈的作文。我的心怦怦跳着，从头到尾一个个数下来，一共是九十八个红双圈。这就是语文老师给我的评价。","带着红双圈的作文在报栏里贴了很久。一天，县文化馆的同志来到学校，看见了报栏里的这篇作文，就揭下来带走了。不久，我的作文刊登在了县办刊物上。县办刊物送到扬州地区，被地区刊物选中，第二次发表。几经周转，次年，《补考》竟发表在上海一家出版社的正式刊物上。","那时，我已经下乡插队。父亲鼓励我：既有一，何不能有二？于是，我就接着“折腾”，陆续发表了很多小说，成了作家。","没有当年作文上的九十八个红双圈，会有我今天的一切吗？人生有无数条轨道可走，之所以选择了其中的一条，是偶然，更是必然。","永远感谢我的老师，感谢母校的报栏，感谢挂在我生命之树上的红双圈。","我为少男少女们歌唱。","我歌唱早晨，","我歌唱希望，","我歌唱那些属于未来的事物，","我歌唱正在生长的力量。","我的歌呵，","你飞吧，","飞到年轻人的心中","去找你停留的地方。","所有使我像草一样颤抖过的","快乐或者好的思想，","都变成声音飞到四方八面去吧，","不管它像一阵微风","或者一片阳光。","轻轻地从我琴弦上","失掉了成年的忧伤，","我重新变得年轻了，","我的血流得很快，","对于生活我又充满了梦想，充满了渴望。","有的人在工作、学习中缺乏耐性和韧性，他们一旦碰了钉子，走了弯路，就开始怀疑自己是否有研究才能。其实，我可以告诉大家，许多有名的科学家和作家，都是经过很多次失败，走过很多弯路才成功的。有人看见一个作家写出一本好小说，或者看见一个科学家发表几篇有分量的论文，便仰慕不已，很想自己能够信手拈来，妙手成章，一觉醒来，誉满天下。其实，成功的作品和论文只不过是作家、学者们整个创作和研究中的极小部分，甚至数量上还不及失败作品的十分之一。大家看到的只是他们成功的作品，而失败的作品是不会公开发表出来的。","要知道，一个科学家在攻克科学堡垒的长征中，失败的次数和经验，远比成功的经验要丰富、深刻得多。失败虽然不是什么令人快乐的事情，但也决不应该因此气馁。在进行研究时，研究方向不正确，走了些岔路，白费了许多精力，这也是常有的事。但不要紧，可以再调换方向进行研究。更重要的是要善于吸取失败的教训，总结已有的经验，再继续前进。","根据我自己的体会，所谓天才，就是坚持不断的努力。有些人也许觉得我在数学方面有什么天分，其实从我身上是找不到这种天分的。我读小学时，因为成绩不好，没有拿到毕业证书，只拿到一张修业证书。初中一年级时，我的数学也是经过补考才及格的。但是说来奇怪，从初中二年级以后，我就发生了一个根本转变，因为我认识到既然我的资质差些，就应该多用点儿时间来学习。别人学一小时，我就学两小时，这样，我的数学成绩得以不断提高。","一直到现在我也贯彻这个原则：别人看一篇东西要三小时，我就花三个半小时。经过长期积累，就多少可以看出成绩来。并且在基本技巧烂熟之后，往往能够一个钟头就看懂一篇人家看十天半月也解不透的文章。所以，前一段时间的加倍努力，在后一段时间能收到预想不到的效果。","是的，聪明在于学习，天才在于积累。","亲爱的方老师：","窗外的栀子花又盛开了，一年一度的毕业季到来了。","还记得一年级时，稚嫩的我忐忑不安地跨进校门，穿过走廊，来到教室。一个清瘦而高挑的身影出现在我眼前，那就是您。您俯下身子，轻轻地对我说：“你是书哲？”我抬起头来望着您，惊讶于您居然叫得出我的名字。您笑着用温暖的大手握住我的小手，把我带到座位上，对我说：“我是方老师。”我望着浅笑盈盈的您，一字一顿地念着“方——老——师”。","您的字总是那么干净漂亮，一个个娟秀端庄的方块字像小士兵一样排列在黑板上。小小的我急于模仿，可一笔一画却是歪歪扭扭的，我为此特别沮丧。您语重心长地对我说：“字如其人，每个人的字都不同，所以，书哲，你不能一味地模仿，还要仔细观察字的结构……”说罢，亲切地摸摸我的头，然后握着我的手，捏着笔杆慢慢地在纸上移动，几个端庄整齐的汉字便出现在了本子上。在您的熏陶下，我的字写得越来越漂亮，越来越大气。","运动会上，您就像一个稚气未脱的小孩子，挥动手臂大声地呐喊助威。原本白皙的脸庞因为兴奋而涨得通红，一头长发随风舞动。当运动员冲过终点时，您会快步奔上去，紧紧地把他搂在怀里，脸上洋溢着孩子般的幸福与骄傲。遇到没发挥好的运动员，您会拉住他的手，温柔地鼓励他别放弃。","就这样，您无怨无悔地把我们从懵懂天真的一年级带到心智成熟的六年级。成长路上您的关爱、叮咛与教诲，我都将铭记在心。","祝您","桃李满天下","您的学生书哲","5月30日"]},{"id":470,"grade":"六年级下册","title":"1 采薇（节选）","paragraphs":["昔我往矣，","杨柳依依。","今我来思，","雨雪霏霏。","行道迟迟，","载渴载饥。","我心伤悲，","莫知我哀！","回想当初我离开的时候，连杨柳都与我依依惜别。","如今回来路途中，却纷纷扬扬下起了大雪。","路途曲折漫长难行走，又渴又饥真劳累。","我心里不觉伤悲起来，没有人会懂得我的痛苦的！"]},{"id":471,"grade":"六年级下册","title":"2 送元二使安西","paragraphs":["作者：[唐代] 王维","渭城朝雨浥轻尘，","客舍青青柳色新。","劝君更尽一杯酒，","西出阳关无故人。","渭城早晨一场春雨沾湿了轻尘，客舍周围柳树的枝叶翠嫩一新。","老朋友请你再干一杯美酒，向西出了阳关就难以遇到故旧亲人。","王维（701年－761年，一说699年—761年），字摩诘(jié)，号摩诘居士。汉族，河东蒲州（今山西运城）人，祖籍山西祁县，唐朝诗人，有“诗佛”之称。苏轼评价其：“味摩诘之诗，诗中有画；观摩诘之画，画中有诗。”开元九年（721年）中进士，任太乐丞。天宝年间，拜吏部郎中、给事中。唐肃宗乾元年间任尚书右丞，世称“王右丞”。王维是盛唐诗人的代表，今存诗400余首，重要诗作有《相思》《山居秋暝》等。王维精通佛学，受禅宗影响很大。佛教有一部《维摩诘经》，是王维名和字的由来。王维诗书画都很有名，多才多艺，音乐也很精通。与孟浩然合称“王孟”。"]},{"id":472,"grade":"六年级下册","title":"3 春夜喜雨","paragraphs":["作者：[唐代] 杜甫","好雨知时节，","当春乃发生。","随风潜入夜，","润物细无声。","野径云俱黑，","江船火独明。","晓看红湿处，","花重锦官城。","好雨知道下雨的节气，正是在春天植物萌发生长的时候。","随着春风在夜里悄悄落下，无声地滋润着春天万物。","雨夜中田间小路黑茫茫一片，只有江船上的灯火独自闪烁。","天刚亮时看着那雨水润湿的花丛，娇美红艳，整个锦官城变成了繁花盛开的世界。","杜甫（712－770），字子美，自号少陵野老，世称“杜工部”、“杜少陵”等，汉族，河南府巩县（今河南省巩义市）人，唐代伟大的现实主义诗人，杜甫被世人尊为“诗圣”，其诗被称为“诗史”。杜甫与李白合称“李杜”，为了跟另外两位诗人李商隐与杜牧即“小李杜”区别开来，杜甫与李白又合称“大李杜”。他忧国忧民，人格高尚，他的约1400余首诗被保留了下来，诗艺精湛，在中国古典诗歌中备受推崇，影响深远。759-766年间曾居成都，后世有杜甫草堂纪念。"]},{"id":473,"grade":"六年级下册","title":"4 早春呈水部张十八员外","paragraphs":["作者：[唐代] 韩愈","天街小雨润如酥，","草色遥看近却无。","最是一年春好处，","绝胜烟柳满皇都。","天街上细密的春雨润滑如酥，远望草色依稀连成一片，近看时却显得稀疏。","一年之中最美的就是这早春的景色，远胜过绿柳满城的春末。","韩愈（768年－824年12月25日），字退之，河南河阳（今河南省孟州市）人，自称“祖籍昌黎郡”，世称“韩昌黎”、“昌黎先生”。唐代中期大臣，文学家、思想家、政治家，秘书郎韩仲卿之子。元和十二年（817年），出任宰相裴度行军司马，从平“淮西之乱”。直言谏迎佛骨，贬为潮州刺史。宦海沉浮，累迁吏部侍郎，人称“韩吏部”。长庆四年（824年），韩愈病逝，年五十七，追赠礼部尚书，谥号为“文”，故称“韩文公”。元丰元年（1078年），追封昌黎郡伯，并从祀孔庙。韩愈作为唐代古文运动的倡导者，名列“唐宋八大家”之首，有“文章巨公”和“百代文宗”之名。与柳宗元并称“韩柳”，与柳宗元、欧阳修和苏轼并称“千古文章四大家”。倡导“文道合一”、“气盛言宜”、“务去陈言”、“文从字顺”等写作理论，对后人具有指导意义。著有《韩昌黎集》等。"]},{"id":474,"grade":"六年级下册","title":"5 江上渔者","paragraphs":["作者：[宋代] 范仲淹","江上往来人，","但爱鲈鱼美。","君看一叶舟，","出没风波里。","江岸边行人来来往往，只是喜爱味道鲜美的鲈鱼。","你看那一叶小小渔船，时隐时现在滔滔风浪里。","范仲淹（989年10月1日－1052年6月19日），字希文。祖籍邠州，后移居苏州吴县。北宋初年政治家、文学家。范仲淹幼年丧父，母亲改嫁长山朱氏，遂更名朱说。大中祥符八年（1015年），范仲淹苦读及第，授广德军司理参军。后历任兴化县令、秘阁校理、陈州通判、苏州知州等职，因秉公直言而屡遭贬斥。皇祐四年（1052年），改知颍州，在扶疾上任的途中逝世，年六十四。累赠太师、中书令兼尚书令、楚国公，谥号“文正”，世称范文正公。"]},{"id":475,"grade":"六年级下册","title":"6 泊船瓜洲","paragraphs":["作者：[宋代] 王安石","京口瓜洲一水间，","钟山只隔数重山。","春风又绿江南岸，","明月何时照我还？","京口和瓜洲之间只隔着一条长江，钟山就隐没在几座山峦的后面。","和煦的春风又吹绿了江南岸边景色，皎洁的明月什么时候才能照着我回到家乡呢？","王安石（1021年12月18日－1086年5月21日），字介甫，号半山，谥文，封荆国公。世人又称王荆公。汉族，北宋抚州临川人（今江西省抚州市临川区邓家巷人），中国北宋著名政治家、思想家、文学家、改革家，唐宋八大家之一。欧阳修称赞王安石：“翰林风月三千首，吏部文章二百年。老去自怜心尚在，后来谁与子争先。”传世文集有《王临川集》、《临川集拾遗》等。其诗文各体兼擅，词虽不多，但亦擅长，且有名作《桂枝香》等。而王荆公最得世人共传之诗句莫过于《泊船瓜洲》中的“春风又绿江南岸，明月何时照我还。”"]},{"id":476,"grade":"六年级下册","title":"7 游园不值","paragraphs":["作者：[宋代] 叶绍翁","应怜屐齿印苍苔，","小扣柴扉久不开。","春色满园关不住，","一枝红杏出墙来。","也许是园主担心我的木屐踩坏他那爱惜的青苔，我轻轻地敲打柴门久久不开。","叶绍翁，南宋中期诗人，字嗣宗，号靖逸，处州龙泉人。祖籍建安（今福建建瓯），本姓李，后嗣于龙泉(今属浙江丽水)叶氏。生卒年不详。曾任朝廷小官。其学出自叶适，他长期隐居钱塘西湖之滨，与真德秀交往甚密，与葛天民互相酬唱。"]},{"id":477,"grade":"六年级下册","title":"8 卜算子·送鲍浩然之浙东","paragraphs":["作者：[宋代] 王观","水是眼波横，山是眉峰聚。欲问行人去那边？眉眼盈盈处。","才始送春归，又送君归去。若到江南赶上春，千万和春住。","水像美人流动的眼波，山如美人蹙起的眉毛。想问行人去哪里？到山水交汇的地方。","刚刚把春天送走，又要送你归去。如果你到江南能赶上春天，千万要把春天的景色留住。","王观(1035--1100)，字通叟，生于如皋(今江苏如皋)，北宋著名词人。王安石为开封府试官时，他得中科举及第。宋仁宗嘉佑二年(1057年)，考中进士。其后，历任大理寺丞、江都知县等职，在任时作《扬州赋》，宋神宗阅后大喜，大加褒赏；又撰《扬州芍药谱》一卷，遂被重用为翰林学士净土。"]},{"id":478,"grade":"六年级下册","title":"9 浣溪沙（游蕲水清泉寺）","paragraphs":["作者：[宋代] 苏轼","游蕲水清泉寺，寺临兰溪，溪水西流。","山下兰芽短浸溪，松间沙路净无泥，萧萧暮雨子规啼。","谁道人生无再少？门前流水尚能西！休将白发唱黄鸡。","游玩蕲水的清泉寺，寺庙在兰溪的旁边，溪水向西流淌。","山脚下兰草新抽的幼芽浸润在溪水中，松林间的沙路被雨水冲洗得一尘不染，傍晚时分，细雨萧萧，杜鹃声声。","谁说人生就不能再回到少年时期？ 门前的溪水都还能向西边流淌！不要在老年感叹时光的飞逝啊！","苏轼，（1037年1月8日-1101年8月24日）字子瞻、和仲，号铁冠道人、东坡居士，世称苏东坡、苏仙，汉族，眉州眉山（四川省眉山市）人，祖籍河北栾城，北宋著名文学家、书法家、画家，历史治水名人。苏轼是北宋中期文坛领袖，在诗、词、散文、书、画等方面取得很高成就。文纵横恣肆；诗题材广阔，清新豪健，善用夸张比喻，独具风格，与黄庭坚并称“苏黄”；词开豪放一派，与辛弃疾同是豪放派代表，并称“苏辛”；散文著述宏富，豪放自如，与欧阳修并称“欧苏”，为“唐宋八大家”之一。苏轼善书，“宋四家”之一；擅长文人画，尤擅墨竹、怪石、枯木等。与韩愈、柳宗元和欧阳修合称“千古文章四大家”。作品有《东坡七集》《东坡易传》《东坡乐府》《潇湘竹石图卷》《古木怪石图卷》等。"]},{"id":479,"grade":"六年级下册","title":"10 清平乐·春归何处","paragraphs":["作者：[宋代] 黄庭坚","春归何处？寂寞无行路。若有人知春去处。唤取归来同住。","春无踪迹谁知？除非问取黄鹂。百啭无人能解，因风飞过蔷薇。","春天将归向何处？现在的我却找不到春的踪迹。如果有人知道春天的去处，请叫它仍旧回来和我同住。","可是又有谁会知道春天离开的踪迹呢？除非你问一问黄鹂鸟。但是没有人能够理解它迂回婉转的啼鸣声。看吧，它已经趁着风势飞过了那片蔷薇。","黄庭坚（1045.8.9-1105.5.24），字鲁直，号山谷道人，晚号涪翁，洪州分宁（今江西省九江市修水县）人，北宋著名文学家、书法家，为盛极一时的江西诗派开山之祖，与杜甫、陈师道和陈与义素有“一祖三宗”（黄庭坚为其中一宗）之称。与张耒、晁补之、秦观都游学于苏轼门下，合称为“苏门四学士”。生前与苏轼齐名，世称“苏黄”。著有《山谷词》，且黄庭坚书法亦能独树一格，为“宋四家”之一。"]}];
